INSERT INTO `pats_bot_knowledge` (`id`, `categoria`, `subcategoria`, `intent`, `pregunta_base`, `respuesta`, `nota_operativa`, `requiere_revision`, `observacion_revision`, `nivel_confianza`, `keywords`, `respuesta_corta`, `requiere_login`, `requiere_datos_usuario`, `prioridad`, `activo`, `fuente`, `version_conocimiento`, `canal`, `created_at`, `updated_at`) VALUES
(1, 'Identidad PATS', 'Definición', 'que_es_pats', '¿Qué es PASAPORTE A TU SALUD?', 'PASAPORTE A TU SALUD, también llamado PATS, es un programa de beneficios, descuentos y precios preferenciales en servicios médicos privados dentro de la red autorizada. Es personal, exclusivo e intransferible. Importante: PATS no es un seguro médico.', NULL, 0, NULL, 'ALTA', 'que es pats,pasaporte a tu salud,tarjeta,programa,beneficios,descuentos,precio preferencial', 'PATS es un programa de beneficios y descuentos médicos. No es un seguro médico.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(2, 'Identidad PATS', 'No seguro médico', 'no_seguro', '¿PATS es un seguro médico?', 'No. PATS no es un seguro médico, no funciona como póliza de gastos médicos y no sustituye un seguro. Es un programa de beneficios, descuentos y precios preferenciales dentro de la red autorizada.', NULL, 0, NULL, 'ALTA', 'es seguro,seguro medico,poliza,gastos medicos,cobertura,no es seguro,no sustituye seguro', 'No. PATS no es seguro médico; es un programa de beneficios y precios preferenciales.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(3, 'Identidad PATS', 'Diferencia contra seguro', 'no_seguro', '¿Cuál es la diferencia entre PATS y un seguro?', 'Un seguro médico puede cubrir riesgos conforme a una póliza. PATS no funciona así. PATS da acceso a beneficios, descuentos o precios preferenciales en servicios médicos privados dentro de la red autorizada.', NULL, 0, NULL, 'ALTA', 'diferencia seguro,pats seguro,cobertura,póliza,poliza,beneficios,no cubre como seguro', 'PATS no cubre como seguro; da beneficios y precios preferenciales en red autorizada.', 0, 0, 98, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(4, 'Identidad PATS', 'Uso personal', 'uso_qr', '¿Puedo prestar mi PATS a otra persona?', 'No. PATS es personal, exclusivo e intransferible. No debe prestarse, compartirse ni utilizarse a nombre de otra persona.', NULL, 0, NULL, 'ALTA', 'prestar,compartir,otra persona,intransferible,personal,exclusivo,usar por alguien mas', 'No. PATS es personal e intransferible.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(5, 'Identidad PATS', 'Uso indebido', 'uso_qr', '¿Qué pasa si alguien más usa mi PATS?', 'PATS debe ser utilizado únicamente por la persona titular. Usarlo a nombre de otra persona se considera uso indebido y puede impedir la atención o generar revisión por parte del personal autorizado.', NULL, 0, NULL, 'ALTA', 'uso indebido,otra persona,prestar pasaporte,compartir qr,titular', 'PATS solo puede usarlo la persona titular.', 0, 0, 90, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(6, 'Beneficios', 'Servicios sin costo', 'beneficios', '¿Qué incluye PATS sin costo?', 'Con PATS vigente puedes acceder sin costo a consultas de medicina general ilimitadas y consultas de urgencias ilimitadas, siempre dentro de la red autorizada y conforme a las reglas del programa.', NULL, 0, NULL, 'ALTA', 'gratis,sin costo,consulta general,urgencias,ilimitadas,beneficios incluidos', 'Incluye consultas generales y de urgencias ilimitadas sin costo dentro de la red autorizada.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(7, 'Beneficios', 'Servicios con precio preferencial', 'beneficios', '¿Qué servicios tienen precio preferencial con PATS?', 'PATS puede darte acceso a precios preferenciales o descuentos en hospitalización, consultas con especialistas afiliados, farmacia, laboratorio clínico, imagenología, cirugías, uso de quirófano, terapia intensiva y otros servicios médicos dentro de la red autorizada.', NULL, 0, NULL, 'ALTA', 'precio preferencial,descuento,hospitalizacion,especialistas,farmacia,laboratorio,imagenologia,cirugia,quirofano,terapia intensiva', 'PATS ofrece precios preferenciales en servicios médicos dentro de la red autorizada.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(8, 'Beneficios', 'Beneficios generales', 'beneficios', '¿Qué beneficios tengo con PATS?', 'Tus beneficios dependen del servicio y de la red autorizada. Algunos servicios pueden ser sin costo, como consulta general y urgencias; otros tienen descuentos o precios preferenciales, como especialistas, laboratorio, imagenología, farmacia, hospitalización o cirugía.', NULL, 0, NULL, 'ALTA', 'beneficios,tengo,servicios,que puedo usar,descuentos,precio especial,precio preferencial', 'PATS te da beneficios sin costo en algunos servicios y precios preferenciales en otros.', 0, 0, 95, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(9, 'Beneficios', 'No todos los servicios son gratis', 'beneficios', '¿Todos los servicios son gratis con PATS?', 'No. Algunos servicios pueden ser sin costo conforme al programa, como consulta general y urgencias dentro de red autorizada. Otros servicios no son gratis, pero pueden tener descuento o precio preferencial.', NULL, 0, NULL, 'ALTA', 'todo gratis,servicios gratis,no pago,gratis,descuento,precio preferencial', 'No todo es gratis; algunos servicios tienen descuento o precio preferencial.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(10, 'Beneficios', 'Consulta de precios', 'precios_servicios', '¿Dónde reviso la lista de precios preferenciales?', 'La lista de precios preferenciales debe consultarse en la app oficial o con medios autorizados por PATS, como concierge físico o virtual, admisión o personal autorizado.', NULL, 0, NULL, 'ALTA', 'lista precios,precios preferenciales,tabulador,app,concierge,admisión,admision', 'Consulta precios en la app oficial o con personal autorizado PATS.', 0, 0, 90, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(11, 'Pagos', 'Costo mensual', 'costo', '¿Cuánto cuesta PATS al mes?', 'PATS tiene un costo mensual de $800 MXN, IVA incluido. El pago debe realizarse dentro de los primeros 5 días de cada mes por los medios autorizados.', NULL, 0, NULL, 'ALTA', 'cuanto cuesta,costo mensual,precio,mensualidad,800,pago mensual,iva', 'PATS cuesta $800 MXN al mes, IVA incluido.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(12, 'Pagos', 'Costo anual', 'costo', '¿Cuánto cuesta PATS anual?', 'Si se contrata por 12 meses, el costo anual corresponde a 12 mensualidades de $800 MXN, es decir $9,600 MXN, salvo que exista una condición comercial autorizada diferente.', NULL, 0, NULL, 'ALTA', 'costo anual,pago anual,9600,12 meses,anualidad,precio anual', 'El costo anual base es de $9,600 MXN por 12 meses.', 0, 0, 95, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(13, 'Pagos', 'Fecha límite', 'pago', '¿Cuándo debo pagar PATS?', 'El pago mensual debe realizarse dentro de los primeros 5 días de cada mes por medios autorizados por PATS.', NULL, 0, NULL, 'ALTA', 'cuando pagar,fecha limite,primeros 5 dias,corte,pago mensual', 'Debes pagar dentro de los primeros 5 días de cada mes.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(14, 'Pagos', 'Medios autorizados', 'pago', '¿Dónde puedo pagar PATS?', 'El pago de PATS debe realizarse por medios autorizados, como app, link de pago, transferencia bancaria o módulos PATS, según estén disponibles oficialmente.', NULL, 0, NULL, 'ALTA', 'donde pago,medios de pago,app,link de pago,transferencia,modulo,pago pats', 'Paga únicamente por medios autorizados PATS.', 0, 0, 90, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(15, 'Vigencia', 'Duración', 'vigencia', '¿Cuánto dura mi PATS?', 'Cada pago activa PATS por 30 días o por 12 meses, según se especifique al momento de la compra. La vigencia se renueva conforme se realicen los pagos correspondientes.', NULL, 0, NULL, 'ALTA', 'vigencia,dura,30 dias,12 meses,renueva,activo,vigente', 'La vigencia puede ser de 30 días o 12 meses según el pago contratado.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(16, 'Vigencia', 'Renovación', 'vigencia', '¿Cómo se renueva PATS?', 'PATS se renueva conforme se realicen los pagos correspondientes. Si el pago es mensual, debe hacerse dentro de los primeros 5 días de cada mes para conservar vigencia.', NULL, 0, NULL, 'ALTA', 'renovar,renovacion,pago mensual,vigente,continuar activo', 'Se renueva realizando el pago correspondiente en tiempo.', 0, 0, 95, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(17, 'Vigencia', 'Estatus activo', 'vigencia', '¿Cómo sé si mi PATS está activo?', 'Para confirmar si tu PATS está activo debe revisarse tu estatus en la app oficial o con personal autorizado PATS. Si estás en admisión o concierge, valida el estatus del usuario antes de confirmar beneficios.', NULL, 0, NULL, 'ALTA', 'estatus,activo,vigente,mi pats activo,validar activo', 'Consulta tu estatus en la app o con personal autorizado.', 1, 1, 95, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(18, 'Pagos', 'Falta de pago', 'falta_pago', '¿Qué pasa si dejo de pagar PATS?', 'Si interrumpes tus pagos, PATS deja de estar activo. Tienes 5 días naturales después de la fecha de corte para no perder la vigencia. Si deseas reactivarlo, debes cubrir mensualidades vencidas, la mensualidad vigente y la cuota de reactivación aplicable.', NULL, 0, NULL, 'ALTA', 'deje de pagar,no pague,vencido,inactivo,adeudo,fecha de corte,5 dias', 'Si dejas de pagar, PATS puede quedar inactivo y requerir reactivación.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(19, 'Pagos', 'Días de gracia', 'falta_pago', '¿Tengo días de gracia para pagar PATS?', 'Sí. El manual indica que tienes 5 días naturales después de tu fecha de corte para no perder la vigencia de tu pasaporte.', NULL, 0, NULL, 'ALTA', 'dias de gracia,5 dias,fecha de corte,prorroga,pagar tarde', 'Tienes 5 días naturales después de tu fecha de corte.', 0, 0, 95, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(20, 'Pagos', 'Reactivación', 'reactivacion', '¿Cómo reactivo mi PATS?', 'Para reactivar PATS debes pagar la mensualidad o mensualidades vencidas, la mensualidad vigente y la cuota de reactivación correspondiente por cada mes no pagado.', NULL, 0, NULL, 'ALTA', 'reactivar,reactivacion,meses vencidos,mensualidad vigente,cuota', 'Debes pagar adeudos, mensualidad vigente y cuota de reactivación.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(21, 'Pagos', 'Cuota reactivación', 'reactivacion', '¿Cuánto cuesta la reactivación de PATS?', 'La reactivación requiere cubrir mensualidades vencidas, mensualidad vigente y una cuota de reactivación. El manual indica una cuota de $100 MXN por cada mes no pagado.', NULL, 0, NULL, 'ALTA', 'cuanto reactivar,cuota reactivacion,100,mes no pagado,adeudo', 'La cuota indicada es de $100 MXN por cada mes no pagado, más adeudos.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(22, 'Acceso', 'Entrega de usuario', 'acceso_app', '¿Cuándo recibo mi usuario y contraseña?', 'Después del primer pago, PATS debe entregar usuario y contraseña vía correo electrónico dentro de los 5 días hábiles siguientes. En ese correo también se incluye el enlace de acceso a la app oficial.', NULL, 0, NULL, 'ALTA', 'usuario,contraseña,password,correo,primer pago,5 dias habiles,app', 'Después del primer pago recibes usuario, contraseña y acceso a la app por correo.', 0, 0, 95, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(23, 'Acceso', 'No recibí acceso', 'acceso_app', 'No he recibido mi usuario de PATS, ¿qué hago?', 'Si ya realizaste tu primer pago y no has recibido usuario o contraseña dentro del plazo indicado, contacta a Concierge PATS o personal autorizado para validar tu registro, correo y estatus de activación.', NULL, 0, NULL, 'ALTA', 'no recibi usuario,no me llego correo,no tengo contraseña,no puedo entrar,app', 'Contacta a Concierge PATS para validar tu registro y correo.', 1, 1, 90, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(24, 'Uso', 'Uso de QR', 'uso_qr', '¿Qué debo presentar para usar PATS?', 'Para usar PATS debes presentar identificación oficial y tu QR o pasaporte digital. El personal puede validar que el pasaporte esté activo y que el servicio corresponda a la red autorizada.', NULL, 0, NULL, 'ALTA', 'identificacion,qr,pasaporte digital,tarjeta,usar pats,presentar', 'Presenta identificación oficial y QR o pasaporte digital.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(25, 'Uso', 'Sin QR', 'uso_qr', '¿Puedo usar PATS si no tengo mi QR?', 'El QR o pasaporte digital es el medio de validación recomendado. Si no lo tienes disponible, acude con personal autorizado PATS para validar tu identidad, estatus y acceso.', NULL, 0, NULL, 'ALTA', 'no tengo qr,sin qr,olvide qr,no aparece qr,validar identidad', 'Si no tienes QR, pide validación con personal autorizado PATS.', 1, 1, 90, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(26, 'Uso', 'Identificación oficial', 'uso_qr', '¿Necesito identificación oficial para usar PATS?', 'Sí. Cada vez que uses PATS debes presentar identificación oficial junto con tu QR o pasaporte digital.', NULL, 0, NULL, 'ALTA', 'identificacion oficial,ine,pasaporte,documento,identificarme', 'Sí, debes presentar identificación oficial.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(27, 'Servicios', 'Consulta general', 'consulta_general', '¿Cómo uso PATS para consulta general?', 'Para consulta general, acude a un hospital dentro de la red autorizada y presenta identificación oficial y QR o pasaporte digital. Si durante la atención se genera un procedimiento, insumo o medicamento extra, se paga directamente al hospital.', NULL, 0, NULL, 'ALTA', 'consulta general,medicina general,hospital,doctor general,gratis', 'Acude a la red autorizada con identificación y QR. Extras se pagan al hospital.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(28, 'Servicios', 'Consulta general costo', 'consulta_general', '¿La consulta general cuesta con PATS?', 'Con PATS vigente, la consulta de medicina general puede ser sin costo dentro de la red autorizada y con médicos afiliados al programa.', NULL, 0, NULL, 'ALTA', 'consulta general gratis,sin costo,medicina general,pago consulta', 'La consulta general puede ser sin costo dentro de la red autorizada.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(29, 'Servicios', 'Urgencias', 'urgencias', '¿Cómo uso PATS en urgencias?', 'Para consulta de urgencias, acude al hospital dentro de la red autorizada y presenta identificación oficial y QR o pasaporte digital. Si se genera un procedimiento, insumo o medicamento adicional, el costo se paga directamente al hospital.', NULL, 0, NULL, 'ALTA', 'urgencias,emergencia,hospital,consulta urgencias,qr', 'Acude a urgencias dentro de la red autorizada con identificación y QR.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(30, 'Servicios', 'Urgencias costo', 'urgencias', '¿La consulta de urgencias es gratis con PATS?', 'Con PATS vigente, la consulta de urgencias puede ser sin costo dentro de la red autorizada. Sin embargo, procedimientos, insumos, medicamentos u otros servicios derivados pueden tener costo preferencial y pagarse directamente al hospital.', NULL, 0, NULL, 'ALTA', 'urgencias gratis,consulta urgencias sin costo,procedimientos urgencias,insumos urgencias', 'La consulta puede ser sin costo; extras se pagan al hospital.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(31, 'Servicios', 'Procedimientos en urgencias', 'urgencias', '¿Qué pasa si en urgencias necesito un procedimiento?', 'Si durante la atención de urgencias se requiere un procedimiento, insumo, medicamento o servicio adicional, el costo se paga directamente al hospital y debe revisarse conforme a la lista de precios preferenciales aplicable.', NULL, 0, NULL, 'ALTA', 'procedimiento urgencias,insumo,medicamento extra,pagar hospital,precio preferencial', 'Los procedimientos o extras derivados se pagan al hospital.', 0, 0, 95, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(32, 'Servicios', 'Especialistas agenda', 'especialistas', '¿Cómo agendo una consulta con especialista?', 'Para consulta de especialidad debes agendar por la app oficial o por medios autorizados PATS. Espera confirmación del médico y preséntate 10 minutos antes en la ubicación autorizada.', NULL, 0, NULL, 'ALTA', 'especialista,agenda,cita,medico,confirmacion,consultorio,10 minutos', 'Agenda por medios oficiales y espera confirmación del médico.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(33, 'Servicios', 'Especialistas red', 'especialistas', '¿Puedo ir con cualquier especialista?', 'No. Para obtener precio preferencial, el especialista debe estar dentro de la red médica PATS. Verifica siempre en la app oficial o con medios autorizados antes de acudir.', NULL, 0, NULL, 'ALTA', 'cualquier especialista,medico fuera red,red medica,especialista afiliado', 'Debes acudir con especialistas dentro de la red PATS.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(34, 'Servicios', 'Especialistas pago', 'especialistas', '¿Dónde pago la consulta de especialidad?', 'La consulta de especialidad se paga directamente al médico al terminar la consulta. Si se realiza algún procedimiento en consultorio, el costo debe coincidir con la lista de precios para usuarios PATS.', NULL, 0, NULL, 'ALTA', 'pagar especialista,pago medico,consulta especialidad,procedimiento consultorio', 'La consulta de especialidad se paga directamente al médico.', 0, 0, 95, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(35, 'Servicios', 'Especialistas costo', 'especialistas', '¿Cuánto cuesta una consulta de especialidad con PATS?', 'El manual indica consulta de especialidad con precio preferencial. Para confirmar el costo vigente, verifica la lista oficial de precios PATS en la app o con personal autorizado antes de acudir.', NULL, 0, NULL, 'ALTA', 'precio especialista,costo especialidad,consulta especialista,390,tabulador', 'Confirma el costo vigente en la lista oficial de precios PATS.', 0, 0, 90, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(36, 'Servicios', 'Procedimiento consultorio', 'especialistas', '¿Qué pasa si el especialista hace un procedimiento en consultorio?', 'Si se realiza un procedimiento en consultorio, el costo debe coincidir con la lista de precios para usuarios PATS. Confirma el costo antes de realizar el procedimiento.', NULL, 0, NULL, 'ALTA', 'procedimiento consultorio,especialista,costo procedimiento,lista precios', 'El procedimiento debe coincidir con la lista de precios PATS.', 0, 0, 95, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(37, 'Servicios', 'Laboratorio agenda', 'laboratorio', '¿Cómo uso PATS para laboratorio?', 'Para estudios de laboratorio debes agendar por la app oficial o medios autorizados PATS, esperar confirmación y acudir 10 minutos antes a la sucursal correspondiente. Presenta identificación oficial y QR.', NULL, 0, NULL, 'ALTA', 'laboratorio,analisis,estudios clinicos,agenda,cita,sucursal,10 minutos', 'Agenda por medios oficiales, confirma sucursal y acude con identificación y QR.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(38, 'Servicios', 'Laboratorio red', 'laboratorio', '¿Puedo ir a cualquier laboratorio?', 'No. Para aplicar beneficios o precios preferenciales, el laboratorio debe estar dentro de la red PATS. Verifica la red autorizada antes de acudir.', NULL, 0, NULL, 'ALTA', 'cualquier laboratorio,laboratorio fuera red,red laboratorio,autorizado', 'Debes acudir a laboratorios dentro de la red PATS.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(39, 'Servicios', 'Laboratorio pago', 'laboratorio', '¿Dónde pago los estudios de laboratorio?', 'Los estudios de laboratorio se pagan directamente al laboratorio o prestador autorizado, conforme a la lista de precios preferenciales vigente.', NULL, 0, NULL, 'ALTA', 'pago laboratorio,donde pago laboratorio,estudios laboratorio,precio laboratorio', 'Se pagan directamente al laboratorio autorizado.', 0, 0, 95, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(40, 'Servicios', 'Imagenología agenda', 'imagenologia', '¿Cómo uso PATS para imagenología o rayos X?', 'Para imagenología, rayos X u otros estudios de imagen debes agendar por la app oficial o medios autorizados PATS, esperar confirmación y acudir 10 minutos antes a la ubicación correspondiente.', NULL, 0, NULL, 'ALTA', 'imagenologia,rayos x,ultrasonido,tomografia,resonancia,agenda', 'Agenda el estudio de imagen por medios oficiales y confirma ubicación.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(41, 'Servicios', 'Imagenología red', 'imagenologia', '¿Puedo hacerme estudios de imagen en cualquier centro?', 'No. Para aplicar precio preferencial, el centro de imagenología o rayos X debe estar dentro de la red autorizada PATS.', NULL, 0, NULL, 'ALTA', 'centro imagen,cualquier centro,imagen fuera red,rayos x fuera red', 'Debes acudir a centros de imagen dentro de la red PATS.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(42, 'Servicios', 'Imagenología pago', 'imagenologia', '¿Dónde pago imagenología o rayos X?', 'Los estudios de imagenología o rayos X se pagan directamente al prestador autorizado correspondiente, conforme a la lista de precios preferenciales vigente.', NULL, 0, NULL, 'ALTA', 'pago imagen,pago rayos x,donde pago imagenologia,precio imagen', 'Se pagan directamente al prestador autorizado.', 0, 0, 95, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(43, 'Servicios', 'Farmacia general', 'farmacia', '¿Cómo uso PATS en farmacia?', 'Puedes adquirir medicamentos directamente en Farmacia PATS conforme al catálogo disponible y precios preferenciales aplicables. Presenta identificación oficial y QR cuando sea requerido.', NULL, 0, NULL, 'ALTA', 'farmacia,medicamentos,catalogo,comprar medicamentos,precio preferencial', 'Compra medicamentos en Farmacia PATS conforme al catálogo disponible.', 0, 0, 95, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(44, 'Servicios', 'Medicamento especialidad', 'farmacia', '¿Qué pasa si necesito medicamento de especialidad?', 'Para medicamentos de especialidad puede requerirse receta médica. El medicamento debe estar disponible conforme al catálogo o reglas vigentes de Farmacia PATS.', NULL, 0, NULL, 'ALTA', 'medicamento especialidad,receta,medicamento especial,requiere receta', 'Puede requerirse receta médica para medicamento de especialidad.', 0, 0, 95, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(45, 'Servicios', 'Farmacia pago', 'farmacia', '¿Dónde pago los medicamentos?', 'Los medicamentos se pagan directamente en Farmacia PATS o en el punto autorizado correspondiente.', NULL, 0, NULL, 'ALTA', 'pagar medicamento,pago farmacia,donde pago farmacia,medicamentos', 'Los medicamentos se pagan directamente en Farmacia PATS.', 0, 0, 90, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(46, 'Servicios', 'Medicamentos fuera catálogo', 'farmacia', '¿PATS cubre medicamentos fuera del catálogo?', 'No. El manual indica que PATS no incluye medicamentos fuera del catálogo de Farmacia PATS.', NULL, 0, NULL, 'ALTA', 'medicamento fuera catalogo,no esta catalogo,no incluye medicamento', 'No incluye medicamentos fuera del catálogo Farmacia PATS.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(47, 'Servicios', 'Hospitalización', 'hospitalizacion', '¿PATS incluye hospitalización?', 'La hospitalización no es gratuita. PATS puede otorgar precios preferenciales o descuentos en hospitalización dentro de la red autorizada. El pago se realiza directamente al hospital.', NULL, 0, NULL, 'ALTA', 'hospitalizacion,internamiento,hospital,precio preferencial,pago hospital', 'La hospitalización puede tener precio preferencial, pero no es gratuita.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(48, 'Servicios', 'Servicios hospitalarios', 'hospitalizacion', '¿Qué servicios hospitalarios pueden tener precio preferencial?', 'PATS puede ofrecer precio preferencial en servicios hospitalarios dentro de la red autorizada, como hospitalización, procedimientos, estudios, servicios derivados, quirófano o terapia intensiva, según tabulador vigente.', NULL, 0, NULL, 'ALTA', 'servicios hospitalarios,hospital,procedimientos,estudios,quirofano,terapia intensiva', 'Los servicios hospitalarios pueden tener precio preferencial según tabulador.', 0, 0, 95, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(49, 'Servicios', 'Cirugías', 'cirugia', '¿PATS cubre cirugías?', 'PATS no cubre cirugías como seguro médico. Puede darte acceso a precios preferenciales en cirugías o procedimientos en quirófano dentro de la red autorizada, siempre que cumplas las reglas de vigencia y uso establecidas.', NULL, 0, NULL, 'ALTA', 'cirugia,cubre cirugia,operacion,quirofano,procedimiento quirurgico,no seguro', 'PATS no cubre como seguro, pero puede dar precios preferenciales en cirugías autorizadas.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(50, 'Servicios', 'Quirófano', 'cirugia', '¿El uso de quirófano tiene descuento con PATS?', 'El uso de quirófano puede tener precio preferencial dentro de la red autorizada, sujeto al tabulador vigente, condiciones del servicio y reglas aplicables de PATS.', NULL, 0, NULL, 'ALTA', 'quirofano,uso quirofano,precio quirofano,descuento quirofano', 'Puede aplicar precio preferencial de quirófano según tabulador vigente.', 0, 0, 95, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(51, 'Servicios', 'Terapia intensiva', 'terapia_intensiva', '¿PATS cubre terapia intensiva?', 'PATS no cubre terapia intensiva como seguro. Puede otorgar acceso a precios preferenciales en terapia intensiva dentro de la red autorizada, sujeto a consumo y reglas del programa.', NULL, 0, NULL, 'ALTA', 'terapia intensiva,uci,uti,intensiva,cubre,precio preferencial', 'Puede aplicar precio preferencial, pero no cobertura como seguro.', 0, 0, 95, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(52, 'Servicios', 'Pago hospital', 'hospitalizacion', '¿Dónde pago hospitalización, cirugía o servicios hospitalarios?', 'Los servicios hospitalarios, hospitalización, procedimientos de urgencias, cirugías, quirófano o terapia intensiva se pagan directamente al hospital o prestador autorizado correspondiente.', NULL, 0, NULL, 'ALTA', 'pago hospital,donde pago hospitalizacion,cirugia,pagar quirofano,terapia intensiva', 'Se pagan directamente al hospital o prestador autorizado.', 0, 0, 95, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(53, 'Servicios', 'Regla cirugía vigencia', 'cirugia', '¿Qué requisitos debo cumplir para usar precios preferenciales en cirugía?', 'Para acceder a precios preferenciales en cirugías o procedimientos de quirófano debes tener PATS activo y vigente. También pueden aplicar reglas especiales de antigüedad, anualidad o pago completo según el caso. Confirma siempre con personal autorizado antes de programar.', NULL, 0, NULL, 'ALTA', 'requisitos cirugia,antiguedad,anualidad,pago completo,activo,vigente', 'Debes tener PATS activo y validar reglas especiales antes de cirugía.', 1, 1, 90, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(54, 'Precios', 'Costo por servicio', 'precios_servicios', '¿Cuánto cuesta cada servicio con PATS?', 'El costo depende del tipo de atención. Consulta general y urgencias pueden ser sin costo dentro de red. Otros servicios como especialistas, laboratorio, imagenología, farmacia, hospitalización, cirugía o terapia intensiva deben revisarse en la lista de precios preferenciales vigente.', NULL, 0, NULL, 'ALTA', 'cuanto cuesta servicio,precio servicio,tabulador,lista precios,costo final', 'Depende del servicio; revisa el tabulador vigente PATS.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(55, 'Precios', 'Confirmar costo final', 'precios_servicios', '¿Debo preguntar el costo antes del servicio?', 'Sí. Antes de recibir un servicio con precio preferencial, confirma el costo final con el prestador autorizado o personal PATS. Esto evita confusiones por procedimientos, insumos o medicamentos adicionales.', NULL, 0, NULL, 'ALTA', 'preguntar costo,costo final,antes del servicio,precio final,confirmar precio', 'Sí, confirma siempre el costo final antes del servicio.', 0, 0, 95, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(56, 'Precios', 'Precio no coincide', 'precios_servicios', '¿Qué hago si el precio no coincide con la lista PATS?', 'Si el precio informado no coincide con la lista de precios PATS, solicita revisión con Concierge PATS, admisión o personal autorizado antes de realizar el pago o recibir el servicio.', NULL, 0, NULL, 'ALTA', 'precio no coincide,me cobran mas,tabulador diferente,lista precios', 'Solicita revisión con personal autorizado antes de pagar.', 1, 1, 95, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(57, 'Uso', 'Uso ilimitado', 'uso_ilimitado', '¿Cuántas veces puedo usar PATS?', 'El manual indica que PATS tiene uso ilimitado y no considera preexistencias. Sin embargo, ciertos servicios como cirugías, terapia intensiva y algunas atenciones pueden estar sujetos a reglas especiales.', NULL, 0, NULL, 'ALTA', 'cuantas veces,uso ilimitado,limite,usar varias veces,preexistencias', 'PATS tiene uso ilimitado, pero algunos servicios tienen reglas especiales.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(58, 'Uso', 'Preexistencias', 'uso_ilimitado', '¿PATS tiene preexistencias?', 'El manual indica que PATS no tiene preexistencias. Aun así, recuerda que no es un seguro médico; los servicios aplican como beneficios o precios preferenciales dentro de la red autorizada.', NULL, 0, NULL, 'ALTA', 'preexistencias,enfermedad previa,padecimiento previo,no tiene preexistencias', 'El manual indica que PATS no tiene preexistencias.', 0, 0, 95, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(59, 'Exclusiones', 'No incluido', 'exclusiones', '¿Qué no incluye PATS?', 'PATS no incluye trasplantes, tratamientos experimentales, tratamientos oncológicos, hemodiálisis, medicamentos fuera del catálogo de Farmacia PATS, atención fuera de la red autorizada, especialistas fuera de la red, estudios fuera de red o cualquier servicio no indicado expresamente dentro del programa.', NULL, 0, NULL, 'ALTA', 'no incluye,no cubre,exclusiones,trasplantes,oncológicos,hemodialisis,experimental,fuera red', 'No incluye servicios fuera de red ni tratamientos excluidos como trasplantes, oncológicos o hemodiálisis.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(60, 'Exclusiones', 'Trasplantes', 'exclusiones', '¿PATS incluye trasplantes?', 'No. El manual indica que PATS no incluye trasplantes.', NULL, 0, NULL, 'ALTA', 'trasplante,trasplantes,transplante,no cubre trasplante', 'No. PATS no incluye trasplantes.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(61, 'Exclusiones', 'Oncología', 'exclusiones', '¿PATS incluye tratamientos oncológicos?', 'No. El manual indica que PATS no incluye tratamientos oncológicos.', NULL, 0, NULL, 'ALTA', 'oncologia,cancer,cáncer,tratamiento oncologico,quimioterapia', 'No. PATS no incluye tratamientos oncológicos.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(62, 'Exclusiones', 'Hemodiálisis', 'exclusiones', '¿PATS incluye hemodiálisis?', 'No. El manual indica que PATS no incluye hemodiálisis.', NULL, 0, NULL, 'ALTA', 'hemodialisis,diálisis,dialisis,riñon,renal', 'No. PATS no incluye hemodiálisis.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(63, 'Exclusiones', 'Experimental', 'exclusiones', '¿PATS incluye tratamientos experimentales?', 'No. El manual indica que PATS no incluye tratamientos experimentales.', NULL, 0, NULL, 'ALTA', 'tratamiento experimental,experimental,ensayo,protocolo experimental', 'No. PATS no incluye tratamientos experimentales.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(64, 'Exclusiones', 'Fuera de red', 'fuera_red', '¿Puedo usar PATS fuera de la red autorizada?', 'No. Los beneficios y precios preferenciales de PATS aplican dentro de la red autorizada. Atención fuera de red, médicos no afiliados o estudios fuera de red no forman parte de los beneficios.', NULL, 0, NULL, 'ALTA', 'fuera de red,otro hospital,otro medico,no afiliado,no autorizado', 'PATS aplica únicamente dentro de la red autorizada.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(65, 'Reglas especiales', 'Mayores de 65 años', 'mayores_65', '¿Qué pasa si tengo 65 años o más?', 'Si al momento de contratar tienes 65 años cumplidos, debes adquirir o incorporar a dos personas adicionales menores de esa edad. De lo contrario, PATS no podrá quedar activo y no podrás acceder a los servicios.', NULL, 0, NULL, 'ALTA', '65 años,mayor de 65,adulto mayor,dos personas adicionales,activar', 'Si tienes 65 años o más, debes incorporar dos personas adicionales menores de esa edad.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(66, 'Reglas especiales', 'Menores de edad', 'menores_dependientes', '¿Puede usar PATS un menor de edad?', 'Sí, pero si el usuario es menor de 18 años, el registro, uso de la app, pago y gestión de servicios estarán asignados a un padre, madre o tutor responsable.', NULL, 0, NULL, 'ALTA', 'menor,menores,menor de edad,18 años,tutor,padre,madre', 'Sí, pero debe gestionarlo un padre, madre o tutor responsable.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(67, 'Reglas especiales', 'Dependientes', 'menores_dependientes', '¿Qué pasa si el usuario es dependiente?', 'Si el usuario es dependiente, la gestión del registro, app, pagos y servicios debe estar asignada a la persona responsable correspondiente.', NULL, 0, NULL, 'ALTA', 'dependiente,usuario dependiente,tutor,responsable,familiar', 'Un usuario dependiente debe ser gestionado por su responsable.', 0, 0, 90, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(68, 'Responsabilidad', 'Responsabilidad médica', 'responsabilidad_medica', '¿PATS es responsable de la atención médica?', 'PATS administra el programa de beneficios, pero la atención médica la presta directamente el profesional de salud, hospital, laboratorio, farmacia o prestador correspondiente. La responsabilidad de la calidad, resultado o consecuencias del servicio corresponde al prestador del servicio.', NULL, 0, NULL, 'ALTA', 'responsabilidad medica,doctor,hospital,resultado,calidad,negligencia,prestador', 'La atención médica la presta directamente el profesional o institución correspondiente.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(69, 'Responsabilidad', 'Queja médica', 'responsabilidad_medica', '¿Qué hago si tengo una queja sobre la atención médica?', 'Si tienes una queja sobre la atención médica recibida, debes reportarla al prestador del servicio y también puedes informar a Concierge PATS o personal autorizado para orientación y seguimiento administrativo.', NULL, 0, NULL, 'ALTA', 'queja médica,mal servicio,doctor,hospital,reclamo,atencion medica', 'Reporta la queja al prestador y avisa a personal autorizado PATS.', 1, 1, 85, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(70, 'Cancelación', 'Cancelar PATS', 'cancelacion', '¿Puedo cancelar PATS?', 'La cancelación del contrato PATS puede realizarse mediante aviso por escrito con 30 días de anticipación. La cancelación aplica para el siguiente periodo mensual y no hay reembolso de pagos ya realizados.', NULL, 0, NULL, 'ALTA', 'cancelar,cancelacion,baja,aviso,30 dias,reembolso', 'Sí, con aviso por escrito de 30 días. No hay reembolso de pagos realizados.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(71, 'Cancelación', 'No reembolso', 'cancelacion', '¿PATS devuelve dinero si cancelo?', 'No. El manual indica que no hay reembolso de pagos ya realizados.', NULL, 0, NULL, 'ALTA', 'reembolso,devolucion,me regresan dinero,cancelar devolver', 'No hay reembolso de pagos ya realizados.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(72, 'Cancelación', 'Terminación contrato', 'cancelacion', '¿Cómo puede terminar el contrato PATS?', 'El contrato puede terminar por falta de pago, acuerdo por escrito entre las partes o incumplimiento de alguna cláusula. En caso de terminación, no hay devolución de dinero.', NULL, 0, NULL, 'ALTA', 'terminar contrato,contrato,falta de pago,incumplimiento,acuerdo escrito', 'Puede terminar por falta de pago, acuerdo escrito o incumplimiento.', 0, 0, 95, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(73, 'Cancelación', 'Comprar otro PATS', 'cancelacion', '¿Puedo comprar otro PATS si cancelé o venció el anterior?', 'El manual indica que PATS es personal, exclusivo e intransferible. Si queda vencido, debe revisarse la reactivación bajo las condiciones correspondientes, no tratarse como un pasaporte nuevo para evadir adeudos.', NULL, 0, NULL, 'ALTA', 'comprar otro pats,nuevo pasaporte,vencido,reactivar,adeudo', 'Si venció, debe revisarse reactivación bajo las condiciones aplicables.', 1, 1, 90, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(74, 'Privacidad', 'Datos personales', 'privacidad', '¿Qué pasa con mis datos personales?', 'PATS indica que protege los datos personales mediante medidas como cifrado, firewalls, actualizaciones de seguridad y políticas de privacidad. También permite ejercer derechos ARCO: Acceso, Rectificación, Cancelación y Oposición.', NULL, 0, NULL, 'ALTA', 'datos personales,privacidad,cifrado,firewall,arco,lfpdppp,proteccion', 'PATS protege datos personales y permite ejercer derechos ARCO.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(75, 'Privacidad', 'Derechos ARCO', 'privacidad', '¿Qué son los derechos ARCO?', 'Los derechos ARCO permiten solicitar Acceso, Rectificación, Cancelación u Oposición respecto al uso de datos personales, conforme a la normativa aplicable en México.', NULL, 0, NULL, 'ALTA', 'arco,acceso,rectificacion,cancelacion,oposicion,derechos datos', 'ARCO significa Acceso, Rectificación, Cancelación y Oposición.', 0, 0, 95, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(76, 'Privacidad', 'Seguridad datos', 'privacidad', '¿Cómo protege PATS mi información?', 'PATS indica medidas de seguridad como cifrado de datos, firewalls, actualizaciones constantes y políticas de privacidad para proteger información almacenada y en tránsito.', NULL, 0, NULL, 'ALTA', 'cifrado,encriptacion,firewall,seguridad datos,protege informacion', 'Usa medidas como cifrado, firewalls y políticas de privacidad.', 0, 0, 90, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(77, 'Recomendaciones', 'Uso correcto', 'recomendaciones', '¿Qué recomendaciones debo seguir para usar PATS?', 'Para aprovechar PATS, paga dentro de los primeros 5 días de cada mes, agenda por medios oficiales, verifica que el médico o servicio esté dentro de la red, lleva identificación y QR, pregunta el costo final antes del servicio y mantén actualizados tus datos.', NULL, 0, NULL, 'ALTA', 'recomendaciones,consejos,usar bien,pagar a tiempo,medios oficiales,red,qr,costo final', 'Paga a tiempo, agenda por medios oficiales, verifica red y lleva identificación y QR.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(78, 'Recomendaciones', 'Verificar red', 'recomendaciones', '¿Por qué debo verificar la red antes de atenderme?', 'Debes verificar la red porque los beneficios y precios preferenciales aplican únicamente con prestadores autorizados PATS. Si acudes fuera de red, los beneficios pueden no aplicar.', NULL, 0, NULL, 'ALTA', 'verificar red,red autorizada,medico afiliado,prestador autorizado,fuera de red', 'Porque los beneficios aplican únicamente dentro de red autorizada.', 0, 0, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(79, 'Recomendaciones', 'Actualizar datos', 'recomendaciones', '¿Debo actualizar mis datos en la app?', 'Sí. Si cambias domicilio, correo, teléfono u otros datos, debes actualizarlos en tu perfil de la app oficial o solicitar apoyo a personal autorizado.', NULL, 0, NULL, 'ALTA', 'actualizar datos,cambiar domicilio,cambiar telefono,cambiar correo,perfil', 'Sí, mantén tus datos actualizados.', 1, 1, 90, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(80, 'Canalización', 'Duda no resuelta', 'canalizar', '¿Qué hago si mi duda no aparece en el manual?', 'Si la duda no aparece claramente en el manual o requiere revisar tu estatus, pago, red, tabulador o caso particular, debe canalizarse con Concierge PATS, admisión o personal autorizado.', NULL, 0, NULL, 'ALTA', 'duda,no aparece,no se,caso especial,concierge,admision,soporte', 'Canaliza la duda con Concierge PATS o personal autorizado.', 1, 1, 95, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(81, 'Canalización', 'Validación por admisión', 'canalizar', '¿Qué debe validar admisión antes de aplicar beneficios PATS?', 'Admisión o concierge debe validar que el usuario esté activo, que presente identificación y QR, que el prestador esté dentro de la red autorizada y que el servicio corresponda al tabulador o beneficio vigente.', NULL, 0, NULL, 'ALTA', 'admision,validar,activo,qr,identificacion,red,tabulador,concierge', 'Validar activo, identificación, QR, red autorizada y tabulador aplicable.', 1, 1, 100, 1, 'MANUAL_USUARIO_PATS_COMPLETO', 'PATS_MANUAL_2026', 'GENERAL', '2026-04-27 19:59:57', '2026-04-27 19:59:57');

