--
-- Volcado de datos para la tabla `pats_bot_rules`
--

INSERT INTO `pats_bot_rules` (`id`, `rule_key`, `nombre`, `descripcion`, `tipo`, `config_json`, `activo`, `created_at`, `updated_at`) VALUES
(1, 'calculo_reactivacion_mensual', 'Cálculo de reactivación mensual', 'Calcula adeudo estimado por mensualidades vencidas, mensualidad vigente y cuota de reactivación.', 'CALCULO', '{\"moneda\": \"MXN\", \"formula\": \"meses_vencidos * 800 + mensualidad_vigente + meses_vencidos * 100\", \"mensualidad\": 800, \"cuota_reactivacion_mes\": 100}', 1, '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(2, 'validar_no_seguro', 'Aclaración obligatoria: PATS no es seguro', 'Cuando el usuario use palabras como seguro, póliza, cobertura o cubre, aclarar que PATS no es seguro médico.', 'RESPUESTA_DINAMICA', '{\"mensaje_base\": \"PATS no es un seguro médico; es un programa de beneficios, descuentos y precios preferenciales dentro de la red autorizada.\"}', 1, '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(3, 'validar_red_autorizada', 'Validación de red autorizada', 'Antes de confirmar un servicio, debe validarse que el médico, hospital, laboratorio, imagenología o farmacia esté dentro de la red autorizada PATS.', 'VALIDACION', '{\"requiere_validar_red\": true}', 1, '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(4, 'validar_estatus_activo', 'Validación de estatus activo', 'Para usar beneficios, debe validarse que el usuario tenga PATS activo y vigente.', 'VALIDACION', '{\"requiere_estatus_activo\": true}', 1, '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(5, 'validar_mayor_65', 'Regla mayores de 65 años', 'Usuarios de 65 años o más requieren incorporar dos personas adicionales menores de esa edad.', 'VALIDACION', '{\"edad_minima_regla\": 65, \"personas_adicionales_requeridas\": 2}', 1, '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(6, 'validar_menor_dependiente', 'Regla menores o dependientes', 'Menores de edad o dependientes requieren padre, madre o tutor responsable.', 'VALIDACION', '{\"edad_mayoria\": 18, \"requiere_tutor\": true}', 1, '2026-04-27 19:59:57', '2026-04-27 19:59:57'),
(7, 'validar_tabulador', 'Validación de tabulador PATS', 'Antes de confirmar precio, debe consultarse tabulador vigente o lista oficial autorizada.', 'VALIDACION', '{\"requiere_tabulador_vigente\": true}', 1, '2026-04-27 19:59:57', '2026-04-27 19:59:57');

