INSERT INTO `pats_contratos_firmados` (`id_contrato_firmado`, `id_orden`, `id_pasaporte`, `id_distribuidor`, `id_franquicia`, `token_publico`, `contrato_clave`, `contrato_version`, `html_contrato_renderizado`, `firma_afiliado_base64`, `nombre_firmante`, `hash_contrato`, `fecha_firma`, `ip_firma`, `user_agent_firma`, `pdf_path`, `estatus`, `created_at`, `updated_at`) VALUES
(1, 2, NULL, 0, 0, '', 'contrato_pats_base', '1.0', '<style>\r\n  .pats-contract{font-family:Arial,Helvetica,sans-serif;color:#172033;font-size:12px;line-height:1.52;background:#fff;padding:4px}\r\n  .pats-contract h1,.pats-contract h2,.pats-contract h3,.pats-contract h4{text-align:center;margin:12px 0 8px;color:#0d1b3e}\r\n  .pats-contract h1{font-size:16px;text-transform:uppercase;letter-spacing:.05em}\r\n  .pats-contract h2{font-size:15px;text-transform:uppercase;letter-spacing:.04em}\r\n  .pats-contract h3{font-size:13px;text-transform:uppercase;letter-spacing:.08em}\r\n  .pats-contract h4{font-size:12px;text-align:left;text-transform:uppercase;margin-top:12px}\r\n  .pats-contract p{margin:6px 0;text-align:justify}\r\n  .pats-contract ul{margin:6px 0 8px 18px;padding:0}.pats-contract li{margin:4px 0;text-align:justify}\r\n  .pats-contract table{width:100%;border-collapse:collapse;margin:8px 0 12px}.pats-contract th,.pats-contract td{border:1px solid #cbd5e1;padding:6px;vertical-align:top}.pats-contract th{background:#eef4ff;color:#0d1b3e;text-align:left}\r\n  .pats-contract .center{text-align:center}.pats-contract .muted{color:#64748b}.pats-contract .small{font-size:10px}.pats-contract .badge{display:inline-block;padding:3px 8px;border-radius:999px;background:#eef4ff;color:#1d4ed8;font-weight:700;margin:2px 4px 2px 0}\r\n  .pats-contract .sign-grid{display:grid;grid-template-columns:1fr 1fr;gap:22px;margin-top:28px}.pats-contract .sign-box{text-align:center;min-height:95px}.pats-contract .line{border-top:1px solid #0f172a;margin:48px 8px 6px}.pats-contract .signature-img{max-width:220px;max-height:82px;display:block;margin:0 auto 4px}\r\n  .pats-contract .annex{page-break-before:auto;border-top:2px solid #0d1b3e;margin-top:18px;padding-top:12px}.pats-contract .page-break{page-break-before:always;border-top:1px dashed #cbd5e1;margin-top:18px;padding-top:12px}\r\n</style>\r\n<div class=\"pats-contract\">\r\n  <h1>Carátula del contrato de adquisición de tarjeta de descuento</h1>\r\n  <p>CARÁTULA DEL CONTRATO DE ADQUISICIÓN DE TARJETA DE DESCUENTO (EN LO SUCESIVO “LA CARÁTULA”), QUE CELEBRAN POR UNA PARTE LA SOCIEDAD SEÑALADA EN EL APARTADO 1.- DE LA CARÁTULA, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL PRESTADOR”, REPRESENTADA EN ESTE ACTO POR LA PERSONA FÍSICA QUE SE INDICA EN EL APARTADO 2.- DE LA CARÁTULA; Y POR LA OTRA PARTE, LA PERSONA FÍSICA SEÑALADA EN EL APARTADO 5.- DE LA CARÁTULA, POR SU PROPIO DERECHO, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL AFILIADO”; Y CUANDO LOS ANTES NOMBRADOS ACTÚEN DE MANERA CONJUNTA, SE LES DENOMINARÁ COMO “LAS PARTES”; QUIENES SE SUJETAN AL TENOR DE LA CARÁTULA, DECLARACIONES Y CLÁUSULAS SIGUIENTES:</p>\r\n    \r\n  <h2>C A R Á T U L A</h2>\r\n  <table>\r\n    <tr><th style=\"width:8%\">Apartado</th><th style=\"width:42%\">Definición</th><th>Respuesta</th></tr>\r\n    <tr><td>1.-</td><td>Nombre de “EL PRESTADOR”</td><td>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE</td></tr>\r\n    <tr><td>2.-</td><td>Nombre del Representante Legal de “EL PRESTADOR”</td><td>PEDRO AZCÁRRAGA RAMOS</td></tr>\r\n    <tr><td>3.-</td><td>Domicilio de “EL PRESTADOR”</td><td>CALLE PASEO SINFONÍA NÚMERO EXTERIOR 1, LOCAL 2-14, LOMAS DE ANGELÓPOLIS II, SAN ANDRÉS CHOLULA, ESTADO DE PUEBLA, CÓDIGO POSTAL 72830</td></tr>\r\n    <tr><td>4.-</td><td>Clave del Registro Federal de Contribuyentes de “EL PRESTADOR”</td><td>COH2202144H5</td></tr>\r\n    <tr><td>5.-</td><td>Nombre de “EL AFILIADO”</td><td>Mateo Miranda Casas</td></tr>\r\n    <tr><td>6.-</td><td>Domicilio de “EL AFILIADO”</td><td>Jornal 115, Col. zapopan, C.P. 45255, cholula, Jalisco, México</td></tr>\r\n    <tr><td>7.-</td><td>Clave del Registro Federal de Contribuyentes de “EL AFILIADO”</td><td>GFDGSDFG</td></tr>\r\n    <tr><td>8.-</td><td>Costo mensual de “LA TARJETA DE DESCUENTO”</td><td>$800.00 M.N.</td></tr>\r\n    <tr><td>9.-</td><td>Cuenta bancaria de “EL PRESTADOR” para pagos</td><td>Cuenta: 01600866709<br>CLABE: 042650016008667096<br>Institución Bancaria: Banca Mifel, S.A., Institución de Banca Múltiple, Grupo Financiero Mifel</td></tr>\r\n    <tr><td>10.-</td><td>Cuota de Reactivación de “LA TARJETA DE DESCUENTO”</td><td>$100.00 M.N. por cada mes que se haya interrumpido el pago.</td></tr>\r\n    <tr><td>11.-</td><td>Datos de la Tarjeta de Crédito de “EL AFILIADO”</td><td>Número de tarjeta: pendiente de confirmar por pasarela/token de pago.<br>Institución bancaria: pendiente de confirmar por pasarela. <br><span class=\"small\">No se almacena número completo de tarjeta en este formulario.</span></td></tr>\r\n    <tr><td>12.-</td><td>Anexos</td><td>ANEXO 1. Identificación oficial de “EL AFILIADO”<br>ANEXO 2. Comprobante de domicilio de “EL AFILIADO”<br>ANEXO 3. Constancia de Situación Fiscal de “EL AFILIADO”, si aplica<br>ANEXO 4. Cuotas de recuperación y/o precios base a cubrir a “EL PRESTADOR”<br>ANEXO 5. Aviso de privacidad<br>ANEXO 6. Declaración de dueño beneficiario</td></tr>\r\n    <tr><td>13.-</td><td>Fecha de Firma del Contrato</td><td>12 de mayo de 2026</td></tr>\r\n  </table>\r\n\r\n  <div class=\"sign-grid\">\r\n    <div class=\"sign-box\"><div class=\"line\"></div><strong>“EL PRESTADOR”</strong><br>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE<br>Representada por PEDRO AZCÁRRAGA RAMOS</div>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>“EL AFILIADO”</strong><br>Mateo Miranda Casas<br><span class=\"small\">La persona física señalada en el Apartado 5.- de la Carátula</span></div>\r\n  </div>\r\n\r\n  <div class=\"page-break\"></div>\r\n  <h1>Contrato de adquisición de tarjeta de descuento</h1>\r\n  <p>CONTRATO DE ADQUISICIÓN DE TARJETA DE DESCUENTO, QUE CELEBRAN POR UNA PARTE LA SOCIEDAD SEÑALADA EN EL APARTADO 1.- DE LA CARÁTULA, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL PRESTADOR”, REPRESENTADA EN ESTE ACTO POR LA PERSONA FÍSICA QUE SE INDICA EN EL APARTADO 2.- DE LA CARÁTULA; Y POR LA OTRA PARTE, LA PERSONA FÍSICA SEÑALADA EN EL APARTADO 5.- DE LA CARÁTULA, POR SU PROPIO DERECHO, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL AFILIADO”; Y CUANDO LOS ANTES NOMBRADOS ACTÚEN DE MANERA CONJUNTA, SE LES DENOMINARÁ COMO “LAS PARTES”; QUIENES SE SUJETAN AL TENOR DE LAS DECLARACIONES Y CLÁUSULAS SIGUIENTES:</p>\r\n\r\n  <h2>D E C L A R A C I O N E S</h2>\r\n  <h4>I.- Declara “EL PRESTADOR” por conducto de su representación:</h4>\r\n  <p>A. Que, su representada es una sociedad mercantil constituida conforme a las leyes de los Estados Unidos Mexicanos, según consta en la escritura pública número 39,861, del volumen 830 de fecha catorce de febrero de dos mil veintidós, otorgada ante la fe del Licenciado Ernesto Joaquín Briones Amador, Notario Público Titular de la Notaría Pública número 46 de las del Distrito Judicial de Puebla, Estado de Puebla, cuyo primer testimonio se encuentra inscrito ante las oficinas del Registro Público de Comercio del Distrito Judicial de Puebla, Estado de Puebla, bajo el Folio Mercantil Electrónico: N-2022022991, por virtud del cual se llevó a cabo la Constitución de la persona moral denominada CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE.</p>\r\n  <p>B. Que, la persona física que la representa en este acto, señalada en el Apartado 2.- de la Carátula, cuenta con todas y cada una de las facultades necesarias para la celebración del presente contrato, las cuales se desprenden del instrumento descrito en el punto declarativo inmediato anterior, mismas que manifiesta bajo protesta de decir verdad que no le han sido suspendidas, revocadas o limitadas en forma alguna.</p>\r\n  <p>C. Que, su representada tiene como domicilio fiscal el señalado en el Apartado 3.- de la Carátula del presente contrato, mismo que designa como domicilio convencional para cualquier cuestión relacionada con la celebración del presente contrato.</p>\r\n  <p>D. Que, su representada se encuentra inscrita en el Registro Federal de Contribuyentes bajo la clave señalada en el Apartado 4.- de la Carátula.</p>\r\n  <p>E. Que, ha desarrollado y es su deseo comparecer a la celebración del presente instrumento con la finalidad de enajenar en favor de “EL AFILIADO”, una Tarjeta de Descuento que da acceso a “UN PROGRAMA DE BENEFICIOS QUE OTORGA DESCUENTOS A LOS COSTOS Y PERMITE RECIBIR SERVICIOS MÉDICOS PRIVADOS DE ALTA CALIDAD DE FORMA ACCESIBLE, CLARA Y SIN RESTRICCIONES DENTRO DE LA RED DE HOSPITALES 50 (FIFTY) DOCTORS CON SEDE EN EL ESTADO DE PUEBLA”, en lo sucesivo “LA TARJETA DE DESCUENTO”, en los términos y condiciones que se establecerán más adelante.</p>\r\n  <p>F. Que, su representada no es una Aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas sino una empresa dedicada, entre otros, a la operación y administración de establecimientos destinados a la atención y asistencia de enfermos, por lo que la enajenación de “LA TARJETA DE DESCUENTO” únicamente constituye un acto de comercio que brindará a “EL AFILIADO” acceso a un programa de beneficios como ha quedado descrito anteriormente.</p>\r\n\r\n  <h4>II.- Declara “EL AFILIADO”, por su propio derecho:</h4>\r\n      <p>A. Que, su nombre se señala en el Apartado 5.- de la Carátula, es una persona física de nacionalidad mexicana, en pleno ejercicio de sus derechos, legal y jurídicamente capaz para celebrar el presente Contrato, quien se identifica con credencial para votar vigente expedida por el Instituto Nacional Electoral, tipo INE, número GGFADGFADGDA, que en copia simple o archivo digital se agrega al cuerpo del presente contrato como ANEXO 1.</p>\r\n    <p>B. Que, tiene como domicilio particular el señalado en el Apartado 6.- de la Carátula, mismo que designa como domicilio convencional para cualquier cuestión relacionada con la celebración del presente contrato, tal y como lo acredita con el comprobante de domicilio que en copia simple o archivo digital se agrega al cuerpo del presente contrato como ANEXO 2.</p>\r\n  <p>C. Que, su CURP es DDDDDDD y su RFC/identificación fiscal es GFDGSDFG; asimismo manifiesta que cuenta con capacidad económica para obligarse en términos del presente contrato y que los recursos con los que cubrirá sus obligaciones provendrán de fuentes lícitas. En caso de nacionalidad extranjera/no mexicana, se tendrán por no aplicables CURP, INE y constancia fiscal mexicana salvo manifestación expresa de residencia fiscal o RFC mexicano.</p>\r\n  <p>D. Que, es su deseo comparecer a la celebración del presente instrumento con la finalidad de adquirir “LA TARJETA DE DESCUENTO” de acuerdo con los términos y condiciones que se establecen a continuación.</p>\r\n  <p>E. Que, previo a la celebración del presente contrato fue informado y manifiesta expresamente que reconoce que “EL PRESTADOR” no es una Aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas y que las actividades comerciales objeto del presente contrato no consisten en la contratación de un seguro, de la índole que fuere, sino que únicamente implica la adquisición de una tarjeta de descuento que da acceso a un programa de beneficios que otorga descuentos a los costos y permite recibir servicios médicos privados de alta calidad de forma accesible, clara y sin restricciones dentro de la red de hospitales 50 (FIFTY) Doctors con sede en el Estado de Puebla.</p>\r\n  <p>F. Que, reconoce que “EL PRESTADOR” se dedica a la operación de centros hospitalarios y que la emisión de “LA TARJETA DE DESCUENTO” únicamente corresponde a la intención de este último de crear un programa de descuentos para el acceso a los servicios prestados por la Red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla.</p>\r\n\r\n  <h4>III.- Declaran conjuntamente “LAS PARTES”:</h4>\r\n  <p>1. Que, se reconocen recíprocamente la personalidad con la que comparecen a la celebración del presente acuerdo de voluntades.</p>\r\n  <p>2. Que, el presente contrato es el instrumento que las vincula en sus derechos y obligaciones.</p>\r\n  <p>3. Que, es su deseo celebrar el presente contrato y han negociado libremente los términos y condiciones del mismo con pleno conocimiento de sus alcances e implicaciones jurídicas, por lo que en su celebración no existe dolo, error, mala fe, lesión o cualquier otro vicio del consentimiento que pudiese afectarlo de inexistencia o nulidad.</p>\r\n\r\n  <h2>C L Á U S U L A S</h2>\r\n  <h4>PRIMERA.- OBJETO.</h4>\r\n  <p>El objeto del presente Contrato es que “EL AFILIADO” adquiera de “EL PRESTADOR”, a título oneroso y temporal, el derecho de uso ilimitado y sin restricción alguna de “LA TARJETA DE DESCUENTO” emitida por CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE, la cual consiste en que “EL AFILIADO” aproveche y acceda a “UN PROGRAMA DE BENEFICIOS QUE OTORGA DESCUENTOS A LOS COSTOS Y PERMITE RECIBIR SERVICIOS MÉDICOS PRIVADOS DE ALTA CALIDAD DE FORMA ACCESIBLE, CLARA Y SIN RESTRICCIONES DENTRO DE LA RED DE HOSPITALES 50 (FIFTY) DOCTORS CON SEDE EN EL ESTADO DE PUEBLA”.</p>\r\n  <p>Estableciendo que, la comercialización de “LA TARJETA DE DESCUENTO” por parte de “EL PRESTADOR” en ningún momento constituirá la venta, promoción o por cualquier medio la contratación de una póliza de seguro, bajo el entendido de que “EL PRESTADOR” no es una aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas (CNSF); sino que comercializa “LA TARJETA DE DESCUENTO” en favor de terceros con la finalidad de otorgar descuentos a los precios respecto de los servicios médicos que presta en el territorio nacional.</p>\r\n\r\n  <h4>SEGUNDA.- PRECIO DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“LAS PARTES” establecen de común acuerdo que “LA TARJETA DE DESCUENTO” tendrá como costo mensual la cantidad señalada en el Apartado 8.- de la Carátula del presente contrato; cantidad que ya incluye IVA, y la cual deberá ser cubierta por “EL AFILIADO” en favor de “EL PRESTADOR” dentro de los primeros 5 (cinco) días de cada mes, sin necesidad de gestiones o avisos de cobro, ya sea mediante:</p>\r\n  <p>(i) Transferencia electrónica de fondos a la cuenta bancaria señalada en el Apartado 9.- de la Carátula del presente contrato y de la cual es titular “EL PRESTADOR”.</p>\r\n  <p>(ii) Cheque que se recibirá salvo buen cobro en el Domicilio de “EL PRESTADOR” señalado en el Apartado 3.- de la Carátula del presente contrato, y que en caso de no ser pagado por falta de fondos suficientes o por otras causas imputables a “EL AFILIADO”, éste último está de acuerdo en que deberá cubrir a “EL PRESTADOR” el 20% (veinte por ciento) del monto del cheque por concepto de indemnización por daños y perjuicios en términos del artículo 193 de la Ley General de Títulos y Operaciones de Crédito, independientemente de cualquier otro cargo que se pudiera generar.</p>\r\n  <p>(iii) Cargos mensuales automáticos recurrentes a la tarjeta de crédito de “EL AFILIADO” según los datos señalados en el Apartado 11.- de la Carátula del presente contrato, quien manifiesta bajo protesta de decir verdad que autoriza a “EL PRESTADOR” a realizar los cargos mensuales correspondientes por el costo mensual de “LA TARJETA DE DESCUENTO” en dicha tarjeta o en la tarjeta que por renovación, reposición, robo o extravío le haya asignado el banco emisor. La autorización estará vigente mientras “EL AFILIADO” no haya notificado a “EL PRESTADOR” por escrito y con acuse de recibo su deseo de cancelar su afiliación o no renovarla, o en su defecto, realizar su baja respectiva en el sitio web o aplicación de “EL PRESTADOR”.</p>\r\n  <p>Esta autorización no exime a “EL AFILIADO” del pago mensual por el uso de “LA TARJETA DE DESCUENTO” y demás obligaciones contractuales, por lo que, en caso de que el cobro no sea autorizado por el banco emisor o por cualquier razón no pueda realizarse, “EL AFILIADO” deberá notificar tal situación a “EL PRESTADOR” a la dirección de correo electrónico silvia@pasaporteatusalud.com, a efecto de solicitar una forma de pago diversa, quedando obligado a cubrir de inmediato el pago correspondiente.</p>\r\n  <p>(iv) Cualquier otro medio de pago aceptado por “EL PRESTADOR”, mismo que se dará a conocer a través de sus medios oficiales de comunicación.</p>\r\n  <p>“EL PRESTADOR” podrá variar unilateralmente el costo mensual de “LA TARJETA DE DESCUENTO”, previo aviso a “EL AFILIADO” con 30 (treinta) días de anticipación a través de sus medios oficiales de comunicación.</p>\r\n  <p>Para el caso de que “EL AFILIADO” adquiera y cubra el precio de “LA TARJETA DE DESCUENTO” y posteriormente deje de pagar una mensualidad, deberá cubrir a “EL PRESTADOR”, por concepto de cuota de reactivación, la cantidad señalada en el Apartado 10.- de la Carátula por cada mes que haya interrumpido y/o no haya cubierto el precio de “LA TARJETA DE DESCUENTO”, hasta la fecha en que pretenda volver a adquirirla.</p>\r\n\r\n  <h4>TERCERA.- VIGENCIA DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“LA TARJETA DE DESCUENTO” objeto del presente contrato tendrá una vigencia de 30 días contados a partir de que “EL AFILIADO” cubra a “EL PRESTADOR” el precio establecido anteriormente, en el entendido de que la vigencia del presente contrato y de “LA TARJETA DE DESCUENTO” se prorrogarán automáticamente sin necesidad de celebrar documento adicional entre “LAS PARTES” siempre y cuando “EL AFILIADO” cubra, de mes en mes o en la frecuencia contratada, el precio vigente de “LA TARJETA DE DESCUENTO”.</p>\r\n  <p>“EL AFILIADO” tendrá derecho a revocar su consentimiento dentro de los 5 (cinco) días siguientes a la entrega de “LA TARJETA DE DESCUENTO” o la firma del presente contrato, lo que ocurra último, sin responsabilidad alguna, siempre y cuando no haya obtenido beneficio alguno por el uso de “LA TARJETA DE DESCUENTO”.</p>\r\n\r\n  <h4>CUARTA.- BENEFICIOS DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“EL AFILIADO”, de forma exclusiva, personal e intransferible, gozará de forma gratuita de los servicios que se mencionan a continuación:</p>\r\n  <ul><li>Consultas gratuitas ilimitadas de medicina general (no de especialidad) en la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla, únicamente con los doctores afiliados al programa de Pasaporte a tu Salud.</li><li>Consultas de urgencia gratuitas en la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla.</li></ul>\r\n  <p>No así respecto de los servicios que, de manera enunciativa más no limitativa, se describen a continuación:</p>\r\n  <ul><li>Hospitalización dentro de la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla, sujeto a la disponibilidad de cada uno de ellos.</li><li>Consultas de especialidad ilimitadas a costo preferencial, con médicos especialistas pertenecientes al programa PATS.</li><li>Acceso a farmacia PATS con costos reducidos de medicamentos genéricos.</li><li>Imagenología y laboratorios ilimitados con costos preferenciales.</li><li>Acceso a cirugías con cuota de recuperación preferente, con o sin honorarios médicos incluidos según corresponda.</li></ul>\r\n  <p>Dichos servicios generarán, por evento, el pago de una cuota con cargo a “EL AFILIADO”, misma que resultará de aplicar los porcentajes de descuento que se desprenden del ANEXO 4 del presente contrato a los precios publicados al público en general o los precios preferenciales indicados.</p>\r\n  <p>Mientras “LA TARJETA DE DESCUENTO” se encuentre vigente, “EL AFILIADO” gozará de todos los beneficios que la misma le otorga; sin embargo, para el caso de que requiera cirugía o procedimiento quirúrgico en quirófano, deberá haber sufragado por adelantado la adquisición de “LA TARJETA DE DESCUENTO” por un periodo de 12 (doce) meses y encontrarse dentro de dicho periodo de vigencia.</p>\r\n\r\n  <h4>QUINTA.- OBLIGACIONES DE “EL PRESTADOR”.</h4>\r\n  <p>“EL PRESTADOR” se obliga a: (i) otorgar a “EL AFILIADO” el acceso ilimitado a “LA TARJETA DE DESCUENTO” durante la vigencia del contrato; (ii) mantener actualizada y operativa la Red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla; (iii) proporcionar a “EL AFILIADO”, de forma digital, “LA TARJETA DE DESCUENTO” dentro de los 5 (cinco) días hábiles siguientes al primer pago; e (iv) informar por escrito cualquier modificación a la red de hospitales o al tabulador de cuotas con al menos 10 (diez) días de anticipación.</p>\r\n\r\n  <h4>SEXTA.- OBLIGACIONES DE “EL AFILIADO”.</h4>\r\n  <p>“EL AFILIADO” se obliga a: (i) pagar puntualmente el precio de “LA TARJETA DE DESCUENTO”; (ii) utilizarla de forma exclusiva, personal e intransferible; (iii) cubrir directamente a los hospitales y con anterioridad a recibir el servicio médico las cuotas de recuperación según tabulador vigente; (iv) presentar identificación oficial y “LA TARJETA DE DESCUENTO” o código QR cada vez que haga uso de beneficios; y (v) notificar por escrito cualquier cambio de domicilio o datos de contacto en un plazo no mayor a 5 (cinco) días.</p>\r\n\r\n  <h4>SÉPTIMA.- ACCESO A LOS BENEFICIOS Y PROCEDIMIENTO.</h4>\r\n  <p>Para hacer uso de “LA TARJETA DE DESCUENTO”, “EL AFILIADO” deberá agendar sus citas directamente con los doctores pertenecientes a la Red de Hospitales 50 (FIFTY) Doctors, que en ese momento se encuentren adscritos al programa de beneficios, a través de la aplicación oficial, página de internet oficial de PATS o medios oficiales que indique “EL PRESTADOR”.</p>\r\n  <p>“EL AFILIADO” se obliga a pagar directamente al médico especialista perteneciente al programa el costo de la consulta de especialidad de que se trate, en términos de los porcentajes de descuento del ANEXO 4. En caso de no estar facultado para asistir por fuerza mayor, tendrá un plazo de 30 (treinta) días contados a partir de haber generado la cita para solicitar una nueva consulta médica.</p>\r\n\r\n  <h4>OCTAVA.- EXCLUSIONES Y LIMITACIONES.</h4>\r\n  <p>Los beneficios no incluirán: (i) trasplantes de órganos; (ii) tratamientos experimentales; (iii) tratamientos de oncología a excepción de algunas cirugías; (iv) medicamentos extra hospitalarios que no estén recogidos en el catálogo de Farmacia PATS; (v) atención médica con especialistas no adscritos o no publicados en los medios oficiales; y (vi) cualquier servicio no listado expresamente.</p>\r\n\r\n  <h4>NOVENA.- CAUSAS DE TERMINACIÓN.</h4>\r\n  <p>El contrato podrá terminarse por falta de pago, mutuo consentimiento por escrito o incumplimiento de cualquiera de las cláusulas por cualquiera de “LAS PARTES”. En caso de terminación, “EL AFILIADO” no tendrá derecho a exigir la devolución de cantidad alguna.</p>\r\n\r\n  <h4>DÉCIMA.- CANCELACIÓN VOLUNTARIA.</h4>\r\n  <p>“EL AFILIADO” podrá cancelar “LA TARJETA DE DESCUENTO” mediante aviso por escrito con 30 (treinta) días de anticipación. Dicha cancelación surtirá efectos a partir del siguiente periodo mensual y no generará reembolso de pagos ya realizados.</p>\r\n\r\n  <h4>DÉCIMA PRIMERA.- PROTECCIÓN DE DATOS PERSONALES.</h4>\r\n  <p>“LAS PARTES” acuerdan que el tratamiento de datos personales se sujetará a la Ley Federal de Protección de Datos Personales en Posesión de los Particulares. “EL AFILIADO” autoriza expresamente el uso de sus datos para la gestión de “LA TARJETA DE DESCUENTO”. El aviso de privacidad se integra al presente contrato como ANEXO 5.</p>\r\n\r\n  <h4>DÉCIMA SEGUNDA.- RESPONSABILIDAD.</h4>\r\n  <p>“EL AFILIADO” reconoce y acepta que “LA TARJETA DE DESCUENTO” es emitida y administrada directamente por CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE, quien es responsable de la operación de la red de descuentos, afiliación de prestadores médicos y prestación de cualquier servicio relacionado con “LA TARJETA DE DESCUENTO”.</p>\r\n  <p>En consecuencia, “EL PRESTADOR” no tendrá responsabilidad directa ni indirecta por la prestación, calidad, eficacia, resultado, daño, perjuicio, lesión, complicación, secuela, evento adverso o consecuencia derivada de servicios médicos recibidos, incluyendo aquellos ocasionados por negligencia, impericia o mala praxis de profesionales de la salud o prestadores afiliados. Cualquier relación derivada de la prestación de servicios médicos se establece directamente entre “EL AFILIADO” y los prestadores de servicios de salud correspondientes. Esta limitación subsistirá a la terminación del contrato.</p>\r\n\r\n  <h4>DÉCIMA TERCERA.- PREVENCIÓN DE LAVADO DE DINERO Y ORIGEN DE LOS RECURSOS.</h4>\r\n  <p>“LAS PARTES” declaran bajo protesta de decir verdad que los recursos económicos, bienes y derechos que utilicen para cumplir obligaciones derivadas de este contrato tienen y tendrán origen lícito. “EL AFILIADO” manifiesta que el pago inicial y pagos futuros provienen de fuentes lícitas y no de actividades tipificadas como delitos.</p>\r\n  <p>“LAS PARTES” reconocen que la prestación de servicios de comercio puede ser considerada actividad vulnerable, por lo que se obligan a proporcionar información y documentación requerida para integrar expediente de identificación e informar si tienen conocimiento de la existencia de beneficiario controlador.</p>\r\n\r\n  <h4>DÉCIMA CUARTA.- CONFORMACIÓN DEL EXPEDIENTE DE IDENTIFICACIÓN.</h4>\r\n  <p>“EL PRESTADOR” queda obligado a conformar y mantener un expediente de identificación de “EL AFILIADO”. Para tales efectos, “EL AFILIADO” se obliga a entregar los documentos aplicables: identificación oficial vigente o pasaporte, acta de nacimiento cuando aplique, comprobante de domicilio, constancia de situación fiscal cuando aplique, CURP, y declaración de dueño beneficiario.</p>\r\n  <p>Cuando exista persona responsable, la documentación de identificación y representación deberá integrarse al expediente; la CIF/constancia fiscal corresponde al tutor cuando aplique. “EL PRESTADOR” conservará dicho expediente por un periodo mínimo de 5 (cinco) años contados a partir de que termine la vigencia del contrato o termine por cualquiera de sus causales, garantizando la confidencialidad de los datos personales.</p>\r\n\r\n  <h4>DÉCIMA QUINTA.- CAUSAL ESPECÍFICA DE RESCISIÓN.</h4>\r\n  <p>Será motivo de rescisión inmediata sin necesidad de declaración judicial y sin responsabilidad para la parte afectada cuando cualquiera de “LAS PARTES” se niegue a proporcionar información requerida para cumplimiento de la Ley Federal para la Prevención e Identificación de Operaciones con Recursos de Procedencia Ilícita, proporcione información falsa o aparezca en listas de personas bloqueadas emitidas por autoridad competente.</p>\r\n\r\n  <h4>DÉCIMA SEXTA.- LEGISLACIÓN APLICABLE Y JURISDICCIÓN.</h4>\r\n  <p>“LAS PARTES” establecen que la Procuraduría Federal del Consumidor es competente en vía administrativa para resolver cualquier controversia sobre interpretación o cumplimiento. Sin perjuicio de lo anterior, se someten expresamente a la jurisdicción de los tribunales competentes del fuero común del Distrito Judicial de Puebla, Estado de Puebla, renunciando de manera expresa e irrevocable a cualquier otro fuero o jurisdicción que pudiera corresponderles.</p>\r\n\r\n  <p>Enteradas “LAS PARTES” del contenido y alcance del presente contrato, y entendidas de los derechos y obligaciones que contraen, firman el presente instrumento, incluyendo sus anexos, manifestando que no medió error, dolo, mala fe, violencia o lesión, ni vicio del consentimiento alguno, en la Ciudad de Puebla, Estado de Puebla, reconociendo que la fecha de firma es 12 de mayo de 2026.</p>\r\n\r\n  <div class=\"sign-grid\">\r\n    <div class=\"sign-box\"><div class=\"line\"></div><strong>“EL PRESTADOR”</strong><br>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE<br>Representada por PEDRO AZCÁRRAGA RAMOS</div>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>“EL AFILIADO”</strong><br>Mateo Miranda Casas</div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 1<br>Identificación oficial de “EL AFILIADO”</h2><p>Se integra al expediente la identificación oficial cargada por el usuario en el formulario. Para mexicanos, corresponde a identificación oficial/INE cuando aplique. Para extranjeros/no mexicanos, corresponde a identificación oficial o pasaporte vigente; al menos el frente es obligatorio y el reverso será opcional cuando el documento no lo tenga.</p><p><strong>Tipo:</strong> INE. <strong>Emitida por / país emisor:</strong> México. <strong>Número:</strong> GGFADGFADGDA.</p></div>\r\n  <div class=\"annex\"><h2>ANEXO 2<br>COMPROBANTE DE DOMICILIO DE “EL AFILIADO”</h2><p>Se integra al expediente el comprobante de domicilio cargado por el usuario. Domicilio declarado: Jornal 115, Col. zapopan, C.P. 45255, cholula, Jalisco, México.</p></div>\r\n  <div class=\"annex\"><h2>ANEXO 3<br>CONSTANCIA DE SITUACIÓN FISCAL DE “EL AFILIADO”</h2><p>Constancia de Situación Fiscal de “EL AFILIADO”, si aplica. En caso de pacientes representados, la constancia fiscal o CIF corresponde a la persona responsable cuando sea aplicable, no al menor. Para afiliados extranjeros/no mexicanos, no será obligatoria salvo que declaren RFC mexicano o residencia fiscal aplicable.</p></div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 4<br>CUOTAS DE RECUPERACIÓN Y/O PRECIOS BASE A CUBRIR A “EL PRESTADOR”</h2>\r\n    <p>En el presente anexo se establecen los porcentajes de descuento a obtener como titular de “LA TARJETA DE DESCUENTO”, por lo que la cantidad a cubrir por “EL AFILIADO” directamente al hospital de la cadena 50 (FIFTY) Doctors o al doctor que preste el servicio se obtendrá de aplicar el porcentaje de descuento correspondiente al precio publicado por los medios oficiales o al precio vigente en el establecimiento.</p>\r\n    <table><tr><th>Servicios / procedimientos</th><th>Descuentos</th></tr><tr><td>Consulta de urgencias</td><td>100%</td></tr><tr><td>Consulta de medicina general</td><td>100%</td></tr><tr><td>Habitación hospitalaria</td><td>90%</td></tr><tr><td>Uso de áreas de urgencias médicas</td><td>80%</td></tr><tr><td>Utilización de cubículos de terapia intensiva (UCIA-UCIN-UCIP)</td><td>75%</td></tr><tr><td>CEYE</td><td>75%</td></tr><tr><td>Uso quirófano</td><td>75%</td></tr><tr><td>Servicio de cuneros</td><td>75%</td></tr><tr><td>Materiales & medicamentos del cuadro básico, genéricos intercambiables</td><td>70%</td></tr><tr><td>Hemodinamia</td><td>70%</td></tr><tr><td>Imagenología</td><td>70%</td></tr><tr><td>Endoprótesis</td><td>70%</td></tr><tr><td>Osteosíntesis</td><td>70%</td></tr><tr><td>Prótesis</td><td>70%</td></tr><tr><td>Órtesis</td><td>70%</td></tr><tr><td>Laboratorio clínico</td><td>60%</td></tr></table>\r\n    <p class=\"small\">Los descuentos aplican con los proveedores suscritos al convenio de Pasaporte a tu Salud.</p>\r\n    <table><tr><th>Servicios / procedimientos</th><th>Precios base</th></tr><tr><td>Consulta de especialidades médicas</td><td>$390.00</td></tr><tr><td>Colposcopía</td><td>$400.00</td></tr><tr><td>Retiro de puntos de sutura</td><td>$80.00</td></tr><tr><td>Aplicación de medicamento intramuscular</td><td>$60.00</td></tr><tr><td>Retiro de DIU</td><td>$500.00</td></tr><tr><td>Colocación de DIU</td><td>$700.00</td></tr><tr><td>Extracción de cuerpo extraño (oído y nariz)</td><td>$300.00</td></tr><tr><td>Lavado ótico</td><td>$250.00</td></tr><tr><td>Curación de sitio quirúrgico</td><td>$250.00</td></tr><tr><td>Retiro de yeso</td><td>$250.00</td></tr><tr><td>Visita día de hospitalización</td><td>$650.00</td></tr><tr><td>Visita de urgencias</td><td>$750.00</td></tr><tr><td>Día de terapia intensiva</td><td>$850.00</td></tr></table>\r\n    <p class=\"small\">Todos los precios incluyen IVA. La factura de servicios hospitalarios será emitida con el desglose correspondiente y el ahorro otorgado por ser titular de “LA TARJETA DE DESCUENTO”.</p>\r\n    <p>Exclusiones y limitaciones: se aplicarán descuentos y precios especiales para el acompañante de “EL AFILIADO” en la misma habitación únicamente para la primera noche de hospitalización. Los precios y porcentajes de descuento darán derecho a la utilización de materiales y medicamentos del cuadro básico, genéricos intercambiables; cualquier otro tipo de medicación será cubierto directamente por “EL AFILIADO”. Los costos de procedimientos quirúrgicos incluyen honorarios médicos cuando así se indique. “EL AFILIADO” podrá atenderse con el médico tratante que elija, debiendo cubrir honorarios directamente a dicho médico, conservando el derecho a beneficios dentro de la red aplicable.</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Firma de aceptación de “EL AFILIADO”</strong><br>Mateo Miranda Casas</div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 5<br>AVISO DE PRIVACIDAD</h2>\r\n    <p>En cumplimiento de las disposiciones establecidas en la Ley Federal de Protección de Datos Personales en Posesión de Particulares, su Reglamento y los lineamientos aplicables, “CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE” (en lo sucesivo “EL PRESTADOR”), con domicilio en CALLE PASEO SINFONÍA NÚMERO EXTERIOR 1, LOCAL 2-14, LOMAS DE ANGELÓPOLIS II, SAN ANDRÉS CHOLULA, ESTADO DE PUEBLA, CÓDIGO POSTAL 72830, da a conocer el Aviso de Privacidad al tenor del cual manejará por medio de su representación y/o empleados los datos personales y/o documentación proporcionada por el afiliado o usuario de “LA TARJETA DE DESCUENTO”.</p>\r\n    <p>Se tendrá por aceptado expresamente el presente Aviso de Privacidad una vez proporcionados los datos personales y firmada digitalmente la aceptación del contrato, motivo por el cual “EL PRESTADOR” estará facultado para manejar la información conforme a la legislación aplicable.</p>\r\n    <h4>Modificación del aviso de privacidad</h4><p>Este aviso podrá ser modificado o adecuado a las necesidades de “EL PRESTADOR”. Las modificaciones o actualizaciones serán incorporadas al presente aviso y estarán disponibles en la página de internet, domicilio de “EL PRESTADOR” o serán enviadas al último correo electrónico proporcionado.</p>\r\n    <h4>Finalidad de la información</h4><p>La información será utilizada para: elaborar y mantener actualizada la base de usuarios; identificar afiliados; proporcionar la tarjeta digital; otorgar acceso al programa de beneficios; informar modificaciones a la red o tabulador; realizar análisis estadísticos internos y brindar un óptimo servicio médico.</p>\r\n    <h4>Tipo de datos necesarios</h4><p>Se solicitarán datos de identificación, contacto, legales, contractuales y fiscales cuando aplique, incluyendo nombre completo, lugar y fecha de nacimiento, firma, identificación oficial, nacionalidad, CURP y RFC cuando sean aplicables, domicilio, teléfono y correo electrónico.</p>\r\n    <h4>Transferencias de la información</h4><p>El usuario autoriza proporcionar información sin consentimiento adicional en los casos previstos por ley, resolución de autoridad competente, tratados aplicables, salvaguarda de interés público, procuración o administración de justicia, reconocimiento o defensa de derechos en procesos judiciales, y a socios comerciales, técnicos o estratégicos que asuman obligaciones de confidencialidad y seguridad equivalentes.</p>\r\n    <h4>Limitación del uso o divulgación de datos y derechos ARCO</h4><p>El usuario podrá limitar el uso o divulgación de sus datos personales y ejercer derechos de acceso, rectificación, cancelación u oposición mediante solicitud escrita dirigida a “EL PRESTADOR” en su domicilio o al correo silvia@pasaporteatusalud.com, acompañando documento que acredite su identidad.</p>\r\n    <h4>Revocación de consentimiento</h4><p>El usuario podrá revocar su consentimiento siguiendo el mismo procedimiento, considerando que para ciertos fines la revocación puede implicar la cancelación de “LA TARJETA DE DESCUENTO” y la imposibilidad de acceder al programa.</p>\r\n    <p><strong>Nombre:</strong> Mateo Miranda Casas<br><strong>Fecha:</strong> 12 de mayo de 2026</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Firma</strong></div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 6<br>DECLARACIÓN DE DUEÑO BENEFICIARIO</h2>\r\n    <p>DE CONFORMIDAD CON LO DISPUESTO EN LOS ARTÍCULOS 18 FRACCIÓN I Y III DE LA LEY FEDERAL PARA PREVENCIÓN E IDENTIFICACIÓN DE OPERACIONES CON RECURSOS DE PROCEDENCIA ILÍCITA, EL ARTÍCULO 15 DE SU REGLAMENTO Y EL ARTÍCULO 13 DE LAS REGLAS DE CARÁCTER GENERAL, MANIFIESTO BAJO PROTESTA DE DECIR VERDAD:</p>\r\n    <h4>Datos de identificación del cliente</h4>\r\n    <table><tr><th>Campo</th><th>Respuesta</th></tr><tr><td>Apellido paterno, materno y nombre(s)</td><td>Mateo Miranda Casas</td></tr><tr><td>Fecha de nacimiento</td><td>1986-12-15</td></tr><tr><td>País de nacimiento</td><td>México</td></tr><tr><td>Nacionalidad</td><td>mexicana</td></tr><tr><td>Actividad, ocupación o profesión</td><td>Comerciante</td></tr><tr><td>Estado civil</td><td>CASADO(A)</td></tr><tr><td>Domicilio particular</td><td>Jornal 115, Col. zapopan, C.P. 45255, cholula, Jalisco, México</td></tr><tr><td>Teléfonos</td><td>4444444444</td></tr><tr><td>Correo electrónico</td><td>lll@gmail.com</td></tr><tr><td>CURP</td><td>DDDDDDD</td></tr><tr><td>RFC</td><td>GFDGSDFG</td></tr><tr><td>Tipo de identificación</td><td>INE</td></tr><tr><td>Emitida por / país emisor</td><td>México</td></tr><tr><td>Número de identificación</td><td>GGFADGFADGDA</td></tr></table>\r\n    <h4>Datos de identificación de la operación</h4>\r\n    <table><tr><th>Campo</th><th>Respuesta</th></tr><tr><td>Tipo de operación</td><td>Adquisición de tarjeta de descuento PATS</td></tr><tr><td>Monto de operación</td><td>$800.00 M.N.</td></tr><tr><td>Fecha de operación</td><td>12 de mayo de 2026</td></tr><tr><td>Forma de pago</td><td>Pasarela / medio autorizado por “EL PRESTADOR”</td></tr><tr><td>Moneda</td><td>MXN</td></tr></table>\r\n    <h4>Información de la existencia del dueño beneficiario o beneficiario controlador</h4>\r\n    <p>Declaro que soy el beneficiario directo de la operación y no existe ningún otro dueño beneficiario o beneficiario controlador: <strong>SI</strong>.</p>\r\n    <h4>Aviso de privacidad</h4><p>Los datos personales serán protegidos y tratados conforme al Aviso de Privacidad contenido en el cuerpo del presente contrato y la legislación aplicable.</p>\r\n    <p>H. Puebla de Zaragoza al 12 del mes de mayo del año 2026.</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Nombre y firma</strong><br>Mateo Miranda Casas</div>\r\n  </div>\r\n\r\n  \r\n  </div>\r\n', 'data:image/png;base64,', 'Mateo Miranda Casas', '9886e618fad4c7ef63355e02c577c2a4b58aa1eea0a0858b9166b7dcf5ad40d0', '2026-05-13 00:09:40', '189.190.196.8', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:150.0) Gecko/20100101 Firefox/150.0', '', 'firmado', '2026-05-13 00:09:40', '2026-05-13 00:09:40');
INSERT INTO `pats_contratos_firmados` (`id_contrato_firmado`, `id_orden`, `id_pasaporte`, `id_distribuidor`, `id_franquicia`, `token_publico`, `contrato_clave`, `contrato_version`, `html_contrato_renderizado`, `firma_afiliado_base64`, `nombre_firmante`, `hash_contrato`, `fecha_firma`, `ip_firma`, `user_agent_firma`, `pdf_path`, `estatus`, `created_at`, `updated_at`) VALUES
(2, 3, 5, 0, 0, '', 'contrato_pats_base', '1.0', '<style>\r\n  .pats-contract{font-family:Arial,Helvetica,sans-serif;color:#172033;font-size:12px;line-height:1.52;background:#fff;padding:4px}\r\n  .pats-contract h1,.pats-contract h2,.pats-contract h3,.pats-contract h4{text-align:center;margin:12px 0 8px;color:#0d1b3e}\r\n  .pats-contract h1{font-size:16px;text-transform:uppercase;letter-spacing:.05em}\r\n  .pats-contract h2{font-size:15px;text-transform:uppercase;letter-spacing:.04em}\r\n  .pats-contract h3{font-size:13px;text-transform:uppercase;letter-spacing:.08em}\r\n  .pats-contract h4{font-size:12px;text-align:left;text-transform:uppercase;margin-top:12px}\r\n  .pats-contract p{margin:6px 0;text-align:justify}\r\n  .pats-contract ul{margin:6px 0 8px 18px;padding:0}.pats-contract li{margin:4px 0;text-align:justify}\r\n  .pats-contract table{width:100%;border-collapse:collapse;margin:8px 0 12px}.pats-contract th,.pats-contract td{border:1px solid #cbd5e1;padding:6px;vertical-align:top}.pats-contract th{background:#eef4ff;color:#0d1b3e;text-align:left}\r\n  .pats-contract .center{text-align:center}.pats-contract .muted{color:#64748b}.pats-contract .small{font-size:10px}.pats-contract .badge{display:inline-block;padding:3px 8px;border-radius:999px;background:#eef4ff;color:#1d4ed8;font-weight:700;margin:2px 4px 2px 0}\r\n  .pats-contract .sign-grid{display:grid;grid-template-columns:1fr 1fr;gap:22px;margin-top:28px}.pats-contract .sign-box{text-align:center;min-height:95px}.pats-contract .line{border-top:1px solid #0f172a;margin:48px 8px 6px}.pats-contract .signature-img{max-width:220px;max-height:82px;display:block;margin:0 auto 4px}\r\n  .pats-contract .annex{page-break-before:auto;border-top:2px solid #0d1b3e;margin-top:18px;padding-top:12px}.pats-contract .page-break{page-break-before:always;border-top:1px dashed #cbd5e1;margin-top:18px;padding-top:12px}\r\n</style>\r\n<div class=\"pats-contract\">\r\n  <h1>Carátula del contrato de adquisición de tarjeta de descuento</h1>\r\n  <p>CARÁTULA DEL CONTRATO DE ADQUISICIÓN DE TARJETA DE DESCUENTO (EN LO SUCESIVO “LA CARÁTULA”), QUE CELEBRAN POR UNA PARTE LA SOCIEDAD SEÑALADA EN EL APARTADO 1.- DE LA CARÁTULA, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL PRESTADOR”, REPRESENTADA EN ESTE ACTO POR LA PERSONA FÍSICA QUE SE INDICA EN EL APARTADO 2.- DE LA CARÁTULA; Y POR LA OTRA PARTE, LA PERSONA FÍSICA SEÑALADA EN EL APARTADO 5.- DE LA CARÁTULA, POR SU PROPIO DERECHO, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL AFILIADO”; Y CUANDO LOS ANTES NOMBRADOS ACTÚEN DE MANERA CONJUNTA, SE LES DENOMINARÁ COMO “LAS PARTES”; QUIENES SE SUJETAN AL TENOR DE LA CARÁTULA, DECLARACIONES Y CLÁUSULAS SIGUIENTES:</p>\r\n    \r\n  <h2>C A R Á T U L A</h2>\r\n  <table>\r\n    <tr><th style=\"width:8%\">Apartado</th><th style=\"width:42%\">Definición</th><th>Respuesta</th></tr>\r\n    <tr><td>1.-</td><td>Nombre de “EL PRESTADOR”</td><td>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE</td></tr>\r\n    <tr><td>2.-</td><td>Nombre del Representante Legal de “EL PRESTADOR”</td><td>PEDRO AZCÁRRAGA RAMOS</td></tr>\r\n    <tr><td>3.-</td><td>Domicilio de “EL PRESTADOR”</td><td>CALLE PASEO SINFONÍA NÚMERO EXTERIOR 1, LOCAL 2-14, LOMAS DE ANGELÓPOLIS II, SAN ANDRÉS CHOLULA, ESTADO DE PUEBLA, CÓDIGO POSTAL 72830</td></tr>\r\n    <tr><td>4.-</td><td>Clave del Registro Federal de Contribuyentes de “EL PRESTADOR”</td><td>COH2202144H5</td></tr>\r\n    <tr><td>5.-</td><td>Nombre de “EL AFILIADO”</td><td>Pablo García García</td></tr>\r\n    <tr><td>6.-</td><td>Domicilio de “EL AFILIADO”</td><td>Jornal 115, Col. zapopan, C.P. 45255, cholula, Jalisco, México</td></tr>\r\n    <tr><td>7.-</td><td>Clave del Registro Federal de Contribuyentes de “EL AFILIADO”</td><td>Pendiente / no proporcionado</td></tr>\r\n    <tr><td>8.-</td><td>Costo mensual de “LA TARJETA DE DESCUENTO”</td><td>$800.00 M.N.</td></tr>\r\n    <tr><td>9.-</td><td>Cuenta bancaria de “EL PRESTADOR” para pagos</td><td>Cuenta: 01600866709<br>CLABE: 042650016008667096<br>Institución Bancaria: Banca Mifel, S.A., Institución de Banca Múltiple, Grupo Financiero Mifel</td></tr>\r\n    <tr><td>10.-</td><td>Cuota de Reactivación de “LA TARJETA DE DESCUENTO”</td><td>$100.00 M.N. por cada mes que se haya interrumpido el pago.</td></tr>\r\n    <tr><td>11.-</td><td>Datos de la Tarjeta de Crédito de “EL AFILIADO”</td><td>Número de tarjeta: pendiente de confirmar por pasarela/token de pago.<br>Institución bancaria: pendiente de confirmar por pasarela. <br><span class=\"small\">No se almacena número completo de tarjeta en este formulario.</span></td></tr>\r\n    <tr><td>12.-</td><td>Anexos</td><td>ANEXO 1. Identificación oficial de “EL AFILIADO”<br>ANEXO 2. Comprobante de domicilio de “EL AFILIADO”<br>ANEXO 3. Constancia de Situación Fiscal de “EL AFILIADO”, si aplica<br>ANEXO 4. Cuotas de recuperación y/o precios base a cubrir a “EL PRESTADOR”<br>ANEXO 5. Aviso de privacidad<br>ANEXO 6. Declaración de dueño beneficiario</td></tr>\r\n    <tr><td>13.-</td><td>Fecha de Firma del Contrato</td><td>12 de mayo de 2026</td></tr>\r\n  </table>\r\n\r\n  <div class=\"sign-grid\">\r\n    <div class=\"sign-box\"><div class=\"line\"></div><strong>“EL PRESTADOR”</strong><br>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE<br>Representada por PEDRO AZCÁRRAGA RAMOS</div>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>“EL AFILIADO”</strong><br>Pablo García García<br><span class=\"small\">La persona física señalada en el Apartado 5.- de la Carátula</span></div>\r\n  </div>\r\n\r\n  <div class=\"page-break\"></div>\r\n  <h1>Contrato de adquisición de tarjeta de descuento</h1>\r\n  <p>CONTRATO DE ADQUISICIÓN DE TARJETA DE DESCUENTO, QUE CELEBRAN POR UNA PARTE LA SOCIEDAD SEÑALADA EN EL APARTADO 1.- DE LA CARÁTULA, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL PRESTADOR”, REPRESENTADA EN ESTE ACTO POR LA PERSONA FÍSICA QUE SE INDICA EN EL APARTADO 2.- DE LA CARÁTULA; Y POR LA OTRA PARTE, LA PERSONA FÍSICA SEÑALADA EN EL APARTADO 5.- DE LA CARÁTULA, POR SU PROPIO DERECHO, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL AFILIADO”; Y CUANDO LOS ANTES NOMBRADOS ACTÚEN DE MANERA CONJUNTA, SE LES DENOMINARÁ COMO “LAS PARTES”; QUIENES SE SUJETAN AL TENOR DE LAS DECLARACIONES Y CLÁUSULAS SIGUIENTES:</p>\r\n\r\n  <h2>D E C L A R A C I O N E S</h2>\r\n  <h4>I.- Declara “EL PRESTADOR” por conducto de su representación:</h4>\r\n  <p>A. Que, su representada es una sociedad mercantil constituida conforme a las leyes de los Estados Unidos Mexicanos, según consta en la escritura pública número 39,861, del volumen 830 de fecha catorce de febrero de dos mil veintidós, otorgada ante la fe del Licenciado Ernesto Joaquín Briones Amador, Notario Público Titular de la Notaría Pública número 46 de las del Distrito Judicial de Puebla, Estado de Puebla, cuyo primer testimonio se encuentra inscrito ante las oficinas del Registro Público de Comercio del Distrito Judicial de Puebla, Estado de Puebla, bajo el Folio Mercantil Electrónico: N-2022022991, por virtud del cual se llevó a cabo la Constitución de la persona moral denominada CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE.</p>\r\n  <p>B. Que, la persona física que la representa en este acto, señalada en el Apartado 2.- de la Carátula, cuenta con todas y cada una de las facultades necesarias para la celebración del presente contrato, las cuales se desprenden del instrumento descrito en el punto declarativo inmediato anterior, mismas que manifiesta bajo protesta de decir verdad que no le han sido suspendidas, revocadas o limitadas en forma alguna.</p>\r\n  <p>C. Que, su representada tiene como domicilio fiscal el señalado en el Apartado 3.- de la Carátula del presente contrato, mismo que designa como domicilio convencional para cualquier cuestión relacionada con la celebración del presente contrato.</p>\r\n  <p>D. Que, su representada se encuentra inscrita en el Registro Federal de Contribuyentes bajo la clave señalada en el Apartado 4.- de la Carátula.</p>\r\n  <p>E. Que, ha desarrollado y es su deseo comparecer a la celebración del presente instrumento con la finalidad de enajenar en favor de “EL AFILIADO”, una Tarjeta de Descuento que da acceso a “UN PROGRAMA DE BENEFICIOS QUE OTORGA DESCUENTOS A LOS COSTOS Y PERMITE RECIBIR SERVICIOS MÉDICOS PRIVADOS DE ALTA CALIDAD DE FORMA ACCESIBLE, CLARA Y SIN RESTRICCIONES DENTRO DE LA RED DE HOSPITALES 50 (FIFTY) DOCTORS CON SEDE EN EL ESTADO DE PUEBLA”, en lo sucesivo “LA TARJETA DE DESCUENTO”, en los términos y condiciones que se establecerán más adelante.</p>\r\n  <p>F. Que, su representada no es una Aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas sino una empresa dedicada, entre otros, a la operación y administración de establecimientos destinados a la atención y asistencia de enfermos, por lo que la enajenación de “LA TARJETA DE DESCUENTO” únicamente constituye un acto de comercio que brindará a “EL AFILIADO” acceso a un programa de beneficios como ha quedado descrito anteriormente.</p>\r\n\r\n  <h4>II.- Declara “EL AFILIADO”, por su propio derecho:</h4>\r\n      <p>A. Que, su nombre se señala en el Apartado 5.- de la Carátula, es una persona física de nacionalidad mexicana, en pleno ejercicio de sus derechos, legal y jurídicamente capaz para celebrar el presente Contrato, quien se identifica con credencial para votar vigente expedida por el Instituto Nacional Electoral, tipo INE, número GGFADGFADGDA, que en copia simple o archivo digital se agrega al cuerpo del presente contrato como ANEXO 1.</p>\r\n    <p>B. Que, tiene como domicilio particular el señalado en el Apartado 6.- de la Carátula, mismo que designa como domicilio convencional para cualquier cuestión relacionada con la celebración del presente contrato, tal y como lo acredita con el comprobante de domicilio que en copia simple o archivo digital se agrega al cuerpo del presente contrato como ANEXO 2.</p>\r\n  <p>C. Que, su CURP es 444444444444444 y su RFC/identificación fiscal es Pendiente / no proporcionado; asimismo manifiesta que cuenta con capacidad económica para obligarse en términos del presente contrato y que los recursos con los que cubrirá sus obligaciones provendrán de fuentes lícitas. En caso de nacionalidad extranjera/no mexicana, se tendrán por no aplicables CURP, INE y constancia fiscal mexicana salvo manifestación expresa de residencia fiscal o RFC mexicano.</p>\r\n  <p>D. Que, es su deseo comparecer a la celebración del presente instrumento con la finalidad de adquirir “LA TARJETA DE DESCUENTO” de acuerdo con los términos y condiciones que se establecen a continuación.</p>\r\n  <p>E. Que, previo a la celebración del presente contrato fue informado y manifiesta expresamente que reconoce que “EL PRESTADOR” no es una Aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas y que las actividades comerciales objeto del presente contrato no consisten en la contratación de un seguro, de la índole que fuere, sino que únicamente implica la adquisición de una tarjeta de descuento que da acceso a un programa de beneficios que otorga descuentos a los costos y permite recibir servicios médicos privados de alta calidad de forma accesible, clara y sin restricciones dentro de la red de hospitales 50 (FIFTY) Doctors con sede en el Estado de Puebla.</p>\r\n  <p>F. Que, reconoce que “EL PRESTADOR” se dedica a la operación de centros hospitalarios y que la emisión de “LA TARJETA DE DESCUENTO” únicamente corresponde a la intención de este último de crear un programa de descuentos para el acceso a los servicios prestados por la Red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla.</p>\r\n\r\n  <h4>III.- Declaran conjuntamente “LAS PARTES”:</h4>\r\n  <p>1. Que, se reconocen recíprocamente la personalidad con la que comparecen a la celebración del presente acuerdo de voluntades.</p>\r\n  <p>2. Que, el presente contrato es el instrumento que las vincula en sus derechos y obligaciones.</p>\r\n  <p>3. Que, es su deseo celebrar el presente contrato y han negociado libremente los términos y condiciones del mismo con pleno conocimiento de sus alcances e implicaciones jurídicas, por lo que en su celebración no existe dolo, error, mala fe, lesión o cualquier otro vicio del consentimiento que pudiese afectarlo de inexistencia o nulidad.</p>\r\n\r\n  <h2>C L Á U S U L A S</h2>\r\n  <h4>PRIMERA.- OBJETO.</h4>\r\n  <p>El objeto del presente Contrato es que “EL AFILIADO” adquiera de “EL PRESTADOR”, a título oneroso y temporal, el derecho de uso ilimitado y sin restricción alguna de “LA TARJETA DE DESCUENTO” emitida por CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE, la cual consiste en que “EL AFILIADO” aproveche y acceda a “UN PROGRAMA DE BENEFICIOS QUE OTORGA DESCUENTOS A LOS COSTOS Y PERMITE RECIBIR SERVICIOS MÉDICOS PRIVADOS DE ALTA CALIDAD DE FORMA ACCESIBLE, CLARA Y SIN RESTRICCIONES DENTRO DE LA RED DE HOSPITALES 50 (FIFTY) DOCTORS CON SEDE EN EL ESTADO DE PUEBLA”.</p>\r\n  <p>Estableciendo que, la comercialización de “LA TARJETA DE DESCUENTO” por parte de “EL PRESTADOR” en ningún momento constituirá la venta, promoción o por cualquier medio la contratación de una póliza de seguro, bajo el entendido de que “EL PRESTADOR” no es una aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas (CNSF); sino que comercializa “LA TARJETA DE DESCUENTO” en favor de terceros con la finalidad de otorgar descuentos a los precios respecto de los servicios médicos que presta en el territorio nacional.</p>\r\n\r\n  <h4>SEGUNDA.- PRECIO DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“LAS PARTES” establecen de común acuerdo que “LA TARJETA DE DESCUENTO” tendrá como costo mensual la cantidad señalada en el Apartado 8.- de la Carátula del presente contrato; cantidad que ya incluye IVA, y la cual deberá ser cubierta por “EL AFILIADO” en favor de “EL PRESTADOR” dentro de los primeros 5 (cinco) días de cada mes, sin necesidad de gestiones o avisos de cobro, ya sea mediante:</p>\r\n  <p>(i) Transferencia electrónica de fondos a la cuenta bancaria señalada en el Apartado 9.- de la Carátula del presente contrato y de la cual es titular “EL PRESTADOR”.</p>\r\n  <p>(ii) Cheque que se recibirá salvo buen cobro en el Domicilio de “EL PRESTADOR” señalado en el Apartado 3.- de la Carátula del presente contrato, y que en caso de no ser pagado por falta de fondos suficientes o por otras causas imputables a “EL AFILIADO”, éste último está de acuerdo en que deberá cubrir a “EL PRESTADOR” el 20% (veinte por ciento) del monto del cheque por concepto de indemnización por daños y perjuicios en términos del artículo 193 de la Ley General de Títulos y Operaciones de Crédito, independientemente de cualquier otro cargo que se pudiera generar.</p>\r\n  <p>(iii) Cargos mensuales automáticos recurrentes a la tarjeta de crédito de “EL AFILIADO” según los datos señalados en el Apartado 11.- de la Carátula del presente contrato, quien manifiesta bajo protesta de decir verdad que autoriza a “EL PRESTADOR” a realizar los cargos mensuales correspondientes por el costo mensual de “LA TARJETA DE DESCUENTO” en dicha tarjeta o en la tarjeta que por renovación, reposición, robo o extravío le haya asignado el banco emisor. La autorización estará vigente mientras “EL AFILIADO” no haya notificado a “EL PRESTADOR” por escrito y con acuse de recibo su deseo de cancelar su afiliación o no renovarla, o en su defecto, realizar su baja respectiva en el sitio web o aplicación de “EL PRESTADOR”.</p>\r\n  <p>Esta autorización no exime a “EL AFILIADO” del pago mensual por el uso de “LA TARJETA DE DESCUENTO” y demás obligaciones contractuales, por lo que, en caso de que el cobro no sea autorizado por el banco emisor o por cualquier razón no pueda realizarse, “EL AFILIADO” deberá notificar tal situación a “EL PRESTADOR” a la dirección de correo electrónico silvia@pasaporteatusalud.com, a efecto de solicitar una forma de pago diversa, quedando obligado a cubrir de inmediato el pago correspondiente.</p>\r\n  <p>(iv) Cualquier otro medio de pago aceptado por “EL PRESTADOR”, mismo que se dará a conocer a través de sus medios oficiales de comunicación.</p>\r\n  <p>“EL PRESTADOR” podrá variar unilateralmente el costo mensual de “LA TARJETA DE DESCUENTO”, previo aviso a “EL AFILIADO” con 30 (treinta) días de anticipación a través de sus medios oficiales de comunicación.</p>\r\n  <p>Para el caso de que “EL AFILIADO” adquiera y cubra el precio de “LA TARJETA DE DESCUENTO” y posteriormente deje de pagar una mensualidad, deberá cubrir a “EL PRESTADOR”, por concepto de cuota de reactivación, la cantidad señalada en el Apartado 10.- de la Carátula por cada mes que haya interrumpido y/o no haya cubierto el precio de “LA TARJETA DE DESCUENTO”, hasta la fecha en que pretenda volver a adquirirla.</p>\r\n\r\n  <h4>TERCERA.- VIGENCIA DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“LA TARJETA DE DESCUENTO” objeto del presente contrato tendrá una vigencia de 30 días contados a partir de que “EL AFILIADO” cubra a “EL PRESTADOR” el precio establecido anteriormente, en el entendido de que la vigencia del presente contrato y de “LA TARJETA DE DESCUENTO” se prorrogarán automáticamente sin necesidad de celebrar documento adicional entre “LAS PARTES” siempre y cuando “EL AFILIADO” cubra, de mes en mes o en la frecuencia contratada, el precio vigente de “LA TARJETA DE DESCUENTO”.</p>\r\n  <p>“EL AFILIADO” tendrá derecho a revocar su consentimiento dentro de los 5 (cinco) días siguientes a la entrega de “LA TARJETA DE DESCUENTO” o la firma del presente contrato, lo que ocurra último, sin responsabilidad alguna, siempre y cuando no haya obtenido beneficio alguno por el uso de “LA TARJETA DE DESCUENTO”.</p>\r\n\r\n  <h4>CUARTA.- BENEFICIOS DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“EL AFILIADO”, de forma exclusiva, personal e intransferible, gozará de forma gratuita de los servicios que se mencionan a continuación:</p>\r\n  <ul><li>Consultas gratuitas ilimitadas de medicina general (no de especialidad) en la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla, únicamente con los doctores afiliados al programa de Pasaporte a tu Salud.</li><li>Consultas de urgencia gratuitas en la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla.</li></ul>\r\n  <p>No así respecto de los servicios que, de manera enunciativa más no limitativa, se describen a continuación:</p>\r\n  <ul><li>Hospitalización dentro de la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla, sujeto a la disponibilidad de cada uno de ellos.</li><li>Consultas de especialidad ilimitadas a costo preferencial, con médicos especialistas pertenecientes al programa PATS.</li><li>Acceso a farmacia PATS con costos reducidos de medicamentos genéricos.</li><li>Imagenología y laboratorios ilimitados con costos preferenciales.</li><li>Acceso a cirugías con cuota de recuperación preferente, con o sin honorarios médicos incluidos según corresponda.</li></ul>\r\n  <p>Dichos servicios generarán, por evento, el pago de una cuota con cargo a “EL AFILIADO”, misma que resultará de aplicar los porcentajes de descuento que se desprenden del ANEXO 4 del presente contrato a los precios publicados al público en general o los precios preferenciales indicados.</p>\r\n  <p>Mientras “LA TARJETA DE DESCUENTO” se encuentre vigente, “EL AFILIADO” gozará de todos los beneficios que la misma le otorga; sin embargo, para el caso de que requiera cirugía o procedimiento quirúrgico en quirófano, deberá haber sufragado por adelantado la adquisición de “LA TARJETA DE DESCUENTO” por un periodo de 12 (doce) meses y encontrarse dentro de dicho periodo de vigencia.</p>\r\n\r\n  <h4>QUINTA.- OBLIGACIONES DE “EL PRESTADOR”.</h4>\r\n  <p>“EL PRESTADOR” se obliga a: (i) otorgar a “EL AFILIADO” el acceso ilimitado a “LA TARJETA DE DESCUENTO” durante la vigencia del contrato; (ii) mantener actualizada y operativa la Red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla; (iii) proporcionar a “EL AFILIADO”, de forma digital, “LA TARJETA DE DESCUENTO” dentro de los 5 (cinco) días hábiles siguientes al primer pago; e (iv) informar por escrito cualquier modificación a la red de hospitales o al tabulador de cuotas con al menos 10 (diez) días de anticipación.</p>\r\n\r\n  <h4>SEXTA.- OBLIGACIONES DE “EL AFILIADO”.</h4>\r\n  <p>“EL AFILIADO” se obliga a: (i) pagar puntualmente el precio de “LA TARJETA DE DESCUENTO”; (ii) utilizarla de forma exclusiva, personal e intransferible; (iii) cubrir directamente a los hospitales y con anterioridad a recibir el servicio médico las cuotas de recuperación según tabulador vigente; (iv) presentar identificación oficial y “LA TARJETA DE DESCUENTO” o código QR cada vez que haga uso de beneficios; y (v) notificar por escrito cualquier cambio de domicilio o datos de contacto en un plazo no mayor a 5 (cinco) días.</p>\r\n\r\n  <h4>SÉPTIMA.- ACCESO A LOS BENEFICIOS Y PROCEDIMIENTO.</h4>\r\n  <p>Para hacer uso de “LA TARJETA DE DESCUENTO”, “EL AFILIADO” deberá agendar sus citas directamente con los doctores pertenecientes a la Red de Hospitales 50 (FIFTY) Doctors, que en ese momento se encuentren adscritos al programa de beneficios, a través de la aplicación oficial, página de internet oficial de PATS o medios oficiales que indique “EL PRESTADOR”.</p>\r\n  <p>“EL AFILIADO” se obliga a pagar directamente al médico especialista perteneciente al programa el costo de la consulta de especialidad de que se trate, en términos de los porcentajes de descuento del ANEXO 4. En caso de no estar facultado para asistir por fuerza mayor, tendrá un plazo de 30 (treinta) días contados a partir de haber generado la cita para solicitar una nueva consulta médica.</p>\r\n\r\n  <h4>OCTAVA.- EXCLUSIONES Y LIMITACIONES.</h4>\r\n  <p>Los beneficios no incluirán: (i) trasplantes de órganos; (ii) tratamientos experimentales; (iii) tratamientos de oncología a excepción de algunas cirugías; (iv) medicamentos extra hospitalarios que no estén recogidos en el catálogo de Farmacia PATS; (v) atención médica con especialistas no adscritos o no publicados en los medios oficiales; y (vi) cualquier servicio no listado expresamente.</p>\r\n\r\n  <h4>NOVENA.- CAUSAS DE TERMINACIÓN.</h4>\r\n  <p>El contrato podrá terminarse por falta de pago, mutuo consentimiento por escrito o incumplimiento de cualquiera de las cláusulas por cualquiera de “LAS PARTES”. En caso de terminación, “EL AFILIADO” no tendrá derecho a exigir la devolución de cantidad alguna.</p>\r\n\r\n  <h4>DÉCIMA.- CANCELACIÓN VOLUNTARIA.</h4>\r\n  <p>“EL AFILIADO” podrá cancelar “LA TARJETA DE DESCUENTO” mediante aviso por escrito con 30 (treinta) días de anticipación. Dicha cancelación surtirá efectos a partir del siguiente periodo mensual y no generará reembolso de pagos ya realizados.</p>\r\n\r\n  <h4>DÉCIMA PRIMERA.- PROTECCIÓN DE DATOS PERSONALES.</h4>\r\n  <p>“LAS PARTES” acuerdan que el tratamiento de datos personales se sujetará a la Ley Federal de Protección de Datos Personales en Posesión de los Particulares. “EL AFILIADO” autoriza expresamente el uso de sus datos para la gestión de “LA TARJETA DE DESCUENTO”. El aviso de privacidad se integra al presente contrato como ANEXO 5.</p>\r\n\r\n  <h4>DÉCIMA SEGUNDA.- RESPONSABILIDAD.</h4>\r\n  <p>“EL AFILIADO” reconoce y acepta que “LA TARJETA DE DESCUENTO” es emitida y administrada directamente por CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE, quien es responsable de la operación de la red de descuentos, afiliación de prestadores médicos y prestación de cualquier servicio relacionado con “LA TARJETA DE DESCUENTO”.</p>\r\n  <p>En consecuencia, “EL PRESTADOR” no tendrá responsabilidad directa ni indirecta por la prestación, calidad, eficacia, resultado, daño, perjuicio, lesión, complicación, secuela, evento adverso o consecuencia derivada de servicios médicos recibidos, incluyendo aquellos ocasionados por negligencia, impericia o mala praxis de profesionales de la salud o prestadores afiliados. Cualquier relación derivada de la prestación de servicios médicos se establece directamente entre “EL AFILIADO” y los prestadores de servicios de salud correspondientes. Esta limitación subsistirá a la terminación del contrato.</p>\r\n\r\n  <h4>DÉCIMA TERCERA.- PREVENCIÓN DE LAVADO DE DINERO Y ORIGEN DE LOS RECURSOS.</h4>\r\n  <p>“LAS PARTES” declaran bajo protesta de decir verdad que los recursos económicos, bienes y derechos que utilicen para cumplir obligaciones derivadas de este contrato tienen y tendrán origen lícito. “EL AFILIADO” manifiesta que el pago inicial y pagos futuros provienen de fuentes lícitas y no de actividades tipificadas como delitos.</p>\r\n  <p>“LAS PARTES” reconocen que la prestación de servicios de comercio puede ser considerada actividad vulnerable, por lo que se obligan a proporcionar información y documentación requerida para integrar expediente de identificación e informar si tienen conocimiento de la existencia de beneficiario controlador.</p>\r\n\r\n  <h4>DÉCIMA CUARTA.- CONFORMACIÓN DEL EXPEDIENTE DE IDENTIFICACIÓN.</h4>\r\n  <p>“EL PRESTADOR” queda obligado a conformar y mantener un expediente de identificación de “EL AFILIADO”. Para tales efectos, “EL AFILIADO” se obliga a entregar los documentos aplicables: identificación oficial vigente o pasaporte, acta de nacimiento cuando aplique, comprobante de domicilio, constancia de situación fiscal cuando aplique, CURP, y declaración de dueño beneficiario.</p>\r\n  <p>Cuando exista persona responsable, la documentación de identificación y representación deberá integrarse al expediente; la CIF/constancia fiscal corresponde al tutor cuando aplique. “EL PRESTADOR” conservará dicho expediente por un periodo mínimo de 5 (cinco) años contados a partir de que termine la vigencia del contrato o termine por cualquiera de sus causales, garantizando la confidencialidad de los datos personales.</p>\r\n\r\n  <h4>DÉCIMA QUINTA.- CAUSAL ESPECÍFICA DE RESCISIÓN.</h4>\r\n  <p>Será motivo de rescisión inmediata sin necesidad de declaración judicial y sin responsabilidad para la parte afectada cuando cualquiera de “LAS PARTES” se niegue a proporcionar información requerida para cumplimiento de la Ley Federal para la Prevención e Identificación de Operaciones con Recursos de Procedencia Ilícita, proporcione información falsa o aparezca en listas de personas bloqueadas emitidas por autoridad competente.</p>\r\n\r\n  <h4>DÉCIMA SEXTA.- LEGISLACIÓN APLICABLE Y JURISDICCIÓN.</h4>\r\n  <p>“LAS PARTES” establecen que la Procuraduría Federal del Consumidor es competente en vía administrativa para resolver cualquier controversia sobre interpretación o cumplimiento. Sin perjuicio de lo anterior, se someten expresamente a la jurisdicción de los tribunales competentes del fuero común del Distrito Judicial de Puebla, Estado de Puebla, renunciando de manera expresa e irrevocable a cualquier otro fuero o jurisdicción que pudiera corresponderles.</p>\r\n\r\n  <p>Enteradas “LAS PARTES” del contenido y alcance del presente contrato, y entendidas de los derechos y obligaciones que contraen, firman el presente instrumento, incluyendo sus anexos, manifestando que no medió error, dolo, mala fe, violencia o lesión, ni vicio del consentimiento alguno, en la Ciudad de Puebla, Estado de Puebla, reconociendo que la fecha de firma es 12 de mayo de 2026.</p>\r\n\r\n  <div class=\"sign-grid\">\r\n    <div class=\"sign-box\"><div class=\"line\"></div><strong>“EL PRESTADOR”</strong><br>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE<br>Representada por PEDRO AZCÁRRAGA RAMOS</div>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>“EL AFILIADO”</strong><br>Pablo García García</div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 1<br>Identificación oficial de “EL AFILIADO”</h2><p>Se integra al expediente la identificación oficial cargada por el usuario en el formulario. Para mexicanos, corresponde a identificación oficial/INE cuando aplique. Para extranjeros/no mexicanos, corresponde a identificación oficial o pasaporte vigente; al menos el frente es obligatorio y el reverso será opcional cuando el documento no lo tenga.</p><p><strong>Tipo:</strong> INE. <strong>Emitida por / país emisor:</strong> México. <strong>Número:</strong> GGFADGFADGDA.</p></div>\r\n  <div class=\"annex\"><h2>ANEXO 2<br>COMPROBANTE DE DOMICILIO DE “EL AFILIADO”</h2><p>Se integra al expediente el comprobante de domicilio cargado por el usuario. Domicilio declarado: Jornal 115, Col. zapopan, C.P. 45255, cholula, Jalisco, México.</p></div>\r\n  <div class=\"annex\"><h2>ANEXO 3<br>CONSTANCIA DE SITUACIÓN FISCAL DE “EL AFILIADO”</h2><p>Constancia de Situación Fiscal de “EL AFILIADO”, si aplica. En caso de pacientes representados, la constancia fiscal o CIF corresponde a la persona responsable cuando sea aplicable, no al menor. Para afiliados extranjeros/no mexicanos, no será obligatoria salvo que declaren RFC mexicano o residencia fiscal aplicable.</p></div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 4<br>CUOTAS DE RECUPERACIÓN Y/O PRECIOS BASE A CUBRIR A “EL PRESTADOR”</h2>\r\n    <p>En el presente anexo se establecen los porcentajes de descuento a obtener como titular de “LA TARJETA DE DESCUENTO”, por lo que la cantidad a cubrir por “EL AFILIADO” directamente al hospital de la cadena 50 (FIFTY) Doctors o al doctor que preste el servicio se obtendrá de aplicar el porcentaje de descuento correspondiente al precio publicado por los medios oficiales o al precio vigente en el establecimiento.</p>\r\n    <table><tr><th>Servicios / procedimientos</th><th>Descuentos</th></tr><tr><td>Consulta de urgencias</td><td>100%</td></tr><tr><td>Consulta de medicina general</td><td>100%</td></tr><tr><td>Habitación hospitalaria</td><td>90%</td></tr><tr><td>Uso de áreas de urgencias médicas</td><td>80%</td></tr><tr><td>Utilización de cubículos de terapia intensiva (UCIA-UCIN-UCIP)</td><td>75%</td></tr><tr><td>CEYE</td><td>75%</td></tr><tr><td>Uso quirófano</td><td>75%</td></tr><tr><td>Servicio de cuneros</td><td>75%</td></tr><tr><td>Materiales & medicamentos del cuadro básico, genéricos intercambiables</td><td>70%</td></tr><tr><td>Hemodinamia</td><td>70%</td></tr><tr><td>Imagenología</td><td>70%</td></tr><tr><td>Endoprótesis</td><td>70%</td></tr><tr><td>Osteosíntesis</td><td>70%</td></tr><tr><td>Prótesis</td><td>70%</td></tr><tr><td>Órtesis</td><td>70%</td></tr><tr><td>Laboratorio clínico</td><td>60%</td></tr></table>\r\n    <p class=\"small\">Los descuentos aplican con los proveedores suscritos al convenio de Pasaporte a tu Salud.</p>\r\n    <table><tr><th>Servicios / procedimientos</th><th>Precios base</th></tr><tr><td>Consulta de especialidades médicas</td><td>$390.00</td></tr><tr><td>Colposcopía</td><td>$400.00</td></tr><tr><td>Retiro de puntos de sutura</td><td>$80.00</td></tr><tr><td>Aplicación de medicamento intramuscular</td><td>$60.00</td></tr><tr><td>Retiro de DIU</td><td>$500.00</td></tr><tr><td>Colocación de DIU</td><td>$700.00</td></tr><tr><td>Extracción de cuerpo extraño (oído y nariz)</td><td>$300.00</td></tr><tr><td>Lavado ótico</td><td>$250.00</td></tr><tr><td>Curación de sitio quirúrgico</td><td>$250.00</td></tr><tr><td>Retiro de yeso</td><td>$250.00</td></tr><tr><td>Visita día de hospitalización</td><td>$650.00</td></tr><tr><td>Visita de urgencias</td><td>$750.00</td></tr><tr><td>Día de terapia intensiva</td><td>$850.00</td></tr></table>\r\n    <p class=\"small\">Todos los precios incluyen IVA. La factura de servicios hospitalarios será emitida con el desglose correspondiente y el ahorro otorgado por ser titular de “LA TARJETA DE DESCUENTO”.</p>\r\n    <p>Exclusiones y limitaciones: se aplicarán descuentos y precios especiales para el acompañante de “EL AFILIADO” en la misma habitación únicamente para la primera noche de hospitalización. Los precios y porcentajes de descuento darán derecho a la utilización de materiales y medicamentos del cuadro básico, genéricos intercambiables; cualquier otro tipo de medicación será cubierto directamente por “EL AFILIADO”. Los costos de procedimientos quirúrgicos incluyen honorarios médicos cuando así se indique. “EL AFILIADO” podrá atenderse con el médico tratante que elija, debiendo cubrir honorarios directamente a dicho médico, conservando el derecho a beneficios dentro de la red aplicable.</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Firma de aceptación de “EL AFILIADO”</strong><br>Pablo García García</div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 5<br>AVISO DE PRIVACIDAD</h2>\r\n    <p>En cumplimiento de las disposiciones establecidas en la Ley Federal de Protección de Datos Personales en Posesión de Particulares, su Reglamento y los lineamientos aplicables, “CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE” (en lo sucesivo “EL PRESTADOR”), con domicilio en CALLE PASEO SINFONÍA NÚMERO EXTERIOR 1, LOCAL 2-14, LOMAS DE ANGELÓPOLIS II, SAN ANDRÉS CHOLULA, ESTADO DE PUEBLA, CÓDIGO POSTAL 72830, da a conocer el Aviso de Privacidad al tenor del cual manejará por medio de su representación y/o empleados los datos personales y/o documentación proporcionada por el afiliado o usuario de “LA TARJETA DE DESCUENTO”.</p>\r\n    <p>Se tendrá por aceptado expresamente el presente Aviso de Privacidad una vez proporcionados los datos personales y firmada digitalmente la aceptación del contrato, motivo por el cual “EL PRESTADOR” estará facultado para manejar la información conforme a la legislación aplicable.</p>\r\n    <h4>Modificación del aviso de privacidad</h4><p>Este aviso podrá ser modificado o adecuado a las necesidades de “EL PRESTADOR”. Las modificaciones o actualizaciones serán incorporadas al presente aviso y estarán disponibles en la página de internet, domicilio de “EL PRESTADOR” o serán enviadas al último correo electrónico proporcionado.</p>\r\n    <h4>Finalidad de la información</h4><p>La información será utilizada para: elaborar y mantener actualizada la base de usuarios; identificar afiliados; proporcionar la tarjeta digital; otorgar acceso al programa de beneficios; informar modificaciones a la red o tabulador; realizar análisis estadísticos internos y brindar un óptimo servicio médico.</p>\r\n    <h4>Tipo de datos necesarios</h4><p>Se solicitarán datos de identificación, contacto, legales, contractuales y fiscales cuando aplique, incluyendo nombre completo, lugar y fecha de nacimiento, firma, identificación oficial, nacionalidad, CURP y RFC cuando sean aplicables, domicilio, teléfono y correo electrónico.</p>\r\n    <h4>Transferencias de la información</h4><p>El usuario autoriza proporcionar información sin consentimiento adicional en los casos previstos por ley, resolución de autoridad competente, tratados aplicables, salvaguarda de interés público, procuración o administración de justicia, reconocimiento o defensa de derechos en procesos judiciales, y a socios comerciales, técnicos o estratégicos que asuman obligaciones de confidencialidad y seguridad equivalentes.</p>\r\n    <h4>Limitación del uso o divulgación de datos y derechos ARCO</h4><p>El usuario podrá limitar el uso o divulgación de sus datos personales y ejercer derechos de acceso, rectificación, cancelación u oposición mediante solicitud escrita dirigida a “EL PRESTADOR” en su domicilio o al correo silvia@pasaporteatusalud.com, acompañando documento que acredite su identidad.</p>\r\n    <h4>Revocación de consentimiento</h4><p>El usuario podrá revocar su consentimiento siguiendo el mismo procedimiento, considerando que para ciertos fines la revocación puede implicar la cancelación de “LA TARJETA DE DESCUENTO” y la imposibilidad de acceder al programa.</p>\r\n    <p><strong>Nombre:</strong> Pablo García García<br><strong>Fecha:</strong> 12 de mayo de 2026</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Firma</strong></div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 6<br>DECLARACIÓN DE DUEÑO BENEFICIARIO</h2>\r\n    <p>DE CONFORMIDAD CON LO DISPUESTO EN LOS ARTÍCULOS 18 FRACCIÓN I Y III DE LA LEY FEDERAL PARA PREVENCIÓN E IDENTIFICACIÓN DE OPERACIONES CON RECURSOS DE PROCEDENCIA ILÍCITA, EL ARTÍCULO 15 DE SU REGLAMENTO Y EL ARTÍCULO 13 DE LAS REGLAS DE CARÁCTER GENERAL, MANIFIESTO BAJO PROTESTA DE DECIR VERDAD:</p>\r\n    <h4>Datos de identificación del cliente</h4>\r\n    <table><tr><th>Campo</th><th>Respuesta</th></tr><tr><td>Apellido paterno, materno y nombre(s)</td><td>Pablo García García</td></tr><tr><td>Fecha de nacimiento</td><td>1984-12-15</td></tr><tr><td>País de nacimiento</td><td>México</td></tr><tr><td>Nacionalidad</td><td>mexicana</td></tr><tr><td>Actividad, ocupación o profesión</td><td>Comerciante</td></tr><tr><td>Estado civil</td><td>CASADO(A)</td></tr><tr><td>Domicilio particular</td><td>Jornal 115, Col. zapopan, C.P. 45255, cholula, Jalisco, México</td></tr><tr><td>Teléfonos</td><td>3333333333</td></tr><tr><td>Correo electrónico</td><td>pablo@jaa.com</td></tr><tr><td>CURP</td><td>444444444444444</td></tr><tr><td>RFC</td><td>Pendiente / no proporcionado</td></tr><tr><td>Tipo de identificación</td><td>INE</td></tr><tr><td>Emitida por / país emisor</td><td>México</td></tr><tr><td>Número de identificación</td><td>GGFADGFADGDA</td></tr></table>\r\n    <h4>Datos de identificación de la operación</h4>\r\n    <table><tr><th>Campo</th><th>Respuesta</th></tr><tr><td>Tipo de operación</td><td>Adquisición de tarjeta de descuento PATS</td></tr><tr><td>Monto de operación</td><td>$800.00 M.N.</td></tr><tr><td>Fecha de operación</td><td>12 de mayo de 2026</td></tr><tr><td>Forma de pago</td><td>Pasarela / medio autorizado por “EL PRESTADOR”</td></tr><tr><td>Moneda</td><td>MXN</td></tr></table>\r\n    <h4>Información de la existencia del dueño beneficiario o beneficiario controlador</h4>\r\n    <p>Declaro que soy el beneficiario directo de la operación y no existe ningún otro dueño beneficiario o beneficiario controlador: <strong>SI</strong>.</p>\r\n    <h4>Aviso de privacidad</h4><p>Los datos personales serán protegidos y tratados conforme al Aviso de Privacidad contenido en el cuerpo del presente contrato y la legislación aplicable.</p>\r\n    <p>H. Puebla de Zaragoza al 12 del mes de mayo del año 2026.</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Nombre y firma</strong><br>Pablo García García</div>\r\n  </div>\r\n\r\n  \r\n  </div>\r\n', 'data:image/png;base64,', 'Pablo García García', 'eec618517712d541d4ae87184bbdb607e265171b0487b9e23c3cacba69c4554d', '2026-05-12 23:36:23', '189.190.196.8', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:150.0) Gecko/20100101 Firefox/150.0', '', 'firmado', '2026-05-12 23:36:23', '2026-05-12 23:36:23');
INSERT INTO `pats_contratos_firmados` (`id_contrato_firmado`, `id_orden`, `id_pasaporte`, `id_distribuidor`, `id_franquicia`, `token_publico`, `contrato_clave`, `contrato_version`, `html_contrato_renderizado`, `firma_afiliado_base64`, `nombre_firmante`, `hash_contrato`, `fecha_firma`, `ip_firma`, `user_agent_firma`, `pdf_path`, `estatus`, `created_at`, `updated_at`) VALUES
(3, 5, 7, 0, 0, '', 'contrato_pats_base', '1.0', '<style>\r\n  .pats-contract{font-family:Arial,Helvetica,sans-serif;color:#172033;font-size:12px;line-height:1.52;background:#fff;padding:4px}\r\n  .pats-contract h1,.pats-contract h2,.pats-contract h3,.pats-contract h4{text-align:center;margin:12px 0 8px;color:#0d1b3e}\r\n  .pats-contract h1{font-size:16px;text-transform:uppercase;letter-spacing:.05em}\r\n  .pats-contract h2{font-size:15px;text-transform:uppercase;letter-spacing:.04em}\r\n  .pats-contract h3{font-size:13px;text-transform:uppercase;letter-spacing:.08em}\r\n  .pats-contract h4{font-size:12px;text-align:left;text-transform:uppercase;margin-top:12px}\r\n  .pats-contract p{margin:6px 0;text-align:justify}\r\n  .pats-contract ul{margin:6px 0 8px 18px;padding:0}.pats-contract li{margin:4px 0;text-align:justify}\r\n  .pats-contract table{width:100%;border-collapse:collapse;margin:8px 0 12px}.pats-contract th,.pats-contract td{border:1px solid #cbd5e1;padding:6px;vertical-align:top}.pats-contract th{background:#eef4ff;color:#0d1b3e;text-align:left}\r\n  .pats-contract .center{text-align:center}.pats-contract .muted{color:#64748b}.pats-contract .small{font-size:10px}.pats-contract .badge{display:inline-block;padding:3px 8px;border-radius:999px;background:#eef4ff;color:#1d4ed8;font-weight:700;margin:2px 4px 2px 0}\r\n  .pats-contract .sign-grid{display:grid;grid-template-columns:1fr 1fr;gap:22px;margin-top:28px}.pats-contract .sign-box{text-align:center;min-height:95px}.pats-contract .line{border-top:1px solid #0f172a;margin:48px 8px 6px}.pats-contract .signature-img{max-width:220px;max-height:82px;display:block;margin:0 auto 4px}\r\n  .pats-contract .annex{page-break-before:auto;border-top:2px solid #0d1b3e;margin-top:18px;padding-top:12px}.pats-contract .page-break{page-break-before:always;border-top:1px dashed #cbd5e1;margin-top:18px;padding-top:12px}\r\n</style>\r\n<div class=\"pats-contract\">\r\n  <h1>Carátula del contrato de adquisición de tarjeta de descuento</h1>\r\n  <p>CARÁTULA DEL CONTRATO DE ADQUISICIÓN DE TARJETA DE DESCUENTO (EN LO SUCESIVO “LA CARÁTULA”), QUE CELEBRAN POR UNA PARTE LA SOCIEDAD SEÑALADA EN EL APARTADO 1.- DE LA CARÁTULA, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL PRESTADOR”, REPRESENTADA EN ESTE ACTO POR LA PERSONA FÍSICA QUE SE INDICA EN EL APARTADO 2.- DE LA CARÁTULA; Y POR LA OTRA PARTE, LA PERSONA FÍSICA SEÑALADA EN EL APARTADO 5.- DE LA CARÁTULA, POR SU PROPIO DERECHO, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL AFILIADO”; Y CUANDO LOS ANTES NOMBRADOS ACTÚEN DE MANERA CONJUNTA, SE LES DENOMINARÁ COMO “LAS PARTES”; QUIENES SE SUJETAN AL TENOR DE LA CARÁTULA, DECLARACIONES Y CLÁUSULAS SIGUIENTES:</p>\r\n    \r\n  <h2>C A R Á T U L A</h2>\r\n  <table>\r\n    <tr><th style=\"width:8%\">Apartado</th><th style=\"width:42%\">Definición</th><th>Respuesta</th></tr>\r\n    <tr><td>1.-</td><td>Nombre de “EL PRESTADOR”</td><td>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE</td></tr>\r\n    <tr><td>2.-</td><td>Nombre del Representante Legal de “EL PRESTADOR”</td><td>PEDRO AZCÁRRAGA RAMOS</td></tr>\r\n    <tr><td>3.-</td><td>Domicilio de “EL PRESTADOR”</td><td>CALLE PASEO SINFONÍA NÚMERO EXTERIOR 1, LOCAL 2-14, LOMAS DE ANGELÓPOLIS II, SAN ANDRÉS CHOLULA, ESTADO DE PUEBLA, CÓDIGO POSTAL 72830</td></tr>\r\n    <tr><td>4.-</td><td>Clave del Registro Federal de Contribuyentes de “EL PRESTADOR”</td><td>COH2202144H5</td></tr>\r\n    <tr><td>5.-</td><td>Nombre de “EL AFILIADO”</td><td>Jua Carlos Fuentes Moya</td></tr>\r\n    <tr><td>6.-</td><td>Domicilio de “EL AFILIADO”</td><td>Jornal 115, Col. zapopan, C.P. 45255, zapopan, Jalisco, México</td></tr>\r\n    <tr><td>7.-</td><td>Clave del Registro Federal de Contribuyentes de “EL AFILIADO”</td><td>FUMJ81082222</td></tr>\r\n    <tr><td>8.-</td><td>Costo mensual de “LA TARJETA DE DESCUENTO”</td><td>$800.00 M.N.</td></tr>\r\n    <tr><td>9.-</td><td>Cuenta bancaria de “EL PRESTADOR” para pagos</td><td>Cuenta: 01600866709<br>CLABE: 042650016008667096<br>Institución Bancaria: Banca Mifel, S.A., Institución de Banca Múltiple, Grupo Financiero Mifel</td></tr>\r\n    <tr><td>10.-</td><td>Cuota de Reactivación de “LA TARJETA DE DESCUENTO”</td><td>$100.00 M.N. por cada mes que se haya interrumpido el pago.</td></tr>\r\n    <tr><td>11.-</td><td>Datos de la Tarjeta de Crédito de “EL AFILIADO”</td><td>Número de tarjeta: pendiente de confirmar por pasarela/token de pago.<br>Institución bancaria: pendiente de confirmar por pasarela. <br><span class=\"small\">No se almacena número completo de tarjeta en este formulario.</span></td></tr>\r\n    <tr><td>12.-</td><td>Anexos</td><td>ANEXO 1. Identificación oficial de “EL AFILIADO”<br>ANEXO 2. Comprobante de domicilio de “EL AFILIADO”<br>ANEXO 3. Constancia de Situación Fiscal de “EL AFILIADO”, si aplica<br>ANEXO 4. Cuotas de recuperación y/o precios base a cubrir a “EL PRESTADOR”<br>ANEXO 5. Aviso de privacidad<br>ANEXO 6. Declaración de dueño beneficiario</td></tr>\r\n    <tr><td>13.-</td><td>Fecha de Firma del Contrato</td><td>12 de mayo de 2026</td></tr>\r\n  </table>\r\n\r\n  <div class=\"sign-grid\">\r\n    <div class=\"sign-box\"><div class=\"line\"></div><strong>“EL PRESTADOR”</strong><br>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE<br>Representada por PEDRO AZCÁRRAGA RAMOS</div>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>“EL AFILIADO”</strong><br>Jua Carlos Fuentes Moya<br><span class=\"small\">La persona física señalada en el Apartado 5.- de la Carátula</span></div>\r\n  </div>\r\n\r\n  <div class=\"page-break\"></div>\r\n  <h1>Contrato de adquisición de tarjeta de descuento</h1>\r\n  <p>CONTRATO DE ADQUISICIÓN DE TARJETA DE DESCUENTO, QUE CELEBRAN POR UNA PARTE LA SOCIEDAD SEÑALADA EN EL APARTADO 1.- DE LA CARÁTULA, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL PRESTADOR”, REPRESENTADA EN ESTE ACTO POR LA PERSONA FÍSICA QUE SE INDICA EN EL APARTADO 2.- DE LA CARÁTULA; Y POR LA OTRA PARTE, LA PERSONA FÍSICA SEÑALADA EN EL APARTADO 5.- DE LA CARÁTULA, POR SU PROPIO DERECHO, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL AFILIADO”; Y CUANDO LOS ANTES NOMBRADOS ACTÚEN DE MANERA CONJUNTA, SE LES DENOMINARÁ COMO “LAS PARTES”; QUIENES SE SUJETAN AL TENOR DE LAS DECLARACIONES Y CLÁUSULAS SIGUIENTES:</p>\r\n\r\n  <h2>D E C L A R A C I O N E S</h2>\r\n  <h4>I.- Declara “EL PRESTADOR” por conducto de su representación:</h4>\r\n  <p>A. Que, su representada es una sociedad mercantil constituida conforme a las leyes de los Estados Unidos Mexicanos, según consta en la escritura pública número 39,861, del volumen 830 de fecha catorce de febrero de dos mil veintidós, otorgada ante la fe del Licenciado Ernesto Joaquín Briones Amador, Notario Público Titular de la Notaría Pública número 46 de las del Distrito Judicial de Puebla, Estado de Puebla, cuyo primer testimonio se encuentra inscrito ante las oficinas del Registro Público de Comercio del Distrito Judicial de Puebla, Estado de Puebla, bajo el Folio Mercantil Electrónico: N-2022022991, por virtud del cual se llevó a cabo la Constitución de la persona moral denominada CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE.</p>\r\n  <p>B. Que, la persona física que la representa en este acto, señalada en el Apartado 2.- de la Carátula, cuenta con todas y cada una de las facultades necesarias para la celebración del presente contrato, las cuales se desprenden del instrumento descrito en el punto declarativo inmediato anterior, mismas que manifiesta bajo protesta de decir verdad que no le han sido suspendidas, revocadas o limitadas en forma alguna.</p>\r\n  <p>C. Que, su representada tiene como domicilio fiscal el señalado en el Apartado 3.- de la Carátula del presente contrato, mismo que designa como domicilio convencional para cualquier cuestión relacionada con la celebración del presente contrato.</p>\r\n  <p>D. Que, su representada se encuentra inscrita en el Registro Federal de Contribuyentes bajo la clave señalada en el Apartado 4.- de la Carátula.</p>\r\n  <p>E. Que, ha desarrollado y es su deseo comparecer a la celebración del presente instrumento con la finalidad de enajenar en favor de “EL AFILIADO”, una Tarjeta de Descuento que da acceso a “UN PROGRAMA DE BENEFICIOS QUE OTORGA DESCUENTOS A LOS COSTOS Y PERMITE RECIBIR SERVICIOS MÉDICOS PRIVADOS DE ALTA CALIDAD DE FORMA ACCESIBLE, CLARA Y SIN RESTRICCIONES DENTRO DE LA RED DE HOSPITALES 50 (FIFTY) DOCTORS CON SEDE EN EL ESTADO DE PUEBLA”, en lo sucesivo “LA TARJETA DE DESCUENTO”, en los términos y condiciones que se establecerán más adelante.</p>\r\n  <p>F. Que, su representada no es una Aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas sino una empresa dedicada, entre otros, a la operación y administración de establecimientos destinados a la atención y asistencia de enfermos, por lo que la enajenación de “LA TARJETA DE DESCUENTO” únicamente constituye un acto de comercio que brindará a “EL AFILIADO” acceso a un programa de beneficios como ha quedado descrito anteriormente.</p>\r\n\r\n  <h4>II.- Declara “EL AFILIADO”, por su propio derecho:</h4>\r\n      <p>A. Que, su nombre se señala en el Apartado 5.- de la Carátula, es una persona física de nacionalidad mexicana, en pleno ejercicio de sus derechos, legal y jurídicamente capaz para celebrar el presente Contrato, quien se identifica con credencial para votar vigente expedida por el Instituto Nacional Electoral, tipo INE, número 1452114522, que en copia simple o archivo digital se agrega al cuerpo del presente contrato como ANEXO 1.</p>\r\n    <p>B. Que, tiene como domicilio particular el señalado en el Apartado 6.- de la Carátula, mismo que designa como domicilio convencional para cualquier cuestión relacionada con la celebración del presente contrato, tal y como lo acredita con el comprobante de domicilio que en copia simple o archivo digital se agrega al cuerpo del presente contrato como ANEXO 2.</p>\r\n  <p>C. Que, su CURP es 145214521452145214 y su RFC/identificación fiscal es FUMJ81082222; asimismo manifiesta que cuenta con capacidad económica para obligarse en términos del presente contrato y que los recursos con los que cubrirá sus obligaciones provendrán de fuentes lícitas. En caso de nacionalidad extranjera/no mexicana, se tendrán por no aplicables CURP, INE y constancia fiscal mexicana salvo manifestación expresa de residencia fiscal o RFC mexicano.</p>\r\n  <p>D. Que, es su deseo comparecer a la celebración del presente instrumento con la finalidad de adquirir “LA TARJETA DE DESCUENTO” de acuerdo con los términos y condiciones que se establecen a continuación.</p>\r\n  <p>E. Que, previo a la celebración del presente contrato fue informado y manifiesta expresamente que reconoce que “EL PRESTADOR” no es una Aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas y que las actividades comerciales objeto del presente contrato no consisten en la contratación de un seguro, de la índole que fuere, sino que únicamente implica la adquisición de una tarjeta de descuento que da acceso a un programa de beneficios que otorga descuentos a los costos y permite recibir servicios médicos privados de alta calidad de forma accesible, clara y sin restricciones dentro de la red de hospitales 50 (FIFTY) Doctors con sede en el Estado de Puebla.</p>\r\n  <p>F. Que, reconoce que “EL PRESTADOR” se dedica a la operación de centros hospitalarios y que la emisión de “LA TARJETA DE DESCUENTO” únicamente corresponde a la intención de este último de crear un programa de descuentos para el acceso a los servicios prestados por la Red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla.</p>\r\n\r\n  <h4>III.- Declaran conjuntamente “LAS PARTES”:</h4>\r\n  <p>1. Que, se reconocen recíprocamente la personalidad con la que comparecen a la celebración del presente acuerdo de voluntades.</p>\r\n  <p>2. Que, el presente contrato es el instrumento que las vincula en sus derechos y obligaciones.</p>\r\n  <p>3. Que, es su deseo celebrar el presente contrato y han negociado libremente los términos y condiciones del mismo con pleno conocimiento de sus alcances e implicaciones jurídicas, por lo que en su celebración no existe dolo, error, mala fe, lesión o cualquier otro vicio del consentimiento que pudiese afectarlo de inexistencia o nulidad.</p>\r\n\r\n  <h2>C L Á U S U L A S</h2>\r\n  <h4>PRIMERA.- OBJETO.</h4>\r\n  <p>El objeto del presente Contrato es que “EL AFILIADO” adquiera de “EL PRESTADOR”, a título oneroso y temporal, el derecho de uso ilimitado y sin restricción alguna de “LA TARJETA DE DESCUENTO” emitida por CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE, la cual consiste en que “EL AFILIADO” aproveche y acceda a “UN PROGRAMA DE BENEFICIOS QUE OTORGA DESCUENTOS A LOS COSTOS Y PERMITE RECIBIR SERVICIOS MÉDICOS PRIVADOS DE ALTA CALIDAD DE FORMA ACCESIBLE, CLARA Y SIN RESTRICCIONES DENTRO DE LA RED DE HOSPITALES 50 (FIFTY) DOCTORS CON SEDE EN EL ESTADO DE PUEBLA”.</p>\r\n  <p>Estableciendo que, la comercialización de “LA TARJETA DE DESCUENTO” por parte de “EL PRESTADOR” en ningún momento constituirá la venta, promoción o por cualquier medio la contratación de una póliza de seguro, bajo el entendido de que “EL PRESTADOR” no es una aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas (CNSF); sino que comercializa “LA TARJETA DE DESCUENTO” en favor de terceros con la finalidad de otorgar descuentos a los precios respecto de los servicios médicos que presta en el territorio nacional.</p>\r\n\r\n  <h4>SEGUNDA.- PRECIO DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“LAS PARTES” establecen de común acuerdo que “LA TARJETA DE DESCUENTO” tendrá como costo mensual la cantidad señalada en el Apartado 8.- de la Carátula del presente contrato; cantidad que ya incluye IVA, y la cual deberá ser cubierta por “EL AFILIADO” en favor de “EL PRESTADOR” dentro de los primeros 5 (cinco) días de cada mes, sin necesidad de gestiones o avisos de cobro, ya sea mediante:</p>\r\n  <p>(i) Transferencia electrónica de fondos a la cuenta bancaria señalada en el Apartado 9.- de la Carátula del presente contrato y de la cual es titular “EL PRESTADOR”.</p>\r\n  <p>(ii) Cheque que se recibirá salvo buen cobro en el Domicilio de “EL PRESTADOR” señalado en el Apartado 3.- de la Carátula del presente contrato, y que en caso de no ser pagado por falta de fondos suficientes o por otras causas imputables a “EL AFILIADO”, éste último está de acuerdo en que deberá cubrir a “EL PRESTADOR” el 20% (veinte por ciento) del monto del cheque por concepto de indemnización por daños y perjuicios en términos del artículo 193 de la Ley General de Títulos y Operaciones de Crédito, independientemente de cualquier otro cargo que se pudiera generar.</p>\r\n  <p>(iii) Cargos mensuales automáticos recurrentes a la tarjeta de crédito de “EL AFILIADO” según los datos señalados en el Apartado 11.- de la Carátula del presente contrato, quien manifiesta bajo protesta de decir verdad que autoriza a “EL PRESTADOR” a realizar los cargos mensuales correspondientes por el costo mensual de “LA TARJETA DE DESCUENTO” en dicha tarjeta o en la tarjeta que por renovación, reposición, robo o extravío le haya asignado el banco emisor. La autorización estará vigente mientras “EL AFILIADO” no haya notificado a “EL PRESTADOR” por escrito y con acuse de recibo su deseo de cancelar su afiliación o no renovarla, o en su defecto, realizar su baja respectiva en el sitio web o aplicación de “EL PRESTADOR”.</p>\r\n  <p>Esta autorización no exime a “EL AFILIADO” del pago mensual por el uso de “LA TARJETA DE DESCUENTO” y demás obligaciones contractuales, por lo que, en caso de que el cobro no sea autorizado por el banco emisor o por cualquier razón no pueda realizarse, “EL AFILIADO” deberá notificar tal situación a “EL PRESTADOR” a la dirección de correo electrónico silvia@pasaporteatusalud.com, a efecto de solicitar una forma de pago diversa, quedando obligado a cubrir de inmediato el pago correspondiente.</p>\r\n  <p>(iv) Cualquier otro medio de pago aceptado por “EL PRESTADOR”, mismo que se dará a conocer a través de sus medios oficiales de comunicación.</p>\r\n  <p>“EL PRESTADOR” podrá variar unilateralmente el costo mensual de “LA TARJETA DE DESCUENTO”, previo aviso a “EL AFILIADO” con 30 (treinta) días de anticipación a través de sus medios oficiales de comunicación.</p>\r\n  <p>Para el caso de que “EL AFILIADO” adquiera y cubra el precio de “LA TARJETA DE DESCUENTO” y posteriormente deje de pagar una mensualidad, deberá cubrir a “EL PRESTADOR”, por concepto de cuota de reactivación, la cantidad señalada en el Apartado 10.- de la Carátula por cada mes que haya interrumpido y/o no haya cubierto el precio de “LA TARJETA DE DESCUENTO”, hasta la fecha en que pretenda volver a adquirirla.</p>\r\n\r\n  <h4>TERCERA.- VIGENCIA DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“LA TARJETA DE DESCUENTO” objeto del presente contrato tendrá una vigencia de 30 días contados a partir de que “EL AFILIADO” cubra a “EL PRESTADOR” el precio establecido anteriormente, en el entendido de que la vigencia del presente contrato y de “LA TARJETA DE DESCUENTO” se prorrogarán automáticamente sin necesidad de celebrar documento adicional entre “LAS PARTES” siempre y cuando “EL AFILIADO” cubra, de mes en mes o en la frecuencia contratada, el precio vigente de “LA TARJETA DE DESCUENTO”.</p>\r\n  <p>“EL AFILIADO” tendrá derecho a revocar su consentimiento dentro de los 5 (cinco) días siguientes a la entrega de “LA TARJETA DE DESCUENTO” o la firma del presente contrato, lo que ocurra último, sin responsabilidad alguna, siempre y cuando no haya obtenido beneficio alguno por el uso de “LA TARJETA DE DESCUENTO”.</p>\r\n\r\n  <h4>CUARTA.- BENEFICIOS DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“EL AFILIADO”, de forma exclusiva, personal e intransferible, gozará de forma gratuita de los servicios que se mencionan a continuación:</p>\r\n  <ul><li>Consultas gratuitas ilimitadas de medicina general (no de especialidad) en la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla, únicamente con los doctores afiliados al programa de Pasaporte a tu Salud.</li><li>Consultas de urgencia gratuitas en la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla.</li></ul>\r\n  <p>No así respecto de los servicios que, de manera enunciativa más no limitativa, se describen a continuación:</p>\r\n  <ul><li>Hospitalización dentro de la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla, sujeto a la disponibilidad de cada uno de ellos.</li><li>Consultas de especialidad ilimitadas a costo preferencial, con médicos especialistas pertenecientes al programa PATS.</li><li>Acceso a farmacia PATS con costos reducidos de medicamentos genéricos.</li><li>Imagenología y laboratorios ilimitados con costos preferenciales.</li><li>Acceso a cirugías con cuota de recuperación preferente, con o sin honorarios médicos incluidos según corresponda.</li></ul>\r\n  <p>Dichos servicios generarán, por evento, el pago de una cuota con cargo a “EL AFILIADO”, misma que resultará de aplicar los porcentajes de descuento que se desprenden del ANEXO 4 del presente contrato a los precios publicados al público en general o los precios preferenciales indicados.</p>\r\n  <p>Mientras “LA TARJETA DE DESCUENTO” se encuentre vigente, “EL AFILIADO” gozará de todos los beneficios que la misma le otorga; sin embargo, para el caso de que requiera cirugía o procedimiento quirúrgico en quirófano, deberá haber sufragado por adelantado la adquisición de “LA TARJETA DE DESCUENTO” por un periodo de 12 (doce) meses y encontrarse dentro de dicho periodo de vigencia.</p>\r\n\r\n  <h4>QUINTA.- OBLIGACIONES DE “EL PRESTADOR”.</h4>\r\n  <p>“EL PRESTADOR” se obliga a: (i) otorgar a “EL AFILIADO” el acceso ilimitado a “LA TARJETA DE DESCUENTO” durante la vigencia del contrato; (ii) mantener actualizada y operativa la Red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla; (iii) proporcionar a “EL AFILIADO”, de forma digital, “LA TARJETA DE DESCUENTO” dentro de los 5 (cinco) días hábiles siguientes al primer pago; e (iv) informar por escrito cualquier modificación a la red de hospitales o al tabulador de cuotas con al menos 10 (diez) días de anticipación.</p>\r\n\r\n  <h4>SEXTA.- OBLIGACIONES DE “EL AFILIADO”.</h4>\r\n  <p>“EL AFILIADO” se obliga a: (i) pagar puntualmente el precio de “LA TARJETA DE DESCUENTO”; (ii) utilizarla de forma exclusiva, personal e intransferible; (iii) cubrir directamente a los hospitales y con anterioridad a recibir el servicio médico las cuotas de recuperación según tabulador vigente; (iv) presentar identificación oficial y “LA TARJETA DE DESCUENTO” o código QR cada vez que haga uso de beneficios; y (v) notificar por escrito cualquier cambio de domicilio o datos de contacto en un plazo no mayor a 5 (cinco) días.</p>\r\n\r\n  <h4>SÉPTIMA.- ACCESO A LOS BENEFICIOS Y PROCEDIMIENTO.</h4>\r\n  <p>Para hacer uso de “LA TARJETA DE DESCUENTO”, “EL AFILIADO” deberá agendar sus citas directamente con los doctores pertenecientes a la Red de Hospitales 50 (FIFTY) Doctors, que en ese momento se encuentren adscritos al programa de beneficios, a través de la aplicación oficial, página de internet oficial de PATS o medios oficiales que indique “EL PRESTADOR”.</p>\r\n  <p>“EL AFILIADO” se obliga a pagar directamente al médico especialista perteneciente al programa el costo de la consulta de especialidad de que se trate, en términos de los porcentajes de descuento del ANEXO 4. En caso de no estar facultado para asistir por fuerza mayor, tendrá un plazo de 30 (treinta) días contados a partir de haber generado la cita para solicitar una nueva consulta médica.</p>\r\n\r\n  <h4>OCTAVA.- EXCLUSIONES Y LIMITACIONES.</h4>\r\n  <p>Los beneficios no incluirán: (i) trasplantes de órganos; (ii) tratamientos experimentales; (iii) tratamientos de oncología a excepción de algunas cirugías; (iv) medicamentos extra hospitalarios que no estén recogidos en el catálogo de Farmacia PATS; (v) atención médica con especialistas no adscritos o no publicados en los medios oficiales; y (vi) cualquier servicio no listado expresamente.</p>\r\n\r\n  <h4>NOVENA.- CAUSAS DE TERMINACIÓN.</h4>\r\n  <p>El contrato podrá terminarse por falta de pago, mutuo consentimiento por escrito o incumplimiento de cualquiera de las cláusulas por cualquiera de “LAS PARTES”. En caso de terminación, “EL AFILIADO” no tendrá derecho a exigir la devolución de cantidad alguna.</p>\r\n\r\n  <h4>DÉCIMA.- CANCELACIÓN VOLUNTARIA.</h4>\r\n  <p>“EL AFILIADO” podrá cancelar “LA TARJETA DE DESCUENTO” mediante aviso por escrito con 30 (treinta) días de anticipación. Dicha cancelación surtirá efectos a partir del siguiente periodo mensual y no generará reembolso de pagos ya realizados.</p>\r\n\r\n  <h4>DÉCIMA PRIMERA.- PROTECCIÓN DE DATOS PERSONALES.</h4>\r\n  <p>“LAS PARTES” acuerdan que el tratamiento de datos personales se sujetará a la Ley Federal de Protección de Datos Personales en Posesión de los Particulares. “EL AFILIADO” autoriza expresamente el uso de sus datos para la gestión de “LA TARJETA DE DESCUENTO”. El aviso de privacidad se integra al presente contrato como ANEXO 5.</p>\r\n\r\n  <h4>DÉCIMA SEGUNDA.- RESPONSABILIDAD.</h4>\r\n  <p>“EL AFILIADO” reconoce y acepta que “LA TARJETA DE DESCUENTO” es emitida y administrada directamente por CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE, quien es responsable de la operación de la red de descuentos, afiliación de prestadores médicos y prestación de cualquier servicio relacionado con “LA TARJETA DE DESCUENTO”.</p>\r\n  <p>En consecuencia, “EL PRESTADOR” no tendrá responsabilidad directa ni indirecta por la prestación, calidad, eficacia, resultado, daño, perjuicio, lesión, complicación, secuela, evento adverso o consecuencia derivada de servicios médicos recibidos, incluyendo aquellos ocasionados por negligencia, impericia o mala praxis de profesionales de la salud o prestadores afiliados. Cualquier relación derivada de la prestación de servicios médicos se establece directamente entre “EL AFILIADO” y los prestadores de servicios de salud correspondientes. Esta limitación subsistirá a la terminación del contrato.</p>\r\n\r\n  <h4>DÉCIMA TERCERA.- PREVENCIÓN DE LAVADO DE DINERO Y ORIGEN DE LOS RECURSOS.</h4>\r\n  <p>“LAS PARTES” declaran bajo protesta de decir verdad que los recursos económicos, bienes y derechos que utilicen para cumplir obligaciones derivadas de este contrato tienen y tendrán origen lícito. “EL AFILIADO” manifiesta que el pago inicial y pagos futuros provienen de fuentes lícitas y no de actividades tipificadas como delitos.</p>\r\n  <p>“LAS PARTES” reconocen que la prestación de servicios de comercio puede ser considerada actividad vulnerable, por lo que se obligan a proporcionar información y documentación requerida para integrar expediente de identificación e informar si tienen conocimiento de la existencia de beneficiario controlador.</p>\r\n\r\n  <h4>DÉCIMA CUARTA.- CONFORMACIÓN DEL EXPEDIENTE DE IDENTIFICACIÓN.</h4>\r\n  <p>“EL PRESTADOR” queda obligado a conformar y mantener un expediente de identificación de “EL AFILIADO”. Para tales efectos, “EL AFILIADO” se obliga a entregar los documentos aplicables: identificación oficial vigente o pasaporte, acta de nacimiento cuando aplique, comprobante de domicilio, constancia de situación fiscal cuando aplique, CURP, y declaración de dueño beneficiario.</p>\r\n  <p>Cuando exista persona responsable, la documentación de identificación y representación deberá integrarse al expediente; la CIF/constancia fiscal corresponde al tutor cuando aplique. “EL PRESTADOR” conservará dicho expediente por un periodo mínimo de 5 (cinco) años contados a partir de que termine la vigencia del contrato o termine por cualquiera de sus causales, garantizando la confidencialidad de los datos personales.</p>\r\n\r\n  <h4>DÉCIMA QUINTA.- CAUSAL ESPECÍFICA DE RESCISIÓN.</h4>\r\n  <p>Será motivo de rescisión inmediata sin necesidad de declaración judicial y sin responsabilidad para la parte afectada cuando cualquiera de “LAS PARTES” se niegue a proporcionar información requerida para cumplimiento de la Ley Federal para la Prevención e Identificación de Operaciones con Recursos de Procedencia Ilícita, proporcione información falsa o aparezca en listas de personas bloqueadas emitidas por autoridad competente.</p>\r\n\r\n  <h4>DÉCIMA SEXTA.- LEGISLACIÓN APLICABLE Y JURISDICCIÓN.</h4>\r\n  <p>“LAS PARTES” establecen que la Procuraduría Federal del Consumidor es competente en vía administrativa para resolver cualquier controversia sobre interpretación o cumplimiento. Sin perjuicio de lo anterior, se someten expresamente a la jurisdicción de los tribunales competentes del fuero común del Distrito Judicial de Puebla, Estado de Puebla, renunciando de manera expresa e irrevocable a cualquier otro fuero o jurisdicción que pudiera corresponderles.</p>\r\n\r\n  <p>Enteradas “LAS PARTES” del contenido y alcance del presente contrato, y entendidas de los derechos y obligaciones que contraen, firman el presente instrumento, incluyendo sus anexos, manifestando que no medió error, dolo, mala fe, violencia o lesión, ni vicio del consentimiento alguno, en la Ciudad de Puebla, Estado de Puebla, reconociendo que la fecha de firma es 12 de mayo de 2026.</p>\r\n\r\n  <div class=\"sign-grid\">\r\n    <div class=\"sign-box\"><div class=\"line\"></div><strong>“EL PRESTADOR”</strong><br>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE<br>Representada por PEDRO AZCÁRRAGA RAMOS</div>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>“EL AFILIADO”</strong><br>Jua Carlos Fuentes Moya</div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 1<br>Identificación oficial de “EL AFILIADO”</h2><p>Se integra al expediente la identificación oficial cargada por el usuario en el formulario. Para mexicanos, corresponde a identificación oficial/INE cuando aplique. Para extranjeros/no mexicanos, corresponde a identificación oficial o pasaporte vigente; al menos el frente es obligatorio y el reverso será opcional cuando el documento no lo tenga.</p><p><strong>Tipo:</strong> INE. <strong>Emitida por / país emisor:</strong> México. <strong>Número:</strong> 1452114522.</p></div>\r\n  <div class=\"annex\"><h2>ANEXO 2<br>COMPROBANTE DE DOMICILIO DE “EL AFILIADO”</h2><p>Se integra al expediente el comprobante de domicilio cargado por el usuario. Domicilio declarado: Jornal 115, Col. zapopan, C.P. 45255, zapopan, Jalisco, México.</p></div>\r\n  <div class=\"annex\"><h2>ANEXO 3<br>CONSTANCIA DE SITUACIÓN FISCAL DE “EL AFILIADO”</h2><p>Constancia de Situación Fiscal de “EL AFILIADO”, si aplica. En caso de pacientes representados, la constancia fiscal o CIF corresponde a la persona responsable cuando sea aplicable, no al menor. Para afiliados extranjeros/no mexicanos, no será obligatoria salvo que declaren RFC mexicano o residencia fiscal aplicable.</p></div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 4<br>CUOTAS DE RECUPERACIÓN Y/O PRECIOS BASE A CUBRIR A “EL PRESTADOR”</h2>\r\n    <p>En el presente anexo se establecen los porcentajes de descuento a obtener como titular de “LA TARJETA DE DESCUENTO”, por lo que la cantidad a cubrir por “EL AFILIADO” directamente al hospital de la cadena 50 (FIFTY) Doctors o al doctor que preste el servicio se obtendrá de aplicar el porcentaje de descuento correspondiente al precio publicado por los medios oficiales o al precio vigente en el establecimiento.</p>\r\n    <table><tr><th>Servicios / procedimientos</th><th>Descuentos</th></tr><tr><td>Consulta de urgencias</td><td>100%</td></tr><tr><td>Consulta de medicina general</td><td>100%</td></tr><tr><td>Habitación hospitalaria</td><td>90%</td></tr><tr><td>Uso de áreas de urgencias médicas</td><td>80%</td></tr><tr><td>Utilización de cubículos de terapia intensiva (UCIA-UCIN-UCIP)</td><td>75%</td></tr><tr><td>CEYE</td><td>75%</td></tr><tr><td>Uso quirófano</td><td>75%</td></tr><tr><td>Servicio de cuneros</td><td>75%</td></tr><tr><td>Materiales & medicamentos del cuadro básico, genéricos intercambiables</td><td>70%</td></tr><tr><td>Hemodinamia</td><td>70%</td></tr><tr><td>Imagenología</td><td>70%</td></tr><tr><td>Endoprótesis</td><td>70%</td></tr><tr><td>Osteosíntesis</td><td>70%</td></tr><tr><td>Prótesis</td><td>70%</td></tr><tr><td>Órtesis</td><td>70%</td></tr><tr><td>Laboratorio clínico</td><td>60%</td></tr></table>\r\n    <p class=\"small\">Los descuentos aplican con los proveedores suscritos al convenio de Pasaporte a tu Salud.</p>\r\n    <table><tr><th>Servicios / procedimientos</th><th>Precios base</th></tr><tr><td>Consulta de especialidades médicas</td><td>$390.00</td></tr><tr><td>Colposcopía</td><td>$400.00</td></tr><tr><td>Retiro de puntos de sutura</td><td>$80.00</td></tr><tr><td>Aplicación de medicamento intramuscular</td><td>$60.00</td></tr><tr><td>Retiro de DIU</td><td>$500.00</td></tr><tr><td>Colocación de DIU</td><td>$700.00</td></tr><tr><td>Extracción de cuerpo extraño (oído y nariz)</td><td>$300.00</td></tr><tr><td>Lavado ótico</td><td>$250.00</td></tr><tr><td>Curación de sitio quirúrgico</td><td>$250.00</td></tr><tr><td>Retiro de yeso</td><td>$250.00</td></tr><tr><td>Visita día de hospitalización</td><td>$650.00</td></tr><tr><td>Visita de urgencias</td><td>$750.00</td></tr><tr><td>Día de terapia intensiva</td><td>$850.00</td></tr></table>\r\n    <p class=\"small\">Todos los precios incluyen IVA. La factura de servicios hospitalarios será emitida con el desglose correspondiente y el ahorro otorgado por ser titular de “LA TARJETA DE DESCUENTO”.</p>\r\n    <p>Exclusiones y limitaciones: se aplicarán descuentos y precios especiales para el acompañante de “EL AFILIADO” en la misma habitación únicamente para la primera noche de hospitalización. Los precios y porcentajes de descuento darán derecho a la utilización de materiales y medicamentos del cuadro básico, genéricos intercambiables; cualquier otro tipo de medicación será cubierto directamente por “EL AFILIADO”. Los costos de procedimientos quirúrgicos incluyen honorarios médicos cuando así se indique. “EL AFILIADO” podrá atenderse con el médico tratante que elija, debiendo cubrir honorarios directamente a dicho médico, conservando el derecho a beneficios dentro de la red aplicable.</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Firma de aceptación de “EL AFILIADO”</strong><br>Jua Carlos Fuentes Moya</div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 5<br>AVISO DE PRIVACIDAD</h2>\r\n    <p>En cumplimiento de las disposiciones establecidas en la Ley Federal de Protección de Datos Personales en Posesión de Particulares, su Reglamento y los lineamientos aplicables, “CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE” (en lo sucesivo “EL PRESTADOR”), con domicilio en CALLE PASEO SINFONÍA NÚMERO EXTERIOR 1, LOCAL 2-14, LOMAS DE ANGELÓPOLIS II, SAN ANDRÉS CHOLULA, ESTADO DE PUEBLA, CÓDIGO POSTAL 72830, da a conocer el Aviso de Privacidad al tenor del cual manejará por medio de su representación y/o empleados los datos personales y/o documentación proporcionada por el afiliado o usuario de “LA TARJETA DE DESCUENTO”.</p>\r\n    <p>Se tendrá por aceptado expresamente el presente Aviso de Privacidad una vez proporcionados los datos personales y firmada digitalmente la aceptación del contrato, motivo por el cual “EL PRESTADOR” estará facultado para manejar la información conforme a la legislación aplicable.</p>\r\n    <h4>Modificación del aviso de privacidad</h4><p>Este aviso podrá ser modificado o adecuado a las necesidades de “EL PRESTADOR”. Las modificaciones o actualizaciones serán incorporadas al presente aviso y estarán disponibles en la página de internet, domicilio de “EL PRESTADOR” o serán enviadas al último correo electrónico proporcionado.</p>\r\n    <h4>Finalidad de la información</h4><p>La información será utilizada para: elaborar y mantener actualizada la base de usuarios; identificar afiliados; proporcionar la tarjeta digital; otorgar acceso al programa de beneficios; informar modificaciones a la red o tabulador; realizar análisis estadísticos internos y brindar un óptimo servicio médico.</p>\r\n    <h4>Tipo de datos necesarios</h4><p>Se solicitarán datos de identificación, contacto, legales, contractuales y fiscales cuando aplique, incluyendo nombre completo, lugar y fecha de nacimiento, firma, identificación oficial, nacionalidad, CURP y RFC cuando sean aplicables, domicilio, teléfono y correo electrónico.</p>\r\n    <h4>Transferencias de la información</h4><p>El usuario autoriza proporcionar información sin consentimiento adicional en los casos previstos por ley, resolución de autoridad competente, tratados aplicables, salvaguarda de interés público, procuración o administración de justicia, reconocimiento o defensa de derechos en procesos judiciales, y a socios comerciales, técnicos o estratégicos que asuman obligaciones de confidencialidad y seguridad equivalentes.</p>\r\n    <h4>Limitación del uso o divulgación de datos y derechos ARCO</h4><p>El usuario podrá limitar el uso o divulgación de sus datos personales y ejercer derechos de acceso, rectificación, cancelación u oposición mediante solicitud escrita dirigida a “EL PRESTADOR” en su domicilio o al correo silvia@pasaporteatusalud.com, acompañando documento que acredite su identidad.</p>\r\n    <h4>Revocación de consentimiento</h4><p>El usuario podrá revocar su consentimiento siguiendo el mismo procedimiento, considerando que para ciertos fines la revocación puede implicar la cancelación de “LA TARJETA DE DESCUENTO” y la imposibilidad de acceder al programa.</p>\r\n    <p><strong>Nombre:</strong> Jua Carlos Fuentes Moya<br><strong>Fecha:</strong> 12 de mayo de 2026</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Firma</strong></div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 6<br>DECLARACIÓN DE DUEÑO BENEFICIARIO</h2>\r\n    <p>DE CONFORMIDAD CON LO DISPUESTO EN LOS ARTÍCULOS 18 FRACCIÓN I Y III DE LA LEY FEDERAL PARA PREVENCIÓN E IDENTIFICACIÓN DE OPERACIONES CON RECURSOS DE PROCEDENCIA ILÍCITA, EL ARTÍCULO 15 DE SU REGLAMENTO Y EL ARTÍCULO 13 DE LAS REGLAS DE CARÁCTER GENERAL, MANIFIESTO BAJO PROTESTA DE DECIR VERDAD:</p>\r\n    <h4>Datos de identificación del cliente</h4>\r\n    <table><tr><th>Campo</th><th>Respuesta</th></tr><tr><td>Apellido paterno, materno y nombre(s)</td><td>Jua Carlos Fuentes Moya</td></tr><tr><td>Fecha de nacimiento</td><td>1981-08-22</td></tr><tr><td>País de nacimiento</td><td>México</td></tr><tr><td>Nacionalidad</td><td>mexicana</td></tr><tr><td>Actividad, ocupación o profesión</td><td>Estudiante</td></tr><tr><td>Estado civil</td><td>SOLTERO(A)</td></tr><tr><td>Domicilio particular</td><td>Jornal 115, Col. zapopan, C.P. 45255, zapopan, Jalisco, México</td></tr><tr><td>Teléfonos</td><td>3333333333</td></tr><tr><td>Correo electrónico</td><td>roel.fuentes@gmail.com</td></tr><tr><td>CURP</td><td>145214521452145214</td></tr><tr><td>RFC</td><td>FUMJ81082222</td></tr><tr><td>Tipo de identificación</td><td>INE</td></tr><tr><td>Emitida por / país emisor</td><td>México</td></tr><tr><td>Número de identificación</td><td>1452114522</td></tr></table>\r\n    <h4>Datos de identificación de la operación</h4>\r\n    <table><tr><th>Campo</th><th>Respuesta</th></tr><tr><td>Tipo de operación</td><td>Adquisición de tarjeta de descuento PATS</td></tr><tr><td>Monto de operación</td><td>$800.00 M.N.</td></tr><tr><td>Fecha de operación</td><td>12 de mayo de 2026</td></tr><tr><td>Forma de pago</td><td>Pasarela / medio autorizado por “EL PRESTADOR”</td></tr><tr><td>Moneda</td><td>MXN</td></tr></table>\r\n    <h4>Información de la existencia del dueño beneficiario o beneficiario controlador</h4>\r\n    <p>Declaro que soy el beneficiario directo de la operación y no existe ningún otro dueño beneficiario o beneficiario controlador: <strong>SI</strong>.</p>\r\n    <h4>Aviso de privacidad</h4><p>Los datos personales serán protegidos y tratados conforme al Aviso de Privacidad contenido en el cuerpo del presente contrato y la legislación aplicable.</p>\r\n    <p>H. Puebla de Zaragoza al 12 del mes de mayo del año 2026.</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Nombre y firma</strong><br>Jua Carlos Fuentes Moya</div>\r\n  </div>\r\n\r\n  \r\n  </div>\r\n', 'data:image/png;base64,', 'Jua Carlos Fuentes Moya', '75ee35f1fc5ce1c840c938584a78ba8d02679225bf6ef60aab34537728053ded', '2026-05-12 23:53:40', '189.190.196.8', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:150.0) Gecko/20100101 Firefox/150.0', '', 'firmado', '2026-05-12 23:53:40', '2026-05-12 23:53:40');
INSERT INTO `pats_contratos_firmados` (`id_contrato_firmado`, `id_orden`, `id_pasaporte`, `id_distribuidor`, `id_franquicia`, `token_publico`, `contrato_clave`, `contrato_version`, `html_contrato_renderizado`, `firma_afiliado_base64`, `nombre_firmante`, `hash_contrato`, `fecha_firma`, `ip_firma`, `user_agent_firma`, `pdf_path`, `estatus`, `created_at`, `updated_at`) VALUES
(4, 6, 8, 0, 0, '', 'contrato_pats_base', '1.0', '<style>\r\n  .pats-contract{font-family:Arial,Helvetica,sans-serif;color:#172033;font-size:12px;line-height:1.52;background:#fff;padding:4px}\r\n  .pats-contract h1,.pats-contract h2,.pats-contract h3,.pats-contract h4{text-align:center;margin:12px 0 8px;color:#0d1b3e}\r\n  .pats-contract h1{font-size:16px;text-transform:uppercase;letter-spacing:.05em}\r\n  .pats-contract h2{font-size:15px;text-transform:uppercase;letter-spacing:.04em}\r\n  .pats-contract h3{font-size:13px;text-transform:uppercase;letter-spacing:.08em}\r\n  .pats-contract h4{font-size:12px;text-align:left;text-transform:uppercase;margin-top:12px}\r\n  .pats-contract p{margin:6px 0;text-align:justify}\r\n  .pats-contract ul{margin:6px 0 8px 18px;padding:0}.pats-contract li{margin:4px 0;text-align:justify}\r\n  .pats-contract table{width:100%;border-collapse:collapse;margin:8px 0 12px}.pats-contract th,.pats-contract td{border:1px solid #cbd5e1;padding:6px;vertical-align:top}.pats-contract th{background:#eef4ff;color:#0d1b3e;text-align:left}\r\n  .pats-contract .center{text-align:center}.pats-contract .muted{color:#64748b}.pats-contract .small{font-size:10px}.pats-contract .badge{display:inline-block;padding:3px 8px;border-radius:999px;background:#eef4ff;color:#1d4ed8;font-weight:700;margin:2px 4px 2px 0}\r\n  .pats-contract .sign-grid{display:grid;grid-template-columns:1fr 1fr;gap:22px;margin-top:28px}.pats-contract .sign-box{text-align:center;min-height:95px}.pats-contract .line{border-top:1px solid #0f172a;margin:48px 8px 6px}.pats-contract .signature-img{max-width:220px;max-height:82px;display:block;margin:0 auto 4px}\r\n  .pats-contract .annex{page-break-before:auto;border-top:2px solid #0d1b3e;margin-top:18px;padding-top:12px}.pats-contract .page-break{page-break-before:always;border-top:1px dashed #cbd5e1;margin-top:18px;padding-top:12px}\r\n</style>\r\n<div class=\"pats-contract\">\r\n  <h1>Carátula del contrato de adquisición de tarjeta de descuento</h1>\r\n  <p>CARÁTULA DEL CONTRATO DE ADQUISICIÓN DE TARJETA DE DESCUENTO (EN LO SUCESIVO “LA CARÁTULA”), QUE CELEBRAN POR UNA PARTE LA SOCIEDAD SEÑALADA EN EL APARTADO 1.- DE LA CARÁTULA, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL PRESTADOR”, REPRESENTADA EN ESTE ACTO POR LA PERSONA FÍSICA QUE SE INDICA EN EL APARTADO 2.- DE LA CARÁTULA; Y POR LA OTRA PARTE, LA PERSONA FÍSICA SEÑALADA EN EL APARTADO 5.- DE LA CARÁTULA, POR SU PROPIO DERECHO, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL AFILIADO”; Y CUANDO LOS ANTES NOMBRADOS ACTÚEN DE MANERA CONJUNTA, SE LES DENOMINARÁ COMO “LAS PARTES”; QUIENES SE SUJETAN AL TENOR DE LA CARÁTULA, DECLARACIONES Y CLÁUSULAS SIGUIENTES:</p>\r\n    \r\n  <h2>C A R Á T U L A</h2>\r\n  <table>\r\n    <tr><th style=\"width:8%\">Apartado</th><th style=\"width:42%\">Definición</th><th>Respuesta</th></tr>\r\n    <tr><td>1.-</td><td>Nombre de “EL PRESTADOR”</td><td>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE</td></tr>\r\n    <tr><td>2.-</td><td>Nombre del Representante Legal de “EL PRESTADOR”</td><td>PEDRO AZCÁRRAGA RAMOS</td></tr>\r\n    <tr><td>3.-</td><td>Domicilio de “EL PRESTADOR”</td><td>CALLE PASEO SINFONÍA NÚMERO EXTERIOR 1, LOCAL 2-14, LOMAS DE ANGELÓPOLIS II, SAN ANDRÉS CHOLULA, ESTADO DE PUEBLA, CÓDIGO POSTAL 72830</td></tr>\r\n    <tr><td>4.-</td><td>Clave del Registro Federal de Contribuyentes de “EL PRESTADOR”</td><td>COH2202144H5</td></tr>\r\n    <tr><td>5.-</td><td>Nombre de “EL AFILIADO”</td><td>Jua Carlos Fuentes Moya</td></tr>\r\n    <tr><td>6.-</td><td>Domicilio de “EL AFILIADO”</td><td>Jornal 115, Col. jalpa, C.P. 45255, cholula, Jalisco, México</td></tr>\r\n    <tr><td>7.-</td><td>Clave del Registro Federal de Contribuyentes de “EL AFILIADO”</td><td>FUMJ81082222</td></tr>\r\n    <tr><td>8.-</td><td>Costo mensual de “LA TARJETA DE DESCUENTO”</td><td>$800.00 M.N.</td></tr>\r\n    <tr><td>9.-</td><td>Cuenta bancaria de “EL PRESTADOR” para pagos</td><td>Cuenta: 01600866709<br>CLABE: 042650016008667096<br>Institución Bancaria: Banca Mifel, S.A., Institución de Banca Múltiple, Grupo Financiero Mifel</td></tr>\r\n    <tr><td>10.-</td><td>Cuota de Reactivación de “LA TARJETA DE DESCUENTO”</td><td>$100.00 M.N. por cada mes que se haya interrumpido el pago.</td></tr>\r\n    <tr><td>11.-</td><td>Datos de la Tarjeta de Crédito de “EL AFILIADO”</td><td>Número de tarjeta: pendiente de confirmar por pasarela/token de pago.<br>Institución bancaria: pendiente de confirmar por pasarela. <br><span class=\"small\">No se almacena número completo de tarjeta en este formulario.</span></td></tr>\r\n    <tr><td>12.-</td><td>Anexos</td><td>ANEXO 1. Identificación oficial de “EL AFILIADO”<br>ANEXO 2. Comprobante de domicilio de “EL AFILIADO”<br>ANEXO 3. Constancia de Situación Fiscal de “EL AFILIADO”, si aplica<br>ANEXO 4. Cuotas de recuperación y/o precios base a cubrir a “EL PRESTADOR”<br>ANEXO 5. Aviso de privacidad<br>ANEXO 6. Declaración de dueño beneficiario</td></tr>\r\n    <tr><td>13.-</td><td>Fecha de Firma del Contrato</td><td>13 de mayo de 2026</td></tr>\r\n  </table>\r\n\r\n  <div class=\"sign-grid\">\r\n    <div class=\"sign-box\"><div class=\"line\"></div><strong>“EL PRESTADOR”</strong><br>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE<br>Representada por PEDRO AZCÁRRAGA RAMOS</div>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>“EL AFILIADO”</strong><br>Jua Carlos Fuentes Moya<br><span class=\"small\">La persona física señalada en el Apartado 5.- de la Carátula</span></div>\r\n  </div>\r\n\r\n  <div class=\"page-break\"></div>\r\n  <h1>Contrato de adquisición de tarjeta de descuento</h1>\r\n  <p>CONTRATO DE ADQUISICIÓN DE TARJETA DE DESCUENTO, QUE CELEBRAN POR UNA PARTE LA SOCIEDAD SEÑALADA EN EL APARTADO 1.- DE LA CARÁTULA, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL PRESTADOR”, REPRESENTADA EN ESTE ACTO POR LA PERSONA FÍSICA QUE SE INDICA EN EL APARTADO 2.- DE LA CARÁTULA; Y POR LA OTRA PARTE, LA PERSONA FÍSICA SEÑALADA EN EL APARTADO 5.- DE LA CARÁTULA, POR SU PROPIO DERECHO, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL AFILIADO”; Y CUANDO LOS ANTES NOMBRADOS ACTÚEN DE MANERA CONJUNTA, SE LES DENOMINARÁ COMO “LAS PARTES”; QUIENES SE SUJETAN AL TENOR DE LAS DECLARACIONES Y CLÁUSULAS SIGUIENTES:</p>\r\n\r\n  <h2>D E C L A R A C I O N E S</h2>\r\n  <h4>I.- Declara “EL PRESTADOR” por conducto de su representación:</h4>\r\n  <p>A. Que, su representada es una sociedad mercantil constituida conforme a las leyes de los Estados Unidos Mexicanos, según consta en la escritura pública número 39,861, del volumen 830 de fecha catorce de febrero de dos mil veintidós, otorgada ante la fe del Licenciado Ernesto Joaquín Briones Amador, Notario Público Titular de la Notaría Pública número 46 de las del Distrito Judicial de Puebla, Estado de Puebla, cuyo primer testimonio se encuentra inscrito ante las oficinas del Registro Público de Comercio del Distrito Judicial de Puebla, Estado de Puebla, bajo el Folio Mercantil Electrónico: N-2022022991, por virtud del cual se llevó a cabo la Constitución de la persona moral denominada CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE.</p>\r\n  <p>B. Que, la persona física que la representa en este acto, señalada en el Apartado 2.- de la Carátula, cuenta con todas y cada una de las facultades necesarias para la celebración del presente contrato, las cuales se desprenden del instrumento descrito en el punto declarativo inmediato anterior, mismas que manifiesta bajo protesta de decir verdad que no le han sido suspendidas, revocadas o limitadas en forma alguna.</p>\r\n  <p>C. Que, su representada tiene como domicilio fiscal el señalado en el Apartado 3.- de la Carátula del presente contrato, mismo que designa como domicilio convencional para cualquier cuestión relacionada con la celebración del presente contrato.</p>\r\n  <p>D. Que, su representada se encuentra inscrita en el Registro Federal de Contribuyentes bajo la clave señalada en el Apartado 4.- de la Carátula.</p>\r\n  <p>E. Que, ha desarrollado y es su deseo comparecer a la celebración del presente instrumento con la finalidad de enajenar en favor de “EL AFILIADO”, una Tarjeta de Descuento que da acceso a “UN PROGRAMA DE BENEFICIOS QUE OTORGA DESCUENTOS A LOS COSTOS Y PERMITE RECIBIR SERVICIOS MÉDICOS PRIVADOS DE ALTA CALIDAD DE FORMA ACCESIBLE, CLARA Y SIN RESTRICCIONES DENTRO DE LA RED DE HOSPITALES 50 (FIFTY) DOCTORS CON SEDE EN EL ESTADO DE PUEBLA”, en lo sucesivo “LA TARJETA DE DESCUENTO”, en los términos y condiciones que se establecerán más adelante.</p>\r\n  <p>F. Que, su representada no es una Aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas sino una empresa dedicada, entre otros, a la operación y administración de establecimientos destinados a la atención y asistencia de enfermos, por lo que la enajenación de “LA TARJETA DE DESCUENTO” únicamente constituye un acto de comercio que brindará a “EL AFILIADO” acceso a un programa de beneficios como ha quedado descrito anteriormente.</p>\r\n\r\n  <h4>II.- Declara “EL AFILIADO”, por su propio derecho:</h4>\r\n      <p>A. Que, su nombre se señala en el Apartado 5.- de la Carátula, es una persona física de nacionalidad mexicana, en pleno ejercicio de sus derechos, legal y jurídicamente capaz para celebrar el presente Contrato, quien se identifica con credencial para votar vigente expedida por el Instituto Nacional Electoral, tipo INE, número GGFADGFADGDA, que en copia simple o archivo digital se agrega al cuerpo del presente contrato como ANEXO 1.</p>\r\n    <p>B. Que, tiene como domicilio particular el señalado en el Apartado 6.- de la Carátula, mismo que designa como domicilio convencional para cualquier cuestión relacionada con la celebración del presente contrato, tal y como lo acredita con el comprobante de domicilio que en copia simple o archivo digital se agrega al cuerpo del presente contrato como ANEXO 2.</p>\r\n  <p>C. Que, su CURP es 145214521452145214 y su RFC/identificación fiscal es FUMJ81082222; asimismo manifiesta que cuenta con capacidad económica para obligarse en términos del presente contrato y que los recursos con los que cubrirá sus obligaciones provendrán de fuentes lícitas. En caso de nacionalidad extranjera/no mexicana, se tendrán por no aplicables CURP, INE y constancia fiscal mexicana salvo manifestación expresa de residencia fiscal o RFC mexicano.</p>\r\n  <p>D. Que, es su deseo comparecer a la celebración del presente instrumento con la finalidad de adquirir “LA TARJETA DE DESCUENTO” de acuerdo con los términos y condiciones que se establecen a continuación.</p>\r\n  <p>E. Que, previo a la celebración del presente contrato fue informado y manifiesta expresamente que reconoce que “EL PRESTADOR” no es una Aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas y que las actividades comerciales objeto del presente contrato no consisten en la contratación de un seguro, de la índole que fuere, sino que únicamente implica la adquisición de una tarjeta de descuento que da acceso a un programa de beneficios que otorga descuentos a los costos y permite recibir servicios médicos privados de alta calidad de forma accesible, clara y sin restricciones dentro de la red de hospitales 50 (FIFTY) Doctors con sede en el Estado de Puebla.</p>\r\n  <p>F. Que, reconoce que “EL PRESTADOR” se dedica a la operación de centros hospitalarios y que la emisión de “LA TARJETA DE DESCUENTO” únicamente corresponde a la intención de este último de crear un programa de descuentos para el acceso a los servicios prestados por la Red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla.</p>\r\n\r\n  <h4>III.- Declaran conjuntamente “LAS PARTES”:</h4>\r\n  <p>1. Que, se reconocen recíprocamente la personalidad con la que comparecen a la celebración del presente acuerdo de voluntades.</p>\r\n  <p>2. Que, el presente contrato es el instrumento que las vincula en sus derechos y obligaciones.</p>\r\n  <p>3. Que, es su deseo celebrar el presente contrato y han negociado libremente los términos y condiciones del mismo con pleno conocimiento de sus alcances e implicaciones jurídicas, por lo que en su celebración no existe dolo, error, mala fe, lesión o cualquier otro vicio del consentimiento que pudiese afectarlo de inexistencia o nulidad.</p>\r\n\r\n  <h2>C L Á U S U L A S</h2>\r\n  <h4>PRIMERA.- OBJETO.</h4>\r\n  <p>El objeto del presente Contrato es que “EL AFILIADO” adquiera de “EL PRESTADOR”, a título oneroso y temporal, el derecho de uso ilimitado y sin restricción alguna de “LA TARJETA DE DESCUENTO” emitida por CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE, la cual consiste en que “EL AFILIADO” aproveche y acceda a “UN PROGRAMA DE BENEFICIOS QUE OTORGA DESCUENTOS A LOS COSTOS Y PERMITE RECIBIR SERVICIOS MÉDICOS PRIVADOS DE ALTA CALIDAD DE FORMA ACCESIBLE, CLARA Y SIN RESTRICCIONES DENTRO DE LA RED DE HOSPITALES 50 (FIFTY) DOCTORS CON SEDE EN EL ESTADO DE PUEBLA”.</p>\r\n  <p>Estableciendo que, la comercialización de “LA TARJETA DE DESCUENTO” por parte de “EL PRESTADOR” en ningún momento constituirá la venta, promoción o por cualquier medio la contratación de una póliza de seguro, bajo el entendido de que “EL PRESTADOR” no es una aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas (CNSF); sino que comercializa “LA TARJETA DE DESCUENTO” en favor de terceros con la finalidad de otorgar descuentos a los precios respecto de los servicios médicos que presta en el territorio nacional.</p>\r\n\r\n  <h4>SEGUNDA.- PRECIO DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“LAS PARTES” establecen de común acuerdo que “LA TARJETA DE DESCUENTO” tendrá como costo mensual la cantidad señalada en el Apartado 8.- de la Carátula del presente contrato; cantidad que ya incluye IVA, y la cual deberá ser cubierta por “EL AFILIADO” en favor de “EL PRESTADOR” dentro de los primeros 5 (cinco) días de cada mes, sin necesidad de gestiones o avisos de cobro, ya sea mediante:</p>\r\n  <p>(i) Transferencia electrónica de fondos a la cuenta bancaria señalada en el Apartado 9.- de la Carátula del presente contrato y de la cual es titular “EL PRESTADOR”.</p>\r\n  <p>(ii) Cheque que se recibirá salvo buen cobro en el Domicilio de “EL PRESTADOR” señalado en el Apartado 3.- de la Carátula del presente contrato, y que en caso de no ser pagado por falta de fondos suficientes o por otras causas imputables a “EL AFILIADO”, éste último está de acuerdo en que deberá cubrir a “EL PRESTADOR” el 20% (veinte por ciento) del monto del cheque por concepto de indemnización por daños y perjuicios en términos del artículo 193 de la Ley General de Títulos y Operaciones de Crédito, independientemente de cualquier otro cargo que se pudiera generar.</p>\r\n  <p>(iii) Cargos mensuales automáticos recurrentes a la tarjeta de crédito de “EL AFILIADO” según los datos señalados en el Apartado 11.- de la Carátula del presente contrato, quien manifiesta bajo protesta de decir verdad que autoriza a “EL PRESTADOR” a realizar los cargos mensuales correspondientes por el costo mensual de “LA TARJETA DE DESCUENTO” en dicha tarjeta o en la tarjeta que por renovación, reposición, robo o extravío le haya asignado el banco emisor. La autorización estará vigente mientras “EL AFILIADO” no haya notificado a “EL PRESTADOR” por escrito y con acuse de recibo su deseo de cancelar su afiliación o no renovarla, o en su defecto, realizar su baja respectiva en el sitio web o aplicación de “EL PRESTADOR”.</p>\r\n  <p>Esta autorización no exime a “EL AFILIADO” del pago mensual por el uso de “LA TARJETA DE DESCUENTO” y demás obligaciones contractuales, por lo que, en caso de que el cobro no sea autorizado por el banco emisor o por cualquier razón no pueda realizarse, “EL AFILIADO” deberá notificar tal situación a “EL PRESTADOR” a la dirección de correo electrónico silvia@pasaporteatusalud.com, a efecto de solicitar una forma de pago diversa, quedando obligado a cubrir de inmediato el pago correspondiente.</p>\r\n  <p>(iv) Cualquier otro medio de pago aceptado por “EL PRESTADOR”, mismo que se dará a conocer a través de sus medios oficiales de comunicación.</p>\r\n  <p>“EL PRESTADOR” podrá variar unilateralmente el costo mensual de “LA TARJETA DE DESCUENTO”, previo aviso a “EL AFILIADO” con 30 (treinta) días de anticipación a través de sus medios oficiales de comunicación.</p>\r\n  <p>Para el caso de que “EL AFILIADO” adquiera y cubra el precio de “LA TARJETA DE DESCUENTO” y posteriormente deje de pagar una mensualidad, deberá cubrir a “EL PRESTADOR”, por concepto de cuota de reactivación, la cantidad señalada en el Apartado 10.- de la Carátula por cada mes que haya interrumpido y/o no haya cubierto el precio de “LA TARJETA DE DESCUENTO”, hasta la fecha en que pretenda volver a adquirirla.</p>\r\n\r\n  <h4>TERCERA.- VIGENCIA DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“LA TARJETA DE DESCUENTO” objeto del presente contrato tendrá una vigencia de 30 días contados a partir de que “EL AFILIADO” cubra a “EL PRESTADOR” el precio establecido anteriormente, en el entendido de que la vigencia del presente contrato y de “LA TARJETA DE DESCUENTO” se prorrogarán automáticamente sin necesidad de celebrar documento adicional entre “LAS PARTES” siempre y cuando “EL AFILIADO” cubra, de mes en mes o en la frecuencia contratada, el precio vigente de “LA TARJETA DE DESCUENTO”.</p>\r\n  <p>“EL AFILIADO” tendrá derecho a revocar su consentimiento dentro de los 5 (cinco) días siguientes a la entrega de “LA TARJETA DE DESCUENTO” o la firma del presente contrato, lo que ocurra último, sin responsabilidad alguna, siempre y cuando no haya obtenido beneficio alguno por el uso de “LA TARJETA DE DESCUENTO”.</p>\r\n\r\n  <h4>CUARTA.- BENEFICIOS DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“EL AFILIADO”, de forma exclusiva, personal e intransferible, gozará de forma gratuita de los servicios que se mencionan a continuación:</p>\r\n  <ul><li>Consultas gratuitas ilimitadas de medicina general (no de especialidad) en la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla, únicamente con los doctores afiliados al programa de Pasaporte a tu Salud.</li><li>Consultas de urgencia gratuitas en la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla.</li></ul>\r\n  <p>No así respecto de los servicios que, de manera enunciativa más no limitativa, se describen a continuación:</p>\r\n  <ul><li>Hospitalización dentro de la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla, sujeto a la disponibilidad de cada uno de ellos.</li><li>Consultas de especialidad ilimitadas a costo preferencial, con médicos especialistas pertenecientes al programa PATS.</li><li>Acceso a farmacia PATS con costos reducidos de medicamentos genéricos.</li><li>Imagenología y laboratorios ilimitados con costos preferenciales.</li><li>Acceso a cirugías con cuota de recuperación preferente, con o sin honorarios médicos incluidos según corresponda.</li></ul>\r\n  <p>Dichos servicios generarán, por evento, el pago de una cuota con cargo a “EL AFILIADO”, misma que resultará de aplicar los porcentajes de descuento que se desprenden del ANEXO 4 del presente contrato a los precios publicados al público en general o los precios preferenciales indicados.</p>\r\n  <p>Mientras “LA TARJETA DE DESCUENTO” se encuentre vigente, “EL AFILIADO” gozará de todos los beneficios que la misma le otorga; sin embargo, para el caso de que requiera cirugía o procedimiento quirúrgico en quirófano, deberá haber sufragado por adelantado la adquisición de “LA TARJETA DE DESCUENTO” por un periodo de 12 (doce) meses y encontrarse dentro de dicho periodo de vigencia.</p>\r\n\r\n  <h4>QUINTA.- OBLIGACIONES DE “EL PRESTADOR”.</h4>\r\n  <p>“EL PRESTADOR” se obliga a: (i) otorgar a “EL AFILIADO” el acceso ilimitado a “LA TARJETA DE DESCUENTO” durante la vigencia del contrato; (ii) mantener actualizada y operativa la Red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla; (iii) proporcionar a “EL AFILIADO”, de forma digital, “LA TARJETA DE DESCUENTO” dentro de los 5 (cinco) días hábiles siguientes al primer pago; e (iv) informar por escrito cualquier modificación a la red de hospitales o al tabulador de cuotas con al menos 10 (diez) días de anticipación.</p>\r\n\r\n  <h4>SEXTA.- OBLIGACIONES DE “EL AFILIADO”.</h4>\r\n  <p>“EL AFILIADO” se obliga a: (i) pagar puntualmente el precio de “LA TARJETA DE DESCUENTO”; (ii) utilizarla de forma exclusiva, personal e intransferible; (iii) cubrir directamente a los hospitales y con anterioridad a recibir el servicio médico las cuotas de recuperación según tabulador vigente; (iv) presentar identificación oficial y “LA TARJETA DE DESCUENTO” o código QR cada vez que haga uso de beneficios; y (v) notificar por escrito cualquier cambio de domicilio o datos de contacto en un plazo no mayor a 5 (cinco) días.</p>\r\n\r\n  <h4>SÉPTIMA.- ACCESO A LOS BENEFICIOS Y PROCEDIMIENTO.</h4>\r\n  <p>Para hacer uso de “LA TARJETA DE DESCUENTO”, “EL AFILIADO” deberá agendar sus citas directamente con los doctores pertenecientes a la Red de Hospitales 50 (FIFTY) Doctors, que en ese momento se encuentren adscritos al programa de beneficios, a través de la aplicación oficial, página de internet oficial de PATS o medios oficiales que indique “EL PRESTADOR”.</p>\r\n  <p>“EL AFILIADO” se obliga a pagar directamente al médico especialista perteneciente al programa el costo de la consulta de especialidad de que se trate, en términos de los porcentajes de descuento del ANEXO 4. En caso de no estar facultado para asistir por fuerza mayor, tendrá un plazo de 30 (treinta) días contados a partir de haber generado la cita para solicitar una nueva consulta médica.</p>\r\n\r\n  <h4>OCTAVA.- EXCLUSIONES Y LIMITACIONES.</h4>\r\n  <p>Los beneficios no incluirán: (i) trasplantes de órganos; (ii) tratamientos experimentales; (iii) tratamientos de oncología a excepción de algunas cirugías; (iv) medicamentos extra hospitalarios que no estén recogidos en el catálogo de Farmacia PATS; (v) atención médica con especialistas no adscritos o no publicados en los medios oficiales; y (vi) cualquier servicio no listado expresamente.</p>\r\n\r\n  <h4>NOVENA.- CAUSAS DE TERMINACIÓN.</h4>\r\n  <p>El contrato podrá terminarse por falta de pago, mutuo consentimiento por escrito o incumplimiento de cualquiera de las cláusulas por cualquiera de “LAS PARTES”. En caso de terminación, “EL AFILIADO” no tendrá derecho a exigir la devolución de cantidad alguna.</p>\r\n\r\n  <h4>DÉCIMA.- CANCELACIÓN VOLUNTARIA.</h4>\r\n  <p>“EL AFILIADO” podrá cancelar “LA TARJETA DE DESCUENTO” mediante aviso por escrito con 30 (treinta) días de anticipación. Dicha cancelación surtirá efectos a partir del siguiente periodo mensual y no generará reembolso de pagos ya realizados.</p>\r\n\r\n  <h4>DÉCIMA PRIMERA.- PROTECCIÓN DE DATOS PERSONALES.</h4>\r\n  <p>“LAS PARTES” acuerdan que el tratamiento de datos personales se sujetará a la Ley Federal de Protección de Datos Personales en Posesión de los Particulares. “EL AFILIADO” autoriza expresamente el uso de sus datos para la gestión de “LA TARJETA DE DESCUENTO”. El aviso de privacidad se integra al presente contrato como ANEXO 5.</p>\r\n\r\n  <h4>DÉCIMA SEGUNDA.- RESPONSABILIDAD.</h4>\r\n  <p>“EL AFILIADO” reconoce y acepta que “LA TARJETA DE DESCUENTO” es emitida y administrada directamente por CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE, quien es responsable de la operación de la red de descuentos, afiliación de prestadores médicos y prestación de cualquier servicio relacionado con “LA TARJETA DE DESCUENTO”.</p>\r\n  <p>En consecuencia, “EL PRESTADOR” no tendrá responsabilidad directa ni indirecta por la prestación, calidad, eficacia, resultado, daño, perjuicio, lesión, complicación, secuela, evento adverso o consecuencia derivada de servicios médicos recibidos, incluyendo aquellos ocasionados por negligencia, impericia o mala praxis de profesionales de la salud o prestadores afiliados. Cualquier relación derivada de la prestación de servicios médicos se establece directamente entre “EL AFILIADO” y los prestadores de servicios de salud correspondientes. Esta limitación subsistirá a la terminación del contrato.</p>\r\n\r\n  <h4>DÉCIMA TERCERA.- PREVENCIÓN DE LAVADO DE DINERO Y ORIGEN DE LOS RECURSOS.</h4>\r\n  <p>“LAS PARTES” declaran bajo protesta de decir verdad que los recursos económicos, bienes y derechos que utilicen para cumplir obligaciones derivadas de este contrato tienen y tendrán origen lícito. “EL AFILIADO” manifiesta que el pago inicial y pagos futuros provienen de fuentes lícitas y no de actividades tipificadas como delitos.</p>\r\n  <p>“LAS PARTES” reconocen que la prestación de servicios de comercio puede ser considerada actividad vulnerable, por lo que se obligan a proporcionar información y documentación requerida para integrar expediente de identificación e informar si tienen conocimiento de la existencia de beneficiario controlador.</p>\r\n\r\n  <h4>DÉCIMA CUARTA.- CONFORMACIÓN DEL EXPEDIENTE DE IDENTIFICACIÓN.</h4>\r\n  <p>“EL PRESTADOR” queda obligado a conformar y mantener un expediente de identificación de “EL AFILIADO”. Para tales efectos, “EL AFILIADO” se obliga a entregar los documentos aplicables: identificación oficial vigente o pasaporte, acta de nacimiento cuando aplique, comprobante de domicilio, constancia de situación fiscal cuando aplique, CURP, y declaración de dueño beneficiario.</p>\r\n  <p>Cuando exista persona responsable, la documentación de identificación y representación deberá integrarse al expediente; la CIF/constancia fiscal corresponde al tutor cuando aplique. “EL PRESTADOR” conservará dicho expediente por un periodo mínimo de 5 (cinco) años contados a partir de que termine la vigencia del contrato o termine por cualquiera de sus causales, garantizando la confidencialidad de los datos personales.</p>\r\n\r\n  <h4>DÉCIMA QUINTA.- CAUSAL ESPECÍFICA DE RESCISIÓN.</h4>\r\n  <p>Será motivo de rescisión inmediata sin necesidad de declaración judicial y sin responsabilidad para la parte afectada cuando cualquiera de “LAS PARTES” se niegue a proporcionar información requerida para cumplimiento de la Ley Federal para la Prevención e Identificación de Operaciones con Recursos de Procedencia Ilícita, proporcione información falsa o aparezca en listas de personas bloqueadas emitidas por autoridad competente.</p>\r\n\r\n  <h4>DÉCIMA SEXTA.- LEGISLACIÓN APLICABLE Y JURISDICCIÓN.</h4>\r\n  <p>“LAS PARTES” establecen que la Procuraduría Federal del Consumidor es competente en vía administrativa para resolver cualquier controversia sobre interpretación o cumplimiento. Sin perjuicio de lo anterior, se someten expresamente a la jurisdicción de los tribunales competentes del fuero común del Distrito Judicial de Puebla, Estado de Puebla, renunciando de manera expresa e irrevocable a cualquier otro fuero o jurisdicción que pudiera corresponderles.</p>\r\n\r\n  <p>Enteradas “LAS PARTES” del contenido y alcance del presente contrato, y entendidas de los derechos y obligaciones que contraen, firman el presente instrumento, incluyendo sus anexos, manifestando que no medió error, dolo, mala fe, violencia o lesión, ni vicio del consentimiento alguno, en la Ciudad de Puebla, Estado de Puebla, reconociendo que la fecha de firma es 13 de mayo de 2026.</p>\r\n\r\n  <div class=\"sign-grid\">\r\n    <div class=\"sign-box\"><div class=\"line\"></div><strong>“EL PRESTADOR”</strong><br>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE<br>Representada por PEDRO AZCÁRRAGA RAMOS</div>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>“EL AFILIADO”</strong><br>Jua Carlos Fuentes Moya</div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 1<br>Identificación oficial de “EL AFILIADO”</h2><p>Se integra al expediente la identificación oficial cargada por el usuario en el formulario. Para mexicanos, corresponde a identificación oficial/INE cuando aplique. Para extranjeros/no mexicanos, corresponde a identificación oficial o pasaporte vigente; al menos el frente es obligatorio y el reverso será opcional cuando el documento no lo tenga.</p><p><strong>Tipo:</strong> INE. <strong>Emitida por / país emisor:</strong> México. <strong>Número:</strong> GGFADGFADGDA.</p></div>\r\n  <div class=\"annex\"><h2>ANEXO 2<br>COMPROBANTE DE DOMICILIO DE “EL AFILIADO”</h2><p>Se integra al expediente el comprobante de domicilio cargado por el usuario. Domicilio declarado: Jornal 115, Col. jalpa, C.P. 45255, cholula, Jalisco, México.</p></div>\r\n  <div class=\"annex\"><h2>ANEXO 3<br>CONSTANCIA DE SITUACIÓN FISCAL DE “EL AFILIADO”</h2><p>Constancia de Situación Fiscal de “EL AFILIADO”, si aplica. En caso de pacientes representados, la constancia fiscal o CIF corresponde a la persona responsable cuando sea aplicable, no al menor. Para afiliados extranjeros/no mexicanos, no será obligatoria salvo que declaren RFC mexicano o residencia fiscal aplicable.</p></div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 4<br>CUOTAS DE RECUPERACIÓN Y/O PRECIOS BASE A CUBRIR A “EL PRESTADOR”</h2>\r\n    <p>En el presente anexo se establecen los porcentajes de descuento a obtener como titular de “LA TARJETA DE DESCUENTO”, por lo que la cantidad a cubrir por “EL AFILIADO” directamente al hospital de la cadena 50 (FIFTY) Doctors o al doctor que preste el servicio se obtendrá de aplicar el porcentaje de descuento correspondiente al precio publicado por los medios oficiales o al precio vigente en el establecimiento.</p>\r\n    <table><tr><th>Servicios / procedimientos</th><th>Descuentos</th></tr><tr><td>Consulta de urgencias</td><td>100%</td></tr><tr><td>Consulta de medicina general</td><td>100%</td></tr><tr><td>Habitación hospitalaria</td><td>90%</td></tr><tr><td>Uso de áreas de urgencias médicas</td><td>80%</td></tr><tr><td>Utilización de cubículos de terapia intensiva (UCIA-UCIN-UCIP)</td><td>75%</td></tr><tr><td>CEYE</td><td>75%</td></tr><tr><td>Uso quirófano</td><td>75%</td></tr><tr><td>Servicio de cuneros</td><td>75%</td></tr><tr><td>Materiales & medicamentos del cuadro básico, genéricos intercambiables</td><td>70%</td></tr><tr><td>Hemodinamia</td><td>70%</td></tr><tr><td>Imagenología</td><td>70%</td></tr><tr><td>Endoprótesis</td><td>70%</td></tr><tr><td>Osteosíntesis</td><td>70%</td></tr><tr><td>Prótesis</td><td>70%</td></tr><tr><td>Órtesis</td><td>70%</td></tr><tr><td>Laboratorio clínico</td><td>60%</td></tr></table>\r\n    <p class=\"small\">Los descuentos aplican con los proveedores suscritos al convenio de Pasaporte a tu Salud.</p>\r\n    <table><tr><th>Servicios / procedimientos</th><th>Precios base</th></tr><tr><td>Consulta de especialidades médicas</td><td>$390.00</td></tr><tr><td>Colposcopía</td><td>$400.00</td></tr><tr><td>Retiro de puntos de sutura</td><td>$80.00</td></tr><tr><td>Aplicación de medicamento intramuscular</td><td>$60.00</td></tr><tr><td>Retiro de DIU</td><td>$500.00</td></tr><tr><td>Colocación de DIU</td><td>$700.00</td></tr><tr><td>Extracción de cuerpo extraño (oído y nariz)</td><td>$300.00</td></tr><tr><td>Lavado ótico</td><td>$250.00</td></tr><tr><td>Curación de sitio quirúrgico</td><td>$250.00</td></tr><tr><td>Retiro de yeso</td><td>$250.00</td></tr><tr><td>Visita día de hospitalización</td><td>$650.00</td></tr><tr><td>Visita de urgencias</td><td>$750.00</td></tr><tr><td>Día de terapia intensiva</td><td>$850.00</td></tr></table>\r\n    <p class=\"small\">Todos los precios incluyen IVA. La factura de servicios hospitalarios será emitida con el desglose correspondiente y el ahorro otorgado por ser titular de “LA TARJETA DE DESCUENTO”.</p>\r\n    <p>Exclusiones y limitaciones: se aplicarán descuentos y precios especiales para el acompañante de “EL AFILIADO” en la misma habitación únicamente para la primera noche de hospitalización. Los precios y porcentajes de descuento darán derecho a la utilización de materiales y medicamentos del cuadro básico, genéricos intercambiables; cualquier otro tipo de medicación será cubierto directamente por “EL AFILIADO”. Los costos de procedimientos quirúrgicos incluyen honorarios médicos cuando así se indique. “EL AFILIADO” podrá atenderse con el médico tratante que elija, debiendo cubrir honorarios directamente a dicho médico, conservando el derecho a beneficios dentro de la red aplicable.</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Firma de aceptación de “EL AFILIADO”</strong><br>Jua Carlos Fuentes Moya</div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 5<br>AVISO DE PRIVACIDAD</h2>\r\n    <p>En cumplimiento de las disposiciones establecidas en la Ley Federal de Protección de Datos Personales en Posesión de Particulares, su Reglamento y los lineamientos aplicables, “CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE” (en lo sucesivo “EL PRESTADOR”), con domicilio en CALLE PASEO SINFONÍA NÚMERO EXTERIOR 1, LOCAL 2-14, LOMAS DE ANGELÓPOLIS II, SAN ANDRÉS CHOLULA, ESTADO DE PUEBLA, CÓDIGO POSTAL 72830, da a conocer el Aviso de Privacidad al tenor del cual manejará por medio de su representación y/o empleados los datos personales y/o documentación proporcionada por el afiliado o usuario de “LA TARJETA DE DESCUENTO”.</p>\r\n    <p>Se tendrá por aceptado expresamente el presente Aviso de Privacidad una vez proporcionados los datos personales y firmada digitalmente la aceptación del contrato, motivo por el cual “EL PRESTADOR” estará facultado para manejar la información conforme a la legislación aplicable.</p>\r\n    <h4>Modificación del aviso de privacidad</h4><p>Este aviso podrá ser modificado o adecuado a las necesidades de “EL PRESTADOR”. Las modificaciones o actualizaciones serán incorporadas al presente aviso y estarán disponibles en la página de internet, domicilio de “EL PRESTADOR” o serán enviadas al último correo electrónico proporcionado.</p>\r\n    <h4>Finalidad de la información</h4><p>La información será utilizada para: elaborar y mantener actualizada la base de usuarios; identificar afiliados; proporcionar la tarjeta digital; otorgar acceso al programa de beneficios; informar modificaciones a la red o tabulador; realizar análisis estadísticos internos y brindar un óptimo servicio médico.</p>\r\n    <h4>Tipo de datos necesarios</h4><p>Se solicitarán datos de identificación, contacto, legales, contractuales y fiscales cuando aplique, incluyendo nombre completo, lugar y fecha de nacimiento, firma, identificación oficial, nacionalidad, CURP y RFC cuando sean aplicables, domicilio, teléfono y correo electrónico.</p>\r\n    <h4>Transferencias de la información</h4><p>El usuario autoriza proporcionar información sin consentimiento adicional en los casos previstos por ley, resolución de autoridad competente, tratados aplicables, salvaguarda de interés público, procuración o administración de justicia, reconocimiento o defensa de derechos en procesos judiciales, y a socios comerciales, técnicos o estratégicos que asuman obligaciones de confidencialidad y seguridad equivalentes.</p>\r\n    <h4>Limitación del uso o divulgación de datos y derechos ARCO</h4><p>El usuario podrá limitar el uso o divulgación de sus datos personales y ejercer derechos de acceso, rectificación, cancelación u oposición mediante solicitud escrita dirigida a “EL PRESTADOR” en su domicilio o al correo silvia@pasaporteatusalud.com, acompañando documento que acredite su identidad.</p>\r\n    <h4>Revocación de consentimiento</h4><p>El usuario podrá revocar su consentimiento siguiendo el mismo procedimiento, considerando que para ciertos fines la revocación puede implicar la cancelación de “LA TARJETA DE DESCUENTO” y la imposibilidad de acceder al programa.</p>\r\n    <p><strong>Nombre:</strong> Jua Carlos Fuentes Moya<br><strong>Fecha:</strong> 13 de mayo de 2026</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Firma</strong></div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 6<br>DECLARACIÓN DE DUEÑO BENEFICIARIO</h2>\r\n    <p>DE CONFORMIDAD CON LO DISPUESTO EN LOS ARTÍCULOS 18 FRACCIÓN I Y III DE LA LEY FEDERAL PARA PREVENCIÓN E IDENTIFICACIÓN DE OPERACIONES CON RECURSOS DE PROCEDENCIA ILÍCITA, EL ARTÍCULO 15 DE SU REGLAMENTO Y EL ARTÍCULO 13 DE LAS REGLAS DE CARÁCTER GENERAL, MANIFIESTO BAJO PROTESTA DE DECIR VERDAD:</p>\r\n    <h4>Datos de identificación del cliente</h4>\r\n    <table><tr><th>Campo</th><th>Respuesta</th></tr><tr><td>Apellido paterno, materno y nombre(s)</td><td>Jua Carlos Fuentes Moya</td></tr><tr><td>Fecha de nacimiento</td><td>1981-08-22</td></tr><tr><td>País de nacimiento</td><td>México</td></tr><tr><td>Nacionalidad</td><td>mexicana</td></tr><tr><td>Actividad, ocupación o profesión</td><td>Comerciante</td></tr><tr><td>Estado civil</td><td>CASADO(A)</td></tr><tr><td>Domicilio particular</td><td>Jornal 115, Col. jalpa, C.P. 45255, cholula, Jalisco, México</td></tr><tr><td>Teléfonos</td><td>4444444444</td></tr><tr><td>Correo electrónico</td><td>roel.fuentes@gmail.com</td></tr><tr><td>CURP</td><td>145214521452145214</td></tr><tr><td>RFC</td><td>FUMJ81082222</td></tr><tr><td>Tipo de identificación</td><td>INE</td></tr><tr><td>Emitida por / país emisor</td><td>México</td></tr><tr><td>Número de identificación</td><td>GGFADGFADGDA</td></tr></table>\r\n    <h4>Datos de identificación de la operación</h4>\r\n    <table><tr><th>Campo</th><th>Respuesta</th></tr><tr><td>Tipo de operación</td><td>Adquisición de tarjeta de descuento PATS</td></tr><tr><td>Monto de operación</td><td>$800.00 M.N.</td></tr><tr><td>Fecha de operación</td><td>13 de mayo de 2026</td></tr><tr><td>Forma de pago</td><td>Pasarela / medio autorizado por “EL PRESTADOR”</td></tr><tr><td>Moneda</td><td>MXN</td></tr></table>\r\n    <h4>Información de la existencia del dueño beneficiario o beneficiario controlador</h4>\r\n    <p>Declaro que soy el beneficiario directo de la operación y no existe ningún otro dueño beneficiario o beneficiario controlador: <strong>SI</strong>.</p>\r\n    <h4>Aviso de privacidad</h4><p>Los datos personales serán protegidos y tratados conforme al Aviso de Privacidad contenido en el cuerpo del presente contrato y la legislación aplicable.</p>\r\n    <p>H. Puebla de Zaragoza al 13 del mes de mayo del año 2026.</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Nombre y firma</strong><br>Jua Carlos Fuentes Moya</div>\r\n  </div>\r\n\r\n  \r\n  </div>\r\n', 'data:image/png;base64,', 'Jua Carlos Fuentes Moya', 'd254dbc58775c2992ff573c8cdf0a0d2b10d973a0751c3fb22946a2a37a28775', '2026-05-13 00:07:19', '189.190.196.8', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:150.0) Gecko/20100101 Firefox/150.0', '', 'firmado', '2026-05-13 00:07:19', '2026-05-13 00:07:19');
INSERT INTO `pats_contratos_firmados` (`id_contrato_firmado`, `id_orden`, `id_pasaporte`, `id_distribuidor`, `id_franquicia`, `token_publico`, `contrato_clave`, `contrato_version`, `html_contrato_renderizado`, `firma_afiliado_base64`, `nombre_firmante`, `hash_contrato`, `fecha_firma`, `ip_firma`, `user_agent_firma`, `pdf_path`, `estatus`, `created_at`, `updated_at`) VALUES
(5, 7, 9, 0, 0, '', 'contrato_pats_base', '1.0', '<style>\r\n  .pats-contract{font-family:Arial,Helvetica,sans-serif;color:#172033;font-size:12px;line-height:1.52;background:#fff;padding:4px}\r\n  .pats-contract h1,.pats-contract h2,.pats-contract h3,.pats-contract h4{text-align:center;margin:12px 0 8px;color:#0d1b3e}\r\n  .pats-contract h1{font-size:16px;text-transform:uppercase;letter-spacing:.05em}\r\n  .pats-contract h2{font-size:15px;text-transform:uppercase;letter-spacing:.04em}\r\n  .pats-contract h3{font-size:13px;text-transform:uppercase;letter-spacing:.08em}\r\n  .pats-contract h4{font-size:12px;text-align:left;text-transform:uppercase;margin-top:12px}\r\n  .pats-contract p{margin:6px 0;text-align:justify}\r\n  .pats-contract ul{margin:6px 0 8px 18px;padding:0}.pats-contract li{margin:4px 0;text-align:justify}\r\n  .pats-contract table{width:100%;border-collapse:collapse;margin:8px 0 12px}.pats-contract th,.pats-contract td{border:1px solid #cbd5e1;padding:6px;vertical-align:top}.pats-contract th{background:#eef4ff;color:#0d1b3e;text-align:left}\r\n  .pats-contract .center{text-align:center}.pats-contract .muted{color:#64748b}.pats-contract .small{font-size:10px}.pats-contract .badge{display:inline-block;padding:3px 8px;border-radius:999px;background:#eef4ff;color:#1d4ed8;font-weight:700;margin:2px 4px 2px 0}\r\n  .pats-contract .sign-grid{display:grid;grid-template-columns:1fr 1fr;gap:22px;margin-top:28px}.pats-contract .sign-box{text-align:center;min-height:95px}.pats-contract .line{border-top:1px solid #0f172a;margin:48px 8px 6px}.pats-contract .signature-img{max-width:220px;max-height:82px;display:block;margin:0 auto 4px}\r\n  .pats-contract .annex{page-break-before:auto;border-top:2px solid #0d1b3e;margin-top:18px;padding-top:12px}.pats-contract .page-break{page-break-before:always;border-top:1px dashed #cbd5e1;margin-top:18px;padding-top:12px}\r\n</style>\r\n<div class=\"pats-contract\">\r\n  <h1>Carátula del contrato de adquisición de tarjeta de descuento</h1>\r\n  <p>CARÁTULA DEL CONTRATO DE ADQUISICIÓN DE TARJETA DE DESCUENTO (EN LO SUCESIVO “LA CARÁTULA”), QUE CELEBRAN POR UNA PARTE LA SOCIEDAD SEÑALADA EN EL APARTADO 1.- DE LA CARÁTULA, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL PRESTADOR”, REPRESENTADA EN ESTE ACTO POR LA PERSONA FÍSICA QUE SE INDICA EN EL APARTADO 2.- DE LA CARÁTULA; Y POR LA OTRA PARTE, LA PERSONA FÍSICA SEÑALADA EN EL APARTADO 5.- DE LA CARÁTULA, POR SU PROPIO DERECHO, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL AFILIADO”; Y CUANDO LOS ANTES NOMBRADOS ACTÚEN DE MANERA CONJUNTA, SE LES DENOMINARÁ COMO “LAS PARTES”; QUIENES SE SUJETAN AL TENOR DE LA CARÁTULA, DECLARACIONES Y CLÁUSULAS SIGUIENTES:</p>\r\n    \r\n  <h2>C A R Á T U L A</h2>\r\n  <table>\r\n    <tr><th style=\"width:8%\">Apartado</th><th style=\"width:42%\">Definición</th><th>Respuesta</th></tr>\r\n    <tr><td>1.-</td><td>Nombre de “EL PRESTADOR”</td><td>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE</td></tr>\r\n    <tr><td>2.-</td><td>Nombre del Representante Legal de “EL PRESTADOR”</td><td>PEDRO AZCÁRRAGA RAMOS</td></tr>\r\n    <tr><td>3.-</td><td>Domicilio de “EL PRESTADOR”</td><td>CALLE PASEO SINFONÍA NÚMERO EXTERIOR 1, LOCAL 2-14, LOMAS DE ANGELÓPOLIS II, SAN ANDRÉS CHOLULA, ESTADO DE PUEBLA, CÓDIGO POSTAL 72830</td></tr>\r\n    <tr><td>4.-</td><td>Clave del Registro Federal de Contribuyentes de “EL PRESTADOR”</td><td>COH2202144H5</td></tr>\r\n    <tr><td>5.-</td><td>Nombre de “EL AFILIADO”</td><td>Jua Carlos García García</td></tr>\r\n    <tr><td>6.-</td><td>Domicilio de “EL AFILIADO”</td><td>Jornal 115, Col. zapopan, C.P. 45255, zapopan, Jalisco, México</td></tr>\r\n    <tr><td>7.-</td><td>Clave del Registro Federal de Contribuyentes de “EL AFILIADO”</td><td>Pendiente / no proporcionado</td></tr>\r\n    <tr><td>8.-</td><td>Costo mensual de “LA TARJETA DE DESCUENTO”</td><td>$800.00 M.N.</td></tr>\r\n    <tr><td>9.-</td><td>Cuenta bancaria de “EL PRESTADOR” para pagos</td><td>Cuenta: 01600866709<br>CLABE: 042650016008667096<br>Institución Bancaria: Banca Mifel, S.A., Institución de Banca Múltiple, Grupo Financiero Mifel</td></tr>\r\n    <tr><td>10.-</td><td>Cuota de Reactivación de “LA TARJETA DE DESCUENTO”</td><td>$100.00 M.N. por cada mes que se haya interrumpido el pago.</td></tr>\r\n    <tr><td>11.-</td><td>Datos de la Tarjeta de Crédito de “EL AFILIADO”</td><td>Número de tarjeta: pendiente de confirmar por pasarela/token de pago.<br>Institución bancaria: pendiente de confirmar por pasarela. <br><span class=\"small\">No se almacena número completo de tarjeta en este formulario.</span></td></tr>\r\n    <tr><td>12.-</td><td>Anexos</td><td>ANEXO 1. Identificación oficial de “EL AFILIADO”<br>ANEXO 2. Comprobante de domicilio de “EL AFILIADO”<br>ANEXO 3. Constancia de Situación Fiscal de “EL AFILIADO”, si aplica<br>ANEXO 4. Cuotas de recuperación y/o precios base a cubrir a “EL PRESTADOR”<br>ANEXO 5. Aviso de privacidad<br>ANEXO 6. Declaración de dueño beneficiario</td></tr>\r\n    <tr><td>13.-</td><td>Fecha de Firma del Contrato</td><td>13 de mayo de 2026</td></tr>\r\n  </table>\r\n\r\n  <div class=\"sign-grid\">\r\n    <div class=\"sign-box\"><div class=\"line\"></div><strong>“EL PRESTADOR”</strong><br>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE<br>Representada por PEDRO AZCÁRRAGA RAMOS</div>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>“EL AFILIADO”</strong><br>Jua Carlos García García<br><span class=\"small\">La persona física señalada en el Apartado 5.- de la Carátula</span></div>\r\n  </div>\r\n\r\n  <div class=\"page-break\"></div>\r\n  <h1>Contrato de adquisición de tarjeta de descuento</h1>\r\n  <p>CONTRATO DE ADQUISICIÓN DE TARJETA DE DESCUENTO, QUE CELEBRAN POR UNA PARTE LA SOCIEDAD SEÑALADA EN EL APARTADO 1.- DE LA CARÁTULA, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL PRESTADOR”, REPRESENTADA EN ESTE ACTO POR LA PERSONA FÍSICA QUE SE INDICA EN EL APARTADO 2.- DE LA CARÁTULA; Y POR LA OTRA PARTE, LA PERSONA FÍSICA SEÑALADA EN EL APARTADO 5.- DE LA CARÁTULA, POR SU PROPIO DERECHO, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL AFILIADO”; Y CUANDO LOS ANTES NOMBRADOS ACTÚEN DE MANERA CONJUNTA, SE LES DENOMINARÁ COMO “LAS PARTES”; QUIENES SE SUJETAN AL TENOR DE LAS DECLARACIONES Y CLÁUSULAS SIGUIENTES:</p>\r\n\r\n  <h2>D E C L A R A C I O N E S</h2>\r\n  <h4>I.- Declara “EL PRESTADOR” por conducto de su representación:</h4>\r\n  <p>A. Que, su representada es una sociedad mercantil constituida conforme a las leyes de los Estados Unidos Mexicanos, según consta en la escritura pública número 39,861, del volumen 830 de fecha catorce de febrero de dos mil veintidós, otorgada ante la fe del Licenciado Ernesto Joaquín Briones Amador, Notario Público Titular de la Notaría Pública número 46 de las del Distrito Judicial de Puebla, Estado de Puebla, cuyo primer testimonio se encuentra inscrito ante las oficinas del Registro Público de Comercio del Distrito Judicial de Puebla, Estado de Puebla, bajo el Folio Mercantil Electrónico: N-2022022991, por virtud del cual se llevó a cabo la Constitución de la persona moral denominada CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE.</p>\r\n  <p>B. Que, la persona física que la representa en este acto, señalada en el Apartado 2.- de la Carátula, cuenta con todas y cada una de las facultades necesarias para la celebración del presente contrato, las cuales se desprenden del instrumento descrito en el punto declarativo inmediato anterior, mismas que manifiesta bajo protesta de decir verdad que no le han sido suspendidas, revocadas o limitadas en forma alguna.</p>\r\n  <p>C. Que, su representada tiene como domicilio fiscal el señalado en el Apartado 3.- de la Carátula del presente contrato, mismo que designa como domicilio convencional para cualquier cuestión relacionada con la celebración del presente contrato.</p>\r\n  <p>D. Que, su representada se encuentra inscrita en el Registro Federal de Contribuyentes bajo la clave señalada en el Apartado 4.- de la Carátula.</p>\r\n  <p>E. Que, ha desarrollado y es su deseo comparecer a la celebración del presente instrumento con la finalidad de enajenar en favor de “EL AFILIADO”, una Tarjeta de Descuento que da acceso a “UN PROGRAMA DE BENEFICIOS QUE OTORGA DESCUENTOS A LOS COSTOS Y PERMITE RECIBIR SERVICIOS MÉDICOS PRIVADOS DE ALTA CALIDAD DE FORMA ACCESIBLE, CLARA Y SIN RESTRICCIONES DENTRO DE LA RED DE HOSPITALES 50 (FIFTY) DOCTORS CON SEDE EN EL ESTADO DE PUEBLA”, en lo sucesivo “LA TARJETA DE DESCUENTO”, en los términos y condiciones que se establecerán más adelante.</p>\r\n  <p>F. Que, su representada no es una Aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas sino una empresa dedicada, entre otros, a la operación y administración de establecimientos destinados a la atención y asistencia de enfermos, por lo que la enajenación de “LA TARJETA DE DESCUENTO” únicamente constituye un acto de comercio que brindará a “EL AFILIADO” acceso a un programa de beneficios como ha quedado descrito anteriormente.</p>\r\n\r\n  <h4>II.- Declara “EL AFILIADO”, por su propio derecho:</h4>\r\n      <p>A. Que, su nombre se señala en el Apartado 5.- de la Carátula, es una persona física de nacionalidad mexicana, en pleno ejercicio de sus derechos, legal y jurídicamente capaz para celebrar el presente Contrato, quien se identifica con credencial para votar vigente expedida por el Instituto Nacional Electoral, tipo INE, número 1452114522, que en copia simple o archivo digital se agrega al cuerpo del presente contrato como ANEXO 1.</p>\r\n    <p>B. Que, tiene como domicilio particular el señalado en el Apartado 6.- de la Carátula, mismo que designa como domicilio convencional para cualquier cuestión relacionada con la celebración del presente contrato, tal y como lo acredita con el comprobante de domicilio que en copia simple o archivo digital se agrega al cuerpo del presente contrato como ANEXO 2.</p>\r\n  <p>C. Que, su CURP es 145214521452145214 y su RFC/identificación fiscal es Pendiente / no proporcionado; asimismo manifiesta que cuenta con capacidad económica para obligarse en términos del presente contrato y que los recursos con los que cubrirá sus obligaciones provendrán de fuentes lícitas. En caso de nacionalidad extranjera/no mexicana, se tendrán por no aplicables CURP, INE y constancia fiscal mexicana salvo manifestación expresa de residencia fiscal o RFC mexicano.</p>\r\n  <p>D. Que, es su deseo comparecer a la celebración del presente instrumento con la finalidad de adquirir “LA TARJETA DE DESCUENTO” de acuerdo con los términos y condiciones que se establecen a continuación.</p>\r\n  <p>E. Que, previo a la celebración del presente contrato fue informado y manifiesta expresamente que reconoce que “EL PRESTADOR” no es una Aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas y que las actividades comerciales objeto del presente contrato no consisten en la contratación de un seguro, de la índole que fuere, sino que únicamente implica la adquisición de una tarjeta de descuento que da acceso a un programa de beneficios que otorga descuentos a los costos y permite recibir servicios médicos privados de alta calidad de forma accesible, clara y sin restricciones dentro de la red de hospitales 50 (FIFTY) Doctors con sede en el Estado de Puebla.</p>\r\n  <p>F. Que, reconoce que “EL PRESTADOR” se dedica a la operación de centros hospitalarios y que la emisión de “LA TARJETA DE DESCUENTO” únicamente corresponde a la intención de este último de crear un programa de descuentos para el acceso a los servicios prestados por la Red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla.</p>\r\n\r\n  <h4>III.- Declaran conjuntamente “LAS PARTES”:</h4>\r\n  <p>1. Que, se reconocen recíprocamente la personalidad con la que comparecen a la celebración del presente acuerdo de voluntades.</p>\r\n  <p>2. Que, el presente contrato es el instrumento que las vincula en sus derechos y obligaciones.</p>\r\n  <p>3. Que, es su deseo celebrar el presente contrato y han negociado libremente los términos y condiciones del mismo con pleno conocimiento de sus alcances e implicaciones jurídicas, por lo que en su celebración no existe dolo, error, mala fe, lesión o cualquier otro vicio del consentimiento que pudiese afectarlo de inexistencia o nulidad.</p>\r\n\r\n  <h2>C L Á U S U L A S</h2>\r\n  <h4>PRIMERA.- OBJETO.</h4>\r\n  <p>El objeto del presente Contrato es que “EL AFILIADO” adquiera de “EL PRESTADOR”, a título oneroso y temporal, el derecho de uso ilimitado y sin restricción alguna de “LA TARJETA DE DESCUENTO” emitida por CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE, la cual consiste en que “EL AFILIADO” aproveche y acceda a “UN PROGRAMA DE BENEFICIOS QUE OTORGA DESCUENTOS A LOS COSTOS Y PERMITE RECIBIR SERVICIOS MÉDICOS PRIVADOS DE ALTA CALIDAD DE FORMA ACCESIBLE, CLARA Y SIN RESTRICCIONES DENTRO DE LA RED DE HOSPITALES 50 (FIFTY) DOCTORS CON SEDE EN EL ESTADO DE PUEBLA”.</p>\r\n  <p>Estableciendo que, la comercialización de “LA TARJETA DE DESCUENTO” por parte de “EL PRESTADOR” en ningún momento constituirá la venta, promoción o por cualquier medio la contratación de una póliza de seguro, bajo el entendido de que “EL PRESTADOR” no es una aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas (CNSF); sino que comercializa “LA TARJETA DE DESCUENTO” en favor de terceros con la finalidad de otorgar descuentos a los precios respecto de los servicios médicos que presta en el territorio nacional.</p>\r\n\r\n  <h4>SEGUNDA.- PRECIO DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“LAS PARTES” establecen de común acuerdo que “LA TARJETA DE DESCUENTO” tendrá como costo mensual la cantidad señalada en el Apartado 8.- de la Carátula del presente contrato; cantidad que ya incluye IVA, y la cual deberá ser cubierta por “EL AFILIADO” en favor de “EL PRESTADOR” dentro de los primeros 5 (cinco) días de cada mes, sin necesidad de gestiones o avisos de cobro, ya sea mediante:</p>\r\n  <p>(i) Transferencia electrónica de fondos a la cuenta bancaria señalada en el Apartado 9.- de la Carátula del presente contrato y de la cual es titular “EL PRESTADOR”.</p>\r\n  <p>(ii) Cheque que se recibirá salvo buen cobro en el Domicilio de “EL PRESTADOR” señalado en el Apartado 3.- de la Carátula del presente contrato, y que en caso de no ser pagado por falta de fondos suficientes o por otras causas imputables a “EL AFILIADO”, éste último está de acuerdo en que deberá cubrir a “EL PRESTADOR” el 20% (veinte por ciento) del monto del cheque por concepto de indemnización por daños y perjuicios en términos del artículo 193 de la Ley General de Títulos y Operaciones de Crédito, independientemente de cualquier otro cargo que se pudiera generar.</p>\r\n  <p>(iii) Cargos mensuales automáticos recurrentes a la tarjeta de crédito de “EL AFILIADO” según los datos señalados en el Apartado 11.- de la Carátula del presente contrato, quien manifiesta bajo protesta de decir verdad que autoriza a “EL PRESTADOR” a realizar los cargos mensuales correspondientes por el costo mensual de “LA TARJETA DE DESCUENTO” en dicha tarjeta o en la tarjeta que por renovación, reposición, robo o extravío le haya asignado el banco emisor. La autorización estará vigente mientras “EL AFILIADO” no haya notificado a “EL PRESTADOR” por escrito y con acuse de recibo su deseo de cancelar su afiliación o no renovarla, o en su defecto, realizar su baja respectiva en el sitio web o aplicación de “EL PRESTADOR”.</p>\r\n  <p>Esta autorización no exime a “EL AFILIADO” del pago mensual por el uso de “LA TARJETA DE DESCUENTO” y demás obligaciones contractuales, por lo que, en caso de que el cobro no sea autorizado por el banco emisor o por cualquier razón no pueda realizarse, “EL AFILIADO” deberá notificar tal situación a “EL PRESTADOR” a la dirección de correo electrónico silvia@pasaporteatusalud.com, a efecto de solicitar una forma de pago diversa, quedando obligado a cubrir de inmediato el pago correspondiente.</p>\r\n  <p>(iv) Cualquier otro medio de pago aceptado por “EL PRESTADOR”, mismo que se dará a conocer a través de sus medios oficiales de comunicación.</p>\r\n  <p>“EL PRESTADOR” podrá variar unilateralmente el costo mensual de “LA TARJETA DE DESCUENTO”, previo aviso a “EL AFILIADO” con 30 (treinta) días de anticipación a través de sus medios oficiales de comunicación.</p>\r\n  <p>Para el caso de que “EL AFILIADO” adquiera y cubra el precio de “LA TARJETA DE DESCUENTO” y posteriormente deje de pagar una mensualidad, deberá cubrir a “EL PRESTADOR”, por concepto de cuota de reactivación, la cantidad señalada en el Apartado 10.- de la Carátula por cada mes que haya interrumpido y/o no haya cubierto el precio de “LA TARJETA DE DESCUENTO”, hasta la fecha en que pretenda volver a adquirirla.</p>\r\n\r\n  <h4>TERCERA.- VIGENCIA DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“LA TARJETA DE DESCUENTO” objeto del presente contrato tendrá una vigencia de 30 días contados a partir de que “EL AFILIADO” cubra a “EL PRESTADOR” el precio establecido anteriormente, en el entendido de que la vigencia del presente contrato y de “LA TARJETA DE DESCUENTO” se prorrogarán automáticamente sin necesidad de celebrar documento adicional entre “LAS PARTES” siempre y cuando “EL AFILIADO” cubra, de mes en mes o en la frecuencia contratada, el precio vigente de “LA TARJETA DE DESCUENTO”.</p>\r\n  <p>“EL AFILIADO” tendrá derecho a revocar su consentimiento dentro de los 5 (cinco) días siguientes a la entrega de “LA TARJETA DE DESCUENTO” o la firma del presente contrato, lo que ocurra último, sin responsabilidad alguna, siempre y cuando no haya obtenido beneficio alguno por el uso de “LA TARJETA DE DESCUENTO”.</p>\r\n\r\n  <h4>CUARTA.- BENEFICIOS DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“EL AFILIADO”, de forma exclusiva, personal e intransferible, gozará de forma gratuita de los servicios que se mencionan a continuación:</p>\r\n  <ul><li>Consultas gratuitas ilimitadas de medicina general (no de especialidad) en la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla, únicamente con los doctores afiliados al programa de Pasaporte a tu Salud.</li><li>Consultas de urgencia gratuitas en la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla.</li></ul>\r\n  <p>No así respecto de los servicios que, de manera enunciativa más no limitativa, se describen a continuación:</p>\r\n  <ul><li>Hospitalización dentro de la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla, sujeto a la disponibilidad de cada uno de ellos.</li><li>Consultas de especialidad ilimitadas a costo preferencial, con médicos especialistas pertenecientes al programa PATS.</li><li>Acceso a farmacia PATS con costos reducidos de medicamentos genéricos.</li><li>Imagenología y laboratorios ilimitados con costos preferenciales.</li><li>Acceso a cirugías con cuota de recuperación preferente, con o sin honorarios médicos incluidos según corresponda.</li></ul>\r\n  <p>Dichos servicios generarán, por evento, el pago de una cuota con cargo a “EL AFILIADO”, misma que resultará de aplicar los porcentajes de descuento que se desprenden del ANEXO 4 del presente contrato a los precios publicados al público en general o los precios preferenciales indicados.</p>\r\n  <p>Mientras “LA TARJETA DE DESCUENTO” se encuentre vigente, “EL AFILIADO” gozará de todos los beneficios que la misma le otorga; sin embargo, para el caso de que requiera cirugía o procedimiento quirúrgico en quirófano, deberá haber sufragado por adelantado la adquisición de “LA TARJETA DE DESCUENTO” por un periodo de 12 (doce) meses y encontrarse dentro de dicho periodo de vigencia.</p>\r\n\r\n  <h4>QUINTA.- OBLIGACIONES DE “EL PRESTADOR”.</h4>\r\n  <p>“EL PRESTADOR” se obliga a: (i) otorgar a “EL AFILIADO” el acceso ilimitado a “LA TARJETA DE DESCUENTO” durante la vigencia del contrato; (ii) mantener actualizada y operativa la Red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla; (iii) proporcionar a “EL AFILIADO”, de forma digital, “LA TARJETA DE DESCUENTO” dentro de los 5 (cinco) días hábiles siguientes al primer pago; e (iv) informar por escrito cualquier modificación a la red de hospitales o al tabulador de cuotas con al menos 10 (diez) días de anticipación.</p>\r\n\r\n  <h4>SEXTA.- OBLIGACIONES DE “EL AFILIADO”.</h4>\r\n  <p>“EL AFILIADO” se obliga a: (i) pagar puntualmente el precio de “LA TARJETA DE DESCUENTO”; (ii) utilizarla de forma exclusiva, personal e intransferible; (iii) cubrir directamente a los hospitales y con anterioridad a recibir el servicio médico las cuotas de recuperación según tabulador vigente; (iv) presentar identificación oficial y “LA TARJETA DE DESCUENTO” o código QR cada vez que haga uso de beneficios; y (v) notificar por escrito cualquier cambio de domicilio o datos de contacto en un plazo no mayor a 5 (cinco) días.</p>\r\n\r\n  <h4>SÉPTIMA.- ACCESO A LOS BENEFICIOS Y PROCEDIMIENTO.</h4>\r\n  <p>Para hacer uso de “LA TARJETA DE DESCUENTO”, “EL AFILIADO” deberá agendar sus citas directamente con los doctores pertenecientes a la Red de Hospitales 50 (FIFTY) Doctors, que en ese momento se encuentren adscritos al programa de beneficios, a través de la aplicación oficial, página de internet oficial de PATS o medios oficiales que indique “EL PRESTADOR”.</p>\r\n  <p>“EL AFILIADO” se obliga a pagar directamente al médico especialista perteneciente al programa el costo de la consulta de especialidad de que se trate, en términos de los porcentajes de descuento del ANEXO 4. En caso de no estar facultado para asistir por fuerza mayor, tendrá un plazo de 30 (treinta) días contados a partir de haber generado la cita para solicitar una nueva consulta médica.</p>\r\n\r\n  <h4>OCTAVA.- EXCLUSIONES Y LIMITACIONES.</h4>\r\n  <p>Los beneficios no incluirán: (i) trasplantes de órganos; (ii) tratamientos experimentales; (iii) tratamientos de oncología a excepción de algunas cirugías; (iv) medicamentos extra hospitalarios que no estén recogidos en el catálogo de Farmacia PATS; (v) atención médica con especialistas no adscritos o no publicados en los medios oficiales; y (vi) cualquier servicio no listado expresamente.</p>\r\n\r\n  <h4>NOVENA.- CAUSAS DE TERMINACIÓN.</h4>\r\n  <p>El contrato podrá terminarse por falta de pago, mutuo consentimiento por escrito o incumplimiento de cualquiera de las cláusulas por cualquiera de “LAS PARTES”. En caso de terminación, “EL AFILIADO” no tendrá derecho a exigir la devolución de cantidad alguna.</p>\r\n\r\n  <h4>DÉCIMA.- CANCELACIÓN VOLUNTARIA.</h4>\r\n  <p>“EL AFILIADO” podrá cancelar “LA TARJETA DE DESCUENTO” mediante aviso por escrito con 30 (treinta) días de anticipación. Dicha cancelación surtirá efectos a partir del siguiente periodo mensual y no generará reembolso de pagos ya realizados.</p>\r\n\r\n  <h4>DÉCIMA PRIMERA.- PROTECCIÓN DE DATOS PERSONALES.</h4>\r\n  <p>“LAS PARTES” acuerdan que el tratamiento de datos personales se sujetará a la Ley Federal de Protección de Datos Personales en Posesión de los Particulares. “EL AFILIADO” autoriza expresamente el uso de sus datos para la gestión de “LA TARJETA DE DESCUENTO”. El aviso de privacidad se integra al presente contrato como ANEXO 5.</p>\r\n\r\n  <h4>DÉCIMA SEGUNDA.- RESPONSABILIDAD.</h4>\r\n  <p>“EL AFILIADO” reconoce y acepta que “LA TARJETA DE DESCUENTO” es emitida y administrada directamente por CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE, quien es responsable de la operación de la red de descuentos, afiliación de prestadores médicos y prestación de cualquier servicio relacionado con “LA TARJETA DE DESCUENTO”.</p>\r\n  <p>En consecuencia, “EL PRESTADOR” no tendrá responsabilidad directa ni indirecta por la prestación, calidad, eficacia, resultado, daño, perjuicio, lesión, complicación, secuela, evento adverso o consecuencia derivada de servicios médicos recibidos, incluyendo aquellos ocasionados por negligencia, impericia o mala praxis de profesionales de la salud o prestadores afiliados. Cualquier relación derivada de la prestación de servicios médicos se establece directamente entre “EL AFILIADO” y los prestadores de servicios de salud correspondientes. Esta limitación subsistirá a la terminación del contrato.</p>\r\n\r\n  <h4>DÉCIMA TERCERA.- PREVENCIÓN DE LAVADO DE DINERO Y ORIGEN DE LOS RECURSOS.</h4>\r\n  <p>“LAS PARTES” declaran bajo protesta de decir verdad que los recursos económicos, bienes y derechos que utilicen para cumplir obligaciones derivadas de este contrato tienen y tendrán origen lícito. “EL AFILIADO” manifiesta que el pago inicial y pagos futuros provienen de fuentes lícitas y no de actividades tipificadas como delitos.</p>\r\n  <p>“LAS PARTES” reconocen que la prestación de servicios de comercio puede ser considerada actividad vulnerable, por lo que se obligan a proporcionar información y documentación requerida para integrar expediente de identificación e informar si tienen conocimiento de la existencia de beneficiario controlador.</p>\r\n\r\n  <h4>DÉCIMA CUARTA.- CONFORMACIÓN DEL EXPEDIENTE DE IDENTIFICACIÓN.</h4>\r\n  <p>“EL PRESTADOR” queda obligado a conformar y mantener un expediente de identificación de “EL AFILIADO”. Para tales efectos, “EL AFILIADO” se obliga a entregar los documentos aplicables: identificación oficial vigente o pasaporte, acta de nacimiento cuando aplique, comprobante de domicilio, constancia de situación fiscal cuando aplique, CURP, y declaración de dueño beneficiario.</p>\r\n  <p>Cuando exista persona responsable, la documentación de identificación y representación deberá integrarse al expediente; la CIF/constancia fiscal corresponde al tutor cuando aplique. “EL PRESTADOR” conservará dicho expediente por un periodo mínimo de 5 (cinco) años contados a partir de que termine la vigencia del contrato o termine por cualquiera de sus causales, garantizando la confidencialidad de los datos personales.</p>\r\n\r\n  <h4>DÉCIMA QUINTA.- CAUSAL ESPECÍFICA DE RESCISIÓN.</h4>\r\n  <p>Será motivo de rescisión inmediata sin necesidad de declaración judicial y sin responsabilidad para la parte afectada cuando cualquiera de “LAS PARTES” se niegue a proporcionar información requerida para cumplimiento de la Ley Federal para la Prevención e Identificación de Operaciones con Recursos de Procedencia Ilícita, proporcione información falsa o aparezca en listas de personas bloqueadas emitidas por autoridad competente.</p>\r\n\r\n  <h4>DÉCIMA SEXTA.- LEGISLACIÓN APLICABLE Y JURISDICCIÓN.</h4>\r\n  <p>“LAS PARTES” establecen que la Procuraduría Federal del Consumidor es competente en vía administrativa para resolver cualquier controversia sobre interpretación o cumplimiento. Sin perjuicio de lo anterior, se someten expresamente a la jurisdicción de los tribunales competentes del fuero común del Distrito Judicial de Puebla, Estado de Puebla, renunciando de manera expresa e irrevocable a cualquier otro fuero o jurisdicción que pudiera corresponderles.</p>\r\n\r\n  <p>Enteradas “LAS PARTES” del contenido y alcance del presente contrato, y entendidas de los derechos y obligaciones que contraen, firman el presente instrumento, incluyendo sus anexos, manifestando que no medió error, dolo, mala fe, violencia o lesión, ni vicio del consentimiento alguno, en la Ciudad de Puebla, Estado de Puebla, reconociendo que la fecha de firma es 13 de mayo de 2026.</p>\r\n\r\n  <div class=\"sign-grid\">\r\n    <div class=\"sign-box\"><div class=\"line\"></div><strong>“EL PRESTADOR”</strong><br>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE<br>Representada por PEDRO AZCÁRRAGA RAMOS</div>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>“EL AFILIADO”</strong><br>Jua Carlos García García</div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 1<br>Identificación oficial de “EL AFILIADO”</h2><p>Se integra al expediente la identificación oficial cargada por el usuario en el formulario. Para mexicanos, corresponde a identificación oficial/INE cuando aplique. Para extranjeros/no mexicanos, corresponde a identificación oficial o pasaporte vigente; al menos el frente es obligatorio y el reverso será opcional cuando el documento no lo tenga.</p><p><strong>Tipo:</strong> INE. <strong>Emitida por / país emisor:</strong> México. <strong>Número:</strong> 1452114522.</p></div>\r\n  <div class=\"annex\"><h2>ANEXO 2<br>COMPROBANTE DE DOMICILIO DE “EL AFILIADO”</h2><p>Se integra al expediente el comprobante de domicilio cargado por el usuario. Domicilio declarado: Jornal 115, Col. zapopan, C.P. 45255, zapopan, Jalisco, México.</p></div>\r\n  <div class=\"annex\"><h2>ANEXO 3<br>CONSTANCIA DE SITUACIÓN FISCAL DE “EL AFILIADO”</h2><p>Constancia de Situación Fiscal de “EL AFILIADO”, si aplica. En caso de pacientes representados, la constancia fiscal o CIF corresponde a la persona responsable cuando sea aplicable, no al menor. Para afiliados extranjeros/no mexicanos, no será obligatoria salvo que declaren RFC mexicano o residencia fiscal aplicable.</p></div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 4<br>CUOTAS DE RECUPERACIÓN Y/O PRECIOS BASE A CUBRIR A “EL PRESTADOR”</h2>\r\n    <p>En el presente anexo se establecen los porcentajes de descuento a obtener como titular de “LA TARJETA DE DESCUENTO”, por lo que la cantidad a cubrir por “EL AFILIADO” directamente al hospital de la cadena 50 (FIFTY) Doctors o al doctor que preste el servicio se obtendrá de aplicar el porcentaje de descuento correspondiente al precio publicado por los medios oficiales o al precio vigente en el establecimiento.</p>\r\n    <table><tr><th>Servicios / procedimientos</th><th>Descuentos</th></tr><tr><td>Consulta de urgencias</td><td>100%</td></tr><tr><td>Consulta de medicina general</td><td>100%</td></tr><tr><td>Habitación hospitalaria</td><td>90%</td></tr><tr><td>Uso de áreas de urgencias médicas</td><td>80%</td></tr><tr><td>Utilización de cubículos de terapia intensiva (UCIA-UCIN-UCIP)</td><td>75%</td></tr><tr><td>CEYE</td><td>75%</td></tr><tr><td>Uso quirófano</td><td>75%</td></tr><tr><td>Servicio de cuneros</td><td>75%</td></tr><tr><td>Materiales & medicamentos del cuadro básico, genéricos intercambiables</td><td>70%</td></tr><tr><td>Hemodinamia</td><td>70%</td></tr><tr><td>Imagenología</td><td>70%</td></tr><tr><td>Endoprótesis</td><td>70%</td></tr><tr><td>Osteosíntesis</td><td>70%</td></tr><tr><td>Prótesis</td><td>70%</td></tr><tr><td>Órtesis</td><td>70%</td></tr><tr><td>Laboratorio clínico</td><td>60%</td></tr></table>\r\n    <p class=\"small\">Los descuentos aplican con los proveedores suscritos al convenio de Pasaporte a tu Salud.</p>\r\n    <table><tr><th>Servicios / procedimientos</th><th>Precios base</th></tr><tr><td>Consulta de especialidades médicas</td><td>$390.00</td></tr><tr><td>Colposcopía</td><td>$400.00</td></tr><tr><td>Retiro de puntos de sutura</td><td>$80.00</td></tr><tr><td>Aplicación de medicamento intramuscular</td><td>$60.00</td></tr><tr><td>Retiro de DIU</td><td>$500.00</td></tr><tr><td>Colocación de DIU</td><td>$700.00</td></tr><tr><td>Extracción de cuerpo extraño (oído y nariz)</td><td>$300.00</td></tr><tr><td>Lavado ótico</td><td>$250.00</td></tr><tr><td>Curación de sitio quirúrgico</td><td>$250.00</td></tr><tr><td>Retiro de yeso</td><td>$250.00</td></tr><tr><td>Visita día de hospitalización</td><td>$650.00</td></tr><tr><td>Visita de urgencias</td><td>$750.00</td></tr><tr><td>Día de terapia intensiva</td><td>$850.00</td></tr></table>\r\n    <p class=\"small\">Todos los precios incluyen IVA. La factura de servicios hospitalarios será emitida con el desglose correspondiente y el ahorro otorgado por ser titular de “LA TARJETA DE DESCUENTO”.</p>\r\n    <p>Exclusiones y limitaciones: se aplicarán descuentos y precios especiales para el acompañante de “EL AFILIADO” en la misma habitación únicamente para la primera noche de hospitalización. Los precios y porcentajes de descuento darán derecho a la utilización de materiales y medicamentos del cuadro básico, genéricos intercambiables; cualquier otro tipo de medicación será cubierto directamente por “EL AFILIADO”. Los costos de procedimientos quirúrgicos incluyen honorarios médicos cuando así se indique. “EL AFILIADO” podrá atenderse con el médico tratante que elija, debiendo cubrir honorarios directamente a dicho médico, conservando el derecho a beneficios dentro de la red aplicable.</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Firma de aceptación de “EL AFILIADO”</strong><br>Jua Carlos García García</div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 5<br>AVISO DE PRIVACIDAD</h2>\r\n    <p>En cumplimiento de las disposiciones establecidas en la Ley Federal de Protección de Datos Personales en Posesión de Particulares, su Reglamento y los lineamientos aplicables, “CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE” (en lo sucesivo “EL PRESTADOR”), con domicilio en CALLE PASEO SINFONÍA NÚMERO EXTERIOR 1, LOCAL 2-14, LOMAS DE ANGELÓPOLIS II, SAN ANDRÉS CHOLULA, ESTADO DE PUEBLA, CÓDIGO POSTAL 72830, da a conocer el Aviso de Privacidad al tenor del cual manejará por medio de su representación y/o empleados los datos personales y/o documentación proporcionada por el afiliado o usuario de “LA TARJETA DE DESCUENTO”.</p>\r\n    <p>Se tendrá por aceptado expresamente el presente Aviso de Privacidad una vez proporcionados los datos personales y firmada digitalmente la aceptación del contrato, motivo por el cual “EL PRESTADOR” estará facultado para manejar la información conforme a la legislación aplicable.</p>\r\n    <h4>Modificación del aviso de privacidad</h4><p>Este aviso podrá ser modificado o adecuado a las necesidades de “EL PRESTADOR”. Las modificaciones o actualizaciones serán incorporadas al presente aviso y estarán disponibles en la página de internet, domicilio de “EL PRESTADOR” o serán enviadas al último correo electrónico proporcionado.</p>\r\n    <h4>Finalidad de la información</h4><p>La información será utilizada para: elaborar y mantener actualizada la base de usuarios; identificar afiliados; proporcionar la tarjeta digital; otorgar acceso al programa de beneficios; informar modificaciones a la red o tabulador; realizar análisis estadísticos internos y brindar un óptimo servicio médico.</p>\r\n    <h4>Tipo de datos necesarios</h4><p>Se solicitarán datos de identificación, contacto, legales, contractuales y fiscales cuando aplique, incluyendo nombre completo, lugar y fecha de nacimiento, firma, identificación oficial, nacionalidad, CURP y RFC cuando sean aplicables, domicilio, teléfono y correo electrónico.</p>\r\n    <h4>Transferencias de la información</h4><p>El usuario autoriza proporcionar información sin consentimiento adicional en los casos previstos por ley, resolución de autoridad competente, tratados aplicables, salvaguarda de interés público, procuración o administración de justicia, reconocimiento o defensa de derechos en procesos judiciales, y a socios comerciales, técnicos o estratégicos que asuman obligaciones de confidencialidad y seguridad equivalentes.</p>\r\n    <h4>Limitación del uso o divulgación de datos y derechos ARCO</h4><p>El usuario podrá limitar el uso o divulgación de sus datos personales y ejercer derechos de acceso, rectificación, cancelación u oposición mediante solicitud escrita dirigida a “EL PRESTADOR” en su domicilio o al correo silvia@pasaporteatusalud.com, acompañando documento que acredite su identidad.</p>\r\n    <h4>Revocación de consentimiento</h4><p>El usuario podrá revocar su consentimiento siguiendo el mismo procedimiento, considerando que para ciertos fines la revocación puede implicar la cancelación de “LA TARJETA DE DESCUENTO” y la imposibilidad de acceder al programa.</p>\r\n    <p><strong>Nombre:</strong> Jua Carlos García García<br><strong>Fecha:</strong> 13 de mayo de 2026</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Firma</strong></div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 6<br>DECLARACIÓN DE DUEÑO BENEFICIARIO</h2>\r\n    <p>DE CONFORMIDAD CON LO DISPUESTO EN LOS ARTÍCULOS 18 FRACCIÓN I Y III DE LA LEY FEDERAL PARA PREVENCIÓN E IDENTIFICACIÓN DE OPERACIONES CON RECURSOS DE PROCEDENCIA ILÍCITA, EL ARTÍCULO 15 DE SU REGLAMENTO Y EL ARTÍCULO 13 DE LAS REGLAS DE CARÁCTER GENERAL, MANIFIESTO BAJO PROTESTA DE DECIR VERDAD:</p>\r\n    <h4>Datos de identificación del cliente</h4>\r\n    <table><tr><th>Campo</th><th>Respuesta</th></tr><tr><td>Apellido paterno, materno y nombre(s)</td><td>Jua Carlos García García</td></tr><tr><td>Fecha de nacimiento</td><td>1981-08-22</td></tr><tr><td>País de nacimiento</td><td>México</td></tr><tr><td>Nacionalidad</td><td>mexicana</td></tr><tr><td>Actividad, ocupación o profesión</td><td>Comerciante</td></tr><tr><td>Estado civil</td><td>CASADO(A)</td></tr><tr><td>Domicilio particular</td><td>Jornal 115, Col. zapopan, C.P. 45255, zapopan, Jalisco, México</td></tr><tr><td>Teléfonos</td><td>4444444444</td></tr><tr><td>Correo electrónico</td><td>roel.fuentes@gmail.com</td></tr><tr><td>CURP</td><td>145214521452145214</td></tr><tr><td>RFC</td><td>Pendiente / no proporcionado</td></tr><tr><td>Tipo de identificación</td><td>INE</td></tr><tr><td>Emitida por / país emisor</td><td>México</td></tr><tr><td>Número de identificación</td><td>1452114522</td></tr></table>\r\n    <h4>Datos de identificación de la operación</h4>\r\n    <table><tr><th>Campo</th><th>Respuesta</th></tr><tr><td>Tipo de operación</td><td>Adquisición de tarjeta de descuento PATS</td></tr><tr><td>Monto de operación</td><td>$800.00 M.N.</td></tr><tr><td>Fecha de operación</td><td>13 de mayo de 2026</td></tr><tr><td>Forma de pago</td><td>Pasarela / medio autorizado por “EL PRESTADOR”</td></tr><tr><td>Moneda</td><td>MXN</td></tr></table>\r\n    <h4>Información de la existencia del dueño beneficiario o beneficiario controlador</h4>\r\n    <p>Declaro que soy el beneficiario directo de la operación y no existe ningún otro dueño beneficiario o beneficiario controlador: <strong>SI</strong>.</p>\r\n    <h4>Aviso de privacidad</h4><p>Los datos personales serán protegidos y tratados conforme al Aviso de Privacidad contenido en el cuerpo del presente contrato y la legislación aplicable.</p>\r\n    <p>H. Puebla de Zaragoza al 13 del mes de mayo del año 2026.</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Nombre y firma</strong><br>Jua Carlos García García</div>\r\n  </div>\r\n\r\n  \r\n  </div>\r\n', 'data:image/png;base64,', 'Jua Carlos García García', 'a5fb60548b667c6dd188f520cf9755f52e0a99ee62bd069e16f1010fd51b2302', '2026-05-13 00:19:04', '189.190.196.8', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:150.0) Gecko/20100101 Firefox/150.0', '', 'firmado', '2026-05-13 00:19:04', '2026-05-13 00:19:04');
INSERT INTO `pats_contratos_firmados` (`id_contrato_firmado`, `id_orden`, `id_pasaporte`, `id_distribuidor`, `id_franquicia`, `token_publico`, `contrato_clave`, `contrato_version`, `html_contrato_renderizado`, `firma_afiliado_base64`, `nombre_firmante`, `hash_contrato`, `fecha_firma`, `ip_firma`, `user_agent_firma`, `pdf_path`, `estatus`, `created_at`, `updated_at`) VALUES
(6, 8, 11, 0, 0, '', 'contrato_pats_base', '1.0', '<style>\r\n  .pats-contract{font-family:Arial,Helvetica,sans-serif;color:#172033;font-size:12px;line-height:1.52;background:#fff;padding:4px}\r\n  .pats-contract h1,.pats-contract h2,.pats-contract h3,.pats-contract h4{text-align:center;margin:12px 0 8px;color:#0d1b3e}\r\n  .pats-contract h1{font-size:16px;text-transform:uppercase;letter-spacing:.05em}\r\n  .pats-contract h2{font-size:15px;text-transform:uppercase;letter-spacing:.04em}\r\n  .pats-contract h3{font-size:13px;text-transform:uppercase;letter-spacing:.08em}\r\n  .pats-contract h4{font-size:12px;text-align:left;text-transform:uppercase;margin-top:12px}\r\n  .pats-contract p{margin:6px 0;text-align:justify}\r\n  .pats-contract ul{margin:6px 0 8px 18px;padding:0}.pats-contract li{margin:4px 0;text-align:justify}\r\n  .pats-contract table{width:100%;border-collapse:collapse;margin:8px 0 12px}.pats-contract th,.pats-contract td{border:1px solid #cbd5e1;padding:6px;vertical-align:top}.pats-contract th{background:#eef4ff;color:#0d1b3e;text-align:left}\r\n  .pats-contract .center{text-align:center}.pats-contract .muted{color:#64748b}.pats-contract .small{font-size:10px}.pats-contract .badge{display:inline-block;padding:3px 8px;border-radius:999px;background:#eef4ff;color:#1d4ed8;font-weight:700;margin:2px 4px 2px 0}\r\n  .pats-contract .sign-grid{display:grid;grid-template-columns:1fr 1fr;gap:22px;margin-top:28px}.pats-contract .sign-box{text-align:center;min-height:95px}.pats-contract .line{border-top:1px solid #0f172a;margin:48px 8px 6px}.pats-contract .signature-img{max-width:220px;max-height:82px;display:block;margin:0 auto 4px}\r\n  .pats-contract .annex{page-break-before:auto;border-top:2px solid #0d1b3e;margin-top:18px;padding-top:12px}.pats-contract .page-break{page-break-before:always;border-top:1px dashed #cbd5e1;margin-top:18px;padding-top:12px}\r\n</style>\r\n<div class=\"pats-contract\">\r\n  <h1>Carátula del contrato de adquisición de tarjeta de descuento</h1>\r\n  <p>CARÁTULA DEL CONTRATO DE ADQUISICIÓN DE TARJETA DE DESCUENTO (EN LO SUCESIVO “LA CARÁTULA”), QUE CELEBRAN POR UNA PARTE LA SOCIEDAD SEÑALADA EN EL APARTADO 1.- DE LA CARÁTULA, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL PRESTADOR”, REPRESENTADA EN ESTE ACTO POR LA PERSONA FÍSICA QUE SE INDICA EN EL APARTADO 2.- DE LA CARÁTULA; Y POR LA OTRA PARTE, LA PERSONA FÍSICA SEÑALADA EN EL APARTADO 5.- DE LA CARÁTULA, POR SU PROPIO DERECHO, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL AFILIADO”; Y CUANDO LOS ANTES NOMBRADOS ACTÚEN DE MANERA CONJUNTA, SE LES DENOMINARÁ COMO “LAS PARTES”; QUIENES SE SUJETAN AL TENOR DE LA CARÁTULA, DECLARACIONES Y CLÁUSULAS SIGUIENTES:</p>\r\n    \r\n  <h2>C A R Á T U L A</h2>\r\n  <table>\r\n    <tr><th style=\"width:8%\">Apartado</th><th style=\"width:42%\">Definición</th><th>Respuesta</th></tr>\r\n    <tr><td>1.-</td><td>Nombre de “EL PRESTADOR”</td><td>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE</td></tr>\r\n    <tr><td>2.-</td><td>Nombre del Representante Legal de “EL PRESTADOR”</td><td>PEDRO AZCÁRRAGA RAMOS</td></tr>\r\n    <tr><td>3.-</td><td>Domicilio de “EL PRESTADOR”</td><td>CALLE PASEO SINFONÍA NÚMERO EXTERIOR 1, LOCAL 2-14, LOMAS DE ANGELÓPOLIS II, SAN ANDRÉS CHOLULA, ESTADO DE PUEBLA, CÓDIGO POSTAL 72830</td></tr>\r\n    <tr><td>4.-</td><td>Clave del Registro Federal de Contribuyentes de “EL PRESTADOR”</td><td>COH2202144H5</td></tr>\r\n    <tr><td>5.-</td><td>Nombre de “EL AFILIADO”</td><td>Javier Jimenez Sanchez</td></tr>\r\n    <tr><td>6.-</td><td>Domicilio de “EL AFILIADO”</td><td>Jornal 115, Col. zapopan, C.P. 45255, cholula, Jalisco, México</td></tr>\r\n    <tr><td>7.-</td><td>Clave del Registro Federal de Contribuyentes de “EL AFILIADO”</td><td>GFDGSDFG</td></tr>\r\n    <tr><td>8.-</td><td>Costo mensual de “LA TARJETA DE DESCUENTO”</td><td>$800.00 M.N.</td></tr>\r\n    <tr><td>9.-</td><td>Cuenta bancaria de “EL PRESTADOR” para pagos</td><td>Cuenta: 01600866709<br>CLABE: 042650016008667096<br>Institución Bancaria: Banca Mifel, S.A., Institución de Banca Múltiple, Grupo Financiero Mifel</td></tr>\r\n    <tr><td>10.-</td><td>Cuota de Reactivación de “LA TARJETA DE DESCUENTO”</td><td>$100.00 M.N. por cada mes que se haya interrumpido el pago.</td></tr>\r\n    <tr><td>11.-</td><td>Datos de la Tarjeta de Crédito de “EL AFILIADO”</td><td>Número de tarjeta: pendiente de confirmar por pasarela/token de pago.<br>Institución bancaria: pendiente de confirmar por pasarela. <br><span class=\"small\">No se almacena número completo de tarjeta en este formulario.</span></td></tr>\r\n    <tr><td>12.-</td><td>Anexos</td><td>ANEXO 1. Identificación oficial de “EL AFILIADO”<br>ANEXO 2. Comprobante de domicilio de “EL AFILIADO”<br>ANEXO 3. Constancia de Situación Fiscal de “EL AFILIADO”, si aplica<br>ANEXO 4. Cuotas de recuperación y/o precios base a cubrir a “EL PRESTADOR”<br>ANEXO 5. Aviso de privacidad<br>ANEXO 6. Declaración de dueño beneficiario</td></tr>\r\n    <tr><td>13.-</td><td>Fecha de Firma del Contrato</td><td>13 de mayo de 2026</td></tr>\r\n  </table>\r\n\r\n  <div class=\"sign-grid\">\r\n    <div class=\"sign-box\"><div class=\"line\"></div><strong>“EL PRESTADOR”</strong><br>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE<br>Representada por PEDRO AZCÁRRAGA RAMOS</div>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>“EL AFILIADO”</strong><br>Javier Jimenez Sanchez<br><span class=\"small\">La persona física señalada en el Apartado 5.- de la Carátula</span></div>\r\n  </div>\r\n\r\n  <div class=\"page-break\"></div>\r\n  <h1>Contrato de adquisición de tarjeta de descuento</h1>\r\n  <p>CONTRATO DE ADQUISICIÓN DE TARJETA DE DESCUENTO, QUE CELEBRAN POR UNA PARTE LA SOCIEDAD SEÑALADA EN EL APARTADO 1.- DE LA CARÁTULA, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL PRESTADOR”, REPRESENTADA EN ESTE ACTO POR LA PERSONA FÍSICA QUE SE INDICA EN EL APARTADO 2.- DE LA CARÁTULA; Y POR LA OTRA PARTE, LA PERSONA FÍSICA SEÑALADA EN EL APARTADO 5.- DE LA CARÁTULA, POR SU PROPIO DERECHO, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL AFILIADO”; Y CUANDO LOS ANTES NOMBRADOS ACTÚEN DE MANERA CONJUNTA, SE LES DENOMINARÁ COMO “LAS PARTES”; QUIENES SE SUJETAN AL TENOR DE LAS DECLARACIONES Y CLÁUSULAS SIGUIENTES:</p>\r\n\r\n  <h2>D E C L A R A C I O N E S</h2>\r\n  <h4>I.- Declara “EL PRESTADOR” por conducto de su representación:</h4>\r\n  <p>A. Que, su representada es una sociedad mercantil constituida conforme a las leyes de los Estados Unidos Mexicanos, según consta en la escritura pública número 39,861, del volumen 830 de fecha catorce de febrero de dos mil veintidós, otorgada ante la fe del Licenciado Ernesto Joaquín Briones Amador, Notario Público Titular de la Notaría Pública número 46 de las del Distrito Judicial de Puebla, Estado de Puebla, cuyo primer testimonio se encuentra inscrito ante las oficinas del Registro Público de Comercio del Distrito Judicial de Puebla, Estado de Puebla, bajo el Folio Mercantil Electrónico: N-2022022991, por virtud del cual se llevó a cabo la Constitución de la persona moral denominada CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE.</p>\r\n  <p>B. Que, la persona física que la representa en este acto, señalada en el Apartado 2.- de la Carátula, cuenta con todas y cada una de las facultades necesarias para la celebración del presente contrato, las cuales se desprenden del instrumento descrito en el punto declarativo inmediato anterior, mismas que manifiesta bajo protesta de decir verdad que no le han sido suspendidas, revocadas o limitadas en forma alguna.</p>\r\n  <p>C. Que, su representada tiene como domicilio fiscal el señalado en el Apartado 3.- de la Carátula del presente contrato, mismo que designa como domicilio convencional para cualquier cuestión relacionada con la celebración del presente contrato.</p>\r\n  <p>D. Que, su representada se encuentra inscrita en el Registro Federal de Contribuyentes bajo la clave señalada en el Apartado 4.- de la Carátula.</p>\r\n  <p>E. Que, ha desarrollado y es su deseo comparecer a la celebración del presente instrumento con la finalidad de enajenar en favor de “EL AFILIADO”, una Tarjeta de Descuento que da acceso a “UN PROGRAMA DE BENEFICIOS QUE OTORGA DESCUENTOS A LOS COSTOS Y PERMITE RECIBIR SERVICIOS MÉDICOS PRIVADOS DE ALTA CALIDAD DE FORMA ACCESIBLE, CLARA Y SIN RESTRICCIONES DENTRO DE LA RED DE HOSPITALES 50 (FIFTY) DOCTORS CON SEDE EN EL ESTADO DE PUEBLA”, en lo sucesivo “LA TARJETA DE DESCUENTO”, en los términos y condiciones que se establecerán más adelante.</p>\r\n  <p>F. Que, su representada no es una Aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas sino una empresa dedicada, entre otros, a la operación y administración de establecimientos destinados a la atención y asistencia de enfermos, por lo que la enajenación de “LA TARJETA DE DESCUENTO” únicamente constituye un acto de comercio que brindará a “EL AFILIADO” acceso a un programa de beneficios como ha quedado descrito anteriormente.</p>\r\n\r\n  <h4>II.- Declara “EL AFILIADO”, por su propio derecho:</h4>\r\n      <p>A. Que, su nombre se señala en el Apartado 5.- de la Carátula, es una persona física de nacionalidad mexicana, en pleno ejercicio de sus derechos, legal y jurídicamente capaz para celebrar el presente Contrato, quien se identifica con credencial para votar vigente expedida por el Instituto Nacional Electoral, tipo INE, número GGFADGFADGDA, que en copia simple o archivo digital se agrega al cuerpo del presente contrato como ANEXO 1.</p>\r\n    <p>B. Que, tiene como domicilio particular el señalado en el Apartado 6.- de la Carátula, mismo que designa como domicilio convencional para cualquier cuestión relacionada con la celebración del presente contrato, tal y como lo acredita con el comprobante de domicilio que en copia simple o archivo digital se agrega al cuerpo del presente contrato como ANEXO 2.</p>\r\n  <p>C. Que, su CURP es 145214521452145214 y su RFC/identificación fiscal es GFDGSDFG; asimismo manifiesta que cuenta con capacidad económica para obligarse en términos del presente contrato y que los recursos con los que cubrirá sus obligaciones provendrán de fuentes lícitas. En caso de nacionalidad extranjera/no mexicana, se tendrán por no aplicables CURP, INE y constancia fiscal mexicana salvo manifestación expresa de residencia fiscal o RFC mexicano.</p>\r\n  <p>D. Que, es su deseo comparecer a la celebración del presente instrumento con la finalidad de adquirir “LA TARJETA DE DESCUENTO” de acuerdo con los términos y condiciones que se establecen a continuación.</p>\r\n  <p>E. Que, previo a la celebración del presente contrato fue informado y manifiesta expresamente que reconoce que “EL PRESTADOR” no es una Aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas y que las actividades comerciales objeto del presente contrato no consisten en la contratación de un seguro, de la índole que fuere, sino que únicamente implica la adquisición de una tarjeta de descuento que da acceso a un programa de beneficios que otorga descuentos a los costos y permite recibir servicios médicos privados de alta calidad de forma accesible, clara y sin restricciones dentro de la red de hospitales 50 (FIFTY) Doctors con sede en el Estado de Puebla.</p>\r\n  <p>F. Que, reconoce que “EL PRESTADOR” se dedica a la operación de centros hospitalarios y que la emisión de “LA TARJETA DE DESCUENTO” únicamente corresponde a la intención de este último de crear un programa de descuentos para el acceso a los servicios prestados por la Red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla.</p>\r\n\r\n  <h4>III.- Declaran conjuntamente “LAS PARTES”:</h4>\r\n  <p>1. Que, se reconocen recíprocamente la personalidad con la que comparecen a la celebración del presente acuerdo de voluntades.</p>\r\n  <p>2. Que, el presente contrato es el instrumento que las vincula en sus derechos y obligaciones.</p>\r\n  <p>3. Que, es su deseo celebrar el presente contrato y han negociado libremente los términos y condiciones del mismo con pleno conocimiento de sus alcances e implicaciones jurídicas, por lo que en su celebración no existe dolo, error, mala fe, lesión o cualquier otro vicio del consentimiento que pudiese afectarlo de inexistencia o nulidad.</p>\r\n\r\n  <h2>C L Á U S U L A S</h2>\r\n  <h4>PRIMERA.- OBJETO.</h4>\r\n  <p>El objeto del presente Contrato es que “EL AFILIADO” adquiera de “EL PRESTADOR”, a título oneroso y temporal, el derecho de uso ilimitado y sin restricción alguna de “LA TARJETA DE DESCUENTO” emitida por CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE, la cual consiste en que “EL AFILIADO” aproveche y acceda a “UN PROGRAMA DE BENEFICIOS QUE OTORGA DESCUENTOS A LOS COSTOS Y PERMITE RECIBIR SERVICIOS MÉDICOS PRIVADOS DE ALTA CALIDAD DE FORMA ACCESIBLE, CLARA Y SIN RESTRICCIONES DENTRO DE LA RED DE HOSPITALES 50 (FIFTY) DOCTORS CON SEDE EN EL ESTADO DE PUEBLA”.</p>\r\n  <p>Estableciendo que, la comercialización de “LA TARJETA DE DESCUENTO” por parte de “EL PRESTADOR” en ningún momento constituirá la venta, promoción o por cualquier medio la contratación de una póliza de seguro, bajo el entendido de que “EL PRESTADOR” no es una aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas (CNSF); sino que comercializa “LA TARJETA DE DESCUENTO” en favor de terceros con la finalidad de otorgar descuentos a los precios respecto de los servicios médicos que presta en el territorio nacional.</p>\r\n\r\n  <h4>SEGUNDA.- PRECIO DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“LAS PARTES” establecen de común acuerdo que “LA TARJETA DE DESCUENTO” tendrá como costo mensual la cantidad señalada en el Apartado 8.- de la Carátula del presente contrato; cantidad que ya incluye IVA, y la cual deberá ser cubierta por “EL AFILIADO” en favor de “EL PRESTADOR” dentro de los primeros 5 (cinco) días de cada mes, sin necesidad de gestiones o avisos de cobro, ya sea mediante:</p>\r\n  <p>(i) Transferencia electrónica de fondos a la cuenta bancaria señalada en el Apartado 9.- de la Carátula del presente contrato y de la cual es titular “EL PRESTADOR”.</p>\r\n  <p>(ii) Cheque que se recibirá salvo buen cobro en el Domicilio de “EL PRESTADOR” señalado en el Apartado 3.- de la Carátula del presente contrato, y que en caso de no ser pagado por falta de fondos suficientes o por otras causas imputables a “EL AFILIADO”, éste último está de acuerdo en que deberá cubrir a “EL PRESTADOR” el 20% (veinte por ciento) del monto del cheque por concepto de indemnización por daños y perjuicios en términos del artículo 193 de la Ley General de Títulos y Operaciones de Crédito, independientemente de cualquier otro cargo que se pudiera generar.</p>\r\n  <p>(iii) Cargos mensuales automáticos recurrentes a la tarjeta de crédito de “EL AFILIADO” según los datos señalados en el Apartado 11.- de la Carátula del presente contrato, quien manifiesta bajo protesta de decir verdad que autoriza a “EL PRESTADOR” a realizar los cargos mensuales correspondientes por el costo mensual de “LA TARJETA DE DESCUENTO” en dicha tarjeta o en la tarjeta que por renovación, reposición, robo o extravío le haya asignado el banco emisor. La autorización estará vigente mientras “EL AFILIADO” no haya notificado a “EL PRESTADOR” por escrito y con acuse de recibo su deseo de cancelar su afiliación o no renovarla, o en su defecto, realizar su baja respectiva en el sitio web o aplicación de “EL PRESTADOR”.</p>\r\n  <p>Esta autorización no exime a “EL AFILIADO” del pago mensual por el uso de “LA TARJETA DE DESCUENTO” y demás obligaciones contractuales, por lo que, en caso de que el cobro no sea autorizado por el banco emisor o por cualquier razón no pueda realizarse, “EL AFILIADO” deberá notificar tal situación a “EL PRESTADOR” a la dirección de correo electrónico silvia@pasaporteatusalud.com, a efecto de solicitar una forma de pago diversa, quedando obligado a cubrir de inmediato el pago correspondiente.</p>\r\n  <p>(iv) Cualquier otro medio de pago aceptado por “EL PRESTADOR”, mismo que se dará a conocer a través de sus medios oficiales de comunicación.</p>\r\n  <p>“EL PRESTADOR” podrá variar unilateralmente el costo mensual de “LA TARJETA DE DESCUENTO”, previo aviso a “EL AFILIADO” con 30 (treinta) días de anticipación a través de sus medios oficiales de comunicación.</p>\r\n  <p>Para el caso de que “EL AFILIADO” adquiera y cubra el precio de “LA TARJETA DE DESCUENTO” y posteriormente deje de pagar una mensualidad, deberá cubrir a “EL PRESTADOR”, por concepto de cuota de reactivación, la cantidad señalada en el Apartado 10.- de la Carátula por cada mes que haya interrumpido y/o no haya cubierto el precio de “LA TARJETA DE DESCUENTO”, hasta la fecha en que pretenda volver a adquirirla.</p>\r\n\r\n  <h4>TERCERA.- VIGENCIA DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“LA TARJETA DE DESCUENTO” objeto del presente contrato tendrá una vigencia de 30 días contados a partir de que “EL AFILIADO” cubra a “EL PRESTADOR” el precio establecido anteriormente, en el entendido de que la vigencia del presente contrato y de “LA TARJETA DE DESCUENTO” se prorrogarán automáticamente sin necesidad de celebrar documento adicional entre “LAS PARTES” siempre y cuando “EL AFILIADO” cubra, de mes en mes o en la frecuencia contratada, el precio vigente de “LA TARJETA DE DESCUENTO”.</p>\r\n  <p>“EL AFILIADO” tendrá derecho a revocar su consentimiento dentro de los 5 (cinco) días siguientes a la entrega de “LA TARJETA DE DESCUENTO” o la firma del presente contrato, lo que ocurra último, sin responsabilidad alguna, siempre y cuando no haya obtenido beneficio alguno por el uso de “LA TARJETA DE DESCUENTO”.</p>\r\n\r\n  <h4>CUARTA.- BENEFICIOS DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“EL AFILIADO”, de forma exclusiva, personal e intransferible, gozará de forma gratuita de los servicios que se mencionan a continuación:</p>\r\n  <ul><li>Consultas gratuitas ilimitadas de medicina general (no de especialidad) en la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla, únicamente con los doctores afiliados al programa de Pasaporte a tu Salud.</li><li>Consultas de urgencia gratuitas en la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla.</li></ul>\r\n  <p>No así respecto de los servicios que, de manera enunciativa más no limitativa, se describen a continuación:</p>\r\n  <ul><li>Hospitalización dentro de la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla, sujeto a la disponibilidad de cada uno de ellos.</li><li>Consultas de especialidad ilimitadas a costo preferencial, con médicos especialistas pertenecientes al programa PATS.</li><li>Acceso a farmacia PATS con costos reducidos de medicamentos genéricos.</li><li>Imagenología y laboratorios ilimitados con costos preferenciales.</li><li>Acceso a cirugías con cuota de recuperación preferente, con o sin honorarios médicos incluidos según corresponda.</li></ul>\r\n  <p>Dichos servicios generarán, por evento, el pago de una cuota con cargo a “EL AFILIADO”, misma que resultará de aplicar los porcentajes de descuento que se desprenden del ANEXO 4 del presente contrato a los precios publicados al público en general o los precios preferenciales indicados.</p>\r\n  <p>Mientras “LA TARJETA DE DESCUENTO” se encuentre vigente, “EL AFILIADO” gozará de todos los beneficios que la misma le otorga; sin embargo, para el caso de que requiera cirugía o procedimiento quirúrgico en quirófano, deberá haber sufragado por adelantado la adquisición de “LA TARJETA DE DESCUENTO” por un periodo de 12 (doce) meses y encontrarse dentro de dicho periodo de vigencia.</p>\r\n\r\n  <h4>QUINTA.- OBLIGACIONES DE “EL PRESTADOR”.</h4>\r\n  <p>“EL PRESTADOR” se obliga a: (i) otorgar a “EL AFILIADO” el acceso ilimitado a “LA TARJETA DE DESCUENTO” durante la vigencia del contrato; (ii) mantener actualizada y operativa la Red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla; (iii) proporcionar a “EL AFILIADO”, de forma digital, “LA TARJETA DE DESCUENTO” dentro de los 5 (cinco) días hábiles siguientes al primer pago; e (iv) informar por escrito cualquier modificación a la red de hospitales o al tabulador de cuotas con al menos 10 (diez) días de anticipación.</p>\r\n\r\n  <h4>SEXTA.- OBLIGACIONES DE “EL AFILIADO”.</h4>\r\n  <p>“EL AFILIADO” se obliga a: (i) pagar puntualmente el precio de “LA TARJETA DE DESCUENTO”; (ii) utilizarla de forma exclusiva, personal e intransferible; (iii) cubrir directamente a los hospitales y con anterioridad a recibir el servicio médico las cuotas de recuperación según tabulador vigente; (iv) presentar identificación oficial y “LA TARJETA DE DESCUENTO” o código QR cada vez que haga uso de beneficios; y (v) notificar por escrito cualquier cambio de domicilio o datos de contacto en un plazo no mayor a 5 (cinco) días.</p>\r\n\r\n  <h4>SÉPTIMA.- ACCESO A LOS BENEFICIOS Y PROCEDIMIENTO.</h4>\r\n  <p>Para hacer uso de “LA TARJETA DE DESCUENTO”, “EL AFILIADO” deberá agendar sus citas directamente con los doctores pertenecientes a la Red de Hospitales 50 (FIFTY) Doctors, que en ese momento se encuentren adscritos al programa de beneficios, a través de la aplicación oficial, página de internet oficial de PATS o medios oficiales que indique “EL PRESTADOR”.</p>\r\n  <p>“EL AFILIADO” se obliga a pagar directamente al médico especialista perteneciente al programa el costo de la consulta de especialidad de que se trate, en términos de los porcentajes de descuento del ANEXO 4. En caso de no estar facultado para asistir por fuerza mayor, tendrá un plazo de 30 (treinta) días contados a partir de haber generado la cita para solicitar una nueva consulta médica.</p>\r\n\r\n  <h4>OCTAVA.- EXCLUSIONES Y LIMITACIONES.</h4>\r\n  <p>Los beneficios no incluirán: (i) trasplantes de órganos; (ii) tratamientos experimentales; (iii) tratamientos de oncología a excepción de algunas cirugías; (iv) medicamentos extra hospitalarios que no estén recogidos en el catálogo de Farmacia PATS; (v) atención médica con especialistas no adscritos o no publicados en los medios oficiales; y (vi) cualquier servicio no listado expresamente.</p>\r\n\r\n  <h4>NOVENA.- CAUSAS DE TERMINACIÓN.</h4>\r\n  <p>El contrato podrá terminarse por falta de pago, mutuo consentimiento por escrito o incumplimiento de cualquiera de las cláusulas por cualquiera de “LAS PARTES”. En caso de terminación, “EL AFILIADO” no tendrá derecho a exigir la devolución de cantidad alguna.</p>\r\n\r\n  <h4>DÉCIMA.- CANCELACIÓN VOLUNTARIA.</h4>\r\n  <p>“EL AFILIADO” podrá cancelar “LA TARJETA DE DESCUENTO” mediante aviso por escrito con 30 (treinta) días de anticipación. Dicha cancelación surtirá efectos a partir del siguiente periodo mensual y no generará reembolso de pagos ya realizados.</p>\r\n\r\n  <h4>DÉCIMA PRIMERA.- PROTECCIÓN DE DATOS PERSONALES.</h4>\r\n  <p>“LAS PARTES” acuerdan que el tratamiento de datos personales se sujetará a la Ley Federal de Protección de Datos Personales en Posesión de los Particulares. “EL AFILIADO” autoriza expresamente el uso de sus datos para la gestión de “LA TARJETA DE DESCUENTO”. El aviso de privacidad se integra al presente contrato como ANEXO 5.</p>\r\n\r\n  <h4>DÉCIMA SEGUNDA.- RESPONSABILIDAD.</h4>\r\n  <p>“EL AFILIADO” reconoce y acepta que “LA TARJETA DE DESCUENTO” es emitida y administrada directamente por CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE, quien es responsable de la operación de la red de descuentos, afiliación de prestadores médicos y prestación de cualquier servicio relacionado con “LA TARJETA DE DESCUENTO”.</p>\r\n  <p>En consecuencia, “EL PRESTADOR” no tendrá responsabilidad directa ni indirecta por la prestación, calidad, eficacia, resultado, daño, perjuicio, lesión, complicación, secuela, evento adverso o consecuencia derivada de servicios médicos recibidos, incluyendo aquellos ocasionados por negligencia, impericia o mala praxis de profesionales de la salud o prestadores afiliados. Cualquier relación derivada de la prestación de servicios médicos se establece directamente entre “EL AFILIADO” y los prestadores de servicios de salud correspondientes. Esta limitación subsistirá a la terminación del contrato.</p>\r\n\r\n  <h4>DÉCIMA TERCERA.- PREVENCIÓN DE LAVADO DE DINERO Y ORIGEN DE LOS RECURSOS.</h4>\r\n  <p>“LAS PARTES” declaran bajo protesta de decir verdad que los recursos económicos, bienes y derechos que utilicen para cumplir obligaciones derivadas de este contrato tienen y tendrán origen lícito. “EL AFILIADO” manifiesta que el pago inicial y pagos futuros provienen de fuentes lícitas y no de actividades tipificadas como delitos.</p>\r\n  <p>“LAS PARTES” reconocen que la prestación de servicios de comercio puede ser considerada actividad vulnerable, por lo que se obligan a proporcionar información y documentación requerida para integrar expediente de identificación e informar si tienen conocimiento de la existencia de beneficiario controlador.</p>\r\n\r\n  <h4>DÉCIMA CUARTA.- CONFORMACIÓN DEL EXPEDIENTE DE IDENTIFICACIÓN.</h4>\r\n  <p>“EL PRESTADOR” queda obligado a conformar y mantener un expediente de identificación de “EL AFILIADO”. Para tales efectos, “EL AFILIADO” se obliga a entregar los documentos aplicables: identificación oficial vigente o pasaporte, acta de nacimiento cuando aplique, comprobante de domicilio, constancia de situación fiscal cuando aplique, CURP, y declaración de dueño beneficiario.</p>\r\n  <p>Cuando exista persona responsable, la documentación de identificación y representación deberá integrarse al expediente; la CIF/constancia fiscal corresponde al tutor cuando aplique. “EL PRESTADOR” conservará dicho expediente por un periodo mínimo de 5 (cinco) años contados a partir de que termine la vigencia del contrato o termine por cualquiera de sus causales, garantizando la confidencialidad de los datos personales.</p>\r\n\r\n  <h4>DÉCIMA QUINTA.- CAUSAL ESPECÍFICA DE RESCISIÓN.</h4>\r\n  <p>Será motivo de rescisión inmediata sin necesidad de declaración judicial y sin responsabilidad para la parte afectada cuando cualquiera de “LAS PARTES” se niegue a proporcionar información requerida para cumplimiento de la Ley Federal para la Prevención e Identificación de Operaciones con Recursos de Procedencia Ilícita, proporcione información falsa o aparezca en listas de personas bloqueadas emitidas por autoridad competente.</p>\r\n\r\n  <h4>DÉCIMA SEXTA.- LEGISLACIÓN APLICABLE Y JURISDICCIÓN.</h4>\r\n  <p>“LAS PARTES” establecen que la Procuraduría Federal del Consumidor es competente en vía administrativa para resolver cualquier controversia sobre interpretación o cumplimiento. Sin perjuicio de lo anterior, se someten expresamente a la jurisdicción de los tribunales competentes del fuero común del Distrito Judicial de Puebla, Estado de Puebla, renunciando de manera expresa e irrevocable a cualquier otro fuero o jurisdicción que pudiera corresponderles.</p>\r\n\r\n  <p>Enteradas “LAS PARTES” del contenido y alcance del presente contrato, y entendidas de los derechos y obligaciones que contraen, firman el presente instrumento, incluyendo sus anexos, manifestando que no medió error, dolo, mala fe, violencia o lesión, ni vicio del consentimiento alguno, en la Ciudad de Puebla, Estado de Puebla, reconociendo que la fecha de firma es 13 de mayo de 2026.</p>\r\n\r\n  <div class=\"sign-grid\">\r\n    <div class=\"sign-box\"><div class=\"line\"></div><strong>“EL PRESTADOR”</strong><br>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE<br>Representada por PEDRO AZCÁRRAGA RAMOS</div>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>“EL AFILIADO”</strong><br>Javier Jimenez Sanchez</div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 1<br>Identificación oficial de “EL AFILIADO”</h2><p>Se integra al expediente la identificación oficial cargada por el usuario en el formulario. Para mexicanos, corresponde a identificación oficial/INE cuando aplique. Para extranjeros/no mexicanos, corresponde a identificación oficial o pasaporte vigente; al menos el frente es obligatorio y el reverso será opcional cuando el documento no lo tenga.</p><p><strong>Tipo:</strong> INE. <strong>Emitida por / país emisor:</strong> México. <strong>Número:</strong> GGFADGFADGDA.</p></div>\r\n  <div class=\"annex\"><h2>ANEXO 2<br>COMPROBANTE DE DOMICILIO DE “EL AFILIADO”</h2><p>Se integra al expediente el comprobante de domicilio cargado por el usuario. Domicilio declarado: Jornal 115, Col. zapopan, C.P. 45255, cholula, Jalisco, México.</p></div>\r\n  <div class=\"annex\"><h2>ANEXO 3<br>CONSTANCIA DE SITUACIÓN FISCAL DE “EL AFILIADO”</h2><p>Constancia de Situación Fiscal de “EL AFILIADO”, si aplica. En caso de pacientes representados, la constancia fiscal o CIF corresponde a la persona responsable cuando sea aplicable, no al menor. Para afiliados extranjeros/no mexicanos, no será obligatoria salvo que declaren RFC mexicano o residencia fiscal aplicable.</p></div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 4<br>CUOTAS DE RECUPERACIÓN Y/O PRECIOS BASE A CUBRIR A “EL PRESTADOR”</h2>\r\n    <p>En el presente anexo se establecen los porcentajes de descuento a obtener como titular de “LA TARJETA DE DESCUENTO”, por lo que la cantidad a cubrir por “EL AFILIADO” directamente al hospital de la cadena 50 (FIFTY) Doctors o al doctor que preste el servicio se obtendrá de aplicar el porcentaje de descuento correspondiente al precio publicado por los medios oficiales o al precio vigente en el establecimiento.</p>\r\n    <table><tr><th>Servicios / procedimientos</th><th>Descuentos</th></tr><tr><td>Consulta de urgencias</td><td>100%</td></tr><tr><td>Consulta de medicina general</td><td>100%</td></tr><tr><td>Habitación hospitalaria</td><td>90%</td></tr><tr><td>Uso de áreas de urgencias médicas</td><td>80%</td></tr><tr><td>Utilización de cubículos de terapia intensiva (UCIA-UCIN-UCIP)</td><td>75%</td></tr><tr><td>CEYE</td><td>75%</td></tr><tr><td>Uso quirófano</td><td>75%</td></tr><tr><td>Servicio de cuneros</td><td>75%</td></tr><tr><td>Materiales & medicamentos del cuadro básico, genéricos intercambiables</td><td>70%</td></tr><tr><td>Hemodinamia</td><td>70%</td></tr><tr><td>Imagenología</td><td>70%</td></tr><tr><td>Endoprótesis</td><td>70%</td></tr><tr><td>Osteosíntesis</td><td>70%</td></tr><tr><td>Prótesis</td><td>70%</td></tr><tr><td>Órtesis</td><td>70%</td></tr><tr><td>Laboratorio clínico</td><td>60%</td></tr></table>\r\n    <p class=\"small\">Los descuentos aplican con los proveedores suscritos al convenio de Pasaporte a tu Salud.</p>\r\n    <table><tr><th>Servicios / procedimientos</th><th>Precios base</th></tr><tr><td>Consulta de especialidades médicas</td><td>$390.00</td></tr><tr><td>Colposcopía</td><td>$400.00</td></tr><tr><td>Retiro de puntos de sutura</td><td>$80.00</td></tr><tr><td>Aplicación de medicamento intramuscular</td><td>$60.00</td></tr><tr><td>Retiro de DIU</td><td>$500.00</td></tr><tr><td>Colocación de DIU</td><td>$700.00</td></tr><tr><td>Extracción de cuerpo extraño (oído y nariz)</td><td>$300.00</td></tr><tr><td>Lavado ótico</td><td>$250.00</td></tr><tr><td>Curación de sitio quirúrgico</td><td>$250.00</td></tr><tr><td>Retiro de yeso</td><td>$250.00</td></tr><tr><td>Visita día de hospitalización</td><td>$650.00</td></tr><tr><td>Visita de urgencias</td><td>$750.00</td></tr><tr><td>Día de terapia intensiva</td><td>$850.00</td></tr></table>\r\n    <p class=\"small\">Todos los precios incluyen IVA. La factura de servicios hospitalarios será emitida con el desglose correspondiente y el ahorro otorgado por ser titular de “LA TARJETA DE DESCUENTO”.</p>\r\n    <p>Exclusiones y limitaciones: se aplicarán descuentos y precios especiales para el acompañante de “EL AFILIADO” en la misma habitación únicamente para la primera noche de hospitalización. Los precios y porcentajes de descuento darán derecho a la utilización de materiales y medicamentos del cuadro básico, genéricos intercambiables; cualquier otro tipo de medicación será cubierto directamente por “EL AFILIADO”. Los costos de procedimientos quirúrgicos incluyen honorarios médicos cuando así se indique. “EL AFILIADO” podrá atenderse con el médico tratante que elija, debiendo cubrir honorarios directamente a dicho médico, conservando el derecho a beneficios dentro de la red aplicable.</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Firma de aceptación de “EL AFILIADO”</strong><br>Javier Jimenez Sanchez</div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 5<br>AVISO DE PRIVACIDAD</h2>\r\n    <p>En cumplimiento de las disposiciones establecidas en la Ley Federal de Protección de Datos Personales en Posesión de Particulares, su Reglamento y los lineamientos aplicables, “CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE” (en lo sucesivo “EL PRESTADOR”), con domicilio en CALLE PASEO SINFONÍA NÚMERO EXTERIOR 1, LOCAL 2-14, LOMAS DE ANGELÓPOLIS II, SAN ANDRÉS CHOLULA, ESTADO DE PUEBLA, CÓDIGO POSTAL 72830, da a conocer el Aviso de Privacidad al tenor del cual manejará por medio de su representación y/o empleados los datos personales y/o documentación proporcionada por el afiliado o usuario de “LA TARJETA DE DESCUENTO”.</p>\r\n    <p>Se tendrá por aceptado expresamente el presente Aviso de Privacidad una vez proporcionados los datos personales y firmada digitalmente la aceptación del contrato, motivo por el cual “EL PRESTADOR” estará facultado para manejar la información conforme a la legislación aplicable.</p>\r\n    <h4>Modificación del aviso de privacidad</h4><p>Este aviso podrá ser modificado o adecuado a las necesidades de “EL PRESTADOR”. Las modificaciones o actualizaciones serán incorporadas al presente aviso y estarán disponibles en la página de internet, domicilio de “EL PRESTADOR” o serán enviadas al último correo electrónico proporcionado.</p>\r\n    <h4>Finalidad de la información</h4><p>La información será utilizada para: elaborar y mantener actualizada la base de usuarios; identificar afiliados; proporcionar la tarjeta digital; otorgar acceso al programa de beneficios; informar modificaciones a la red o tabulador; realizar análisis estadísticos internos y brindar un óptimo servicio médico.</p>\r\n    <h4>Tipo de datos necesarios</h4><p>Se solicitarán datos de identificación, contacto, legales, contractuales y fiscales cuando aplique, incluyendo nombre completo, lugar y fecha de nacimiento, firma, identificación oficial, nacionalidad, CURP y RFC cuando sean aplicables, domicilio, teléfono y correo electrónico.</p>\r\n    <h4>Transferencias de la información</h4><p>El usuario autoriza proporcionar información sin consentimiento adicional en los casos previstos por ley, resolución de autoridad competente, tratados aplicables, salvaguarda de interés público, procuración o administración de justicia, reconocimiento o defensa de derechos en procesos judiciales, y a socios comerciales, técnicos o estratégicos que asuman obligaciones de confidencialidad y seguridad equivalentes.</p>\r\n    <h4>Limitación del uso o divulgación de datos y derechos ARCO</h4><p>El usuario podrá limitar el uso o divulgación de sus datos personales y ejercer derechos de acceso, rectificación, cancelación u oposición mediante solicitud escrita dirigida a “EL PRESTADOR” en su domicilio o al correo silvia@pasaporteatusalud.com, acompañando documento que acredite su identidad.</p>\r\n    <h4>Revocación de consentimiento</h4><p>El usuario podrá revocar su consentimiento siguiendo el mismo procedimiento, considerando que para ciertos fines la revocación puede implicar la cancelación de “LA TARJETA DE DESCUENTO” y la imposibilidad de acceder al programa.</p>\r\n    <p><strong>Nombre:</strong> Javier Jimenez Sanchez<br><strong>Fecha:</strong> 13 de mayo de 2026</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Firma</strong></div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 6<br>DECLARACIÓN DE DUEÑO BENEFICIARIO</h2>\r\n    <p>DE CONFORMIDAD CON LO DISPUESTO EN LOS ARTÍCULOS 18 FRACCIÓN I Y III DE LA LEY FEDERAL PARA PREVENCIÓN E IDENTIFICACIÓN DE OPERACIONES CON RECURSOS DE PROCEDENCIA ILÍCITA, EL ARTÍCULO 15 DE SU REGLAMENTO Y EL ARTÍCULO 13 DE LAS REGLAS DE CARÁCTER GENERAL, MANIFIESTO BAJO PROTESTA DE DECIR VERDAD:</p>\r\n    <h4>Datos de identificación del cliente</h4>\r\n    <table><tr><th>Campo</th><th>Respuesta</th></tr><tr><td>Apellido paterno, materno y nombre(s)</td><td>Javier Jimenez Sanchez</td></tr><tr><td>Fecha de nacimiento</td><td>1980-05-08</td></tr><tr><td>País de nacimiento</td><td>México</td></tr><tr><td>Nacionalidad</td><td>mexicana</td></tr><tr><td>Actividad, ocupación o profesión</td><td>Comerciante</td></tr><tr><td>Estado civil</td><td>CASADO(A)</td></tr><tr><td>Domicilio particular</td><td>Jornal 115, Col. zapopan, C.P. 45255, cholula, Jalisco, México</td></tr><tr><td>Teléfonos</td><td>3333333333</td></tr><tr><td>Correo electrónico</td><td>juancarlos@pasaporteatusalud.com</td></tr><tr><td>CURP</td><td>145214521452145214</td></tr><tr><td>RFC</td><td>GFDGSDFG</td></tr><tr><td>Tipo de identificación</td><td>INE</td></tr><tr><td>Emitida por / país emisor</td><td>México</td></tr><tr><td>Número de identificación</td><td>GGFADGFADGDA</td></tr></table>\r\n    <h4>Datos de identificación de la operación</h4>\r\n    <table><tr><th>Campo</th><th>Respuesta</th></tr><tr><td>Tipo de operación</td><td>Adquisición de tarjeta de descuento PATS</td></tr><tr><td>Monto de operación</td><td>$800.00 M.N.</td></tr><tr><td>Fecha de operación</td><td>13 de mayo de 2026</td></tr><tr><td>Forma de pago</td><td>Pasarela / medio autorizado por “EL PRESTADOR”</td></tr><tr><td>Moneda</td><td>MXN</td></tr></table>\r\n    <h4>Información de la existencia del dueño beneficiario o beneficiario controlador</h4>\r\n    <p>Declaro que soy el beneficiario directo de la operación y no existe ningún otro dueño beneficiario o beneficiario controlador: <strong>SI</strong>.</p>\r\n    <h4>Aviso de privacidad</h4><p>Los datos personales serán protegidos y tratados conforme al Aviso de Privacidad contenido en el cuerpo del presente contrato y la legislación aplicable.</p>\r\n    <p>H. Puebla de Zaragoza al 13 del mes de mayo del año 2026.</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Nombre y firma</strong><br>Javier Jimenez Sanchez</div>\r\n  </div>\r\n\r\n  \r\n  </div>\r\n', 'data:image/png;base64,', 'Javier Jimenez Sanchez', '4d69fb1ca29175765521c3cb0d5975ede5ffb75c5f3fe6013dd95b710605a943', '2026-05-13 00:28:33', '189.190.196.8', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:150.0) Gecko/20100101 Firefox/150.0', '', 'firmado', '2026-05-13 00:28:33', '2026-05-13 00:28:33');
INSERT INTO `pats_contratos_firmados` (`id_contrato_firmado`, `id_orden`, `id_pasaporte`, `id_distribuidor`, `id_franquicia`, `token_publico`, `contrato_clave`, `contrato_version`, `html_contrato_renderizado`, `firma_afiliado_base64`, `nombre_firmante`, `hash_contrato`, `fecha_firma`, `ip_firma`, `user_agent_firma`, `pdf_path`, `estatus`, `created_at`, `updated_at`) VALUES
(7, 9, 12, 0, 0, '', 'contrato_pats_base', '1.0', '<style>\r\n  .pats-contract{font-family:Arial,Helvetica,sans-serif;color:#172033;font-size:12px;line-height:1.52;background:#fff;padding:4px}\r\n  .pats-contract h1,.pats-contract h2,.pats-contract h3,.pats-contract h4{text-align:center;margin:12px 0 8px;color:#0d1b3e}\r\n  .pats-contract h1{font-size:16px;text-transform:uppercase;letter-spacing:.05em}\r\n  .pats-contract h2{font-size:15px;text-transform:uppercase;letter-spacing:.04em}\r\n  .pats-contract h3{font-size:13px;text-transform:uppercase;letter-spacing:.08em}\r\n  .pats-contract h4{font-size:12px;text-align:left;text-transform:uppercase;margin-top:12px}\r\n  .pats-contract p{margin:6px 0;text-align:justify}\r\n  .pats-contract ul{margin:6px 0 8px 18px;padding:0}.pats-contract li{margin:4px 0;text-align:justify}\r\n  .pats-contract table{width:100%;border-collapse:collapse;margin:8px 0 12px}.pats-contract th,.pats-contract td{border:1px solid #cbd5e1;padding:6px;vertical-align:top}.pats-contract th{background:#eef4ff;color:#0d1b3e;text-align:left}\r\n  .pats-contract .center{text-align:center}.pats-contract .muted{color:#64748b}.pats-contract .small{font-size:10px}.pats-contract .badge{display:inline-block;padding:3px 8px;border-radius:999px;background:#eef4ff;color:#1d4ed8;font-weight:700;margin:2px 4px 2px 0}\r\n  .pats-contract .sign-grid{display:grid;grid-template-columns:1fr 1fr;gap:22px;margin-top:28px}.pats-contract .sign-box{text-align:center;min-height:95px}.pats-contract .line{border-top:1px solid #0f172a;margin:48px 8px 6px}.pats-contract .signature-img{max-width:220px;max-height:82px;display:block;margin:0 auto 4px}\r\n  .pats-contract .annex{page-break-before:auto;border-top:2px solid #0d1b3e;margin-top:18px;padding-top:12px}.pats-contract .page-break{page-break-before:always;border-top:1px dashed #cbd5e1;margin-top:18px;padding-top:12px}\r\n</style>\r\n<div class=\"pats-contract\">\r\n  <h1>Carátula del contrato de adquisición de tarjeta de descuento</h1>\r\n  <p>CARÁTULA DEL CONTRATO DE ADQUISICIÓN DE TARJETA DE DESCUENTO (EN LO SUCESIVO “LA CARÁTULA”), QUE CELEBRAN POR UNA PARTE LA SOCIEDAD SEÑALADA EN EL APARTADO 1.- DE LA CARÁTULA, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL PRESTADOR”, REPRESENTADA EN ESTE ACTO POR LA PERSONA FÍSICA QUE SE INDICA EN EL APARTADO 2.- DE LA CARÁTULA; Y POR LA OTRA PARTE, LA PERSONA FÍSICA SEÑALADA EN EL APARTADO 5.- DE LA CARÁTULA, POR SU PROPIO DERECHO, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL AFILIADO”; Y CUANDO LOS ANTES NOMBRADOS ACTÚEN DE MANERA CONJUNTA, SE LES DENOMINARÁ COMO “LAS PARTES”; QUIENES SE SUJETAN AL TENOR DE LA CARÁTULA, DECLARACIONES Y CLÁUSULAS SIGUIENTES:</p>\r\n    \r\n  <h2>C A R Á T U L A</h2>\r\n  <table>\r\n    <tr><th style=\"width:8%\">Apartado</th><th style=\"width:42%\">Definición</th><th>Respuesta</th></tr>\r\n    <tr><td>1.-</td><td>Nombre de “EL PRESTADOR”</td><td>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE</td></tr>\r\n    <tr><td>2.-</td><td>Nombre del Representante Legal de “EL PRESTADOR”</td><td>PEDRO AZCÁRRAGA RAMOS</td></tr>\r\n    <tr><td>3.-</td><td>Domicilio de “EL PRESTADOR”</td><td>CALLE PASEO SINFONÍA NÚMERO EXTERIOR 1, LOCAL 2-14, LOMAS DE ANGELÓPOLIS II, SAN ANDRÉS CHOLULA, ESTADO DE PUEBLA, CÓDIGO POSTAL 72830</td></tr>\r\n    <tr><td>4.-</td><td>Clave del Registro Federal de Contribuyentes de “EL PRESTADOR”</td><td>COH2202144H5</td></tr>\r\n    <tr><td>5.-</td><td>Nombre de “EL AFILIADO”</td><td>Thalia Sodi Miranda</td></tr>\r\n    <tr><td>6.-</td><td>Domicilio de “EL AFILIADO”</td><td>Jornal 115, Col. zapopan, C.P. 45255, zapopan, Jalisco, México</td></tr>\r\n    <tr><td>7.-</td><td>Clave del Registro Federal de Contribuyentes de “EL AFILIADO”</td><td>Pendiente / no proporcionado</td></tr>\r\n    <tr><td>8.-</td><td>Costo anual de “LA TARJETA DE DESCUENTO”</td><td>$9,600.00 M.N.</td></tr>\r\n    <tr><td>9.-</td><td>Cuenta bancaria de “EL PRESTADOR” para pagos</td><td>Cuenta: 01600866709<br>CLABE: 042650016008667096<br>Institución Bancaria: Banca Mifel, S.A., Institución de Banca Múltiple, Grupo Financiero Mifel</td></tr>\r\n    <tr><td>10.-</td><td>Cuota de Reactivación de “LA TARJETA DE DESCUENTO”</td><td>$100.00 M.N. por cada mes que se haya interrumpido el pago.</td></tr>\r\n    <tr><td>11.-</td><td>Datos de la Tarjeta de Crédito de “EL AFILIADO”</td><td>Número de tarjeta: pendiente de confirmar por pasarela/token de pago.<br>Institución bancaria: pendiente de confirmar por pasarela. <br><span class=\"small\">No se almacena número completo de tarjeta en este formulario.</span></td></tr>\r\n    <tr><td>12.-</td><td>Anexos</td><td>ANEXO 1. Identificación oficial de “EL AFILIADO”<br>ANEXO 2. Comprobante de domicilio de “EL AFILIADO”<br>ANEXO 3. Constancia de Situación Fiscal de “EL AFILIADO”, si aplica<br>ANEXO 4. Cuotas de recuperación y/o precios base a cubrir a “EL PRESTADOR”<br>ANEXO 5. Aviso de privacidad<br>ANEXO 6. Declaración de dueño beneficiario</td></tr>\r\n    <tr><td>13.-</td><td>Fecha de Firma del Contrato</td><td>13 de mayo de 2026</td></tr>\r\n  </table>\r\n\r\n  <div class=\"sign-grid\">\r\n    <div class=\"sign-box\"><div class=\"line\"></div><strong>“EL PRESTADOR”</strong><br>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE<br>Representada por PEDRO AZCÁRRAGA RAMOS</div>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>“EL AFILIADO”</strong><br>Thalia Sodi Miranda<br><span class=\"small\">La persona física señalada en el Apartado 5.- de la Carátula</span></div>\r\n  </div>\r\n\r\n  <div class=\"page-break\"></div>\r\n  <h1>Contrato de adquisición de tarjeta de descuento</h1>\r\n  <p>CONTRATO DE ADQUISICIÓN DE TARJETA DE DESCUENTO, QUE CELEBRAN POR UNA PARTE LA SOCIEDAD SEÑALADA EN EL APARTADO 1.- DE LA CARÁTULA, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL PRESTADOR”, REPRESENTADA EN ESTE ACTO POR LA PERSONA FÍSICA QUE SE INDICA EN EL APARTADO 2.- DE LA CARÁTULA; Y POR LA OTRA PARTE, LA PERSONA FÍSICA SEÑALADA EN EL APARTADO 5.- DE LA CARÁTULA, POR SU PROPIO DERECHO, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL AFILIADO”; Y CUANDO LOS ANTES NOMBRADOS ACTÚEN DE MANERA CONJUNTA, SE LES DENOMINARÁ COMO “LAS PARTES”; QUIENES SE SUJETAN AL TENOR DE LAS DECLARACIONES Y CLÁUSULAS SIGUIENTES:</p>\r\n\r\n  <h2>D E C L A R A C I O N E S</h2>\r\n  <h4>I.- Declara “EL PRESTADOR” por conducto de su representación:</h4>\r\n  <p>A. Que, su representada es una sociedad mercantil constituida conforme a las leyes de los Estados Unidos Mexicanos, según consta en la escritura pública número 39,861, del volumen 830 de fecha catorce de febrero de dos mil veintidós, otorgada ante la fe del Licenciado Ernesto Joaquín Briones Amador, Notario Público Titular de la Notaría Pública número 46 de las del Distrito Judicial de Puebla, Estado de Puebla, cuyo primer testimonio se encuentra inscrito ante las oficinas del Registro Público de Comercio del Distrito Judicial de Puebla, Estado de Puebla, bajo el Folio Mercantil Electrónico: N-2022022991, por virtud del cual se llevó a cabo la Constitución de la persona moral denominada CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE.</p>\r\n  <p>B. Que, la persona física que la representa en este acto, señalada en el Apartado 2.- de la Carátula, cuenta con todas y cada una de las facultades necesarias para la celebración del presente contrato, las cuales se desprenden del instrumento descrito en el punto declarativo inmediato anterior, mismas que manifiesta bajo protesta de decir verdad que no le han sido suspendidas, revocadas o limitadas en forma alguna.</p>\r\n  <p>C. Que, su representada tiene como domicilio fiscal el señalado en el Apartado 3.- de la Carátula del presente contrato, mismo que designa como domicilio convencional para cualquier cuestión relacionada con la celebración del presente contrato.</p>\r\n  <p>D. Que, su representada se encuentra inscrita en el Registro Federal de Contribuyentes bajo la clave señalada en el Apartado 4.- de la Carátula.</p>\r\n  <p>E. Que, ha desarrollado y es su deseo comparecer a la celebración del presente instrumento con la finalidad de enajenar en favor de “EL AFILIADO”, una Tarjeta de Descuento que da acceso a “UN PROGRAMA DE BENEFICIOS QUE OTORGA DESCUENTOS A LOS COSTOS Y PERMITE RECIBIR SERVICIOS MÉDICOS PRIVADOS DE ALTA CALIDAD DE FORMA ACCESIBLE, CLARA Y SIN RESTRICCIONES DENTRO DE LA RED DE HOSPITALES 50 (FIFTY) DOCTORS CON SEDE EN EL ESTADO DE PUEBLA”, en lo sucesivo “LA TARJETA DE DESCUENTO”, en los términos y condiciones que se establecerán más adelante.</p>\r\n  <p>F. Que, su representada no es una Aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas sino una empresa dedicada, entre otros, a la operación y administración de establecimientos destinados a la atención y asistencia de enfermos, por lo que la enajenación de “LA TARJETA DE DESCUENTO” únicamente constituye un acto de comercio que brindará a “EL AFILIADO” acceso a un programa de beneficios como ha quedado descrito anteriormente.</p>\r\n\r\n  <h4>II.- Declara “EL AFILIADO”, por su propio derecho:</h4>\r\n      <p>A. Que, su nombre se señala en el Apartado 5.- de la Carátula, es una persona física de nacionalidad mexicana, en pleno ejercicio de sus derechos, legal y jurídicamente capaz para celebrar el presente Contrato, quien se identifica con credencial para votar vigente expedida por el Instituto Nacional Electoral, tipo INE, número AAAAAAAAAAAAA, que en copia simple o archivo digital se agrega al cuerpo del presente contrato como ANEXO 1.</p>\r\n    <p>B. Que, tiene como domicilio particular el señalado en el Apartado 6.- de la Carátula, mismo que designa como domicilio convencional para cualquier cuestión relacionada con la celebración del presente contrato, tal y como lo acredita con el comprobante de domicilio que en copia simple o archivo digital se agrega al cuerpo del presente contrato como ANEXO 2.</p>\r\n  <p>C. Que, su CURP es 145214521452145214 y su RFC/identificación fiscal es Pendiente / no proporcionado; asimismo manifiesta que cuenta con capacidad económica para obligarse en términos del presente contrato y que los recursos con los que cubrirá sus obligaciones provendrán de fuentes lícitas. En caso de nacionalidad extranjera/no mexicana, se tendrán por no aplicables CURP, INE y constancia fiscal mexicana salvo manifestación expresa de residencia fiscal o RFC mexicano.</p>\r\n  <p>D. Que, es su deseo comparecer a la celebración del presente instrumento con la finalidad de adquirir “LA TARJETA DE DESCUENTO” de acuerdo con los términos y condiciones que se establecen a continuación.</p>\r\n  <p>E. Que, previo a la celebración del presente contrato fue informado y manifiesta expresamente que reconoce que “EL PRESTADOR” no es una Aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas y que las actividades comerciales objeto del presente contrato no consisten en la contratación de un seguro, de la índole que fuere, sino que únicamente implica la adquisición de una tarjeta de descuento que da acceso a un programa de beneficios que otorga descuentos a los costos y permite recibir servicios médicos privados de alta calidad de forma accesible, clara y sin restricciones dentro de la red de hospitales 50 (FIFTY) Doctors con sede en el Estado de Puebla.</p>\r\n  <p>F. Que, reconoce que “EL PRESTADOR” se dedica a la operación de centros hospitalarios y que la emisión de “LA TARJETA DE DESCUENTO” únicamente corresponde a la intención de este último de crear un programa de descuentos para el acceso a los servicios prestados por la Red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla.</p>\r\n\r\n  <h4>III.- Declaran conjuntamente “LAS PARTES”:</h4>\r\n  <p>1. Que, se reconocen recíprocamente la personalidad con la que comparecen a la celebración del presente acuerdo de voluntades.</p>\r\n  <p>2. Que, el presente contrato es el instrumento que las vincula en sus derechos y obligaciones.</p>\r\n  <p>3. Que, es su deseo celebrar el presente contrato y han negociado libremente los términos y condiciones del mismo con pleno conocimiento de sus alcances e implicaciones jurídicas, por lo que en su celebración no existe dolo, error, mala fe, lesión o cualquier otro vicio del consentimiento que pudiese afectarlo de inexistencia o nulidad.</p>\r\n\r\n  <h2>C L Á U S U L A S</h2>\r\n  <h4>PRIMERA.- OBJETO.</h4>\r\n  <p>El objeto del presente Contrato es que “EL AFILIADO” adquiera de “EL PRESTADOR”, a título oneroso y temporal, el derecho de uso ilimitado y sin restricción alguna de “LA TARJETA DE DESCUENTO” emitida por CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE, la cual consiste en que “EL AFILIADO” aproveche y acceda a “UN PROGRAMA DE BENEFICIOS QUE OTORGA DESCUENTOS A LOS COSTOS Y PERMITE RECIBIR SERVICIOS MÉDICOS PRIVADOS DE ALTA CALIDAD DE FORMA ACCESIBLE, CLARA Y SIN RESTRICCIONES DENTRO DE LA RED DE HOSPITALES 50 (FIFTY) DOCTORS CON SEDE EN EL ESTADO DE PUEBLA”.</p>\r\n  <p>Estableciendo que, la comercialización de “LA TARJETA DE DESCUENTO” por parte de “EL PRESTADOR” en ningún momento constituirá la venta, promoción o por cualquier medio la contratación de una póliza de seguro, bajo el entendido de que “EL PRESTADOR” no es una aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas (CNSF); sino que comercializa “LA TARJETA DE DESCUENTO” en favor de terceros con la finalidad de otorgar descuentos a los precios respecto de los servicios médicos que presta en el territorio nacional.</p>\r\n\r\n  <h4>SEGUNDA.- PRECIO DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“LAS PARTES” establecen de común acuerdo que “LA TARJETA DE DESCUENTO” tendrá como costo anual la cantidad señalada en el Apartado 8.- de la Carátula del presente contrato; cantidad que ya incluye IVA, y la cual deberá ser cubierta por “EL AFILIADO” en favor de “EL PRESTADOR” dentro de los primeros 5 (cinco) días de cada mes, sin necesidad de gestiones o avisos de cobro, ya sea mediante:</p>\r\n  <p>(i) Transferencia electrónica de fondos a la cuenta bancaria señalada en el Apartado 9.- de la Carátula del presente contrato y de la cual es titular “EL PRESTADOR”.</p>\r\n  <p>(ii) Cheque que se recibirá salvo buen cobro en el Domicilio de “EL PRESTADOR” señalado en el Apartado 3.- de la Carátula del presente contrato, y que en caso de no ser pagado por falta de fondos suficientes o por otras causas imputables a “EL AFILIADO”, éste último está de acuerdo en que deberá cubrir a “EL PRESTADOR” el 20% (veinte por ciento) del monto del cheque por concepto de indemnización por daños y perjuicios en términos del artículo 193 de la Ley General de Títulos y Operaciones de Crédito, independientemente de cualquier otro cargo que se pudiera generar.</p>\r\n  <p>(iii) Cargos mensuales automáticos recurrentes a la tarjeta de crédito de “EL AFILIADO” según los datos señalados en el Apartado 11.- de la Carátula del presente contrato, quien manifiesta bajo protesta de decir verdad que autoriza a “EL PRESTADOR” a realizar los cargos mensuales correspondientes por el costo anual de “LA TARJETA DE DESCUENTO” en dicha tarjeta o en la tarjeta que por renovación, reposición, robo o extravío le haya asignado el banco emisor. La autorización estará vigente mientras “EL AFILIADO” no haya notificado a “EL PRESTADOR” por escrito y con acuse de recibo su deseo de cancelar su afiliación o no renovarla, o en su defecto, realizar su baja respectiva en el sitio web o aplicación de “EL PRESTADOR”.</p>\r\n  <p>Esta autorización no exime a “EL AFILIADO” del pago anual por el uso de “LA TARJETA DE DESCUENTO” y demás obligaciones contractuales, por lo que, en caso de que el cobro no sea autorizado por el banco emisor o por cualquier razón no pueda realizarse, “EL AFILIADO” deberá notificar tal situación a “EL PRESTADOR” a la dirección de correo electrónico silvia@pasaporteatusalud.com, a efecto de solicitar una forma de pago diversa, quedando obligado a cubrir de inmediato el pago correspondiente.</p>\r\n  <p>(iv) Cualquier otro medio de pago aceptado por “EL PRESTADOR”, mismo que se dará a conocer a través de sus medios oficiales de comunicación.</p>\r\n  <p>“EL PRESTADOR” podrá variar unilateralmente el costo mensual de “LA TARJETA DE DESCUENTO”, previo aviso a “EL AFILIADO” con 30 (treinta) días de anticipación a través de sus medios oficiales de comunicación.</p>\r\n  <p>Para el caso de que “EL AFILIADO” adquiera y cubra el precio de “LA TARJETA DE DESCUENTO” y posteriormente deje de pagar una mensualidad, deberá cubrir a “EL PRESTADOR”, por concepto de cuota de reactivación, la cantidad señalada en el Apartado 10.- de la Carátula por cada mes que haya interrumpido y/o no haya cubierto el precio de “LA TARJETA DE DESCUENTO”, hasta la fecha en que pretenda volver a adquirirla.</p>\r\n\r\n  <h4>TERCERA.- VIGENCIA DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“LA TARJETA DE DESCUENTO” objeto del presente contrato tendrá una vigencia de 12 meses contados a partir de que “EL AFILIADO” cubra a “EL PRESTADOR” el precio establecido anteriormente, en el entendido de que la vigencia del presente contrato y de “LA TARJETA DE DESCUENTO” se prorrogarán automáticamente sin necesidad de celebrar documento adicional entre “LAS PARTES” siempre y cuando “EL AFILIADO” cubra, de mes en mes o en la frecuencia contratada, el precio vigente de “LA TARJETA DE DESCUENTO”.</p>\r\n  <p>“EL AFILIADO” tendrá derecho a revocar su consentimiento dentro de los 5 (cinco) días siguientes a la entrega de “LA TARJETA DE DESCUENTO” o la firma del presente contrato, lo que ocurra último, sin responsabilidad alguna, siempre y cuando no haya obtenido beneficio alguno por el uso de “LA TARJETA DE DESCUENTO”.</p>\r\n\r\n  <h4>CUARTA.- BENEFICIOS DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“EL AFILIADO”, de forma exclusiva, personal e intransferible, gozará de forma gratuita de los servicios que se mencionan a continuación:</p>\r\n  <ul><li>Consultas gratuitas ilimitadas de medicina general (no de especialidad) en la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla, únicamente con los doctores afiliados al programa de Pasaporte a tu Salud.</li><li>Consultas de urgencia gratuitas en la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla.</li></ul>\r\n  <p>No así respecto de los servicios que, de manera enunciativa más no limitativa, se describen a continuación:</p>\r\n  <ul><li>Hospitalización dentro de la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla, sujeto a la disponibilidad de cada uno de ellos.</li><li>Consultas de especialidad ilimitadas a costo preferencial, con médicos especialistas pertenecientes al programa PATS.</li><li>Acceso a farmacia PATS con costos reducidos de medicamentos genéricos.</li><li>Imagenología y laboratorios ilimitados con costos preferenciales.</li><li>Acceso a cirugías con cuota de recuperación preferente, con o sin honorarios médicos incluidos según corresponda.</li></ul>\r\n  <p>Dichos servicios generarán, por evento, el pago de una cuota con cargo a “EL AFILIADO”, misma que resultará de aplicar los porcentajes de descuento que se desprenden del ANEXO 4 del presente contrato a los precios publicados al público en general o los precios preferenciales indicados.</p>\r\n  <p>Mientras “LA TARJETA DE DESCUENTO” se encuentre vigente, “EL AFILIADO” gozará de todos los beneficios que la misma le otorga; sin embargo, para el caso de que requiera cirugía o procedimiento quirúrgico en quirófano, deberá haber sufragado por adelantado la adquisición de “LA TARJETA DE DESCUENTO” por un periodo de 12 (doce) meses y encontrarse dentro de dicho periodo de vigencia.</p>\r\n\r\n  <h4>QUINTA.- OBLIGACIONES DE “EL PRESTADOR”.</h4>\r\n  <p>“EL PRESTADOR” se obliga a: (i) otorgar a “EL AFILIADO” el acceso ilimitado a “LA TARJETA DE DESCUENTO” durante la vigencia del contrato; (ii) mantener actualizada y operativa la Red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla; (iii) proporcionar a “EL AFILIADO”, de forma digital, “LA TARJETA DE DESCUENTO” dentro de los 5 (cinco) días hábiles siguientes al primer pago; e (iv) informar por escrito cualquier modificación a la red de hospitales o al tabulador de cuotas con al menos 10 (diez) días de anticipación.</p>\r\n\r\n  <h4>SEXTA.- OBLIGACIONES DE “EL AFILIADO”.</h4>\r\n  <p>“EL AFILIADO” se obliga a: (i) pagar puntualmente el precio de “LA TARJETA DE DESCUENTO”; (ii) utilizarla de forma exclusiva, personal e intransferible; (iii) cubrir directamente a los hospitales y con anterioridad a recibir el servicio médico las cuotas de recuperación según tabulador vigente; (iv) presentar identificación oficial y “LA TARJETA DE DESCUENTO” o código QR cada vez que haga uso de beneficios; y (v) notificar por escrito cualquier cambio de domicilio o datos de contacto en un plazo no mayor a 5 (cinco) días.</p>\r\n\r\n  <h4>SÉPTIMA.- ACCESO A LOS BENEFICIOS Y PROCEDIMIENTO.</h4>\r\n  <p>Para hacer uso de “LA TARJETA DE DESCUENTO”, “EL AFILIADO” deberá agendar sus citas directamente con los doctores pertenecientes a la Red de Hospitales 50 (FIFTY) Doctors, que en ese momento se encuentren adscritos al programa de beneficios, a través de la aplicación oficial, página de internet oficial de PATS o medios oficiales que indique “EL PRESTADOR”.</p>\r\n  <p>“EL AFILIADO” se obliga a pagar directamente al médico especialista perteneciente al programa el costo de la consulta de especialidad de que se trate, en términos de los porcentajes de descuento del ANEXO 4. En caso de no estar facultado para asistir por fuerza mayor, tendrá un plazo de 30 (treinta) días contados a partir de haber generado la cita para solicitar una nueva consulta médica.</p>\r\n\r\n  <h4>OCTAVA.- EXCLUSIONES Y LIMITACIONES.</h4>\r\n  <p>Los beneficios no incluirán: (i) trasplantes de órganos; (ii) tratamientos experimentales; (iii) tratamientos de oncología a excepción de algunas cirugías; (iv) medicamentos extra hospitalarios que no estén recogidos en el catálogo de Farmacia PATS; (v) atención médica con especialistas no adscritos o no publicados en los medios oficiales; y (vi) cualquier servicio no listado expresamente.</p>\r\n\r\n  <h4>NOVENA.- CAUSAS DE TERMINACIÓN.</h4>\r\n  <p>El contrato podrá terminarse por falta de pago, mutuo consentimiento por escrito o incumplimiento de cualquiera de las cláusulas por cualquiera de “LAS PARTES”. En caso de terminación, “EL AFILIADO” no tendrá derecho a exigir la devolución de cantidad alguna.</p>\r\n\r\n  <h4>DÉCIMA.- CANCELACIÓN VOLUNTARIA.</h4>\r\n  <p>“EL AFILIADO” podrá cancelar “LA TARJETA DE DESCUENTO” mediante aviso por escrito con 30 (treinta) días de anticipación. Dicha cancelación surtirá efectos a partir del siguiente periodo mensual y no generará reembolso de pagos ya realizados.</p>\r\n\r\n  <h4>DÉCIMA PRIMERA.- PROTECCIÓN DE DATOS PERSONALES.</h4>\r\n  <p>“LAS PARTES” acuerdan que el tratamiento de datos personales se sujetará a la Ley Federal de Protección de Datos Personales en Posesión de los Particulares. “EL AFILIADO” autoriza expresamente el uso de sus datos para la gestión de “LA TARJETA DE DESCUENTO”. El aviso de privacidad se integra al presente contrato como ANEXO 5.</p>\r\n\r\n  <h4>DÉCIMA SEGUNDA.- RESPONSABILIDAD.</h4>\r\n  <p>“EL AFILIADO” reconoce y acepta que “LA TARJETA DE DESCUENTO” es emitida y administrada directamente por CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE, quien es responsable de la operación de la red de descuentos, afiliación de prestadores médicos y prestación de cualquier servicio relacionado con “LA TARJETA DE DESCUENTO”.</p>\r\n  <p>En consecuencia, “EL PRESTADOR” no tendrá responsabilidad directa ni indirecta por la prestación, calidad, eficacia, resultado, daño, perjuicio, lesión, complicación, secuela, evento adverso o consecuencia derivada de servicios médicos recibidos, incluyendo aquellos ocasionados por negligencia, impericia o mala praxis de profesionales de la salud o prestadores afiliados. Cualquier relación derivada de la prestación de servicios médicos se establece directamente entre “EL AFILIADO” y los prestadores de servicios de salud correspondientes. Esta limitación subsistirá a la terminación del contrato.</p>\r\n\r\n  <h4>DÉCIMA TERCERA.- PREVENCIÓN DE LAVADO DE DINERO Y ORIGEN DE LOS RECURSOS.</h4>\r\n  <p>“LAS PARTES” declaran bajo protesta de decir verdad que los recursos económicos, bienes y derechos que utilicen para cumplir obligaciones derivadas de este contrato tienen y tendrán origen lícito. “EL AFILIADO” manifiesta que el pago inicial y pagos futuros provienen de fuentes lícitas y no de actividades tipificadas como delitos.</p>\r\n  <p>“LAS PARTES” reconocen que la prestación de servicios de comercio puede ser considerada actividad vulnerable, por lo que se obligan a proporcionar información y documentación requerida para integrar expediente de identificación e informar si tienen conocimiento de la existencia de beneficiario controlador.</p>\r\n\r\n  <h4>DÉCIMA CUARTA.- CONFORMACIÓN DEL EXPEDIENTE DE IDENTIFICACIÓN.</h4>\r\n  <p>“EL PRESTADOR” queda obligado a conformar y mantener un expediente de identificación de “EL AFILIADO”. Para tales efectos, “EL AFILIADO” se obliga a entregar los documentos aplicables: identificación oficial vigente o pasaporte, acta de nacimiento cuando aplique, comprobante de domicilio, constancia de situación fiscal cuando aplique, CURP, y declaración de dueño beneficiario.</p>\r\n  <p>Cuando exista persona responsable, la documentación de identificación y representación deberá integrarse al expediente; la CIF/constancia fiscal corresponde al tutor cuando aplique. “EL PRESTADOR” conservará dicho expediente por un periodo mínimo de 5 (cinco) años contados a partir de que termine la vigencia del contrato o termine por cualquiera de sus causales, garantizando la confidencialidad de los datos personales.</p>\r\n\r\n  <h4>DÉCIMA QUINTA.- CAUSAL ESPECÍFICA DE RESCISIÓN.</h4>\r\n  <p>Será motivo de rescisión inmediata sin necesidad de declaración judicial y sin responsabilidad para la parte afectada cuando cualquiera de “LAS PARTES” se niegue a proporcionar información requerida para cumplimiento de la Ley Federal para la Prevención e Identificación de Operaciones con Recursos de Procedencia Ilícita, proporcione información falsa o aparezca en listas de personas bloqueadas emitidas por autoridad competente.</p>\r\n\r\n  <h4>DÉCIMA SEXTA.- LEGISLACIÓN APLICABLE Y JURISDICCIÓN.</h4>\r\n  <p>“LAS PARTES” establecen que la Procuraduría Federal del Consumidor es competente en vía administrativa para resolver cualquier controversia sobre interpretación o cumplimiento. Sin perjuicio de lo anterior, se someten expresamente a la jurisdicción de los tribunales competentes del fuero común del Distrito Judicial de Puebla, Estado de Puebla, renunciando de manera expresa e irrevocable a cualquier otro fuero o jurisdicción que pudiera corresponderles.</p>\r\n\r\n  <p>Enteradas “LAS PARTES” del contenido y alcance del presente contrato, y entendidas de los derechos y obligaciones que contraen, firman el presente instrumento, incluyendo sus anexos, manifestando que no medió error, dolo, mala fe, violencia o lesión, ni vicio del consentimiento alguno, en la Ciudad de Puebla, Estado de Puebla, reconociendo que la fecha de firma es 13 de mayo de 2026.</p>\r\n\r\n  <div class=\"sign-grid\">\r\n    <div class=\"sign-box\"><div class=\"line\"></div><strong>“EL PRESTADOR”</strong><br>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE<br>Representada por PEDRO AZCÁRRAGA RAMOS</div>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>“EL AFILIADO”</strong><br>Thalia Sodi Miranda</div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 1<br>Identificación oficial de “EL AFILIADO”</h2><p>Se integra al expediente la identificación oficial cargada por el usuario en el formulario. Para mexicanos, corresponde a identificación oficial/INE cuando aplique. Para extranjeros/no mexicanos, corresponde a identificación oficial o pasaporte vigente; al menos el frente es obligatorio y el reverso será opcional cuando el documento no lo tenga.</p><p><strong>Tipo:</strong> INE. <strong>Emitida por / país emisor:</strong> México. <strong>Número:</strong> AAAAAAAAAAAAA.</p></div>\r\n  <div class=\"annex\"><h2>ANEXO 2<br>COMPROBANTE DE DOMICILIO DE “EL AFILIADO”</h2><p>Se integra al expediente el comprobante de domicilio cargado por el usuario. Domicilio declarado: Jornal 115, Col. zapopan, C.P. 45255, zapopan, Jalisco, México.</p></div>\r\n  <div class=\"annex\"><h2>ANEXO 3<br>CONSTANCIA DE SITUACIÓN FISCAL DE “EL AFILIADO”</h2><p>Constancia de Situación Fiscal de “EL AFILIADO”, si aplica. En caso de pacientes representados, la constancia fiscal o CIF corresponde a la persona responsable cuando sea aplicable, no al menor. Para afiliados extranjeros/no mexicanos, no será obligatoria salvo que declaren RFC mexicano o residencia fiscal aplicable.</p></div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 4<br>CUOTAS DE RECUPERACIÓN Y/O PRECIOS BASE A CUBRIR A “EL PRESTADOR”</h2>\r\n    <p>En el presente anexo se establecen los porcentajes de descuento a obtener como titular de “LA TARJETA DE DESCUENTO”, por lo que la cantidad a cubrir por “EL AFILIADO” directamente al hospital de la cadena 50 (FIFTY) Doctors o al doctor que preste el servicio se obtendrá de aplicar el porcentaje de descuento correspondiente al precio publicado por los medios oficiales o al precio vigente en el establecimiento.</p>\r\n    <table><tr><th>Servicios / procedimientos</th><th>Descuentos</th></tr><tr><td>Consulta de urgencias</td><td>100%</td></tr><tr><td>Consulta de medicina general</td><td>100%</td></tr><tr><td>Habitación hospitalaria</td><td>90%</td></tr><tr><td>Uso de áreas de urgencias médicas</td><td>80%</td></tr><tr><td>Utilización de cubículos de terapia intensiva (UCIA-UCIN-UCIP)</td><td>75%</td></tr><tr><td>CEYE</td><td>75%</td></tr><tr><td>Uso quirófano</td><td>75%</td></tr><tr><td>Servicio de cuneros</td><td>75%</td></tr><tr><td>Materiales & medicamentos del cuadro básico, genéricos intercambiables</td><td>70%</td></tr><tr><td>Hemodinamia</td><td>70%</td></tr><tr><td>Imagenología</td><td>70%</td></tr><tr><td>Endoprótesis</td><td>70%</td></tr><tr><td>Osteosíntesis</td><td>70%</td></tr><tr><td>Prótesis</td><td>70%</td></tr><tr><td>Órtesis</td><td>70%</td></tr><tr><td>Laboratorio clínico</td><td>60%</td></tr></table>\r\n    <p class=\"small\">Los descuentos aplican con los proveedores suscritos al convenio de Pasaporte a tu Salud.</p>\r\n    <table><tr><th>Servicios / procedimientos</th><th>Precios base</th></tr><tr><td>Consulta de especialidades médicas</td><td>$390.00</td></tr><tr><td>Colposcopía</td><td>$400.00</td></tr><tr><td>Retiro de puntos de sutura</td><td>$80.00</td></tr><tr><td>Aplicación de medicamento intramuscular</td><td>$60.00</td></tr><tr><td>Retiro de DIU</td><td>$500.00</td></tr><tr><td>Colocación de DIU</td><td>$700.00</td></tr><tr><td>Extracción de cuerpo extraño (oído y nariz)</td><td>$300.00</td></tr><tr><td>Lavado ótico</td><td>$250.00</td></tr><tr><td>Curación de sitio quirúrgico</td><td>$250.00</td></tr><tr><td>Retiro de yeso</td><td>$250.00</td></tr><tr><td>Visita día de hospitalización</td><td>$650.00</td></tr><tr><td>Visita de urgencias</td><td>$750.00</td></tr><tr><td>Día de terapia intensiva</td><td>$850.00</td></tr></table>\r\n    <p class=\"small\">Todos los precios incluyen IVA. La factura de servicios hospitalarios será emitida con el desglose correspondiente y el ahorro otorgado por ser titular de “LA TARJETA DE DESCUENTO”.</p>\r\n    <p>Exclusiones y limitaciones: se aplicarán descuentos y precios especiales para el acompañante de “EL AFILIADO” en la misma habitación únicamente para la primera noche de hospitalización. Los precios y porcentajes de descuento darán derecho a la utilización de materiales y medicamentos del cuadro básico, genéricos intercambiables; cualquier otro tipo de medicación será cubierto directamente por “EL AFILIADO”. Los costos de procedimientos quirúrgicos incluyen honorarios médicos cuando así se indique. “EL AFILIADO” podrá atenderse con el médico tratante que elija, debiendo cubrir honorarios directamente a dicho médico, conservando el derecho a beneficios dentro de la red aplicable.</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Firma de aceptación de “EL AFILIADO”</strong><br>Thalia Sodi Miranda</div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 5<br>AVISO DE PRIVACIDAD</h2>\r\n    <p>En cumplimiento de las disposiciones establecidas en la Ley Federal de Protección de Datos Personales en Posesión de Particulares, su Reglamento y los lineamientos aplicables, “CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE” (en lo sucesivo “EL PRESTADOR”), con domicilio en CALLE PASEO SINFONÍA NÚMERO EXTERIOR 1, LOCAL 2-14, LOMAS DE ANGELÓPOLIS II, SAN ANDRÉS CHOLULA, ESTADO DE PUEBLA, CÓDIGO POSTAL 72830, da a conocer el Aviso de Privacidad al tenor del cual manejará por medio de su representación y/o empleados los datos personales y/o documentación proporcionada por el afiliado o usuario de “LA TARJETA DE DESCUENTO”.</p>\r\n    <p>Se tendrá por aceptado expresamente el presente Aviso de Privacidad una vez proporcionados los datos personales y firmada digitalmente la aceptación del contrato, motivo por el cual “EL PRESTADOR” estará facultado para manejar la información conforme a la legislación aplicable.</p>\r\n    <h4>Modificación del aviso de privacidad</h4><p>Este aviso podrá ser modificado o adecuado a las necesidades de “EL PRESTADOR”. Las modificaciones o actualizaciones serán incorporadas al presente aviso y estarán disponibles en la página de internet, domicilio de “EL PRESTADOR” o serán enviadas al último correo electrónico proporcionado.</p>\r\n    <h4>Finalidad de la información</h4><p>La información será utilizada para: elaborar y mantener actualizada la base de usuarios; identificar afiliados; proporcionar la tarjeta digital; otorgar acceso al programa de beneficios; informar modificaciones a la red o tabulador; realizar análisis estadísticos internos y brindar un óptimo servicio médico.</p>\r\n    <h4>Tipo de datos necesarios</h4><p>Se solicitarán datos de identificación, contacto, legales, contractuales y fiscales cuando aplique, incluyendo nombre completo, lugar y fecha de nacimiento, firma, identificación oficial, nacionalidad, CURP y RFC cuando sean aplicables, domicilio, teléfono y correo electrónico.</p>\r\n    <h4>Transferencias de la información</h4><p>El usuario autoriza proporcionar información sin consentimiento adicional en los casos previstos por ley, resolución de autoridad competente, tratados aplicables, salvaguarda de interés público, procuración o administración de justicia, reconocimiento o defensa de derechos en procesos judiciales, y a socios comerciales, técnicos o estratégicos que asuman obligaciones de confidencialidad y seguridad equivalentes.</p>\r\n    <h4>Limitación del uso o divulgación de datos y derechos ARCO</h4><p>El usuario podrá limitar el uso o divulgación de sus datos personales y ejercer derechos de acceso, rectificación, cancelación u oposición mediante solicitud escrita dirigida a “EL PRESTADOR” en su domicilio o al correo silvia@pasaporteatusalud.com, acompañando documento que acredite su identidad.</p>\r\n    <h4>Revocación de consentimiento</h4><p>El usuario podrá revocar su consentimiento siguiendo el mismo procedimiento, considerando que para ciertos fines la revocación puede implicar la cancelación de “LA TARJETA DE DESCUENTO” y la imposibilidad de acceder al programa.</p>\r\n    <p><strong>Nombre:</strong> Thalia Sodi Miranda<br><strong>Fecha:</strong> 13 de mayo de 2026</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Firma</strong></div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 6<br>DECLARACIÓN DE DUEÑO BENEFICIARIO</h2>\r\n    <p>DE CONFORMIDAD CON LO DISPUESTO EN LOS ARTÍCULOS 18 FRACCIÓN I Y III DE LA LEY FEDERAL PARA PREVENCIÓN E IDENTIFICACIÓN DE OPERACIONES CON RECURSOS DE PROCEDENCIA ILÍCITA, EL ARTÍCULO 15 DE SU REGLAMENTO Y EL ARTÍCULO 13 DE LAS REGLAS DE CARÁCTER GENERAL, MANIFIESTO BAJO PROTESTA DE DECIR VERDAD:</p>\r\n    <h4>Datos de identificación del cliente</h4>\r\n    <table><tr><th>Campo</th><th>Respuesta</th></tr><tr><td>Apellido paterno, materno y nombre(s)</td><td>Thalia Sodi Miranda</td></tr><tr><td>Fecha de nacimiento</td><td>1977-12-15</td></tr><tr><td>País de nacimiento</td><td>México</td></tr><tr><td>Nacionalidad</td><td>mexicana</td></tr><tr><td>Actividad, ocupación o profesión</td><td>Comerciante</td></tr><tr><td>Estado civil</td><td>CASADO(A)</td></tr><tr><td>Domicilio particular</td><td>Jornal 115, Col. zapopan, C.P. 45255, zapopan, Jalisco, México</td></tr><tr><td>Teléfonos</td><td>4444444444</td></tr><tr><td>Correo electrónico</td><td>juancarlos@pasaporteatusalud.com</td></tr><tr><td>CURP</td><td>145214521452145214</td></tr><tr><td>RFC</td><td>Pendiente / no proporcionado</td></tr><tr><td>Tipo de identificación</td><td>INE</td></tr><tr><td>Emitida por / país emisor</td><td>México</td></tr><tr><td>Número de identificación</td><td>AAAAAAAAAAAAA</td></tr></table>\r\n    <h4>Datos de identificación de la operación</h4>\r\n    <table><tr><th>Campo</th><th>Respuesta</th></tr><tr><td>Tipo de operación</td><td>Adquisición de tarjeta de descuento PATS</td></tr><tr><td>Monto de operación</td><td>$9,600.00 M.N.</td></tr><tr><td>Fecha de operación</td><td>13 de mayo de 2026</td></tr><tr><td>Forma de pago</td><td>Pasarela / medio autorizado por “EL PRESTADOR”</td></tr><tr><td>Moneda</td><td>MXN</td></tr></table>\r\n    <h4>Información de la existencia del dueño beneficiario o beneficiario controlador</h4>\r\n    <p>Declaro que soy el beneficiario directo de la operación y no existe ningún otro dueño beneficiario o beneficiario controlador: <strong>SI</strong>.</p>\r\n    <h4>Aviso de privacidad</h4><p>Los datos personales serán protegidos y tratados conforme al Aviso de Privacidad contenido en el cuerpo del presente contrato y la legislación aplicable.</p>\r\n    <p>H. Puebla de Zaragoza al 13 del mes de mayo del año 2026.</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Nombre y firma</strong><br>Thalia Sodi Miranda</div>\r\n  </div>\r\n\r\n  \r\n  </div>\r\n', 'data:image/png;base64,', 'Thalia Sodi Miranda', '2aab237587e6a8b1113787ff42410340d7a10f8938b9976da1544e782337ec96', '2026-05-13 00:44:22', '189.190.196.8', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:150.0) Gecko/20100101 Firefox/150.0', '', 'firmado', '2026-05-13 00:44:22', '2026-05-13 00:44:22');
INSERT INTO `pats_contratos_firmados` (`id_contrato_firmado`, `id_orden`, `id_pasaporte`, `id_distribuidor`, `id_franquicia`, `token_publico`, `contrato_clave`, `contrato_version`, `html_contrato_renderizado`, `firma_afiliado_base64`, `nombre_firmante`, `hash_contrato`, `fecha_firma`, `ip_firma`, `user_agent_firma`, `pdf_path`, `estatus`, `created_at`, `updated_at`) VALUES
(8, 10, 13, 0, 0, '', 'contrato_pats_base', '1.0', '<style>\r\n  .pats-contract{font-family:Arial,Helvetica,sans-serif;color:#172033;font-size:12px;line-height:1.52;background:#fff;padding:4px}\r\n  .pats-contract h1,.pats-contract h2,.pats-contract h3,.pats-contract h4{text-align:center;margin:12px 0 8px;color:#0d1b3e}\r\n  .pats-contract h1{font-size:16px;text-transform:uppercase;letter-spacing:.05em}\r\n  .pats-contract h2{font-size:15px;text-transform:uppercase;letter-spacing:.04em}\r\n  .pats-contract h3{font-size:13px;text-transform:uppercase;letter-spacing:.08em}\r\n  .pats-contract h4{font-size:12px;text-align:left;text-transform:uppercase;margin-top:12px}\r\n  .pats-contract p{margin:6px 0;text-align:justify}\r\n  .pats-contract ul{margin:6px 0 8px 18px;padding:0}.pats-contract li{margin:4px 0;text-align:justify}\r\n  .pats-contract table{width:100%;border-collapse:collapse;margin:8px 0 12px}.pats-contract th,.pats-contract td{border:1px solid #cbd5e1;padding:6px;vertical-align:top}.pats-contract th{background:#eef4ff;color:#0d1b3e;text-align:left}\r\n  .pats-contract .center{text-align:center}.pats-contract .muted{color:#64748b}.pats-contract .small{font-size:10px}.pats-contract .badge{display:inline-block;padding:3px 8px;border-radius:999px;background:#eef4ff;color:#1d4ed8;font-weight:700;margin:2px 4px 2px 0}\r\n  .pats-contract .sign-grid{display:grid;grid-template-columns:1fr 1fr;gap:22px;margin-top:28px}.pats-contract .sign-box{text-align:center;min-height:95px}.pats-contract .line{border-top:1px solid #0f172a;margin:48px 8px 6px}.pats-contract .signature-img{max-width:220px;max-height:82px;display:block;margin:0 auto 4px}\r\n  .pats-contract .annex{page-break-before:auto;border-top:2px solid #0d1b3e;margin-top:18px;padding-top:12px}.pats-contract .page-break{page-break-before:always;border-top:1px dashed #cbd5e1;margin-top:18px;padding-top:12px}\r\n</style>\r\n<div class=\"pats-contract\">\r\n  <h1>Carátula del contrato de adquisición de tarjeta de descuento</h1>\r\n  <p>CARÁTULA DEL CONTRATO DE ADQUISICIÓN DE TARJETA DE DESCUENTO (EN LO SUCESIVO “LA CARÁTULA”), QUE CELEBRAN POR UNA PARTE LA SOCIEDAD SEÑALADA EN EL APARTADO 1.- DE LA CARÁTULA, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL PRESTADOR”, REPRESENTADA EN ESTE ACTO POR LA PERSONA FÍSICA QUE SE INDICA EN EL APARTADO 2.- DE LA CARÁTULA; Y POR LA OTRA PARTE, LA PERSONA FÍSICA SEÑALADA EN EL APARTADO 5.- DE LA CARÁTULA, REPRESENTADA POR SU MAMÁ, PAPÁ O TUTOR, A QUIEN PARA EFECTOS DE BENEFICIO MÉDICO SE LE DENOMINARÁ COMO “EL AFILIADO” O “EL PACIENTE MENOR”; Y CUANDO LOS ANTES NOMBRADOS ACTÚEN DE MANERA CONJUNTA, SE LES DENOMINARÁ COMO “LAS PARTES”; QUIENES SE SUJETAN AL TENOR DE LA CARÁTULA, DECLARACIONES Y CLÁUSULAS SIGUIENTES:</p>\r\n  <p><span class=\"badge\">Menor de edad</span> El paciente/beneficiario real es el menor indicado en el Apartado 5; el contrato, avisos, aceptación y administración de usuario/contraseña son firmados y aceptados por su mamá, papá o tutor.</p>  \r\n  <h2>C A R Á T U L A</h2>\r\n  <table>\r\n    <tr><th style=\"width:8%\">Apartado</th><th style=\"width:42%\">Definición</th><th>Respuesta</th></tr>\r\n    <tr><td>1.-</td><td>Nombre de “EL PRESTADOR”</td><td>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE</td></tr>\r\n    <tr><td>2.-</td><td>Nombre del Representante Legal de “EL PRESTADOR”</td><td>PEDRO AZCÁRRAGA RAMOS</td></tr>\r\n    <tr><td>3.-</td><td>Domicilio de “EL PRESTADOR”</td><td>CALLE PASEO SINFONÍA NÚMERO EXTERIOR 1, LOCAL 2-14, LOMAS DE ANGELÓPOLIS II, SAN ANDRÉS CHOLULA, ESTADO DE PUEBLA, CÓDIGO POSTAL 72830</td></tr>\r\n    <tr><td>4.-</td><td>Clave del Registro Federal de Contribuyentes de “EL PRESTADOR”</td><td>COH2202144H5</td></tr>\r\n    <tr><td>5.-</td><td>Nombre de “EL AFILIADO”</td><td>Mateo Fuentes Vazquez<br><span class=\"small\">Paciente representado por: Papa Papa Papa</span></td></tr>\r\n    <tr><td>6.-</td><td>Domicilio de “EL AFILIADO”</td><td>jjj 115, Col. zapopan, C.P. 45255, cholula, Jalisco, México</td></tr>\r\n    <tr><td>7.-</td><td>Clave del Registro Federal de Contribuyentes de “EL AFILIADO”</td><td>Pendiente / no proporcionado</td></tr>\r\n    <tr><td>8.-</td><td>Costo mensual de “LA TARJETA DE DESCUENTO”</td><td>$800.00 M.N.</td></tr>\r\n    <tr><td>9.-</td><td>Cuenta bancaria de “EL PRESTADOR” para pagos</td><td>Cuenta: 01600866709<br>CLABE: 042650016008667096<br>Institución Bancaria: Banca Mifel, S.A., Institución de Banca Múltiple, Grupo Financiero Mifel</td></tr>\r\n    <tr><td>10.-</td><td>Cuota de Reactivación de “LA TARJETA DE DESCUENTO”</td><td>$100.00 M.N. por cada mes que se haya interrumpido el pago.</td></tr>\r\n    <tr><td>11.-</td><td>Datos de la Tarjeta de Crédito de “EL AFILIADO”</td><td>Número de tarjeta: pendiente de confirmar por pasarela/token de pago.<br>Institución bancaria: pendiente de confirmar por pasarela. <br><span class=\"small\">No se almacena número completo de tarjeta en este formulario.</span></td></tr>\r\n    <tr><td>12.-</td><td>Anexos</td><td>ANEXO 1. Identificación oficial de “EL AFILIADO”<br>ANEXO 2. Comprobante de domicilio de “EL AFILIADO”<br>ANEXO 3. Constancia de Situación Fiscal de “EL AFILIADO”, si aplica<br>ANEXO 4. Cuotas de recuperación y/o precios base a cubrir a “EL PRESTADOR”<br>ANEXO 5. Aviso de privacidad<br>ANEXO 6. Declaración de dueño beneficiario<br>ANEXO 7. Documentación y aceptación de la persona responsable</td></tr>\r\n    <tr><td>13.-</td><td>Fecha de Firma del Contrato</td><td>13 de mayo de 2026</td></tr>\r\n  </table>\r\n\r\n  <div class=\"sign-grid\">\r\n    <div class=\"sign-box\"><div class=\"line\"></div><strong>“EL PRESTADOR”</strong><br>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE<br>Representada por PEDRO AZCÁRRAGA RAMOS</div>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>“MAMÁ, PAPÁ O TUTOR / FIRMANTE”</strong><br>Papa Papa Papa<br><span class=\"small\">Firma como responsable de Mateo Fuentes Vazquez</span></div>\r\n  </div>\r\n\r\n  <div class=\"page-break\"></div>\r\n  <h1>Contrato de adquisición de tarjeta de descuento</h1>\r\n  <p>CONTRATO DE ADQUISICIÓN DE TARJETA DE DESCUENTO, QUE CELEBRAN POR UNA PARTE LA SOCIEDAD SEÑALADA EN EL APARTADO 1.- DE LA CARÁTULA, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL PRESTADOR”, REPRESENTADA EN ESTE ACTO POR LA PERSONA FÍSICA QUE SE INDICA EN EL APARTADO 2.- DE LA CARÁTULA; Y POR LA OTRA PARTE, LA PERSONA MENOR DE EDAD SEÑALADA EN EL APARTADO 5.- DE LA CARÁTULA, REPRESENTADA EN ESTE ACTO POR SU MAMÁ, PAPÁ O TUTOR, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL AFILIADO”; Y CUANDO LOS ANTES NOMBRADOS ACTÚEN DE MANERA CONJUNTA, SE LES DENOMINARÁ COMO “LAS PARTES”; QUIENES SE SUJETAN AL TENOR DE LAS DECLARACIONES Y CLÁUSULAS SIGUIENTES:</p>\r\n\r\n  <h2>D E C L A R A C I O N E S</h2>\r\n  <h4>I.- Declara “EL PRESTADOR” por conducto de su representación:</h4>\r\n  <p>A. Que, su representada es una sociedad mercantil constituida conforme a las leyes de los Estados Unidos Mexicanos, según consta en la escritura pública número 39,861, del volumen 830 de fecha catorce de febrero de dos mil veintidós, otorgada ante la fe del Licenciado Ernesto Joaquín Briones Amador, Notario Público Titular de la Notaría Pública número 46 de las del Distrito Judicial de Puebla, Estado de Puebla, cuyo primer testimonio se encuentra inscrito ante las oficinas del Registro Público de Comercio del Distrito Judicial de Puebla, Estado de Puebla, bajo el Folio Mercantil Electrónico: N-2022022991, por virtud del cual se llevó a cabo la Constitución de la persona moral denominada CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE.</p>\r\n  <p>B. Que, la persona física que la representa en este acto, señalada en el Apartado 2.- de la Carátula, cuenta con todas y cada una de las facultades necesarias para la celebración del presente contrato, las cuales se desprenden del instrumento descrito en el punto declarativo inmediato anterior, mismas que manifiesta bajo protesta de decir verdad que no le han sido suspendidas, revocadas o limitadas en forma alguna.</p>\r\n  <p>C. Que, su representada tiene como domicilio fiscal el señalado en el Apartado 3.- de la Carátula del presente contrato, mismo que designa como domicilio convencional para cualquier cuestión relacionada con la celebración del presente contrato.</p>\r\n  <p>D. Que, su representada se encuentra inscrita en el Registro Federal de Contribuyentes bajo la clave señalada en el Apartado 4.- de la Carátula.</p>\r\n  <p>E. Que, ha desarrollado y es su deseo comparecer a la celebración del presente instrumento con la finalidad de enajenar en favor de “EL AFILIADO”, una Tarjeta de Descuento que da acceso a “UN PROGRAMA DE BENEFICIOS QUE OTORGA DESCUENTOS A LOS COSTOS Y PERMITE RECIBIR SERVICIOS MÉDICOS PRIVADOS DE ALTA CALIDAD DE FORMA ACCESIBLE, CLARA Y SIN RESTRICCIONES DENTRO DE LA RED DE HOSPITALES 50 (FIFTY) DOCTORS CON SEDE EN EL ESTADO DE PUEBLA”, en lo sucesivo “LA TARJETA DE DESCUENTO”, en los términos y condiciones que se establecerán más adelante.</p>\r\n  <p>F. Que, su representada no es una Aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas sino una empresa dedicada, entre otros, a la operación y administración de establecimientos destinados a la atención y asistencia de enfermos, por lo que la enajenación de “LA TARJETA DE DESCUENTO” únicamente constituye un acto de comercio que brindará a “EL AFILIADO” acceso a un programa de beneficios como ha quedado descrito anteriormente.</p>\r\n\r\n  <h4>II.- Declara “EL AFILIADO” por conducto de la persona responsable firmante:</h4>\r\n      <p>A. Que, el nombre de “EL AFILIADO”/paciente se señala en el Apartado 5.- de la Carátula: Mateo Fuentes Vazquez, con fecha de nacimiento 2015-05-05 y nacionalidad mexicana. Comparece representado por Papa Papa Papa, en carácter de PADRE, quien declara estar facultado para celebrar el presente contrato, firmarlo digitalmente, administrar usuario y contraseña, aceptar avisos, efectuar pagos y gestionar los beneficios de “LA TARJETA DE DESCUENTO” en favor del paciente.</p>\r\n    <p>B. Que, la persona responsable se identifica con identificación oficial mexicana vigente, tipo INE, número GFADGDAGFADFG. En caso de ser mexicano, deberá integrar CURP y documentación fiscal cuando aplique. </p>\r\n    <p>B. Que, tiene como domicilio particular el señalado en el Apartado 6.- de la Carátula, mismo que designa como domicilio convencional para cualquier cuestión relacionada con la celebración del presente contrato, tal y como lo acredita con el comprobante de domicilio que en copia simple o archivo digital se agrega al cuerpo del presente contrato como ANEXO 2.</p>\r\n  <p>C. Que, su CURP es CURP y su RFC/identificación fiscal es Pendiente / no proporcionado; asimismo manifiesta que cuenta con capacidad económica para obligarse en términos del presente contrato y que los recursos con los que cubrirá sus obligaciones provendrán de fuentes lícitas. En caso de nacionalidad extranjera/no mexicana, se tendrán por no aplicables CURP, INE y constancia fiscal mexicana salvo manifestación expresa de residencia fiscal o RFC mexicano.</p>\r\n  <p>D. Que, es su deseo comparecer a la celebración del presente instrumento con la finalidad de adquirir “LA TARJETA DE DESCUENTO” de acuerdo con los términos y condiciones que se establecen a continuación.</p>\r\n  <p>E. Que, previo a la celebración del presente contrato fue informado y manifiesta expresamente que reconoce que “EL PRESTADOR” no es una Aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas y que las actividades comerciales objeto del presente contrato no consisten en la contratación de un seguro, de la índole que fuere, sino que únicamente implica la adquisición de una tarjeta de descuento que da acceso a un programa de beneficios que otorga descuentos a los costos y permite recibir servicios médicos privados de alta calidad de forma accesible, clara y sin restricciones dentro de la red de hospitales 50 (FIFTY) Doctors con sede en el Estado de Puebla.</p>\r\n  <p>F. Que, reconoce que “EL PRESTADOR” se dedica a la operación de centros hospitalarios y que la emisión de “LA TARJETA DE DESCUENTO” únicamente corresponde a la intención de este último de crear un programa de descuentos para el acceso a los servicios prestados por la Red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla.</p>\r\n\r\n  <h4>III.- Declaran conjuntamente “LAS PARTES”:</h4>\r\n  <p>1. Que, se reconocen recíprocamente la personalidad con la que comparecen a la celebración del presente acuerdo de voluntades.</p>\r\n  <p>2. Que, el presente contrato es el instrumento que las vincula en sus derechos y obligaciones.</p>\r\n  <p>3. Que, es su deseo celebrar el presente contrato y han negociado libremente los términos y condiciones del mismo con pleno conocimiento de sus alcances e implicaciones jurídicas, por lo que en su celebración no existe dolo, error, mala fe, lesión o cualquier otro vicio del consentimiento que pudiese afectarlo de inexistencia o nulidad.</p>\r\n\r\n  <h2>C L Á U S U L A S</h2>\r\n  <h4>PRIMERA.- OBJETO.</h4>\r\n  <p>El objeto del presente Contrato es que “EL AFILIADO” adquiera de “EL PRESTADOR”, a título oneroso y temporal, el derecho de uso ilimitado y sin restricción alguna de “LA TARJETA DE DESCUENTO” emitida por CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE, la cual consiste en que “EL AFILIADO” aproveche y acceda a “UN PROGRAMA DE BENEFICIOS QUE OTORGA DESCUENTOS A LOS COSTOS Y PERMITE RECIBIR SERVICIOS MÉDICOS PRIVADOS DE ALTA CALIDAD DE FORMA ACCESIBLE, CLARA Y SIN RESTRICCIONES DENTRO DE LA RED DE HOSPITALES 50 (FIFTY) DOCTORS CON SEDE EN EL ESTADO DE PUEBLA”.</p>\r\n  <p>Estableciendo que, la comercialización de “LA TARJETA DE DESCUENTO” por parte de “EL PRESTADOR” en ningún momento constituirá la venta, promoción o por cualquier medio la contratación de una póliza de seguro, bajo el entendido de que “EL PRESTADOR” no es una aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas (CNSF); sino que comercializa “LA TARJETA DE DESCUENTO” en favor de terceros con la finalidad de otorgar descuentos a los precios respecto de los servicios médicos que presta en el territorio nacional.</p>\r\n\r\n  <h4>SEGUNDA.- PRECIO DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“LAS PARTES” establecen de común acuerdo que “LA TARJETA DE DESCUENTO” tendrá como costo mensual la cantidad señalada en el Apartado 8.- de la Carátula del presente contrato; cantidad que ya incluye IVA, y la cual deberá ser cubierta por “EL AFILIADO” en favor de “EL PRESTADOR” dentro de los primeros 5 (cinco) días de cada mes, sin necesidad de gestiones o avisos de cobro, ya sea mediante:</p>\r\n  <p>(i) Transferencia electrónica de fondos a la cuenta bancaria señalada en el Apartado 9.- de la Carátula del presente contrato y de la cual es titular “EL PRESTADOR”.</p>\r\n  <p>(ii) Cheque que se recibirá salvo buen cobro en el Domicilio de “EL PRESTADOR” señalado en el Apartado 3.- de la Carátula del presente contrato, y que en caso de no ser pagado por falta de fondos suficientes o por otras causas imputables a “EL AFILIADO”, éste último está de acuerdo en que deberá cubrir a “EL PRESTADOR” el 20% (veinte por ciento) del monto del cheque por concepto de indemnización por daños y perjuicios en términos del artículo 193 de la Ley General de Títulos y Operaciones de Crédito, independientemente de cualquier otro cargo que se pudiera generar.</p>\r\n  <p>(iii) Cargos mensuales automáticos recurrentes a la tarjeta de crédito de “EL AFILIADO” según los datos señalados en el Apartado 11.- de la Carátula del presente contrato, quien manifiesta bajo protesta de decir verdad que autoriza a “EL PRESTADOR” a realizar los cargos mensuales correspondientes por el costo mensual de “LA TARJETA DE DESCUENTO” en dicha tarjeta o en la tarjeta que por renovación, reposición, robo o extravío le haya asignado el banco emisor. La autorización estará vigente mientras “EL AFILIADO” no haya notificado a “EL PRESTADOR” por escrito y con acuse de recibo su deseo de cancelar su afiliación o no renovarla, o en su defecto, realizar su baja respectiva en el sitio web o aplicación de “EL PRESTADOR”.</p>\r\n  <p>Esta autorización no exime a “EL AFILIADO” del pago mensual por el uso de “LA TARJETA DE DESCUENTO” y demás obligaciones contractuales, por lo que, en caso de que el cobro no sea autorizado por el banco emisor o por cualquier razón no pueda realizarse, “EL AFILIADO” deberá notificar tal situación a “EL PRESTADOR” a la dirección de correo electrónico silvia@pasaporteatusalud.com, a efecto de solicitar una forma de pago diversa, quedando obligado a cubrir de inmediato el pago correspondiente.</p>\r\n  <p>(iv) Cualquier otro medio de pago aceptado por “EL PRESTADOR”, mismo que se dará a conocer a través de sus medios oficiales de comunicación.</p>\r\n  <p>“EL PRESTADOR” podrá variar unilateralmente el costo mensual de “LA TARJETA DE DESCUENTO”, previo aviso a “EL AFILIADO” con 30 (treinta) días de anticipación a través de sus medios oficiales de comunicación.</p>\r\n  <p>Para el caso de que “EL AFILIADO” adquiera y cubra el precio de “LA TARJETA DE DESCUENTO” y posteriormente deje de pagar una mensualidad, deberá cubrir a “EL PRESTADOR”, por concepto de cuota de reactivación, la cantidad señalada en el Apartado 10.- de la Carátula por cada mes que haya interrumpido y/o no haya cubierto el precio de “LA TARJETA DE DESCUENTO”, hasta la fecha en que pretenda volver a adquirirla.</p>\r\n\r\n  <h4>TERCERA.- VIGENCIA DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“LA TARJETA DE DESCUENTO” objeto del presente contrato tendrá una vigencia de 30 días contados a partir de que “EL AFILIADO” cubra a “EL PRESTADOR” el precio establecido anteriormente, en el entendido de que la vigencia del presente contrato y de “LA TARJETA DE DESCUENTO” se prorrogarán automáticamente sin necesidad de celebrar documento adicional entre “LAS PARTES” siempre y cuando “EL AFILIADO” cubra, de mes en mes o en la frecuencia contratada, el precio vigente de “LA TARJETA DE DESCUENTO”.</p>\r\n  <p>“EL AFILIADO” tendrá derecho a revocar su consentimiento dentro de los 5 (cinco) días siguientes a la entrega de “LA TARJETA DE DESCUENTO” o la firma del presente contrato, lo que ocurra último, sin responsabilidad alguna, siempre y cuando no haya obtenido beneficio alguno por el uso de “LA TARJETA DE DESCUENTO”.</p>\r\n\r\n  <h4>CUARTA.- BENEFICIOS DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“EL AFILIADO”, de forma exclusiva, personal e intransferible, gozará de forma gratuita de los servicios que se mencionan a continuación:</p>\r\n  <ul><li>Consultas gratuitas ilimitadas de medicina general (no de especialidad) en la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla, únicamente con los doctores afiliados al programa de Pasaporte a tu Salud.</li><li>Consultas de urgencia gratuitas en la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla.</li></ul>\r\n  <p>No así respecto de los servicios que, de manera enunciativa más no limitativa, se describen a continuación:</p>\r\n  <ul><li>Hospitalización dentro de la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla, sujeto a la disponibilidad de cada uno de ellos.</li><li>Consultas de especialidad ilimitadas a costo preferencial, con médicos especialistas pertenecientes al programa PATS.</li><li>Acceso a farmacia PATS con costos reducidos de medicamentos genéricos.</li><li>Imagenología y laboratorios ilimitados con costos preferenciales.</li><li>Acceso a cirugías con cuota de recuperación preferente, con o sin honorarios médicos incluidos según corresponda.</li></ul>\r\n  <p>Dichos servicios generarán, por evento, el pago de una cuota con cargo a “EL AFILIADO”, misma que resultará de aplicar los porcentajes de descuento que se desprenden del ANEXO 4 del presente contrato a los precios publicados al público en general o los precios preferenciales indicados.</p>\r\n  <p>Mientras “LA TARJETA DE DESCUENTO” se encuentre vigente, “EL AFILIADO” gozará de todos los beneficios que la misma le otorga; sin embargo, para el caso de que requiera cirugía o procedimiento quirúrgico en quirófano, deberá haber sufragado por adelantado la adquisición de “LA TARJETA DE DESCUENTO” por un periodo de 12 (doce) meses y encontrarse dentro de dicho periodo de vigencia.</p>\r\n\r\n  <h4>QUINTA.- OBLIGACIONES DE “EL PRESTADOR”.</h4>\r\n  <p>“EL PRESTADOR” se obliga a: (i) otorgar a “EL AFILIADO” el acceso ilimitado a “LA TARJETA DE DESCUENTO” durante la vigencia del contrato; (ii) mantener actualizada y operativa la Red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla; (iii) proporcionar a “EL AFILIADO”, de forma digital, “LA TARJETA DE DESCUENTO” dentro de los 5 (cinco) días hábiles siguientes al primer pago; e (iv) informar por escrito cualquier modificación a la red de hospitales o al tabulador de cuotas con al menos 10 (diez) días de anticipación.</p>\r\n\r\n  <h4>SEXTA.- OBLIGACIONES DE “EL AFILIADO”.</h4>\r\n  <p>“EL AFILIADO” se obliga a: (i) pagar puntualmente el precio de “LA TARJETA DE DESCUENTO”; (ii) utilizarla de forma exclusiva, personal e intransferible; (iii) cubrir directamente a los hospitales y con anterioridad a recibir el servicio médico las cuotas de recuperación según tabulador vigente; (iv) presentar identificación oficial y “LA TARJETA DE DESCUENTO” o código QR cada vez que haga uso de beneficios; y (v) notificar por escrito cualquier cambio de domicilio o datos de contacto en un plazo no mayor a 5 (cinco) días.</p>\r\n\r\n  <h4>SÉPTIMA.- ACCESO A LOS BENEFICIOS Y PROCEDIMIENTO.</h4>\r\n  <p>Para hacer uso de “LA TARJETA DE DESCUENTO”, “EL AFILIADO” deberá agendar sus citas directamente con los doctores pertenecientes a la Red de Hospitales 50 (FIFTY) Doctors, que en ese momento se encuentren adscritos al programa de beneficios, a través de la aplicación oficial, página de internet oficial de PATS o medios oficiales que indique “EL PRESTADOR”.</p>\r\n  <p>“EL AFILIADO” se obliga a pagar directamente al médico especialista perteneciente al programa el costo de la consulta de especialidad de que se trate, en términos de los porcentajes de descuento del ANEXO 4. En caso de no estar facultado para asistir por fuerza mayor, tendrá un plazo de 30 (treinta) días contados a partir de haber generado la cita para solicitar una nueva consulta médica.</p>\r\n\r\n  <h4>OCTAVA.- EXCLUSIONES Y LIMITACIONES.</h4>\r\n  <p>Los beneficios no incluirán: (i) trasplantes de órganos; (ii) tratamientos experimentales; (iii) tratamientos de oncología a excepción de algunas cirugías; (iv) medicamentos extra hospitalarios que no estén recogidos en el catálogo de Farmacia PATS; (v) atención médica con especialistas no adscritos o no publicados en los medios oficiales; y (vi) cualquier servicio no listado expresamente.</p>\r\n\r\n  <h4>NOVENA.- CAUSAS DE TERMINACIÓN.</h4>\r\n  <p>El contrato podrá terminarse por falta de pago, mutuo consentimiento por escrito o incumplimiento de cualquiera de las cláusulas por cualquiera de “LAS PARTES”. En caso de terminación, “EL AFILIADO” no tendrá derecho a exigir la devolución de cantidad alguna.</p>\r\n\r\n  <h4>DÉCIMA.- CANCELACIÓN VOLUNTARIA.</h4>\r\n  <p>“EL AFILIADO” podrá cancelar “LA TARJETA DE DESCUENTO” mediante aviso por escrito con 30 (treinta) días de anticipación. Dicha cancelación surtirá efectos a partir del siguiente periodo mensual y no generará reembolso de pagos ya realizados.</p>\r\n\r\n  <h4>DÉCIMA PRIMERA.- PROTECCIÓN DE DATOS PERSONALES.</h4>\r\n  <p>“LAS PARTES” acuerdan que el tratamiento de datos personales se sujetará a la Ley Federal de Protección de Datos Personales en Posesión de los Particulares. “EL AFILIADO” autoriza expresamente el uso de sus datos para la gestión de “LA TARJETA DE DESCUENTO”. El aviso de privacidad se integra al presente contrato como ANEXO 5.</p>\r\n\r\n  <h4>DÉCIMA SEGUNDA.- RESPONSABILIDAD.</h4>\r\n  <p>“EL AFILIADO” reconoce y acepta que “LA TARJETA DE DESCUENTO” es emitida y administrada directamente por CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE, quien es responsable de la operación de la red de descuentos, afiliación de prestadores médicos y prestación de cualquier servicio relacionado con “LA TARJETA DE DESCUENTO”.</p>\r\n  <p>En consecuencia, “EL PRESTADOR” no tendrá responsabilidad directa ni indirecta por la prestación, calidad, eficacia, resultado, daño, perjuicio, lesión, complicación, secuela, evento adverso o consecuencia derivada de servicios médicos recibidos, incluyendo aquellos ocasionados por negligencia, impericia o mala praxis de profesionales de la salud o prestadores afiliados. Cualquier relación derivada de la prestación de servicios médicos se establece directamente entre “EL AFILIADO” y los prestadores de servicios de salud correspondientes. Esta limitación subsistirá a la terminación del contrato.</p>\r\n\r\n  <h4>DÉCIMA TERCERA.- PREVENCIÓN DE LAVADO DE DINERO Y ORIGEN DE LOS RECURSOS.</h4>\r\n  <p>“LAS PARTES” declaran bajo protesta de decir verdad que los recursos económicos, bienes y derechos que utilicen para cumplir obligaciones derivadas de este contrato tienen y tendrán origen lícito. “EL AFILIADO” manifiesta que el pago inicial y pagos futuros provienen de fuentes lícitas y no de actividades tipificadas como delitos.</p>\r\n  <p>“LAS PARTES” reconocen que la prestación de servicios de comercio puede ser considerada actividad vulnerable, por lo que se obligan a proporcionar información y documentación requerida para integrar expediente de identificación e informar si tienen conocimiento de la existencia de beneficiario controlador.</p>\r\n\r\n  <h4>DÉCIMA CUARTA.- CONFORMACIÓN DEL EXPEDIENTE DE IDENTIFICACIÓN.</h4>\r\n  <p>“EL PRESTADOR” queda obligado a conformar y mantener un expediente de identificación de “EL AFILIADO”. Para tales efectos, “EL AFILIADO” se obliga a entregar los documentos aplicables: identificación oficial vigente o pasaporte, acta de nacimiento cuando aplique, comprobante de domicilio, constancia de situación fiscal cuando aplique, CURP, y declaración de dueño beneficiario.</p>\r\n  <p>Cuando exista persona responsable, la documentación de identificación y representación deberá integrarse al expediente; la CIF/constancia fiscal corresponde al tutor cuando aplique. “EL PRESTADOR” conservará dicho expediente por un periodo mínimo de 5 (cinco) años contados a partir de que termine la vigencia del contrato o termine por cualquiera de sus causales, garantizando la confidencialidad de los datos personales.</p>\r\n\r\n  <h4>DÉCIMA QUINTA.- CAUSAL ESPECÍFICA DE RESCISIÓN.</h4>\r\n  <p>Será motivo de rescisión inmediata sin necesidad de declaración judicial y sin responsabilidad para la parte afectada cuando cualquiera de “LAS PARTES” se niegue a proporcionar información requerida para cumplimiento de la Ley Federal para la Prevención e Identificación de Operaciones con Recursos de Procedencia Ilícita, proporcione información falsa o aparezca en listas de personas bloqueadas emitidas por autoridad competente.</p>\r\n\r\n  <h4>DÉCIMA SEXTA.- LEGISLACIÓN APLICABLE Y JURISDICCIÓN.</h4>\r\n  <p>“LAS PARTES” establecen que la Procuraduría Federal del Consumidor es competente en vía administrativa para resolver cualquier controversia sobre interpretación o cumplimiento. Sin perjuicio de lo anterior, se someten expresamente a la jurisdicción de los tribunales competentes del fuero común del Distrito Judicial de Puebla, Estado de Puebla, renunciando de manera expresa e irrevocable a cualquier otro fuero o jurisdicción que pudiera corresponderles.</p>\r\n\r\n  <p>Enteradas “LAS PARTES” del contenido y alcance del presente contrato, y entendidas de los derechos y obligaciones que contraen, firman el presente instrumento, incluyendo sus anexos, manifestando que no medió error, dolo, mala fe, violencia o lesión, ni vicio del consentimiento alguno, en la Ciudad de Puebla, Estado de Puebla, reconociendo que la fecha de firma es 13 de mayo de 2026.</p>\r\n\r\n  <div class=\"sign-grid\">\r\n    <div class=\"sign-box\"><div class=\"line\"></div><strong>“EL PRESTADOR”</strong><br>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE<br>Representada por PEDRO AZCÁRRAGA RAMOS</div>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>“MAMÁ, PAPÁ O TUTOR / FIRMANTE”</strong><br>Papa Papa Papa</div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 1<br>Identificación oficial de “EL AFILIADO”</h2><p>Se integra al expediente la identificación oficial cargada por el usuario en el formulario. Para mexicanos, corresponde a identificación oficial/INE cuando aplique. Para extranjeros/no mexicanos, corresponde a identificación oficial o pasaporte vigente; al menos el frente es obligatorio y el reverso será opcional cuando el documento no lo tenga.</p><p><strong>Tipo:</strong> . <strong>Emitida por / país emisor:</strong> . <strong>Número:</strong> Pendiente.</p></div>\r\n  <div class=\"annex\"><h2>ANEXO 2<br>COMPROBANTE DE DOMICILIO DE “EL AFILIADO”</h2><p>Se integra al expediente el comprobante de domicilio cargado por el usuario. Domicilio declarado: jjj 115, Col. zapopan, C.P. 45255, cholula, Jalisco, México.</p></div>\r\n  <div class=\"annex\"><h2>ANEXO 3<br>CONSTANCIA DE SITUACIÓN FISCAL DE “EL AFILIADO”</h2><p>Constancia de Situación Fiscal de “EL AFILIADO”, si aplica. En caso de pacientes representados, la constancia fiscal o CIF corresponde a la persona responsable cuando sea aplicable, no al menor. Para afiliados extranjeros/no mexicanos, no será obligatoria salvo que declaren RFC mexicano o residencia fiscal aplicable.</p></div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 4<br>CUOTAS DE RECUPERACIÓN Y/O PRECIOS BASE A CUBRIR A “EL PRESTADOR”</h2>\r\n    <p>En el presente anexo se establecen los porcentajes de descuento a obtener como titular de “LA TARJETA DE DESCUENTO”, por lo que la cantidad a cubrir por “EL AFILIADO” directamente al hospital de la cadena 50 (FIFTY) Doctors o al doctor que preste el servicio se obtendrá de aplicar el porcentaje de descuento correspondiente al precio publicado por los medios oficiales o al precio vigente en el establecimiento.</p>\r\n    <table><tr><th>Servicios / procedimientos</th><th>Descuentos</th></tr><tr><td>Consulta de urgencias</td><td>100%</td></tr><tr><td>Consulta de medicina general</td><td>100%</td></tr><tr><td>Habitación hospitalaria</td><td>90%</td></tr><tr><td>Uso de áreas de urgencias médicas</td><td>80%</td></tr><tr><td>Utilización de cubículos de terapia intensiva (UCIA-UCIN-UCIP)</td><td>75%</td></tr><tr><td>CEYE</td><td>75%</td></tr><tr><td>Uso quirófano</td><td>75%</td></tr><tr><td>Servicio de cuneros</td><td>75%</td></tr><tr><td>Materiales & medicamentos del cuadro básico, genéricos intercambiables</td><td>70%</td></tr><tr><td>Hemodinamia</td><td>70%</td></tr><tr><td>Imagenología</td><td>70%</td></tr><tr><td>Endoprótesis</td><td>70%</td></tr><tr><td>Osteosíntesis</td><td>70%</td></tr><tr><td>Prótesis</td><td>70%</td></tr><tr><td>Órtesis</td><td>70%</td></tr><tr><td>Laboratorio clínico</td><td>60%</td></tr></table>\r\n    <p class=\"small\">Los descuentos aplican con los proveedores suscritos al convenio de Pasaporte a tu Salud.</p>\r\n    <table><tr><th>Servicios / procedimientos</th><th>Precios base</th></tr><tr><td>Consulta de especialidades médicas</td><td>$390.00</td></tr><tr><td>Colposcopía</td><td>$400.00</td></tr><tr><td>Retiro de puntos de sutura</td><td>$80.00</td></tr><tr><td>Aplicación de medicamento intramuscular</td><td>$60.00</td></tr><tr><td>Retiro de DIU</td><td>$500.00</td></tr><tr><td>Colocación de DIU</td><td>$700.00</td></tr><tr><td>Extracción de cuerpo extraño (oído y nariz)</td><td>$300.00</td></tr><tr><td>Lavado ótico</td><td>$250.00</td></tr><tr><td>Curación de sitio quirúrgico</td><td>$250.00</td></tr><tr><td>Retiro de yeso</td><td>$250.00</td></tr><tr><td>Visita día de hospitalización</td><td>$650.00</td></tr><tr><td>Visita de urgencias</td><td>$750.00</td></tr><tr><td>Día de terapia intensiva</td><td>$850.00</td></tr></table>\r\n    <p class=\"small\">Todos los precios incluyen IVA. La factura de servicios hospitalarios será emitida con el desglose correspondiente y el ahorro otorgado por ser titular de “LA TARJETA DE DESCUENTO”.</p>\r\n    <p>Exclusiones y limitaciones: se aplicarán descuentos y precios especiales para el acompañante de “EL AFILIADO” en la misma habitación únicamente para la primera noche de hospitalización. Los precios y porcentajes de descuento darán derecho a la utilización de materiales y medicamentos del cuadro básico, genéricos intercambiables; cualquier otro tipo de medicación será cubierto directamente por “EL AFILIADO”. Los costos de procedimientos quirúrgicos incluyen honorarios médicos cuando así se indique. “EL AFILIADO” podrá atenderse con el médico tratante que elija, debiendo cubrir honorarios directamente a dicho médico, conservando el derecho a beneficios dentro de la red aplicable.</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Firma de aceptación de “EL AFILIADO”</strong><br>Papa Papa Papa</div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 5<br>AVISO DE PRIVACIDAD</h2>\r\n    <p>En cumplimiento de las disposiciones establecidas en la Ley Federal de Protección de Datos Personales en Posesión de Particulares, su Reglamento y los lineamientos aplicables, “CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE” (en lo sucesivo “EL PRESTADOR”), con domicilio en CALLE PASEO SINFONÍA NÚMERO EXTERIOR 1, LOCAL 2-14, LOMAS DE ANGELÓPOLIS II, SAN ANDRÉS CHOLULA, ESTADO DE PUEBLA, CÓDIGO POSTAL 72830, da a conocer el Aviso de Privacidad al tenor del cual manejará por medio de su representación y/o empleados los datos personales y/o documentación proporcionada por el afiliado o usuario de “LA TARJETA DE DESCUENTO”.</p>\r\n    <p>Se tendrá por aceptado expresamente el presente Aviso de Privacidad una vez proporcionados los datos personales y firmada digitalmente la aceptación del contrato, motivo por el cual “EL PRESTADOR” estará facultado para manejar la información conforme a la legislación aplicable.</p>\r\n    <h4>Modificación del aviso de privacidad</h4><p>Este aviso podrá ser modificado o adecuado a las necesidades de “EL PRESTADOR”. Las modificaciones o actualizaciones serán incorporadas al presente aviso y estarán disponibles en la página de internet, domicilio de “EL PRESTADOR” o serán enviadas al último correo electrónico proporcionado.</p>\r\n    <h4>Finalidad de la información</h4><p>La información será utilizada para: elaborar y mantener actualizada la base de usuarios; identificar afiliados; proporcionar la tarjeta digital; otorgar acceso al programa de beneficios; informar modificaciones a la red o tabulador; realizar análisis estadísticos internos y brindar un óptimo servicio médico.</p>\r\n    <h4>Tipo de datos necesarios</h4><p>Se solicitarán datos de identificación, contacto, legales, contractuales y fiscales cuando aplique, incluyendo nombre completo, lugar y fecha de nacimiento, firma, identificación oficial, nacionalidad, CURP y RFC cuando sean aplicables, domicilio, teléfono y correo electrónico.</p>\r\n    <h4>Transferencias de la información</h4><p>El usuario autoriza proporcionar información sin consentimiento adicional en los casos previstos por ley, resolución de autoridad competente, tratados aplicables, salvaguarda de interés público, procuración o administración de justicia, reconocimiento o defensa de derechos en procesos judiciales, y a socios comerciales, técnicos o estratégicos que asuman obligaciones de confidencialidad y seguridad equivalentes.</p>\r\n    <h4>Limitación del uso o divulgación de datos y derechos ARCO</h4><p>El usuario podrá limitar el uso o divulgación de sus datos personales y ejercer derechos de acceso, rectificación, cancelación u oposición mediante solicitud escrita dirigida a “EL PRESTADOR” en su domicilio o al correo silvia@pasaporteatusalud.com, acompañando documento que acredite su identidad.</p>\r\n    <h4>Revocación de consentimiento</h4><p>El usuario podrá revocar su consentimiento siguiendo el mismo procedimiento, considerando que para ciertos fines la revocación puede implicar la cancelación de “LA TARJETA DE DESCUENTO” y la imposibilidad de acceder al programa.</p>\r\n    <p><strong>Nombre:</strong> Papa Papa Papa<br><strong>Fecha:</strong> 13 de mayo de 2026</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Firma</strong></div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 6<br>DECLARACIÓN DE DUEÑO BENEFICIARIO</h2>\r\n    <p>DE CONFORMIDAD CON LO DISPUESTO EN LOS ARTÍCULOS 18 FRACCIÓN I Y III DE LA LEY FEDERAL PARA PREVENCIÓN E IDENTIFICACIÓN DE OPERACIONES CON RECURSOS DE PROCEDENCIA ILÍCITA, EL ARTÍCULO 15 DE SU REGLAMENTO Y EL ARTÍCULO 13 DE LAS REGLAS DE CARÁCTER GENERAL, MANIFIESTO BAJO PROTESTA DE DECIR VERDAD:</p>\r\n    <h4>Datos de identificación del cliente</h4>\r\n    <table><tr><th>Campo</th><th>Respuesta</th></tr><tr><td>Apellido paterno, materno y nombre(s)</td><td>Mateo Fuentes Vazquez</td></tr><tr><td>Fecha de nacimiento</td><td>2015-05-05</td></tr><tr><td>País de nacimiento</td><td>México</td></tr><tr><td>Nacionalidad</td><td>mexicana</td></tr><tr><td>Actividad, ocupación o profesión</td><td>Pendiente</td></tr><tr><td>Estado civil</td><td>Pendiente</td></tr><tr><td>Domicilio particular</td><td>jjj 115, Col. zapopan, C.P. 45255, cholula, Jalisco, México</td></tr><tr><td>Teléfonos</td><td>2222222222</td></tr><tr><td>Correo electrónico</td><td>roel.fuentes@gmail.com</td></tr><tr><td>CURP</td><td>CURP</td></tr><tr><td>RFC</td><td>Pendiente / no proporcionado</td></tr><tr><td>Tipo de identificación</td><td></td></tr><tr><td>Emitida por / país emisor</td><td></td></tr><tr><td>Número de identificación</td><td></td></tr></table>\r\n    <h4>Datos de identificación de la operación</h4>\r\n    <table><tr><th>Campo</th><th>Respuesta</th></tr><tr><td>Tipo de operación</td><td>Adquisición de tarjeta de descuento PATS</td></tr><tr><td>Monto de operación</td><td>$800.00 M.N.</td></tr><tr><td>Fecha de operación</td><td>13 de mayo de 2026</td></tr><tr><td>Forma de pago</td><td>Pasarela / medio autorizado por “EL PRESTADOR”</td></tr><tr><td>Moneda</td><td>MXN</td></tr></table>\r\n    <h4>Información de la existencia del dueño beneficiario o beneficiario controlador</h4>\r\n    <p>Declaro que soy el beneficiario directo de la operación y no existe ningún otro dueño beneficiario o beneficiario controlador: <strong>SI</strong>.</p>\r\n    <h4>Aviso de privacidad</h4><p>Los datos personales serán protegidos y tratados conforme al Aviso de Privacidad contenido en el cuerpo del presente contrato y la legislación aplicable.</p>\r\n    <p>H. Puebla de Zaragoza al 13 del mes de mayo del año 2026.</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Nombre y firma</strong><br>Papa Papa Papa</div>\r\n  </div>\r\n\r\n    <div class=\"annex\"><h2>ANEXO 7<br>DOCUMENTACIÓN Y ACEPTACIÓN DE LA PERSONA RESPONSABLE</h2><p><strong>Paciente:</strong> Mateo Fuentes Vazquez. <strong>CURP/ID:</strong> CURP. <strong>Fecha de nacimiento:</strong> 2015-05-05.</p><p><strong>Persona responsable firmante:</strong> Papa Papa Papa. <strong>CURP:</strong> ADFAFAFADF. <strong>RFC/CIF:</strong> DGDAGADFGAD. <strong>Identificación:</strong> INE GFADGDAGFADFG.</p><p>La persona responsable acepta administrar usuario, contraseña, consentimientos, pagos y obligaciones contractuales del paciente, y reconoce que los beneficios corresponden al menor como paciente/afiliado real.</p></div>\r\n  \r\n  </div>\r\n', 'data:image/png;base64,', 'Papa Papa Papa', '7339fbb72d525b3f02851a011ac4acb75ddd9e65238f85fa3e69bc63e54d6812', '2026-05-13 00:55:26', '189.190.196.8', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:150.0) Gecko/20100101 Firefox/150.0', '', 'firmado', '2026-05-13 00:55:26', '2026-05-13 00:55:26');
INSERT INTO `pats_contratos_firmados` (`id_contrato_firmado`, `id_orden`, `id_pasaporte`, `id_distribuidor`, `id_franquicia`, `token_publico`, `contrato_clave`, `contrato_version`, `html_contrato_renderizado`, `firma_afiliado_base64`, `nombre_firmante`, `hash_contrato`, `fecha_firma`, `ip_firma`, `user_agent_firma`, `pdf_path`, `estatus`, `created_at`, `updated_at`) VALUES
(9, 1, 1, 0, 0, '', 'contrato_pats_base', '1.0', '<style>\r\n  .pats-contract{font-family:Arial,Helvetica,sans-serif;color:#172033;font-size:12px;line-height:1.52;background:#fff;padding:4px}\r\n  .pats-contract h1,.pats-contract h2,.pats-contract h3,.pats-contract h4{text-align:center;margin:12px 0 8px;color:#0d1b3e}\r\n  .pats-contract h1{font-size:16px;text-transform:uppercase;letter-spacing:.05em}\r\n  .pats-contract h2{font-size:15px;text-transform:uppercase;letter-spacing:.04em}\r\n  .pats-contract h3{font-size:13px;text-transform:uppercase;letter-spacing:.08em}\r\n  .pats-contract h4{font-size:12px;text-align:left;text-transform:uppercase;margin-top:12px}\r\n  .pats-contract p{margin:6px 0;text-align:justify}\r\n  .pats-contract ul{margin:6px 0 8px 18px;padding:0}.pats-contract li{margin:4px 0;text-align:justify}\r\n  .pats-contract table{width:100%;border-collapse:collapse;margin:8px 0 12px}.pats-contract th,.pats-contract td{border:1px solid #cbd5e1;padding:6px;vertical-align:top}.pats-contract th{background:#eef4ff;color:#0d1b3e;text-align:left}\r\n  .pats-contract .center{text-align:center}.pats-contract .muted{color:#64748b}.pats-contract .small{font-size:10px}.pats-contract .badge{display:inline-block;padding:3px 8px;border-radius:999px;background:#eef4ff;color:#1d4ed8;font-weight:700;margin:2px 4px 2px 0}\r\n  .pats-contract .sign-grid{display:grid;grid-template-columns:1fr 1fr;gap:22px;margin-top:28px}.pats-contract .sign-box{text-align:center;min-height:95px}.pats-contract .line{border-top:1px solid #0f172a;margin:48px 8px 6px}.pats-contract .signature-img{max-width:220px;max-height:82px;display:block;margin:0 auto 4px}\r\n  .pats-contract .annex{page-break-before:auto;border-top:2px solid #0d1b3e;margin-top:18px;padding-top:12px}.pats-contract .page-break{page-break-before:always;border-top:1px dashed #cbd5e1;margin-top:18px;padding-top:12px}\r\n</style>\r\n<div class=\"pats-contract\">\r\n  <h1>Carátula del contrato de adquisición de tarjeta de descuento</h1>\r\n  <p>CARÁTULA DEL CONTRATO DE ADQUISICIÓN DE TARJETA DE DESCUENTO (EN LO SUCESIVO “LA CARÁTULA”), QUE CELEBRAN POR UNA PARTE LA SOCIEDAD SEÑALADA EN EL APARTADO 1.- DE LA CARÁTULA, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL PRESTADOR”, REPRESENTADA EN ESTE ACTO POR LA PERSONA FÍSICA QUE SE INDICA EN EL APARTADO 2.- DE LA CARÁTULA; Y POR LA OTRA PARTE, LA PERSONA FÍSICA SEÑALADA EN EL APARTADO 5.- DE LA CARÁTULA, POR SU PROPIO DERECHO, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL AFILIADO”; Y CUANDO LOS ANTES NOMBRADOS ACTÚEN DE MANERA CONJUNTA, SE LES DENOMINARÁ COMO “LAS PARTES”; QUIENES SE SUJETAN AL TENOR DE LA CARÁTULA, DECLARACIONES Y CLÁUSULAS SIGUIENTES:</p>\r\n    \r\n  <h2>C A R Á T U L A</h2>\r\n  <table>\r\n    <tr><th style=\"width:8%\">Apartado</th><th style=\"width:42%\">Definición</th><th>Respuesta</th></tr>\r\n    <tr><td>1.-</td><td>Nombre de “EL PRESTADOR”</td><td>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE</td></tr>\r\n    <tr><td>2.-</td><td>Nombre del Representante Legal de “EL PRESTADOR”</td><td>PEDRO AZCÁRRAGA RAMOS</td></tr>\r\n    <tr><td>3.-</td><td>Domicilio de “EL PRESTADOR”</td><td>CALLE PASEO SINFONÍA NÚMERO EXTERIOR 1, LOCAL 2-14, LOMAS DE ANGELÓPOLIS II, SAN ANDRÉS CHOLULA, ESTADO DE PUEBLA, CÓDIGO POSTAL 72830</td></tr>\r\n    <tr><td>4.-</td><td>Clave del Registro Federal de Contribuyentes de “EL PRESTADOR”</td><td>COH2202144H5</td></tr>\r\n    <tr><td>5.-</td><td>Nombre de “EL AFILIADO”</td><td>Juan Manuel LOpez LOpez</td></tr>\r\n    <tr><td>6.-</td><td>Domicilio de “EL AFILIADO”</td><td>casa 12, Col. casa, C.P. 14523, zapopan, Jalisco, México</td></tr>\r\n    <tr><td>7.-</td><td>Clave del Registro Federal de Contribuyentes de “EL AFILIADO”</td><td>Pendiente / no proporcionado</td></tr>\r\n    <tr><td>8.-</td><td>Costo mensual de “LA TARJETA DE DESCUENTO”</td><td>$800.00 M.N.</td></tr>\r\n    <tr><td>9.-</td><td>Cuenta bancaria de “EL PRESTADOR” para pagos</td><td>Cuenta: 01600866709<br>CLABE: 042650016008667096<br>Institución Bancaria: Banca Mifel, S.A., Institución de Banca Múltiple, Grupo Financiero Mifel</td></tr>\r\n    <tr><td>10.-</td><td>Cuota de Reactivación de “LA TARJETA DE DESCUENTO”</td><td>$100.00 M.N. por cada mes que se haya interrumpido el pago.</td></tr>\r\n    <tr><td>11.-</td><td>Datos de la Tarjeta de Crédito de “EL AFILIADO”</td><td>Número de tarjeta: pendiente de confirmar por pasarela/token de pago.<br>Institución bancaria: pendiente de confirmar por pasarela. <br><span class=\"small\">No se almacena número completo de tarjeta en este formulario.</span></td></tr>\r\n    <tr><td>12.-</td><td>Anexos</td><td>ANEXO 1. Identificación oficial de “EL AFILIADO”<br>ANEXO 2. Comprobante de domicilio de “EL AFILIADO”<br>ANEXO 3. Constancia de Situación Fiscal de “EL AFILIADO”, si aplica<br>ANEXO 4. Cuotas de recuperación y/o precios base a cubrir a “EL PRESTADOR”<br>ANEXO 5. Aviso de privacidad<br>ANEXO 6. Declaración de dueño beneficiario</td></tr>\r\n    <tr><td>13.-</td><td>Fecha de Firma del Contrato</td><td>13 de mayo de 2026</td></tr>\r\n  </table>\r\n\r\n  <div class=\"sign-grid\">\r\n    <div class=\"sign-box\"><div class=\"line\"></div><strong>“EL PRESTADOR”</strong><br>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE<br>Representada por PEDRO AZCÁRRAGA RAMOS</div>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>“EL AFILIADO”</strong><br>Juan Manuel LOpez LOpez<br><span class=\"small\">La persona física señalada en el Apartado 5.- de la Carátula</span></div>\r\n  </div>\r\n\r\n  <div class=\"page-break\"></div>\r\n  <h1>Contrato de adquisición de tarjeta de descuento</h1>\r\n  <p>CONTRATO DE ADQUISICIÓN DE TARJETA DE DESCUENTO, QUE CELEBRAN POR UNA PARTE LA SOCIEDAD SEÑALADA EN EL APARTADO 1.- DE LA CARÁTULA, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL PRESTADOR”, REPRESENTADA EN ESTE ACTO POR LA PERSONA FÍSICA QUE SE INDICA EN EL APARTADO 2.- DE LA CARÁTULA; Y POR LA OTRA PARTE, LA PERSONA FÍSICA SEÑALADA EN EL APARTADO 5.- DE LA CARÁTULA, POR SU PROPIO DERECHO, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL AFILIADO”; Y CUANDO LOS ANTES NOMBRADOS ACTÚEN DE MANERA CONJUNTA, SE LES DENOMINARÁ COMO “LAS PARTES”; QUIENES SE SUJETAN AL TENOR DE LAS DECLARACIONES Y CLÁUSULAS SIGUIENTES:</p>\r\n\r\n  <h2>D E C L A R A C I O N E S</h2>\r\n  <h4>I.- Declara “EL PRESTADOR” por conducto de su representación:</h4>\r\n  <p>A. Que, su representada es una sociedad mercantil constituida conforme a las leyes de los Estados Unidos Mexicanos, según consta en la escritura pública número 39,861, del volumen 830 de fecha catorce de febrero de dos mil veintidós, otorgada ante la fe del Licenciado Ernesto Joaquín Briones Amador, Notario Público Titular de la Notaría Pública número 46 de las del Distrito Judicial de Puebla, Estado de Puebla, cuyo primer testimonio se encuentra inscrito ante las oficinas del Registro Público de Comercio del Distrito Judicial de Puebla, Estado de Puebla, bajo el Folio Mercantil Electrónico: N-2022022991, por virtud del cual se llevó a cabo la Constitución de la persona moral denominada CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE.</p>\r\n  <p>B. Que, la persona física que la representa en este acto, señalada en el Apartado 2.- de la Carátula, cuenta con todas y cada una de las facultades necesarias para la celebración del presente contrato, las cuales se desprenden del instrumento descrito en el punto declarativo inmediato anterior, mismas que manifiesta bajo protesta de decir verdad que no le han sido suspendidas, revocadas o limitadas en forma alguna.</p>\r\n  <p>C. Que, su representada tiene como domicilio fiscal el señalado en el Apartado 3.- de la Carátula del presente contrato, mismo que designa como domicilio convencional para cualquier cuestión relacionada con la celebración del presente contrato.</p>\r\n  <p>D. Que, su representada se encuentra inscrita en el Registro Federal de Contribuyentes bajo la clave señalada en el Apartado 4.- de la Carátula.</p>\r\n  <p>E. Que, ha desarrollado y es su deseo comparecer a la celebración del presente instrumento con la finalidad de enajenar en favor de “EL AFILIADO”, una Tarjeta de Descuento que da acceso a “UN PROGRAMA DE BENEFICIOS QUE OTORGA DESCUENTOS A LOS COSTOS Y PERMITE RECIBIR SERVICIOS MÉDICOS PRIVADOS DE ALTA CALIDAD DE FORMA ACCESIBLE, CLARA Y SIN RESTRICCIONES DENTRO DE LA RED DE HOSPITALES 50 (FIFTY) DOCTORS CON SEDE EN EL ESTADO DE PUEBLA”, en lo sucesivo “LA TARJETA DE DESCUENTO”, en los términos y condiciones que se establecerán más adelante.</p>\r\n  <p>F. Que, su representada no es una Aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas sino una empresa dedicada, entre otros, a la operación y administración de establecimientos destinados a la atención y asistencia de enfermos, por lo que la enajenación de “LA TARJETA DE DESCUENTO” únicamente constituye un acto de comercio que brindará a “EL AFILIADO” acceso a un programa de beneficios como ha quedado descrito anteriormente.</p>\r\n\r\n  <h4>II.- Declara “EL AFILIADO”, por su propio derecho:</h4>\r\n      <p>A. Que, su nombre se señala en el Apartado 5.- de la Carátula, es una persona física de nacionalidad mexicana, en pleno ejercicio de sus derechos, legal y jurídicamente capaz para celebrar el presente Contrato, quien se identifica con credencial para votar vigente expedida por el Instituto Nacional Electoral, tipo INE, número DAAVFDSDDD, que en copia simple o archivo digital se agrega al cuerpo del presente contrato como ANEXO 1.</p>\r\n    <p>B. Que, tiene como domicilio particular el señalado en el Apartado 6.- de la Carátula, mismo que designa como domicilio convencional para cualquier cuestión relacionada con la celebración del presente contrato, tal y como lo acredita con el comprobante de domicilio que en copia simple o archivo digital se agrega al cuerpo del presente contrato como ANEXO 2.</p>\r\n  <p>C. Que, su CURP es 14521452144DDDDDDD y su RFC/identificación fiscal es Pendiente / no proporcionado; asimismo manifiesta que cuenta con capacidad económica para obligarse en términos del presente contrato y que los recursos con los que cubrirá sus obligaciones provendrán de fuentes lícitas. En caso de nacionalidad extranjera/no mexicana, se tendrán por no aplicables CURP, INE y constancia fiscal mexicana salvo manifestación expresa de residencia fiscal o RFC mexicano.</p>\r\n  <p>D. Que, es su deseo comparecer a la celebración del presente instrumento con la finalidad de adquirir “LA TARJETA DE DESCUENTO” de acuerdo con los términos y condiciones que se establecen a continuación.</p>\r\n  <p>E. Que, previo a la celebración del presente contrato fue informado y manifiesta expresamente que reconoce que “EL PRESTADOR” no es una Aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas y que las actividades comerciales objeto del presente contrato no consisten en la contratación de un seguro, de la índole que fuere, sino que únicamente implica la adquisición de una tarjeta de descuento que da acceso a un programa de beneficios que otorga descuentos a los costos y permite recibir servicios médicos privados de alta calidad de forma accesible, clara y sin restricciones dentro de la red de hospitales 50 (FIFTY) Doctors con sede en el Estado de Puebla.</p>\r\n  <p>F. Que, reconoce que “EL PRESTADOR” se dedica a la operación de centros hospitalarios y que la emisión de “LA TARJETA DE DESCUENTO” únicamente corresponde a la intención de este último de crear un programa de descuentos para el acceso a los servicios prestados por la Red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla.</p>\r\n\r\n  <h4>III.- Declaran conjuntamente “LAS PARTES”:</h4>\r\n  <p>1. Que, se reconocen recíprocamente la personalidad con la que comparecen a la celebración del presente acuerdo de voluntades.</p>\r\n  <p>2. Que, el presente contrato es el instrumento que las vincula en sus derechos y obligaciones.</p>\r\n  <p>3. Que, es su deseo celebrar el presente contrato y han negociado libremente los términos y condiciones del mismo con pleno conocimiento de sus alcances e implicaciones jurídicas, por lo que en su celebración no existe dolo, error, mala fe, lesión o cualquier otro vicio del consentimiento que pudiese afectarlo de inexistencia o nulidad.</p>\r\n\r\n  <h2>C L Á U S U L A S</h2>\r\n  <h4>PRIMERA.- OBJETO.</h4>\r\n  <p>El objeto del presente Contrato es que “EL AFILIADO” adquiera de “EL PRESTADOR”, a título oneroso y temporal, el derecho de uso ilimitado y sin restricción alguna de “LA TARJETA DE DESCUENTO” emitida por CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE, la cual consiste en que “EL AFILIADO” aproveche y acceda a “UN PROGRAMA DE BENEFICIOS QUE OTORGA DESCUENTOS A LOS COSTOS Y PERMITE RECIBIR SERVICIOS MÉDICOS PRIVADOS DE ALTA CALIDAD DE FORMA ACCESIBLE, CLARA Y SIN RESTRICCIONES DENTRO DE LA RED DE HOSPITALES 50 (FIFTY) DOCTORS CON SEDE EN EL ESTADO DE PUEBLA”.</p>\r\n  <p>Estableciendo que, la comercialización de “LA TARJETA DE DESCUENTO” por parte de “EL PRESTADOR” en ningún momento constituirá la venta, promoción o por cualquier medio la contratación de una póliza de seguro, bajo el entendido de que “EL PRESTADOR” no es una aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas (CNSF); sino que comercializa “LA TARJETA DE DESCUENTO” en favor de terceros con la finalidad de otorgar descuentos a los precios respecto de los servicios médicos que presta en el territorio nacional.</p>\r\n\r\n  <h4>SEGUNDA.- PRECIO DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“LAS PARTES” establecen de común acuerdo que “LA TARJETA DE DESCUENTO” tendrá como costo mensual la cantidad señalada en el Apartado 8.- de la Carátula del presente contrato; cantidad que ya incluye IVA, y la cual deberá ser cubierta por “EL AFILIADO” en favor de “EL PRESTADOR” dentro de los primeros 5 (cinco) días de cada mes, sin necesidad de gestiones o avisos de cobro, ya sea mediante:</p>\r\n  <p>(i) Transferencia electrónica de fondos a la cuenta bancaria señalada en el Apartado 9.- de la Carátula del presente contrato y de la cual es titular “EL PRESTADOR”.</p>\r\n  <p>(ii) Cheque que se recibirá salvo buen cobro en el Domicilio de “EL PRESTADOR” señalado en el Apartado 3.- de la Carátula del presente contrato, y que en caso de no ser pagado por falta de fondos suficientes o por otras causas imputables a “EL AFILIADO”, éste último está de acuerdo en que deberá cubrir a “EL PRESTADOR” el 20% (veinte por ciento) del monto del cheque por concepto de indemnización por daños y perjuicios en términos del artículo 193 de la Ley General de Títulos y Operaciones de Crédito, independientemente de cualquier otro cargo que se pudiera generar.</p>\r\n  <p>(iii) Cargos mensuales automáticos recurrentes a la tarjeta de crédito de “EL AFILIADO” según los datos señalados en el Apartado 11.- de la Carátula del presente contrato, quien manifiesta bajo protesta de decir verdad que autoriza a “EL PRESTADOR” a realizar los cargos mensuales correspondientes por el costo mensual de “LA TARJETA DE DESCUENTO” en dicha tarjeta o en la tarjeta que por renovación, reposición, robo o extravío le haya asignado el banco emisor. La autorización estará vigente mientras “EL AFILIADO” no haya notificado a “EL PRESTADOR” por escrito y con acuse de recibo su deseo de cancelar su afiliación o no renovarla, o en su defecto, realizar su baja respectiva en el sitio web o aplicación de “EL PRESTADOR”.</p>\r\n  <p>Esta autorización no exime a “EL AFILIADO” del pago mensual por el uso de “LA TARJETA DE DESCUENTO” y demás obligaciones contractuales, por lo que, en caso de que el cobro no sea autorizado por el banco emisor o por cualquier razón no pueda realizarse, “EL AFILIADO” deberá notificar tal situación a “EL PRESTADOR” a la dirección de correo electrónico silvia@pasaporteatusalud.com, a efecto de solicitar una forma de pago diversa, quedando obligado a cubrir de inmediato el pago correspondiente.</p>\r\n  <p>(iv) Cualquier otro medio de pago aceptado por “EL PRESTADOR”, mismo que se dará a conocer a través de sus medios oficiales de comunicación.</p>\r\n  <p>“EL PRESTADOR” podrá variar unilateralmente el costo mensual de “LA TARJETA DE DESCUENTO”, previo aviso a “EL AFILIADO” con 30 (treinta) días de anticipación a través de sus medios oficiales de comunicación.</p>\r\n  <p>Para el caso de que “EL AFILIADO” adquiera y cubra el precio de “LA TARJETA DE DESCUENTO” y posteriormente deje de pagar una mensualidad, deberá cubrir a “EL PRESTADOR”, por concepto de cuota de reactivación, la cantidad señalada en el Apartado 10.- de la Carátula por cada mes que haya interrumpido y/o no haya cubierto el precio de “LA TARJETA DE DESCUENTO”, hasta la fecha en que pretenda volver a adquirirla.</p>\r\n\r\n  <h4>TERCERA.- VIGENCIA DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“LA TARJETA DE DESCUENTO” objeto del presente contrato tendrá una vigencia de 30 días contados a partir de que “EL AFILIADO” cubra a “EL PRESTADOR” el precio establecido anteriormente, en el entendido de que la vigencia del presente contrato y de “LA TARJETA DE DESCUENTO” se prorrogarán automáticamente sin necesidad de celebrar documento adicional entre “LAS PARTES” siempre y cuando “EL AFILIADO” cubra, de mes en mes o en la frecuencia contratada, el precio vigente de “LA TARJETA DE DESCUENTO”.</p>\r\n  <p>“EL AFILIADO” tendrá derecho a revocar su consentimiento dentro de los 5 (cinco) días siguientes a la entrega de “LA TARJETA DE DESCUENTO” o la firma del presente contrato, lo que ocurra último, sin responsabilidad alguna, siempre y cuando no haya obtenido beneficio alguno por el uso de “LA TARJETA DE DESCUENTO”.</p>\r\n\r\n  <h4>CUARTA.- BENEFICIOS DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“EL AFILIADO”, de forma exclusiva, personal e intransferible, gozará de forma gratuita de los servicios que se mencionan a continuación:</p>\r\n  <ul><li>Consultas gratuitas ilimitadas de medicina general (no de especialidad) en la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla, únicamente con los doctores afiliados al programa de Pasaporte a tu Salud.</li><li>Consultas de urgencia gratuitas en la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla.</li></ul>\r\n  <p>No así respecto de los servicios que, de manera enunciativa más no limitativa, se describen a continuación:</p>\r\n  <ul><li>Hospitalización dentro de la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla, sujeto a la disponibilidad de cada uno de ellos.</li><li>Consultas de especialidad ilimitadas a costo preferencial, con médicos especialistas pertenecientes al programa PATS.</li><li>Acceso a farmacia PATS con costos reducidos de medicamentos genéricos.</li><li>Imagenología y laboratorios ilimitados con costos preferenciales.</li><li>Acceso a cirugías con cuota de recuperación preferente, con o sin honorarios médicos incluidos según corresponda.</li></ul>\r\n  <p>Dichos servicios generarán, por evento, el pago de una cuota con cargo a “EL AFILIADO”, misma que resultará de aplicar los porcentajes de descuento que se desprenden del ANEXO 4 del presente contrato a los precios publicados al público en general o los precios preferenciales indicados.</p>\r\n  <p>Mientras “LA TARJETA DE DESCUENTO” se encuentre vigente, “EL AFILIADO” gozará de todos los beneficios que la misma le otorga; sin embargo, para el caso de que requiera cirugía o procedimiento quirúrgico en quirófano, deberá haber sufragado por adelantado la adquisición de “LA TARJETA DE DESCUENTO” por un periodo de 12 (doce) meses y encontrarse dentro de dicho periodo de vigencia.</p>\r\n\r\n  <h4>QUINTA.- OBLIGACIONES DE “EL PRESTADOR”.</h4>\r\n  <p>“EL PRESTADOR” se obliga a: (i) otorgar a “EL AFILIADO” el acceso ilimitado a “LA TARJETA DE DESCUENTO” durante la vigencia del contrato; (ii) mantener actualizada y operativa la Red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla; (iii) proporcionar a “EL AFILIADO”, de forma digital, “LA TARJETA DE DESCUENTO” dentro de los 5 (cinco) días hábiles siguientes al primer pago; e (iv) informar por escrito cualquier modificación a la red de hospitales o al tabulador de cuotas con al menos 10 (diez) días de anticipación.</p>\r\n\r\n  <h4>SEXTA.- OBLIGACIONES DE “EL AFILIADO”.</h4>\r\n  <p>“EL AFILIADO” se obliga a: (i) pagar puntualmente el precio de “LA TARJETA DE DESCUENTO”; (ii) utilizarla de forma exclusiva, personal e intransferible; (iii) cubrir directamente a los hospitales y con anterioridad a recibir el servicio médico las cuotas de recuperación según tabulador vigente; (iv) presentar identificación oficial y “LA TARJETA DE DESCUENTO” o código QR cada vez que haga uso de beneficios; y (v) notificar por escrito cualquier cambio de domicilio o datos de contacto en un plazo no mayor a 5 (cinco) días.</p>\r\n\r\n  <h4>SÉPTIMA.- ACCESO A LOS BENEFICIOS Y PROCEDIMIENTO.</h4>\r\n  <p>Para hacer uso de “LA TARJETA DE DESCUENTO”, “EL AFILIADO” deberá agendar sus citas directamente con los doctores pertenecientes a la Red de Hospitales 50 (FIFTY) Doctors, que en ese momento se encuentren adscritos al programa de beneficios, a través de la aplicación oficial, página de internet oficial de PATS o medios oficiales que indique “EL PRESTADOR”.</p>\r\n  <p>“EL AFILIADO” se obliga a pagar directamente al médico especialista perteneciente al programa el costo de la consulta de especialidad de que se trate, en términos de los porcentajes de descuento del ANEXO 4. En caso de no estar facultado para asistir por fuerza mayor, tendrá un plazo de 30 (treinta) días contados a partir de haber generado la cita para solicitar una nueva consulta médica.</p>\r\n\r\n  <h4>OCTAVA.- EXCLUSIONES Y LIMITACIONES.</h4>\r\n  <p>Los beneficios no incluirán: (i) trasplantes de órganos; (ii) tratamientos experimentales; (iii) tratamientos de oncología a excepción de algunas cirugías; (iv) medicamentos extra hospitalarios que no estén recogidos en el catálogo de Farmacia PATS; (v) atención médica con especialistas no adscritos o no publicados en los medios oficiales; y (vi) cualquier servicio no listado expresamente.</p>\r\n\r\n  <h4>NOVENA.- CAUSAS DE TERMINACIÓN.</h4>\r\n  <p>El contrato podrá terminarse por falta de pago, mutuo consentimiento por escrito o incumplimiento de cualquiera de las cláusulas por cualquiera de “LAS PARTES”. En caso de terminación, “EL AFILIADO” no tendrá derecho a exigir la devolución de cantidad alguna.</p>\r\n\r\n  <h4>DÉCIMA.- CANCELACIÓN VOLUNTARIA.</h4>\r\n  <p>“EL AFILIADO” podrá cancelar “LA TARJETA DE DESCUENTO” mediante aviso por escrito con 30 (treinta) días de anticipación. Dicha cancelación surtirá efectos a partir del siguiente periodo mensual y no generará reembolso de pagos ya realizados.</p>\r\n\r\n  <h4>DÉCIMA PRIMERA.- PROTECCIÓN DE DATOS PERSONALES.</h4>\r\n  <p>“LAS PARTES” acuerdan que el tratamiento de datos personales se sujetará a la Ley Federal de Protección de Datos Personales en Posesión de los Particulares. “EL AFILIADO” autoriza expresamente el uso de sus datos para la gestión de “LA TARJETA DE DESCUENTO”. El aviso de privacidad se integra al presente contrato como ANEXO 5.</p>\r\n\r\n  <h4>DÉCIMA SEGUNDA.- RESPONSABILIDAD.</h4>\r\n  <p>“EL AFILIADO” reconoce y acepta que “LA TARJETA DE DESCUENTO” es emitida y administrada directamente por CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE, quien es responsable de la operación de la red de descuentos, afiliación de prestadores médicos y prestación de cualquier servicio relacionado con “LA TARJETA DE DESCUENTO”.</p>\r\n  <p>En consecuencia, “EL PRESTADOR” no tendrá responsabilidad directa ni indirecta por la prestación, calidad, eficacia, resultado, daño, perjuicio, lesión, complicación, secuela, evento adverso o consecuencia derivada de servicios médicos recibidos, incluyendo aquellos ocasionados por negligencia, impericia o mala praxis de profesionales de la salud o prestadores afiliados. Cualquier relación derivada de la prestación de servicios médicos se establece directamente entre “EL AFILIADO” y los prestadores de servicios de salud correspondientes. Esta limitación subsistirá a la terminación del contrato.</p>\r\n\r\n  <h4>DÉCIMA TERCERA.- PREVENCIÓN DE LAVADO DE DINERO Y ORIGEN DE LOS RECURSOS.</h4>\r\n  <p>“LAS PARTES” declaran bajo protesta de decir verdad que los recursos económicos, bienes y derechos que utilicen para cumplir obligaciones derivadas de este contrato tienen y tendrán origen lícito. “EL AFILIADO” manifiesta que el pago inicial y pagos futuros provienen de fuentes lícitas y no de actividades tipificadas como delitos.</p>\r\n  <p>“LAS PARTES” reconocen que la prestación de servicios de comercio puede ser considerada actividad vulnerable, por lo que se obligan a proporcionar información y documentación requerida para integrar expediente de identificación e informar si tienen conocimiento de la existencia de beneficiario controlador.</p>\r\n\r\n  <h4>DÉCIMA CUARTA.- CONFORMACIÓN DEL EXPEDIENTE DE IDENTIFICACIÓN.</h4>\r\n  <p>“EL PRESTADOR” queda obligado a conformar y mantener un expediente de identificación de “EL AFILIADO”. Para tales efectos, “EL AFILIADO” se obliga a entregar los documentos aplicables: identificación oficial vigente o pasaporte, acta de nacimiento cuando aplique, comprobante de domicilio, constancia de situación fiscal cuando aplique, CURP, y declaración de dueño beneficiario.</p>\r\n  <p>Cuando exista persona responsable, la documentación de identificación y representación deberá integrarse al expediente; la CIF/constancia fiscal corresponde al tutor cuando aplique. “EL PRESTADOR” conservará dicho expediente por un periodo mínimo de 5 (cinco) años contados a partir de que termine la vigencia del contrato o termine por cualquiera de sus causales, garantizando la confidencialidad de los datos personales.</p>\r\n\r\n  <h4>DÉCIMA QUINTA.- CAUSAL ESPECÍFICA DE RESCISIÓN.</h4>\r\n  <p>Será motivo de rescisión inmediata sin necesidad de declaración judicial y sin responsabilidad para la parte afectada cuando cualquiera de “LAS PARTES” se niegue a proporcionar información requerida para cumplimiento de la Ley Federal para la Prevención e Identificación de Operaciones con Recursos de Procedencia Ilícita, proporcione información falsa o aparezca en listas de personas bloqueadas emitidas por autoridad competente.</p>\r\n\r\n  <h4>DÉCIMA SEXTA.- LEGISLACIÓN APLICABLE Y JURISDICCIÓN.</h4>\r\n  <p>“LAS PARTES” establecen que la Procuraduría Federal del Consumidor es competente en vía administrativa para resolver cualquier controversia sobre interpretación o cumplimiento. Sin perjuicio de lo anterior, se someten expresamente a la jurisdicción de los tribunales competentes del fuero común del Distrito Judicial de Puebla, Estado de Puebla, renunciando de manera expresa e irrevocable a cualquier otro fuero o jurisdicción que pudiera corresponderles.</p>\r\n\r\n  <p>Enteradas “LAS PARTES” del contenido y alcance del presente contrato, y entendidas de los derechos y obligaciones que contraen, firman el presente instrumento, incluyendo sus anexos, manifestando que no medió error, dolo, mala fe, violencia o lesión, ni vicio del consentimiento alguno, en la Ciudad de Puebla, Estado de Puebla, reconociendo que la fecha de firma es 13 de mayo de 2026.</p>\r\n\r\n  <div class=\"sign-grid\">\r\n    <div class=\"sign-box\"><div class=\"line\"></div><strong>“EL PRESTADOR”</strong><br>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE<br>Representada por PEDRO AZCÁRRAGA RAMOS</div>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>“EL AFILIADO”</strong><br>Juan Manuel LOpez LOpez</div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 1<br>Identificación oficial de “EL AFILIADO”</h2><p>Se integra al expediente la identificación oficial cargada por el usuario en el formulario. Para mexicanos, corresponde a identificación oficial/INE cuando aplique. Para extranjeros/no mexicanos, corresponde a identificación oficial o pasaporte vigente; al menos el frente es obligatorio y el reverso será opcional cuando el documento no lo tenga.</p><p><strong>Tipo:</strong> INE. <strong>Emitida por / país emisor:</strong> México. <strong>Número:</strong> DAAVFDSDDD.</p></div>\r\n  <div class=\"annex\"><h2>ANEXO 2<br>COMPROBANTE DE DOMICILIO DE “EL AFILIADO”</h2><p>Se integra al expediente el comprobante de domicilio cargado por el usuario. Domicilio declarado: casa 12, Col. casa, C.P. 14523, zapopan, Jalisco, México.</p></div>\r\n  <div class=\"annex\"><h2>ANEXO 3<br>CONSTANCIA DE SITUACIÓN FISCAL DE “EL AFILIADO”</h2><p>Constancia de Situación Fiscal de “EL AFILIADO”, si aplica. En caso de pacientes representados, la constancia fiscal o CIF corresponde a la persona responsable cuando sea aplicable, no al menor. Para afiliados extranjeros/no mexicanos, no será obligatoria salvo que declaren RFC mexicano o residencia fiscal aplicable.</p></div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 4<br>CUOTAS DE RECUPERACIÓN Y/O PRECIOS BASE A CUBRIR A “EL PRESTADOR”</h2>\r\n    <p>En el presente anexo se establecen los porcentajes de descuento a obtener como titular de “LA TARJETA DE DESCUENTO”, por lo que la cantidad a cubrir por “EL AFILIADO” directamente al hospital de la cadena 50 (FIFTY) Doctors o al doctor que preste el servicio se obtendrá de aplicar el porcentaje de descuento correspondiente al precio publicado por los medios oficiales o al precio vigente en el establecimiento.</p>\r\n    <table><tr><th>Servicios / procedimientos</th><th>Descuentos</th></tr><tr><td>Consulta de urgencias</td><td>100%</td></tr><tr><td>Consulta de medicina general</td><td>100%</td></tr><tr><td>Habitación hospitalaria</td><td>90%</td></tr><tr><td>Uso de áreas de urgencias médicas</td><td>80%</td></tr><tr><td>Utilización de cubículos de terapia intensiva (UCIA-UCIN-UCIP)</td><td>75%</td></tr><tr><td>CEYE</td><td>75%</td></tr><tr><td>Uso quirófano</td><td>75%</td></tr><tr><td>Servicio de cuneros</td><td>75%</td></tr><tr><td>Materiales & medicamentos del cuadro básico, genéricos intercambiables</td><td>70%</td></tr><tr><td>Hemodinamia</td><td>70%</td></tr><tr><td>Imagenología</td><td>70%</td></tr><tr><td>Endoprótesis</td><td>70%</td></tr><tr><td>Osteosíntesis</td><td>70%</td></tr><tr><td>Prótesis</td><td>70%</td></tr><tr><td>Órtesis</td><td>70%</td></tr><tr><td>Laboratorio clínico</td><td>60%</td></tr></table>\r\n    <p class=\"small\">Los descuentos aplican con los proveedores suscritos al convenio de Pasaporte a tu Salud.</p>\r\n    <table><tr><th>Servicios / procedimientos</th><th>Precios base</th></tr><tr><td>Consulta de especialidades médicas</td><td>$390.00</td></tr><tr><td>Colposcopía</td><td>$400.00</td></tr><tr><td>Retiro de puntos de sutura</td><td>$80.00</td></tr><tr><td>Aplicación de medicamento intramuscular</td><td>$60.00</td></tr><tr><td>Retiro de DIU</td><td>$500.00</td></tr><tr><td>Colocación de DIU</td><td>$700.00</td></tr><tr><td>Extracción de cuerpo extraño (oído y nariz)</td><td>$300.00</td></tr><tr><td>Lavado ótico</td><td>$250.00</td></tr><tr><td>Curación de sitio quirúrgico</td><td>$250.00</td></tr><tr><td>Retiro de yeso</td><td>$250.00</td></tr><tr><td>Visita día de hospitalización</td><td>$650.00</td></tr><tr><td>Visita de urgencias</td><td>$750.00</td></tr><tr><td>Día de terapia intensiva</td><td>$850.00</td></tr></table>\r\n    <p class=\"small\">Todos los precios incluyen IVA. La factura de servicios hospitalarios será emitida con el desglose correspondiente y el ahorro otorgado por ser titular de “LA TARJETA DE DESCUENTO”.</p>\r\n    <p>Exclusiones y limitaciones: se aplicarán descuentos y precios especiales para el acompañante de “EL AFILIADO” en la misma habitación únicamente para la primera noche de hospitalización. Los precios y porcentajes de descuento darán derecho a la utilización de materiales y medicamentos del cuadro básico, genéricos intercambiables; cualquier otro tipo de medicación será cubierto directamente por “EL AFILIADO”. Los costos de procedimientos quirúrgicos incluyen honorarios médicos cuando así se indique. “EL AFILIADO” podrá atenderse con el médico tratante que elija, debiendo cubrir honorarios directamente a dicho médico, conservando el derecho a beneficios dentro de la red aplicable.</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Firma de aceptación de “EL AFILIADO”</strong><br>Juan Manuel LOpez LOpez</div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 5<br>AVISO DE PRIVACIDAD</h2>\r\n    <p>En cumplimiento de las disposiciones establecidas en la Ley Federal de Protección de Datos Personales en Posesión de Particulares, su Reglamento y los lineamientos aplicables, “CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE” (en lo sucesivo “EL PRESTADOR”), con domicilio en CALLE PASEO SINFONÍA NÚMERO EXTERIOR 1, LOCAL 2-14, LOMAS DE ANGELÓPOLIS II, SAN ANDRÉS CHOLULA, ESTADO DE PUEBLA, CÓDIGO POSTAL 72830, da a conocer el Aviso de Privacidad al tenor del cual manejará por medio de su representación y/o empleados los datos personales y/o documentación proporcionada por el afiliado o usuario de “LA TARJETA DE DESCUENTO”.</p>\r\n    <p>Se tendrá por aceptado expresamente el presente Aviso de Privacidad una vez proporcionados los datos personales y firmada digitalmente la aceptación del contrato, motivo por el cual “EL PRESTADOR” estará facultado para manejar la información conforme a la legislación aplicable.</p>\r\n    <h4>Modificación del aviso de privacidad</h4><p>Este aviso podrá ser modificado o adecuado a las necesidades de “EL PRESTADOR”. Las modificaciones o actualizaciones serán incorporadas al presente aviso y estarán disponibles en la página de internet, domicilio de “EL PRESTADOR” o serán enviadas al último correo electrónico proporcionado.</p>\r\n    <h4>Finalidad de la información</h4><p>La información será utilizada para: elaborar y mantener actualizada la base de usuarios; identificar afiliados; proporcionar la tarjeta digital; otorgar acceso al programa de beneficios; informar modificaciones a la red o tabulador; realizar análisis estadísticos internos y brindar un óptimo servicio médico.</p>\r\n    <h4>Tipo de datos necesarios</h4><p>Se solicitarán datos de identificación, contacto, legales, contractuales y fiscales cuando aplique, incluyendo nombre completo, lugar y fecha de nacimiento, firma, identificación oficial, nacionalidad, CURP y RFC cuando sean aplicables, domicilio, teléfono y correo electrónico.</p>\r\n    <h4>Transferencias de la información</h4><p>El usuario autoriza proporcionar información sin consentimiento adicional en los casos previstos por ley, resolución de autoridad competente, tratados aplicables, salvaguarda de interés público, procuración o administración de justicia, reconocimiento o defensa de derechos en procesos judiciales, y a socios comerciales, técnicos o estratégicos que asuman obligaciones de confidencialidad y seguridad equivalentes.</p>\r\n    <h4>Limitación del uso o divulgación de datos y derechos ARCO</h4><p>El usuario podrá limitar el uso o divulgación de sus datos personales y ejercer derechos de acceso, rectificación, cancelación u oposición mediante solicitud escrita dirigida a “EL PRESTADOR” en su domicilio o al correo silvia@pasaporteatusalud.com, acompañando documento que acredite su identidad.</p>\r\n    <h4>Revocación de consentimiento</h4><p>El usuario podrá revocar su consentimiento siguiendo el mismo procedimiento, considerando que para ciertos fines la revocación puede implicar la cancelación de “LA TARJETA DE DESCUENTO” y la imposibilidad de acceder al programa.</p>\r\n    <p><strong>Nombre:</strong> Juan Manuel LOpez LOpez<br><strong>Fecha:</strong> 13 de mayo de 2026</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Firma</strong></div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 6<br>DECLARACIÓN DE DUEÑO BENEFICIARIO</h2>\r\n    <p>DE CONFORMIDAD CON LO DISPUESTO EN LOS ARTÍCULOS 18 FRACCIÓN I Y III DE LA LEY FEDERAL PARA PREVENCIÓN E IDENTIFICACIÓN DE OPERACIONES CON RECURSOS DE PROCEDENCIA ILÍCITA, EL ARTÍCULO 15 DE SU REGLAMENTO Y EL ARTÍCULO 13 DE LAS REGLAS DE CARÁCTER GENERAL, MANIFIESTO BAJO PROTESTA DE DECIR VERDAD:</p>\r\n    <h4>Datos de identificación del cliente</h4>\r\n    <table><tr><th>Campo</th><th>Respuesta</th></tr><tr><td>Apellido paterno, materno y nombre(s)</td><td>Juan Manuel LOpez LOpez</td></tr><tr><td>Fecha de nacimiento</td><td>1984-12-12</td></tr><tr><td>País de nacimiento</td><td>México</td></tr><tr><td>Nacionalidad</td><td>mexicana</td></tr><tr><td>Actividad, ocupación o profesión</td><td>estudiante</td></tr><tr><td>Estado civil</td><td>SOLTERO(A)</td></tr><tr><td>Domicilio particular</td><td>casa 12, Col. casa, C.P. 14523, zapopan, Jalisco, México</td></tr><tr><td>Teléfonos</td><td>4452211111</td></tr><tr><td>Correo electrónico</td><td>roel.fuentes@gmail.com</td></tr><tr><td>CURP</td><td>14521452144DDDDDDD</td></tr><tr><td>RFC</td><td>Pendiente / no proporcionado</td></tr><tr><td>Tipo de identificación</td><td>INE</td></tr><tr><td>Emitida por / país emisor</td><td>México</td></tr><tr><td>Número de identificación</td><td>DAAVFDSDDD</td></tr></table>\r\n    <h4>Datos de identificación de la operación</h4>\r\n    <table><tr><th>Campo</th><th>Respuesta</th></tr><tr><td>Tipo de operación</td><td>Adquisición de tarjeta de descuento PATS</td></tr><tr><td>Monto de operación</td><td>$800.00 M.N.</td></tr><tr><td>Fecha de operación</td><td>13 de mayo de 2026</td></tr><tr><td>Forma de pago</td><td>Pasarela / medio autorizado por “EL PRESTADOR”</td></tr><tr><td>Moneda</td><td>MXN</td></tr></table>\r\n    <h4>Información de la existencia del dueño beneficiario o beneficiario controlador</h4>\r\n    <p>Declaro que soy el beneficiario directo de la operación y no existe ningún otro dueño beneficiario o beneficiario controlador: <strong>SI</strong>.</p>\r\n    <h4>Aviso de privacidad</h4><p>Los datos personales serán protegidos y tratados conforme al Aviso de Privacidad contenido en el cuerpo del presente contrato y la legislación aplicable.</p>\r\n    <p>H. Puebla de Zaragoza al 13 del mes de mayo del año 2026.</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Nombre y firma</strong><br>Juan Manuel LOpez LOpez</div>\r\n  </div>\r\n\r\n  \r\n  </div>\r\n', 'data:image/png;base64,', 'Juan Manuel LOpez LOpez', 'b49b695746f5f4c343ddc14ef7b38697ce534c6874b0a969f09ec4b271105bb6', '2026-05-13 03:30:22', '189.190.196.8', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:150.0) Gecko/20100101 Firefox/150.0', '', 'firmado', '2026-05-13 03:30:22', '2026-05-13 03:30:22');
INSERT INTO `pats_contratos_firmados` (`id_contrato_firmado`, `id_orden`, `id_pasaporte`, `id_distribuidor`, `id_franquicia`, `token_publico`, `contrato_clave`, `contrato_version`, `html_contrato_renderizado`, `firma_afiliado_base64`, `nombre_firmante`, `hash_contrato`, `fecha_firma`, `ip_firma`, `user_agent_firma`, `pdf_path`, `estatus`, `created_at`, `updated_at`) VALUES
(10, 2, 2, 1, 1, 'b4bea98c9badb5b9d4c6ce7da50ffd7f02766757a7807265323a228c0dc7b907', 'contrato_pats_base', '1.0', '<style>\r\n  .pats-contract{font-family:Arial,Helvetica,sans-serif;color:#172033;font-size:12px;line-height:1.52;background:#fff;padding:4px}\r\n  .pats-contract h1,.pats-contract h2,.pats-contract h3,.pats-contract h4{text-align:center;margin:12px 0 8px;color:#0d1b3e}\r\n  .pats-contract h1{font-size:16px;text-transform:uppercase;letter-spacing:.05em}\r\n  .pats-contract h2{font-size:15px;text-transform:uppercase;letter-spacing:.04em}\r\n  .pats-contract h3{font-size:13px;text-transform:uppercase;letter-spacing:.08em}\r\n  .pats-contract h4{font-size:12px;text-align:left;text-transform:uppercase;margin-top:12px}\r\n  .pats-contract p{margin:6px 0;text-align:justify}\r\n  .pats-contract ul{margin:6px 0 8px 18px;padding:0}.pats-contract li{margin:4px 0;text-align:justify}\r\n  .pats-contract table{width:100%;border-collapse:collapse;margin:8px 0 12px}.pats-contract th,.pats-contract td{border:1px solid #cbd5e1;padding:6px;vertical-align:top}.pats-contract th{background:#eef4ff;color:#0d1b3e;text-align:left}\r\n  .pats-contract .center{text-align:center}.pats-contract .muted{color:#64748b}.pats-contract .small{font-size:10px}.pats-contract .badge{display:inline-block;padding:3px 8px;border-radius:999px;background:#eef4ff;color:#1d4ed8;font-weight:700;margin:2px 4px 2px 0}\r\n  .pats-contract .sign-grid{display:grid;grid-template-columns:1fr 1fr;gap:22px;margin-top:28px}.pats-contract .sign-box{text-align:center;min-height:95px}.pats-contract .line{border-top:1px solid #0f172a;margin:48px 8px 6px}.pats-contract .signature-img{max-width:220px;max-height:82px;display:block;margin:0 auto 4px}\r\n  .pats-contract .annex{page-break-before:auto;border-top:2px solid #0d1b3e;margin-top:18px;padding-top:12px}.pats-contract .page-break{page-break-before:always;border-top:1px dashed #cbd5e1;margin-top:18px;padding-top:12px}\r\n</style>\r\n<div class=\"pats-contract\">\r\n  <h1>Carátula del contrato de adquisición de tarjeta de descuento</h1>\r\n  <p>CARÁTULA DEL CONTRATO DE ADQUISICIÓN DE TARJETA DE DESCUENTO (EN LO SUCESIVO “LA CARÁTULA”), QUE CELEBRAN POR UNA PARTE LA SOCIEDAD SEÑALADA EN EL APARTADO 1.- DE LA CARÁTULA, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL PRESTADOR”, REPRESENTADA EN ESTE ACTO POR LA PERSONA FÍSICA QUE SE INDICA EN EL APARTADO 2.- DE LA CARÁTULA; Y POR LA OTRA PARTE, LA PERSONA FÍSICA SEÑALADA EN EL APARTADO 5.- DE LA CARÁTULA, POR SU PROPIO DERECHO, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL AFILIADO”; Y CUANDO LOS ANTES NOMBRADOS ACTÚEN DE MANERA CONJUNTA, SE LES DENOMINARÁ COMO “LAS PARTES”; QUIENES SE SUJETAN AL TENOR DE LA CARÁTULA, DECLARACIONES Y CLÁUSULAS SIGUIENTES:</p>\r\n    \r\n  <h2>C A R Á T U L A</h2>\r\n  <table>\r\n    <tr><th style=\"width:8%\">Apartado</th><th style=\"width:42%\">Definición</th><th>Respuesta</th></tr>\r\n    <tr><td>1.-</td><td>Nombre de “EL PRESTADOR”</td><td>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE</td></tr>\r\n    <tr><td>2.-</td><td>Nombre del Representante Legal de “EL PRESTADOR”</td><td>PEDRO AZCÁRRAGA RAMOS</td></tr>\r\n    <tr><td>3.-</td><td>Domicilio de “EL PRESTADOR”</td><td>CALLE PASEO SINFONÍA NÚMERO EXTERIOR 1, LOCAL 2-14, LOMAS DE ANGELÓPOLIS II, SAN ANDRÉS CHOLULA, ESTADO DE PUEBLA, CÓDIGO POSTAL 72830</td></tr>\r\n    <tr><td>4.-</td><td>Clave del Registro Federal de Contribuyentes de “EL PRESTADOR”</td><td>COH2202144H5</td></tr>\r\n    <tr><td>5.-</td><td>Nombre de “EL AFILIADO”</td><td>Pablo Aja Fresnedo</td></tr>\r\n    <tr><td>6.-</td><td>Domicilio de “EL AFILIADO”</td><td>dddd dd, Col. dd, C.P. 14521, ddd, Puebla, México</td></tr>\r\n    <tr><td>7.-</td><td>Clave del Registro Federal de Contribuyentes de “EL AFILIADO”</td><td>DDDD</td></tr>\r\n    <tr><td>8.-</td><td>Costo anual de “LA TARJETA DE DESCUENTO”</td><td>$9,600.00 M.N.</td></tr>\r\n    <tr><td>9.-</td><td>Cuenta bancaria de “EL PRESTADOR” para pagos</td><td>Cuenta: 01600866709<br>CLABE: 042650016008667096<br>Institución Bancaria: Banca Mifel, S.A., Institución de Banca Múltiple, Grupo Financiero Mifel</td></tr>\r\n    <tr><td>10.-</td><td>Cuota de Reactivación de “LA TARJETA DE DESCUENTO”</td><td>$100.00 M.N. por cada mes que se haya interrumpido el pago.</td></tr>\r\n    <tr><td>11.-</td><td>Datos de la Tarjeta de Crédito de “EL AFILIADO”</td><td>Número de tarjeta: pendiente de confirmar por pasarela/token de pago.<br>Institución bancaria: pendiente de confirmar por pasarela. <br><span class=\"small\">No se almacena número completo de tarjeta en este formulario.</span></td></tr>\r\n    <tr><td>12.-</td><td>Anexos</td><td>ANEXO 1. Identificación oficial de “EL AFILIADO”<br>ANEXO 2. Comprobante de domicilio de “EL AFILIADO”<br>ANEXO 3. Constancia de Situación Fiscal de “EL AFILIADO”, si aplica<br>ANEXO 4. Cuotas de recuperación y/o precios base a cubrir a “EL PRESTADOR”<br>ANEXO 5. Aviso de privacidad<br>ANEXO 6. Declaración de dueño beneficiario</td></tr>\r\n    <tr><td>13.-</td><td>Fecha de Firma del Contrato</td><td>13 de mayo de 2026</td></tr>\r\n  </table>\r\n\r\n  <div class=\"sign-grid\">\r\n    <div class=\"sign-box\"><div class=\"line\"></div><strong>“EL PRESTADOR”</strong><br>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE<br>Representada por PEDRO AZCÁRRAGA RAMOS</div>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>“EL AFILIADO”</strong><br>Pablo Aja Fresnedo<br><span class=\"small\">La persona física señalada en el Apartado 5.- de la Carátula</span></div>\r\n  </div>\r\n\r\n  <div class=\"page-break\"></div>\r\n  <h1>Contrato de adquisición de tarjeta de descuento</h1>\r\n  <p>CONTRATO DE ADQUISICIÓN DE TARJETA DE DESCUENTO, QUE CELEBRAN POR UNA PARTE LA SOCIEDAD SEÑALADA EN EL APARTADO 1.- DE LA CARÁTULA, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL PRESTADOR”, REPRESENTADA EN ESTE ACTO POR LA PERSONA FÍSICA QUE SE INDICA EN EL APARTADO 2.- DE LA CARÁTULA; Y POR LA OTRA PARTE, LA PERSONA FÍSICA SEÑALADA EN EL APARTADO 5.- DE LA CARÁTULA, POR SU PROPIO DERECHO, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL AFILIADO”; Y CUANDO LOS ANTES NOMBRADOS ACTÚEN DE MANERA CONJUNTA, SE LES DENOMINARÁ COMO “LAS PARTES”; QUIENES SE SUJETAN AL TENOR DE LAS DECLARACIONES Y CLÁUSULAS SIGUIENTES:</p>\r\n\r\n  <h2>D E C L A R A C I O N E S</h2>\r\n  <h4>I.- Declara “EL PRESTADOR” por conducto de su representación:</h4>\r\n  <p>A. Que, su representada es una sociedad mercantil constituida conforme a las leyes de los Estados Unidos Mexicanos, según consta en la escritura pública número 39,861, del volumen 830 de fecha catorce de febrero de dos mil veintidós, otorgada ante la fe del Licenciado Ernesto Joaquín Briones Amador, Notario Público Titular de la Notaría Pública número 46 de las del Distrito Judicial de Puebla, Estado de Puebla, cuyo primer testimonio se encuentra inscrito ante las oficinas del Registro Público de Comercio del Distrito Judicial de Puebla, Estado de Puebla, bajo el Folio Mercantil Electrónico: N-2022022991, por virtud del cual se llevó a cabo la Constitución de la persona moral denominada CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE.</p>\r\n  <p>B. Que, la persona física que la representa en este acto, señalada en el Apartado 2.- de la Carátula, cuenta con todas y cada una de las facultades necesarias para la celebración del presente contrato, las cuales se desprenden del instrumento descrito en el punto declarativo inmediato anterior, mismas que manifiesta bajo protesta de decir verdad que no le han sido suspendidas, revocadas o limitadas en forma alguna.</p>\r\n  <p>C. Que, su representada tiene como domicilio fiscal el señalado en el Apartado 3.- de la Carátula del presente contrato, mismo que designa como domicilio convencional para cualquier cuestión relacionada con la celebración del presente contrato.</p>\r\n  <p>D. Que, su representada se encuentra inscrita en el Registro Federal de Contribuyentes bajo la clave señalada en el Apartado 4.- de la Carátula.</p>\r\n  <p>E. Que, ha desarrollado y es su deseo comparecer a la celebración del presente instrumento con la finalidad de enajenar en favor de “EL AFILIADO”, una Tarjeta de Descuento que da acceso a “UN PROGRAMA DE BENEFICIOS QUE OTORGA DESCUENTOS A LOS COSTOS Y PERMITE RECIBIR SERVICIOS MÉDICOS PRIVADOS DE ALTA CALIDAD DE FORMA ACCESIBLE, CLARA Y SIN RESTRICCIONES DENTRO DE LA RED DE HOSPITALES 50 (FIFTY) DOCTORS CON SEDE EN EL ESTADO DE PUEBLA”, en lo sucesivo “LA TARJETA DE DESCUENTO”, en los términos y condiciones que se establecerán más adelante.</p>\r\n  <p>F. Que, su representada no es una Aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas sino una empresa dedicada, entre otros, a la operación y administración de establecimientos destinados a la atención y asistencia de enfermos, por lo que la enajenación de “LA TARJETA DE DESCUENTO” únicamente constituye un acto de comercio que brindará a “EL AFILIADO” acceso a un programa de beneficios como ha quedado descrito anteriormente.</p>\r\n\r\n  <h4>II.- Declara “EL AFILIADO”, por su propio derecho:</h4>\r\n      <p>A. Que, su nombre se señala en el Apartado 5.- de la Carátula, es una persona física de nacionalidad mexicana, en pleno ejercicio de sus derechos, legal y jurídicamente capaz para celebrar el presente Contrato, quien se identifica con credencial para votar vigente expedida por el Instituto Nacional Electoral, tipo INE, número DDDD, que en copia simple o archivo digital se agrega al cuerpo del presente contrato como ANEXO 1.</p>\r\n    <p>B. Que, tiene como domicilio particular el señalado en el Apartado 6.- de la Carátula, mismo que designa como domicilio convencional para cualquier cuestión relacionada con la celebración del presente contrato, tal y como lo acredita con el comprobante de domicilio que en copia simple o archivo digital se agrega al cuerpo del presente contrato como ANEXO 2.</p>\r\n  <p>C. Que, su CURP es DD y su RFC/identificación fiscal es DDDD; asimismo manifiesta que cuenta con capacidad económica para obligarse en términos del presente contrato y que los recursos con los que cubrirá sus obligaciones provendrán de fuentes lícitas. En caso de nacionalidad extranjera/no mexicana, se tendrán por no aplicables CURP, INE y constancia fiscal mexicana salvo manifestación expresa de residencia fiscal o RFC mexicano.</p>\r\n  <p>D. Que, es su deseo comparecer a la celebración del presente instrumento con la finalidad de adquirir “LA TARJETA DE DESCUENTO” de acuerdo con los términos y condiciones que se establecen a continuación.</p>\r\n  <p>E. Que, previo a la celebración del presente contrato fue informado y manifiesta expresamente que reconoce que “EL PRESTADOR” no es una Aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas y que las actividades comerciales objeto del presente contrato no consisten en la contratación de un seguro, de la índole que fuere, sino que únicamente implica la adquisición de una tarjeta de descuento que da acceso a un programa de beneficios que otorga descuentos a los costos y permite recibir servicios médicos privados de alta calidad de forma accesible, clara y sin restricciones dentro de la red de hospitales 50 (FIFTY) Doctors con sede en el Estado de Puebla.</p>\r\n  <p>F. Que, reconoce que “EL PRESTADOR” se dedica a la operación de centros hospitalarios y que la emisión de “LA TARJETA DE DESCUENTO” únicamente corresponde a la intención de este último de crear un programa de descuentos para el acceso a los servicios prestados por la Red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla.</p>\r\n\r\n  <h4>III.- Declaran conjuntamente “LAS PARTES”:</h4>\r\n  <p>1. Que, se reconocen recíprocamente la personalidad con la que comparecen a la celebración del presente acuerdo de voluntades.</p>\r\n  <p>2. Que, el presente contrato es el instrumento que las vincula en sus derechos y obligaciones.</p>\r\n  <p>3. Que, es su deseo celebrar el presente contrato y han negociado libremente los términos y condiciones del mismo con pleno conocimiento de sus alcances e implicaciones jurídicas, por lo que en su celebración no existe dolo, error, mala fe, lesión o cualquier otro vicio del consentimiento que pudiese afectarlo de inexistencia o nulidad.</p>\r\n\r\n  <h2>C L Á U S U L A S</h2>\r\n  <h4>PRIMERA.- OBJETO.</h4>\r\n  <p>El objeto del presente Contrato es que “EL AFILIADO” adquiera de “EL PRESTADOR”, a título oneroso y temporal, el derecho de uso ilimitado y sin restricción alguna de “LA TARJETA DE DESCUENTO” emitida por CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE, la cual consiste en que “EL AFILIADO” aproveche y acceda a “UN PROGRAMA DE BENEFICIOS QUE OTORGA DESCUENTOS A LOS COSTOS Y PERMITE RECIBIR SERVICIOS MÉDICOS PRIVADOS DE ALTA CALIDAD DE FORMA ACCESIBLE, CLARA Y SIN RESTRICCIONES DENTRO DE LA RED DE HOSPITALES 50 (FIFTY) DOCTORS CON SEDE EN EL ESTADO DE PUEBLA”.</p>\r\n  <p>Estableciendo que, la comercialización de “LA TARJETA DE DESCUENTO” por parte de “EL PRESTADOR” en ningún momento constituirá la venta, promoción o por cualquier medio la contratación de una póliza de seguro, bajo el entendido de que “EL PRESTADOR” no es una aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas (CNSF); sino que comercializa “LA TARJETA DE DESCUENTO” en favor de terceros con la finalidad de otorgar descuentos a los precios respecto de los servicios médicos que presta en el territorio nacional.</p>\r\n\r\n  <h4>SEGUNDA.- PRECIO DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“LAS PARTES” establecen de común acuerdo que “LA TARJETA DE DESCUENTO” tendrá como costo anual la cantidad señalada en el Apartado 8.- de la Carátula del presente contrato; cantidad que ya incluye IVA, y la cual deberá ser cubierta por “EL AFILIADO” en favor de “EL PRESTADOR” dentro de los primeros 5 (cinco) días de cada mes, sin necesidad de gestiones o avisos de cobro, ya sea mediante:</p>\r\n  <p>(i) Transferencia electrónica de fondos a la cuenta bancaria señalada en el Apartado 9.- de la Carátula del presente contrato y de la cual es titular “EL PRESTADOR”.</p>\r\n  <p>(ii) Cheque que se recibirá salvo buen cobro en el Domicilio de “EL PRESTADOR” señalado en el Apartado 3.- de la Carátula del presente contrato, y que en caso de no ser pagado por falta de fondos suficientes o por otras causas imputables a “EL AFILIADO”, éste último está de acuerdo en que deberá cubrir a “EL PRESTADOR” el 20% (veinte por ciento) del monto del cheque por concepto de indemnización por daños y perjuicios en términos del artículo 193 de la Ley General de Títulos y Operaciones de Crédito, independientemente de cualquier otro cargo que se pudiera generar.</p>\r\n  <p>(iii) Cargos mensuales automáticos recurrentes a la tarjeta de crédito de “EL AFILIADO” según los datos señalados en el Apartado 11.- de la Carátula del presente contrato, quien manifiesta bajo protesta de decir verdad que autoriza a “EL PRESTADOR” a realizar los cargos mensuales correspondientes por el costo anual de “LA TARJETA DE DESCUENTO” en dicha tarjeta o en la tarjeta que por renovación, reposición, robo o extravío le haya asignado el banco emisor. La autorización estará vigente mientras “EL AFILIADO” no haya notificado a “EL PRESTADOR” por escrito y con acuse de recibo su deseo de cancelar su afiliación o no renovarla, o en su defecto, realizar su baja respectiva en el sitio web o aplicación de “EL PRESTADOR”.</p>\r\n  <p>Esta autorización no exime a “EL AFILIADO” del pago anual por el uso de “LA TARJETA DE DESCUENTO” y demás obligaciones contractuales, por lo que, en caso de que el cobro no sea autorizado por el banco emisor o por cualquier razón no pueda realizarse, “EL AFILIADO” deberá notificar tal situación a “EL PRESTADOR” a la dirección de correo electrónico silvia@pasaporteatusalud.com, a efecto de solicitar una forma de pago diversa, quedando obligado a cubrir de inmediato el pago correspondiente.</p>\r\n  <p>(iv) Cualquier otro medio de pago aceptado por “EL PRESTADOR”, mismo que se dará a conocer a través de sus medios oficiales de comunicación.</p>\r\n  <p>“EL PRESTADOR” podrá variar unilateralmente el costo mensual de “LA TARJETA DE DESCUENTO”, previo aviso a “EL AFILIADO” con 30 (treinta) días de anticipación a través de sus medios oficiales de comunicación.</p>\r\n  <p>Para el caso de que “EL AFILIADO” adquiera y cubra el precio de “LA TARJETA DE DESCUENTO” y posteriormente deje de pagar una mensualidad, deberá cubrir a “EL PRESTADOR”, por concepto de cuota de reactivación, la cantidad señalada en el Apartado 10.- de la Carátula por cada mes que haya interrumpido y/o no haya cubierto el precio de “LA TARJETA DE DESCUENTO”, hasta la fecha en que pretenda volver a adquirirla.</p>\r\n\r\n  <h4>TERCERA.- VIGENCIA DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“LA TARJETA DE DESCUENTO” objeto del presente contrato tendrá una vigencia de 12 meses contados a partir de que “EL AFILIADO” cubra a “EL PRESTADOR” el precio establecido anteriormente, en el entendido de que la vigencia del presente contrato y de “LA TARJETA DE DESCUENTO” se prorrogarán automáticamente sin necesidad de celebrar documento adicional entre “LAS PARTES” siempre y cuando “EL AFILIADO” cubra, de mes en mes o en la frecuencia contratada, el precio vigente de “LA TARJETA DE DESCUENTO”.</p>\r\n  <p>“EL AFILIADO” tendrá derecho a revocar su consentimiento dentro de los 5 (cinco) días siguientes a la entrega de “LA TARJETA DE DESCUENTO” o la firma del presente contrato, lo que ocurra último, sin responsabilidad alguna, siempre y cuando no haya obtenido beneficio alguno por el uso de “LA TARJETA DE DESCUENTO”.</p>\r\n\r\n  <h4>CUARTA.- BENEFICIOS DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“EL AFILIADO”, de forma exclusiva, personal e intransferible, gozará de forma gratuita de los servicios que se mencionan a continuación:</p>\r\n  <ul><li>Consultas gratuitas ilimitadas de medicina general (no de especialidad) en la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla, únicamente con los doctores afiliados al programa de Pasaporte a tu Salud.</li><li>Consultas de urgencia gratuitas en la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla.</li></ul>\r\n  <p>No así respecto de los servicios que, de manera enunciativa más no limitativa, se describen a continuación:</p>\r\n  <ul><li>Hospitalización dentro de la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla, sujeto a la disponibilidad de cada uno de ellos.</li><li>Consultas de especialidad ilimitadas a costo preferencial, con médicos especialistas pertenecientes al programa PATS.</li><li>Acceso a farmacia PATS con costos reducidos de medicamentos genéricos.</li><li>Imagenología y laboratorios ilimitados con costos preferenciales.</li><li>Acceso a cirugías con cuota de recuperación preferente, con o sin honorarios médicos incluidos según corresponda.</li></ul>\r\n  <p>Dichos servicios generarán, por evento, el pago de una cuota con cargo a “EL AFILIADO”, misma que resultará de aplicar los porcentajes de descuento que se desprenden del ANEXO 4 del presente contrato a los precios publicados al público en general o los precios preferenciales indicados.</p>\r\n  <p>Mientras “LA TARJETA DE DESCUENTO” se encuentre vigente, “EL AFILIADO” gozará de todos los beneficios que la misma le otorga; sin embargo, para el caso de que requiera cirugía o procedimiento quirúrgico en quirófano, deberá haber sufragado por adelantado la adquisición de “LA TARJETA DE DESCUENTO” por un periodo de 12 (doce) meses y encontrarse dentro de dicho periodo de vigencia.</p>\r\n\r\n  <h4>QUINTA.- OBLIGACIONES DE “EL PRESTADOR”.</h4>\r\n  <p>“EL PRESTADOR” se obliga a: (i) otorgar a “EL AFILIADO” el acceso ilimitado a “LA TARJETA DE DESCUENTO” durante la vigencia del contrato; (ii) mantener actualizada y operativa la Red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla; (iii) proporcionar a “EL AFILIADO”, de forma digital, “LA TARJETA DE DESCUENTO” dentro de los 5 (cinco) días hábiles siguientes al primer pago; e (iv) informar por escrito cualquier modificación a la red de hospitales o al tabulador de cuotas con al menos 10 (diez) días de anticipación.</p>\r\n\r\n  <h4>SEXTA.- OBLIGACIONES DE “EL AFILIADO”.</h4>\r\n  <p>“EL AFILIADO” se obliga a: (i) pagar puntualmente el precio de “LA TARJETA DE DESCUENTO”; (ii) utilizarla de forma exclusiva, personal e intransferible; (iii) cubrir directamente a los hospitales y con anterioridad a recibir el servicio médico las cuotas de recuperación según tabulador vigente; (iv) presentar identificación oficial y “LA TARJETA DE DESCUENTO” o código QR cada vez que haga uso de beneficios; y (v) notificar por escrito cualquier cambio de domicilio o datos de contacto en un plazo no mayor a 5 (cinco) días.</p>\r\n\r\n  <h4>SÉPTIMA.- ACCESO A LOS BENEFICIOS Y PROCEDIMIENTO.</h4>\r\n  <p>Para hacer uso de “LA TARJETA DE DESCUENTO”, “EL AFILIADO” deberá agendar sus citas directamente con los doctores pertenecientes a la Red de Hospitales 50 (FIFTY) Doctors, que en ese momento se encuentren adscritos al programa de beneficios, a través de la aplicación oficial, página de internet oficial de PATS o medios oficiales que indique “EL PRESTADOR”.</p>\r\n  <p>“EL AFILIADO” se obliga a pagar directamente al médico especialista perteneciente al programa el costo de la consulta de especialidad de que se trate, en términos de los porcentajes de descuento del ANEXO 4. En caso de no estar facultado para asistir por fuerza mayor, tendrá un plazo de 30 (treinta) días contados a partir de haber generado la cita para solicitar una nueva consulta médica.</p>\r\n\r\n  <h4>OCTAVA.- EXCLUSIONES Y LIMITACIONES.</h4>\r\n  <p>Los beneficios no incluirán: (i) trasplantes de órganos; (ii) tratamientos experimentales; (iii) tratamientos de oncología a excepción de algunas cirugías; (iv) medicamentos extra hospitalarios que no estén recogidos en el catálogo de Farmacia PATS; (v) atención médica con especialistas no adscritos o no publicados en los medios oficiales; y (vi) cualquier servicio no listado expresamente.</p>\r\n\r\n  <h4>NOVENA.- CAUSAS DE TERMINACIÓN.</h4>\r\n  <p>El contrato podrá terminarse por falta de pago, mutuo consentimiento por escrito o incumplimiento de cualquiera de las cláusulas por cualquiera de “LAS PARTES”. En caso de terminación, “EL AFILIADO” no tendrá derecho a exigir la devolución de cantidad alguna.</p>\r\n\r\n  <h4>DÉCIMA.- CANCELACIÓN VOLUNTARIA.</h4>\r\n  <p>“EL AFILIADO” podrá cancelar “LA TARJETA DE DESCUENTO” mediante aviso por escrito con 30 (treinta) días de anticipación. Dicha cancelación surtirá efectos a partir del siguiente periodo mensual y no generará reembolso de pagos ya realizados.</p>\r\n\r\n  <h4>DÉCIMA PRIMERA.- PROTECCIÓN DE DATOS PERSONALES.</h4>\r\n  <p>“LAS PARTES” acuerdan que el tratamiento de datos personales se sujetará a la Ley Federal de Protección de Datos Personales en Posesión de los Particulares. “EL AFILIADO” autoriza expresamente el uso de sus datos para la gestión de “LA TARJETA DE DESCUENTO”. El aviso de privacidad se integra al presente contrato como ANEXO 5.</p>\r\n\r\n  <h4>DÉCIMA SEGUNDA.- RESPONSABILIDAD.</h4>\r\n  <p>“EL AFILIADO” reconoce y acepta que “LA TARJETA DE DESCUENTO” es emitida y administrada directamente por CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE, quien es responsable de la operación de la red de descuentos, afiliación de prestadores médicos y prestación de cualquier servicio relacionado con “LA TARJETA DE DESCUENTO”.</p>\r\n  <p>En consecuencia, “EL PRESTADOR” no tendrá responsabilidad directa ni indirecta por la prestación, calidad, eficacia, resultado, daño, perjuicio, lesión, complicación, secuela, evento adverso o consecuencia derivada de servicios médicos recibidos, incluyendo aquellos ocasionados por negligencia, impericia o mala praxis de profesionales de la salud o prestadores afiliados. Cualquier relación derivada de la prestación de servicios médicos se establece directamente entre “EL AFILIADO” y los prestadores de servicios de salud correspondientes. Esta limitación subsistirá a la terminación del contrato.</p>\r\n\r\n  <h4>DÉCIMA TERCERA.- PREVENCIÓN DE LAVADO DE DINERO Y ORIGEN DE LOS RECURSOS.</h4>\r\n  <p>“LAS PARTES” declaran bajo protesta de decir verdad que los recursos económicos, bienes y derechos que utilicen para cumplir obligaciones derivadas de este contrato tienen y tendrán origen lícito. “EL AFILIADO” manifiesta que el pago inicial y pagos futuros provienen de fuentes lícitas y no de actividades tipificadas como delitos.</p>\r\n  <p>“LAS PARTES” reconocen que la prestación de servicios de comercio puede ser considerada actividad vulnerable, por lo que se obligan a proporcionar información y documentación requerida para integrar expediente de identificación e informar si tienen conocimiento de la existencia de beneficiario controlador.</p>\r\n\r\n  <h4>DÉCIMA CUARTA.- CONFORMACIÓN DEL EXPEDIENTE DE IDENTIFICACIÓN.</h4>\r\n  <p>“EL PRESTADOR” queda obligado a conformar y mantener un expediente de identificación de “EL AFILIADO”. Para tales efectos, “EL AFILIADO” se obliga a entregar los documentos aplicables: identificación oficial vigente o pasaporte, acta de nacimiento cuando aplique, comprobante de domicilio, constancia de situación fiscal cuando aplique, CURP, y declaración de dueño beneficiario.</p>\r\n  <p>Cuando exista persona responsable, la documentación de identificación y representación deberá integrarse al expediente; la CIF/constancia fiscal corresponde al tutor cuando aplique. “EL PRESTADOR” conservará dicho expediente por un periodo mínimo de 5 (cinco) años contados a partir de que termine la vigencia del contrato o termine por cualquiera de sus causales, garantizando la confidencialidad de los datos personales.</p>\r\n\r\n  <h4>DÉCIMA QUINTA.- CAUSAL ESPECÍFICA DE RESCISIÓN.</h4>\r\n  <p>Será motivo de rescisión inmediata sin necesidad de declaración judicial y sin responsabilidad para la parte afectada cuando cualquiera de “LAS PARTES” se niegue a proporcionar información requerida para cumplimiento de la Ley Federal para la Prevención e Identificación de Operaciones con Recursos de Procedencia Ilícita, proporcione información falsa o aparezca en listas de personas bloqueadas emitidas por autoridad competente.</p>\r\n\r\n  <h4>DÉCIMA SEXTA.- LEGISLACIÓN APLICABLE Y JURISDICCIÓN.</h4>\r\n  <p>“LAS PARTES” establecen que la Procuraduría Federal del Consumidor es competente en vía administrativa para resolver cualquier controversia sobre interpretación o cumplimiento. Sin perjuicio de lo anterior, se someten expresamente a la jurisdicción de los tribunales competentes del fuero común del Distrito Judicial de Puebla, Estado de Puebla, renunciando de manera expresa e irrevocable a cualquier otro fuero o jurisdicción que pudiera corresponderles.</p>\r\n\r\n  <p>Enteradas “LAS PARTES” del contenido y alcance del presente contrato, y entendidas de los derechos y obligaciones que contraen, firman el presente instrumento, incluyendo sus anexos, manifestando que no medió error, dolo, mala fe, violencia o lesión, ni vicio del consentimiento alguno, en la Ciudad de Puebla, Estado de Puebla, reconociendo que la fecha de firma es 13 de mayo de 2026.</p>\r\n\r\n  <div class=\"sign-grid\">\r\n    <div class=\"sign-box\"><div class=\"line\"></div><strong>“EL PRESTADOR”</strong><br>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE<br>Representada por PEDRO AZCÁRRAGA RAMOS</div>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>“EL AFILIADO”</strong><br>Pablo Aja Fresnedo</div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 1<br>Identificación oficial de “EL AFILIADO”</h2><p>Se integra al expediente la identificación oficial cargada por el usuario en el formulario. Para mexicanos, corresponde a identificación oficial/INE cuando aplique. Para extranjeros/no mexicanos, corresponde a identificación oficial o pasaporte vigente; al menos el frente es obligatorio y el reverso será opcional cuando el documento no lo tenga.</p><p><strong>Tipo:</strong> INE. <strong>Emitida por / país emisor:</strong> México. <strong>Número:</strong> DDDD.</p></div>\r\n  <div class=\"annex\"><h2>ANEXO 2<br>COMPROBANTE DE DOMICILIO DE “EL AFILIADO”</h2><p>Se integra al expediente el comprobante de domicilio cargado por el usuario. Domicilio declarado: dddd dd, Col. dd, C.P. 14521, ddd, Puebla, México.</p></div>\r\n  <div class=\"annex\"><h2>ANEXO 3<br>CONSTANCIA DE SITUACIÓN FISCAL DE “EL AFILIADO”</h2><p>Constancia de Situación Fiscal de “EL AFILIADO”, si aplica. En caso de pacientes representados, la constancia fiscal o CIF corresponde a la persona responsable cuando sea aplicable, no al menor. Para afiliados extranjeros/no mexicanos, no será obligatoria salvo que declaren RFC mexicano o residencia fiscal aplicable.</p></div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 4<br>CUOTAS DE RECUPERACIÓN Y/O PRECIOS BASE A CUBRIR A “EL PRESTADOR”</h2>\r\n    <p>En el presente anexo se establecen los porcentajes de descuento a obtener como titular de “LA TARJETA DE DESCUENTO”, por lo que la cantidad a cubrir por “EL AFILIADO” directamente al hospital de la cadena 50 (FIFTY) Doctors o al doctor que preste el servicio se obtendrá de aplicar el porcentaje de descuento correspondiente al precio publicado por los medios oficiales o al precio vigente en el establecimiento.</p>\r\n    <table><tr><th>Servicios / procedimientos</th><th>Descuentos</th></tr><tr><td>Consulta de urgencias</td><td>100%</td></tr><tr><td>Consulta de medicina general</td><td>100%</td></tr><tr><td>Habitación hospitalaria</td><td>90%</td></tr><tr><td>Uso de áreas de urgencias médicas</td><td>80%</td></tr><tr><td>Utilización de cubículos de terapia intensiva (UCIA-UCIN-UCIP)</td><td>75%</td></tr><tr><td>CEYE</td><td>75%</td></tr><tr><td>Uso quirófano</td><td>75%</td></tr><tr><td>Servicio de cuneros</td><td>75%</td></tr><tr><td>Materiales & medicamentos del cuadro básico, genéricos intercambiables</td><td>70%</td></tr><tr><td>Hemodinamia</td><td>70%</td></tr><tr><td>Imagenología</td><td>70%</td></tr><tr><td>Endoprótesis</td><td>70%</td></tr><tr><td>Osteosíntesis</td><td>70%</td></tr><tr><td>Prótesis</td><td>70%</td></tr><tr><td>Órtesis</td><td>70%</td></tr><tr><td>Laboratorio clínico</td><td>60%</td></tr></table>\r\n    <p class=\"small\">Los descuentos aplican con los proveedores suscritos al convenio de Pasaporte a tu Salud.</p>\r\n    <table><tr><th>Servicios / procedimientos</th><th>Precios base</th></tr><tr><td>Consulta de especialidades médicas</td><td>$390.00</td></tr><tr><td>Colposcopía</td><td>$400.00</td></tr><tr><td>Retiro de puntos de sutura</td><td>$80.00</td></tr><tr><td>Aplicación de medicamento intramuscular</td><td>$60.00</td></tr><tr><td>Retiro de DIU</td><td>$500.00</td></tr><tr><td>Colocación de DIU</td><td>$700.00</td></tr><tr><td>Extracción de cuerpo extraño (oído y nariz)</td><td>$300.00</td></tr><tr><td>Lavado ótico</td><td>$250.00</td></tr><tr><td>Curación de sitio quirúrgico</td><td>$250.00</td></tr><tr><td>Retiro de yeso</td><td>$250.00</td></tr><tr><td>Visita día de hospitalización</td><td>$650.00</td></tr><tr><td>Visita de urgencias</td><td>$750.00</td></tr><tr><td>Día de terapia intensiva</td><td>$850.00</td></tr></table>\r\n    <p class=\"small\">Todos los precios incluyen IVA. La factura de servicios hospitalarios será emitida con el desglose correspondiente y el ahorro otorgado por ser titular de “LA TARJETA DE DESCUENTO”.</p>\r\n    <p>Exclusiones y limitaciones: se aplicarán descuentos y precios especiales para el acompañante de “EL AFILIADO” en la misma habitación únicamente para la primera noche de hospitalización. Los precios y porcentajes de descuento darán derecho a la utilización de materiales y medicamentos del cuadro básico, genéricos intercambiables; cualquier otro tipo de medicación será cubierto directamente por “EL AFILIADO”. Los costos de procedimientos quirúrgicos incluyen honorarios médicos cuando así se indique. “EL AFILIADO” podrá atenderse con el médico tratante que elija, debiendo cubrir honorarios directamente a dicho médico, conservando el derecho a beneficios dentro de la red aplicable.</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Firma de aceptación de “EL AFILIADO”</strong><br>Pablo Aja Fresnedo</div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 5<br>AVISO DE PRIVACIDAD</h2>\r\n    <p>En cumplimiento de las disposiciones establecidas en la Ley Federal de Protección de Datos Personales en Posesión de Particulares, su Reglamento y los lineamientos aplicables, “CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE” (en lo sucesivo “EL PRESTADOR”), con domicilio en CALLE PASEO SINFONÍA NÚMERO EXTERIOR 1, LOCAL 2-14, LOMAS DE ANGELÓPOLIS II, SAN ANDRÉS CHOLULA, ESTADO DE PUEBLA, CÓDIGO POSTAL 72830, da a conocer el Aviso de Privacidad al tenor del cual manejará por medio de su representación y/o empleados los datos personales y/o documentación proporcionada por el afiliado o usuario de “LA TARJETA DE DESCUENTO”.</p>\r\n    <p>Se tendrá por aceptado expresamente el presente Aviso de Privacidad una vez proporcionados los datos personales y firmada digitalmente la aceptación del contrato, motivo por el cual “EL PRESTADOR” estará facultado para manejar la información conforme a la legislación aplicable.</p>\r\n    <h4>Modificación del aviso de privacidad</h4><p>Este aviso podrá ser modificado o adecuado a las necesidades de “EL PRESTADOR”. Las modificaciones o actualizaciones serán incorporadas al presente aviso y estarán disponibles en la página de internet, domicilio de “EL PRESTADOR” o serán enviadas al último correo electrónico proporcionado.</p>\r\n    <h4>Finalidad de la información</h4><p>La información será utilizada para: elaborar y mantener actualizada la base de usuarios; identificar afiliados; proporcionar la tarjeta digital; otorgar acceso al programa de beneficios; informar modificaciones a la red o tabulador; realizar análisis estadísticos internos y brindar un óptimo servicio médico.</p>\r\n    <h4>Tipo de datos necesarios</h4><p>Se solicitarán datos de identificación, contacto, legales, contractuales y fiscales cuando aplique, incluyendo nombre completo, lugar y fecha de nacimiento, firma, identificación oficial, nacionalidad, CURP y RFC cuando sean aplicables, domicilio, teléfono y correo electrónico.</p>\r\n    <h4>Transferencias de la información</h4><p>El usuario autoriza proporcionar información sin consentimiento adicional en los casos previstos por ley, resolución de autoridad competente, tratados aplicables, salvaguarda de interés público, procuración o administración de justicia, reconocimiento o defensa de derechos en procesos judiciales, y a socios comerciales, técnicos o estratégicos que asuman obligaciones de confidencialidad y seguridad equivalentes.</p>\r\n    <h4>Limitación del uso o divulgación de datos y derechos ARCO</h4><p>El usuario podrá limitar el uso o divulgación de sus datos personales y ejercer derechos de acceso, rectificación, cancelación u oposición mediante solicitud escrita dirigida a “EL PRESTADOR” en su domicilio o al correo silvia@pasaporteatusalud.com, acompañando documento que acredite su identidad.</p>\r\n    <h4>Revocación de consentimiento</h4><p>El usuario podrá revocar su consentimiento siguiendo el mismo procedimiento, considerando que para ciertos fines la revocación puede implicar la cancelación de “LA TARJETA DE DESCUENTO” y la imposibilidad de acceder al programa.</p>\r\n    <p><strong>Nombre:</strong> Pablo Aja Fresnedo<br><strong>Fecha:</strong> 13 de mayo de 2026</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Firma</strong></div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 6<br>DECLARACIÓN DE DUEÑO BENEFICIARIO</h2>\r\n    <p>DE CONFORMIDAD CON LO DISPUESTO EN LOS ARTÍCULOS 18 FRACCIÓN I Y III DE LA LEY FEDERAL PARA PREVENCIÓN E IDENTIFICACIÓN DE OPERACIONES CON RECURSOS DE PROCEDENCIA ILÍCITA, EL ARTÍCULO 15 DE SU REGLAMENTO Y EL ARTÍCULO 13 DE LAS REGLAS DE CARÁCTER GENERAL, MANIFIESTO BAJO PROTESTA DE DECIR VERDAD:</p>\r\n    <h4>Datos de identificación del cliente</h4>\r\n    <table><tr><th>Campo</th><th>Respuesta</th></tr><tr><td>Apellido paterno, materno y nombre(s)</td><td>Pablo Aja Fresnedo</td></tr><tr><td>Fecha de nacimiento</td><td>1981-12-12</td></tr><tr><td>País de nacimiento</td><td>México</td></tr><tr><td>Nacionalidad</td><td>mexicana</td></tr><tr><td>Actividad, ocupación o profesión</td><td>ddd</td></tr><tr><td>Estado civil</td><td>SOLTERO(A)</td></tr><tr><td>Domicilio particular</td><td>dddd dd, Col. dd, C.P. 14521, ddd, Puebla, México</td></tr><tr><td>Teléfonos</td><td>1111111111</td></tr><tr><td>Correo electrónico</td><td>pabloajaf@gmail.com</td></tr><tr><td>CURP</td><td>DD</td></tr><tr><td>RFC</td><td>DDDD</td></tr><tr><td>Tipo de identificación</td><td>INE</td></tr><tr><td>Emitida por / país emisor</td><td>México</td></tr><tr><td>Número de identificación</td><td>DDDD</td></tr></table>\r\n    <h4>Datos de identificación de la operación</h4>\r\n    <table><tr><th>Campo</th><th>Respuesta</th></tr><tr><td>Tipo de operación</td><td>Adquisición de tarjeta de descuento PATS</td></tr><tr><td>Monto de operación</td><td>$9,600.00 M.N.</td></tr><tr><td>Fecha de operación</td><td>13 de mayo de 2026</td></tr><tr><td>Forma de pago</td><td>Pasarela / medio autorizado por “EL PRESTADOR”</td></tr><tr><td>Moneda</td><td>MXN</td></tr></table>\r\n    <h4>Información de la existencia del dueño beneficiario o beneficiario controlador</h4>\r\n    <p>Declaro que soy el beneficiario directo de la operación y no existe ningún otro dueño beneficiario o beneficiario controlador: <strong>SI</strong>.</p>\r\n    <h4>Aviso de privacidad</h4><p>Los datos personales serán protegidos y tratados conforme al Aviso de Privacidad contenido en el cuerpo del presente contrato y la legislación aplicable.</p>\r\n    <p>H. Puebla de Zaragoza al 13 del mes de mayo del año 2026.</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Nombre y firma</strong><br>Pablo Aja Fresnedo</div>\r\n  </div>\r\n\r\n  \r\n  </div>\r\n', 'data:image/png;base64,', 'Pablo Aja Fresnedo', '9b23423f2b4a1a39b1f4ef48a18d1466aefb63e14c7453c5e2e6c7893144f17b', '2026-05-13 14:53:53', '189.190.218.123', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:150.0) Gecko/20100101 Firefox/150.0', '', 'firmado', '2026-05-13 14:53:53', '2026-05-13 14:53:53');
INSERT INTO `pats_contratos_firmados` (`id_contrato_firmado`, `id_orden`, `id_pasaporte`, `id_distribuidor`, `id_franquicia`, `token_publico`, `contrato_clave`, `contrato_version`, `html_contrato_renderizado`, `firma_afiliado_base64`, `nombre_firmante`, `hash_contrato`, `fecha_firma`, `ip_firma`, `user_agent_firma`, `pdf_path`, `estatus`, `created_at`, `updated_at`) VALUES
(11, 1, 1, 0, 0, '', 'contrato_pats_base', '1.0', '<style>\r\n  .pats-contract{font-family:Arial,Helvetica,sans-serif;color:#172033;font-size:12px;line-height:1.52;background:#fff;padding:4px}\r\n  .pats-contract h1,.pats-contract h2,.pats-contract h3,.pats-contract h4{text-align:center;margin:12px 0 8px;color:#0d1b3e}\r\n  .pats-contract h1{font-size:16px;text-transform:uppercase;letter-spacing:.05em}\r\n  .pats-contract h2{font-size:15px;text-transform:uppercase;letter-spacing:.04em}\r\n  .pats-contract h3{font-size:13px;text-transform:uppercase;letter-spacing:.08em}\r\n  .pats-contract h4{font-size:12px;text-align:left;text-transform:uppercase;margin-top:12px}\r\n  .pats-contract p{margin:6px 0;text-align:justify}\r\n  .pats-contract ul{margin:6px 0 8px 18px;padding:0}.pats-contract li{margin:4px 0;text-align:justify}\r\n  .pats-contract table{width:100%;border-collapse:collapse;margin:8px 0 12px}.pats-contract th,.pats-contract td{border:1px solid #cbd5e1;padding:6px;vertical-align:top}.pats-contract th{background:#eef4ff;color:#0d1b3e;text-align:left}\r\n  .pats-contract .center{text-align:center}.pats-contract .muted{color:#64748b}.pats-contract .small{font-size:10px}.pats-contract .badge{display:inline-block;padding:3px 8px;border-radius:999px;background:#eef4ff;color:#1d4ed8;font-weight:700;margin:2px 4px 2px 0}\r\n  .pats-contract .sign-grid{display:grid;grid-template-columns:1fr 1fr;gap:22px;margin-top:28px}.pats-contract .sign-box{text-align:center;min-height:95px}.pats-contract .line{border-top:1px solid #0f172a;margin:48px 8px 6px}.pats-contract .signature-img{max-width:220px;max-height:82px;display:block;margin:0 auto 4px}\r\n  .pats-contract .annex{page-break-before:auto;border-top:2px solid #0d1b3e;margin-top:18px;padding-top:12px}.pats-contract .page-break{page-break-before:always;border-top:1px dashed #cbd5e1;margin-top:18px;padding-top:12px}\r\n</style>\r\n<div class=\"pats-contract\">\r\n  <h1>Carátula del contrato de adquisición de tarjeta de descuento</h1>\r\n  <p>CARÁTULA DEL CONTRATO DE ADQUISICIÓN DE TARJETA DE DESCUENTO (EN LO SUCESIVO “LA CARÁTULA”), QUE CELEBRAN POR UNA PARTE LA SOCIEDAD SEÑALADA EN EL APARTADO 1.- DE LA CARÁTULA, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL PRESTADOR”, REPRESENTADA EN ESTE ACTO POR LA PERSONA FÍSICA QUE SE INDICA EN EL APARTADO 2.- DE LA CARÁTULA; Y POR LA OTRA PARTE, LA PERSONA FÍSICA SEÑALADA EN EL APARTADO 5.- DE LA CARÁTULA, POR SU PROPIO DERECHO, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL AFILIADO”; Y CUANDO LOS ANTES NOMBRADOS ACTÚEN DE MANERA CONJUNTA, SE LES DENOMINARÁ COMO “LAS PARTES”; QUIENES SE SUJETAN AL TENOR DE LA CARÁTULA, DECLARACIONES Y CLÁUSULAS SIGUIENTES:</p>\r\n    \r\n  <h2>C A R Á T U L A</h2>\r\n  <table>\r\n    <tr><th style=\"width:8%\">Apartado</th><th style=\"width:42%\">Definición</th><th>Respuesta</th></tr>\r\n    <tr><td>1.-</td><td>Nombre de “EL PRESTADOR”</td><td>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE</td></tr>\r\n    <tr><td>2.-</td><td>Nombre del Representante Legal de “EL PRESTADOR”</td><td>PEDRO AZCÁRRAGA RAMOS</td></tr>\r\n    <tr><td>3.-</td><td>Domicilio de “EL PRESTADOR”</td><td>CALLE PASEO SINFONÍA NÚMERO EXTERIOR 1, LOCAL 2-14, LOMAS DE ANGELÓPOLIS II, SAN ANDRÉS CHOLULA, ESTADO DE PUEBLA, CÓDIGO POSTAL 72830</td></tr>\r\n    <tr><td>4.-</td><td>Clave del Registro Federal de Contribuyentes de “EL PRESTADOR”</td><td>COH2202144H5</td></tr>\r\n    <tr><td>5.-</td><td>Nombre de “EL AFILIADO”</td><td>Juan Carlos Fuentes Moya</td></tr>\r\n    <tr><td>6.-</td><td>Domicilio de “EL AFILIADO”</td><td>Avellaneada 118, Col. Valle imperaial, C.P. 14521, Zapopan, Jalisco, México</td></tr>\r\n    <tr><td>7.-</td><td>Clave del Registro Federal de Contribuyentes de “EL AFILIADO”</td><td>FUMJ9810822NR</td></tr>\r\n    <tr><td>8.-</td><td>Costo mensual de “LA TARJETA DE DESCUENTO”</td><td>$800.00 M.N.</td></tr>\r\n    <tr><td>9.-</td><td>Cuenta bancaria de “EL PRESTADOR” para pagos</td><td>Cuenta: 01600866709<br>CLABE: 042650016008667096<br>Institución Bancaria: Banca Mifel, S.A., Institución de Banca Múltiple, Grupo Financiero Mifel</td></tr>\r\n    <tr><td>10.-</td><td>Cuota de Reactivación de “LA TARJETA DE DESCUENTO”</td><td>$100.00 M.N. por cada mes que se haya interrumpido el pago.</td></tr>\r\n    <tr><td>11.-</td><td>Datos de la Tarjeta de Crédito de “EL AFILIADO”</td><td>Número de tarjeta: pendiente de confirmar por pasarela/token de pago.<br>Institución bancaria: pendiente de confirmar por pasarela. <br><span class=\"small\">No se almacena número completo de tarjeta en este formulario.</span></td></tr>\r\n    <tr><td>12.-</td><td>Anexos</td><td>ANEXO 1. Identificación oficial de “EL AFILIADO”<br>ANEXO 2. Comprobante de domicilio de “EL AFILIADO”<br>ANEXO 3. Constancia de Situación Fiscal de “EL AFILIADO”, si aplica<br>ANEXO 4. Cuotas de recuperación y/o precios base a cubrir a “EL PRESTADOR”<br>ANEXO 5. Aviso de privacidad<br>ANEXO 6. Declaración de dueño beneficiario</td></tr>\r\n    <tr><td>13.-</td><td>Fecha de Firma del Contrato</td><td>13 de mayo de 2026</td></tr>\r\n  </table>\r\n\r\n  <div class=\"sign-grid\">\r\n    <div class=\"sign-box\"><div class=\"line\"></div><strong>“EL PRESTADOR”</strong><br>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE<br>Representada por PEDRO AZCÁRRAGA RAMOS</div>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>“EL AFILIADO”</strong><br>Juan Carlos Fuentes Moya<br><span class=\"small\">La persona física señalada en el Apartado 5.- de la Carátula</span></div>\r\n  </div>\r\n\r\n  <div class=\"page-break\"></div>\r\n  <h1>Contrato de adquisición de tarjeta de descuento</h1>\r\n  <p>CONTRATO DE ADQUISICIÓN DE TARJETA DE DESCUENTO, QUE CELEBRAN POR UNA PARTE LA SOCIEDAD SEÑALADA EN EL APARTADO 1.- DE LA CARÁTULA, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL PRESTADOR”, REPRESENTADA EN ESTE ACTO POR LA PERSONA FÍSICA QUE SE INDICA EN EL APARTADO 2.- DE LA CARÁTULA; Y POR LA OTRA PARTE, LA PERSONA FÍSICA SEÑALADA EN EL APARTADO 5.- DE LA CARÁTULA, POR SU PROPIO DERECHO, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL AFILIADO”; Y CUANDO LOS ANTES NOMBRADOS ACTÚEN DE MANERA CONJUNTA, SE LES DENOMINARÁ COMO “LAS PARTES”; QUIENES SE SUJETAN AL TENOR DE LAS DECLARACIONES Y CLÁUSULAS SIGUIENTES:</p>\r\n\r\n  <h2>D E C L A R A C I O N E S</h2>\r\n  <h4>I.- Declara “EL PRESTADOR” por conducto de su representación:</h4>\r\n  <p>A. Que, su representada es una sociedad mercantil constituida conforme a las leyes de los Estados Unidos Mexicanos, según consta en la escritura pública número 39,861, del volumen 830 de fecha catorce de febrero de dos mil veintidós, otorgada ante la fe del Licenciado Ernesto Joaquín Briones Amador, Notario Público Titular de la Notaría Pública número 46 de las del Distrito Judicial de Puebla, Estado de Puebla, cuyo primer testimonio se encuentra inscrito ante las oficinas del Registro Público de Comercio del Distrito Judicial de Puebla, Estado de Puebla, bajo el Folio Mercantil Electrónico: N-2022022991, por virtud del cual se llevó a cabo la Constitución de la persona moral denominada CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE.</p>\r\n  <p>B. Que, la persona física que la representa en este acto, señalada en el Apartado 2.- de la Carátula, cuenta con todas y cada una de las facultades necesarias para la celebración del presente contrato, las cuales se desprenden del instrumento descrito en el punto declarativo inmediato anterior, mismas que manifiesta bajo protesta de decir verdad que no le han sido suspendidas, revocadas o limitadas en forma alguna.</p>\r\n  <p>C. Que, su representada tiene como domicilio fiscal el señalado en el Apartado 3.- de la Carátula del presente contrato, mismo que designa como domicilio convencional para cualquier cuestión relacionada con la celebración del presente contrato.</p>\r\n  <p>D. Que, su representada se encuentra inscrita en el Registro Federal de Contribuyentes bajo la clave señalada en el Apartado 4.- de la Carátula.</p>\r\n  <p>E. Que, ha desarrollado y es su deseo comparecer a la celebración del presente instrumento con la finalidad de enajenar en favor de “EL AFILIADO”, una Tarjeta de Descuento que da acceso a “UN PROGRAMA DE BENEFICIOS QUE OTORGA DESCUENTOS A LOS COSTOS Y PERMITE RECIBIR SERVICIOS MÉDICOS PRIVADOS DE ALTA CALIDAD DE FORMA ACCESIBLE, CLARA Y SIN RESTRICCIONES DENTRO DE LA RED DE HOSPITALES 50 (FIFTY) DOCTORS CON SEDE EN EL ESTADO DE PUEBLA”, en lo sucesivo “LA TARJETA DE DESCUENTO”, en los términos y condiciones que se establecerán más adelante.</p>\r\n  <p>F. Que, su representada no es una Aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas sino una empresa dedicada, entre otros, a la operación y administración de establecimientos destinados a la atención y asistencia de enfermos, por lo que la enajenación de “LA TARJETA DE DESCUENTO” únicamente constituye un acto de comercio que brindará a “EL AFILIADO” acceso a un programa de beneficios como ha quedado descrito anteriormente.</p>\r\n\r\n  <h4>II.- Declara “EL AFILIADO”, por su propio derecho:</h4>\r\n      <p>A. Que, su nombre se señala en el Apartado 5.- de la Carátula, es una persona física de nacionalidad mexicana, en pleno ejercicio de sus derechos, legal y jurídicamente capaz para celebrar el presente Contrato, quien se identifica con credencial para votar vigente expedida por el Instituto Nacional Electoral, tipo INE, número INEAAAA, que en copia simple o archivo digital se agrega al cuerpo del presente contrato como ANEXO 1.</p>\r\n    <p>B. Que, tiene como domicilio particular el señalado en el Apartado 6.- de la Carátula, mismo que designa como domicilio convencional para cualquier cuestión relacionada con la celebración del presente contrato, tal y como lo acredita con el comprobante de domicilio que en copia simple o archivo digital se agrega al cuerpo del presente contrato como ANEXO 2.</p>\r\n  <p>C. Que, su CURP es DDDDDDDD y su RFC/identificación fiscal es FUMJ9810822NR; asimismo manifiesta que cuenta con capacidad económica para obligarse en términos del presente contrato y que los recursos con los que cubrirá sus obligaciones provendrán de fuentes lícitas. En caso de nacionalidad extranjera/no mexicana, se tendrán por no aplicables CURP, INE y constancia fiscal mexicana salvo manifestación expresa de residencia fiscal o RFC mexicano.</p>\r\n  <p>D. Que, es su deseo comparecer a la celebración del presente instrumento con la finalidad de adquirir “LA TARJETA DE DESCUENTO” de acuerdo con los términos y condiciones que se establecen a continuación.</p>\r\n  <p>E. Que, previo a la celebración del presente contrato fue informado y manifiesta expresamente que reconoce que “EL PRESTADOR” no es una Aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas y que las actividades comerciales objeto del presente contrato no consisten en la contratación de un seguro, de la índole que fuere, sino que únicamente implica la adquisición de una tarjeta de descuento que da acceso a un programa de beneficios que otorga descuentos a los costos y permite recibir servicios médicos privados de alta calidad de forma accesible, clara y sin restricciones dentro de la red de hospitales 50 (FIFTY) Doctors con sede en el Estado de Puebla.</p>\r\n  <p>F. Que, reconoce que “EL PRESTADOR” se dedica a la operación de centros hospitalarios y que la emisión de “LA TARJETA DE DESCUENTO” únicamente corresponde a la intención de este último de crear un programa de descuentos para el acceso a los servicios prestados por la Red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla.</p>\r\n\r\n  <h4>III.- Declaran conjuntamente “LAS PARTES”:</h4>\r\n  <p>1. Que, se reconocen recíprocamente la personalidad con la que comparecen a la celebración del presente acuerdo de voluntades.</p>\r\n  <p>2. Que, el presente contrato es el instrumento que las vincula en sus derechos y obligaciones.</p>\r\n  <p>3. Que, es su deseo celebrar el presente contrato y han negociado libremente los términos y condiciones del mismo con pleno conocimiento de sus alcances e implicaciones jurídicas, por lo que en su celebración no existe dolo, error, mala fe, lesión o cualquier otro vicio del consentimiento que pudiese afectarlo de inexistencia o nulidad.</p>\r\n\r\n  <h2>C L Á U S U L A S</h2>\r\n  <h4>PRIMERA.- OBJETO.</h4>\r\n  <p>El objeto del presente Contrato es que “EL AFILIADO” adquiera de “EL PRESTADOR”, a título oneroso y temporal, el derecho de uso ilimitado y sin restricción alguna de “LA TARJETA DE DESCUENTO” emitida por CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE, la cual consiste en que “EL AFILIADO” aproveche y acceda a “UN PROGRAMA DE BENEFICIOS QUE OTORGA DESCUENTOS A LOS COSTOS Y PERMITE RECIBIR SERVICIOS MÉDICOS PRIVADOS DE ALTA CALIDAD DE FORMA ACCESIBLE, CLARA Y SIN RESTRICCIONES DENTRO DE LA RED DE HOSPITALES 50 (FIFTY) DOCTORS CON SEDE EN EL ESTADO DE PUEBLA”.</p>\r\n  <p>Estableciendo que, la comercialización de “LA TARJETA DE DESCUENTO” por parte de “EL PRESTADOR” en ningún momento constituirá la venta, promoción o por cualquier medio la contratación de una póliza de seguro, bajo el entendido de que “EL PRESTADOR” no es una aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas (CNSF); sino que comercializa “LA TARJETA DE DESCUENTO” en favor de terceros con la finalidad de otorgar descuentos a los precios respecto de los servicios médicos que presta en el territorio nacional.</p>\r\n\r\n  <h4>SEGUNDA.- PRECIO DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“LAS PARTES” establecen de común acuerdo que “LA TARJETA DE DESCUENTO” tendrá como costo mensual la cantidad señalada en el Apartado 8.- de la Carátula del presente contrato; cantidad que ya incluye IVA, y la cual deberá ser cubierta por “EL AFILIADO” en favor de “EL PRESTADOR” dentro de los primeros 5 (cinco) días de cada mes, sin necesidad de gestiones o avisos de cobro, ya sea mediante:</p>\r\n  <p>(i) Transferencia electrónica de fondos a la cuenta bancaria señalada en el Apartado 9.- de la Carátula del presente contrato y de la cual es titular “EL PRESTADOR”.</p>\r\n  <p>(ii) Cheque que se recibirá salvo buen cobro en el Domicilio de “EL PRESTADOR” señalado en el Apartado 3.- de la Carátula del presente contrato, y que en caso de no ser pagado por falta de fondos suficientes o por otras causas imputables a “EL AFILIADO”, éste último está de acuerdo en que deberá cubrir a “EL PRESTADOR” el 20% (veinte por ciento) del monto del cheque por concepto de indemnización por daños y perjuicios en términos del artículo 193 de la Ley General de Títulos y Operaciones de Crédito, independientemente de cualquier otro cargo que se pudiera generar.</p>\r\n  <p>(iii) Cargos mensuales automáticos recurrentes a la tarjeta de crédito de “EL AFILIADO” según los datos señalados en el Apartado 11.- de la Carátula del presente contrato, quien manifiesta bajo protesta de decir verdad que autoriza a “EL PRESTADOR” a realizar los cargos mensuales correspondientes por el costo mensual de “LA TARJETA DE DESCUENTO” en dicha tarjeta o en la tarjeta que por renovación, reposición, robo o extravío le haya asignado el banco emisor. La autorización estará vigente mientras “EL AFILIADO” no haya notificado a “EL PRESTADOR” por escrito y con acuse de recibo su deseo de cancelar su afiliación o no renovarla, o en su defecto, realizar su baja respectiva en el sitio web o aplicación de “EL PRESTADOR”.</p>\r\n  <p>Esta autorización no exime a “EL AFILIADO” del pago mensual por el uso de “LA TARJETA DE DESCUENTO” y demás obligaciones contractuales, por lo que, en caso de que el cobro no sea autorizado por el banco emisor o por cualquier razón no pueda realizarse, “EL AFILIADO” deberá notificar tal situación a “EL PRESTADOR” a la dirección de correo electrónico silvia@pasaporteatusalud.com, a efecto de solicitar una forma de pago diversa, quedando obligado a cubrir de inmediato el pago correspondiente.</p>\r\n  <p>(iv) Cualquier otro medio de pago aceptado por “EL PRESTADOR”, mismo que se dará a conocer a través de sus medios oficiales de comunicación.</p>\r\n  <p>“EL PRESTADOR” podrá variar unilateralmente el costo mensual de “LA TARJETA DE DESCUENTO”, previo aviso a “EL AFILIADO” con 30 (treinta) días de anticipación a través de sus medios oficiales de comunicación.</p>\r\n  <p>Para el caso de que “EL AFILIADO” adquiera y cubra el precio de “LA TARJETA DE DESCUENTO” y posteriormente deje de pagar una mensualidad, deberá cubrir a “EL PRESTADOR”, por concepto de cuota de reactivación, la cantidad señalada en el Apartado 10.- de la Carátula por cada mes que haya interrumpido y/o no haya cubierto el precio de “LA TARJETA DE DESCUENTO”, hasta la fecha en que pretenda volver a adquirirla.</p>\r\n\r\n  <h4>TERCERA.- VIGENCIA DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“LA TARJETA DE DESCUENTO” objeto del presente contrato tendrá una vigencia de 30 días contados a partir de que “EL AFILIADO” cubra a “EL PRESTADOR” el precio establecido anteriormente, en el entendido de que la vigencia del presente contrato y de “LA TARJETA DE DESCUENTO” se prorrogarán automáticamente sin necesidad de celebrar documento adicional entre “LAS PARTES” siempre y cuando “EL AFILIADO” cubra, de mes en mes o en la frecuencia contratada, el precio vigente de “LA TARJETA DE DESCUENTO”.</p>\r\n  <p>“EL AFILIADO” tendrá derecho a revocar su consentimiento dentro de los 5 (cinco) días siguientes a la entrega de “LA TARJETA DE DESCUENTO” o la firma del presente contrato, lo que ocurra último, sin responsabilidad alguna, siempre y cuando no haya obtenido beneficio alguno por el uso de “LA TARJETA DE DESCUENTO”.</p>\r\n\r\n  <h4>CUARTA.- BENEFICIOS DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“EL AFILIADO”, de forma exclusiva, personal e intransferible, gozará de forma gratuita de los servicios que se mencionan a continuación:</p>\r\n  <ul><li>Consultas gratuitas ilimitadas de medicina general (no de especialidad) en la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla, únicamente con los doctores afiliados al programa de Pasaporte a tu Salud.</li><li>Consultas de urgencia gratuitas en la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla.</li></ul>\r\n  <p>No así respecto de los servicios que, de manera enunciativa más no limitativa, se describen a continuación:</p>\r\n  <ul><li>Hospitalización dentro de la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla, sujeto a la disponibilidad de cada uno de ellos.</li><li>Consultas de especialidad ilimitadas a costo preferencial, con médicos especialistas pertenecientes al programa PATS.</li><li>Acceso a farmacia PATS con costos reducidos de medicamentos genéricos.</li><li>Imagenología y laboratorios ilimitados con costos preferenciales.</li><li>Acceso a cirugías con cuota de recuperación preferente, con o sin honorarios médicos incluidos según corresponda.</li></ul>\r\n  <p>Dichos servicios generarán, por evento, el pago de una cuota con cargo a “EL AFILIADO”, misma que resultará de aplicar los porcentajes de descuento que se desprenden del ANEXO 4 del presente contrato a los precios publicados al público en general o los precios preferenciales indicados.</p>\r\n  <p>Mientras “LA TARJETA DE DESCUENTO” se encuentre vigente, “EL AFILIADO” gozará de todos los beneficios que la misma le otorga; sin embargo, para el caso de que requiera cirugía o procedimiento quirúrgico en quirófano, deberá haber sufragado por adelantado la adquisición de “LA TARJETA DE DESCUENTO” por un periodo de 12 (doce) meses y encontrarse dentro de dicho periodo de vigencia.</p>\r\n\r\n  <h4>QUINTA.- OBLIGACIONES DE “EL PRESTADOR”.</h4>\r\n  <p>“EL PRESTADOR” se obliga a: (i) otorgar a “EL AFILIADO” el acceso ilimitado a “LA TARJETA DE DESCUENTO” durante la vigencia del contrato; (ii) mantener actualizada y operativa la Red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla; (iii) proporcionar a “EL AFILIADO”, de forma digital, “LA TARJETA DE DESCUENTO” dentro de los 5 (cinco) días hábiles siguientes al primer pago; e (iv) informar por escrito cualquier modificación a la red de hospitales o al tabulador de cuotas con al menos 10 (diez) días de anticipación.</p>\r\n\r\n  <h4>SEXTA.- OBLIGACIONES DE “EL AFILIADO”.</h4>\r\n  <p>“EL AFILIADO” se obliga a: (i) pagar puntualmente el precio de “LA TARJETA DE DESCUENTO”; (ii) utilizarla de forma exclusiva, personal e intransferible; (iii) cubrir directamente a los hospitales y con anterioridad a recibir el servicio médico las cuotas de recuperación según tabulador vigente; (iv) presentar identificación oficial y “LA TARJETA DE DESCUENTO” o código QR cada vez que haga uso de beneficios; y (v) notificar por escrito cualquier cambio de domicilio o datos de contacto en un plazo no mayor a 5 (cinco) días.</p>\r\n\r\n  <h4>SÉPTIMA.- ACCESO A LOS BENEFICIOS Y PROCEDIMIENTO.</h4>\r\n  <p>Para hacer uso de “LA TARJETA DE DESCUENTO”, “EL AFILIADO” deberá agendar sus citas directamente con los doctores pertenecientes a la Red de Hospitales 50 (FIFTY) Doctors, que en ese momento se encuentren adscritos al programa de beneficios, a través de la aplicación oficial, página de internet oficial de PATS o medios oficiales que indique “EL PRESTADOR”.</p>\r\n  <p>“EL AFILIADO” se obliga a pagar directamente al médico especialista perteneciente al programa el costo de la consulta de especialidad de que se trate, en términos de los porcentajes de descuento del ANEXO 4. En caso de no estar facultado para asistir por fuerza mayor, tendrá un plazo de 30 (treinta) días contados a partir de haber generado la cita para solicitar una nueva consulta médica.</p>\r\n\r\n  <h4>OCTAVA.- EXCLUSIONES Y LIMITACIONES.</h4>\r\n  <p>Los beneficios no incluirán: (i) trasplantes de órganos; (ii) tratamientos experimentales; (iii) tratamientos de oncología a excepción de algunas cirugías; (iv) medicamentos extra hospitalarios que no estén recogidos en el catálogo de Farmacia PATS; (v) atención médica con especialistas no adscritos o no publicados en los medios oficiales; y (vi) cualquier servicio no listado expresamente.</p>\r\n\r\n  <h4>NOVENA.- CAUSAS DE TERMINACIÓN.</h4>\r\n  <p>El contrato podrá terminarse por falta de pago, mutuo consentimiento por escrito o incumplimiento de cualquiera de las cláusulas por cualquiera de “LAS PARTES”. En caso de terminación, “EL AFILIADO” no tendrá derecho a exigir la devolución de cantidad alguna.</p>\r\n\r\n  <h4>DÉCIMA.- CANCELACIÓN VOLUNTARIA.</h4>\r\n  <p>“EL AFILIADO” podrá cancelar “LA TARJETA DE DESCUENTO” mediante aviso por escrito con 30 (treinta) días de anticipación. Dicha cancelación surtirá efectos a partir del siguiente periodo mensual y no generará reembolso de pagos ya realizados.</p>\r\n\r\n  <h4>DÉCIMA PRIMERA.- PROTECCIÓN DE DATOS PERSONALES.</h4>\r\n  <p>“LAS PARTES” acuerdan que el tratamiento de datos personales se sujetará a la Ley Federal de Protección de Datos Personales en Posesión de los Particulares. “EL AFILIADO” autoriza expresamente el uso de sus datos para la gestión de “LA TARJETA DE DESCUENTO”. El aviso de privacidad se integra al presente contrato como ANEXO 5.</p>\r\n\r\n  <h4>DÉCIMA SEGUNDA.- RESPONSABILIDAD.</h4>\r\n  <p>“EL AFILIADO” reconoce y acepta que “LA TARJETA DE DESCUENTO” es emitida y administrada directamente por CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE, quien es responsable de la operación de la red de descuentos, afiliación de prestadores médicos y prestación de cualquier servicio relacionado con “LA TARJETA DE DESCUENTO”.</p>\r\n  <p>En consecuencia, “EL PRESTADOR” no tendrá responsabilidad directa ni indirecta por la prestación, calidad, eficacia, resultado, daño, perjuicio, lesión, complicación, secuela, evento adverso o consecuencia derivada de servicios médicos recibidos, incluyendo aquellos ocasionados por negligencia, impericia o mala praxis de profesionales de la salud o prestadores afiliados. Cualquier relación derivada de la prestación de servicios médicos se establece directamente entre “EL AFILIADO” y los prestadores de servicios de salud correspondientes. Esta limitación subsistirá a la terminación del contrato.</p>\r\n\r\n  <h4>DÉCIMA TERCERA.- PREVENCIÓN DE LAVADO DE DINERO Y ORIGEN DE LOS RECURSOS.</h4>\r\n  <p>“LAS PARTES” declaran bajo protesta de decir verdad que los recursos económicos, bienes y derechos que utilicen para cumplir obligaciones derivadas de este contrato tienen y tendrán origen lícito. “EL AFILIADO” manifiesta que el pago inicial y pagos futuros provienen de fuentes lícitas y no de actividades tipificadas como delitos.</p>\r\n  <p>“LAS PARTES” reconocen que la prestación de servicios de comercio puede ser considerada actividad vulnerable, por lo que se obligan a proporcionar información y documentación requerida para integrar expediente de identificación e informar si tienen conocimiento de la existencia de beneficiario controlador.</p>\r\n\r\n  <h4>DÉCIMA CUARTA.- CONFORMACIÓN DEL EXPEDIENTE DE IDENTIFICACIÓN.</h4>\r\n  <p>“EL PRESTADOR” queda obligado a conformar y mantener un expediente de identificación de “EL AFILIADO”. Para tales efectos, “EL AFILIADO” se obliga a entregar los documentos aplicables: identificación oficial vigente o pasaporte, acta de nacimiento cuando aplique, comprobante de domicilio, constancia de situación fiscal cuando aplique, CURP, y declaración de dueño beneficiario.</p>\r\n  <p>Cuando exista persona responsable, la documentación de identificación y representación deberá integrarse al expediente; la CIF/constancia fiscal corresponde al tutor cuando aplique. “EL PRESTADOR” conservará dicho expediente por un periodo mínimo de 5 (cinco) años contados a partir de que termine la vigencia del contrato o termine por cualquiera de sus causales, garantizando la confidencialidad de los datos personales.</p>\r\n\r\n  <h4>DÉCIMA QUINTA.- CAUSAL ESPECÍFICA DE RESCISIÓN.</h4>\r\n  <p>Será motivo de rescisión inmediata sin necesidad de declaración judicial y sin responsabilidad para la parte afectada cuando cualquiera de “LAS PARTES” se niegue a proporcionar información requerida para cumplimiento de la Ley Federal para la Prevención e Identificación de Operaciones con Recursos de Procedencia Ilícita, proporcione información falsa o aparezca en listas de personas bloqueadas emitidas por autoridad competente.</p>\r\n\r\n  <h4>DÉCIMA SEXTA.- LEGISLACIÓN APLICABLE Y JURISDICCIÓN.</h4>\r\n  <p>“LAS PARTES” establecen que la Procuraduría Federal del Consumidor es competente en vía administrativa para resolver cualquier controversia sobre interpretación o cumplimiento. Sin perjuicio de lo anterior, se someten expresamente a la jurisdicción de los tribunales competentes del fuero común del Distrito Judicial de Puebla, Estado de Puebla, renunciando de manera expresa e irrevocable a cualquier otro fuero o jurisdicción que pudiera corresponderles.</p>\r\n\r\n  <p>Enteradas “LAS PARTES” del contenido y alcance del presente contrato, y entendidas de los derechos y obligaciones que contraen, firman el presente instrumento, incluyendo sus anexos, manifestando que no medió error, dolo, mala fe, violencia o lesión, ni vicio del consentimiento alguno, en la Ciudad de Puebla, Estado de Puebla, reconociendo que la fecha de firma es 13 de mayo de 2026.</p>\r\n\r\n  <div class=\"sign-grid\">\r\n    <div class=\"sign-box\"><div class=\"line\"></div><strong>“EL PRESTADOR”</strong><br>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE<br>Representada por PEDRO AZCÁRRAGA RAMOS</div>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>“EL AFILIADO”</strong><br>Juan Carlos Fuentes Moya</div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 1<br>Identificación oficial de “EL AFILIADO”</h2><p>Se integra al expediente la identificación oficial cargada por el usuario en el formulario. Para mexicanos, corresponde a identificación oficial/INE cuando aplique. Para extranjeros/no mexicanos, corresponde a identificación oficial o pasaporte vigente; al menos el frente es obligatorio y el reverso será opcional cuando el documento no lo tenga.</p><p><strong>Tipo:</strong> INE. <strong>Emitida por / país emisor:</strong> México. <strong>Número:</strong> INEAAAA.</p></div>\r\n  <div class=\"annex\"><h2>ANEXO 2<br>COMPROBANTE DE DOMICILIO DE “EL AFILIADO”</h2><p>Se integra al expediente el comprobante de domicilio cargado por el usuario. Domicilio declarado: Avellaneada 118, Col. Valle imperaial, C.P. 14521, Zapopan, Jalisco, México.</p></div>\r\n  <div class=\"annex\"><h2>ANEXO 3<br>CONSTANCIA DE SITUACIÓN FISCAL DE “EL AFILIADO”</h2><p>Constancia de Situación Fiscal de “EL AFILIADO”, si aplica. En caso de pacientes representados, la constancia fiscal o CIF corresponde a la persona responsable cuando sea aplicable, no al menor. Para afiliados extranjeros/no mexicanos, no será obligatoria salvo que declaren RFC mexicano o residencia fiscal aplicable.</p></div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 4<br>CUOTAS DE RECUPERACIÓN Y/O PRECIOS BASE A CUBRIR A “EL PRESTADOR”</h2>\r\n    <p>En el presente anexo se establecen los porcentajes de descuento a obtener como titular de “LA TARJETA DE DESCUENTO”, por lo que la cantidad a cubrir por “EL AFILIADO” directamente al hospital de la cadena 50 (FIFTY) Doctors o al doctor que preste el servicio se obtendrá de aplicar el porcentaje de descuento correspondiente al precio publicado por los medios oficiales o al precio vigente en el establecimiento.</p>\r\n    <table><tr><th>Servicios / procedimientos</th><th>Descuentos</th></tr><tr><td>Consulta de urgencias</td><td>100%</td></tr><tr><td>Consulta de medicina general</td><td>100%</td></tr><tr><td>Habitación hospitalaria</td><td>90%</td></tr><tr><td>Uso de áreas de urgencias médicas</td><td>80%</td></tr><tr><td>Utilización de cubículos de terapia intensiva (UCIA-UCIN-UCIP)</td><td>75%</td></tr><tr><td>CEYE</td><td>75%</td></tr><tr><td>Uso quirófano</td><td>75%</td></tr><tr><td>Servicio de cuneros</td><td>75%</td></tr><tr><td>Materiales & medicamentos del cuadro básico, genéricos intercambiables</td><td>70%</td></tr><tr><td>Hemodinamia</td><td>70%</td></tr><tr><td>Imagenología</td><td>70%</td></tr><tr><td>Endoprótesis</td><td>70%</td></tr><tr><td>Osteosíntesis</td><td>70%</td></tr><tr><td>Prótesis</td><td>70%</td></tr><tr><td>Órtesis</td><td>70%</td></tr><tr><td>Laboratorio clínico</td><td>60%</td></tr></table>\r\n    <p class=\"small\">Los descuentos aplican con los proveedores suscritos al convenio de Pasaporte a tu Salud.</p>\r\n    <table><tr><th>Servicios / procedimientos</th><th>Precios base</th></tr><tr><td>Consulta de especialidades médicas</td><td>$390.00</td></tr><tr><td>Colposcopía</td><td>$400.00</td></tr><tr><td>Retiro de puntos de sutura</td><td>$80.00</td></tr><tr><td>Aplicación de medicamento intramuscular</td><td>$60.00</td></tr><tr><td>Retiro de DIU</td><td>$500.00</td></tr><tr><td>Colocación de DIU</td><td>$700.00</td></tr><tr><td>Extracción de cuerpo extraño (oído y nariz)</td><td>$300.00</td></tr><tr><td>Lavado ótico</td><td>$250.00</td></tr><tr><td>Curación de sitio quirúrgico</td><td>$250.00</td></tr><tr><td>Retiro de yeso</td><td>$250.00</td></tr><tr><td>Visita día de hospitalización</td><td>$650.00</td></tr><tr><td>Visita de urgencias</td><td>$750.00</td></tr><tr><td>Día de terapia intensiva</td><td>$850.00</td></tr></table>\r\n    <p class=\"small\">Todos los precios incluyen IVA. La factura de servicios hospitalarios será emitida con el desglose correspondiente y el ahorro otorgado por ser titular de “LA TARJETA DE DESCUENTO”.</p>\r\n    <p>Exclusiones y limitaciones: se aplicarán descuentos y precios especiales para el acompañante de “EL AFILIADO” en la misma habitación únicamente para la primera noche de hospitalización. Los precios y porcentajes de descuento darán derecho a la utilización de materiales y medicamentos del cuadro básico, genéricos intercambiables; cualquier otro tipo de medicación será cubierto directamente por “EL AFILIADO”. Los costos de procedimientos quirúrgicos incluyen honorarios médicos cuando así se indique. “EL AFILIADO” podrá atenderse con el médico tratante que elija, debiendo cubrir honorarios directamente a dicho médico, conservando el derecho a beneficios dentro de la red aplicable.</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Firma de aceptación de “EL AFILIADO”</strong><br>Juan Carlos Fuentes Moya</div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 5<br>AVISO DE PRIVACIDAD</h2>\r\n    <p>En cumplimiento de las disposiciones establecidas en la Ley Federal de Protección de Datos Personales en Posesión de Particulares, su Reglamento y los lineamientos aplicables, “CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE” (en lo sucesivo “EL PRESTADOR”), con domicilio en CALLE PASEO SINFONÍA NÚMERO EXTERIOR 1, LOCAL 2-14, LOMAS DE ANGELÓPOLIS II, SAN ANDRÉS CHOLULA, ESTADO DE PUEBLA, CÓDIGO POSTAL 72830, da a conocer el Aviso de Privacidad al tenor del cual manejará por medio de su representación y/o empleados los datos personales y/o documentación proporcionada por el afiliado o usuario de “LA TARJETA DE DESCUENTO”.</p>\r\n    <p>Se tendrá por aceptado expresamente el presente Aviso de Privacidad una vez proporcionados los datos personales y firmada digitalmente la aceptación del contrato, motivo por el cual “EL PRESTADOR” estará facultado para manejar la información conforme a la legislación aplicable.</p>\r\n    <h4>Modificación del aviso de privacidad</h4><p>Este aviso podrá ser modificado o adecuado a las necesidades de “EL PRESTADOR”. Las modificaciones o actualizaciones serán incorporadas al presente aviso y estarán disponibles en la página de internet, domicilio de “EL PRESTADOR” o serán enviadas al último correo electrónico proporcionado.</p>\r\n    <h4>Finalidad de la información</h4><p>La información será utilizada para: elaborar y mantener actualizada la base de usuarios; identificar afiliados; proporcionar la tarjeta digital; otorgar acceso al programa de beneficios; informar modificaciones a la red o tabulador; realizar análisis estadísticos internos y brindar un óptimo servicio médico.</p>\r\n    <h4>Tipo de datos necesarios</h4><p>Se solicitarán datos de identificación, contacto, legales, contractuales y fiscales cuando aplique, incluyendo nombre completo, lugar y fecha de nacimiento, firma, identificación oficial, nacionalidad, CURP y RFC cuando sean aplicables, domicilio, teléfono y correo electrónico.</p>\r\n    <h4>Transferencias de la información</h4><p>El usuario autoriza proporcionar información sin consentimiento adicional en los casos previstos por ley, resolución de autoridad competente, tratados aplicables, salvaguarda de interés público, procuración o administración de justicia, reconocimiento o defensa de derechos en procesos judiciales, y a socios comerciales, técnicos o estratégicos que asuman obligaciones de confidencialidad y seguridad equivalentes.</p>\r\n    <h4>Limitación del uso o divulgación de datos y derechos ARCO</h4><p>El usuario podrá limitar el uso o divulgación de sus datos personales y ejercer derechos de acceso, rectificación, cancelación u oposición mediante solicitud escrita dirigida a “EL PRESTADOR” en su domicilio o al correo silvia@pasaporteatusalud.com, acompañando documento que acredite su identidad.</p>\r\n    <h4>Revocación de consentimiento</h4><p>El usuario podrá revocar su consentimiento siguiendo el mismo procedimiento, considerando que para ciertos fines la revocación puede implicar la cancelación de “LA TARJETA DE DESCUENTO” y la imposibilidad de acceder al programa.</p>\r\n    <p><strong>Nombre:</strong> Juan Carlos Fuentes Moya<br><strong>Fecha:</strong> 13 de mayo de 2026</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Firma</strong></div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 6<br>DECLARACIÓN DE DUEÑO BENEFICIARIO</h2>\r\n    <p>DE CONFORMIDAD CON LO DISPUESTO EN LOS ARTÍCULOS 18 FRACCIÓN I Y III DE LA LEY FEDERAL PARA PREVENCIÓN E IDENTIFICACIÓN DE OPERACIONES CON RECURSOS DE PROCEDENCIA ILÍCITA, EL ARTÍCULO 15 DE SU REGLAMENTO Y EL ARTÍCULO 13 DE LAS REGLAS DE CARÁCTER GENERAL, MANIFIESTO BAJO PROTESTA DE DECIR VERDAD:</p>\r\n    <h4>Datos de identificación del cliente</h4>\r\n    <table><tr><th>Campo</th><th>Respuesta</th></tr><tr><td>Apellido paterno, materno y nombre(s)</td><td>Juan Carlos Fuentes Moya</td></tr><tr><td>Fecha de nacimiento</td><td>1981-08-22</td></tr><tr><td>País de nacimiento</td><td>México</td></tr><tr><td>Nacionalidad</td><td>mexicana</td></tr><tr><td>Actividad, ocupación o profesión</td><td>EMPLEADO</td></tr><tr><td>Estado civil</td><td>CASADO(A)</td></tr><tr><td>Domicilio particular</td><td>Avellaneada 118, Col. Valle imperaial, C.P. 14521, Zapopan, Jalisco, México</td></tr><tr><td>Teléfonos</td><td>5650900475</td></tr><tr><td>Correo electrónico</td><td>roel.fuentes@gmail.com</td></tr><tr><td>CURP</td><td>DDDDDDDD</td></tr><tr><td>RFC</td><td>FUMJ9810822NR</td></tr><tr><td>Tipo de identificación</td><td>INE</td></tr><tr><td>Emitida por / país emisor</td><td>México</td></tr><tr><td>Número de identificación</td><td>INEAAAA</td></tr></table>\r\n    <h4>Datos de identificación de la operación</h4>\r\n    <table><tr><th>Campo</th><th>Respuesta</th></tr><tr><td>Tipo de operación</td><td>Adquisición de tarjeta de descuento PATS</td></tr><tr><td>Monto de operación</td><td>$800.00 M.N.</td></tr><tr><td>Fecha de operación</td><td>13 de mayo de 2026</td></tr><tr><td>Forma de pago</td><td>Pasarela / medio autorizado por “EL PRESTADOR”</td></tr><tr><td>Moneda</td><td>MXN</td></tr></table>\r\n    <h4>Información de la existencia del dueño beneficiario o beneficiario controlador</h4>\r\n    <p>Declaro que soy el beneficiario directo de la operación y no existe ningún otro dueño beneficiario o beneficiario controlador: <strong>SI</strong>.</p>\r\n    <h4>Aviso de privacidad</h4><p>Los datos personales serán protegidos y tratados conforme al Aviso de Privacidad contenido en el cuerpo del presente contrato y la legislación aplicable.</p>\r\n    <p>H. Puebla de Zaragoza al 13 del mes de mayo del año 2026.</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Nombre y firma</strong><br>Juan Carlos Fuentes Moya</div>\r\n  </div>\r\n\r\n  \r\n  </div>\r\n', 'data:image/png;base64,', 'Juan Carlos Fuentes Moya', '0dc8d5faad1d05132a671453561647a1c972d9154aa33247637c97a547193f1b', '2026-05-13 15:45:56', '189.190.218.123', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:150.0) Gecko/20100101 Firefox/150.0', '', 'firmado', '2026-05-13 15:45:56', '2026-05-13 15:45:56');
INSERT INTO `pats_contratos_firmados` (`id_contrato_firmado`, `id_orden`, `id_pasaporte`, `id_distribuidor`, `id_franquicia`, `token_publico`, `contrato_clave`, `contrato_version`, `html_contrato_renderizado`, `firma_afiliado_base64`, `nombre_firmante`, `hash_contrato`, `fecha_firma`, `ip_firma`, `user_agent_firma`, `pdf_path`, `estatus`, `created_at`, `updated_at`) VALUES
(12, 1, 1, 0, 0, '', 'contrato_pats_base', '1.0', '<style>\r\n  .pats-contract{font-family:Arial,Helvetica,sans-serif;color:#172033;font-size:12px;line-height:1.52;background:#fff;padding:4px}\r\n  .pats-contract h1,.pats-contract h2,.pats-contract h3,.pats-contract h4{text-align:center;margin:12px 0 8px;color:#0d1b3e}\r\n  .pats-contract h1{font-size:16px;text-transform:uppercase;letter-spacing:.05em}\r\n  .pats-contract h2{font-size:15px;text-transform:uppercase;letter-spacing:.04em}\r\n  .pats-contract h3{font-size:13px;text-transform:uppercase;letter-spacing:.08em}\r\n  .pats-contract h4{font-size:12px;text-align:left;text-transform:uppercase;margin-top:12px}\r\n  .pats-contract p{margin:6px 0;text-align:justify}\r\n  .pats-contract ul{margin:6px 0 8px 18px;padding:0}.pats-contract li{margin:4px 0;text-align:justify}\r\n  .pats-contract table{width:100%;border-collapse:collapse;margin:8px 0 12px}.pats-contract th,.pats-contract td{border:1px solid #cbd5e1;padding:6px;vertical-align:top}.pats-contract th{background:#eef4ff;color:#0d1b3e;text-align:left}\r\n  .pats-contract .center{text-align:center}.pats-contract .muted{color:#64748b}.pats-contract .small{font-size:10px}.pats-contract .badge{display:inline-block;padding:3px 8px;border-radius:999px;background:#eef4ff;color:#1d4ed8;font-weight:700;margin:2px 4px 2px 0}\r\n  .pats-contract .sign-grid{display:grid;grid-template-columns:1fr 1fr;gap:22px;margin-top:28px}.pats-contract .sign-box{text-align:center;min-height:95px}.pats-contract .line{border-top:1px solid #0f172a;margin:48px 8px 6px}.pats-contract .signature-img{max-width:220px;max-height:82px;display:block;margin:0 auto 4px}\r\n  .pats-contract .annex{page-break-before:auto;border-top:2px solid #0d1b3e;margin-top:18px;padding-top:12px}.pats-contract .page-break{page-break-before:always;border-top:1px dashed #cbd5e1;margin-top:18px;padding-top:12px}\r\n</style>\r\n<div class=\"pats-contract\">\r\n  <h1>Carátula del contrato de adquisición de tarjeta de descuento</h1>\r\n  <p>CARÁTULA DEL CONTRATO DE ADQUISICIÓN DE TARJETA DE DESCUENTO (EN LO SUCESIVO “LA CARÁTULA”), QUE CELEBRAN POR UNA PARTE LA SOCIEDAD SEÑALADA EN EL APARTADO 1.- DE LA CARÁTULA, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL PRESTADOR”, REPRESENTADA EN ESTE ACTO POR LA PERSONA FÍSICA QUE SE INDICA EN EL APARTADO 2.- DE LA CARÁTULA; Y POR LA OTRA PARTE, LA PERSONA FÍSICA SEÑALADA EN EL APARTADO 5.- DE LA CARÁTULA, POR SU PROPIO DERECHO, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL AFILIADO”; Y CUANDO LOS ANTES NOMBRADOS ACTÚEN DE MANERA CONJUNTA, SE LES DENOMINARÁ COMO “LAS PARTES”; QUIENES SE SUJETAN AL TENOR DE LA CARÁTULA, DECLARACIONES Y CLÁUSULAS SIGUIENTES:</p>\r\n    \r\n  <h2>C A R Á T U L A</h2>\r\n  <table>\r\n    <tr><th style=\"width:8%\">Apartado</th><th style=\"width:42%\">Definición</th><th>Respuesta</th></tr>\r\n    <tr><td>1.-</td><td>Nombre de “EL PRESTADOR”</td><td>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE</td></tr>\r\n    <tr><td>2.-</td><td>Nombre del Representante Legal de “EL PRESTADOR”</td><td>PEDRO AZCÁRRAGA RAMOS</td></tr>\r\n    <tr><td>3.-</td><td>Domicilio de “EL PRESTADOR”</td><td>CALLE PASEO SINFONÍA NÚMERO EXTERIOR 1, LOCAL 2-14, LOMAS DE ANGELÓPOLIS II, SAN ANDRÉS CHOLULA, ESTADO DE PUEBLA, CÓDIGO POSTAL 72830</td></tr>\r\n    <tr><td>4.-</td><td>Clave del Registro Federal de Contribuyentes de “EL PRESTADOR”</td><td>COH2202144H5</td></tr>\r\n    <tr><td>5.-</td><td>Nombre de “EL AFILIADO”</td><td>Juan Lopez Fuentes</td></tr>\r\n    <tr><td>6.-</td><td>Domicilio de “EL AFILIADO”</td><td>a a Int. a, Col. aa, C.P. 11111, aaa, Jalisco, México</td></tr>\r\n    <tr><td>7.-</td><td>Clave del Registro Federal de Contribuyentes de “EL AFILIADO”</td><td>AAA</td></tr>\r\n    <tr><td>8.-</td><td>Costo mensual de “LA TARJETA DE DESCUENTO”</td><td>$800.00 M.N.</td></tr>\r\n    <tr><td>9.-</td><td>Cuenta bancaria de “EL PRESTADOR” para pagos</td><td>Cuenta: 01600866709<br>CLABE: 042650016008667096<br>Institución Bancaria: Banca Mifel, S.A., Institución de Banca Múltiple, Grupo Financiero Mifel</td></tr>\r\n    <tr><td>10.-</td><td>Cuota de Reactivación de “LA TARJETA DE DESCUENTO”</td><td>$100.00 M.N. por cada mes que se haya interrumpido el pago.</td></tr>\r\n    <tr><td>11.-</td><td>Datos de la Tarjeta de Crédito de “EL AFILIADO”</td><td>Número de tarjeta: pendiente de confirmar por pasarela/token de pago.<br>Institución bancaria: pendiente de confirmar por pasarela. <br><span class=\"small\">No se almacena número completo de tarjeta en este formulario.</span></td></tr>\r\n    <tr><td>12.-</td><td>Anexos</td><td>ANEXO 1. Identificación oficial de “EL AFILIADO”<br>ANEXO 2. Comprobante de domicilio de “EL AFILIADO”<br>ANEXO 3. Constancia de Situación Fiscal de “EL AFILIADO”, si aplica<br>ANEXO 4. Cuotas de recuperación y/o precios base a cubrir a “EL PRESTADOR”<br>ANEXO 5. Aviso de privacidad<br>ANEXO 6. Declaración de dueño beneficiario</td></tr>\r\n    <tr><td>13.-</td><td>Fecha de Firma del Contrato</td><td>13 de mayo de 2026</td></tr>\r\n  </table>\r\n\r\n  <div class=\"sign-grid\">\r\n    <div class=\"sign-box\"><div class=\"line\"></div><strong>“EL PRESTADOR”</strong><br>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE<br>Representada por PEDRO AZCÁRRAGA RAMOS</div>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>“EL AFILIADO”</strong><br>Juan Lopez Fuentes<br><span class=\"small\">La persona física señalada en el Apartado 5.- de la Carátula</span></div>\r\n  </div>\r\n\r\n  <div class=\"page-break\"></div>\r\n  <h1>Contrato de adquisición de tarjeta de descuento</h1>\r\n  <p>CONTRATO DE ADQUISICIÓN DE TARJETA DE DESCUENTO, QUE CELEBRAN POR UNA PARTE LA SOCIEDAD SEÑALADA EN EL APARTADO 1.- DE LA CARÁTULA, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL PRESTADOR”, REPRESENTADA EN ESTE ACTO POR LA PERSONA FÍSICA QUE SE INDICA EN EL APARTADO 2.- DE LA CARÁTULA; Y POR LA OTRA PARTE, LA PERSONA FÍSICA SEÑALADA EN EL APARTADO 5.- DE LA CARÁTULA, POR SU PROPIO DERECHO, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL AFILIADO”; Y CUANDO LOS ANTES NOMBRADOS ACTÚEN DE MANERA CONJUNTA, SE LES DENOMINARÁ COMO “LAS PARTES”; QUIENES SE SUJETAN AL TENOR DE LAS DECLARACIONES Y CLÁUSULAS SIGUIENTES:</p>\r\n\r\n  <h2>D E C L A R A C I O N E S</h2>\r\n  <h4>I.- Declara “EL PRESTADOR” por conducto de su representación:</h4>\r\n  <p>A. Que, su representada es una sociedad mercantil constituida conforme a las leyes de los Estados Unidos Mexicanos, según consta en la escritura pública número 39,861, del volumen 830 de fecha catorce de febrero de dos mil veintidós, otorgada ante la fe del Licenciado Ernesto Joaquín Briones Amador, Notario Público Titular de la Notaría Pública número 46 de las del Distrito Judicial de Puebla, Estado de Puebla, cuyo primer testimonio se encuentra inscrito ante las oficinas del Registro Público de Comercio del Distrito Judicial de Puebla, Estado de Puebla, bajo el Folio Mercantil Electrónico: N-2022022991, por virtud del cual se llevó a cabo la Constitución de la persona moral denominada CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE.</p>\r\n  <p>B. Que, la persona física que la representa en este acto, señalada en el Apartado 2.- de la Carátula, cuenta con todas y cada una de las facultades necesarias para la celebración del presente contrato, las cuales se desprenden del instrumento descrito en el punto declarativo inmediato anterior, mismas que manifiesta bajo protesta de decir verdad que no le han sido suspendidas, revocadas o limitadas en forma alguna.</p>\r\n  <p>C. Que, su representada tiene como domicilio fiscal el señalado en el Apartado 3.- de la Carátula del presente contrato, mismo que designa como domicilio convencional para cualquier cuestión relacionada con la celebración del presente contrato.</p>\r\n  <p>D. Que, su representada se encuentra inscrita en el Registro Federal de Contribuyentes bajo la clave señalada en el Apartado 4.- de la Carátula.</p>\r\n  <p>E. Que, ha desarrollado y es su deseo comparecer a la celebración del presente instrumento con la finalidad de enajenar en favor de “EL AFILIADO”, una Tarjeta de Descuento que da acceso a “UN PROGRAMA DE BENEFICIOS QUE OTORGA DESCUENTOS A LOS COSTOS Y PERMITE RECIBIR SERVICIOS MÉDICOS PRIVADOS DE ALTA CALIDAD DE FORMA ACCESIBLE, CLARA Y SIN RESTRICCIONES DENTRO DE LA RED DE HOSPITALES 50 (FIFTY) DOCTORS CON SEDE EN EL ESTADO DE PUEBLA”, en lo sucesivo “LA TARJETA DE DESCUENTO”, en los términos y condiciones que se establecerán más adelante.</p>\r\n  <p>F. Que, su representada no es una Aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas sino una empresa dedicada, entre otros, a la operación y administración de establecimientos destinados a la atención y asistencia de enfermos, por lo que la enajenación de “LA TARJETA DE DESCUENTO” únicamente constituye un acto de comercio que brindará a “EL AFILIADO” acceso a un programa de beneficios como ha quedado descrito anteriormente.</p>\r\n\r\n  <h4>II.- Declara “EL AFILIADO”, por su propio derecho:</h4>\r\n      <p>A. Que, su nombre se señala en el Apartado 5.- de la Carátula, es una persona física de nacionalidad mexicana, en pleno ejercicio de sus derechos, legal y jurídicamente capaz para celebrar el presente Contrato, quien se identifica con credencial para votar vigente expedida por el Instituto Nacional Electoral, tipo INE, número AAA, que en copia simple o archivo digital se agrega al cuerpo del presente contrato como ANEXO 1.</p>\r\n    <p>B. Que, tiene como domicilio particular el señalado en el Apartado 6.- de la Carátula, mismo que designa como domicilio convencional para cualquier cuestión relacionada con la celebración del presente contrato, tal y como lo acredita con el comprobante de domicilio que en copia simple o archivo digital se agrega al cuerpo del presente contrato como ANEXO 2.</p>\r\n  <p>C. Que, su CURP es AAAAAA y su RFC/identificación fiscal es AAA; asimismo manifiesta que cuenta con capacidad económica para obligarse en términos del presente contrato y que los recursos con los que cubrirá sus obligaciones provendrán de fuentes lícitas. En caso de nacionalidad extranjera/no mexicana, se tendrán por no aplicables CURP, INE y constancia fiscal mexicana salvo manifestación expresa de residencia fiscal o RFC mexicano.</p>\r\n  <p>D. Que, es su deseo comparecer a la celebración del presente instrumento con la finalidad de adquirir “LA TARJETA DE DESCUENTO” de acuerdo con los términos y condiciones que se establecen a continuación.</p>\r\n  <p>E. Que, previo a la celebración del presente contrato fue informado y manifiesta expresamente que reconoce que “EL PRESTADOR” no es una Aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas y que las actividades comerciales objeto del presente contrato no consisten en la contratación de un seguro, de la índole que fuere, sino que únicamente implica la adquisición de una tarjeta de descuento que da acceso a un programa de beneficios que otorga descuentos a los costos y permite recibir servicios médicos privados de alta calidad de forma accesible, clara y sin restricciones dentro de la red de hospitales 50 (FIFTY) Doctors con sede en el Estado de Puebla.</p>\r\n  <p>F. Que, reconoce que “EL PRESTADOR” se dedica a la operación de centros hospitalarios y que la emisión de “LA TARJETA DE DESCUENTO” únicamente corresponde a la intención de este último de crear un programa de descuentos para el acceso a los servicios prestados por la Red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla.</p>\r\n\r\n  <h4>III.- Declaran conjuntamente “LAS PARTES”:</h4>\r\n  <p>1. Que, se reconocen recíprocamente la personalidad con la que comparecen a la celebración del presente acuerdo de voluntades.</p>\r\n  <p>2. Que, el presente contrato es el instrumento que las vincula en sus derechos y obligaciones.</p>\r\n  <p>3. Que, es su deseo celebrar el presente contrato y han negociado libremente los términos y condiciones del mismo con pleno conocimiento de sus alcances e implicaciones jurídicas, por lo que en su celebración no existe dolo, error, mala fe, lesión o cualquier otro vicio del consentimiento que pudiese afectarlo de inexistencia o nulidad.</p>\r\n\r\n  <h2>C L Á U S U L A S</h2>\r\n  <h4>PRIMERA.- OBJETO.</h4>\r\n  <p>El objeto del presente Contrato es que “EL AFILIADO” adquiera de “EL PRESTADOR”, a título oneroso y temporal, el derecho de uso ilimitado y sin restricción alguna de “LA TARJETA DE DESCUENTO” emitida por CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE, la cual consiste en que “EL AFILIADO” aproveche y acceda a “UN PROGRAMA DE BENEFICIOS QUE OTORGA DESCUENTOS A LOS COSTOS Y PERMITE RECIBIR SERVICIOS MÉDICOS PRIVADOS DE ALTA CALIDAD DE FORMA ACCESIBLE, CLARA Y SIN RESTRICCIONES DENTRO DE LA RED DE HOSPITALES 50 (FIFTY) DOCTORS CON SEDE EN EL ESTADO DE PUEBLA”.</p>\r\n  <p>Estableciendo que, la comercialización de “LA TARJETA DE DESCUENTO” por parte de “EL PRESTADOR” en ningún momento constituirá la venta, promoción o por cualquier medio la contratación de una póliza de seguro, bajo el entendido de que “EL PRESTADOR” no es una aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas (CNSF); sino que comercializa “LA TARJETA DE DESCUENTO” en favor de terceros con la finalidad de otorgar descuentos a los precios respecto de los servicios médicos que presta en el territorio nacional.</p>\r\n\r\n  <h4>SEGUNDA.- PRECIO DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“LAS PARTES” establecen de común acuerdo que “LA TARJETA DE DESCUENTO” tendrá como costo mensual la cantidad señalada en el Apartado 8.- de la Carátula del presente contrato; cantidad que ya incluye IVA, y la cual deberá ser cubierta por “EL AFILIADO” en favor de “EL PRESTADOR” dentro de los primeros 5 (cinco) días de cada mes, sin necesidad de gestiones o avisos de cobro, ya sea mediante:</p>\r\n  <p>(i) Transferencia electrónica de fondos a la cuenta bancaria señalada en el Apartado 9.- de la Carátula del presente contrato y de la cual es titular “EL PRESTADOR”.</p>\r\n  <p>(ii) Cheque que se recibirá salvo buen cobro en el Domicilio de “EL PRESTADOR” señalado en el Apartado 3.- de la Carátula del presente contrato, y que en caso de no ser pagado por falta de fondos suficientes o por otras causas imputables a “EL AFILIADO”, éste último está de acuerdo en que deberá cubrir a “EL PRESTADOR” el 20% (veinte por ciento) del monto del cheque por concepto de indemnización por daños y perjuicios en términos del artículo 193 de la Ley General de Títulos y Operaciones de Crédito, independientemente de cualquier otro cargo que se pudiera generar.</p>\r\n  <p>(iii) Cargos mensuales automáticos recurrentes a la tarjeta de crédito de “EL AFILIADO” según los datos señalados en el Apartado 11.- de la Carátula del presente contrato, quien manifiesta bajo protesta de decir verdad que autoriza a “EL PRESTADOR” a realizar los cargos mensuales correspondientes por el costo mensual de “LA TARJETA DE DESCUENTO” en dicha tarjeta o en la tarjeta que por renovación, reposición, robo o extravío le haya asignado el banco emisor. La autorización estará vigente mientras “EL AFILIADO” no haya notificado a “EL PRESTADOR” por escrito y con acuse de recibo su deseo de cancelar su afiliación o no renovarla, o en su defecto, realizar su baja respectiva en el sitio web o aplicación de “EL PRESTADOR”.</p>\r\n  <p>Esta autorización no exime a “EL AFILIADO” del pago mensual por el uso de “LA TARJETA DE DESCUENTO” y demás obligaciones contractuales, por lo que, en caso de que el cobro no sea autorizado por el banco emisor o por cualquier razón no pueda realizarse, “EL AFILIADO” deberá notificar tal situación a “EL PRESTADOR” a la dirección de correo electrónico silvia@pasaporteatusalud.com, a efecto de solicitar una forma de pago diversa, quedando obligado a cubrir de inmediato el pago correspondiente.</p>\r\n  <p>(iv) Cualquier otro medio de pago aceptado por “EL PRESTADOR”, mismo que se dará a conocer a través de sus medios oficiales de comunicación.</p>\r\n  <p>“EL PRESTADOR” podrá variar unilateralmente el costo mensual de “LA TARJETA DE DESCUENTO”, previo aviso a “EL AFILIADO” con 30 (treinta) días de anticipación a través de sus medios oficiales de comunicación.</p>\r\n  <p>Para el caso de que “EL AFILIADO” adquiera y cubra el precio de “LA TARJETA DE DESCUENTO” y posteriormente deje de pagar una mensualidad, deberá cubrir a “EL PRESTADOR”, por concepto de cuota de reactivación, la cantidad señalada en el Apartado 10.- de la Carátula por cada mes que haya interrumpido y/o no haya cubierto el precio de “LA TARJETA DE DESCUENTO”, hasta la fecha en que pretenda volver a adquirirla.</p>\r\n\r\n  <h4>TERCERA.- VIGENCIA DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“LA TARJETA DE DESCUENTO” objeto del presente contrato tendrá una vigencia de 30 días contados a partir de que “EL AFILIADO” cubra a “EL PRESTADOR” el precio establecido anteriormente, en el entendido de que la vigencia del presente contrato y de “LA TARJETA DE DESCUENTO” se prorrogarán automáticamente sin necesidad de celebrar documento adicional entre “LAS PARTES” siempre y cuando “EL AFILIADO” cubra, de mes en mes o en la frecuencia contratada, el precio vigente de “LA TARJETA DE DESCUENTO”.</p>\r\n  <p>“EL AFILIADO” tendrá derecho a revocar su consentimiento dentro de los 5 (cinco) días siguientes a la entrega de “LA TARJETA DE DESCUENTO” o la firma del presente contrato, lo que ocurra último, sin responsabilidad alguna, siempre y cuando no haya obtenido beneficio alguno por el uso de “LA TARJETA DE DESCUENTO”.</p>\r\n\r\n  <h4>CUARTA.- BENEFICIOS DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“EL AFILIADO”, de forma exclusiva, personal e intransferible, gozará de forma gratuita de los servicios que se mencionan a continuación:</p>\r\n  <ul><li>Consultas gratuitas ilimitadas de medicina general (no de especialidad) en la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla, únicamente con los doctores afiliados al programa de Pasaporte a tu Salud.</li><li>Consultas de urgencia gratuitas en la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla.</li></ul>\r\n  <p>No así respecto de los servicios que, de manera enunciativa más no limitativa, se describen a continuación:</p>\r\n  <ul><li>Hospitalización dentro de la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla, sujeto a la disponibilidad de cada uno de ellos.</li><li>Consultas de especialidad ilimitadas a costo preferencial, con médicos especialistas pertenecientes al programa PATS.</li><li>Acceso a farmacia PATS con costos reducidos de medicamentos genéricos.</li><li>Imagenología y laboratorios ilimitados con costos preferenciales.</li><li>Acceso a cirugías con cuota de recuperación preferente, con o sin honorarios médicos incluidos según corresponda.</li></ul>\r\n  <p>Dichos servicios generarán, por evento, el pago de una cuota con cargo a “EL AFILIADO”, misma que resultará de aplicar los porcentajes de descuento que se desprenden del ANEXO 4 del presente contrato a los precios publicados al público en general o los precios preferenciales indicados.</p>\r\n  <p>Mientras “LA TARJETA DE DESCUENTO” se encuentre vigente, “EL AFILIADO” gozará de todos los beneficios que la misma le otorga; sin embargo, para el caso de que requiera cirugía o procedimiento quirúrgico en quirófano, deberá haber sufragado por adelantado la adquisición de “LA TARJETA DE DESCUENTO” por un periodo de 12 (doce) meses y encontrarse dentro de dicho periodo de vigencia.</p>\r\n\r\n  <h4>QUINTA.- OBLIGACIONES DE “EL PRESTADOR”.</h4>\r\n  <p>“EL PRESTADOR” se obliga a: (i) otorgar a “EL AFILIADO” el acceso ilimitado a “LA TARJETA DE DESCUENTO” durante la vigencia del contrato; (ii) mantener actualizada y operativa la Red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla; (iii) proporcionar a “EL AFILIADO”, de forma digital, “LA TARJETA DE DESCUENTO” dentro de los 5 (cinco) días hábiles siguientes al primer pago; e (iv) informar por escrito cualquier modificación a la red de hospitales o al tabulador de cuotas con al menos 10 (diez) días de anticipación.</p>\r\n\r\n  <h4>SEXTA.- OBLIGACIONES DE “EL AFILIADO”.</h4>\r\n  <p>“EL AFILIADO” se obliga a: (i) pagar puntualmente el precio de “LA TARJETA DE DESCUENTO”; (ii) utilizarla de forma exclusiva, personal e intransferible; (iii) cubrir directamente a los hospitales y con anterioridad a recibir el servicio médico las cuotas de recuperación según tabulador vigente; (iv) presentar identificación oficial y “LA TARJETA DE DESCUENTO” o código QR cada vez que haga uso de beneficios; y (v) notificar por escrito cualquier cambio de domicilio o datos de contacto en un plazo no mayor a 5 (cinco) días.</p>\r\n\r\n  <h4>SÉPTIMA.- ACCESO A LOS BENEFICIOS Y PROCEDIMIENTO.</h4>\r\n  <p>Para hacer uso de “LA TARJETA DE DESCUENTO”, “EL AFILIADO” deberá agendar sus citas directamente con los doctores pertenecientes a la Red de Hospitales 50 (FIFTY) Doctors, que en ese momento se encuentren adscritos al programa de beneficios, a través de la aplicación oficial, página de internet oficial de PATS o medios oficiales que indique “EL PRESTADOR”.</p>\r\n  <p>“EL AFILIADO” se obliga a pagar directamente al médico especialista perteneciente al programa el costo de la consulta de especialidad de que se trate, en términos de los porcentajes de descuento del ANEXO 4. En caso de no estar facultado para asistir por fuerza mayor, tendrá un plazo de 30 (treinta) días contados a partir de haber generado la cita para solicitar una nueva consulta médica.</p>\r\n\r\n  <h4>OCTAVA.- EXCLUSIONES Y LIMITACIONES.</h4>\r\n  <p>Los beneficios no incluirán: (i) trasplantes de órganos; (ii) tratamientos experimentales; (iii) tratamientos de oncología a excepción de algunas cirugías; (iv) medicamentos extra hospitalarios que no estén recogidos en el catálogo de Farmacia PATS; (v) atención médica con especialistas no adscritos o no publicados en los medios oficiales; y (vi) cualquier servicio no listado expresamente.</p>\r\n\r\n  <h4>NOVENA.- CAUSAS DE TERMINACIÓN.</h4>\r\n  <p>El contrato podrá terminarse por falta de pago, mutuo consentimiento por escrito o incumplimiento de cualquiera de las cláusulas por cualquiera de “LAS PARTES”. En caso de terminación, “EL AFILIADO” no tendrá derecho a exigir la devolución de cantidad alguna.</p>\r\n\r\n  <h4>DÉCIMA.- CANCELACIÓN VOLUNTARIA.</h4>\r\n  <p>“EL AFILIADO” podrá cancelar “LA TARJETA DE DESCUENTO” mediante aviso por escrito con 30 (treinta) días de anticipación. Dicha cancelación surtirá efectos a partir del siguiente periodo mensual y no generará reembolso de pagos ya realizados.</p>\r\n\r\n  <h4>DÉCIMA PRIMERA.- PROTECCIÓN DE DATOS PERSONALES.</h4>\r\n  <p>“LAS PARTES” acuerdan que el tratamiento de datos personales se sujetará a la Ley Federal de Protección de Datos Personales en Posesión de los Particulares. “EL AFILIADO” autoriza expresamente el uso de sus datos para la gestión de “LA TARJETA DE DESCUENTO”. El aviso de privacidad se integra al presente contrato como ANEXO 5.</p>\r\n\r\n  <h4>DÉCIMA SEGUNDA.- RESPONSABILIDAD.</h4>\r\n  <p>“EL AFILIADO” reconoce y acepta que “LA TARJETA DE DESCUENTO” es emitida y administrada directamente por CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE, quien es responsable de la operación de la red de descuentos, afiliación de prestadores médicos y prestación de cualquier servicio relacionado con “LA TARJETA DE DESCUENTO”.</p>\r\n  <p>En consecuencia, “EL PRESTADOR” no tendrá responsabilidad directa ni indirecta por la prestación, calidad, eficacia, resultado, daño, perjuicio, lesión, complicación, secuela, evento adverso o consecuencia derivada de servicios médicos recibidos, incluyendo aquellos ocasionados por negligencia, impericia o mala praxis de profesionales de la salud o prestadores afiliados. Cualquier relación derivada de la prestación de servicios médicos se establece directamente entre “EL AFILIADO” y los prestadores de servicios de salud correspondientes. Esta limitación subsistirá a la terminación del contrato.</p>\r\n\r\n  <h4>DÉCIMA TERCERA.- PREVENCIÓN DE LAVADO DE DINERO Y ORIGEN DE LOS RECURSOS.</h4>\r\n  <p>“LAS PARTES” declaran bajo protesta de decir verdad que los recursos económicos, bienes y derechos que utilicen para cumplir obligaciones derivadas de este contrato tienen y tendrán origen lícito. “EL AFILIADO” manifiesta que el pago inicial y pagos futuros provienen de fuentes lícitas y no de actividades tipificadas como delitos.</p>\r\n  <p>“LAS PARTES” reconocen que la prestación de servicios de comercio puede ser considerada actividad vulnerable, por lo que se obligan a proporcionar información y documentación requerida para integrar expediente de identificación e informar si tienen conocimiento de la existencia de beneficiario controlador.</p>\r\n\r\n  <h4>DÉCIMA CUARTA.- CONFORMACIÓN DEL EXPEDIENTE DE IDENTIFICACIÓN.</h4>\r\n  <p>“EL PRESTADOR” queda obligado a conformar y mantener un expediente de identificación de “EL AFILIADO”. Para tales efectos, “EL AFILIADO” se obliga a entregar los documentos aplicables: identificación oficial vigente o pasaporte, acta de nacimiento cuando aplique, comprobante de domicilio, constancia de situación fiscal cuando aplique, CURP, y declaración de dueño beneficiario.</p>\r\n  <p>Cuando exista persona responsable, la documentación de identificación y representación deberá integrarse al expediente; la CIF/constancia fiscal corresponde al tutor cuando aplique. “EL PRESTADOR” conservará dicho expediente por un periodo mínimo de 5 (cinco) años contados a partir de que termine la vigencia del contrato o termine por cualquiera de sus causales, garantizando la confidencialidad de los datos personales.</p>\r\n\r\n  <h4>DÉCIMA QUINTA.- CAUSAL ESPECÍFICA DE RESCISIÓN.</h4>\r\n  <p>Será motivo de rescisión inmediata sin necesidad de declaración judicial y sin responsabilidad para la parte afectada cuando cualquiera de “LAS PARTES” se niegue a proporcionar información requerida para cumplimiento de la Ley Federal para la Prevención e Identificación de Operaciones con Recursos de Procedencia Ilícita, proporcione información falsa o aparezca en listas de personas bloqueadas emitidas por autoridad competente.</p>\r\n\r\n  <h4>DÉCIMA SEXTA.- LEGISLACIÓN APLICABLE Y JURISDICCIÓN.</h4>\r\n  <p>“LAS PARTES” establecen que la Procuraduría Federal del Consumidor es competente en vía administrativa para resolver cualquier controversia sobre interpretación o cumplimiento. Sin perjuicio de lo anterior, se someten expresamente a la jurisdicción de los tribunales competentes del fuero común del Distrito Judicial de Puebla, Estado de Puebla, renunciando de manera expresa e irrevocable a cualquier otro fuero o jurisdicción que pudiera corresponderles.</p>\r\n\r\n  <p>Enteradas “LAS PARTES” del contenido y alcance del presente contrato, y entendidas de los derechos y obligaciones que contraen, firman el presente instrumento, incluyendo sus anexos, manifestando que no medió error, dolo, mala fe, violencia o lesión, ni vicio del consentimiento alguno, en la Ciudad de Puebla, Estado de Puebla, reconociendo que la fecha de firma es 13 de mayo de 2026.</p>\r\n\r\n  <div class=\"sign-grid\">\r\n    <div class=\"sign-box\"><div class=\"line\"></div><strong>“EL PRESTADOR”</strong><br>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE<br>Representada por PEDRO AZCÁRRAGA RAMOS</div>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>“EL AFILIADO”</strong><br>Juan Lopez Fuentes</div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 1<br>Identificación oficial de “EL AFILIADO”</h2><p>Se integra al expediente la identificación oficial cargada por el usuario en el formulario. Para mexicanos, corresponde a identificación oficial/INE cuando aplique. Para extranjeros/no mexicanos, corresponde a identificación oficial o pasaporte vigente; al menos el frente es obligatorio y el reverso será opcional cuando el documento no lo tenga.</p><p><strong>Tipo:</strong> INE. <strong>Emitida por / país emisor:</strong> México. <strong>Número:</strong> AAA.</p></div>\r\n  <div class=\"annex\"><h2>ANEXO 2<br>COMPROBANTE DE DOMICILIO DE “EL AFILIADO”</h2><p>Se integra al expediente el comprobante de domicilio cargado por el usuario. Domicilio declarado: a a Int. a, Col. aa, C.P. 11111, aaa, Jalisco, México.</p></div>\r\n  <div class=\"annex\"><h2>ANEXO 3<br>CONSTANCIA DE SITUACIÓN FISCAL DE “EL AFILIADO”</h2><p>Constancia de Situación Fiscal de “EL AFILIADO”, si aplica. En caso de pacientes representados, la constancia fiscal o CIF corresponde a la persona responsable cuando sea aplicable, no al menor. Para afiliados extranjeros/no mexicanos, no será obligatoria salvo que declaren RFC mexicano o residencia fiscal aplicable.</p></div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 4<br>CUOTAS DE RECUPERACIÓN Y/O PRECIOS BASE A CUBRIR A “EL PRESTADOR”</h2>\r\n    <p>En el presente anexo se establecen los porcentajes de descuento a obtener como titular de “LA TARJETA DE DESCUENTO”, por lo que la cantidad a cubrir por “EL AFILIADO” directamente al hospital de la cadena 50 (FIFTY) Doctors o al doctor que preste el servicio se obtendrá de aplicar el porcentaje de descuento correspondiente al precio publicado por los medios oficiales o al precio vigente en el establecimiento.</p>\r\n    <table><tr><th>Servicios / procedimientos</th><th>Descuentos</th></tr><tr><td>Consulta de urgencias</td><td>100%</td></tr><tr><td>Consulta de medicina general</td><td>100%</td></tr><tr><td>Habitación hospitalaria</td><td>90%</td></tr><tr><td>Uso de áreas de urgencias médicas</td><td>80%</td></tr><tr><td>Utilización de cubículos de terapia intensiva (UCIA-UCIN-UCIP)</td><td>75%</td></tr><tr><td>CEYE</td><td>75%</td></tr><tr><td>Uso quirófano</td><td>75%</td></tr><tr><td>Servicio de cuneros</td><td>75%</td></tr><tr><td>Materiales & medicamentos del cuadro básico, genéricos intercambiables</td><td>70%</td></tr><tr><td>Hemodinamia</td><td>70%</td></tr><tr><td>Imagenología</td><td>70%</td></tr><tr><td>Endoprótesis</td><td>70%</td></tr><tr><td>Osteosíntesis</td><td>70%</td></tr><tr><td>Prótesis</td><td>70%</td></tr><tr><td>Órtesis</td><td>70%</td></tr><tr><td>Laboratorio clínico</td><td>60%</td></tr></table>\r\n    <p class=\"small\">Los descuentos aplican con los proveedores suscritos al convenio de Pasaporte a tu Salud.</p>\r\n    <table><tr><th>Servicios / procedimientos</th><th>Precios base</th></tr><tr><td>Consulta de especialidades médicas</td><td>$390.00</td></tr><tr><td>Colposcopía</td><td>$400.00</td></tr><tr><td>Retiro de puntos de sutura</td><td>$80.00</td></tr><tr><td>Aplicación de medicamento intramuscular</td><td>$60.00</td></tr><tr><td>Retiro de DIU</td><td>$500.00</td></tr><tr><td>Colocación de DIU</td><td>$700.00</td></tr><tr><td>Extracción de cuerpo extraño (oído y nariz)</td><td>$300.00</td></tr><tr><td>Lavado ótico</td><td>$250.00</td></tr><tr><td>Curación de sitio quirúrgico</td><td>$250.00</td></tr><tr><td>Retiro de yeso</td><td>$250.00</td></tr><tr><td>Visita día de hospitalización</td><td>$650.00</td></tr><tr><td>Visita de urgencias</td><td>$750.00</td></tr><tr><td>Día de terapia intensiva</td><td>$850.00</td></tr></table>\r\n    <p class=\"small\">Todos los precios incluyen IVA. La factura de servicios hospitalarios será emitida con el desglose correspondiente y el ahorro otorgado por ser titular de “LA TARJETA DE DESCUENTO”.</p>\r\n    <p>Exclusiones y limitaciones: se aplicarán descuentos y precios especiales para el acompañante de “EL AFILIADO” en la misma habitación únicamente para la primera noche de hospitalización. Los precios y porcentajes de descuento darán derecho a la utilización de materiales y medicamentos del cuadro básico, genéricos intercambiables; cualquier otro tipo de medicación será cubierto directamente por “EL AFILIADO”. Los costos de procedimientos quirúrgicos incluyen honorarios médicos cuando así se indique. “EL AFILIADO” podrá atenderse con el médico tratante que elija, debiendo cubrir honorarios directamente a dicho médico, conservando el derecho a beneficios dentro de la red aplicable.</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Firma de aceptación de “EL AFILIADO”</strong><br>Juan Lopez Fuentes</div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 5<br>AVISO DE PRIVACIDAD</h2>\r\n    <p>En cumplimiento de las disposiciones establecidas en la Ley Federal de Protección de Datos Personales en Posesión de Particulares, su Reglamento y los lineamientos aplicables, “CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE” (en lo sucesivo “EL PRESTADOR”), con domicilio en CALLE PASEO SINFONÍA NÚMERO EXTERIOR 1, LOCAL 2-14, LOMAS DE ANGELÓPOLIS II, SAN ANDRÉS CHOLULA, ESTADO DE PUEBLA, CÓDIGO POSTAL 72830, da a conocer el Aviso de Privacidad al tenor del cual manejará por medio de su representación y/o empleados los datos personales y/o documentación proporcionada por el afiliado o usuario de “LA TARJETA DE DESCUENTO”.</p>\r\n    <p>Se tendrá por aceptado expresamente el presente Aviso de Privacidad una vez proporcionados los datos personales y firmada digitalmente la aceptación del contrato, motivo por el cual “EL PRESTADOR” estará facultado para manejar la información conforme a la legislación aplicable.</p>\r\n    <h4>Modificación del aviso de privacidad</h4><p>Este aviso podrá ser modificado o adecuado a las necesidades de “EL PRESTADOR”. Las modificaciones o actualizaciones serán incorporadas al presente aviso y estarán disponibles en la página de internet, domicilio de “EL PRESTADOR” o serán enviadas al último correo electrónico proporcionado.</p>\r\n    <h4>Finalidad de la información</h4><p>La información será utilizada para: elaborar y mantener actualizada la base de usuarios; identificar afiliados; proporcionar la tarjeta digital; otorgar acceso al programa de beneficios; informar modificaciones a la red o tabulador; realizar análisis estadísticos internos y brindar un óptimo servicio médico.</p>\r\n    <h4>Tipo de datos necesarios</h4><p>Se solicitarán datos de identificación, contacto, legales, contractuales y fiscales cuando aplique, incluyendo nombre completo, lugar y fecha de nacimiento, firma, identificación oficial, nacionalidad, CURP y RFC cuando sean aplicables, domicilio, teléfono y correo electrónico.</p>\r\n    <h4>Transferencias de la información</h4><p>El usuario autoriza proporcionar información sin consentimiento adicional en los casos previstos por ley, resolución de autoridad competente, tratados aplicables, salvaguarda de interés público, procuración o administración de justicia, reconocimiento o defensa de derechos en procesos judiciales, y a socios comerciales, técnicos o estratégicos que asuman obligaciones de confidencialidad y seguridad equivalentes.</p>\r\n    <h4>Limitación del uso o divulgación de datos y derechos ARCO</h4><p>El usuario podrá limitar el uso o divulgación de sus datos personales y ejercer derechos de acceso, rectificación, cancelación u oposición mediante solicitud escrita dirigida a “EL PRESTADOR” en su domicilio o al correo silvia@pasaporteatusalud.com, acompañando documento que acredite su identidad.</p>\r\n    <h4>Revocación de consentimiento</h4><p>El usuario podrá revocar su consentimiento siguiendo el mismo procedimiento, considerando que para ciertos fines la revocación puede implicar la cancelación de “LA TARJETA DE DESCUENTO” y la imposibilidad de acceder al programa.</p>\r\n    <p><strong>Nombre:</strong> Juan Lopez Fuentes<br><strong>Fecha:</strong> 13 de mayo de 2026</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Firma</strong></div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 6<br>DECLARACIÓN DE DUEÑO BENEFICIARIO</h2>\r\n    <p>DE CONFORMIDAD CON LO DISPUESTO EN LOS ARTÍCULOS 18 FRACCIÓN I Y III DE LA LEY FEDERAL PARA PREVENCIÓN E IDENTIFICACIÓN DE OPERACIONES CON RECURSOS DE PROCEDENCIA ILÍCITA, EL ARTÍCULO 15 DE SU REGLAMENTO Y EL ARTÍCULO 13 DE LAS REGLAS DE CARÁCTER GENERAL, MANIFIESTO BAJO PROTESTA DE DECIR VERDAD:</p>\r\n    <h4>Datos de identificación del cliente</h4>\r\n    <table><tr><th>Campo</th><th>Respuesta</th></tr><tr><td>Apellido paterno, materno y nombre(s)</td><td>Juan Lopez Fuentes</td></tr><tr><td>Fecha de nacimiento</td><td>1982-08-22</td></tr><tr><td>País de nacimiento</td><td>México</td></tr><tr><td>Nacionalidad</td><td>mexicana</td></tr><tr><td>Actividad, ocupación o profesión</td><td>aa</td></tr><tr><td>Estado civil</td><td>DIVORCIADO(A)</td></tr><tr><td>Domicilio particular</td><td>a a Int. a, Col. aa, C.P. 11111, aaa, Jalisco, México</td></tr><tr><td>Teléfonos</td><td>1214521452</td></tr><tr><td>Correo electrónico</td><td>roel.fuentes@gmail.com</td></tr><tr><td>CURP</td><td>AAAAAA</td></tr><tr><td>RFC</td><td>AAA</td></tr><tr><td>Tipo de identificación</td><td>INE</td></tr><tr><td>Emitida por / país emisor</td><td>México</td></tr><tr><td>Número de identificación</td><td>AAA</td></tr></table>\r\n    <h4>Datos de identificación de la operación</h4>\r\n    <table><tr><th>Campo</th><th>Respuesta</th></tr><tr><td>Tipo de operación</td><td>Adquisición de tarjeta de descuento PATS</td></tr><tr><td>Monto de operación</td><td>$800.00 M.N.</td></tr><tr><td>Fecha de operación</td><td>13 de mayo de 2026</td></tr><tr><td>Forma de pago</td><td>Pasarela / medio autorizado por “EL PRESTADOR”</td></tr><tr><td>Moneda</td><td>MXN</td></tr></table>\r\n    <h4>Información de la existencia del dueño beneficiario o beneficiario controlador</h4>\r\n    <p>Declaro que soy el beneficiario directo de la operación y no existe ningún otro dueño beneficiario o beneficiario controlador: <strong>SI</strong>.</p>\r\n    <h4>Aviso de privacidad</h4><p>Los datos personales serán protegidos y tratados conforme al Aviso de Privacidad contenido en el cuerpo del presente contrato y la legislación aplicable.</p>\r\n    <p>H. Puebla de Zaragoza al 13 del mes de mayo del año 2026.</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Nombre y firma</strong><br>Juan Lopez Fuentes</div>\r\n  </div>\r\n\r\n  \r\n  </div>\r\n', 'data:image/png;base64,', 'Juan Lopez Fuentes', '852d7642f0176088f71866d9f5178a18adfe75f3121239ab81c1a5095009a81b', '2026-05-13 19:59:15', '189.190.218.123', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:150.0) Gecko/20100101 Firefox/150.0', '', 'firmado', '2026-05-13 19:59:15', '2026-05-13 19:59:15');
INSERT INTO `pats_contratos_firmados` (`id_contrato_firmado`, `id_orden`, `id_pasaporte`, `id_distribuidor`, `id_franquicia`, `token_publico`, `contrato_clave`, `contrato_version`, `html_contrato_renderizado`, `firma_afiliado_base64`, `nombre_firmante`, `hash_contrato`, `fecha_firma`, `ip_firma`, `user_agent_firma`, `pdf_path`, `estatus`, `created_at`, `updated_at`) VALUES
(13, 1, 1, 0, 0, '', 'contrato_pats_base', '1.0', '<style>\r\n  .pats-contract{font-family:Arial,Helvetica,sans-serif;color:#172033;font-size:12px;line-height:1.52;background:#fff;padding:4px}\r\n  .pats-contract h1,.pats-contract h2,.pats-contract h3,.pats-contract h4{text-align:center;margin:12px 0 8px;color:#0d1b3e}\r\n  .pats-contract h1{font-size:16px;text-transform:uppercase;letter-spacing:.05em}\r\n  .pats-contract h2{font-size:15px;text-transform:uppercase;letter-spacing:.04em}\r\n  .pats-contract h3{font-size:13px;text-transform:uppercase;letter-spacing:.08em}\r\n  .pats-contract h4{font-size:12px;text-align:left;text-transform:uppercase;margin-top:12px}\r\n  .pats-contract p{margin:6px 0;text-align:justify}\r\n  .pats-contract ul{margin:6px 0 8px 18px;padding:0}.pats-contract li{margin:4px 0;text-align:justify}\r\n  .pats-contract table{width:100%;border-collapse:collapse;margin:8px 0 12px}.pats-contract th,.pats-contract td{border:1px solid #cbd5e1;padding:6px;vertical-align:top}.pats-contract th{background:#eef4ff;color:#0d1b3e;text-align:left}\r\n  .pats-contract .center{text-align:center}.pats-contract .muted{color:#64748b}.pats-contract .small{font-size:10px}.pats-contract .badge{display:inline-block;padding:3px 8px;border-radius:999px;background:#eef4ff;color:#1d4ed8;font-weight:700;margin:2px 4px 2px 0}\r\n  .pats-contract .sign-grid{display:grid;grid-template-columns:1fr 1fr;gap:22px;margin-top:28px}.pats-contract .sign-box{text-align:center;min-height:95px}.pats-contract .line{border-top:1px solid #0f172a;margin:48px 8px 6px}.pats-contract .signature-img{max-width:220px;max-height:82px;display:block;margin:0 auto 4px}\r\n  .pats-contract .annex{page-break-before:auto;border-top:2px solid #0d1b3e;margin-top:18px;padding-top:12px}.pats-contract .page-break{page-break-before:always;border-top:1px dashed #cbd5e1;margin-top:18px;padding-top:12px}\r\n</style>\r\n<div class=\"pats-contract\">\r\n  <h1>Carátula del contrato de adquisición de tarjeta de descuento</h1>\r\n  <p>CARÁTULA DEL CONTRATO DE ADQUISICIÓN DE TARJETA DE DESCUENTO (EN LO SUCESIVO “LA CARÁTULA”), QUE CELEBRAN POR UNA PARTE LA SOCIEDAD SEÑALADA EN EL APARTADO 1.- DE LA CARÁTULA, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL PRESTADOR”, REPRESENTADA EN ESTE ACTO POR LA PERSONA FÍSICA QUE SE INDICA EN EL APARTADO 2.- DE LA CARÁTULA; Y POR LA OTRA PARTE, LA PERSONA FÍSICA SEÑALADA EN EL APARTADO 5.- DE LA CARÁTULA, POR SU PROPIO DERECHO, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL AFILIADO”; Y CUANDO LOS ANTES NOMBRADOS ACTÚEN DE MANERA CONJUNTA, SE LES DENOMINARÁ COMO “LAS PARTES”; QUIENES SE SUJETAN AL TENOR DE LA CARÁTULA, DECLARACIONES Y CLÁUSULAS SIGUIENTES:</p>\r\n    \r\n  <h2>C A R Á T U L A</h2>\r\n  <table>\r\n    <tr><th style=\"width:8%\">Apartado</th><th style=\"width:42%\">Definición</th><th>Respuesta</th></tr>\r\n    <tr><td>1.-</td><td>Nombre de “EL PRESTADOR”</td><td>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE</td></tr>\r\n    <tr><td>2.-</td><td>Nombre del Representante Legal de “EL PRESTADOR”</td><td>PEDRO AZCÁRRAGA RAMOS</td></tr>\r\n    <tr><td>3.-</td><td>Domicilio de “EL PRESTADOR”</td><td>CALLE PASEO SINFONÍA NÚMERO EXTERIOR 1, LOCAL 2-14, LOMAS DE ANGELÓPOLIS II, SAN ANDRÉS CHOLULA, ESTADO DE PUEBLA, CÓDIGO POSTAL 72830</td></tr>\r\n    <tr><td>4.-</td><td>Clave del Registro Federal de Contribuyentes de “EL PRESTADOR”</td><td>COH2202144H5</td></tr>\r\n    <tr><td>5.-</td><td>Nombre de “EL AFILIADO”</td><td>Juan a a</td></tr>\r\n    <tr><td>6.-</td><td>Domicilio de “EL AFILIADO”</td><td>aa 452, Col. sss, C.P. 15325, aaa, Jalisco, México</td></tr>\r\n    <tr><td>7.-</td><td>Clave del Registro Federal de Contribuyentes de “EL AFILIADO”</td><td>AAA</td></tr>\r\n    <tr><td>8.-</td><td>Costo mensual de “LA TARJETA DE DESCUENTO”</td><td>$800.00 M.N.</td></tr>\r\n    <tr><td>9.-</td><td>Cuenta bancaria de “EL PRESTADOR” para pagos</td><td>Cuenta: 01600866709<br>CLABE: 042650016008667096<br>Institución Bancaria: Banca Mifel, S.A., Institución de Banca Múltiple, Grupo Financiero Mifel</td></tr>\r\n    <tr><td>10.-</td><td>Cuota de Reactivación de “LA TARJETA DE DESCUENTO”</td><td>$100.00 M.N. por cada mes que se haya interrumpido el pago.</td></tr>\r\n    <tr><td>11.-</td><td>Datos de la Tarjeta de Crédito de “EL AFILIADO”</td><td>Número de tarjeta: pendiente de confirmar por pasarela/token de pago.<br>Institución bancaria: pendiente de confirmar por pasarela. <br><span class=\"small\">No se almacena número completo de tarjeta en este formulario.</span></td></tr>\r\n    <tr><td>12.-</td><td>Anexos</td><td>ANEXO 1. Identificación oficial de “EL AFILIADO”<br>ANEXO 2. Comprobante de domicilio de “EL AFILIADO”<br>ANEXO 3. Constancia de Situación Fiscal de “EL AFILIADO”, si aplica<br>ANEXO 4. Cuotas de recuperación y/o precios base a cubrir a “EL PRESTADOR”<br>ANEXO 5. Aviso de privacidad<br>ANEXO 6. Declaración de dueño beneficiario</td></tr>\r\n    <tr><td>13.-</td><td>Fecha de Firma del Contrato</td><td>13 de mayo de 2026</td></tr>\r\n  </table>\r\n\r\n  <div class=\"sign-grid\">\r\n    <div class=\"sign-box\"><div class=\"line\"></div><strong>“EL PRESTADOR”</strong><br>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE<br>Representada por PEDRO AZCÁRRAGA RAMOS</div>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>“EL AFILIADO”</strong><br>Juan a a<br><span class=\"small\">La persona física señalada en el Apartado 5.- de la Carátula</span></div>\r\n  </div>\r\n\r\n  <div class=\"page-break\"></div>\r\n  <h1>Contrato de adquisición de tarjeta de descuento</h1>\r\n  <p>CONTRATO DE ADQUISICIÓN DE TARJETA DE DESCUENTO, QUE CELEBRAN POR UNA PARTE LA SOCIEDAD SEÑALADA EN EL APARTADO 1.- DE LA CARÁTULA, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL PRESTADOR”, REPRESENTADA EN ESTE ACTO POR LA PERSONA FÍSICA QUE SE INDICA EN EL APARTADO 2.- DE LA CARÁTULA; Y POR LA OTRA PARTE, LA PERSONA FÍSICA SEÑALADA EN EL APARTADO 5.- DE LA CARÁTULA, POR SU PROPIO DERECHO, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL AFILIADO”; Y CUANDO LOS ANTES NOMBRADOS ACTÚEN DE MANERA CONJUNTA, SE LES DENOMINARÁ COMO “LAS PARTES”; QUIENES SE SUJETAN AL TENOR DE LAS DECLARACIONES Y CLÁUSULAS SIGUIENTES:</p>\r\n\r\n  <h2>D E C L A R A C I O N E S</h2>\r\n  <h4>I.- Declara “EL PRESTADOR” por conducto de su representación:</h4>\r\n  <p>A. Que, su representada es una sociedad mercantil constituida conforme a las leyes de los Estados Unidos Mexicanos, según consta en la escritura pública número 39,861, del volumen 830 de fecha catorce de febrero de dos mil veintidós, otorgada ante la fe del Licenciado Ernesto Joaquín Briones Amador, Notario Público Titular de la Notaría Pública número 46 de las del Distrito Judicial de Puebla, Estado de Puebla, cuyo primer testimonio se encuentra inscrito ante las oficinas del Registro Público de Comercio del Distrito Judicial de Puebla, Estado de Puebla, bajo el Folio Mercantil Electrónico: N-2022022991, por virtud del cual se llevó a cabo la Constitución de la persona moral denominada CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE.</p>\r\n  <p>B. Que, la persona física que la representa en este acto, señalada en el Apartado 2.- de la Carátula, cuenta con todas y cada una de las facultades necesarias para la celebración del presente contrato, las cuales se desprenden del instrumento descrito en el punto declarativo inmediato anterior, mismas que manifiesta bajo protesta de decir verdad que no le han sido suspendidas, revocadas o limitadas en forma alguna.</p>\r\n  <p>C. Que, su representada tiene como domicilio fiscal el señalado en el Apartado 3.- de la Carátula del presente contrato, mismo que designa como domicilio convencional para cualquier cuestión relacionada con la celebración del presente contrato.</p>\r\n  <p>D. Que, su representada se encuentra inscrita en el Registro Federal de Contribuyentes bajo la clave señalada en el Apartado 4.- de la Carátula.</p>\r\n  <p>E. Que, ha desarrollado y es su deseo comparecer a la celebración del presente instrumento con la finalidad de enajenar en favor de “EL AFILIADO”, una Tarjeta de Descuento que da acceso a “UN PROGRAMA DE BENEFICIOS QUE OTORGA DESCUENTOS A LOS COSTOS Y PERMITE RECIBIR SERVICIOS MÉDICOS PRIVADOS DE ALTA CALIDAD DE FORMA ACCESIBLE, CLARA Y SIN RESTRICCIONES DENTRO DE LA RED DE HOSPITALES 50 (FIFTY) DOCTORS CON SEDE EN EL ESTADO DE PUEBLA”, en lo sucesivo “LA TARJETA DE DESCUENTO”, en los términos y condiciones que se establecerán más adelante.</p>\r\n  <p>F. Que, su representada no es una Aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas sino una empresa dedicada, entre otros, a la operación y administración de establecimientos destinados a la atención y asistencia de enfermos, por lo que la enajenación de “LA TARJETA DE DESCUENTO” únicamente constituye un acto de comercio que brindará a “EL AFILIADO” acceso a un programa de beneficios como ha quedado descrito anteriormente.</p>\r\n\r\n  <h4>II.- Declara “EL AFILIADO”, por su propio derecho:</h4>\r\n      <p>A. Que, su nombre se señala en el Apartado 5.- de la Carátula, es una persona física de nacionalidad mexicana, en pleno ejercicio de sus derechos, legal y jurídicamente capaz para celebrar el presente Contrato, quien se identifica con credencial para votar vigente expedida por el Instituto Nacional Electoral, tipo INE, número AAAA, que en copia simple o archivo digital se agrega al cuerpo del presente contrato como ANEXO 1.</p>\r\n    <p>B. Que, tiene como domicilio particular el señalado en el Apartado 6.- de la Carátula, mismo que designa como domicilio convencional para cualquier cuestión relacionada con la celebración del presente contrato, tal y como lo acredita con el comprobante de domicilio que en copia simple o archivo digital se agrega al cuerpo del presente contrato como ANEXO 2.</p>\r\n  <p>C. Que, su CURP es A y su RFC/identificación fiscal es AAA; asimismo manifiesta que cuenta con capacidad económica para obligarse en términos del presente contrato y que los recursos con los que cubrirá sus obligaciones provendrán de fuentes lícitas. En caso de nacionalidad extranjera/no mexicana, se tendrán por no aplicables CURP, INE y constancia fiscal mexicana salvo manifestación expresa de residencia fiscal o RFC mexicano.</p>\r\n  <p>D. Que, es su deseo comparecer a la celebración del presente instrumento con la finalidad de adquirir “LA TARJETA DE DESCUENTO” de acuerdo con los términos y condiciones que se establecen a continuación.</p>\r\n  <p>E. Que, previo a la celebración del presente contrato fue informado y manifiesta expresamente que reconoce que “EL PRESTADOR” no es una Aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas y que las actividades comerciales objeto del presente contrato no consisten en la contratación de un seguro, de la índole que fuere, sino que únicamente implica la adquisición de una tarjeta de descuento que da acceso a un programa de beneficios que otorga descuentos a los costos y permite recibir servicios médicos privados de alta calidad de forma accesible, clara y sin restricciones dentro de la red de hospitales 50 (FIFTY) Doctors con sede en el Estado de Puebla.</p>\r\n  <p>F. Que, reconoce que “EL PRESTADOR” se dedica a la operación de centros hospitalarios y que la emisión de “LA TARJETA DE DESCUENTO” únicamente corresponde a la intención de este último de crear un programa de descuentos para el acceso a los servicios prestados por la Red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla.</p>\r\n\r\n  <h4>III.- Declaran conjuntamente “LAS PARTES”:</h4>\r\n  <p>1. Que, se reconocen recíprocamente la personalidad con la que comparecen a la celebración del presente acuerdo de voluntades.</p>\r\n  <p>2. Que, el presente contrato es el instrumento que las vincula en sus derechos y obligaciones.</p>\r\n  <p>3. Que, es su deseo celebrar el presente contrato y han negociado libremente los términos y condiciones del mismo con pleno conocimiento de sus alcances e implicaciones jurídicas, por lo que en su celebración no existe dolo, error, mala fe, lesión o cualquier otro vicio del consentimiento que pudiese afectarlo de inexistencia o nulidad.</p>\r\n\r\n  <h2>C L Á U S U L A S</h2>\r\n  <h4>PRIMERA.- OBJETO.</h4>\r\n  <p>El objeto del presente Contrato es que “EL AFILIADO” adquiera de “EL PRESTADOR”, a título oneroso y temporal, el derecho de uso ilimitado y sin restricción alguna de “LA TARJETA DE DESCUENTO” emitida por CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE, la cual consiste en que “EL AFILIADO” aproveche y acceda a “UN PROGRAMA DE BENEFICIOS QUE OTORGA DESCUENTOS A LOS COSTOS Y PERMITE RECIBIR SERVICIOS MÉDICOS PRIVADOS DE ALTA CALIDAD DE FORMA ACCESIBLE, CLARA Y SIN RESTRICCIONES DENTRO DE LA RED DE HOSPITALES 50 (FIFTY) DOCTORS CON SEDE EN EL ESTADO DE PUEBLA”.</p>\r\n  <p>Estableciendo que, la comercialización de “LA TARJETA DE DESCUENTO” por parte de “EL PRESTADOR” en ningún momento constituirá la venta, promoción o por cualquier medio la contratación de una póliza de seguro, bajo el entendido de que “EL PRESTADOR” no es una aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas (CNSF); sino que comercializa “LA TARJETA DE DESCUENTO” en favor de terceros con la finalidad de otorgar descuentos a los precios respecto de los servicios médicos que presta en el territorio nacional.</p>\r\n\r\n  <h4>SEGUNDA.- PRECIO DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“LAS PARTES” establecen de común acuerdo que “LA TARJETA DE DESCUENTO” tendrá como costo mensual la cantidad señalada en el Apartado 8.- de la Carátula del presente contrato; cantidad que ya incluye IVA, y la cual deberá ser cubierta por “EL AFILIADO” en favor de “EL PRESTADOR” dentro de los primeros 5 (cinco) días de cada mes, sin necesidad de gestiones o avisos de cobro, ya sea mediante:</p>\r\n  <p>(i) Transferencia electrónica de fondos a la cuenta bancaria señalada en el Apartado 9.- de la Carátula del presente contrato y de la cual es titular “EL PRESTADOR”.</p>\r\n  <p>(ii) Cheque que se recibirá salvo buen cobro en el Domicilio de “EL PRESTADOR” señalado en el Apartado 3.- de la Carátula del presente contrato, y que en caso de no ser pagado por falta de fondos suficientes o por otras causas imputables a “EL AFILIADO”, éste último está de acuerdo en que deberá cubrir a “EL PRESTADOR” el 20% (veinte por ciento) del monto del cheque por concepto de indemnización por daños y perjuicios en términos del artículo 193 de la Ley General de Títulos y Operaciones de Crédito, independientemente de cualquier otro cargo que se pudiera generar.</p>\r\n  <p>(iii) Cargos mensuales automáticos recurrentes a la tarjeta de crédito de “EL AFILIADO” según los datos señalados en el Apartado 11.- de la Carátula del presente contrato, quien manifiesta bajo protesta de decir verdad que autoriza a “EL PRESTADOR” a realizar los cargos mensuales correspondientes por el costo mensual de “LA TARJETA DE DESCUENTO” en dicha tarjeta o en la tarjeta que por renovación, reposición, robo o extravío le haya asignado el banco emisor. La autorización estará vigente mientras “EL AFILIADO” no haya notificado a “EL PRESTADOR” por escrito y con acuse de recibo su deseo de cancelar su afiliación o no renovarla, o en su defecto, realizar su baja respectiva en el sitio web o aplicación de “EL PRESTADOR”.</p>\r\n  <p>Esta autorización no exime a “EL AFILIADO” del pago mensual por el uso de “LA TARJETA DE DESCUENTO” y demás obligaciones contractuales, por lo que, en caso de que el cobro no sea autorizado por el banco emisor o por cualquier razón no pueda realizarse, “EL AFILIADO” deberá notificar tal situación a “EL PRESTADOR” a la dirección de correo electrónico silvia@pasaporteatusalud.com, a efecto de solicitar una forma de pago diversa, quedando obligado a cubrir de inmediato el pago correspondiente.</p>\r\n  <p>(iv) Cualquier otro medio de pago aceptado por “EL PRESTADOR”, mismo que se dará a conocer a través de sus medios oficiales de comunicación.</p>\r\n  <p>“EL PRESTADOR” podrá variar unilateralmente el costo mensual de “LA TARJETA DE DESCUENTO”, previo aviso a “EL AFILIADO” con 30 (treinta) días de anticipación a través de sus medios oficiales de comunicación.</p>\r\n  <p>Para el caso de que “EL AFILIADO” adquiera y cubra el precio de “LA TARJETA DE DESCUENTO” y posteriormente deje de pagar una mensualidad, deberá cubrir a “EL PRESTADOR”, por concepto de cuota de reactivación, la cantidad señalada en el Apartado 10.- de la Carátula por cada mes que haya interrumpido y/o no haya cubierto el precio de “LA TARJETA DE DESCUENTO”, hasta la fecha en que pretenda volver a adquirirla.</p>\r\n\r\n  <h4>TERCERA.- VIGENCIA DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“LA TARJETA DE DESCUENTO” objeto del presente contrato tendrá una vigencia de 30 días contados a partir de que “EL AFILIADO” cubra a “EL PRESTADOR” el precio establecido anteriormente, en el entendido de que la vigencia del presente contrato y de “LA TARJETA DE DESCUENTO” se prorrogarán automáticamente sin necesidad de celebrar documento adicional entre “LAS PARTES” siempre y cuando “EL AFILIADO” cubra, de mes en mes o en la frecuencia contratada, el precio vigente de “LA TARJETA DE DESCUENTO”.</p>\r\n  <p>“EL AFILIADO” tendrá derecho a revocar su consentimiento dentro de los 5 (cinco) días siguientes a la entrega de “LA TARJETA DE DESCUENTO” o la firma del presente contrato, lo que ocurra último, sin responsabilidad alguna, siempre y cuando no haya obtenido beneficio alguno por el uso de “LA TARJETA DE DESCUENTO”.</p>\r\n\r\n  <h4>CUARTA.- BENEFICIOS DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“EL AFILIADO”, de forma exclusiva, personal e intransferible, gozará de forma gratuita de los servicios que se mencionan a continuación:</p>\r\n  <ul><li>Consultas gratuitas ilimitadas de medicina general (no de especialidad) en la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla, únicamente con los doctores afiliados al programa de Pasaporte a tu Salud.</li><li>Consultas de urgencia gratuitas en la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla.</li></ul>\r\n  <p>No así respecto de los servicios que, de manera enunciativa más no limitativa, se describen a continuación:</p>\r\n  <ul><li>Hospitalización dentro de la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla, sujeto a la disponibilidad de cada uno de ellos.</li><li>Consultas de especialidad ilimitadas a costo preferencial, con médicos especialistas pertenecientes al programa PATS.</li><li>Acceso a farmacia PATS con costos reducidos de medicamentos genéricos.</li><li>Imagenología y laboratorios ilimitados con costos preferenciales.</li><li>Acceso a cirugías con cuota de recuperación preferente, con o sin honorarios médicos incluidos según corresponda.</li></ul>\r\n  <p>Dichos servicios generarán, por evento, el pago de una cuota con cargo a “EL AFILIADO”, misma que resultará de aplicar los porcentajes de descuento que se desprenden del ANEXO 4 del presente contrato a los precios publicados al público en general o los precios preferenciales indicados.</p>\r\n  <p>Mientras “LA TARJETA DE DESCUENTO” se encuentre vigente, “EL AFILIADO” gozará de todos los beneficios que la misma le otorga; sin embargo, para el caso de que requiera cirugía o procedimiento quirúrgico en quirófano, deberá haber sufragado por adelantado la adquisición de “LA TARJETA DE DESCUENTO” por un periodo de 12 (doce) meses y encontrarse dentro de dicho periodo de vigencia.</p>\r\n\r\n  <h4>QUINTA.- OBLIGACIONES DE “EL PRESTADOR”.</h4>\r\n  <p>“EL PRESTADOR” se obliga a: (i) otorgar a “EL AFILIADO” el acceso ilimitado a “LA TARJETA DE DESCUENTO” durante la vigencia del contrato; (ii) mantener actualizada y operativa la Red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla; (iii) proporcionar a “EL AFILIADO”, de forma digital, “LA TARJETA DE DESCUENTO” dentro de los 5 (cinco) días hábiles siguientes al primer pago; e (iv) informar por escrito cualquier modificación a la red de hospitales o al tabulador de cuotas con al menos 10 (diez) días de anticipación.</p>\r\n\r\n  <h4>SEXTA.- OBLIGACIONES DE “EL AFILIADO”.</h4>\r\n  <p>“EL AFILIADO” se obliga a: (i) pagar puntualmente el precio de “LA TARJETA DE DESCUENTO”; (ii) utilizarla de forma exclusiva, personal e intransferible; (iii) cubrir directamente a los hospitales y con anterioridad a recibir el servicio médico las cuotas de recuperación según tabulador vigente; (iv) presentar identificación oficial y “LA TARJETA DE DESCUENTO” o código QR cada vez que haga uso de beneficios; y (v) notificar por escrito cualquier cambio de domicilio o datos de contacto en un plazo no mayor a 5 (cinco) días.</p>\r\n\r\n  <h4>SÉPTIMA.- ACCESO A LOS BENEFICIOS Y PROCEDIMIENTO.</h4>\r\n  <p>Para hacer uso de “LA TARJETA DE DESCUENTO”, “EL AFILIADO” deberá agendar sus citas directamente con los doctores pertenecientes a la Red de Hospitales 50 (FIFTY) Doctors, que en ese momento se encuentren adscritos al programa de beneficios, a través de la aplicación oficial, página de internet oficial de PATS o medios oficiales que indique “EL PRESTADOR”.</p>\r\n  <p>“EL AFILIADO” se obliga a pagar directamente al médico especialista perteneciente al programa el costo de la consulta de especialidad de que se trate, en términos de los porcentajes de descuento del ANEXO 4. En caso de no estar facultado para asistir por fuerza mayor, tendrá un plazo de 30 (treinta) días contados a partir de haber generado la cita para solicitar una nueva consulta médica.</p>\r\n\r\n  <h4>OCTAVA.- EXCLUSIONES Y LIMITACIONES.</h4>\r\n  <p>Los beneficios no incluirán: (i) trasplantes de órganos; (ii) tratamientos experimentales; (iii) tratamientos de oncología a excepción de algunas cirugías; (iv) medicamentos extra hospitalarios que no estén recogidos en el catálogo de Farmacia PATS; (v) atención médica con especialistas no adscritos o no publicados en los medios oficiales; y (vi) cualquier servicio no listado expresamente.</p>\r\n\r\n  <h4>NOVENA.- CAUSAS DE TERMINACIÓN.</h4>\r\n  <p>El contrato podrá terminarse por falta de pago, mutuo consentimiento por escrito o incumplimiento de cualquiera de las cláusulas por cualquiera de “LAS PARTES”. En caso de terminación, “EL AFILIADO” no tendrá derecho a exigir la devolución de cantidad alguna.</p>\r\n\r\n  <h4>DÉCIMA.- CANCELACIÓN VOLUNTARIA.</h4>\r\n  <p>“EL AFILIADO” podrá cancelar “LA TARJETA DE DESCUENTO” mediante aviso por escrito con 30 (treinta) días de anticipación. Dicha cancelación surtirá efectos a partir del siguiente periodo mensual y no generará reembolso de pagos ya realizados.</p>\r\n\r\n  <h4>DÉCIMA PRIMERA.- PROTECCIÓN DE DATOS PERSONALES.</h4>\r\n  <p>“LAS PARTES” acuerdan que el tratamiento de datos personales se sujetará a la Ley Federal de Protección de Datos Personales en Posesión de los Particulares. “EL AFILIADO” autoriza expresamente el uso de sus datos para la gestión de “LA TARJETA DE DESCUENTO”. El aviso de privacidad se integra al presente contrato como ANEXO 5.</p>\r\n\r\n  <h4>DÉCIMA SEGUNDA.- RESPONSABILIDAD.</h4>\r\n  <p>“EL AFILIADO” reconoce y acepta que “LA TARJETA DE DESCUENTO” es emitida y administrada directamente por CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE, quien es responsable de la operación de la red de descuentos, afiliación de prestadores médicos y prestación de cualquier servicio relacionado con “LA TARJETA DE DESCUENTO”.</p>\r\n  <p>En consecuencia, “EL PRESTADOR” no tendrá responsabilidad directa ni indirecta por la prestación, calidad, eficacia, resultado, daño, perjuicio, lesión, complicación, secuela, evento adverso o consecuencia derivada de servicios médicos recibidos, incluyendo aquellos ocasionados por negligencia, impericia o mala praxis de profesionales de la salud o prestadores afiliados. Cualquier relación derivada de la prestación de servicios médicos se establece directamente entre “EL AFILIADO” y los prestadores de servicios de salud correspondientes. Esta limitación subsistirá a la terminación del contrato.</p>\r\n\r\n  <h4>DÉCIMA TERCERA.- PREVENCIÓN DE LAVADO DE DINERO Y ORIGEN DE LOS RECURSOS.</h4>\r\n  <p>“LAS PARTES” declaran bajo protesta de decir verdad que los recursos económicos, bienes y derechos que utilicen para cumplir obligaciones derivadas de este contrato tienen y tendrán origen lícito. “EL AFILIADO” manifiesta que el pago inicial y pagos futuros provienen de fuentes lícitas y no de actividades tipificadas como delitos.</p>\r\n  <p>“LAS PARTES” reconocen que la prestación de servicios de comercio puede ser considerada actividad vulnerable, por lo que se obligan a proporcionar información y documentación requerida para integrar expediente de identificación e informar si tienen conocimiento de la existencia de beneficiario controlador.</p>\r\n\r\n  <h4>DÉCIMA CUARTA.- CONFORMACIÓN DEL EXPEDIENTE DE IDENTIFICACIÓN.</h4>\r\n  <p>“EL PRESTADOR” queda obligado a conformar y mantener un expediente de identificación de “EL AFILIADO”. Para tales efectos, “EL AFILIADO” se obliga a entregar los documentos aplicables: identificación oficial vigente o pasaporte, acta de nacimiento cuando aplique, comprobante de domicilio, constancia de situación fiscal cuando aplique, CURP, y declaración de dueño beneficiario.</p>\r\n  <p>Cuando exista persona responsable, la documentación de identificación y representación deberá integrarse al expediente; la CIF/constancia fiscal corresponde al tutor cuando aplique. “EL PRESTADOR” conservará dicho expediente por un periodo mínimo de 5 (cinco) años contados a partir de que termine la vigencia del contrato o termine por cualquiera de sus causales, garantizando la confidencialidad de los datos personales.</p>\r\n\r\n  <h4>DÉCIMA QUINTA.- CAUSAL ESPECÍFICA DE RESCISIÓN.</h4>\r\n  <p>Será motivo de rescisión inmediata sin necesidad de declaración judicial y sin responsabilidad para la parte afectada cuando cualquiera de “LAS PARTES” se niegue a proporcionar información requerida para cumplimiento de la Ley Federal para la Prevención e Identificación de Operaciones con Recursos de Procedencia Ilícita, proporcione información falsa o aparezca en listas de personas bloqueadas emitidas por autoridad competente.</p>\r\n\r\n  <h4>DÉCIMA SEXTA.- LEGISLACIÓN APLICABLE Y JURISDICCIÓN.</h4>\r\n  <p>“LAS PARTES” establecen que la Procuraduría Federal del Consumidor es competente en vía administrativa para resolver cualquier controversia sobre interpretación o cumplimiento. Sin perjuicio de lo anterior, se someten expresamente a la jurisdicción de los tribunales competentes del fuero común del Distrito Judicial de Puebla, Estado de Puebla, renunciando de manera expresa e irrevocable a cualquier otro fuero o jurisdicción que pudiera corresponderles.</p>\r\n\r\n  <p>Enteradas “LAS PARTES” del contenido y alcance del presente contrato, y entendidas de los derechos y obligaciones que contraen, firman el presente instrumento, incluyendo sus anexos, manifestando que no medió error, dolo, mala fe, violencia o lesión, ni vicio del consentimiento alguno, en la Ciudad de Puebla, Estado de Puebla, reconociendo que la fecha de firma es 13 de mayo de 2026.</p>\r\n\r\n  <div class=\"sign-grid\">\r\n    <div class=\"sign-box\"><div class=\"line\"></div><strong>“EL PRESTADOR”</strong><br>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE<br>Representada por PEDRO AZCÁRRAGA RAMOS</div>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>“EL AFILIADO”</strong><br>Juan a a</div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 1<br>Identificación oficial de “EL AFILIADO”</h2><p>Se integra al expediente la identificación oficial cargada por el usuario en el formulario. Para mexicanos, corresponde a identificación oficial/INE cuando aplique. Para extranjeros/no mexicanos, corresponde a identificación oficial o pasaporte vigente; al menos el frente es obligatorio y el reverso será opcional cuando el documento no lo tenga.</p><p><strong>Tipo:</strong> INE. <strong>Emitida por / país emisor:</strong> México. <strong>Número:</strong> AAAA.</p></div>\r\n  <div class=\"annex\"><h2>ANEXO 2<br>COMPROBANTE DE DOMICILIO DE “EL AFILIADO”</h2><p>Se integra al expediente el comprobante de domicilio cargado por el usuario. Domicilio declarado: aa 452, Col. sss, C.P. 15325, aaa, Jalisco, México.</p></div>\r\n  <div class=\"annex\"><h2>ANEXO 3<br>CONSTANCIA DE SITUACIÓN FISCAL DE “EL AFILIADO”</h2><p>Constancia de Situación Fiscal de “EL AFILIADO”, si aplica. En caso de pacientes representados, la constancia fiscal o CIF corresponde a la persona responsable cuando sea aplicable, no al menor. Para afiliados extranjeros/no mexicanos, no será obligatoria salvo que declaren RFC mexicano o residencia fiscal aplicable.</p></div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 4<br>CUOTAS DE RECUPERACIÓN Y/O PRECIOS BASE A CUBRIR A “EL PRESTADOR”</h2>\r\n    <p>En el presente anexo se establecen los porcentajes de descuento a obtener como titular de “LA TARJETA DE DESCUENTO”, por lo que la cantidad a cubrir por “EL AFILIADO” directamente al hospital de la cadena 50 (FIFTY) Doctors o al doctor que preste el servicio se obtendrá de aplicar el porcentaje de descuento correspondiente al precio publicado por los medios oficiales o al precio vigente en el establecimiento.</p>\r\n    <table><tr><th>Servicios / procedimientos</th><th>Descuentos</th></tr><tr><td>Consulta de urgencias</td><td>100%</td></tr><tr><td>Consulta de medicina general</td><td>100%</td></tr><tr><td>Habitación hospitalaria</td><td>90%</td></tr><tr><td>Uso de áreas de urgencias médicas</td><td>80%</td></tr><tr><td>Utilización de cubículos de terapia intensiva (UCIA-UCIN-UCIP)</td><td>75%</td></tr><tr><td>CEYE</td><td>75%</td></tr><tr><td>Uso quirófano</td><td>75%</td></tr><tr><td>Servicio de cuneros</td><td>75%</td></tr><tr><td>Materiales & medicamentos del cuadro básico, genéricos intercambiables</td><td>70%</td></tr><tr><td>Hemodinamia</td><td>70%</td></tr><tr><td>Imagenología</td><td>70%</td></tr><tr><td>Endoprótesis</td><td>70%</td></tr><tr><td>Osteosíntesis</td><td>70%</td></tr><tr><td>Prótesis</td><td>70%</td></tr><tr><td>Órtesis</td><td>70%</td></tr><tr><td>Laboratorio clínico</td><td>60%</td></tr></table>\r\n    <p class=\"small\">Los descuentos aplican con los proveedores suscritos al convenio de Pasaporte a tu Salud.</p>\r\n    <table><tr><th>Servicios / procedimientos</th><th>Precios base</th></tr><tr><td>Consulta de especialidades médicas</td><td>$390.00</td></tr><tr><td>Colposcopía</td><td>$400.00</td></tr><tr><td>Retiro de puntos de sutura</td><td>$80.00</td></tr><tr><td>Aplicación de medicamento intramuscular</td><td>$60.00</td></tr><tr><td>Retiro de DIU</td><td>$500.00</td></tr><tr><td>Colocación de DIU</td><td>$700.00</td></tr><tr><td>Extracción de cuerpo extraño (oído y nariz)</td><td>$300.00</td></tr><tr><td>Lavado ótico</td><td>$250.00</td></tr><tr><td>Curación de sitio quirúrgico</td><td>$250.00</td></tr><tr><td>Retiro de yeso</td><td>$250.00</td></tr><tr><td>Visita día de hospitalización</td><td>$650.00</td></tr><tr><td>Visita de urgencias</td><td>$750.00</td></tr><tr><td>Día de terapia intensiva</td><td>$850.00</td></tr></table>\r\n    <p class=\"small\">Todos los precios incluyen IVA. La factura de servicios hospitalarios será emitida con el desglose correspondiente y el ahorro otorgado por ser titular de “LA TARJETA DE DESCUENTO”.</p>\r\n    <p>Exclusiones y limitaciones: se aplicarán descuentos y precios especiales para el acompañante de “EL AFILIADO” en la misma habitación únicamente para la primera noche de hospitalización. Los precios y porcentajes de descuento darán derecho a la utilización de materiales y medicamentos del cuadro básico, genéricos intercambiables; cualquier otro tipo de medicación será cubierto directamente por “EL AFILIADO”. Los costos de procedimientos quirúrgicos incluyen honorarios médicos cuando así se indique. “EL AFILIADO” podrá atenderse con el médico tratante que elija, debiendo cubrir honorarios directamente a dicho médico, conservando el derecho a beneficios dentro de la red aplicable.</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Firma de aceptación de “EL AFILIADO”</strong><br>Juan a a</div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 5<br>AVISO DE PRIVACIDAD</h2>\r\n    <p>En cumplimiento de las disposiciones establecidas en la Ley Federal de Protección de Datos Personales en Posesión de Particulares, su Reglamento y los lineamientos aplicables, “CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE” (en lo sucesivo “EL PRESTADOR”), con domicilio en CALLE PASEO SINFONÍA NÚMERO EXTERIOR 1, LOCAL 2-14, LOMAS DE ANGELÓPOLIS II, SAN ANDRÉS CHOLULA, ESTADO DE PUEBLA, CÓDIGO POSTAL 72830, da a conocer el Aviso de Privacidad al tenor del cual manejará por medio de su representación y/o empleados los datos personales y/o documentación proporcionada por el afiliado o usuario de “LA TARJETA DE DESCUENTO”.</p>\r\n    <p>Se tendrá por aceptado expresamente el presente Aviso de Privacidad una vez proporcionados los datos personales y firmada digitalmente la aceptación del contrato, motivo por el cual “EL PRESTADOR” estará facultado para manejar la información conforme a la legislación aplicable.</p>\r\n    <h4>Modificación del aviso de privacidad</h4><p>Este aviso podrá ser modificado o adecuado a las necesidades de “EL PRESTADOR”. Las modificaciones o actualizaciones serán incorporadas al presente aviso y estarán disponibles en la página de internet, domicilio de “EL PRESTADOR” o serán enviadas al último correo electrónico proporcionado.</p>\r\n    <h4>Finalidad de la información</h4><p>La información será utilizada para: elaborar y mantener actualizada la base de usuarios; identificar afiliados; proporcionar la tarjeta digital; otorgar acceso al programa de beneficios; informar modificaciones a la red o tabulador; realizar análisis estadísticos internos y brindar un óptimo servicio médico.</p>\r\n    <h4>Tipo de datos necesarios</h4><p>Se solicitarán datos de identificación, contacto, legales, contractuales y fiscales cuando aplique, incluyendo nombre completo, lugar y fecha de nacimiento, firma, identificación oficial, nacionalidad, CURP y RFC cuando sean aplicables, domicilio, teléfono y correo electrónico.</p>\r\n    <h4>Transferencias de la información</h4><p>El usuario autoriza proporcionar información sin consentimiento adicional en los casos previstos por ley, resolución de autoridad competente, tratados aplicables, salvaguarda de interés público, procuración o administración de justicia, reconocimiento o defensa de derechos en procesos judiciales, y a socios comerciales, técnicos o estratégicos que asuman obligaciones de confidencialidad y seguridad equivalentes.</p>\r\n    <h4>Limitación del uso o divulgación de datos y derechos ARCO</h4><p>El usuario podrá limitar el uso o divulgación de sus datos personales y ejercer derechos de acceso, rectificación, cancelación u oposición mediante solicitud escrita dirigida a “EL PRESTADOR” en su domicilio o al correo silvia@pasaporteatusalud.com, acompañando documento que acredite su identidad.</p>\r\n    <h4>Revocación de consentimiento</h4><p>El usuario podrá revocar su consentimiento siguiendo el mismo procedimiento, considerando que para ciertos fines la revocación puede implicar la cancelación de “LA TARJETA DE DESCUENTO” y la imposibilidad de acceder al programa.</p>\r\n    <p><strong>Nombre:</strong> Juan a a<br><strong>Fecha:</strong> 13 de mayo de 2026</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Firma</strong></div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 6<br>DECLARACIÓN DE DUEÑO BENEFICIARIO</h2>\r\n    <p>DE CONFORMIDAD CON LO DISPUESTO EN LOS ARTÍCULOS 18 FRACCIÓN I Y III DE LA LEY FEDERAL PARA PREVENCIÓN E IDENTIFICACIÓN DE OPERACIONES CON RECURSOS DE PROCEDENCIA ILÍCITA, EL ARTÍCULO 15 DE SU REGLAMENTO Y EL ARTÍCULO 13 DE LAS REGLAS DE CARÁCTER GENERAL, MANIFIESTO BAJO PROTESTA DE DECIR VERDAD:</p>\r\n    <h4>Datos de identificación del cliente</h4>\r\n    <table><tr><th>Campo</th><th>Respuesta</th></tr><tr><td>Apellido paterno, materno y nombre(s)</td><td>Juan a a</td></tr><tr><td>Fecha de nacimiento</td><td>1981-08-20</td></tr><tr><td>País de nacimiento</td><td>México</td></tr><tr><td>Nacionalidad</td><td>mexicana</td></tr><tr><td>Actividad, ocupación o profesión</td><td>aaa</td></tr><tr><td>Estado civil</td><td>SOLTERO(A)</td></tr><tr><td>Domicilio particular</td><td>aa 452, Col. sss, C.P. 15325, aaa, Jalisco, México</td></tr><tr><td>Teléfonos</td><td>4521252145</td></tr><tr><td>Correo electrónico</td><td>roel.fuentes@gmail.com</td></tr><tr><td>CURP</td><td>A</td></tr><tr><td>RFC</td><td>AAA</td></tr><tr><td>Tipo de identificación</td><td>INE</td></tr><tr><td>Emitida por / país emisor</td><td>México</td></tr><tr><td>Número de identificación</td><td>AAAA</td></tr></table>\r\n    <h4>Datos de identificación de la operación</h4>\r\n    <table><tr><th>Campo</th><th>Respuesta</th></tr><tr><td>Tipo de operación</td><td>Adquisición de tarjeta de descuento PATS</td></tr><tr><td>Monto de operación</td><td>$800.00 M.N.</td></tr><tr><td>Fecha de operación</td><td>13 de mayo de 2026</td></tr><tr><td>Forma de pago</td><td>Pasarela / medio autorizado por “EL PRESTADOR”</td></tr><tr><td>Moneda</td><td>MXN</td></tr></table>\r\n    <h4>Información de la existencia del dueño beneficiario o beneficiario controlador</h4>\r\n    <p>Declaro que soy el beneficiario directo de la operación y no existe ningún otro dueño beneficiario o beneficiario controlador: <strong>SI</strong>.</p>\r\n    <h4>Aviso de privacidad</h4><p>Los datos personales serán protegidos y tratados conforme al Aviso de Privacidad contenido en el cuerpo del presente contrato y la legislación aplicable.</p>\r\n    <p>H. Puebla de Zaragoza al 13 del mes de mayo del año 2026.</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Nombre y firma</strong><br>Juan a a</div>\r\n  </div>\r\n\r\n  \r\n  </div>\r\n', 'data:image/png;base64,', 'Juan a a', 'e6da2af40dcc86eebdb1476be924e11d3f12c5ea51a69eff0a8fa12894499a6f', '2026-05-13 22:02:54', '189.190.196.8', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:150.0) Gecko/20100101 Firefox/150.0', '', 'firmado', '2026-05-13 22:02:54', '2026-05-13 22:02:54');
INSERT INTO `pats_contratos_firmados` (`id_contrato_firmado`, `id_orden`, `id_pasaporte`, `id_distribuidor`, `id_franquicia`, `token_publico`, `contrato_clave`, `contrato_version`, `html_contrato_renderizado`, `firma_afiliado_base64`, `nombre_firmante`, `hash_contrato`, `fecha_firma`, `ip_firma`, `user_agent_firma`, `pdf_path`, `estatus`, `created_at`, `updated_at`) VALUES
(14, 2, 2, 0, 0, '', 'contrato_pats_base', '1.0', '<style>\r\n  .pats-contract{font-family:Arial,Helvetica,sans-serif;color:#172033;font-size:12px;line-height:1.52;background:#fff;padding:4px}\r\n  .pats-contract h1,.pats-contract h2,.pats-contract h3,.pats-contract h4{text-align:center;margin:12px 0 8px;color:#0d1b3e}\r\n  .pats-contract h1{font-size:16px;text-transform:uppercase;letter-spacing:.05em}\r\n  .pats-contract h2{font-size:15px;text-transform:uppercase;letter-spacing:.04em}\r\n  .pats-contract h3{font-size:13px;text-transform:uppercase;letter-spacing:.08em}\r\n  .pats-contract h4{font-size:12px;text-align:left;text-transform:uppercase;margin-top:12px}\r\n  .pats-contract p{margin:6px 0;text-align:justify}\r\n  .pats-contract ul{margin:6px 0 8px 18px;padding:0}.pats-contract li{margin:4px 0;text-align:justify}\r\n  .pats-contract table{width:100%;border-collapse:collapse;margin:8px 0 12px}.pats-contract th,.pats-contract td{border:1px solid #cbd5e1;padding:6px;vertical-align:top}.pats-contract th{background:#eef4ff;color:#0d1b3e;text-align:left}\r\n  .pats-contract .center{text-align:center}.pats-contract .muted{color:#64748b}.pats-contract .small{font-size:10px}.pats-contract .badge{display:inline-block;padding:3px 8px;border-radius:999px;background:#eef4ff;color:#1d4ed8;font-weight:700;margin:2px 4px 2px 0}\r\n  .pats-contract .sign-grid{display:grid;grid-template-columns:1fr 1fr;gap:22px;margin-top:28px}.pats-contract .sign-box{text-align:center;min-height:95px}.pats-contract .line{border-top:1px solid #0f172a;margin:48px 8px 6px}.pats-contract .signature-img{max-width:220px;max-height:82px;display:block;margin:0 auto 4px}\r\n  .pats-contract .annex{page-break-before:auto;border-top:2px solid #0d1b3e;margin-top:18px;padding-top:12px}.pats-contract .page-break{page-break-before:always;border-top:1px dashed #cbd5e1;margin-top:18px;padding-top:12px}\r\n</style>\r\n<div class=\"pats-contract\">\r\n  <h1>Carátula del contrato de adquisición de tarjeta de descuento</h1>\r\n  <p>CARÁTULA DEL CONTRATO DE ADQUISICIÓN DE TARJETA DE DESCUENTO (EN LO SUCESIVO “LA CARÁTULA”), QUE CELEBRAN POR UNA PARTE LA SOCIEDAD SEÑALADA EN EL APARTADO 1.- DE LA CARÁTULA, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL PRESTADOR”, REPRESENTADA EN ESTE ACTO POR LA PERSONA FÍSICA QUE SE INDICA EN EL APARTADO 2.- DE LA CARÁTULA; Y POR LA OTRA PARTE, LA PERSONA FÍSICA SEÑALADA EN EL APARTADO 5.- DE LA CARÁTULA, POR SU PROPIO DERECHO, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL AFILIADO”; Y CUANDO LOS ANTES NOMBRADOS ACTÚEN DE MANERA CONJUNTA, SE LES DENOMINARÁ COMO “LAS PARTES”; QUIENES SE SUJETAN AL TENOR DE LA CARÁTULA, DECLARACIONES Y CLÁUSULAS SIGUIENTES:</p>\r\n    \r\n  <h2>C A R Á T U L A</h2>\r\n  <table>\r\n    <tr><th style=\"width:8%\">Apartado</th><th style=\"width:42%\">Definición</th><th>Respuesta</th></tr>\r\n    <tr><td>1.-</td><td>Nombre de “EL PRESTADOR”</td><td>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE</td></tr>\r\n    <tr><td>2.-</td><td>Nombre del Representante Legal de “EL PRESTADOR”</td><td>PEDRO AZCÁRRAGA RAMOS</td></tr>\r\n    <tr><td>3.-</td><td>Domicilio de “EL PRESTADOR”</td><td>CALLE PASEO SINFONÍA NÚMERO EXTERIOR 1, LOCAL 2-14, LOMAS DE ANGELÓPOLIS II, SAN ANDRÉS CHOLULA, ESTADO DE PUEBLA, CÓDIGO POSTAL 72830</td></tr>\r\n    <tr><td>4.-</td><td>Clave del Registro Federal de Contribuyentes de “EL PRESTADOR”</td><td>COH2202144H5</td></tr>\r\n    <tr><td>5.-</td><td>Nombre de “EL AFILIADO”</td><td>Silvia Ornia Corral</td></tr>\r\n    <tr><td>6.-</td><td>Domicilio de “EL AFILIADO”</td><td>toscana 320 Int. 1b, Col. Florencia, C.P. 25886, Puebla, Puebla, México</td></tr>\r\n    <tr><td>7.-</td><td>Clave del Registro Federal de Contribuyentes de “EL AFILIADO”</td><td>67</td></tr>\r\n    <tr><td>8.-</td><td>Costo mensual de “LA TARJETA DE DESCUENTO”</td><td>$800.00 M.N.</td></tr>\r\n    <tr><td>9.-</td><td>Cuenta bancaria de “EL PRESTADOR” para pagos</td><td>Cuenta: 01600866709<br>CLABE: 042650016008667096<br>Institución Bancaria: Banca Mifel, S.A., Institución de Banca Múltiple, Grupo Financiero Mifel</td></tr>\r\n    <tr><td>10.-</td><td>Cuota de Reactivación de “LA TARJETA DE DESCUENTO”</td><td>$100.00 M.N. por cada mes que se haya interrumpido el pago.</td></tr>\r\n    <tr><td>11.-</td><td>Datos de la Tarjeta de Crédito de “EL AFILIADO”</td><td>Número de tarjeta: pendiente de confirmar por pasarela/token de pago.<br>Institución bancaria: pendiente de confirmar por pasarela. <br><span class=\"small\">No se almacena número completo de tarjeta en este formulario.</span></td></tr>\r\n    <tr><td>12.-</td><td>Anexos</td><td>ANEXO 1. Identificación oficial de “EL AFILIADO”<br>ANEXO 2. Comprobante de domicilio de “EL AFILIADO”<br>ANEXO 3. Constancia de Situación Fiscal de “EL AFILIADO”, si aplica<br>ANEXO 4. Cuotas de recuperación y/o precios base a cubrir a “EL PRESTADOR”<br>ANEXO 5. Aviso de privacidad<br>ANEXO 6. Declaración de dueño beneficiario</td></tr>\r\n    <tr><td>13.-</td><td>Fecha de Firma del Contrato</td><td>13 de mayo de 2026</td></tr>\r\n  </table>\r\n\r\n  <div class=\"sign-grid\">\r\n    <div class=\"sign-box\"><div class=\"line\"></div><strong>“EL PRESTADOR”</strong><br>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE<br>Representada por PEDRO AZCÁRRAGA RAMOS</div>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>“EL AFILIADO”</strong><br>Silvia Ornia Corral<br><span class=\"small\">La persona física señalada en el Apartado 5.- de la Carátula</span></div>\r\n  </div>\r\n\r\n  <div class=\"page-break\"></div>\r\n  <h1>Contrato de adquisición de tarjeta de descuento</h1>\r\n  <p>CONTRATO DE ADQUISICIÓN DE TARJETA DE DESCUENTO, QUE CELEBRAN POR UNA PARTE LA SOCIEDAD SEÑALADA EN EL APARTADO 1.- DE LA CARÁTULA, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL PRESTADOR”, REPRESENTADA EN ESTE ACTO POR LA PERSONA FÍSICA QUE SE INDICA EN EL APARTADO 2.- DE LA CARÁTULA; Y POR LA OTRA PARTE, LA PERSONA FÍSICA SEÑALADA EN EL APARTADO 5.- DE LA CARÁTULA, POR SU PROPIO DERECHO, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL AFILIADO”; Y CUANDO LOS ANTES NOMBRADOS ACTÚEN DE MANERA CONJUNTA, SE LES DENOMINARÁ COMO “LAS PARTES”; QUIENES SE SUJETAN AL TENOR DE LAS DECLARACIONES Y CLÁUSULAS SIGUIENTES:</p>\r\n\r\n  <h2>D E C L A R A C I O N E S</h2>\r\n  <h4>I.- Declara “EL PRESTADOR” por conducto de su representación:</h4>\r\n  <p>A. Que, su representada es una sociedad mercantil constituida conforme a las leyes de los Estados Unidos Mexicanos, según consta en la escritura pública número 39,861, del volumen 830 de fecha catorce de febrero de dos mil veintidós, otorgada ante la fe del Licenciado Ernesto Joaquín Briones Amador, Notario Público Titular de la Notaría Pública número 46 de las del Distrito Judicial de Puebla, Estado de Puebla, cuyo primer testimonio se encuentra inscrito ante las oficinas del Registro Público de Comercio del Distrito Judicial de Puebla, Estado de Puebla, bajo el Folio Mercantil Electrónico: N-2022022991, por virtud del cual se llevó a cabo la Constitución de la persona moral denominada CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE.</p>\r\n  <p>B. Que, la persona física que la representa en este acto, señalada en el Apartado 2.- de la Carátula, cuenta con todas y cada una de las facultades necesarias para la celebración del presente contrato, las cuales se desprenden del instrumento descrito en el punto declarativo inmediato anterior, mismas que manifiesta bajo protesta de decir verdad que no le han sido suspendidas, revocadas o limitadas en forma alguna.</p>\r\n  <p>C. Que, su representada tiene como domicilio fiscal el señalado en el Apartado 3.- de la Carátula del presente contrato, mismo que designa como domicilio convencional para cualquier cuestión relacionada con la celebración del presente contrato.</p>\r\n  <p>D. Que, su representada se encuentra inscrita en el Registro Federal de Contribuyentes bajo la clave señalada en el Apartado 4.- de la Carátula.</p>\r\n  <p>E. Que, ha desarrollado y es su deseo comparecer a la celebración del presente instrumento con la finalidad de enajenar en favor de “EL AFILIADO”, una Tarjeta de Descuento que da acceso a “UN PROGRAMA DE BENEFICIOS QUE OTORGA DESCUENTOS A LOS COSTOS Y PERMITE RECIBIR SERVICIOS MÉDICOS PRIVADOS DE ALTA CALIDAD DE FORMA ACCESIBLE, CLARA Y SIN RESTRICCIONES DENTRO DE LA RED DE HOSPITALES 50 (FIFTY) DOCTORS CON SEDE EN EL ESTADO DE PUEBLA”, en lo sucesivo “LA TARJETA DE DESCUENTO”, en los términos y condiciones que se establecerán más adelante.</p>\r\n  <p>F. Que, su representada no es una Aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas sino una empresa dedicada, entre otros, a la operación y administración de establecimientos destinados a la atención y asistencia de enfermos, por lo que la enajenación de “LA TARJETA DE DESCUENTO” únicamente constituye un acto de comercio que brindará a “EL AFILIADO” acceso a un programa de beneficios como ha quedado descrito anteriormente.</p>\r\n\r\n  <h4>II.- Declara “EL AFILIADO”, por su propio derecho:</h4>\r\n      <p>A. Que, su nombre se señala en el Apartado 5.- de la Carátula, es una persona física de nacionalidad mexicana, en pleno ejercicio de sus derechos, legal y jurídicamente capaz para celebrar el presente Contrato, quien se identifica con credencial para votar vigente expedida por el Instituto Nacional Electoral, tipo INE, número 22, que en copia simple o archivo digital se agrega al cuerpo del presente contrato como ANEXO 1.</p>\r\n    <p>B. Que, tiene como domicilio particular el señalado en el Apartado 6.- de la Carátula, mismo que designa como domicilio convencional para cualquier cuestión relacionada con la celebración del presente contrato, tal y como lo acredita con el comprobante de domicilio que en copia simple o archivo digital se agrega al cuerpo del presente contrato como ANEXO 2.</p>\r\n  <p>C. Que, su CURP es 222222222222222222 y su RFC/identificación fiscal es 67; asimismo manifiesta que cuenta con capacidad económica para obligarse en términos del presente contrato y que los recursos con los que cubrirá sus obligaciones provendrán de fuentes lícitas. En caso de nacionalidad extranjera/no mexicana, se tendrán por no aplicables CURP, INE y constancia fiscal mexicana salvo manifestación expresa de residencia fiscal o RFC mexicano.</p>\r\n  <p>D. Que, es su deseo comparecer a la celebración del presente instrumento con la finalidad de adquirir “LA TARJETA DE DESCUENTO” de acuerdo con los términos y condiciones que se establecen a continuación.</p>\r\n  <p>E. Que, previo a la celebración del presente contrato fue informado y manifiesta expresamente que reconoce que “EL PRESTADOR” no es una Aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas y que las actividades comerciales objeto del presente contrato no consisten en la contratación de un seguro, de la índole que fuere, sino que únicamente implica la adquisición de una tarjeta de descuento que da acceso a un programa de beneficios que otorga descuentos a los costos y permite recibir servicios médicos privados de alta calidad de forma accesible, clara y sin restricciones dentro de la red de hospitales 50 (FIFTY) Doctors con sede en el Estado de Puebla.</p>\r\n  <p>F. Que, reconoce que “EL PRESTADOR” se dedica a la operación de centros hospitalarios y que la emisión de “LA TARJETA DE DESCUENTO” únicamente corresponde a la intención de este último de crear un programa de descuentos para el acceso a los servicios prestados por la Red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla.</p>\r\n\r\n  <h4>III.- Declaran conjuntamente “LAS PARTES”:</h4>\r\n  <p>1. Que, se reconocen recíprocamente la personalidad con la que comparecen a la celebración del presente acuerdo de voluntades.</p>\r\n  <p>2. Que, el presente contrato es el instrumento que las vincula en sus derechos y obligaciones.</p>\r\n  <p>3. Que, es su deseo celebrar el presente contrato y han negociado libremente los términos y condiciones del mismo con pleno conocimiento de sus alcances e implicaciones jurídicas, por lo que en su celebración no existe dolo, error, mala fe, lesión o cualquier otro vicio del consentimiento que pudiese afectarlo de inexistencia o nulidad.</p>\r\n\r\n  <h2>C L Á U S U L A S</h2>\r\n  <h4>PRIMERA.- OBJETO.</h4>\r\n  <p>El objeto del presente Contrato es que “EL AFILIADO” adquiera de “EL PRESTADOR”, a título oneroso y temporal, el derecho de uso ilimitado y sin restricción alguna de “LA TARJETA DE DESCUENTO” emitida por CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE, la cual consiste en que “EL AFILIADO” aproveche y acceda a “UN PROGRAMA DE BENEFICIOS QUE OTORGA DESCUENTOS A LOS COSTOS Y PERMITE RECIBIR SERVICIOS MÉDICOS PRIVADOS DE ALTA CALIDAD DE FORMA ACCESIBLE, CLARA Y SIN RESTRICCIONES DENTRO DE LA RED DE HOSPITALES 50 (FIFTY) DOCTORS CON SEDE EN EL ESTADO DE PUEBLA”.</p>\r\n  <p>Estableciendo que, la comercialización de “LA TARJETA DE DESCUENTO” por parte de “EL PRESTADOR” en ningún momento constituirá la venta, promoción o por cualquier medio la contratación de una póliza de seguro, bajo el entendido de que “EL PRESTADOR” no es una aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas (CNSF); sino que comercializa “LA TARJETA DE DESCUENTO” en favor de terceros con la finalidad de otorgar descuentos a los precios respecto de los servicios médicos que presta en el territorio nacional.</p>\r\n\r\n  <h4>SEGUNDA.- PRECIO DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“LAS PARTES” establecen de común acuerdo que “LA TARJETA DE DESCUENTO” tendrá como costo mensual la cantidad señalada en el Apartado 8.- de la Carátula del presente contrato; cantidad que ya incluye IVA, y la cual deberá ser cubierta por “EL AFILIADO” en favor de “EL PRESTADOR” dentro de los primeros 5 (cinco) días de cada mes, sin necesidad de gestiones o avisos de cobro, ya sea mediante:</p>\r\n  <p>(i) Transferencia electrónica de fondos a la cuenta bancaria señalada en el Apartado 9.- de la Carátula del presente contrato y de la cual es titular “EL PRESTADOR”.</p>\r\n  <p>(ii) Cheque que se recibirá salvo buen cobro en el Domicilio de “EL PRESTADOR” señalado en el Apartado 3.- de la Carátula del presente contrato, y que en caso de no ser pagado por falta de fondos suficientes o por otras causas imputables a “EL AFILIADO”, éste último está de acuerdo en que deberá cubrir a “EL PRESTADOR” el 20% (veinte por ciento) del monto del cheque por concepto de indemnización por daños y perjuicios en términos del artículo 193 de la Ley General de Títulos y Operaciones de Crédito, independientemente de cualquier otro cargo que se pudiera generar.</p>\r\n  <p>(iii) Cargos mensuales automáticos recurrentes a la tarjeta de crédito de “EL AFILIADO” según los datos señalados en el Apartado 11.- de la Carátula del presente contrato, quien manifiesta bajo protesta de decir verdad que autoriza a “EL PRESTADOR” a realizar los cargos mensuales correspondientes por el costo mensual de “LA TARJETA DE DESCUENTO” en dicha tarjeta o en la tarjeta que por renovación, reposición, robo o extravío le haya asignado el banco emisor. La autorización estará vigente mientras “EL AFILIADO” no haya notificado a “EL PRESTADOR” por escrito y con acuse de recibo su deseo de cancelar su afiliación o no renovarla, o en su defecto, realizar su baja respectiva en el sitio web o aplicación de “EL PRESTADOR”.</p>\r\n  <p>Esta autorización no exime a “EL AFILIADO” del pago mensual por el uso de “LA TARJETA DE DESCUENTO” y demás obligaciones contractuales, por lo que, en caso de que el cobro no sea autorizado por el banco emisor o por cualquier razón no pueda realizarse, “EL AFILIADO” deberá notificar tal situación a “EL PRESTADOR” a la dirección de correo electrónico silvia@pasaporteatusalud.com, a efecto de solicitar una forma de pago diversa, quedando obligado a cubrir de inmediato el pago correspondiente.</p>\r\n  <p>(iv) Cualquier otro medio de pago aceptado por “EL PRESTADOR”, mismo que se dará a conocer a través de sus medios oficiales de comunicación.</p>\r\n  <p>“EL PRESTADOR” podrá variar unilateralmente el costo mensual de “LA TARJETA DE DESCUENTO”, previo aviso a “EL AFILIADO” con 30 (treinta) días de anticipación a través de sus medios oficiales de comunicación.</p>\r\n  <p>Para el caso de que “EL AFILIADO” adquiera y cubra el precio de “LA TARJETA DE DESCUENTO” y posteriormente deje de pagar una mensualidad, deberá cubrir a “EL PRESTADOR”, por concepto de cuota de reactivación, la cantidad señalada en el Apartado 10.- de la Carátula por cada mes que haya interrumpido y/o no haya cubierto el precio de “LA TARJETA DE DESCUENTO”, hasta la fecha en que pretenda volver a adquirirla.</p>\r\n\r\n  <h4>TERCERA.- VIGENCIA DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“LA TARJETA DE DESCUENTO” objeto del presente contrato tendrá una vigencia de 30 días contados a partir de que “EL AFILIADO” cubra a “EL PRESTADOR” el precio establecido anteriormente, en el entendido de que la vigencia del presente contrato y de “LA TARJETA DE DESCUENTO” se prorrogarán automáticamente sin necesidad de celebrar documento adicional entre “LAS PARTES” siempre y cuando “EL AFILIADO” cubra, de mes en mes o en la frecuencia contratada, el precio vigente de “LA TARJETA DE DESCUENTO”.</p>\r\n  <p>“EL AFILIADO” tendrá derecho a revocar su consentimiento dentro de los 5 (cinco) días siguientes a la entrega de “LA TARJETA DE DESCUENTO” o la firma del presente contrato, lo que ocurra último, sin responsabilidad alguna, siempre y cuando no haya obtenido beneficio alguno por el uso de “LA TARJETA DE DESCUENTO”.</p>\r\n\r\n  <h4>CUARTA.- BENEFICIOS DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“EL AFILIADO”, de forma exclusiva, personal e intransferible, gozará de forma gratuita de los servicios que se mencionan a continuación:</p>\r\n  <ul><li>Consultas gratuitas ilimitadas de medicina general (no de especialidad) en la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla, únicamente con los doctores afiliados al programa de Pasaporte a tu Salud.</li><li>Consultas de urgencia gratuitas en la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla.</li></ul>\r\n  <p>No así respecto de los servicios que, de manera enunciativa más no limitativa, se describen a continuación:</p>\r\n  <ul><li>Hospitalización dentro de la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla, sujeto a la disponibilidad de cada uno de ellos.</li><li>Consultas de especialidad ilimitadas a costo preferencial, con médicos especialistas pertenecientes al programa PATS.</li><li>Acceso a farmacia PATS con costos reducidos de medicamentos genéricos.</li><li>Imagenología y laboratorios ilimitados con costos preferenciales.</li><li>Acceso a cirugías con cuota de recuperación preferente, con o sin honorarios médicos incluidos según corresponda.</li></ul>\r\n  <p>Dichos servicios generarán, por evento, el pago de una cuota con cargo a “EL AFILIADO”, misma que resultará de aplicar los porcentajes de descuento que se desprenden del ANEXO 4 del presente contrato a los precios publicados al público en general o los precios preferenciales indicados.</p>\r\n  <p>Mientras “LA TARJETA DE DESCUENTO” se encuentre vigente, “EL AFILIADO” gozará de todos los beneficios que la misma le otorga; sin embargo, para el caso de que requiera cirugía o procedimiento quirúrgico en quirófano, deberá haber sufragado por adelantado la adquisición de “LA TARJETA DE DESCUENTO” por un periodo de 12 (doce) meses y encontrarse dentro de dicho periodo de vigencia.</p>\r\n\r\n  <h4>QUINTA.- OBLIGACIONES DE “EL PRESTADOR”.</h4>\r\n  <p>“EL PRESTADOR” se obliga a: (i) otorgar a “EL AFILIADO” el acceso ilimitado a “LA TARJETA DE DESCUENTO” durante la vigencia del contrato; (ii) mantener actualizada y operativa la Red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla; (iii) proporcionar a “EL AFILIADO”, de forma digital, “LA TARJETA DE DESCUENTO” dentro de los 5 (cinco) días hábiles siguientes al primer pago; e (iv) informar por escrito cualquier modificación a la red de hospitales o al tabulador de cuotas con al menos 10 (diez) días de anticipación.</p>\r\n\r\n  <h4>SEXTA.- OBLIGACIONES DE “EL AFILIADO”.</h4>\r\n  <p>“EL AFILIADO” se obliga a: (i) pagar puntualmente el precio de “LA TARJETA DE DESCUENTO”; (ii) utilizarla de forma exclusiva, personal e intransferible; (iii) cubrir directamente a los hospitales y con anterioridad a recibir el servicio médico las cuotas de recuperación según tabulador vigente; (iv) presentar identificación oficial y “LA TARJETA DE DESCUENTO” o código QR cada vez que haga uso de beneficios; y (v) notificar por escrito cualquier cambio de domicilio o datos de contacto en un plazo no mayor a 5 (cinco) días.</p>\r\n\r\n  <h4>SÉPTIMA.- ACCESO A LOS BENEFICIOS Y PROCEDIMIENTO.</h4>\r\n  <p>Para hacer uso de “LA TARJETA DE DESCUENTO”, “EL AFILIADO” deberá agendar sus citas directamente con los doctores pertenecientes a la Red de Hospitales 50 (FIFTY) Doctors, que en ese momento se encuentren adscritos al programa de beneficios, a través de la aplicación oficial, página de internet oficial de PATS o medios oficiales que indique “EL PRESTADOR”.</p>\r\n  <p>“EL AFILIADO” se obliga a pagar directamente al médico especialista perteneciente al programa el costo de la consulta de especialidad de que se trate, en términos de los porcentajes de descuento del ANEXO 4. En caso de no estar facultado para asistir por fuerza mayor, tendrá un plazo de 30 (treinta) días contados a partir de haber generado la cita para solicitar una nueva consulta médica.</p>\r\n\r\n  <h4>OCTAVA.- EXCLUSIONES Y LIMITACIONES.</h4>\r\n  <p>Los beneficios no incluirán: (i) trasplantes de órganos; (ii) tratamientos experimentales; (iii) tratamientos de oncología a excepción de algunas cirugías; (iv) medicamentos extra hospitalarios que no estén recogidos en el catálogo de Farmacia PATS; (v) atención médica con especialistas no adscritos o no publicados en los medios oficiales; y (vi) cualquier servicio no listado expresamente.</p>\r\n\r\n  <h4>NOVENA.- CAUSAS DE TERMINACIÓN.</h4>\r\n  <p>El contrato podrá terminarse por falta de pago, mutuo consentimiento por escrito o incumplimiento de cualquiera de las cláusulas por cualquiera de “LAS PARTES”. En caso de terminación, “EL AFILIADO” no tendrá derecho a exigir la devolución de cantidad alguna.</p>\r\n\r\n  <h4>DÉCIMA.- CANCELACIÓN VOLUNTARIA.</h4>\r\n  <p>“EL AFILIADO” podrá cancelar “LA TARJETA DE DESCUENTO” mediante aviso por escrito con 30 (treinta) días de anticipación. Dicha cancelación surtirá efectos a partir del siguiente periodo mensual y no generará reembolso de pagos ya realizados.</p>\r\n\r\n  <h4>DÉCIMA PRIMERA.- PROTECCIÓN DE DATOS PERSONALES.</h4>\r\n  <p>“LAS PARTES” acuerdan que el tratamiento de datos personales se sujetará a la Ley Federal de Protección de Datos Personales en Posesión de los Particulares. “EL AFILIADO” autoriza expresamente el uso de sus datos para la gestión de “LA TARJETA DE DESCUENTO”. El aviso de privacidad se integra al presente contrato como ANEXO 5.</p>\r\n\r\n  <h4>DÉCIMA SEGUNDA.- RESPONSABILIDAD.</h4>\r\n  <p>“EL AFILIADO” reconoce y acepta que “LA TARJETA DE DESCUENTO” es emitida y administrada directamente por CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE, quien es responsable de la operación de la red de descuentos, afiliación de prestadores médicos y prestación de cualquier servicio relacionado con “LA TARJETA DE DESCUENTO”.</p>\r\n  <p>En consecuencia, “EL PRESTADOR” no tendrá responsabilidad directa ni indirecta por la prestación, calidad, eficacia, resultado, daño, perjuicio, lesión, complicación, secuela, evento adverso o consecuencia derivada de servicios médicos recibidos, incluyendo aquellos ocasionados por negligencia, impericia o mala praxis de profesionales de la salud o prestadores afiliados. Cualquier relación derivada de la prestación de servicios médicos se establece directamente entre “EL AFILIADO” y los prestadores de servicios de salud correspondientes. Esta limitación subsistirá a la terminación del contrato.</p>\r\n\r\n  <h4>DÉCIMA TERCERA.- PREVENCIÓN DE LAVADO DE DINERO Y ORIGEN DE LOS RECURSOS.</h4>\r\n  <p>“LAS PARTES” declaran bajo protesta de decir verdad que los recursos económicos, bienes y derechos que utilicen para cumplir obligaciones derivadas de este contrato tienen y tendrán origen lícito. “EL AFILIADO” manifiesta que el pago inicial y pagos futuros provienen de fuentes lícitas y no de actividades tipificadas como delitos.</p>\r\n  <p>“LAS PARTES” reconocen que la prestación de servicios de comercio puede ser considerada actividad vulnerable, por lo que se obligan a proporcionar información y documentación requerida para integrar expediente de identificación e informar si tienen conocimiento de la existencia de beneficiario controlador.</p>\r\n\r\n  <h4>DÉCIMA CUARTA.- CONFORMACIÓN DEL EXPEDIENTE DE IDENTIFICACIÓN.</h4>\r\n  <p>“EL PRESTADOR” queda obligado a conformar y mantener un expediente de identificación de “EL AFILIADO”. Para tales efectos, “EL AFILIADO” se obliga a entregar los documentos aplicables: identificación oficial vigente o pasaporte, acta de nacimiento cuando aplique, comprobante de domicilio, constancia de situación fiscal cuando aplique, CURP, y declaración de dueño beneficiario.</p>\r\n  <p>Cuando exista persona responsable, la documentación de identificación y representación deberá integrarse al expediente; la CIF/constancia fiscal corresponde al tutor cuando aplique. “EL PRESTADOR” conservará dicho expediente por un periodo mínimo de 5 (cinco) años contados a partir de que termine la vigencia del contrato o termine por cualquiera de sus causales, garantizando la confidencialidad de los datos personales.</p>\r\n\r\n  <h4>DÉCIMA QUINTA.- CAUSAL ESPECÍFICA DE RESCISIÓN.</h4>\r\n  <p>Será motivo de rescisión inmediata sin necesidad de declaración judicial y sin responsabilidad para la parte afectada cuando cualquiera de “LAS PARTES” se niegue a proporcionar información requerida para cumplimiento de la Ley Federal para la Prevención e Identificación de Operaciones con Recursos de Procedencia Ilícita, proporcione información falsa o aparezca en listas de personas bloqueadas emitidas por autoridad competente.</p>\r\n\r\n  <h4>DÉCIMA SEXTA.- LEGISLACIÓN APLICABLE Y JURISDICCIÓN.</h4>\r\n  <p>“LAS PARTES” establecen que la Procuraduría Federal del Consumidor es competente en vía administrativa para resolver cualquier controversia sobre interpretación o cumplimiento. Sin perjuicio de lo anterior, se someten expresamente a la jurisdicción de los tribunales competentes del fuero común del Distrito Judicial de Puebla, Estado de Puebla, renunciando de manera expresa e irrevocable a cualquier otro fuero o jurisdicción que pudiera corresponderles.</p>\r\n\r\n  <p>Enteradas “LAS PARTES” del contenido y alcance del presente contrato, y entendidas de los derechos y obligaciones que contraen, firman el presente instrumento, incluyendo sus anexos, manifestando que no medió error, dolo, mala fe, violencia o lesión, ni vicio del consentimiento alguno, en la Ciudad de Puebla, Estado de Puebla, reconociendo que la fecha de firma es 13 de mayo de 2026.</p>\r\n\r\n  <div class=\"sign-grid\">\r\n    <div class=\"sign-box\"><div class=\"line\"></div><strong>“EL PRESTADOR”</strong><br>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE<br>Representada por PEDRO AZCÁRRAGA RAMOS</div>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>“EL AFILIADO”</strong><br>Silvia Ornia Corral</div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 1<br>Identificación oficial de “EL AFILIADO”</h2><p>Se integra al expediente la identificación oficial cargada por el usuario en el formulario. Para mexicanos, corresponde a identificación oficial/INE cuando aplique. Para extranjeros/no mexicanos, corresponde a identificación oficial o pasaporte vigente; al menos el frente es obligatorio y el reverso será opcional cuando el documento no lo tenga.</p><p><strong>Tipo:</strong> INE. <strong>Emitida por / país emisor:</strong> México. <strong>Número:</strong> 22.</p></div>\r\n  <div class=\"annex\"><h2>ANEXO 2<br>COMPROBANTE DE DOMICILIO DE “EL AFILIADO”</h2><p>Se integra al expediente el comprobante de domicilio cargado por el usuario. Domicilio declarado: toscana 320 Int. 1b, Col. Florencia, C.P. 25886, Puebla, Puebla, México.</p></div>\r\n  <div class=\"annex\"><h2>ANEXO 3<br>CONSTANCIA DE SITUACIÓN FISCAL DE “EL AFILIADO”</h2><p>Constancia de Situación Fiscal de “EL AFILIADO”, si aplica. En caso de pacientes representados, la constancia fiscal o CIF corresponde a la persona responsable cuando sea aplicable, no al menor. Para afiliados extranjeros/no mexicanos, no será obligatoria salvo que declaren RFC mexicano o residencia fiscal aplicable.</p></div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 4<br>CUOTAS DE RECUPERACIÓN Y/O PRECIOS BASE A CUBRIR A “EL PRESTADOR”</h2>\r\n    <p>En el presente anexo se establecen los porcentajes de descuento a obtener como titular de “LA TARJETA DE DESCUENTO”, por lo que la cantidad a cubrir por “EL AFILIADO” directamente al hospital de la cadena 50 (FIFTY) Doctors o al doctor que preste el servicio se obtendrá de aplicar el porcentaje de descuento correspondiente al precio publicado por los medios oficiales o al precio vigente en el establecimiento.</p>\r\n    <table><tr><th>Servicios / procedimientos</th><th>Descuentos</th></tr><tr><td>Consulta de urgencias</td><td>100%</td></tr><tr><td>Consulta de medicina general</td><td>100%</td></tr><tr><td>Habitación hospitalaria</td><td>90%</td></tr><tr><td>Uso de áreas de urgencias médicas</td><td>80%</td></tr><tr><td>Utilización de cubículos de terapia intensiva (UCIA-UCIN-UCIP)</td><td>75%</td></tr><tr><td>CEYE</td><td>75%</td></tr><tr><td>Uso quirófano</td><td>75%</td></tr><tr><td>Servicio de cuneros</td><td>75%</td></tr><tr><td>Materiales & medicamentos del cuadro básico, genéricos intercambiables</td><td>70%</td></tr><tr><td>Hemodinamia</td><td>70%</td></tr><tr><td>Imagenología</td><td>70%</td></tr><tr><td>Endoprótesis</td><td>70%</td></tr><tr><td>Osteosíntesis</td><td>70%</td></tr><tr><td>Prótesis</td><td>70%</td></tr><tr><td>Órtesis</td><td>70%</td></tr><tr><td>Laboratorio clínico</td><td>60%</td></tr></table>\r\n    <p class=\"small\">Los descuentos aplican con los proveedores suscritos al convenio de Pasaporte a tu Salud.</p>\r\n    <table><tr><th>Servicios / procedimientos</th><th>Precios base</th></tr><tr><td>Consulta de especialidades médicas</td><td>$390.00</td></tr><tr><td>Colposcopía</td><td>$400.00</td></tr><tr><td>Retiro de puntos de sutura</td><td>$80.00</td></tr><tr><td>Aplicación de medicamento intramuscular</td><td>$60.00</td></tr><tr><td>Retiro de DIU</td><td>$500.00</td></tr><tr><td>Colocación de DIU</td><td>$700.00</td></tr><tr><td>Extracción de cuerpo extraño (oído y nariz)</td><td>$300.00</td></tr><tr><td>Lavado ótico</td><td>$250.00</td></tr><tr><td>Curación de sitio quirúrgico</td><td>$250.00</td></tr><tr><td>Retiro de yeso</td><td>$250.00</td></tr><tr><td>Visita día de hospitalización</td><td>$650.00</td></tr><tr><td>Visita de urgencias</td><td>$750.00</td></tr><tr><td>Día de terapia intensiva</td><td>$850.00</td></tr></table>\r\n    <p class=\"small\">Todos los precios incluyen IVA. La factura de servicios hospitalarios será emitida con el desglose correspondiente y el ahorro otorgado por ser titular de “LA TARJETA DE DESCUENTO”.</p>\r\n    <p>Exclusiones y limitaciones: se aplicarán descuentos y precios especiales para el acompañante de “EL AFILIADO” en la misma habitación únicamente para la primera noche de hospitalización. Los precios y porcentajes de descuento darán derecho a la utilización de materiales y medicamentos del cuadro básico, genéricos intercambiables; cualquier otro tipo de medicación será cubierto directamente por “EL AFILIADO”. Los costos de procedimientos quirúrgicos incluyen honorarios médicos cuando así se indique. “EL AFILIADO” podrá atenderse con el médico tratante que elija, debiendo cubrir honorarios directamente a dicho médico, conservando el derecho a beneficios dentro de la red aplicable.</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Firma de aceptación de “EL AFILIADO”</strong><br>Silvia Ornia Corral</div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 5<br>AVISO DE PRIVACIDAD</h2>\r\n    <p>En cumplimiento de las disposiciones establecidas en la Ley Federal de Protección de Datos Personales en Posesión de Particulares, su Reglamento y los lineamientos aplicables, “CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE” (en lo sucesivo “EL PRESTADOR”), con domicilio en CALLE PASEO SINFONÍA NÚMERO EXTERIOR 1, LOCAL 2-14, LOMAS DE ANGELÓPOLIS II, SAN ANDRÉS CHOLULA, ESTADO DE PUEBLA, CÓDIGO POSTAL 72830, da a conocer el Aviso de Privacidad al tenor del cual manejará por medio de su representación y/o empleados los datos personales y/o documentación proporcionada por el afiliado o usuario de “LA TARJETA DE DESCUENTO”.</p>\r\n    <p>Se tendrá por aceptado expresamente el presente Aviso de Privacidad una vez proporcionados los datos personales y firmada digitalmente la aceptación del contrato, motivo por el cual “EL PRESTADOR” estará facultado para manejar la información conforme a la legislación aplicable.</p>\r\n    <h4>Modificación del aviso de privacidad</h4><p>Este aviso podrá ser modificado o adecuado a las necesidades de “EL PRESTADOR”. Las modificaciones o actualizaciones serán incorporadas al presente aviso y estarán disponibles en la página de internet, domicilio de “EL PRESTADOR” o serán enviadas al último correo electrónico proporcionado.</p>\r\n    <h4>Finalidad de la información</h4><p>La información será utilizada para: elaborar y mantener actualizada la base de usuarios; identificar afiliados; proporcionar la tarjeta digital; otorgar acceso al programa de beneficios; informar modificaciones a la red o tabulador; realizar análisis estadísticos internos y brindar un óptimo servicio médico.</p>\r\n    <h4>Tipo de datos necesarios</h4><p>Se solicitarán datos de identificación, contacto, legales, contractuales y fiscales cuando aplique, incluyendo nombre completo, lugar y fecha de nacimiento, firma, identificación oficial, nacionalidad, CURP y RFC cuando sean aplicables, domicilio, teléfono y correo electrónico.</p>\r\n    <h4>Transferencias de la información</h4><p>El usuario autoriza proporcionar información sin consentimiento adicional en los casos previstos por ley, resolución de autoridad competente, tratados aplicables, salvaguarda de interés público, procuración o administración de justicia, reconocimiento o defensa de derechos en procesos judiciales, y a socios comerciales, técnicos o estratégicos que asuman obligaciones de confidencialidad y seguridad equivalentes.</p>\r\n    <h4>Limitación del uso o divulgación de datos y derechos ARCO</h4><p>El usuario podrá limitar el uso o divulgación de sus datos personales y ejercer derechos de acceso, rectificación, cancelación u oposición mediante solicitud escrita dirigida a “EL PRESTADOR” en su domicilio o al correo silvia@pasaporteatusalud.com, acompañando documento que acredite su identidad.</p>\r\n    <h4>Revocación de consentimiento</h4><p>El usuario podrá revocar su consentimiento siguiendo el mismo procedimiento, considerando que para ciertos fines la revocación puede implicar la cancelación de “LA TARJETA DE DESCUENTO” y la imposibilidad de acceder al programa.</p>\r\n    <p><strong>Nombre:</strong> Silvia Ornia Corral<br><strong>Fecha:</strong> 13 de mayo de 2026</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Firma</strong></div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 6<br>DECLARACIÓN DE DUEÑO BENEFICIARIO</h2>\r\n    <p>DE CONFORMIDAD CON LO DISPUESTO EN LOS ARTÍCULOS 18 FRACCIÓN I Y III DE LA LEY FEDERAL PARA PREVENCIÓN E IDENTIFICACIÓN DE OPERACIONES CON RECURSOS DE PROCEDENCIA ILÍCITA, EL ARTÍCULO 15 DE SU REGLAMENTO Y EL ARTÍCULO 13 DE LAS REGLAS DE CARÁCTER GENERAL, MANIFIESTO BAJO PROTESTA DE DECIR VERDAD:</p>\r\n    <h4>Datos de identificación del cliente</h4>\r\n    <table><tr><th>Campo</th><th>Respuesta</th></tr><tr><td>Apellido paterno, materno y nombre(s)</td><td>Silvia Ornia Corral</td></tr><tr><td>Fecha de nacimiento</td><td>2001-08-06</td></tr><tr><td>País de nacimiento</td><td>México</td></tr><tr><td>Nacionalidad</td><td>mexicana</td></tr><tr><td>Actividad, ocupación o profesión</td><td>profesora</td></tr><tr><td>Estado civil</td><td>CASADO(A)</td></tr><tr><td>Domicilio particular</td><td>toscana 320 Int. 1b, Col. Florencia, C.P. 25886, Puebla, Puebla, México</td></tr><tr><td>Teléfonos</td><td>2222222222</td></tr><tr><td>Correo electrónico</td><td>silviaornia@hotmail.com</td></tr><tr><td>CURP</td><td>222222222222222222</td></tr><tr><td>RFC</td><td>67</td></tr><tr><td>Tipo de identificación</td><td>INE</td></tr><tr><td>Emitida por / país emisor</td><td>México</td></tr><tr><td>Número de identificación</td><td>22</td></tr></table>\r\n    <h4>Datos de identificación de la operación</h4>\r\n    <table><tr><th>Campo</th><th>Respuesta</th></tr><tr><td>Tipo de operación</td><td>Adquisición de tarjeta de descuento PATS</td></tr><tr><td>Monto de operación</td><td>$800.00 M.N.</td></tr><tr><td>Fecha de operación</td><td>13 de mayo de 2026</td></tr><tr><td>Forma de pago</td><td>Pasarela / medio autorizado por “EL PRESTADOR”</td></tr><tr><td>Moneda</td><td>MXN</td></tr></table>\r\n    <h4>Información de la existencia del dueño beneficiario o beneficiario controlador</h4>\r\n    <p>Declaro que soy el beneficiario directo de la operación y no existe ningún otro dueño beneficiario o beneficiario controlador: <strong>SI</strong>.</p>\r\n    <h4>Aviso de privacidad</h4><p>Los datos personales serán protegidos y tratados conforme al Aviso de Privacidad contenido en el cuerpo del presente contrato y la legislación aplicable.</p>\r\n    <p>H. Puebla de Zaragoza al 13 del mes de mayo del año 2026.</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Nombre y firma</strong><br>Silvia Ornia Corral</div>\r\n  </div>\r\n\r\n  \r\n  </div>\r\n', 'data:image/png;base64,', 'Silvia Ornia Corral', 'a403c41f651085f1befde36e75f09ad90220a43ad139c218766befe9fff2bc82', '2026-05-13 23:08:22', '200.68.170.50', 'Mozilla/5.0 (Linux; Android 10; K) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/148.0.0.0 Mobile Safari/537.36', '', 'firmado', '2026-05-13 23:08:22', '2026-05-13 23:08:22');
INSERT INTO `pats_contratos_firmados` (`id_contrato_firmado`, `id_orden`, `id_pasaporte`, `id_distribuidor`, `id_franquicia`, `token_publico`, `contrato_clave`, `contrato_version`, `html_contrato_renderizado`, `firma_afiliado_base64`, `nombre_firmante`, `hash_contrato`, `fecha_firma`, `ip_firma`, `user_agent_firma`, `pdf_path`, `estatus`, `created_at`, `updated_at`) VALUES
(15, 3, 3, 0, 0, '', 'contrato_pats_base', '1.0', '<style>\r\n  .pats-contract{font-family:Arial,Helvetica,sans-serif;color:#172033;font-size:12px;line-height:1.52;background:#fff;padding:4px}\r\n  .pats-contract h1,.pats-contract h2,.pats-contract h3,.pats-contract h4{text-align:center;margin:12px 0 8px;color:#0d1b3e}\r\n  .pats-contract h1{font-size:16px;text-transform:uppercase;letter-spacing:.05em}\r\n  .pats-contract h2{font-size:15px;text-transform:uppercase;letter-spacing:.04em}\r\n  .pats-contract h3{font-size:13px;text-transform:uppercase;letter-spacing:.08em}\r\n  .pats-contract h4{font-size:12px;text-align:left;text-transform:uppercase;margin-top:12px}\r\n  .pats-contract p{margin:6px 0;text-align:justify}\r\n  .pats-contract ul{margin:6px 0 8px 18px;padding:0}.pats-contract li{margin:4px 0;text-align:justify}\r\n  .pats-contract table{width:100%;border-collapse:collapse;margin:8px 0 12px}.pats-contract th,.pats-contract td{border:1px solid #cbd5e1;padding:6px;vertical-align:top}.pats-contract th{background:#eef4ff;color:#0d1b3e;text-align:left}\r\n  .pats-contract .center{text-align:center}.pats-contract .muted{color:#64748b}.pats-contract .small{font-size:10px}.pats-contract .badge{display:inline-block;padding:3px 8px;border-radius:999px;background:#eef4ff;color:#1d4ed8;font-weight:700;margin:2px 4px 2px 0}\r\n  .pats-contract .sign-grid{display:grid;grid-template-columns:1fr 1fr;gap:22px;margin-top:28px}.pats-contract .sign-box{text-align:center;min-height:95px}.pats-contract .line{border-top:1px solid #0f172a;margin:48px 8px 6px}.pats-contract .signature-img{max-width:220px;max-height:82px;display:block;margin:0 auto 4px}\r\n  .pats-contract .annex{page-break-before:auto;border-top:2px solid #0d1b3e;margin-top:18px;padding-top:12px}.pats-contract .page-break{page-break-before:always;border-top:1px dashed #cbd5e1;margin-top:18px;padding-top:12px}\r\n</style>\r\n<div class=\"pats-contract\">\r\n  <h1>Carátula del contrato de adquisición de tarjeta de descuento</h1>\r\n  <p>CARÁTULA DEL CONTRATO DE ADQUISICIÓN DE TARJETA DE DESCUENTO (EN LO SUCESIVO “LA CARÁTULA”), QUE CELEBRAN POR UNA PARTE LA SOCIEDAD SEÑALADA EN EL APARTADO 1.- DE LA CARÁTULA, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL PRESTADOR”, REPRESENTADA EN ESTE ACTO POR LA PERSONA FÍSICA QUE SE INDICA EN EL APARTADO 2.- DE LA CARÁTULA; Y POR LA OTRA PARTE, LA PERSONA FÍSICA SEÑALADA EN EL APARTADO 5.- DE LA CARÁTULA, POR SU PROPIO DERECHO, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL AFILIADO”; Y CUANDO LOS ANTES NOMBRADOS ACTÚEN DE MANERA CONJUNTA, SE LES DENOMINARÁ COMO “LAS PARTES”; QUIENES SE SUJETAN AL TENOR DE LA CARÁTULA, DECLARACIONES Y CLÁUSULAS SIGUIENTES:</p>\r\n    <p><span class=\"badge\">Afiliado extranjero/no mexicano</span> No se exige CURP, INE ni constancia fiscal mexicana; se acepta identificación oficial o pasaporte vigente, al menos frente.</p>\r\n  <h2>C A R Á T U L A</h2>\r\n  <table>\r\n    <tr><th style=\"width:8%\">Apartado</th><th style=\"width:42%\">Definición</th><th>Respuesta</th></tr>\r\n    <tr><td>1.-</td><td>Nombre de “EL PRESTADOR”</td><td>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE</td></tr>\r\n    <tr><td>2.-</td><td>Nombre del Representante Legal de “EL PRESTADOR”</td><td>PEDRO AZCÁRRAGA RAMOS</td></tr>\r\n    <tr><td>3.-</td><td>Domicilio de “EL PRESTADOR”</td><td>CALLE PASEO SINFONÍA NÚMERO EXTERIOR 1, LOCAL 2-14, LOMAS DE ANGELÓPOLIS II, SAN ANDRÉS CHOLULA, ESTADO DE PUEBLA, CÓDIGO POSTAL 72830</td></tr>\r\n    <tr><td>4.-</td><td>Clave del Registro Federal de Contribuyentes de “EL PRESTADOR”</td><td>COH2202144H5</td></tr>\r\n    <tr><td>5.-</td><td>Nombre de “EL AFILIADO”</td><td>julio garcia braga fernandez</td></tr>\r\n    <tr><td>6.-</td><td>Domicilio de “EL AFILIADO”</td><td>jshshshs 1 Int. 1, Col. colonia, C.P. 33004, puebla, minesota, usa</td></tr>\r\n    <tr><td>7.-</td><td>Clave del Registro Federal de Contribuyentes de “EL AFILIADO”</td><td>No aplica por nacionalidad extranjera / no residente fiscal en México</td></tr>\r\n    <tr><td>8.-</td><td>Costo mensual de “LA TARJETA DE DESCUENTO”</td><td>$800.00 M.N.</td></tr>\r\n    <tr><td>9.-</td><td>Cuenta bancaria de “EL PRESTADOR” para pagos</td><td>Cuenta: 01600866709<br>CLABE: 042650016008667096<br>Institución Bancaria: Banca Mifel, S.A., Institución de Banca Múltiple, Grupo Financiero Mifel</td></tr>\r\n    <tr><td>10.-</td><td>Cuota de Reactivación de “LA TARJETA DE DESCUENTO”</td><td>$100.00 M.N. por cada mes que se haya interrumpido el pago.</td></tr>\r\n    <tr><td>11.-</td><td>Datos de la Tarjeta de Crédito de “EL AFILIADO”</td><td>Número de tarjeta: pendiente de confirmar por pasarela/token de pago.<br>Institución bancaria: pendiente de confirmar por pasarela. <br><span class=\"small\">No se almacena número completo de tarjeta en este formulario.</span></td></tr>\r\n    <tr><td>12.-</td><td>Anexos</td><td>ANEXO 1. Identificación oficial o pasaporte de “EL AFILIADO”<br>ANEXO 2. Comprobante de domicilio de “EL AFILIADO”<br>ANEXO 3. No aplicable salvo que declare RFC mexicano<br>ANEXO 4. Cuotas de recuperación y/o precios base a cubrir a “EL PRESTADOR”<br>ANEXO 5. Aviso de privacidad<br>ANEXO 6. Declaración de dueño beneficiario</td></tr>\r\n    <tr><td>13.-</td><td>Fecha de Firma del Contrato</td><td>13 de mayo de 2026</td></tr>\r\n  </table>\r\n\r\n  <div class=\"sign-grid\">\r\n    <div class=\"sign-box\"><div class=\"line\"></div><strong>“EL PRESTADOR”</strong><br>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE<br>Representada por PEDRO AZCÁRRAGA RAMOS</div>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>“EL AFILIADO”</strong><br>julio garcia braga fernandez<br><span class=\"small\">La persona física señalada en el Apartado 5.- de la Carátula</span></div>\r\n  </div>\r\n\r\n  <div class=\"page-break\"></div>\r\n  <h1>Contrato de adquisición de tarjeta de descuento</h1>\r\n  <p>CONTRATO DE ADQUISICIÓN DE TARJETA DE DESCUENTO, QUE CELEBRAN POR UNA PARTE LA SOCIEDAD SEÑALADA EN EL APARTADO 1.- DE LA CARÁTULA, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL PRESTADOR”, REPRESENTADA EN ESTE ACTO POR LA PERSONA FÍSICA QUE SE INDICA EN EL APARTADO 2.- DE LA CARÁTULA; Y POR LA OTRA PARTE, LA PERSONA FÍSICA SEÑALADA EN EL APARTADO 5.- DE LA CARÁTULA, POR SU PROPIO DERECHO, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL AFILIADO”; Y CUANDO LOS ANTES NOMBRADOS ACTÚEN DE MANERA CONJUNTA, SE LES DENOMINARÁ COMO “LAS PARTES”; QUIENES SE SUJETAN AL TENOR DE LAS DECLARACIONES Y CLÁUSULAS SIGUIENTES:</p>\r\n\r\n  <h2>D E C L A R A C I O N E S</h2>\r\n  <h4>I.- Declara “EL PRESTADOR” por conducto de su representación:</h4>\r\n  <p>A. Que, su representada es una sociedad mercantil constituida conforme a las leyes de los Estados Unidos Mexicanos, según consta en la escritura pública número 39,861, del volumen 830 de fecha catorce de febrero de dos mil veintidós, otorgada ante la fe del Licenciado Ernesto Joaquín Briones Amador, Notario Público Titular de la Notaría Pública número 46 de las del Distrito Judicial de Puebla, Estado de Puebla, cuyo primer testimonio se encuentra inscrito ante las oficinas del Registro Público de Comercio del Distrito Judicial de Puebla, Estado de Puebla, bajo el Folio Mercantil Electrónico: N-2022022991, por virtud del cual se llevó a cabo la Constitución de la persona moral denominada CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE.</p>\r\n  <p>B. Que, la persona física que la representa en este acto, señalada en el Apartado 2.- de la Carátula, cuenta con todas y cada una de las facultades necesarias para la celebración del presente contrato, las cuales se desprenden del instrumento descrito en el punto declarativo inmediato anterior, mismas que manifiesta bajo protesta de decir verdad que no le han sido suspendidas, revocadas o limitadas en forma alguna.</p>\r\n  <p>C. Que, su representada tiene como domicilio fiscal el señalado en el Apartado 3.- de la Carátula del presente contrato, mismo que designa como domicilio convencional para cualquier cuestión relacionada con la celebración del presente contrato.</p>\r\n  <p>D. Que, su representada se encuentra inscrita en el Registro Federal de Contribuyentes bajo la clave señalada en el Apartado 4.- de la Carátula.</p>\r\n  <p>E. Que, ha desarrollado y es su deseo comparecer a la celebración del presente instrumento con la finalidad de enajenar en favor de “EL AFILIADO”, una Tarjeta de Descuento que da acceso a “UN PROGRAMA DE BENEFICIOS QUE OTORGA DESCUENTOS A LOS COSTOS Y PERMITE RECIBIR SERVICIOS MÉDICOS PRIVADOS DE ALTA CALIDAD DE FORMA ACCESIBLE, CLARA Y SIN RESTRICCIONES DENTRO DE LA RED DE HOSPITALES 50 (FIFTY) DOCTORS CON SEDE EN EL ESTADO DE PUEBLA”, en lo sucesivo “LA TARJETA DE DESCUENTO”, en los términos y condiciones que se establecerán más adelante.</p>\r\n  <p>F. Que, su representada no es una Aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas sino una empresa dedicada, entre otros, a la operación y administración de establecimientos destinados a la atención y asistencia de enfermos, por lo que la enajenación de “LA TARJETA DE DESCUENTO” únicamente constituye un acto de comercio que brindará a “EL AFILIADO” acceso a un programa de beneficios como ha quedado descrito anteriormente.</p>\r\n\r\n  <h4>II.- Declara “EL AFILIADO”, por su propio derecho:</h4>\r\n      <p>A. Que, su nombre se señala en el Apartado 5.- de la Carátula, es una persona física de nacionalidad Pendiente, en pleno ejercicio de sus derechos, legal y jurídicamente capaz para celebrar el presente Contrato, quien se identifica con identificación oficial o pasaporte vigente expedido por autoridad competente, tipo PASAPORTE, número -772626362627727272)2, que en copia simple o archivo digital se agrega al cuerpo del presente contrato como ANEXO 1.</p>\r\n    <p>B. Que, tiene como domicilio particular el señalado en el Apartado 6.- de la Carátula, mismo que designa como domicilio convencional para cualquier cuestión relacionada con la celebración del presente contrato, tal y como lo acredita con el comprobante de domicilio que en copia simple o archivo digital se agrega al cuerpo del presente contrato como ANEXO 2.</p>\r\n  <p>C. Que, su CURP es No aplica por nacionalidad extranjera / no mexicana y su RFC/identificación fiscal es No aplica por nacionalidad extranjera / no residente fiscal en México; asimismo manifiesta que cuenta con capacidad económica para obligarse en términos del presente contrato y que los recursos con los que cubrirá sus obligaciones provendrán de fuentes lícitas. En caso de nacionalidad extranjera/no mexicana, se tendrán por no aplicables CURP, INE y constancia fiscal mexicana salvo manifestación expresa de residencia fiscal o RFC mexicano.</p>\r\n  <p>D. Que, es su deseo comparecer a la celebración del presente instrumento con la finalidad de adquirir “LA TARJETA DE DESCUENTO” de acuerdo con los términos y condiciones que se establecen a continuación.</p>\r\n  <p>E. Que, previo a la celebración del presente contrato fue informado y manifiesta expresamente que reconoce que “EL PRESTADOR” no es una Aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas y que las actividades comerciales objeto del presente contrato no consisten en la contratación de un seguro, de la índole que fuere, sino que únicamente implica la adquisición de una tarjeta de descuento que da acceso a un programa de beneficios que otorga descuentos a los costos y permite recibir servicios médicos privados de alta calidad de forma accesible, clara y sin restricciones dentro de la red de hospitales 50 (FIFTY) Doctors con sede en el Estado de Puebla.</p>\r\n  <p>F. Que, reconoce que “EL PRESTADOR” se dedica a la operación de centros hospitalarios y que la emisión de “LA TARJETA DE DESCUENTO” únicamente corresponde a la intención de este último de crear un programa de descuentos para el acceso a los servicios prestados por la Red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla.</p>\r\n\r\n  <h4>III.- Declaran conjuntamente “LAS PARTES”:</h4>\r\n  <p>1. Que, se reconocen recíprocamente la personalidad con la que comparecen a la celebración del presente acuerdo de voluntades.</p>\r\n  <p>2. Que, el presente contrato es el instrumento que las vincula en sus derechos y obligaciones.</p>\r\n  <p>3. Que, es su deseo celebrar el presente contrato y han negociado libremente los términos y condiciones del mismo con pleno conocimiento de sus alcances e implicaciones jurídicas, por lo que en su celebración no existe dolo, error, mala fe, lesión o cualquier otro vicio del consentimiento que pudiese afectarlo de inexistencia o nulidad.</p>\r\n\r\n  <h2>C L Á U S U L A S</h2>\r\n  <h4>PRIMERA.- OBJETO.</h4>\r\n  <p>El objeto del presente Contrato es que “EL AFILIADO” adquiera de “EL PRESTADOR”, a título oneroso y temporal, el derecho de uso ilimitado y sin restricción alguna de “LA TARJETA DE DESCUENTO” emitida por CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE, la cual consiste en que “EL AFILIADO” aproveche y acceda a “UN PROGRAMA DE BENEFICIOS QUE OTORGA DESCUENTOS A LOS COSTOS Y PERMITE RECIBIR SERVICIOS MÉDICOS PRIVADOS DE ALTA CALIDAD DE FORMA ACCESIBLE, CLARA Y SIN RESTRICCIONES DENTRO DE LA RED DE HOSPITALES 50 (FIFTY) DOCTORS CON SEDE EN EL ESTADO DE PUEBLA”.</p>\r\n  <p>Estableciendo que, la comercialización de “LA TARJETA DE DESCUENTO” por parte de “EL PRESTADOR” en ningún momento constituirá la venta, promoción o por cualquier medio la contratación de una póliza de seguro, bajo el entendido de que “EL PRESTADOR” no es una aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas (CNSF); sino que comercializa “LA TARJETA DE DESCUENTO” en favor de terceros con la finalidad de otorgar descuentos a los precios respecto de los servicios médicos que presta en el territorio nacional.</p>\r\n\r\n  <h4>SEGUNDA.- PRECIO DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“LAS PARTES” establecen de común acuerdo que “LA TARJETA DE DESCUENTO” tendrá como costo mensual la cantidad señalada en el Apartado 8.- de la Carátula del presente contrato; cantidad que ya incluye IVA, y la cual deberá ser cubierta por “EL AFILIADO” en favor de “EL PRESTADOR” dentro de los primeros 5 (cinco) días de cada mes, sin necesidad de gestiones o avisos de cobro, ya sea mediante:</p>\r\n  <p>(i) Transferencia electrónica de fondos a la cuenta bancaria señalada en el Apartado 9.- de la Carátula del presente contrato y de la cual es titular “EL PRESTADOR”.</p>\r\n  <p>(ii) Cheque que se recibirá salvo buen cobro en el Domicilio de “EL PRESTADOR” señalado en el Apartado 3.- de la Carátula del presente contrato, y que en caso de no ser pagado por falta de fondos suficientes o por otras causas imputables a “EL AFILIADO”, éste último está de acuerdo en que deberá cubrir a “EL PRESTADOR” el 20% (veinte por ciento) del monto del cheque por concepto de indemnización por daños y perjuicios en términos del artículo 193 de la Ley General de Títulos y Operaciones de Crédito, independientemente de cualquier otro cargo que se pudiera generar.</p>\r\n  <p>(iii) Cargos mensuales automáticos recurrentes a la tarjeta de crédito de “EL AFILIADO” según los datos señalados en el Apartado 11.- de la Carátula del presente contrato, quien manifiesta bajo protesta de decir verdad que autoriza a “EL PRESTADOR” a realizar los cargos mensuales correspondientes por el costo mensual de “LA TARJETA DE DESCUENTO” en dicha tarjeta o en la tarjeta que por renovación, reposición, robo o extravío le haya asignado el banco emisor. La autorización estará vigente mientras “EL AFILIADO” no haya notificado a “EL PRESTADOR” por escrito y con acuse de recibo su deseo de cancelar su afiliación o no renovarla, o en su defecto, realizar su baja respectiva en el sitio web o aplicación de “EL PRESTADOR”.</p>\r\n  <p>Esta autorización no exime a “EL AFILIADO” del pago mensual por el uso de “LA TARJETA DE DESCUENTO” y demás obligaciones contractuales, por lo que, en caso de que el cobro no sea autorizado por el banco emisor o por cualquier razón no pueda realizarse, “EL AFILIADO” deberá notificar tal situación a “EL PRESTADOR” a la dirección de correo electrónico silvia@pasaporteatusalud.com, a efecto de solicitar una forma de pago diversa, quedando obligado a cubrir de inmediato el pago correspondiente.</p>\r\n  <p>(iv) Cualquier otro medio de pago aceptado por “EL PRESTADOR”, mismo que se dará a conocer a través de sus medios oficiales de comunicación.</p>\r\n  <p>“EL PRESTADOR” podrá variar unilateralmente el costo mensual de “LA TARJETA DE DESCUENTO”, previo aviso a “EL AFILIADO” con 30 (treinta) días de anticipación a través de sus medios oficiales de comunicación.</p>\r\n  <p>Para el caso de que “EL AFILIADO” adquiera y cubra el precio de “LA TARJETA DE DESCUENTO” y posteriormente deje de pagar una mensualidad, deberá cubrir a “EL PRESTADOR”, por concepto de cuota de reactivación, la cantidad señalada en el Apartado 10.- de la Carátula por cada mes que haya interrumpido y/o no haya cubierto el precio de “LA TARJETA DE DESCUENTO”, hasta la fecha en que pretenda volver a adquirirla.</p>\r\n\r\n  <h4>TERCERA.- VIGENCIA DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“LA TARJETA DE DESCUENTO” objeto del presente contrato tendrá una vigencia de 30 días contados a partir de que “EL AFILIADO” cubra a “EL PRESTADOR” el precio establecido anteriormente, en el entendido de que la vigencia del presente contrato y de “LA TARJETA DE DESCUENTO” se prorrogarán automáticamente sin necesidad de celebrar documento adicional entre “LAS PARTES” siempre y cuando “EL AFILIADO” cubra, de mes en mes o en la frecuencia contratada, el precio vigente de “LA TARJETA DE DESCUENTO”.</p>\r\n  <p>“EL AFILIADO” tendrá derecho a revocar su consentimiento dentro de los 5 (cinco) días siguientes a la entrega de “LA TARJETA DE DESCUENTO” o la firma del presente contrato, lo que ocurra último, sin responsabilidad alguna, siempre y cuando no haya obtenido beneficio alguno por el uso de “LA TARJETA DE DESCUENTO”.</p>\r\n\r\n  <h4>CUARTA.- BENEFICIOS DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“EL AFILIADO”, de forma exclusiva, personal e intransferible, gozará de forma gratuita de los servicios que se mencionan a continuación:</p>\r\n  <ul><li>Consultas gratuitas ilimitadas de medicina general (no de especialidad) en la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla, únicamente con los doctores afiliados al programa de Pasaporte a tu Salud.</li><li>Consultas de urgencia gratuitas en la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla.</li></ul>\r\n  <p>No así respecto de los servicios que, de manera enunciativa más no limitativa, se describen a continuación:</p>\r\n  <ul><li>Hospitalización dentro de la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla, sujeto a la disponibilidad de cada uno de ellos.</li><li>Consultas de especialidad ilimitadas a costo preferencial, con médicos especialistas pertenecientes al programa PATS.</li><li>Acceso a farmacia PATS con costos reducidos de medicamentos genéricos.</li><li>Imagenología y laboratorios ilimitados con costos preferenciales.</li><li>Acceso a cirugías con cuota de recuperación preferente, con o sin honorarios médicos incluidos según corresponda.</li></ul>\r\n  <p>Dichos servicios generarán, por evento, el pago de una cuota con cargo a “EL AFILIADO”, misma que resultará de aplicar los porcentajes de descuento que se desprenden del ANEXO 4 del presente contrato a los precios publicados al público en general o los precios preferenciales indicados.</p>\r\n  <p>Mientras “LA TARJETA DE DESCUENTO” se encuentre vigente, “EL AFILIADO” gozará de todos los beneficios que la misma le otorga; sin embargo, para el caso de que requiera cirugía o procedimiento quirúrgico en quirófano, deberá haber sufragado por adelantado la adquisición de “LA TARJETA DE DESCUENTO” por un periodo de 12 (doce) meses y encontrarse dentro de dicho periodo de vigencia.</p>\r\n\r\n  <h4>QUINTA.- OBLIGACIONES DE “EL PRESTADOR”.</h4>\r\n  <p>“EL PRESTADOR” se obliga a: (i) otorgar a “EL AFILIADO” el acceso ilimitado a “LA TARJETA DE DESCUENTO” durante la vigencia del contrato; (ii) mantener actualizada y operativa la Red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla; (iii) proporcionar a “EL AFILIADO”, de forma digital, “LA TARJETA DE DESCUENTO” dentro de los 5 (cinco) días hábiles siguientes al primer pago; e (iv) informar por escrito cualquier modificación a la red de hospitales o al tabulador de cuotas con al menos 10 (diez) días de anticipación.</p>\r\n\r\n  <h4>SEXTA.- OBLIGACIONES DE “EL AFILIADO”.</h4>\r\n  <p>“EL AFILIADO” se obliga a: (i) pagar puntualmente el precio de “LA TARJETA DE DESCUENTO”; (ii) utilizarla de forma exclusiva, personal e intransferible; (iii) cubrir directamente a los hospitales y con anterioridad a recibir el servicio médico las cuotas de recuperación según tabulador vigente; (iv) presentar identificación oficial y “LA TARJETA DE DESCUENTO” o código QR cada vez que haga uso de beneficios; y (v) notificar por escrito cualquier cambio de domicilio o datos de contacto en un plazo no mayor a 5 (cinco) días.</p>\r\n\r\n  <h4>SÉPTIMA.- ACCESO A LOS BENEFICIOS Y PROCEDIMIENTO.</h4>\r\n  <p>Para hacer uso de “LA TARJETA DE DESCUENTO”, “EL AFILIADO” deberá agendar sus citas directamente con los doctores pertenecientes a la Red de Hospitales 50 (FIFTY) Doctors, que en ese momento se encuentren adscritos al programa de beneficios, a través de la aplicación oficial, página de internet oficial de PATS o medios oficiales que indique “EL PRESTADOR”.</p>\r\n  <p>“EL AFILIADO” se obliga a pagar directamente al médico especialista perteneciente al programa el costo de la consulta de especialidad de que se trate, en términos de los porcentajes de descuento del ANEXO 4. En caso de no estar facultado para asistir por fuerza mayor, tendrá un plazo de 30 (treinta) días contados a partir de haber generado la cita para solicitar una nueva consulta médica.</p>\r\n\r\n  <h4>OCTAVA.- EXCLUSIONES Y LIMITACIONES.</h4>\r\n  <p>Los beneficios no incluirán: (i) trasplantes de órganos; (ii) tratamientos experimentales; (iii) tratamientos de oncología a excepción de algunas cirugías; (iv) medicamentos extra hospitalarios que no estén recogidos en el catálogo de Farmacia PATS; (v) atención médica con especialistas no adscritos o no publicados en los medios oficiales; y (vi) cualquier servicio no listado expresamente.</p>\r\n\r\n  <h4>NOVENA.- CAUSAS DE TERMINACIÓN.</h4>\r\n  <p>El contrato podrá terminarse por falta de pago, mutuo consentimiento por escrito o incumplimiento de cualquiera de las cláusulas por cualquiera de “LAS PARTES”. En caso de terminación, “EL AFILIADO” no tendrá derecho a exigir la devolución de cantidad alguna.</p>\r\n\r\n  <h4>DÉCIMA.- CANCELACIÓN VOLUNTARIA.</h4>\r\n  <p>“EL AFILIADO” podrá cancelar “LA TARJETA DE DESCUENTO” mediante aviso por escrito con 30 (treinta) días de anticipación. Dicha cancelación surtirá efectos a partir del siguiente periodo mensual y no generará reembolso de pagos ya realizados.</p>\r\n\r\n  <h4>DÉCIMA PRIMERA.- PROTECCIÓN DE DATOS PERSONALES.</h4>\r\n  <p>“LAS PARTES” acuerdan que el tratamiento de datos personales se sujetará a la Ley Federal de Protección de Datos Personales en Posesión de los Particulares. “EL AFILIADO” autoriza expresamente el uso de sus datos para la gestión de “LA TARJETA DE DESCUENTO”. El aviso de privacidad se integra al presente contrato como ANEXO 5.</p>\r\n\r\n  <h4>DÉCIMA SEGUNDA.- RESPONSABILIDAD.</h4>\r\n  <p>“EL AFILIADO” reconoce y acepta que “LA TARJETA DE DESCUENTO” es emitida y administrada directamente por CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE, quien es responsable de la operación de la red de descuentos, afiliación de prestadores médicos y prestación de cualquier servicio relacionado con “LA TARJETA DE DESCUENTO”.</p>\r\n  <p>En consecuencia, “EL PRESTADOR” no tendrá responsabilidad directa ni indirecta por la prestación, calidad, eficacia, resultado, daño, perjuicio, lesión, complicación, secuela, evento adverso o consecuencia derivada de servicios médicos recibidos, incluyendo aquellos ocasionados por negligencia, impericia o mala praxis de profesionales de la salud o prestadores afiliados. Cualquier relación derivada de la prestación de servicios médicos se establece directamente entre “EL AFILIADO” y los prestadores de servicios de salud correspondientes. Esta limitación subsistirá a la terminación del contrato.</p>\r\n\r\n  <h4>DÉCIMA TERCERA.- PREVENCIÓN DE LAVADO DE DINERO Y ORIGEN DE LOS RECURSOS.</h4>\r\n  <p>“LAS PARTES” declaran bajo protesta de decir verdad que los recursos económicos, bienes y derechos que utilicen para cumplir obligaciones derivadas de este contrato tienen y tendrán origen lícito. “EL AFILIADO” manifiesta que el pago inicial y pagos futuros provienen de fuentes lícitas y no de actividades tipificadas como delitos.</p>\r\n  <p>“LAS PARTES” reconocen que la prestación de servicios de comercio puede ser considerada actividad vulnerable, por lo que se obligan a proporcionar información y documentación requerida para integrar expediente de identificación e informar si tienen conocimiento de la existencia de beneficiario controlador.</p>\r\n\r\n  <h4>DÉCIMA CUARTA.- CONFORMACIÓN DEL EXPEDIENTE DE IDENTIFICACIÓN.</h4>\r\n  <p>“EL PRESTADOR” queda obligado a conformar y mantener un expediente de identificación de “EL AFILIADO”. Para tales efectos, “EL AFILIADO” se obliga a entregar los documentos aplicables: identificación oficial vigente o pasaporte, acta de nacimiento cuando aplique, comprobante de domicilio, constancia de situación fiscal cuando aplique, documento equivalente de identificación, y declaración de dueño beneficiario.</p>\r\n  <p>Cuando exista persona responsable, la documentación de identificación y representación deberá integrarse al expediente; la CIF/constancia fiscal corresponde al tutor cuando aplique. “EL PRESTADOR” conservará dicho expediente por un periodo mínimo de 5 (cinco) años contados a partir de que termine la vigencia del contrato o termine por cualquiera de sus causales, garantizando la confidencialidad de los datos personales.</p>\r\n\r\n  <h4>DÉCIMA QUINTA.- CAUSAL ESPECÍFICA DE RESCISIÓN.</h4>\r\n  <p>Será motivo de rescisión inmediata sin necesidad de declaración judicial y sin responsabilidad para la parte afectada cuando cualquiera de “LAS PARTES” se niegue a proporcionar información requerida para cumplimiento de la Ley Federal para la Prevención e Identificación de Operaciones con Recursos de Procedencia Ilícita, proporcione información falsa o aparezca en listas de personas bloqueadas emitidas por autoridad competente.</p>\r\n\r\n  <h4>DÉCIMA SEXTA.- LEGISLACIÓN APLICABLE Y JURISDICCIÓN.</h4>\r\n  <p>“LAS PARTES” establecen que la Procuraduría Federal del Consumidor es competente en vía administrativa para resolver cualquier controversia sobre interpretación o cumplimiento. Sin perjuicio de lo anterior, se someten expresamente a la jurisdicción de los tribunales competentes del fuero común del Distrito Judicial de Puebla, Estado de Puebla, renunciando de manera expresa e irrevocable a cualquier otro fuero o jurisdicción que pudiera corresponderles.</p>\r\n\r\n  <p>Enteradas “LAS PARTES” del contenido y alcance del presente contrato, y entendidas de los derechos y obligaciones que contraen, firman el presente instrumento, incluyendo sus anexos, manifestando que no medió error, dolo, mala fe, violencia o lesión, ni vicio del consentimiento alguno, en la Ciudad de Puebla, Estado de Puebla, reconociendo que la fecha de firma es 13 de mayo de 2026.</p>\r\n\r\n  <div class=\"sign-grid\">\r\n    <div class=\"sign-box\"><div class=\"line\"></div><strong>“EL PRESTADOR”</strong><br>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE<br>Representada por PEDRO AZCÁRRAGA RAMOS</div>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>“EL AFILIADO”</strong><br>julio garcia braga fernandez</div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 1<br>Identificación oficial o pasaporte de “EL AFILIADO”</h2><p>Se integra al expediente la identificación oficial cargada por el usuario en el formulario. Para mexicanos, corresponde a identificación oficial/INE cuando aplique. Para extranjeros/no mexicanos, corresponde a identificación oficial o pasaporte vigente; al menos el frente es obligatorio y el reverso será opcional cuando el documento no lo tenga.</p><p><strong>Tipo:</strong> PASAPORTE. <strong>Emitida por / país emisor:</strong> . <strong>Número:</strong> -772626362627727272)2.</p></div>\r\n  <div class=\"annex\"><h2>ANEXO 2<br>COMPROBANTE DE DOMICILIO DE “EL AFILIADO”</h2><p>Se integra al expediente el comprobante de domicilio cargado por el usuario. Domicilio declarado: jshshshs 1 Int. 1, Col. colonia, C.P. 33004, puebla, minesota, usa.</p></div>\r\n  <div class=\"annex\"><h2>ANEXO 3<br>CONSTANCIA DE SITUACIÓN FISCAL DE “EL AFILIADO”</h2><p>No aplicable salvo que declare RFC mexicano. En caso de pacientes representados, la constancia fiscal o CIF corresponde a la persona responsable cuando sea aplicable, no al menor. Para afiliados extranjeros/no mexicanos, no será obligatoria salvo que declaren RFC mexicano o residencia fiscal aplicable.</p></div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 4<br>CUOTAS DE RECUPERACIÓN Y/O PRECIOS BASE A CUBRIR A “EL PRESTADOR”</h2>\r\n    <p>En el presente anexo se establecen los porcentajes de descuento a obtener como titular de “LA TARJETA DE DESCUENTO”, por lo que la cantidad a cubrir por “EL AFILIADO” directamente al hospital de la cadena 50 (FIFTY) Doctors o al doctor que preste el servicio se obtendrá de aplicar el porcentaje de descuento correspondiente al precio publicado por los medios oficiales o al precio vigente en el establecimiento.</p>\r\n    <table><tr><th>Servicios / procedimientos</th><th>Descuentos</th></tr><tr><td>Consulta de urgencias</td><td>100%</td></tr><tr><td>Consulta de medicina general</td><td>100%</td></tr><tr><td>Habitación hospitalaria</td><td>90%</td></tr><tr><td>Uso de áreas de urgencias médicas</td><td>80%</td></tr><tr><td>Utilización de cubículos de terapia intensiva (UCIA-UCIN-UCIP)</td><td>75%</td></tr><tr><td>CEYE</td><td>75%</td></tr><tr><td>Uso quirófano</td><td>75%</td></tr><tr><td>Servicio de cuneros</td><td>75%</td></tr><tr><td>Materiales & medicamentos del cuadro básico, genéricos intercambiables</td><td>70%</td></tr><tr><td>Hemodinamia</td><td>70%</td></tr><tr><td>Imagenología</td><td>70%</td></tr><tr><td>Endoprótesis</td><td>70%</td></tr><tr><td>Osteosíntesis</td><td>70%</td></tr><tr><td>Prótesis</td><td>70%</td></tr><tr><td>Órtesis</td><td>70%</td></tr><tr><td>Laboratorio clínico</td><td>60%</td></tr></table>\r\n    <p class=\"small\">Los descuentos aplican con los proveedores suscritos al convenio de Pasaporte a tu Salud.</p>\r\n    <table><tr><th>Servicios / procedimientos</th><th>Precios base</th></tr><tr><td>Consulta de especialidades médicas</td><td>$390.00</td></tr><tr><td>Colposcopía</td><td>$400.00</td></tr><tr><td>Retiro de puntos de sutura</td><td>$80.00</td></tr><tr><td>Aplicación de medicamento intramuscular</td><td>$60.00</td></tr><tr><td>Retiro de DIU</td><td>$500.00</td></tr><tr><td>Colocación de DIU</td><td>$700.00</td></tr><tr><td>Extracción de cuerpo extraño (oído y nariz)</td><td>$300.00</td></tr><tr><td>Lavado ótico</td><td>$250.00</td></tr><tr><td>Curación de sitio quirúrgico</td><td>$250.00</td></tr><tr><td>Retiro de yeso</td><td>$250.00</td></tr><tr><td>Visita día de hospitalización</td><td>$650.00</td></tr><tr><td>Visita de urgencias</td><td>$750.00</td></tr><tr><td>Día de terapia intensiva</td><td>$850.00</td></tr></table>\r\n    <p class=\"small\">Todos los precios incluyen IVA. La factura de servicios hospitalarios será emitida con el desglose correspondiente y el ahorro otorgado por ser titular de “LA TARJETA DE DESCUENTO”.</p>\r\n    <p>Exclusiones y limitaciones: se aplicarán descuentos y precios especiales para el acompañante de “EL AFILIADO” en la misma habitación únicamente para la primera noche de hospitalización. Los precios y porcentajes de descuento darán derecho a la utilización de materiales y medicamentos del cuadro básico, genéricos intercambiables; cualquier otro tipo de medicación será cubierto directamente por “EL AFILIADO”. Los costos de procedimientos quirúrgicos incluyen honorarios médicos cuando así se indique. “EL AFILIADO” podrá atenderse con el médico tratante que elija, debiendo cubrir honorarios directamente a dicho médico, conservando el derecho a beneficios dentro de la red aplicable.</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Firma de aceptación de “EL AFILIADO”</strong><br>julio garcia braga fernandez</div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 5<br>AVISO DE PRIVACIDAD</h2>\r\n    <p>En cumplimiento de las disposiciones establecidas en la Ley Federal de Protección de Datos Personales en Posesión de Particulares, su Reglamento y los lineamientos aplicables, “CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE” (en lo sucesivo “EL PRESTADOR”), con domicilio en CALLE PASEO SINFONÍA NÚMERO EXTERIOR 1, LOCAL 2-14, LOMAS DE ANGELÓPOLIS II, SAN ANDRÉS CHOLULA, ESTADO DE PUEBLA, CÓDIGO POSTAL 72830, da a conocer el Aviso de Privacidad al tenor del cual manejará por medio de su representación y/o empleados los datos personales y/o documentación proporcionada por el afiliado o usuario de “LA TARJETA DE DESCUENTO”.</p>\r\n    <p>Se tendrá por aceptado expresamente el presente Aviso de Privacidad una vez proporcionados los datos personales y firmada digitalmente la aceptación del contrato, motivo por el cual “EL PRESTADOR” estará facultado para manejar la información conforme a la legislación aplicable.</p>\r\n    <h4>Modificación del aviso de privacidad</h4><p>Este aviso podrá ser modificado o adecuado a las necesidades de “EL PRESTADOR”. Las modificaciones o actualizaciones serán incorporadas al presente aviso y estarán disponibles en la página de internet, domicilio de “EL PRESTADOR” o serán enviadas al último correo electrónico proporcionado.</p>\r\n    <h4>Finalidad de la información</h4><p>La información será utilizada para: elaborar y mantener actualizada la base de usuarios; identificar afiliados; proporcionar la tarjeta digital; otorgar acceso al programa de beneficios; informar modificaciones a la red o tabulador; realizar análisis estadísticos internos y brindar un óptimo servicio médico.</p>\r\n    <h4>Tipo de datos necesarios</h4><p>Se solicitarán datos de identificación, contacto, legales, contractuales y fiscales cuando aplique, incluyendo nombre completo, lugar y fecha de nacimiento, firma, identificación oficial, nacionalidad, CURP y RFC cuando sean aplicables, domicilio, teléfono y correo electrónico.</p>\r\n    <h4>Transferencias de la información</h4><p>El usuario autoriza proporcionar información sin consentimiento adicional en los casos previstos por ley, resolución de autoridad competente, tratados aplicables, salvaguarda de interés público, procuración o administración de justicia, reconocimiento o defensa de derechos en procesos judiciales, y a socios comerciales, técnicos o estratégicos que asuman obligaciones de confidencialidad y seguridad equivalentes.</p>\r\n    <h4>Limitación del uso o divulgación de datos y derechos ARCO</h4><p>El usuario podrá limitar el uso o divulgación de sus datos personales y ejercer derechos de acceso, rectificación, cancelación u oposición mediante solicitud escrita dirigida a “EL PRESTADOR” en su domicilio o al correo silvia@pasaporteatusalud.com, acompañando documento que acredite su identidad.</p>\r\n    <h4>Revocación de consentimiento</h4><p>El usuario podrá revocar su consentimiento siguiendo el mismo procedimiento, considerando que para ciertos fines la revocación puede implicar la cancelación de “LA TARJETA DE DESCUENTO” y la imposibilidad de acceder al programa.</p>\r\n    <p><strong>Nombre:</strong> julio garcia braga fernandez<br><strong>Fecha:</strong> 13 de mayo de 2026</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Firma</strong></div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 6<br>DECLARACIÓN DE DUEÑO BENEFICIARIO</h2>\r\n    <p>DE CONFORMIDAD CON LO DISPUESTO EN LOS ARTÍCULOS 18 FRACCIÓN I Y III DE LA LEY FEDERAL PARA PREVENCIÓN E IDENTIFICACIÓN DE OPERACIONES CON RECURSOS DE PROCEDENCIA ILÍCITA, EL ARTÍCULO 15 DE SU REGLAMENTO Y EL ARTÍCULO 13 DE LAS REGLAS DE CARÁCTER GENERAL, MANIFIESTO BAJO PROTESTA DE DECIR VERDAD:</p>\r\n    <h4>Datos de identificación del cliente</h4>\r\n    <table><tr><th>Campo</th><th>Respuesta</th></tr><tr><td>Apellido paterno, materno y nombre(s)</td><td>julio garcia braga fernandez</td></tr><tr><td>Fecha de nacimiento</td><td>1990-02-11</td></tr><tr><td>País de nacimiento</td><td></td></tr><tr><td>Nacionalidad</td><td></td></tr><tr><td>Actividad, ocupación o profesión</td><td>medico</td></tr><tr><td>Estado civil</td><td>UNIÓN LIBRE</td></tr><tr><td>Domicilio particular</td><td>jshshshs 1 Int. 1, Col. colonia, C.P. 33004, puebla, minesota, usa</td></tr><tr><td>Teléfonos</td><td>6302061122</td></tr><tr><td>Correo electrónico</td><td>jgarcia_braga@yahoo.es</td></tr><tr><td>CURP</td><td>No aplica por nacionalidad extranjera / no mexicana</td></tr><tr><td>RFC</td><td>No aplica por nacionalidad extranjera / no residente fiscal en México</td></tr><tr><td>Tipo de identificación</td><td>PASAPORTE</td></tr><tr><td>Emitida por / país emisor</td><td></td></tr><tr><td>Número de identificación</td><td>-772626362627727272)2</td></tr></table>\r\n    <h4>Datos de identificación de la operación</h4>\r\n    <table><tr><th>Campo</th><th>Respuesta</th></tr><tr><td>Tipo de operación</td><td>Adquisición de tarjeta de descuento PATS</td></tr><tr><td>Monto de operación</td><td>$800.00 M.N.</td></tr><tr><td>Fecha de operación</td><td>13 de mayo de 2026</td></tr><tr><td>Forma de pago</td><td>Pasarela / medio autorizado por “EL PRESTADOR”</td></tr><tr><td>Moneda</td><td>MXN</td></tr></table>\r\n    <h4>Información de la existencia del dueño beneficiario o beneficiario controlador</h4>\r\n    <p>Declaro que soy el beneficiario directo de la operación y no existe ningún otro dueño beneficiario o beneficiario controlador: <strong>SI</strong>.</p>\r\n    <h4>Aviso de privacidad</h4><p>Los datos personales serán protegidos y tratados conforme al Aviso de Privacidad contenido en el cuerpo del presente contrato y la legislación aplicable.</p>\r\n    <p>H. Puebla de Zaragoza al 13 del mes de mayo del año 2026.</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Nombre y firma</strong><br>julio garcia braga fernandez</div>\r\n  </div>\r\n\r\n  \r\n  </div>\r\n', 'data:image/png;base64,', 'julio garcia braga fernandez', '134d7bd78e0fd08af34ce1b926bee86a266c7b58bba5bfe71ef6b7b79352cb99', '2026-05-13 23:18:45', '189.190.149.83', 'Mozilla/5.0 (iPhone; CPU iPhone OS 18_7 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) Version/26.4 Mobile/15E148 Safari/604.1', '', 'firmado', '2026-05-13 23:18:45', '2026-05-13 23:18:45');
INSERT INTO `pats_contratos_firmados` (`id_contrato_firmado`, `id_orden`, `id_pasaporte`, `id_distribuidor`, `id_franquicia`, `token_publico`, `contrato_clave`, `contrato_version`, `html_contrato_renderizado`, `firma_afiliado_base64`, `nombre_firmante`, `hash_contrato`, `fecha_firma`, `ip_firma`, `user_agent_firma`, `pdf_path`, `estatus`, `created_at`, `updated_at`) VALUES
(16, 1, 1, 0, 0, '', 'contrato_pats_base', '1.0', '<style>\r\n  .pats-contract{font-family:Arial,Helvetica,sans-serif;color:#172033;font-size:12px;line-height:1.52;background:#fff;padding:4px}\r\n  .pats-contract h1,.pats-contract h2,.pats-contract h3,.pats-contract h4{text-align:center;margin:12px 0 8px;color:#0d1b3e}\r\n  .pats-contract h1{font-size:16px;text-transform:uppercase;letter-spacing:.05em}\r\n  .pats-contract h2{font-size:15px;text-transform:uppercase;letter-spacing:.04em}\r\n  .pats-contract h3{font-size:13px;text-transform:uppercase;letter-spacing:.08em}\r\n  .pats-contract h4{font-size:12px;text-align:left;text-transform:uppercase;margin-top:12px}\r\n  .pats-contract p{margin:6px 0;text-align:justify}\r\n  .pats-contract ul{margin:6px 0 8px 18px;padding:0}.pats-contract li{margin:4px 0;text-align:justify}\r\n  .pats-contract table{width:100%;border-collapse:collapse;margin:8px 0 12px}.pats-contract th,.pats-contract td{border:1px solid #cbd5e1;padding:6px;vertical-align:top}.pats-contract th{background:#eef4ff;color:#0d1b3e;text-align:left}\r\n  .pats-contract .center{text-align:center}.pats-contract .muted{color:#64748b}.pats-contract .small{font-size:10px}.pats-contract .badge{display:inline-block;padding:3px 8px;border-radius:999px;background:#eef4ff;color:#1d4ed8;font-weight:700;margin:2px 4px 2px 0}\r\n  .pats-contract .sign-grid{display:grid;grid-template-columns:1fr 1fr;gap:22px;margin-top:28px}.pats-contract .sign-box{text-align:center;min-height:95px}.pats-contract .line{border-top:1px solid #0f172a;margin:48px 8px 6px}.pats-contract .signature-img{max-width:220px;max-height:82px;display:block;margin:0 auto 4px}\r\n  .pats-contract .annex{page-break-before:auto;border-top:2px solid #0d1b3e;margin-top:18px;padding-top:12px}.pats-contract .page-break{page-break-before:always;border-top:1px dashed #cbd5e1;margin-top:18px;padding-top:12px}\r\n</style>\r\n<div class=\"pats-contract\">\r\n  <h1>Carátula del contrato de adquisición de tarjeta de descuento</h1>\r\n  <p>CARÁTULA DEL CONTRATO DE ADQUISICIÓN DE TARJETA DE DESCUENTO (EN LO SUCESIVO “LA CARÁTULA”), QUE CELEBRAN POR UNA PARTE LA SOCIEDAD SEÑALADA EN EL APARTADO 1.- DE LA CARÁTULA, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL PRESTADOR”, REPRESENTADA EN ESTE ACTO POR LA PERSONA FÍSICA QUE SE INDICA EN EL APARTADO 2.- DE LA CARÁTULA; Y POR LA OTRA PARTE, LA PERSONA FÍSICA SEÑALADA EN EL APARTADO 5.- DE LA CARÁTULA, POR SU PROPIO DERECHO, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL AFILIADO”; Y CUANDO LOS ANTES NOMBRADOS ACTÚEN DE MANERA CONJUNTA, SE LES DENOMINARÁ COMO “LAS PARTES”; QUIENES SE SUJETAN AL TENOR DE LA CARÁTULA, DECLARACIONES Y CLÁUSULAS SIGUIENTES:</p>\r\n    \r\n  <h2>C A R Á T U L A</h2>\r\n  <table>\r\n    <tr><th style=\"width:8%\">Apartado</th><th style=\"width:42%\">Definición</th><th>Respuesta</th></tr>\r\n    <tr><td>1.-</td><td>Nombre de “EL PRESTADOR”</td><td>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE</td></tr>\r\n    <tr><td>2.-</td><td>Nombre del Representante Legal de “EL PRESTADOR”</td><td>PEDRO AZCÁRRAGA RAMOS</td></tr>\r\n    <tr><td>3.-</td><td>Domicilio de “EL PRESTADOR”</td><td>CALLE PASEO SINFONÍA NÚMERO EXTERIOR 1, LOCAL 2-14, LOMAS DE ANGELÓPOLIS II, SAN ANDRÉS CHOLULA, ESTADO DE PUEBLA, CÓDIGO POSTAL 72830</td></tr>\r\n    <tr><td>4.-</td><td>Clave del Registro Federal de Contribuyentes de “EL PRESTADOR”</td><td>COH2202144H5</td></tr>\r\n    <tr><td>5.-</td><td>Nombre de “EL AFILIADO”</td><td>Juan Carlos Fuentes Moya</td></tr>\r\n    <tr><td>6.-</td><td>Domicilio de “EL AFILIADO”</td><td>sdffsdf 118, Col. fsdfds, C.P. 45134, fsd, Jalisco, México</td></tr>\r\n    <tr><td>7.-</td><td>Clave del Registro Federal de Contribuyentes de “EL AFILIADO”</td><td>FDSFDSFDS</td></tr>\r\n    <tr><td>8.-</td><td>Costo mensual de “LA TARJETA DE DESCUENTO”</td><td>$800.00 M.N.</td></tr>\r\n    <tr><td>9.-</td><td>Cuenta bancaria de “EL PRESTADOR” para pagos</td><td>Cuenta: 01600866709<br>CLABE: 042650016008667096<br>Institución Bancaria: Banca Mifel, S.A., Institución de Banca Múltiple, Grupo Financiero Mifel</td></tr>\r\n    <tr><td>10.-</td><td>Cuota de Reactivación de “LA TARJETA DE DESCUENTO”</td><td>$100.00 M.N. por cada mes que se haya interrumpido el pago.</td></tr>\r\n    <tr><td>11.-</td><td>Datos de la Tarjeta de Crédito de “EL AFILIADO”</td><td>Número de tarjeta: pendiente de confirmar por pasarela/token de pago.<br>Institución bancaria: pendiente de confirmar por pasarela. <br><span class=\"small\">No se almacena número completo de tarjeta en este formulario.</span></td></tr>\r\n    <tr><td>12.-</td><td>Anexos</td><td>ANEXO 1. Identificación oficial de “EL AFILIADO”<br>ANEXO 2. Comprobante de domicilio de “EL AFILIADO”<br>ANEXO 3. Constancia de Situación Fiscal de “EL AFILIADO”, si aplica<br>ANEXO 4. Cuotas de recuperación y/o precios base a cubrir a “EL PRESTADOR”<br>ANEXO 5. Aviso de privacidad<br>ANEXO 6. Declaración de dueño beneficiario</td></tr>\r\n    <tr><td>13.-</td><td>Fecha de Firma del Contrato</td><td>14 de mayo de 2026</td></tr>\r\n  </table>\r\n\r\n  <div class=\"sign-grid\">\r\n    <div class=\"sign-box\"><div class=\"line\"></div><strong>“EL PRESTADOR”</strong><br>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE<br>Representada por PEDRO AZCÁRRAGA RAMOS</div>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>“EL AFILIADO”</strong><br>Juan Carlos Fuentes Moya<br><span class=\"small\">La persona física señalada en el Apartado 5.- de la Carátula</span></div>\r\n  </div>\r\n\r\n  <div class=\"page-break\"></div>\r\n  <h1>Contrato de adquisición de tarjeta de descuento</h1>\r\n  <p>CONTRATO DE ADQUISICIÓN DE TARJETA DE DESCUENTO, QUE CELEBRAN POR UNA PARTE LA SOCIEDAD SEÑALADA EN EL APARTADO 1.- DE LA CARÁTULA, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL PRESTADOR”, REPRESENTADA EN ESTE ACTO POR LA PERSONA FÍSICA QUE SE INDICA EN EL APARTADO 2.- DE LA CARÁTULA; Y POR LA OTRA PARTE, LA PERSONA FÍSICA SEÑALADA EN EL APARTADO 5.- DE LA CARÁTULA, POR SU PROPIO DERECHO, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL AFILIADO”; Y CUANDO LOS ANTES NOMBRADOS ACTÚEN DE MANERA CONJUNTA, SE LES DENOMINARÁ COMO “LAS PARTES”; QUIENES SE SUJETAN AL TENOR DE LAS DECLARACIONES Y CLÁUSULAS SIGUIENTES:</p>\r\n\r\n  <h2>D E C L A R A C I O N E S</h2>\r\n  <h4>I.- Declara “EL PRESTADOR” por conducto de su representación:</h4>\r\n  <p>A. Que, su representada es una sociedad mercantil constituida conforme a las leyes de los Estados Unidos Mexicanos, según consta en la escritura pública número 39,861, del volumen 830 de fecha catorce de febrero de dos mil veintidós, otorgada ante la fe del Licenciado Ernesto Joaquín Briones Amador, Notario Público Titular de la Notaría Pública número 46 de las del Distrito Judicial de Puebla, Estado de Puebla, cuyo primer testimonio se encuentra inscrito ante las oficinas del Registro Público de Comercio del Distrito Judicial de Puebla, Estado de Puebla, bajo el Folio Mercantil Electrónico: N-2022022991, por virtud del cual se llevó a cabo la Constitución de la persona moral denominada CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE.</p>\r\n  <p>B. Que, la persona física que la representa en este acto, señalada en el Apartado 2.- de la Carátula, cuenta con todas y cada una de las facultades necesarias para la celebración del presente contrato, las cuales se desprenden del instrumento descrito en el punto declarativo inmediato anterior, mismas que manifiesta bajo protesta de decir verdad que no le han sido suspendidas, revocadas o limitadas en forma alguna.</p>\r\n  <p>C. Que, su representada tiene como domicilio fiscal el señalado en el Apartado 3.- de la Carátula del presente contrato, mismo que designa como domicilio convencional para cualquier cuestión relacionada con la celebración del presente contrato.</p>\r\n  <p>D. Que, su representada se encuentra inscrita en el Registro Federal de Contribuyentes bajo la clave señalada en el Apartado 4.- de la Carátula.</p>\r\n  <p>E. Que, ha desarrollado y es su deseo comparecer a la celebración del presente instrumento con la finalidad de enajenar en favor de “EL AFILIADO”, una Tarjeta de Descuento que da acceso a “UN PROGRAMA DE BENEFICIOS QUE OTORGA DESCUENTOS A LOS COSTOS Y PERMITE RECIBIR SERVICIOS MÉDICOS PRIVADOS DE ALTA CALIDAD DE FORMA ACCESIBLE, CLARA Y SIN RESTRICCIONES DENTRO DE LA RED DE HOSPITALES 50 (FIFTY) DOCTORS CON SEDE EN EL ESTADO DE PUEBLA”, en lo sucesivo “LA TARJETA DE DESCUENTO”, en los términos y condiciones que se establecerán más adelante.</p>\r\n  <p>F. Que, su representada no es una Aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas sino una empresa dedicada, entre otros, a la operación y administración de establecimientos destinados a la atención y asistencia de enfermos, por lo que la enajenación de “LA TARJETA DE DESCUENTO” únicamente constituye un acto de comercio que brindará a “EL AFILIADO” acceso a un programa de beneficios como ha quedado descrito anteriormente.</p>\r\n\r\n  <h4>II.- Declara “EL AFILIADO”, por su propio derecho:</h4>\r\n      <p>A. Que, su nombre se señala en el Apartado 5.- de la Carátula, es una persona física de nacionalidad mexicana, en pleno ejercicio de sus derechos, legal y jurídicamente capaz para celebrar el presente Contrato, quien se identifica con credencial para votar vigente expedida por el Instituto Nacional Electoral, tipo INE, número FSDFSDF, que en copia simple o archivo digital se agrega al cuerpo del presente contrato como ANEXO 1.</p>\r\n    <p>B. Que, tiene como domicilio particular el señalado en el Apartado 6.- de la Carátula, mismo que designa como domicilio convencional para cualquier cuestión relacionada con la celebración del presente contrato, tal y como lo acredita con el comprobante de domicilio que en copia simple o archivo digital se agrega al cuerpo del presente contrato como ANEXO 2.</p>\r\n  <p>C. Que, su CURP es SSSS y su RFC/identificación fiscal es FDSFDSFDS; asimismo manifiesta que cuenta con capacidad económica para obligarse en términos del presente contrato y que los recursos con los que cubrirá sus obligaciones provendrán de fuentes lícitas. En caso de nacionalidad extranjera/no mexicana, se tendrán por no aplicables CURP, INE y constancia fiscal mexicana salvo manifestación expresa de residencia fiscal o RFC mexicano.</p>\r\n  <p>D. Que, es su deseo comparecer a la celebración del presente instrumento con la finalidad de adquirir “LA TARJETA DE DESCUENTO” de acuerdo con los términos y condiciones que se establecen a continuación.</p>\r\n  <p>E. Que, previo a la celebración del presente contrato fue informado y manifiesta expresamente que reconoce que “EL PRESTADOR” no es una Aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas y que las actividades comerciales objeto del presente contrato no consisten en la contratación de un seguro, de la índole que fuere, sino que únicamente implica la adquisición de una tarjeta de descuento que da acceso a un programa de beneficios que otorga descuentos a los costos y permite recibir servicios médicos privados de alta calidad de forma accesible, clara y sin restricciones dentro de la red de hospitales 50 (FIFTY) Doctors con sede en el Estado de Puebla.</p>\r\n  <p>F. Que, reconoce que “EL PRESTADOR” se dedica a la operación de centros hospitalarios y que la emisión de “LA TARJETA DE DESCUENTO” únicamente corresponde a la intención de este último de crear un programa de descuentos para el acceso a los servicios prestados por la Red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla.</p>\r\n\r\n  <h4>III.- Declaran conjuntamente “LAS PARTES”:</h4>\r\n  <p>1. Que, se reconocen recíprocamente la personalidad con la que comparecen a la celebración del presente acuerdo de voluntades.</p>\r\n  <p>2. Que, el presente contrato es el instrumento que las vincula en sus derechos y obligaciones.</p>\r\n  <p>3. Que, es su deseo celebrar el presente contrato y han negociado libremente los términos y condiciones del mismo con pleno conocimiento de sus alcances e implicaciones jurídicas, por lo que en su celebración no existe dolo, error, mala fe, lesión o cualquier otro vicio del consentimiento que pudiese afectarlo de inexistencia o nulidad.</p>\r\n\r\n  <h2>C L Á U S U L A S</h2>\r\n  <h4>PRIMERA.- OBJETO.</h4>\r\n  <p>El objeto del presente Contrato es que “EL AFILIADO” adquiera de “EL PRESTADOR”, a título oneroso y temporal, el derecho de uso ilimitado y sin restricción alguna de “LA TARJETA DE DESCUENTO” emitida por CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE, la cual consiste en que “EL AFILIADO” aproveche y acceda a “UN PROGRAMA DE BENEFICIOS QUE OTORGA DESCUENTOS A LOS COSTOS Y PERMITE RECIBIR SERVICIOS MÉDICOS PRIVADOS DE ALTA CALIDAD DE FORMA ACCESIBLE, CLARA Y SIN RESTRICCIONES DENTRO DE LA RED DE HOSPITALES 50 (FIFTY) DOCTORS CON SEDE EN EL ESTADO DE PUEBLA”.</p>\r\n  <p>Estableciendo que, la comercialización de “LA TARJETA DE DESCUENTO” por parte de “EL PRESTADOR” en ningún momento constituirá la venta, promoción o por cualquier medio la contratación de una póliza de seguro, bajo el entendido de que “EL PRESTADOR” no es una aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas (CNSF); sino que comercializa “LA TARJETA DE DESCUENTO” en favor de terceros con la finalidad de otorgar descuentos a los precios respecto de los servicios médicos que presta en el territorio nacional.</p>\r\n\r\n  <h4>SEGUNDA.- PRECIO DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“LAS PARTES” establecen de común acuerdo que “LA TARJETA DE DESCUENTO” tendrá como costo mensual la cantidad señalada en el Apartado 8.- de la Carátula del presente contrato; cantidad que ya incluye IVA, y la cual deberá ser cubierta por “EL AFILIADO” en favor de “EL PRESTADOR” dentro de los primeros 5 (cinco) días de cada mes, sin necesidad de gestiones o avisos de cobro, ya sea mediante:</p>\r\n  <p>(i) Transferencia electrónica de fondos a la cuenta bancaria señalada en el Apartado 9.- de la Carátula del presente contrato y de la cual es titular “EL PRESTADOR”.</p>\r\n  <p>(ii) Cheque que se recibirá salvo buen cobro en el Domicilio de “EL PRESTADOR” señalado en el Apartado 3.- de la Carátula del presente contrato, y que en caso de no ser pagado por falta de fondos suficientes o por otras causas imputables a “EL AFILIADO”, éste último está de acuerdo en que deberá cubrir a “EL PRESTADOR” el 20% (veinte por ciento) del monto del cheque por concepto de indemnización por daños y perjuicios en términos del artículo 193 de la Ley General de Títulos y Operaciones de Crédito, independientemente de cualquier otro cargo que se pudiera generar.</p>\r\n  <p>(iii) Cargos mensuales automáticos recurrentes a la tarjeta de crédito de “EL AFILIADO” según los datos señalados en el Apartado 11.- de la Carátula del presente contrato, quien manifiesta bajo protesta de decir verdad que autoriza a “EL PRESTADOR” a realizar los cargos mensuales correspondientes por el costo mensual de “LA TARJETA DE DESCUENTO” en dicha tarjeta o en la tarjeta que por renovación, reposición, robo o extravío le haya asignado el banco emisor. La autorización estará vigente mientras “EL AFILIADO” no haya notificado a “EL PRESTADOR” por escrito y con acuse de recibo su deseo de cancelar su afiliación o no renovarla, o en su defecto, realizar su baja respectiva en el sitio web o aplicación de “EL PRESTADOR”.</p>\r\n  <p>Esta autorización no exime a “EL AFILIADO” del pago mensual por el uso de “LA TARJETA DE DESCUENTO” y demás obligaciones contractuales, por lo que, en caso de que el cobro no sea autorizado por el banco emisor o por cualquier razón no pueda realizarse, “EL AFILIADO” deberá notificar tal situación a “EL PRESTADOR” a la dirección de correo electrónico silvia@pasaporteatusalud.com, a efecto de solicitar una forma de pago diversa, quedando obligado a cubrir de inmediato el pago correspondiente.</p>\r\n  <p>(iv) Cualquier otro medio de pago aceptado por “EL PRESTADOR”, mismo que se dará a conocer a través de sus medios oficiales de comunicación.</p>\r\n  <p>“EL PRESTADOR” podrá variar unilateralmente el costo mensual de “LA TARJETA DE DESCUENTO”, previo aviso a “EL AFILIADO” con 30 (treinta) días de anticipación a través de sus medios oficiales de comunicación.</p>\r\n  <p>Para el caso de que “EL AFILIADO” adquiera y cubra el precio de “LA TARJETA DE DESCUENTO” y posteriormente deje de pagar una mensualidad, deberá cubrir a “EL PRESTADOR”, por concepto de cuota de reactivación, la cantidad señalada en el Apartado 10.- de la Carátula por cada mes que haya interrumpido y/o no haya cubierto el precio de “LA TARJETA DE DESCUENTO”, hasta la fecha en que pretenda volver a adquirirla.</p>\r\n\r\n  <h4>TERCERA.- VIGENCIA DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“LA TARJETA DE DESCUENTO” objeto del presente contrato tendrá una vigencia de 30 días contados a partir de que “EL AFILIADO” cubra a “EL PRESTADOR” el precio establecido anteriormente, en el entendido de que la vigencia del presente contrato y de “LA TARJETA DE DESCUENTO” se prorrogarán automáticamente sin necesidad de celebrar documento adicional entre “LAS PARTES” siempre y cuando “EL AFILIADO” cubra, de mes en mes o en la frecuencia contratada, el precio vigente de “LA TARJETA DE DESCUENTO”.</p>\r\n  <p>“EL AFILIADO” tendrá derecho a revocar su consentimiento dentro de los 5 (cinco) días siguientes a la entrega de “LA TARJETA DE DESCUENTO” o la firma del presente contrato, lo que ocurra último, sin responsabilidad alguna, siempre y cuando no haya obtenido beneficio alguno por el uso de “LA TARJETA DE DESCUENTO”.</p>\r\n\r\n  <h4>CUARTA.- BENEFICIOS DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“EL AFILIADO”, de forma exclusiva, personal e intransferible, gozará de forma gratuita de los servicios que se mencionan a continuación:</p>\r\n  <ul><li>Consultas gratuitas ilimitadas de medicina general (no de especialidad) en la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla, únicamente con los doctores afiliados al programa de Pasaporte a tu Salud.</li><li>Consultas de urgencia gratuitas en la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla.</li></ul>\r\n  <p>No así respecto de los servicios que, de manera enunciativa más no limitativa, se describen a continuación:</p>\r\n  <ul><li>Hospitalización dentro de la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla, sujeto a la disponibilidad de cada uno de ellos.</li><li>Consultas de especialidad ilimitadas a costo preferencial, con médicos especialistas pertenecientes al programa PATS.</li><li>Acceso a farmacia PATS con costos reducidos de medicamentos genéricos.</li><li>Imagenología y laboratorios ilimitados con costos preferenciales.</li><li>Acceso a cirugías con cuota de recuperación preferente, con o sin honorarios médicos incluidos según corresponda.</li></ul>\r\n  <p>Dichos servicios generarán, por evento, el pago de una cuota con cargo a “EL AFILIADO”, misma que resultará de aplicar los porcentajes de descuento que se desprenden del ANEXO 4 del presente contrato a los precios publicados al público en general o los precios preferenciales indicados.</p>\r\n  <p>Mientras “LA TARJETA DE DESCUENTO” se encuentre vigente, “EL AFILIADO” gozará de todos los beneficios que la misma le otorga; sin embargo, para el caso de que requiera cirugía o procedimiento quirúrgico en quirófano, deberá haber sufragado por adelantado la adquisición de “LA TARJETA DE DESCUENTO” por un periodo de 12 (doce) meses y encontrarse dentro de dicho periodo de vigencia.</p>\r\n\r\n  <h4>QUINTA.- OBLIGACIONES DE “EL PRESTADOR”.</h4>\r\n  <p>“EL PRESTADOR” se obliga a: (i) otorgar a “EL AFILIADO” el acceso ilimitado a “LA TARJETA DE DESCUENTO” durante la vigencia del contrato; (ii) mantener actualizada y operativa la Red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla; (iii) proporcionar a “EL AFILIADO”, de forma digital, “LA TARJETA DE DESCUENTO” dentro de los 5 (cinco) días hábiles siguientes al primer pago; e (iv) informar por escrito cualquier modificación a la red de hospitales o al tabulador de cuotas con al menos 10 (diez) días de anticipación.</p>\r\n\r\n  <h4>SEXTA.- OBLIGACIONES DE “EL AFILIADO”.</h4>\r\n  <p>“EL AFILIADO” se obliga a: (i) pagar puntualmente el precio de “LA TARJETA DE DESCUENTO”; (ii) utilizarla de forma exclusiva, personal e intransferible; (iii) cubrir directamente a los hospitales y con anterioridad a recibir el servicio médico las cuotas de recuperación según tabulador vigente; (iv) presentar identificación oficial y “LA TARJETA DE DESCUENTO” o código QR cada vez que haga uso de beneficios; y (v) notificar por escrito cualquier cambio de domicilio o datos de contacto en un plazo no mayor a 5 (cinco) días.</p>\r\n\r\n  <h4>SÉPTIMA.- ACCESO A LOS BENEFICIOS Y PROCEDIMIENTO.</h4>\r\n  <p>Para hacer uso de “LA TARJETA DE DESCUENTO”, “EL AFILIADO” deberá agendar sus citas directamente con los doctores pertenecientes a la Red de Hospitales 50 (FIFTY) Doctors, que en ese momento se encuentren adscritos al programa de beneficios, a través de la aplicación oficial, página de internet oficial de PATS o medios oficiales que indique “EL PRESTADOR”.</p>\r\n  <p>“EL AFILIADO” se obliga a pagar directamente al médico especialista perteneciente al programa el costo de la consulta de especialidad de que se trate, en términos de los porcentajes de descuento del ANEXO 4. En caso de no estar facultado para asistir por fuerza mayor, tendrá un plazo de 30 (treinta) días contados a partir de haber generado la cita para solicitar una nueva consulta médica.</p>\r\n\r\n  <h4>OCTAVA.- EXCLUSIONES Y LIMITACIONES.</h4>\r\n  <p>Los beneficios no incluirán: (i) trasplantes de órganos; (ii) tratamientos experimentales; (iii) tratamientos de oncología a excepción de algunas cirugías; (iv) medicamentos extra hospitalarios que no estén recogidos en el catálogo de Farmacia PATS; (v) atención médica con especialistas no adscritos o no publicados en los medios oficiales; y (vi) cualquier servicio no listado expresamente.</p>\r\n\r\n  <h4>NOVENA.- CAUSAS DE TERMINACIÓN.</h4>\r\n  <p>El contrato podrá terminarse por falta de pago, mutuo consentimiento por escrito o incumplimiento de cualquiera de las cláusulas por cualquiera de “LAS PARTES”. En caso de terminación, “EL AFILIADO” no tendrá derecho a exigir la devolución de cantidad alguna.</p>\r\n\r\n  <h4>DÉCIMA.- CANCELACIÓN VOLUNTARIA.</h4>\r\n  <p>“EL AFILIADO” podrá cancelar “LA TARJETA DE DESCUENTO” mediante aviso por escrito con 30 (treinta) días de anticipación. Dicha cancelación surtirá efectos a partir del siguiente periodo mensual y no generará reembolso de pagos ya realizados.</p>\r\n\r\n  <h4>DÉCIMA PRIMERA.- PROTECCIÓN DE DATOS PERSONALES.</h4>\r\n  <p>“LAS PARTES” acuerdan que el tratamiento de datos personales se sujetará a la Ley Federal de Protección de Datos Personales en Posesión de los Particulares. “EL AFILIADO” autoriza expresamente el uso de sus datos para la gestión de “LA TARJETA DE DESCUENTO”. El aviso de privacidad se integra al presente contrato como ANEXO 5.</p>\r\n\r\n  <h4>DÉCIMA SEGUNDA.- RESPONSABILIDAD.</h4>\r\n  <p>“EL AFILIADO” reconoce y acepta que “LA TARJETA DE DESCUENTO” es emitida y administrada directamente por CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE, quien es responsable de la operación de la red de descuentos, afiliación de prestadores médicos y prestación de cualquier servicio relacionado con “LA TARJETA DE DESCUENTO”.</p>\r\n  <p>En consecuencia, “EL PRESTADOR” no tendrá responsabilidad directa ni indirecta por la prestación, calidad, eficacia, resultado, daño, perjuicio, lesión, complicación, secuela, evento adverso o consecuencia derivada de servicios médicos recibidos, incluyendo aquellos ocasionados por negligencia, impericia o mala praxis de profesionales de la salud o prestadores afiliados. Cualquier relación derivada de la prestación de servicios médicos se establece directamente entre “EL AFILIADO” y los prestadores de servicios de salud correspondientes. Esta limitación subsistirá a la terminación del contrato.</p>\r\n\r\n  <h4>DÉCIMA TERCERA.- PREVENCIÓN DE LAVADO DE DINERO Y ORIGEN DE LOS RECURSOS.</h4>\r\n  <p>“LAS PARTES” declaran bajo protesta de decir verdad que los recursos económicos, bienes y derechos que utilicen para cumplir obligaciones derivadas de este contrato tienen y tendrán origen lícito. “EL AFILIADO” manifiesta que el pago inicial y pagos futuros provienen de fuentes lícitas y no de actividades tipificadas como delitos.</p>\r\n  <p>“LAS PARTES” reconocen que la prestación de servicios de comercio puede ser considerada actividad vulnerable, por lo que se obligan a proporcionar información y documentación requerida para integrar expediente de identificación e informar si tienen conocimiento de la existencia de beneficiario controlador.</p>\r\n\r\n  <h4>DÉCIMA CUARTA.- CONFORMACIÓN DEL EXPEDIENTE DE IDENTIFICACIÓN.</h4>\r\n  <p>“EL PRESTADOR” queda obligado a conformar y mantener un expediente de identificación de “EL AFILIADO”. Para tales efectos, “EL AFILIADO” se obliga a entregar los documentos aplicables: identificación oficial vigente o pasaporte, acta de nacimiento cuando aplique, comprobante de domicilio, constancia de situación fiscal cuando aplique, CURP, y declaración de dueño beneficiario.</p>\r\n  <p>Cuando exista persona responsable, la documentación de identificación y representación deberá integrarse al expediente; la CIF/constancia fiscal corresponde al tutor cuando aplique. “EL PRESTADOR” conservará dicho expediente por un periodo mínimo de 5 (cinco) años contados a partir de que termine la vigencia del contrato o termine por cualquiera de sus causales, garantizando la confidencialidad de los datos personales.</p>\r\n\r\n  <h4>DÉCIMA QUINTA.- CAUSAL ESPECÍFICA DE RESCISIÓN.</h4>\r\n  <p>Será motivo de rescisión inmediata sin necesidad de declaración judicial y sin responsabilidad para la parte afectada cuando cualquiera de “LAS PARTES” se niegue a proporcionar información requerida para cumplimiento de la Ley Federal para la Prevención e Identificación de Operaciones con Recursos de Procedencia Ilícita, proporcione información falsa o aparezca en listas de personas bloqueadas emitidas por autoridad competente.</p>\r\n\r\n  <h4>DÉCIMA SEXTA.- LEGISLACIÓN APLICABLE Y JURISDICCIÓN.</h4>\r\n  <p>“LAS PARTES” establecen que la Procuraduría Federal del Consumidor es competente en vía administrativa para resolver cualquier controversia sobre interpretación o cumplimiento. Sin perjuicio de lo anterior, se someten expresamente a la jurisdicción de los tribunales competentes del fuero común del Distrito Judicial de Puebla, Estado de Puebla, renunciando de manera expresa e irrevocable a cualquier otro fuero o jurisdicción que pudiera corresponderles.</p>\r\n\r\n  <p>Enteradas “LAS PARTES” del contenido y alcance del presente contrato, y entendidas de los derechos y obligaciones que contraen, firman el presente instrumento, incluyendo sus anexos, manifestando que no medió error, dolo, mala fe, violencia o lesión, ni vicio del consentimiento alguno, en la Ciudad de Puebla, Estado de Puebla, reconociendo que la fecha de firma es 14 de mayo de 2026.</p>\r\n\r\n  <div class=\"sign-grid\">\r\n    <div class=\"sign-box\"><div class=\"line\"></div><strong>“EL PRESTADOR”</strong><br>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE<br>Representada por PEDRO AZCÁRRAGA RAMOS</div>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>“EL AFILIADO”</strong><br>Juan Carlos Fuentes Moya</div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 1<br>Identificación oficial de “EL AFILIADO”</h2><p>Se integra al expediente la identificación oficial cargada por el usuario en el formulario. Para mexicanos, corresponde a identificación oficial/INE cuando aplique. Para extranjeros/no mexicanos, corresponde a identificación oficial o pasaporte vigente; al menos el frente es obligatorio y el reverso será opcional cuando el documento no lo tenga.</p><p><strong>Tipo:</strong> INE. <strong>Emitida por / país emisor:</strong> México. <strong>Número:</strong> FSDFSDF.</p></div>\r\n  <div class=\"annex\"><h2>ANEXO 2<br>COMPROBANTE DE DOMICILIO DE “EL AFILIADO”</h2><p>Se integra al expediente el comprobante de domicilio cargado por el usuario. Domicilio declarado: sdffsdf 118, Col. fsdfds, C.P. 45134, fsd, Jalisco, México.</p></div>\r\n  <div class=\"annex\"><h2>ANEXO 3<br>CONSTANCIA DE SITUACIÓN FISCAL DE “EL AFILIADO”</h2><p>Constancia de Situación Fiscal de “EL AFILIADO”, si aplica. En caso de pacientes representados, la constancia fiscal o CIF corresponde a la persona responsable cuando sea aplicable, no al menor. Para afiliados extranjeros/no mexicanos, no será obligatoria salvo que declaren RFC mexicano o residencia fiscal aplicable.</p></div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 4<br>CUOTAS DE RECUPERACIÓN Y/O PRECIOS BASE A CUBRIR A “EL PRESTADOR”</h2>\r\n    <p>En el presente anexo se establecen los porcentajes de descuento a obtener como titular de “LA TARJETA DE DESCUENTO”, por lo que la cantidad a cubrir por “EL AFILIADO” directamente al hospital de la cadena 50 (FIFTY) Doctors o al doctor que preste el servicio se obtendrá de aplicar el porcentaje de descuento correspondiente al precio publicado por los medios oficiales o al precio vigente en el establecimiento.</p>\r\n    <table><tr><th>Servicios / procedimientos</th><th>Descuentos</th></tr><tr><td>Consulta de urgencias</td><td>100%</td></tr><tr><td>Consulta de medicina general</td><td>100%</td></tr><tr><td>Habitación hospitalaria</td><td>90%</td></tr><tr><td>Uso de áreas de urgencias médicas</td><td>80%</td></tr><tr><td>Utilización de cubículos de terapia intensiva (UCIA-UCIN-UCIP)</td><td>75%</td></tr><tr><td>CEYE</td><td>75%</td></tr><tr><td>Uso quirófano</td><td>75%</td></tr><tr><td>Servicio de cuneros</td><td>75%</td></tr><tr><td>Materiales & medicamentos del cuadro básico, genéricos intercambiables</td><td>70%</td></tr><tr><td>Hemodinamia</td><td>70%</td></tr><tr><td>Imagenología</td><td>70%</td></tr><tr><td>Endoprótesis</td><td>70%</td></tr><tr><td>Osteosíntesis</td><td>70%</td></tr><tr><td>Prótesis</td><td>70%</td></tr><tr><td>Órtesis</td><td>70%</td></tr><tr><td>Laboratorio clínico</td><td>60%</td></tr></table>\r\n    <p class=\"small\">Los descuentos aplican con los proveedores suscritos al convenio de Pasaporte a tu Salud.</p>\r\n    <table><tr><th>Servicios / procedimientos</th><th>Precios base</th></tr><tr><td>Consulta de especialidades médicas</td><td>$390.00</td></tr><tr><td>Colposcopía</td><td>$400.00</td></tr><tr><td>Retiro de puntos de sutura</td><td>$80.00</td></tr><tr><td>Aplicación de medicamento intramuscular</td><td>$60.00</td></tr><tr><td>Retiro de DIU</td><td>$500.00</td></tr><tr><td>Colocación de DIU</td><td>$700.00</td></tr><tr><td>Extracción de cuerpo extraño (oído y nariz)</td><td>$300.00</td></tr><tr><td>Lavado ótico</td><td>$250.00</td></tr><tr><td>Curación de sitio quirúrgico</td><td>$250.00</td></tr><tr><td>Retiro de yeso</td><td>$250.00</td></tr><tr><td>Visita día de hospitalización</td><td>$650.00</td></tr><tr><td>Visita de urgencias</td><td>$750.00</td></tr><tr><td>Día de terapia intensiva</td><td>$850.00</td></tr></table>\r\n    <p class=\"small\">Todos los precios incluyen IVA. La factura de servicios hospitalarios será emitida con el desglose correspondiente y el ahorro otorgado por ser titular de “LA TARJETA DE DESCUENTO”.</p>\r\n    <p>Exclusiones y limitaciones: se aplicarán descuentos y precios especiales para el acompañante de “EL AFILIADO” en la misma habitación únicamente para la primera noche de hospitalización. Los precios y porcentajes de descuento darán derecho a la utilización de materiales y medicamentos del cuadro básico, genéricos intercambiables; cualquier otro tipo de medicación será cubierto directamente por “EL AFILIADO”. Los costos de procedimientos quirúrgicos incluyen honorarios médicos cuando así se indique. “EL AFILIADO” podrá atenderse con el médico tratante que elija, debiendo cubrir honorarios directamente a dicho médico, conservando el derecho a beneficios dentro de la red aplicable.</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Firma de aceptación de “EL AFILIADO”</strong><br>Juan Carlos Fuentes Moya</div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 5<br>AVISO DE PRIVACIDAD</h2>\r\n    <p>En cumplimiento de las disposiciones establecidas en la Ley Federal de Protección de Datos Personales en Posesión de Particulares, su Reglamento y los lineamientos aplicables, “CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE” (en lo sucesivo “EL PRESTADOR”), con domicilio en CALLE PASEO SINFONÍA NÚMERO EXTERIOR 1, LOCAL 2-14, LOMAS DE ANGELÓPOLIS II, SAN ANDRÉS CHOLULA, ESTADO DE PUEBLA, CÓDIGO POSTAL 72830, da a conocer el Aviso de Privacidad al tenor del cual manejará por medio de su representación y/o empleados los datos personales y/o documentación proporcionada por el afiliado o usuario de “LA TARJETA DE DESCUENTO”.</p>\r\n    <p>Se tendrá por aceptado expresamente el presente Aviso de Privacidad una vez proporcionados los datos personales y firmada digitalmente la aceptación del contrato, motivo por el cual “EL PRESTADOR” estará facultado para manejar la información conforme a la legislación aplicable.</p>\r\n    <h4>Modificación del aviso de privacidad</h4><p>Este aviso podrá ser modificado o adecuado a las necesidades de “EL PRESTADOR”. Las modificaciones o actualizaciones serán incorporadas al presente aviso y estarán disponibles en la página de internet, domicilio de “EL PRESTADOR” o serán enviadas al último correo electrónico proporcionado.</p>\r\n    <h4>Finalidad de la información</h4><p>La información será utilizada para: elaborar y mantener actualizada la base de usuarios; identificar afiliados; proporcionar la tarjeta digital; otorgar acceso al programa de beneficios; informar modificaciones a la red o tabulador; realizar análisis estadísticos internos y brindar un óptimo servicio médico.</p>\r\n    <h4>Tipo de datos necesarios</h4><p>Se solicitarán datos de identificación, contacto, legales, contractuales y fiscales cuando aplique, incluyendo nombre completo, lugar y fecha de nacimiento, firma, identificación oficial, nacionalidad, CURP y RFC cuando sean aplicables, domicilio, teléfono y correo electrónico.</p>\r\n    <h4>Transferencias de la información</h4><p>El usuario autoriza proporcionar información sin consentimiento adicional en los casos previstos por ley, resolución de autoridad competente, tratados aplicables, salvaguarda de interés público, procuración o administración de justicia, reconocimiento o defensa de derechos en procesos judiciales, y a socios comerciales, técnicos o estratégicos que asuman obligaciones de confidencialidad y seguridad equivalentes.</p>\r\n    <h4>Limitación del uso o divulgación de datos y derechos ARCO</h4><p>El usuario podrá limitar el uso o divulgación de sus datos personales y ejercer derechos de acceso, rectificación, cancelación u oposición mediante solicitud escrita dirigida a “EL PRESTADOR” en su domicilio o al correo silvia@pasaporteatusalud.com, acompañando documento que acredite su identidad.</p>\r\n    <h4>Revocación de consentimiento</h4><p>El usuario podrá revocar su consentimiento siguiendo el mismo procedimiento, considerando que para ciertos fines la revocación puede implicar la cancelación de “LA TARJETA DE DESCUENTO” y la imposibilidad de acceder al programa.</p>\r\n    <p><strong>Nombre:</strong> Juan Carlos Fuentes Moya<br><strong>Fecha:</strong> 14 de mayo de 2026</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Firma</strong></div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 6<br>DECLARACIÓN DE DUEÑO BENEFICIARIO</h2>\r\n    <p>DE CONFORMIDAD CON LO DISPUESTO EN LOS ARTÍCULOS 18 FRACCIÓN I Y III DE LA LEY FEDERAL PARA PREVENCIÓN E IDENTIFICACIÓN DE OPERACIONES CON RECURSOS DE PROCEDENCIA ILÍCITA, EL ARTÍCULO 15 DE SU REGLAMENTO Y EL ARTÍCULO 13 DE LAS REGLAS DE CARÁCTER GENERAL, MANIFIESTO BAJO PROTESTA DE DECIR VERDAD:</p>\r\n    <h4>Datos de identificación del cliente</h4>\r\n    <table><tr><th>Campo</th><th>Respuesta</th></tr><tr><td>Apellido paterno, materno y nombre(s)</td><td>Juan Carlos Fuentes Moya</td></tr><tr><td>Fecha de nacimiento</td><td>1981-08-22</td></tr><tr><td>País de nacimiento</td><td>México</td></tr><tr><td>Nacionalidad</td><td>mexicana</td></tr><tr><td>Actividad, ocupación o profesión</td><td>fsdfdsf</td></tr><tr><td>Estado civil</td><td>SOLTERO(A)</td></tr><tr><td>Domicilio particular</td><td>sdffsdf 118, Col. fsdfds, C.P. 45134, fsd, Jalisco, México</td></tr><tr><td>Teléfonos</td><td>5650900475</td></tr><tr><td>Correo electrónico</td><td>roel.fuentes@gmail.com</td></tr><tr><td>CURP</td><td>SSSS</td></tr><tr><td>RFC</td><td>FDSFDSFDS</td></tr><tr><td>Tipo de identificación</td><td>INE</td></tr><tr><td>Emitida por / país emisor</td><td>México</td></tr><tr><td>Número de identificación</td><td>FSDFSDF</td></tr></table>\r\n    <h4>Datos de identificación de la operación</h4>\r\n    <table><tr><th>Campo</th><th>Respuesta</th></tr><tr><td>Tipo de operación</td><td>Adquisición de tarjeta de descuento PATS</td></tr><tr><td>Monto de operación</td><td>$800.00 M.N.</td></tr><tr><td>Fecha de operación</td><td>14 de mayo de 2026</td></tr><tr><td>Forma de pago</td><td>Pasarela / medio autorizado por “EL PRESTADOR”</td></tr><tr><td>Moneda</td><td>MXN</td></tr></table>\r\n    <h4>Información de la existencia del dueño beneficiario o beneficiario controlador</h4>\r\n    <p>Declaro que soy el beneficiario directo de la operación y no existe ningún otro dueño beneficiario o beneficiario controlador: <strong>SI</strong>.</p>\r\n    <h4>Aviso de privacidad</h4><p>Los datos personales serán protegidos y tratados conforme al Aviso de Privacidad contenido en el cuerpo del presente contrato y la legislación aplicable.</p>\r\n    <p>H. Puebla de Zaragoza al 14 del mes de mayo del año 2026.</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Nombre y firma</strong><br>Juan Carlos Fuentes Moya</div>\r\n  </div>\r\n\r\n  \r\n  </div>\r\n', 'data:image/png;base64,', 'Juan Carlos Fuentes Moya', '294d40511a8802b68e9166b4b74161326339757df742926c2ac4c091b930b313', '2026-05-14 19:09:33', '189.190.218.123', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/148.0.0.0 Safari/537.36', '', 'firmado', '2026-05-14 19:09:33', '2026-05-14 19:09:33');
INSERT INTO `pats_contratos_firmados` (`id_contrato_firmado`, `id_orden`, `id_pasaporte`, `id_distribuidor`, `id_franquicia`, `token_publico`, `contrato_clave`, `contrato_version`, `html_contrato_renderizado`, `firma_afiliado_base64`, `nombre_firmante`, `hash_contrato`, `fecha_firma`, `ip_firma`, `user_agent_firma`, `pdf_path`, `estatus`, `created_at`, `updated_at`) VALUES
(17, 1, 1, 0, 0, '', 'contrato_pats_base', '1.0', '<style>\r\n  .pats-contract{font-family:Arial,Helvetica,sans-serif;color:#172033;font-size:12px;line-height:1.52;background:#fff;padding:4px}\r\n  .pats-contract h1,.pats-contract h2,.pats-contract h3,.pats-contract h4{text-align:center;margin:12px 0 8px;color:#0d1b3e}\r\n  .pats-contract h1{font-size:16px;text-transform:uppercase;letter-spacing:.05em}\r\n  .pats-contract h2{font-size:15px;text-transform:uppercase;letter-spacing:.04em}\r\n  .pats-contract h3{font-size:13px;text-transform:uppercase;letter-spacing:.08em}\r\n  .pats-contract h4{font-size:12px;text-align:left;text-transform:uppercase;margin-top:12px}\r\n  .pats-contract p{margin:6px 0;text-align:justify}\r\n  .pats-contract ul{margin:6px 0 8px 18px;padding:0}.pats-contract li{margin:4px 0;text-align:justify}\r\n  .pats-contract table{width:100%;border-collapse:collapse;margin:8px 0 12px}.pats-contract th,.pats-contract td{border:1px solid #cbd5e1;padding:6px;vertical-align:top}.pats-contract th{background:#eef4ff;color:#0d1b3e;text-align:left}\r\n  .pats-contract .center{text-align:center}.pats-contract .muted{color:#64748b}.pats-contract .small{font-size:10px}.pats-contract .badge{display:inline-block;padding:3px 8px;border-radius:999px;background:#eef4ff;color:#1d4ed8;font-weight:700;margin:2px 4px 2px 0}\r\n  .pats-contract .sign-grid{display:grid;grid-template-columns:1fr 1fr;gap:22px;margin-top:28px}.pats-contract .sign-box{text-align:center;min-height:95px}.pats-contract .line{border-top:1px solid #0f172a;margin:48px 8px 6px}.pats-contract .signature-img{max-width:220px;max-height:82px;display:block;margin:0 auto 4px}\r\n  .pats-contract .annex{page-break-before:auto;border-top:2px solid #0d1b3e;margin-top:18px;padding-top:12px}.pats-contract .page-break{page-break-before:always;border-top:1px dashed #cbd5e1;margin-top:18px;padding-top:12px}\r\n</style>\r\n<div class=\"pats-contract\">\r\n  <h1>Carátula del contrato de adquisición de tarjeta de descuento</h1>\r\n  <p>CARÁTULA DEL CONTRATO DE ADQUISICIÓN DE TARJETA DE DESCUENTO (EN LO SUCESIVO “LA CARÁTULA”), QUE CELEBRAN POR UNA PARTE LA SOCIEDAD SEÑALADA EN EL APARTADO 1.- DE LA CARÁTULA, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL PRESTADOR”, REPRESENTADA EN ESTE ACTO POR LA PERSONA FÍSICA QUE SE INDICA EN EL APARTADO 2.- DE LA CARÁTULA; Y POR LA OTRA PARTE, LA PERSONA FÍSICA SEÑALADA EN EL APARTADO 5.- DE LA CARÁTULA, POR SU PROPIO DERECHO, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL AFILIADO”; Y CUANDO LOS ANTES NOMBRADOS ACTÚEN DE MANERA CONJUNTA, SE LES DENOMINARÁ COMO “LAS PARTES”; QUIENES SE SUJETAN AL TENOR DE LA CARÁTULA, DECLARACIONES Y CLÁUSULAS SIGUIENTES:</p>\r\n    \r\n  <h2>C A R Á T U L A</h2>\r\n  <table>\r\n    <tr><th style=\"width:8%\">Apartado</th><th style=\"width:42%\">Definición</th><th>Respuesta</th></tr>\r\n    <tr><td>1.-</td><td>Nombre de “EL PRESTADOR”</td><td>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE</td></tr>\r\n    <tr><td>2.-</td><td>Nombre del Representante Legal de “EL PRESTADOR”</td><td>PEDRO AZCÁRRAGA RAMOS</td></tr>\r\n    <tr><td>3.-</td><td>Domicilio de “EL PRESTADOR”</td><td>CALLE PASEO SINFONÍA NÚMERO EXTERIOR 1, LOCAL 2-14, LOMAS DE ANGELÓPOLIS II, SAN ANDRÉS CHOLULA, ESTADO DE PUEBLA, CÓDIGO POSTAL 72830</td></tr>\r\n    <tr><td>4.-</td><td>Clave del Registro Federal de Contribuyentes de “EL PRESTADOR”</td><td>COH2202144H5</td></tr>\r\n    <tr><td>5.-</td><td>Nombre de “EL AFILIADO”</td><td>PABLO AJA FRESNEDO</td></tr>\r\n    <tr><td>6.-</td><td>Domicilio de “EL AFILIADO”</td><td>PASEO SAN CARLOS 3047, Col. VALLE REAL, C.P. 45019, ZAPOPAN, Jalisco, México</td></tr>\r\n    <tr><td>7.-</td><td>Clave del Registro Federal de Contribuyentes de “EL AFILIADO”</td><td>AAFP8601287X3</td></tr>\r\n    <tr><td>8.-</td><td>Costo mensual de “LA TARJETA DE DESCUENTO”</td><td>$800.00 M.N.</td></tr>\r\n    <tr><td>9.-</td><td>Cuenta bancaria de “EL PRESTADOR” para pagos</td><td>Cuenta: 01600866709<br>CLABE: 042650016008667096<br>Institución Bancaria: Banca Mifel, S.A., Institución de Banca Múltiple, Grupo Financiero Mifel</td></tr>\r\n    <tr><td>10.-</td><td>Cuota de Reactivación de “LA TARJETA DE DESCUENTO”</td><td>$100.00 M.N. por cada mes que se haya interrumpido el pago.</td></tr>\r\n    <tr><td>11.-</td><td>Datos de la Tarjeta de Crédito de “EL AFILIADO”</td><td>Número de tarjeta: pendiente de confirmar por pasarela/token de pago.<br>Institución bancaria: pendiente de confirmar por pasarela. <br><span class=\"small\">No se almacena número completo de tarjeta en este formulario.</span></td></tr>\r\n    <tr><td>12.-</td><td>Anexos</td><td>ANEXO 1. Identificación oficial de “EL AFILIADO”<br>ANEXO 2. Comprobante de domicilio de “EL AFILIADO”<br>ANEXO 3. Constancia de Situación Fiscal de “EL AFILIADO”, si aplica<br>ANEXO 4. Cuotas de recuperación y/o precios base a cubrir a “EL PRESTADOR”<br>ANEXO 5. Aviso de privacidad<br>ANEXO 6. Declaración de dueño beneficiario</td></tr>\r\n    <tr><td>13.-</td><td>Fecha de Firma del Contrato</td><td>14 de mayo de 2026</td></tr>\r\n  </table>\r\n\r\n  <div class=\"sign-grid\">\r\n    <div class=\"sign-box\"><div class=\"line\"></div><strong>“EL PRESTADOR”</strong><br>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE<br>Representada por PEDRO AZCÁRRAGA RAMOS</div>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>“EL AFILIADO”</strong><br>PABLO AJA FRESNEDO<br><span class=\"small\">La persona física señalada en el Apartado 5.- de la Carátula</span></div>\r\n  </div>\r\n\r\n  <div class=\"page-break\"></div>\r\n  <h1>Contrato de adquisición de tarjeta de descuento</h1>\r\n  <p>CONTRATO DE ADQUISICIÓN DE TARJETA DE DESCUENTO, QUE CELEBRAN POR UNA PARTE LA SOCIEDAD SEÑALADA EN EL APARTADO 1.- DE LA CARÁTULA, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL PRESTADOR”, REPRESENTADA EN ESTE ACTO POR LA PERSONA FÍSICA QUE SE INDICA EN EL APARTADO 2.- DE LA CARÁTULA; Y POR LA OTRA PARTE, LA PERSONA FÍSICA SEÑALADA EN EL APARTADO 5.- DE LA CARÁTULA, POR SU PROPIO DERECHO, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL AFILIADO”; Y CUANDO LOS ANTES NOMBRADOS ACTÚEN DE MANERA CONJUNTA, SE LES DENOMINARÁ COMO “LAS PARTES”; QUIENES SE SUJETAN AL TENOR DE LAS DECLARACIONES Y CLÁUSULAS SIGUIENTES:</p>\r\n\r\n  <h2>D E C L A R A C I O N E S</h2>\r\n  <h4>I.- Declara “EL PRESTADOR” por conducto de su representación:</h4>\r\n  <p>A. Que, su representada es una sociedad mercantil constituida conforme a las leyes de los Estados Unidos Mexicanos, según consta en la escritura pública número 39,861, del volumen 830 de fecha catorce de febrero de dos mil veintidós, otorgada ante la fe del Licenciado Ernesto Joaquín Briones Amador, Notario Público Titular de la Notaría Pública número 46 de las del Distrito Judicial de Puebla, Estado de Puebla, cuyo primer testimonio se encuentra inscrito ante las oficinas del Registro Público de Comercio del Distrito Judicial de Puebla, Estado de Puebla, bajo el Folio Mercantil Electrónico: N-2022022991, por virtud del cual se llevó a cabo la Constitución de la persona moral denominada CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE.</p>\r\n  <p>B. Que, la persona física que la representa en este acto, señalada en el Apartado 2.- de la Carátula, cuenta con todas y cada una de las facultades necesarias para la celebración del presente contrato, las cuales se desprenden del instrumento descrito en el punto declarativo inmediato anterior, mismas que manifiesta bajo protesta de decir verdad que no le han sido suspendidas, revocadas o limitadas en forma alguna.</p>\r\n  <p>C. Que, su representada tiene como domicilio fiscal el señalado en el Apartado 3.- de la Carátula del presente contrato, mismo que designa como domicilio convencional para cualquier cuestión relacionada con la celebración del presente contrato.</p>\r\n  <p>D. Que, su representada se encuentra inscrita en el Registro Federal de Contribuyentes bajo la clave señalada en el Apartado 4.- de la Carátula.</p>\r\n  <p>E. Que, ha desarrollado y es su deseo comparecer a la celebración del presente instrumento con la finalidad de enajenar en favor de “EL AFILIADO”, una Tarjeta de Descuento que da acceso a “UN PROGRAMA DE BENEFICIOS QUE OTORGA DESCUENTOS A LOS COSTOS Y PERMITE RECIBIR SERVICIOS MÉDICOS PRIVADOS DE ALTA CALIDAD DE FORMA ACCESIBLE, CLARA Y SIN RESTRICCIONES DENTRO DE LA RED DE HOSPITALES 50 (FIFTY) DOCTORS CON SEDE EN EL ESTADO DE PUEBLA”, en lo sucesivo “LA TARJETA DE DESCUENTO”, en los términos y condiciones que se establecerán más adelante.</p>\r\n  <p>F. Que, su representada no es una Aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas sino una empresa dedicada, entre otros, a la operación y administración de establecimientos destinados a la atención y asistencia de enfermos, por lo que la enajenación de “LA TARJETA DE DESCUENTO” únicamente constituye un acto de comercio que brindará a “EL AFILIADO” acceso a un programa de beneficios como ha quedado descrito anteriormente.</p>\r\n\r\n  <h4>II.- Declara “EL AFILIADO”, por su propio derecho:</h4>\r\n      <p>A. Que, su nombre se señala en el Apartado 5.- de la Carátula, es una persona física de nacionalidad mexicana, en pleno ejercicio de sus derechos, legal y jurídicamente capaz para celebrar el presente Contrato, quien se identifica con credencial para votar vigente expedida por el Instituto Nacional Electoral, tipo INE, número IDMEX2362711703, que en copia simple o archivo digital se agrega al cuerpo del presente contrato como ANEXO 1.</p>\r\n    <p>B. Que, tiene como domicilio particular el señalado en el Apartado 6.- de la Carátula, mismo que designa como domicilio convencional para cualquier cuestión relacionada con la celebración del presente contrato, tal y como lo acredita con el comprobante de domicilio que en copia simple o archivo digital se agrega al cuerpo del presente contrato como ANEXO 2.</p>\r\n  <p>C. Que, su CURP es AAFP860128HPLJRB03 y su RFC/identificación fiscal es AAFP8601287X3; asimismo manifiesta que cuenta con capacidad económica para obligarse en términos del presente contrato y que los recursos con los que cubrirá sus obligaciones provendrán de fuentes lícitas. En caso de nacionalidad extranjera/no mexicana, se tendrán por no aplicables CURP, INE y constancia fiscal mexicana salvo manifestación expresa de residencia fiscal o RFC mexicano.</p>\r\n  <p>D. Que, es su deseo comparecer a la celebración del presente instrumento con la finalidad de adquirir “LA TARJETA DE DESCUENTO” de acuerdo con los términos y condiciones que se establecen a continuación.</p>\r\n  <p>E. Que, previo a la celebración del presente contrato fue informado y manifiesta expresamente que reconoce que “EL PRESTADOR” no es una Aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas y que las actividades comerciales objeto del presente contrato no consisten en la contratación de un seguro, de la índole que fuere, sino que únicamente implica la adquisición de una tarjeta de descuento que da acceso a un programa de beneficios que otorga descuentos a los costos y permite recibir servicios médicos privados de alta calidad de forma accesible, clara y sin restricciones dentro de la red de hospitales 50 (FIFTY) Doctors con sede en el Estado de Puebla.</p>\r\n  <p>F. Que, reconoce que “EL PRESTADOR” se dedica a la operación de centros hospitalarios y que la emisión de “LA TARJETA DE DESCUENTO” únicamente corresponde a la intención de este último de crear un programa de descuentos para el acceso a los servicios prestados por la Red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla.</p>\r\n\r\n  <h4>III.- Declaran conjuntamente “LAS PARTES”:</h4>\r\n  <p>1. Que, se reconocen recíprocamente la personalidad con la que comparecen a la celebración del presente acuerdo de voluntades.</p>\r\n  <p>2. Que, el presente contrato es el instrumento que las vincula en sus derechos y obligaciones.</p>\r\n  <p>3. Que, es su deseo celebrar el presente contrato y han negociado libremente los términos y condiciones del mismo con pleno conocimiento de sus alcances e implicaciones jurídicas, por lo que en su celebración no existe dolo, error, mala fe, lesión o cualquier otro vicio del consentimiento que pudiese afectarlo de inexistencia o nulidad.</p>\r\n\r\n  <h2>C L Á U S U L A S</h2>\r\n  <h4>PRIMERA.- OBJETO.</h4>\r\n  <p>El objeto del presente Contrato es que “EL AFILIADO” adquiera de “EL PRESTADOR”, a título oneroso y temporal, el derecho de uso ilimitado y sin restricción alguna de “LA TARJETA DE DESCUENTO” emitida por CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE, la cual consiste en que “EL AFILIADO” aproveche y acceda a “UN PROGRAMA DE BENEFICIOS QUE OTORGA DESCUENTOS A LOS COSTOS Y PERMITE RECIBIR SERVICIOS MÉDICOS PRIVADOS DE ALTA CALIDAD DE FORMA ACCESIBLE, CLARA Y SIN RESTRICCIONES DENTRO DE LA RED DE HOSPITALES 50 (FIFTY) DOCTORS CON SEDE EN EL ESTADO DE PUEBLA”.</p>\r\n  <p>Estableciendo que, la comercialización de “LA TARJETA DE DESCUENTO” por parte de “EL PRESTADOR” en ningún momento constituirá la venta, promoción o por cualquier medio la contratación de una póliza de seguro, bajo el entendido de que “EL PRESTADOR” no es una aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas (CNSF); sino que comercializa “LA TARJETA DE DESCUENTO” en favor de terceros con la finalidad de otorgar descuentos a los precios respecto de los servicios médicos que presta en el territorio nacional.</p>\r\n\r\n  <h4>SEGUNDA.- PRECIO DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“LAS PARTES” establecen de común acuerdo que “LA TARJETA DE DESCUENTO” tendrá como costo mensual la cantidad señalada en el Apartado 8.- de la Carátula del presente contrato; cantidad que ya incluye IVA, y la cual deberá ser cubierta por “EL AFILIADO” en favor de “EL PRESTADOR” dentro de los primeros 5 (cinco) días de cada mes, sin necesidad de gestiones o avisos de cobro, ya sea mediante:</p>\r\n  <p>(i) Transferencia electrónica de fondos a la cuenta bancaria señalada en el Apartado 9.- de la Carátula del presente contrato y de la cual es titular “EL PRESTADOR”.</p>\r\n  <p>(ii) Cheque que se recibirá salvo buen cobro en el Domicilio de “EL PRESTADOR” señalado en el Apartado 3.- de la Carátula del presente contrato, y que en caso de no ser pagado por falta de fondos suficientes o por otras causas imputables a “EL AFILIADO”, éste último está de acuerdo en que deberá cubrir a “EL PRESTADOR” el 20% (veinte por ciento) del monto del cheque por concepto de indemnización por daños y perjuicios en términos del artículo 193 de la Ley General de Títulos y Operaciones de Crédito, independientemente de cualquier otro cargo que se pudiera generar.</p>\r\n  <p>(iii) Cargos mensuales automáticos recurrentes a la tarjeta de crédito de “EL AFILIADO” según los datos señalados en el Apartado 11.- de la Carátula del presente contrato, quien manifiesta bajo protesta de decir verdad que autoriza a “EL PRESTADOR” a realizar los cargos mensuales correspondientes por el costo mensual de “LA TARJETA DE DESCUENTO” en dicha tarjeta o en la tarjeta que por renovación, reposición, robo o extravío le haya asignado el banco emisor. La autorización estará vigente mientras “EL AFILIADO” no haya notificado a “EL PRESTADOR” por escrito y con acuse de recibo su deseo de cancelar su afiliación o no renovarla, o en su defecto, realizar su baja respectiva en el sitio web o aplicación de “EL PRESTADOR”.</p>\r\n  <p>Esta autorización no exime a “EL AFILIADO” del pago mensual por el uso de “LA TARJETA DE DESCUENTO” y demás obligaciones contractuales, por lo que, en caso de que el cobro no sea autorizado por el banco emisor o por cualquier razón no pueda realizarse, “EL AFILIADO” deberá notificar tal situación a “EL PRESTADOR” a la dirección de correo electrónico silvia@pasaporteatusalud.com, a efecto de solicitar una forma de pago diversa, quedando obligado a cubrir de inmediato el pago correspondiente.</p>\r\n  <p>(iv) Cualquier otro medio de pago aceptado por “EL PRESTADOR”, mismo que se dará a conocer a través de sus medios oficiales de comunicación.</p>\r\n  <p>“EL PRESTADOR” podrá variar unilateralmente el costo mensual de “LA TARJETA DE DESCUENTO”, previo aviso a “EL AFILIADO” con 30 (treinta) días de anticipación a través de sus medios oficiales de comunicación.</p>\r\n  <p>Para el caso de que “EL AFILIADO” adquiera y cubra el precio de “LA TARJETA DE DESCUENTO” y posteriormente deje de pagar una mensualidad, deberá cubrir a “EL PRESTADOR”, por concepto de cuota de reactivación, la cantidad señalada en el Apartado 10.- de la Carátula por cada mes que haya interrumpido y/o no haya cubierto el precio de “LA TARJETA DE DESCUENTO”, hasta la fecha en que pretenda volver a adquirirla.</p>\r\n\r\n  <h4>TERCERA.- VIGENCIA DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“LA TARJETA DE DESCUENTO” objeto del presente contrato tendrá una vigencia de 30 días contados a partir de que “EL AFILIADO” cubra a “EL PRESTADOR” el precio establecido anteriormente, en el entendido de que la vigencia del presente contrato y de “LA TARJETA DE DESCUENTO” se prorrogarán automáticamente sin necesidad de celebrar documento adicional entre “LAS PARTES” siempre y cuando “EL AFILIADO” cubra, de mes en mes o en la frecuencia contratada, el precio vigente de “LA TARJETA DE DESCUENTO”.</p>\r\n  <p>“EL AFILIADO” tendrá derecho a revocar su consentimiento dentro de los 5 (cinco) días siguientes a la entrega de “LA TARJETA DE DESCUENTO” o la firma del presente contrato, lo que ocurra último, sin responsabilidad alguna, siempre y cuando no haya obtenido beneficio alguno por el uso de “LA TARJETA DE DESCUENTO”.</p>\r\n\r\n  <h4>CUARTA.- BENEFICIOS DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“EL AFILIADO”, de forma exclusiva, personal e intransferible, gozará de forma gratuita de los servicios que se mencionan a continuación:</p>\r\n  <ul><li>Consultas gratuitas ilimitadas de medicina general (no de especialidad) en la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla, únicamente con los doctores afiliados al programa de Pasaporte a tu Salud.</li><li>Consultas de urgencia gratuitas en la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla.</li></ul>\r\n  <p>No así respecto de los servicios que, de manera enunciativa más no limitativa, se describen a continuación:</p>\r\n  <ul><li>Hospitalización dentro de la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla, sujeto a la disponibilidad de cada uno de ellos.</li><li>Consultas de especialidad ilimitadas a costo preferencial, con médicos especialistas pertenecientes al programa PATS.</li><li>Acceso a farmacia PATS con costos reducidos de medicamentos genéricos.</li><li>Imagenología y laboratorios ilimitados con costos preferenciales.</li><li>Acceso a cirugías con cuota de recuperación preferente, con o sin honorarios médicos incluidos según corresponda.</li></ul>\r\n  <p>Dichos servicios generarán, por evento, el pago de una cuota con cargo a “EL AFILIADO”, misma que resultará de aplicar los porcentajes de descuento que se desprenden del ANEXO 4 del presente contrato a los precios publicados al público en general o los precios preferenciales indicados.</p>\r\n  <p>Mientras “LA TARJETA DE DESCUENTO” se encuentre vigente, “EL AFILIADO” gozará de todos los beneficios que la misma le otorga; sin embargo, para el caso de que requiera cirugía o procedimiento quirúrgico en quirófano, deberá haber sufragado por adelantado la adquisición de “LA TARJETA DE DESCUENTO” por un periodo de 12 (doce) meses y encontrarse dentro de dicho periodo de vigencia.</p>\r\n\r\n  <h4>QUINTA.- OBLIGACIONES DE “EL PRESTADOR”.</h4>\r\n  <p>“EL PRESTADOR” se obliga a: (i) otorgar a “EL AFILIADO” el acceso ilimitado a “LA TARJETA DE DESCUENTO” durante la vigencia del contrato; (ii) mantener actualizada y operativa la Red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla; (iii) proporcionar a “EL AFILIADO”, de forma digital, “LA TARJETA DE DESCUENTO” dentro de los 5 (cinco) días hábiles siguientes al primer pago; e (iv) informar por escrito cualquier modificación a la red de hospitales o al tabulador de cuotas con al menos 10 (diez) días de anticipación.</p>\r\n\r\n  <h4>SEXTA.- OBLIGACIONES DE “EL AFILIADO”.</h4>\r\n  <p>“EL AFILIADO” se obliga a: (i) pagar puntualmente el precio de “LA TARJETA DE DESCUENTO”; (ii) utilizarla de forma exclusiva, personal e intransferible; (iii) cubrir directamente a los hospitales y con anterioridad a recibir el servicio médico las cuotas de recuperación según tabulador vigente; (iv) presentar identificación oficial y “LA TARJETA DE DESCUENTO” o código QR cada vez que haga uso de beneficios; y (v) notificar por escrito cualquier cambio de domicilio o datos de contacto en un plazo no mayor a 5 (cinco) días.</p>\r\n\r\n  <h4>SÉPTIMA.- ACCESO A LOS BENEFICIOS Y PROCEDIMIENTO.</h4>\r\n  <p>Para hacer uso de “LA TARJETA DE DESCUENTO”, “EL AFILIADO” deberá agendar sus citas directamente con los doctores pertenecientes a la Red de Hospitales 50 (FIFTY) Doctors, que en ese momento se encuentren adscritos al programa de beneficios, a través de la aplicación oficial, página de internet oficial de PATS o medios oficiales que indique “EL PRESTADOR”.</p>\r\n  <p>“EL AFILIADO” se obliga a pagar directamente al médico especialista perteneciente al programa el costo de la consulta de especialidad de que se trate, en términos de los porcentajes de descuento del ANEXO 4. En caso de no estar facultado para asistir por fuerza mayor, tendrá un plazo de 30 (treinta) días contados a partir de haber generado la cita para solicitar una nueva consulta médica.</p>\r\n\r\n  <h4>OCTAVA.- EXCLUSIONES Y LIMITACIONES.</h4>\r\n  <p>Los beneficios no incluirán: (i) trasplantes de órganos; (ii) tratamientos experimentales; (iii) tratamientos de oncología a excepción de algunas cirugías; (iv) medicamentos extra hospitalarios que no estén recogidos en el catálogo de Farmacia PATS; (v) atención médica con especialistas no adscritos o no publicados en los medios oficiales; y (vi) cualquier servicio no listado expresamente.</p>\r\n\r\n  <h4>NOVENA.- CAUSAS DE TERMINACIÓN.</h4>\r\n  <p>El contrato podrá terminarse por falta de pago, mutuo consentimiento por escrito o incumplimiento de cualquiera de las cláusulas por cualquiera de “LAS PARTES”. En caso de terminación, “EL AFILIADO” no tendrá derecho a exigir la devolución de cantidad alguna.</p>\r\n\r\n  <h4>DÉCIMA.- CANCELACIÓN VOLUNTARIA.</h4>\r\n  <p>“EL AFILIADO” podrá cancelar “LA TARJETA DE DESCUENTO” mediante aviso por escrito con 30 (treinta) días de anticipación. Dicha cancelación surtirá efectos a partir del siguiente periodo mensual y no generará reembolso de pagos ya realizados.</p>\r\n\r\n  <h4>DÉCIMA PRIMERA.- PROTECCIÓN DE DATOS PERSONALES.</h4>\r\n  <p>“LAS PARTES” acuerdan que el tratamiento de datos personales se sujetará a la Ley Federal de Protección de Datos Personales en Posesión de los Particulares. “EL AFILIADO” autoriza expresamente el uso de sus datos para la gestión de “LA TARJETA DE DESCUENTO”. El aviso de privacidad se integra al presente contrato como ANEXO 5.</p>\r\n\r\n  <h4>DÉCIMA SEGUNDA.- RESPONSABILIDAD.</h4>\r\n  <p>“EL AFILIADO” reconoce y acepta que “LA TARJETA DE DESCUENTO” es emitida y administrada directamente por CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE, quien es responsable de la operación de la red de descuentos, afiliación de prestadores médicos y prestación de cualquier servicio relacionado con “LA TARJETA DE DESCUENTO”.</p>\r\n  <p>En consecuencia, “EL PRESTADOR” no tendrá responsabilidad directa ni indirecta por la prestación, calidad, eficacia, resultado, daño, perjuicio, lesión, complicación, secuela, evento adverso o consecuencia derivada de servicios médicos recibidos, incluyendo aquellos ocasionados por negligencia, impericia o mala praxis de profesionales de la salud o prestadores afiliados. Cualquier relación derivada de la prestación de servicios médicos se establece directamente entre “EL AFILIADO” y los prestadores de servicios de salud correspondientes. Esta limitación subsistirá a la terminación del contrato.</p>\r\n\r\n  <h4>DÉCIMA TERCERA.- PREVENCIÓN DE LAVADO DE DINERO Y ORIGEN DE LOS RECURSOS.</h4>\r\n  <p>“LAS PARTES” declaran bajo protesta de decir verdad que los recursos económicos, bienes y derechos que utilicen para cumplir obligaciones derivadas de este contrato tienen y tendrán origen lícito. “EL AFILIADO” manifiesta que el pago inicial y pagos futuros provienen de fuentes lícitas y no de actividades tipificadas como delitos.</p>\r\n  <p>“LAS PARTES” reconocen que la prestación de servicios de comercio puede ser considerada actividad vulnerable, por lo que se obligan a proporcionar información y documentación requerida para integrar expediente de identificación e informar si tienen conocimiento de la existencia de beneficiario controlador.</p>\r\n\r\n  <h4>DÉCIMA CUARTA.- CONFORMACIÓN DEL EXPEDIENTE DE IDENTIFICACIÓN.</h4>\r\n  <p>“EL PRESTADOR” queda obligado a conformar y mantener un expediente de identificación de “EL AFILIADO”. Para tales efectos, “EL AFILIADO” se obliga a entregar los documentos aplicables: identificación oficial vigente o pasaporte, acta de nacimiento cuando aplique, comprobante de domicilio, constancia de situación fiscal cuando aplique, CURP, y declaración de dueño beneficiario.</p>\r\n  <p>Cuando exista persona responsable, la documentación de identificación y representación deberá integrarse al expediente; la CIF/constancia fiscal corresponde al tutor cuando aplique. “EL PRESTADOR” conservará dicho expediente por un periodo mínimo de 5 (cinco) años contados a partir de que termine la vigencia del contrato o termine por cualquiera de sus causales, garantizando la confidencialidad de los datos personales.</p>\r\n\r\n  <h4>DÉCIMA QUINTA.- CAUSAL ESPECÍFICA DE RESCISIÓN.</h4>\r\n  <p>Será motivo de rescisión inmediata sin necesidad de declaración judicial y sin responsabilidad para la parte afectada cuando cualquiera de “LAS PARTES” se niegue a proporcionar información requerida para cumplimiento de la Ley Federal para la Prevención e Identificación de Operaciones con Recursos de Procedencia Ilícita, proporcione información falsa o aparezca en listas de personas bloqueadas emitidas por autoridad competente.</p>\r\n\r\n  <h4>DÉCIMA SEXTA.- LEGISLACIÓN APLICABLE Y JURISDICCIÓN.</h4>\r\n  <p>“LAS PARTES” establecen que la Procuraduría Federal del Consumidor es competente en vía administrativa para resolver cualquier controversia sobre interpretación o cumplimiento. Sin perjuicio de lo anterior, se someten expresamente a la jurisdicción de los tribunales competentes del fuero común del Distrito Judicial de Puebla, Estado de Puebla, renunciando de manera expresa e irrevocable a cualquier otro fuero o jurisdicción que pudiera corresponderles.</p>\r\n\r\n  <p>Enteradas “LAS PARTES” del contenido y alcance del presente contrato, y entendidas de los derechos y obligaciones que contraen, firman el presente instrumento, incluyendo sus anexos, manifestando que no medió error, dolo, mala fe, violencia o lesión, ni vicio del consentimiento alguno, en la Ciudad de Puebla, Estado de Puebla, reconociendo que la fecha de firma es 14 de mayo de 2026.</p>\r\n\r\n  <div class=\"sign-grid\">\r\n    <div class=\"sign-box\"><div class=\"line\"></div><strong>“EL PRESTADOR”</strong><br>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE<br>Representada por PEDRO AZCÁRRAGA RAMOS</div>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>“EL AFILIADO”</strong><br>PABLO AJA FRESNEDO</div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 1<br>Identificación oficial de “EL AFILIADO”</h2><p>Se integra al expediente la identificación oficial cargada por el usuario en el formulario. Para mexicanos, corresponde a identificación oficial/INE cuando aplique. Para extranjeros/no mexicanos, corresponde a identificación oficial o pasaporte vigente; al menos el frente es obligatorio y el reverso será opcional cuando el documento no lo tenga.</p><p><strong>Tipo:</strong> INE. <strong>Emitida por / país emisor:</strong> México. <strong>Número:</strong> IDMEX2362711703.</p></div>\r\n  <div class=\"annex\"><h2>ANEXO 2<br>COMPROBANTE DE DOMICILIO DE “EL AFILIADO”</h2><p>Se integra al expediente el comprobante de domicilio cargado por el usuario. Domicilio declarado: PASEO SAN CARLOS 3047, Col. VALLE REAL, C.P. 45019, ZAPOPAN, Jalisco, México.</p></div>\r\n  <div class=\"annex\"><h2>ANEXO 3<br>CONSTANCIA DE SITUACIÓN FISCAL DE “EL AFILIADO”</h2><p>Constancia de Situación Fiscal de “EL AFILIADO”, si aplica. En caso de pacientes representados, la constancia fiscal o CIF corresponde a la persona responsable cuando sea aplicable, no al menor. Para afiliados extranjeros/no mexicanos, no será obligatoria salvo que declaren RFC mexicano o residencia fiscal aplicable.</p></div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 4<br>CUOTAS DE RECUPERACIÓN Y/O PRECIOS BASE A CUBRIR A “EL PRESTADOR”</h2>\r\n    <p>En el presente anexo se establecen los porcentajes de descuento a obtener como titular de “LA TARJETA DE DESCUENTO”, por lo que la cantidad a cubrir por “EL AFILIADO” directamente al hospital de la cadena 50 (FIFTY) Doctors o al doctor que preste el servicio se obtendrá de aplicar el porcentaje de descuento correspondiente al precio publicado por los medios oficiales o al precio vigente en el establecimiento.</p>\r\n    <table><tr><th>Servicios / procedimientos</th><th>Descuentos</th></tr><tr><td>Consulta de urgencias</td><td>100%</td></tr><tr><td>Consulta de medicina general</td><td>100%</td></tr><tr><td>Habitación hospitalaria</td><td>90%</td></tr><tr><td>Uso de áreas de urgencias médicas</td><td>80%</td></tr><tr><td>Utilización de cubículos de terapia intensiva (UCIA-UCIN-UCIP)</td><td>75%</td></tr><tr><td>CEYE</td><td>75%</td></tr><tr><td>Uso quirófano</td><td>75%</td></tr><tr><td>Servicio de cuneros</td><td>75%</td></tr><tr><td>Materiales & medicamentos del cuadro básico, genéricos intercambiables</td><td>70%</td></tr><tr><td>Hemodinamia</td><td>70%</td></tr><tr><td>Imagenología</td><td>70%</td></tr><tr><td>Endoprótesis</td><td>70%</td></tr><tr><td>Osteosíntesis</td><td>70%</td></tr><tr><td>Prótesis</td><td>70%</td></tr><tr><td>Órtesis</td><td>70%</td></tr><tr><td>Laboratorio clínico</td><td>60%</td></tr></table>\r\n    <p class=\"small\">Los descuentos aplican con los proveedores suscritos al convenio de Pasaporte a tu Salud.</p>\r\n    <table><tr><th>Servicios / procedimientos</th><th>Precios base</th></tr><tr><td>Consulta de especialidades médicas</td><td>$390.00</td></tr><tr><td>Colposcopía</td><td>$400.00</td></tr><tr><td>Retiro de puntos de sutura</td><td>$80.00</td></tr><tr><td>Aplicación de medicamento intramuscular</td><td>$60.00</td></tr><tr><td>Retiro de DIU</td><td>$500.00</td></tr><tr><td>Colocación de DIU</td><td>$700.00</td></tr><tr><td>Extracción de cuerpo extraño (oído y nariz)</td><td>$300.00</td></tr><tr><td>Lavado ótico</td><td>$250.00</td></tr><tr><td>Curación de sitio quirúrgico</td><td>$250.00</td></tr><tr><td>Retiro de yeso</td><td>$250.00</td></tr><tr><td>Visita día de hospitalización</td><td>$650.00</td></tr><tr><td>Visita de urgencias</td><td>$750.00</td></tr><tr><td>Día de terapia intensiva</td><td>$850.00</td></tr></table>\r\n    <p class=\"small\">Todos los precios incluyen IVA. La factura de servicios hospitalarios será emitida con el desglose correspondiente y el ahorro otorgado por ser titular de “LA TARJETA DE DESCUENTO”.</p>\r\n    <p>Exclusiones y limitaciones: se aplicarán descuentos y precios especiales para el acompañante de “EL AFILIADO” en la misma habitación únicamente para la primera noche de hospitalización. Los precios y porcentajes de descuento darán derecho a la utilización de materiales y medicamentos del cuadro básico, genéricos intercambiables; cualquier otro tipo de medicación será cubierto directamente por “EL AFILIADO”. Los costos de procedimientos quirúrgicos incluyen honorarios médicos cuando así se indique. “EL AFILIADO” podrá atenderse con el médico tratante que elija, debiendo cubrir honorarios directamente a dicho médico, conservando el derecho a beneficios dentro de la red aplicable.</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Firma de aceptación de “EL AFILIADO”</strong><br>PABLO AJA FRESNEDO</div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 5<br>AVISO DE PRIVACIDAD</h2>\r\n    <p>En cumplimiento de las disposiciones establecidas en la Ley Federal de Protección de Datos Personales en Posesión de Particulares, su Reglamento y los lineamientos aplicables, “CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE” (en lo sucesivo “EL PRESTADOR”), con domicilio en CALLE PASEO SINFONÍA NÚMERO EXTERIOR 1, LOCAL 2-14, LOMAS DE ANGELÓPOLIS II, SAN ANDRÉS CHOLULA, ESTADO DE PUEBLA, CÓDIGO POSTAL 72830, da a conocer el Aviso de Privacidad al tenor del cual manejará por medio de su representación y/o empleados los datos personales y/o documentación proporcionada por el afiliado o usuario de “LA TARJETA DE DESCUENTO”.</p>\r\n    <p>Se tendrá por aceptado expresamente el presente Aviso de Privacidad una vez proporcionados los datos personales y firmada digitalmente la aceptación del contrato, motivo por el cual “EL PRESTADOR” estará facultado para manejar la información conforme a la legislación aplicable.</p>\r\n    <h4>Modificación del aviso de privacidad</h4><p>Este aviso podrá ser modificado o adecuado a las necesidades de “EL PRESTADOR”. Las modificaciones o actualizaciones serán incorporadas al presente aviso y estarán disponibles en la página de internet, domicilio de “EL PRESTADOR” o serán enviadas al último correo electrónico proporcionado.</p>\r\n    <h4>Finalidad de la información</h4><p>La información será utilizada para: elaborar y mantener actualizada la base de usuarios; identificar afiliados; proporcionar la tarjeta digital; otorgar acceso al programa de beneficios; informar modificaciones a la red o tabulador; realizar análisis estadísticos internos y brindar un óptimo servicio médico.</p>\r\n    <h4>Tipo de datos necesarios</h4><p>Se solicitarán datos de identificación, contacto, legales, contractuales y fiscales cuando aplique, incluyendo nombre completo, lugar y fecha de nacimiento, firma, identificación oficial, nacionalidad, CURP y RFC cuando sean aplicables, domicilio, teléfono y correo electrónico.</p>\r\n    <h4>Transferencias de la información</h4><p>El usuario autoriza proporcionar información sin consentimiento adicional en los casos previstos por ley, resolución de autoridad competente, tratados aplicables, salvaguarda de interés público, procuración o administración de justicia, reconocimiento o defensa de derechos en procesos judiciales, y a socios comerciales, técnicos o estratégicos que asuman obligaciones de confidencialidad y seguridad equivalentes.</p>\r\n    <h4>Limitación del uso o divulgación de datos y derechos ARCO</h4><p>El usuario podrá limitar el uso o divulgación de sus datos personales y ejercer derechos de acceso, rectificación, cancelación u oposición mediante solicitud escrita dirigida a “EL PRESTADOR” en su domicilio o al correo silvia@pasaporteatusalud.com, acompañando documento que acredite su identidad.</p>\r\n    <h4>Revocación de consentimiento</h4><p>El usuario podrá revocar su consentimiento siguiendo el mismo procedimiento, considerando que para ciertos fines la revocación puede implicar la cancelación de “LA TARJETA DE DESCUENTO” y la imposibilidad de acceder al programa.</p>\r\n    <p><strong>Nombre:</strong> PABLO AJA FRESNEDO<br><strong>Fecha:</strong> 14 de mayo de 2026</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Firma</strong></div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 6<br>DECLARACIÓN DE DUEÑO BENEFICIARIO</h2>\r\n    <p>DE CONFORMIDAD CON LO DISPUESTO EN LOS ARTÍCULOS 18 FRACCIÓN I Y III DE LA LEY FEDERAL PARA PREVENCIÓN E IDENTIFICACIÓN DE OPERACIONES CON RECURSOS DE PROCEDENCIA ILÍCITA, EL ARTÍCULO 15 DE SU REGLAMENTO Y EL ARTÍCULO 13 DE LAS REGLAS DE CARÁCTER GENERAL, MANIFIESTO BAJO PROTESTA DE DECIR VERDAD:</p>\r\n    <h4>Datos de identificación del cliente</h4>\r\n    <table><tr><th>Campo</th><th>Respuesta</th></tr><tr><td>Apellido paterno, materno y nombre(s)</td><td>PABLO AJA FRESNEDO</td></tr><tr><td>Fecha de nacimiento</td><td>1986-01-28</td></tr><tr><td>País de nacimiento</td><td>México</td></tr><tr><td>Nacionalidad</td><td>mexicana</td></tr><tr><td>Actividad, ocupación o profesión</td><td>EMPLEADO</td></tr><tr><td>Estado civil</td><td>CASADO(A)</td></tr><tr><td>Domicilio particular</td><td>PASEO SAN CARLOS 3047, Col. VALLE REAL, C.P. 45019, ZAPOPAN, Jalisco, México</td></tr><tr><td>Teléfonos</td><td>9992181607</td></tr><tr><td>Correo electrónico</td><td>pabloajaf@gmail.com</td></tr><tr><td>CURP</td><td>AAFP860128HPLJRB03</td></tr><tr><td>RFC</td><td>AAFP8601287X3</td></tr><tr><td>Tipo de identificación</td><td>INE</td></tr><tr><td>Emitida por / país emisor</td><td>México</td></tr><tr><td>Número de identificación</td><td>IDMEX2362711703</td></tr></table>\r\n    <h4>Datos de identificación de la operación</h4>\r\n    <table><tr><th>Campo</th><th>Respuesta</th></tr><tr><td>Tipo de operación</td><td>Adquisición de tarjeta de descuento PATS</td></tr><tr><td>Monto de operación</td><td>$800.00 M.N.</td></tr><tr><td>Fecha de operación</td><td>14 de mayo de 2026</td></tr><tr><td>Forma de pago</td><td>Pasarela / medio autorizado por “EL PRESTADOR”</td></tr><tr><td>Moneda</td><td>MXN</td></tr></table>\r\n    <h4>Información de la existencia del dueño beneficiario o beneficiario controlador</h4>\r\n    <p>Declaro que soy el beneficiario directo de la operación y no existe ningún otro dueño beneficiario o beneficiario controlador: <strong>SI</strong>.</p>\r\n    <h4>Aviso de privacidad</h4><p>Los datos personales serán protegidos y tratados conforme al Aviso de Privacidad contenido en el cuerpo del presente contrato y la legislación aplicable.</p>\r\n    <p>H. Puebla de Zaragoza al 14 del mes de mayo del año 2026.</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Nombre y firma</strong><br>PABLO AJA FRESNEDO</div>\r\n  </div>\r\n\r\n  \r\n  </div>\r\n', 'data:image/png;base64,', 'PABLO AJA FRESNEDO', '800ca14031388f0e7d45c2bca9cabd1338a34a0bc35f848815923f23f49a90d9', '2026-05-14 19:26:33', '189.190.218.123', 'Mozilla/5.0 (Macintosh; Intel Mac OS X 10.13; rv:109.0) Gecko/20100101 Firefox/115.0', '', 'firmado', '2026-05-14 19:26:33', '2026-05-14 19:26:33');
INSERT INTO `pats_contratos_firmados` (`id_contrato_firmado`, `id_orden`, `id_pasaporte`, `id_distribuidor`, `id_franquicia`, `token_publico`, `contrato_clave`, `contrato_version`, `html_contrato_renderizado`, `firma_afiliado_base64`, `nombre_firmante`, `hash_contrato`, `fecha_firma`, `ip_firma`, `user_agent_firma`, `pdf_path`, `estatus`, `created_at`, `updated_at`) VALUES
(18, 2, 2, 0, 0, '', 'contrato_pats_base', '1.0', '<style>\r\n  .pats-contract{font-family:Arial,Helvetica,sans-serif;color:#172033;font-size:12px;line-height:1.52;background:#fff;padding:4px}\r\n  .pats-contract h1,.pats-contract h2,.pats-contract h3,.pats-contract h4{text-align:center;margin:12px 0 8px;color:#0d1b3e}\r\n  .pats-contract h1{font-size:16px;text-transform:uppercase;letter-spacing:.05em}\r\n  .pats-contract h2{font-size:15px;text-transform:uppercase;letter-spacing:.04em}\r\n  .pats-contract h3{font-size:13px;text-transform:uppercase;letter-spacing:.08em}\r\n  .pats-contract h4{font-size:12px;text-align:left;text-transform:uppercase;margin-top:12px}\r\n  .pats-contract p{margin:6px 0;text-align:justify}\r\n  .pats-contract ul{margin:6px 0 8px 18px;padding:0}.pats-contract li{margin:4px 0;text-align:justify}\r\n  .pats-contract table{width:100%;border-collapse:collapse;margin:8px 0 12px}.pats-contract th,.pats-contract td{border:1px solid #cbd5e1;padding:6px;vertical-align:top}.pats-contract th{background:#eef4ff;color:#0d1b3e;text-align:left}\r\n  .pats-contract .center{text-align:center}.pats-contract .muted{color:#64748b}.pats-contract .small{font-size:10px}.pats-contract .badge{display:inline-block;padding:3px 8px;border-radius:999px;background:#eef4ff;color:#1d4ed8;font-weight:700;margin:2px 4px 2px 0}\r\n  .pats-contract .sign-grid{display:grid;grid-template-columns:1fr 1fr;gap:22px;margin-top:28px}.pats-contract .sign-box{text-align:center;min-height:95px}.pats-contract .line{border-top:1px solid #0f172a;margin:48px 8px 6px}.pats-contract .signature-img{max-width:220px;max-height:82px;display:block;margin:0 auto 4px}\r\n  .pats-contract .annex{page-break-before:auto;border-top:2px solid #0d1b3e;margin-top:18px;padding-top:12px}.pats-contract .page-break{page-break-before:always;border-top:1px dashed #cbd5e1;margin-top:18px;padding-top:12px}\r\n</style>\r\n<div class=\"pats-contract\">\r\n  <h1>Carátula del contrato de adquisición de tarjeta de descuento</h1>\r\n  <p>CARÁTULA DEL CONTRATO DE ADQUISICIÓN DE TARJETA DE DESCUENTO (EN LO SUCESIVO “LA CARÁTULA”), QUE CELEBRAN POR UNA PARTE LA SOCIEDAD SEÑALADA EN EL APARTADO 1.- DE LA CARÁTULA, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL PRESTADOR”, REPRESENTADA EN ESTE ACTO POR LA PERSONA FÍSICA QUE SE INDICA EN EL APARTADO 2.- DE LA CARÁTULA; Y POR LA OTRA PARTE, LA PERSONA FÍSICA SEÑALADA EN EL APARTADO 5.- DE LA CARÁTULA, POR SU PROPIO DERECHO, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL AFILIADO”; Y CUANDO LOS ANTES NOMBRADOS ACTÚEN DE MANERA CONJUNTA, SE LES DENOMINARÁ COMO “LAS PARTES”; QUIENES SE SUJETAN AL TENOR DE LA CARÁTULA, DECLARACIONES Y CLÁUSULAS SIGUIENTES:</p>\r\n    \r\n  <h2>C A R Á T U L A</h2>\r\n  <table>\r\n    <tr><th style=\"width:8%\">Apartado</th><th style=\"width:42%\">Definición</th><th>Respuesta</th></tr>\r\n    <tr><td>1.-</td><td>Nombre de “EL PRESTADOR”</td><td>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE</td></tr>\r\n    <tr><td>2.-</td><td>Nombre del Representante Legal de “EL PRESTADOR”</td><td>PEDRO AZCÁRRAGA RAMOS</td></tr>\r\n    <tr><td>3.-</td><td>Domicilio de “EL PRESTADOR”</td><td>CALLE PASEO SINFONÍA NÚMERO EXTERIOR 1, LOCAL 2-14, LOMAS DE ANGELÓPOLIS II, SAN ANDRÉS CHOLULA, ESTADO DE PUEBLA, CÓDIGO POSTAL 72830</td></tr>\r\n    <tr><td>4.-</td><td>Clave del Registro Federal de Contribuyentes de “EL PRESTADOR”</td><td>COH2202144H5</td></tr>\r\n    <tr><td>5.-</td><td>Nombre de “EL AFILIADO”</td><td>Carlos David Gonzalez Miranda</td></tr>\r\n    <tr><td>6.-</td><td>Domicilio de “EL AFILIADO”</td><td>Calle 123, Col. Mirador, C.P. 55555, Canto, Jalisco, México</td></tr>\r\n    <tr><td>7.-</td><td>Clave del Registro Federal de Contribuyentes de “EL AFILIADO”</td><td>GOMC56456456</td></tr>\r\n    <tr><td>8.-</td><td>Costo mensual de “LA TARJETA DE DESCUENTO”</td><td>$800.00 M.N.</td></tr>\r\n    <tr><td>9.-</td><td>Cuenta bancaria de “EL PRESTADOR” para pagos</td><td>Cuenta: 01600866709<br>CLABE: 042650016008667096<br>Institución Bancaria: Banca Mifel, S.A., Institución de Banca Múltiple, Grupo Financiero Mifel</td></tr>\r\n    <tr><td>10.-</td><td>Cuota de Reactivación de “LA TARJETA DE DESCUENTO”</td><td>$100.00 M.N. por cada mes que se haya interrumpido el pago.</td></tr>\r\n    <tr><td>11.-</td><td>Datos de la Tarjeta de Crédito de “EL AFILIADO”</td><td>Número de tarjeta: pendiente de confirmar por pasarela/token de pago.<br>Institución bancaria: pendiente de confirmar por pasarela. <br><span class=\"small\">No se almacena número completo de tarjeta en este formulario.</span></td></tr>\r\n    <tr><td>12.-</td><td>Anexos</td><td>ANEXO 1. Identificación oficial de “EL AFILIADO”<br>ANEXO 2. Comprobante de domicilio de “EL AFILIADO”<br>ANEXO 3. Constancia de Situación Fiscal de “EL AFILIADO”, si aplica<br>ANEXO 4. Cuotas de recuperación y/o precios base a cubrir a “EL PRESTADOR”<br>ANEXO 5. Aviso de privacidad<br>ANEXO 6. Declaración de dueño beneficiario</td></tr>\r\n    <tr><td>13.-</td><td>Fecha de Firma del Contrato</td><td>14 de mayo de 2026</td></tr>\r\n  </table>\r\n\r\n  <div class=\"sign-grid\">\r\n    <div class=\"sign-box\"><div class=\"line\"></div><strong>“EL PRESTADOR”</strong><br>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE<br>Representada por PEDRO AZCÁRRAGA RAMOS</div>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>“EL AFILIADO”</strong><br>Carlos David Gonzalez Miranda<br><span class=\"small\">La persona física señalada en el Apartado 5.- de la Carátula</span></div>\r\n  </div>\r\n\r\n  <div class=\"page-break\"></div>\r\n  <h1>Contrato de adquisición de tarjeta de descuento</h1>\r\n  <p>CONTRATO DE ADQUISICIÓN DE TARJETA DE DESCUENTO, QUE CELEBRAN POR UNA PARTE LA SOCIEDAD SEÑALADA EN EL APARTADO 1.- DE LA CARÁTULA, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL PRESTADOR”, REPRESENTADA EN ESTE ACTO POR LA PERSONA FÍSICA QUE SE INDICA EN EL APARTADO 2.- DE LA CARÁTULA; Y POR LA OTRA PARTE, LA PERSONA FÍSICA SEÑALADA EN EL APARTADO 5.- DE LA CARÁTULA, POR SU PROPIO DERECHO, A QUIEN EN LO SUCESIVO SE LE DENOMINARÁ COMO “EL AFILIADO”; Y CUANDO LOS ANTES NOMBRADOS ACTÚEN DE MANERA CONJUNTA, SE LES DENOMINARÁ COMO “LAS PARTES”; QUIENES SE SUJETAN AL TENOR DE LAS DECLARACIONES Y CLÁUSULAS SIGUIENTES:</p>\r\n\r\n  <h2>D E C L A R A C I O N E S</h2>\r\n  <h4>I.- Declara “EL PRESTADOR” por conducto de su representación:</h4>\r\n  <p>A. Que, su representada es una sociedad mercantil constituida conforme a las leyes de los Estados Unidos Mexicanos, según consta en la escritura pública número 39,861, del volumen 830 de fecha catorce de febrero de dos mil veintidós, otorgada ante la fe del Licenciado Ernesto Joaquín Briones Amador, Notario Público Titular de la Notaría Pública número 46 de las del Distrito Judicial de Puebla, Estado de Puebla, cuyo primer testimonio se encuentra inscrito ante las oficinas del Registro Público de Comercio del Distrito Judicial de Puebla, Estado de Puebla, bajo el Folio Mercantil Electrónico: N-2022022991, por virtud del cual se llevó a cabo la Constitución de la persona moral denominada CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE.</p>\r\n  <p>B. Que, la persona física que la representa en este acto, señalada en el Apartado 2.- de la Carátula, cuenta con todas y cada una de las facultades necesarias para la celebración del presente contrato, las cuales se desprenden del instrumento descrito en el punto declarativo inmediato anterior, mismas que manifiesta bajo protesta de decir verdad que no le han sido suspendidas, revocadas o limitadas en forma alguna.</p>\r\n  <p>C. Que, su representada tiene como domicilio fiscal el señalado en el Apartado 3.- de la Carátula del presente contrato, mismo que designa como domicilio convencional para cualquier cuestión relacionada con la celebración del presente contrato.</p>\r\n  <p>D. Que, su representada se encuentra inscrita en el Registro Federal de Contribuyentes bajo la clave señalada en el Apartado 4.- de la Carátula.</p>\r\n  <p>E. Que, ha desarrollado y es su deseo comparecer a la celebración del presente instrumento con la finalidad de enajenar en favor de “EL AFILIADO”, una Tarjeta de Descuento que da acceso a “UN PROGRAMA DE BENEFICIOS QUE OTORGA DESCUENTOS A LOS COSTOS Y PERMITE RECIBIR SERVICIOS MÉDICOS PRIVADOS DE ALTA CALIDAD DE FORMA ACCESIBLE, CLARA Y SIN RESTRICCIONES DENTRO DE LA RED DE HOSPITALES 50 (FIFTY) DOCTORS CON SEDE EN EL ESTADO DE PUEBLA”, en lo sucesivo “LA TARJETA DE DESCUENTO”, en los términos y condiciones que se establecerán más adelante.</p>\r\n  <p>F. Que, su representada no es una Aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas sino una empresa dedicada, entre otros, a la operación y administración de establecimientos destinados a la atención y asistencia de enfermos, por lo que la enajenación de “LA TARJETA DE DESCUENTO” únicamente constituye un acto de comercio que brindará a “EL AFILIADO” acceso a un programa de beneficios como ha quedado descrito anteriormente.</p>\r\n\r\n  <h4>II.- Declara “EL AFILIADO”, por su propio derecho:</h4>\r\n      <p>A. Que, su nombre se señala en el Apartado 5.- de la Carátula, es una persona física de nacionalidad mexicana, en pleno ejercicio de sus derechos, legal y jurídicamente capaz para celebrar el presente Contrato, quien se identifica con credencial para votar vigente expedida por el Instituto Nacional Electoral, tipo INE, número 46566, que en copia simple o archivo digital se agrega al cuerpo del presente contrato como ANEXO 1.</p>\r\n    <p>B. Que, tiene como domicilio particular el señalado en el Apartado 6.- de la Carátula, mismo que designa como domicilio convencional para cualquier cuestión relacionada con la celebración del presente contrato, tal y como lo acredita con el comprobante de domicilio que en copia simple o archivo digital se agrega al cuerpo del presente contrato como ANEXO 2.</p>\r\n  <p>C. Que, su CURP es GOMC1234 y su RFC/identificación fiscal es GOMC56456456; asimismo manifiesta que cuenta con capacidad económica para obligarse en términos del presente contrato y que los recursos con los que cubrirá sus obligaciones provendrán de fuentes lícitas. En caso de nacionalidad extranjera/no mexicana, se tendrán por no aplicables CURP, INE y constancia fiscal mexicana salvo manifestación expresa de residencia fiscal o RFC mexicano.</p>\r\n  <p>D. Que, es su deseo comparecer a la celebración del presente instrumento con la finalidad de adquirir “LA TARJETA DE DESCUENTO” de acuerdo con los términos y condiciones que se establecen a continuación.</p>\r\n  <p>E. Que, previo a la celebración del presente contrato fue informado y manifiesta expresamente que reconoce que “EL PRESTADOR” no es una Aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas y que las actividades comerciales objeto del presente contrato no consisten en la contratación de un seguro, de la índole que fuere, sino que únicamente implica la adquisición de una tarjeta de descuento que da acceso a un programa de beneficios que otorga descuentos a los costos y permite recibir servicios médicos privados de alta calidad de forma accesible, clara y sin restricciones dentro de la red de hospitales 50 (FIFTY) Doctors con sede en el Estado de Puebla.</p>\r\n  <p>F. Que, reconoce que “EL PRESTADOR” se dedica a la operación de centros hospitalarios y que la emisión de “LA TARJETA DE DESCUENTO” únicamente corresponde a la intención de este último de crear un programa de descuentos para el acceso a los servicios prestados por la Red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla.</p>\r\n\r\n  <h4>III.- Declaran conjuntamente “LAS PARTES”:</h4>\r\n  <p>1. Que, se reconocen recíprocamente la personalidad con la que comparecen a la celebración del presente acuerdo de voluntades.</p>\r\n  <p>2. Que, el presente contrato es el instrumento que las vincula en sus derechos y obligaciones.</p>\r\n  <p>3. Que, es su deseo celebrar el presente contrato y han negociado libremente los términos y condiciones del mismo con pleno conocimiento de sus alcances e implicaciones jurídicas, por lo que en su celebración no existe dolo, error, mala fe, lesión o cualquier otro vicio del consentimiento que pudiese afectarlo de inexistencia o nulidad.</p>\r\n\r\n  <h2>C L Á U S U L A S</h2>\r\n  <h4>PRIMERA.- OBJETO.</h4>\r\n  <p>El objeto del presente Contrato es que “EL AFILIADO” adquiera de “EL PRESTADOR”, a título oneroso y temporal, el derecho de uso ilimitado y sin restricción alguna de “LA TARJETA DE DESCUENTO” emitida por CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE, la cual consiste en que “EL AFILIADO” aproveche y acceda a “UN PROGRAMA DE BENEFICIOS QUE OTORGA DESCUENTOS A LOS COSTOS Y PERMITE RECIBIR SERVICIOS MÉDICOS PRIVADOS DE ALTA CALIDAD DE FORMA ACCESIBLE, CLARA Y SIN RESTRICCIONES DENTRO DE LA RED DE HOSPITALES 50 (FIFTY) DOCTORS CON SEDE EN EL ESTADO DE PUEBLA”.</p>\r\n  <p>Estableciendo que, la comercialización de “LA TARJETA DE DESCUENTO” por parte de “EL PRESTADOR” en ningún momento constituirá la venta, promoción o por cualquier medio la contratación de una póliza de seguro, bajo el entendido de que “EL PRESTADOR” no es una aseguradora reconocida por la Comisión Nacional de Seguros y Fianzas (CNSF); sino que comercializa “LA TARJETA DE DESCUENTO” en favor de terceros con la finalidad de otorgar descuentos a los precios respecto de los servicios médicos que presta en el territorio nacional.</p>\r\n\r\n  <h4>SEGUNDA.- PRECIO DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“LAS PARTES” establecen de común acuerdo que “LA TARJETA DE DESCUENTO” tendrá como costo mensual la cantidad señalada en el Apartado 8.- de la Carátula del presente contrato; cantidad que ya incluye IVA, y la cual deberá ser cubierta por “EL AFILIADO” en favor de “EL PRESTADOR” dentro de los primeros 5 (cinco) días de cada mes, sin necesidad de gestiones o avisos de cobro, ya sea mediante:</p>\r\n  <p>(i) Transferencia electrónica de fondos a la cuenta bancaria señalada en el Apartado 9.- de la Carátula del presente contrato y de la cual es titular “EL PRESTADOR”.</p>\r\n  <p>(ii) Cheque que se recibirá salvo buen cobro en el Domicilio de “EL PRESTADOR” señalado en el Apartado 3.- de la Carátula del presente contrato, y que en caso de no ser pagado por falta de fondos suficientes o por otras causas imputables a “EL AFILIADO”, éste último está de acuerdo en que deberá cubrir a “EL PRESTADOR” el 20% (veinte por ciento) del monto del cheque por concepto de indemnización por daños y perjuicios en términos del artículo 193 de la Ley General de Títulos y Operaciones de Crédito, independientemente de cualquier otro cargo que se pudiera generar.</p>\r\n  <p>(iii) Cargos mensuales automáticos recurrentes a la tarjeta de crédito de “EL AFILIADO” según los datos señalados en el Apartado 11.- de la Carátula del presente contrato, quien manifiesta bajo protesta de decir verdad que autoriza a “EL PRESTADOR” a realizar los cargos mensuales correspondientes por el costo mensual de “LA TARJETA DE DESCUENTO” en dicha tarjeta o en la tarjeta que por renovación, reposición, robo o extravío le haya asignado el banco emisor. La autorización estará vigente mientras “EL AFILIADO” no haya notificado a “EL PRESTADOR” por escrito y con acuse de recibo su deseo de cancelar su afiliación o no renovarla, o en su defecto, realizar su baja respectiva en el sitio web o aplicación de “EL PRESTADOR”.</p>\r\n  <p>Esta autorización no exime a “EL AFILIADO” del pago mensual por el uso de “LA TARJETA DE DESCUENTO” y demás obligaciones contractuales, por lo que, en caso de que el cobro no sea autorizado por el banco emisor o por cualquier razón no pueda realizarse, “EL AFILIADO” deberá notificar tal situación a “EL PRESTADOR” a la dirección de correo electrónico silvia@pasaporteatusalud.com, a efecto de solicitar una forma de pago diversa, quedando obligado a cubrir de inmediato el pago correspondiente.</p>\r\n  <p>(iv) Cualquier otro medio de pago aceptado por “EL PRESTADOR”, mismo que se dará a conocer a través de sus medios oficiales de comunicación.</p>\r\n  <p>“EL PRESTADOR” podrá variar unilateralmente el costo mensual de “LA TARJETA DE DESCUENTO”, previo aviso a “EL AFILIADO” con 30 (treinta) días de anticipación a través de sus medios oficiales de comunicación.</p>\r\n  <p>Para el caso de que “EL AFILIADO” adquiera y cubra el precio de “LA TARJETA DE DESCUENTO” y posteriormente deje de pagar una mensualidad, deberá cubrir a “EL PRESTADOR”, por concepto de cuota de reactivación, la cantidad señalada en el Apartado 10.- de la Carátula por cada mes que haya interrumpido y/o no haya cubierto el precio de “LA TARJETA DE DESCUENTO”, hasta la fecha en que pretenda volver a adquirirla.</p>\r\n\r\n  <h4>TERCERA.- VIGENCIA DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“LA TARJETA DE DESCUENTO” objeto del presente contrato tendrá una vigencia de 30 días contados a partir de que “EL AFILIADO” cubra a “EL PRESTADOR” el precio establecido anteriormente, en el entendido de que la vigencia del presente contrato y de “LA TARJETA DE DESCUENTO” se prorrogarán automáticamente sin necesidad de celebrar documento adicional entre “LAS PARTES” siempre y cuando “EL AFILIADO” cubra, de mes en mes o en la frecuencia contratada, el precio vigente de “LA TARJETA DE DESCUENTO”.</p>\r\n  <p>“EL AFILIADO” tendrá derecho a revocar su consentimiento dentro de los 5 (cinco) días siguientes a la entrega de “LA TARJETA DE DESCUENTO” o la firma del presente contrato, lo que ocurra último, sin responsabilidad alguna, siempre y cuando no haya obtenido beneficio alguno por el uso de “LA TARJETA DE DESCUENTO”.</p>\r\n\r\n  <h4>CUARTA.- BENEFICIOS DE “LA TARJETA DE DESCUENTO”.</h4>\r\n  <p>“EL AFILIADO”, de forma exclusiva, personal e intransferible, gozará de forma gratuita de los servicios que se mencionan a continuación:</p>\r\n  <ul><li>Consultas gratuitas ilimitadas de medicina general (no de especialidad) en la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla, únicamente con los doctores afiliados al programa de Pasaporte a tu Salud.</li><li>Consultas de urgencia gratuitas en la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla.</li></ul>\r\n  <p>No así respecto de los servicios que, de manera enunciativa más no limitativa, se describen a continuación:</p>\r\n  <ul><li>Hospitalización dentro de la red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla, sujeto a la disponibilidad de cada uno de ellos.</li><li>Consultas de especialidad ilimitadas a costo preferencial, con médicos especialistas pertenecientes al programa PATS.</li><li>Acceso a farmacia PATS con costos reducidos de medicamentos genéricos.</li><li>Imagenología y laboratorios ilimitados con costos preferenciales.</li><li>Acceso a cirugías con cuota de recuperación preferente, con o sin honorarios médicos incluidos según corresponda.</li></ul>\r\n  <p>Dichos servicios generarán, por evento, el pago de una cuota con cargo a “EL AFILIADO”, misma que resultará de aplicar los porcentajes de descuento que se desprenden del ANEXO 4 del presente contrato a los precios publicados al público en general o los precios preferenciales indicados.</p>\r\n  <p>Mientras “LA TARJETA DE DESCUENTO” se encuentre vigente, “EL AFILIADO” gozará de todos los beneficios que la misma le otorga; sin embargo, para el caso de que requiera cirugía o procedimiento quirúrgico en quirófano, deberá haber sufragado por adelantado la adquisición de “LA TARJETA DE DESCUENTO” por un periodo de 12 (doce) meses y encontrarse dentro de dicho periodo de vigencia.</p>\r\n\r\n  <h4>QUINTA.- OBLIGACIONES DE “EL PRESTADOR”.</h4>\r\n  <p>“EL PRESTADOR” se obliga a: (i) otorgar a “EL AFILIADO” el acceso ilimitado a “LA TARJETA DE DESCUENTO” durante la vigencia del contrato; (ii) mantener actualizada y operativa la Red de Hospitales 50 (FIFTY) Doctors en el Estado de Puebla; (iii) proporcionar a “EL AFILIADO”, de forma digital, “LA TARJETA DE DESCUENTO” dentro de los 5 (cinco) días hábiles siguientes al primer pago; e (iv) informar por escrito cualquier modificación a la red de hospitales o al tabulador de cuotas con al menos 10 (diez) días de anticipación.</p>\r\n\r\n  <h4>SEXTA.- OBLIGACIONES DE “EL AFILIADO”.</h4>\r\n  <p>“EL AFILIADO” se obliga a: (i) pagar puntualmente el precio de “LA TARJETA DE DESCUENTO”; (ii) utilizarla de forma exclusiva, personal e intransferible; (iii) cubrir directamente a los hospitales y con anterioridad a recibir el servicio médico las cuotas de recuperación según tabulador vigente; (iv) presentar identificación oficial y “LA TARJETA DE DESCUENTO” o código QR cada vez que haga uso de beneficios; y (v) notificar por escrito cualquier cambio de domicilio o datos de contacto en un plazo no mayor a 5 (cinco) días.</p>\r\n\r\n  <h4>SÉPTIMA.- ACCESO A LOS BENEFICIOS Y PROCEDIMIENTO.</h4>\r\n  <p>Para hacer uso de “LA TARJETA DE DESCUENTO”, “EL AFILIADO” deberá agendar sus citas directamente con los doctores pertenecientes a la Red de Hospitales 50 (FIFTY) Doctors, que en ese momento se encuentren adscritos al programa de beneficios, a través de la aplicación oficial, página de internet oficial de PATS o medios oficiales que indique “EL PRESTADOR”.</p>\r\n  <p>“EL AFILIADO” se obliga a pagar directamente al médico especialista perteneciente al programa el costo de la consulta de especialidad de que se trate, en términos de los porcentajes de descuento del ANEXO 4. En caso de no estar facultado para asistir por fuerza mayor, tendrá un plazo de 30 (treinta) días contados a partir de haber generado la cita para solicitar una nueva consulta médica.</p>\r\n\r\n  <h4>OCTAVA.- EXCLUSIONES Y LIMITACIONES.</h4>\r\n  <p>Los beneficios no incluirán: (i) trasplantes de órganos; (ii) tratamientos experimentales; (iii) tratamientos de oncología a excepción de algunas cirugías; (iv) medicamentos extra hospitalarios que no estén recogidos en el catálogo de Farmacia PATS; (v) atención médica con especialistas no adscritos o no publicados en los medios oficiales; y (vi) cualquier servicio no listado expresamente.</p>\r\n\r\n  <h4>NOVENA.- CAUSAS DE TERMINACIÓN.</h4>\r\n  <p>El contrato podrá terminarse por falta de pago, mutuo consentimiento por escrito o incumplimiento de cualquiera de las cláusulas por cualquiera de “LAS PARTES”. En caso de terminación, “EL AFILIADO” no tendrá derecho a exigir la devolución de cantidad alguna.</p>\r\n\r\n  <h4>DÉCIMA.- CANCELACIÓN VOLUNTARIA.</h4>\r\n  <p>“EL AFILIADO” podrá cancelar “LA TARJETA DE DESCUENTO” mediante aviso por escrito con 30 (treinta) días de anticipación. Dicha cancelación surtirá efectos a partir del siguiente periodo mensual y no generará reembolso de pagos ya realizados.</p>\r\n\r\n  <h4>DÉCIMA PRIMERA.- PROTECCIÓN DE DATOS PERSONALES.</h4>\r\n  <p>“LAS PARTES” acuerdan que el tratamiento de datos personales se sujetará a la Ley Federal de Protección de Datos Personales en Posesión de los Particulares. “EL AFILIADO” autoriza expresamente el uso de sus datos para la gestión de “LA TARJETA DE DESCUENTO”. El aviso de privacidad se integra al presente contrato como ANEXO 5.</p>\r\n\r\n  <h4>DÉCIMA SEGUNDA.- RESPONSABILIDAD.</h4>\r\n  <p>“EL AFILIADO” reconoce y acepta que “LA TARJETA DE DESCUENTO” es emitida y administrada directamente por CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE, quien es responsable de la operación de la red de descuentos, afiliación de prestadores médicos y prestación de cualquier servicio relacionado con “LA TARJETA DE DESCUENTO”.</p>\r\n  <p>En consecuencia, “EL PRESTADOR” no tendrá responsabilidad directa ni indirecta por la prestación, calidad, eficacia, resultado, daño, perjuicio, lesión, complicación, secuela, evento adverso o consecuencia derivada de servicios médicos recibidos, incluyendo aquellos ocasionados por negligencia, impericia o mala praxis de profesionales de la salud o prestadores afiliados. Cualquier relación derivada de la prestación de servicios médicos se establece directamente entre “EL AFILIADO” y los prestadores de servicios de salud correspondientes. Esta limitación subsistirá a la terminación del contrato.</p>\r\n\r\n  <h4>DÉCIMA TERCERA.- PREVENCIÓN DE LAVADO DE DINERO Y ORIGEN DE LOS RECURSOS.</h4>\r\n  <p>“LAS PARTES” declaran bajo protesta de decir verdad que los recursos económicos, bienes y derechos que utilicen para cumplir obligaciones derivadas de este contrato tienen y tendrán origen lícito. “EL AFILIADO” manifiesta que el pago inicial y pagos futuros provienen de fuentes lícitas y no de actividades tipificadas como delitos.</p>\r\n  <p>“LAS PARTES” reconocen que la prestación de servicios de comercio puede ser considerada actividad vulnerable, por lo que se obligan a proporcionar información y documentación requerida para integrar expediente de identificación e informar si tienen conocimiento de la existencia de beneficiario controlador.</p>\r\n\r\n  <h4>DÉCIMA CUARTA.- CONFORMACIÓN DEL EXPEDIENTE DE IDENTIFICACIÓN.</h4>\r\n  <p>“EL PRESTADOR” queda obligado a conformar y mantener un expediente de identificación de “EL AFILIADO”. Para tales efectos, “EL AFILIADO” se obliga a entregar los documentos aplicables: identificación oficial vigente o pasaporte, acta de nacimiento cuando aplique, comprobante de domicilio, constancia de situación fiscal cuando aplique, CURP, y declaración de dueño beneficiario.</p>\r\n  <p>Cuando exista persona responsable, la documentación de identificación y representación deberá integrarse al expediente; la CIF/constancia fiscal corresponde al tutor cuando aplique. “EL PRESTADOR” conservará dicho expediente por un periodo mínimo de 5 (cinco) años contados a partir de que termine la vigencia del contrato o termine por cualquiera de sus causales, garantizando la confidencialidad de los datos personales.</p>\r\n\r\n  <h4>DÉCIMA QUINTA.- CAUSAL ESPECÍFICA DE RESCISIÓN.</h4>\r\n  <p>Será motivo de rescisión inmediata sin necesidad de declaración judicial y sin responsabilidad para la parte afectada cuando cualquiera de “LAS PARTES” se niegue a proporcionar información requerida para cumplimiento de la Ley Federal para la Prevención e Identificación de Operaciones con Recursos de Procedencia Ilícita, proporcione información falsa o aparezca en listas de personas bloqueadas emitidas por autoridad competente.</p>\r\n\r\n  <h4>DÉCIMA SEXTA.- LEGISLACIÓN APLICABLE Y JURISDICCIÓN.</h4>\r\n  <p>“LAS PARTES” establecen que la Procuraduría Federal del Consumidor es competente en vía administrativa para resolver cualquier controversia sobre interpretación o cumplimiento. Sin perjuicio de lo anterior, se someten expresamente a la jurisdicción de los tribunales competentes del fuero común del Distrito Judicial de Puebla, Estado de Puebla, renunciando de manera expresa e irrevocable a cualquier otro fuero o jurisdicción que pudiera corresponderles.</p>\r\n\r\n  <p>Enteradas “LAS PARTES” del contenido y alcance del presente contrato, y entendidas de los derechos y obligaciones que contraen, firman el presente instrumento, incluyendo sus anexos, manifestando que no medió error, dolo, mala fe, violencia o lesión, ni vicio del consentimiento alguno, en la Ciudad de Puebla, Estado de Puebla, reconociendo que la fecha de firma es 14 de mayo de 2026.</p>\r\n\r\n  <div class=\"sign-grid\">\r\n    <div class=\"sign-box\"><div class=\"line\"></div><strong>“EL PRESTADOR”</strong><br>CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE<br>Representada por PEDRO AZCÁRRAGA RAMOS</div>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>“EL AFILIADO”</strong><br>Carlos David Gonzalez Miranda</div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 1<br>Identificación oficial de “EL AFILIADO”</h2><p>Se integra al expediente la identificación oficial cargada por el usuario en el formulario. Para mexicanos, corresponde a identificación oficial/INE cuando aplique. Para extranjeros/no mexicanos, corresponde a identificación oficial o pasaporte vigente; al menos el frente es obligatorio y el reverso será opcional cuando el documento no lo tenga.</p><p><strong>Tipo:</strong> INE. <strong>Emitida por / país emisor:</strong> México. <strong>Número:</strong> 46566.</p></div>\r\n  <div class=\"annex\"><h2>ANEXO 2<br>COMPROBANTE DE DOMICILIO DE “EL AFILIADO”</h2><p>Se integra al expediente el comprobante de domicilio cargado por el usuario. Domicilio declarado: Calle 123, Col. Mirador, C.P. 55555, Canto, Jalisco, México.</p></div>\r\n  <div class=\"annex\"><h2>ANEXO 3<br>CONSTANCIA DE SITUACIÓN FISCAL DE “EL AFILIADO”</h2><p>Constancia de Situación Fiscal de “EL AFILIADO”, si aplica. En caso de pacientes representados, la constancia fiscal o CIF corresponde a la persona responsable cuando sea aplicable, no al menor. Para afiliados extranjeros/no mexicanos, no será obligatoria salvo que declaren RFC mexicano o residencia fiscal aplicable.</p></div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 4<br>CUOTAS DE RECUPERACIÓN Y/O PRECIOS BASE A CUBRIR A “EL PRESTADOR”</h2>\r\n    <p>En el presente anexo se establecen los porcentajes de descuento a obtener como titular de “LA TARJETA DE DESCUENTO”, por lo que la cantidad a cubrir por “EL AFILIADO” directamente al hospital de la cadena 50 (FIFTY) Doctors o al doctor que preste el servicio se obtendrá de aplicar el porcentaje de descuento correspondiente al precio publicado por los medios oficiales o al precio vigente en el establecimiento.</p>\r\n    <table><tr><th>Servicios / procedimientos</th><th>Descuentos</th></tr><tr><td>Consulta de urgencias</td><td>100%</td></tr><tr><td>Consulta de medicina general</td><td>100%</td></tr><tr><td>Habitación hospitalaria</td><td>90%</td></tr><tr><td>Uso de áreas de urgencias médicas</td><td>80%</td></tr><tr><td>Utilización de cubículos de terapia intensiva (UCIA-UCIN-UCIP)</td><td>75%</td></tr><tr><td>CEYE</td><td>75%</td></tr><tr><td>Uso quirófano</td><td>75%</td></tr><tr><td>Servicio de cuneros</td><td>75%</td></tr><tr><td>Materiales & medicamentos del cuadro básico, genéricos intercambiables</td><td>70%</td></tr><tr><td>Hemodinamia</td><td>70%</td></tr><tr><td>Imagenología</td><td>70%</td></tr><tr><td>Endoprótesis</td><td>70%</td></tr><tr><td>Osteosíntesis</td><td>70%</td></tr><tr><td>Prótesis</td><td>70%</td></tr><tr><td>Órtesis</td><td>70%</td></tr><tr><td>Laboratorio clínico</td><td>60%</td></tr></table>\r\n    <p class=\"small\">Los descuentos aplican con los proveedores suscritos al convenio de Pasaporte a tu Salud.</p>\r\n    <table><tr><th>Servicios / procedimientos</th><th>Precios base</th></tr><tr><td>Consulta de especialidades médicas</td><td>$390.00</td></tr><tr><td>Colposcopía</td><td>$400.00</td></tr><tr><td>Retiro de puntos de sutura</td><td>$80.00</td></tr><tr><td>Aplicación de medicamento intramuscular</td><td>$60.00</td></tr><tr><td>Retiro de DIU</td><td>$500.00</td></tr><tr><td>Colocación de DIU</td><td>$700.00</td></tr><tr><td>Extracción de cuerpo extraño (oído y nariz)</td><td>$300.00</td></tr><tr><td>Lavado ótico</td><td>$250.00</td></tr><tr><td>Curación de sitio quirúrgico</td><td>$250.00</td></tr><tr><td>Retiro de yeso</td><td>$250.00</td></tr><tr><td>Visita día de hospitalización</td><td>$650.00</td></tr><tr><td>Visita de urgencias</td><td>$750.00</td></tr><tr><td>Día de terapia intensiva</td><td>$850.00</td></tr></table>\r\n    <p class=\"small\">Todos los precios incluyen IVA. La factura de servicios hospitalarios será emitida con el desglose correspondiente y el ahorro otorgado por ser titular de “LA TARJETA DE DESCUENTO”.</p>\r\n    <p>Exclusiones y limitaciones: se aplicarán descuentos y precios especiales para el acompañante de “EL AFILIADO” en la misma habitación únicamente para la primera noche de hospitalización. Los precios y porcentajes de descuento darán derecho a la utilización de materiales y medicamentos del cuadro básico, genéricos intercambiables; cualquier otro tipo de medicación será cubierto directamente por “EL AFILIADO”. Los costos de procedimientos quirúrgicos incluyen honorarios médicos cuando así se indique. “EL AFILIADO” podrá atenderse con el médico tratante que elija, debiendo cubrir honorarios directamente a dicho médico, conservando el derecho a beneficios dentro de la red aplicable.</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Firma de aceptación de “EL AFILIADO”</strong><br>Carlos David Gonzalez Miranda</div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 5<br>AVISO DE PRIVACIDAD</h2>\r\n    <p>En cumplimiento de las disposiciones establecidas en la Ley Federal de Protección de Datos Personales en Posesión de Particulares, su Reglamento y los lineamientos aplicables, “CRT OPERADORES DE HOSPITALES, SOCIEDAD ANÓNIMA DE CAPITAL VARIABLE” (en lo sucesivo “EL PRESTADOR”), con domicilio en CALLE PASEO SINFONÍA NÚMERO EXTERIOR 1, LOCAL 2-14, LOMAS DE ANGELÓPOLIS II, SAN ANDRÉS CHOLULA, ESTADO DE PUEBLA, CÓDIGO POSTAL 72830, da a conocer el Aviso de Privacidad al tenor del cual manejará por medio de su representación y/o empleados los datos personales y/o documentación proporcionada por el afiliado o usuario de “LA TARJETA DE DESCUENTO”.</p>\r\n    <p>Se tendrá por aceptado expresamente el presente Aviso de Privacidad una vez proporcionados los datos personales y firmada digitalmente la aceptación del contrato, motivo por el cual “EL PRESTADOR” estará facultado para manejar la información conforme a la legislación aplicable.</p>\r\n    <h4>Modificación del aviso de privacidad</h4><p>Este aviso podrá ser modificado o adecuado a las necesidades de “EL PRESTADOR”. Las modificaciones o actualizaciones serán incorporadas al presente aviso y estarán disponibles en la página de internet, domicilio de “EL PRESTADOR” o serán enviadas al último correo electrónico proporcionado.</p>\r\n    <h4>Finalidad de la información</h4><p>La información será utilizada para: elaborar y mantener actualizada la base de usuarios; identificar afiliados; proporcionar la tarjeta digital; otorgar acceso al programa de beneficios; informar modificaciones a la red o tabulador; realizar análisis estadísticos internos y brindar un óptimo servicio médico.</p>\r\n    <h4>Tipo de datos necesarios</h4><p>Se solicitarán datos de identificación, contacto, legales, contractuales y fiscales cuando aplique, incluyendo nombre completo, lugar y fecha de nacimiento, firma, identificación oficial, nacionalidad, CURP y RFC cuando sean aplicables, domicilio, teléfono y correo electrónico.</p>\r\n    <h4>Transferencias de la información</h4><p>El usuario autoriza proporcionar información sin consentimiento adicional en los casos previstos por ley, resolución de autoridad competente, tratados aplicables, salvaguarda de interés público, procuración o administración de justicia, reconocimiento o defensa de derechos en procesos judiciales, y a socios comerciales, técnicos o estratégicos que asuman obligaciones de confidencialidad y seguridad equivalentes.</p>\r\n    <h4>Limitación del uso o divulgación de datos y derechos ARCO</h4><p>El usuario podrá limitar el uso o divulgación de sus datos personales y ejercer derechos de acceso, rectificación, cancelación u oposición mediante solicitud escrita dirigida a “EL PRESTADOR” en su domicilio o al correo silvia@pasaporteatusalud.com, acompañando documento que acredite su identidad.</p>\r\n    <h4>Revocación de consentimiento</h4><p>El usuario podrá revocar su consentimiento siguiendo el mismo procedimiento, considerando que para ciertos fines la revocación puede implicar la cancelación de “LA TARJETA DE DESCUENTO” y la imposibilidad de acceder al programa.</p>\r\n    <p><strong>Nombre:</strong> Carlos David Gonzalez Miranda<br><strong>Fecha:</strong> 14 de mayo de 2026</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Firma</strong></div>\r\n  </div>\r\n\r\n  <div class=\"annex\"><h2>ANEXO 6<br>DECLARACIÓN DE DUEÑO BENEFICIARIO</h2>\r\n    <p>DE CONFORMIDAD CON LO DISPUESTO EN LOS ARTÍCULOS 18 FRACCIÓN I Y III DE LA LEY FEDERAL PARA PREVENCIÓN E IDENTIFICACIÓN DE OPERACIONES CON RECURSOS DE PROCEDENCIA ILÍCITA, EL ARTÍCULO 15 DE SU REGLAMENTO Y EL ARTÍCULO 13 DE LAS REGLAS DE CARÁCTER GENERAL, MANIFIESTO BAJO PROTESTA DE DECIR VERDAD:</p>\r\n    <h4>Datos de identificación del cliente</h4>\r\n    <table><tr><th>Campo</th><th>Respuesta</th></tr><tr><td>Apellido paterno, materno y nombre(s)</td><td>Carlos David Gonzalez Miranda</td></tr><tr><td>Fecha de nacimiento</td><td>1998-03-06</td></tr><tr><td>País de nacimiento</td><td>México</td></tr><tr><td>Nacionalidad</td><td>mexicana</td></tr><tr><td>Actividad, ocupación o profesión</td><td>Programador</td></tr><tr><td>Estado civil</td><td>SOLTERO(A)</td></tr><tr><td>Domicilio particular</td><td>Calle 123, Col. Mirador, C.P. 55555, Canto, Jalisco, México</td></tr><tr><td>Teléfonos</td><td>3326649812</td></tr><tr><td>Correo electrónico</td><td>carlos.codeglider@gmail.com</td></tr><tr><td>CURP</td><td>GOMC1234</td></tr><tr><td>RFC</td><td>GOMC56456456</td></tr><tr><td>Tipo de identificación</td><td>INE</td></tr><tr><td>Emitida por / país emisor</td><td>México</td></tr><tr><td>Número de identificación</td><td>46566</td></tr></table>\r\n    <h4>Datos de identificación de la operación</h4>\r\n    <table><tr><th>Campo</th><th>Respuesta</th></tr><tr><td>Tipo de operación</td><td>Adquisición de tarjeta de descuento PATS</td></tr><tr><td>Monto de operación</td><td>$800.00 M.N.</td></tr><tr><td>Fecha de operación</td><td>14 de mayo de 2026</td></tr><tr><td>Forma de pago</td><td>Pasarela / medio autorizado por “EL PRESTADOR”</td></tr><tr><td>Moneda</td><td>MXN</td></tr></table>\r\n    <h4>Información de la existencia del dueño beneficiario o beneficiario controlador</h4>\r\n    <p>Declaro que soy el beneficiario directo de la operación y no existe ningún otro dueño beneficiario o beneficiario controlador: <strong>SI</strong>.</p>\r\n    <h4>Aviso de privacidad</h4><p>Los datos personales serán protegidos y tratados conforme al Aviso de Privacidad contenido en el cuerpo del presente contrato y la legislación aplicable.</p>\r\n    <p>H. Puebla de Zaragoza al 14 del mes de mayo del año 2026.</p>\r\n    <div class=\"sign-box\"><img class=\"signature-img\" src=\"data:image/png;base64,\" alt=\"Firma digital\"><strong>Nombre y firma</strong><br>Carlos David Gonzalez Miranda</div>\r\n  </div>\r\n\r\n  \r\n  </div>\r\n', 'data:image/png;base64,', 'Carlos David Gonzalez Miranda', 'b1621f9ab0e1365b5dd6ff02d8d801a1cd0560f00255828115142669484ffe4e', '2026-05-14 19:50:19', '189.203.235.253', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/148.0.0.0 Safari/537.36', '', 'firmado', '2026-05-14 19:50:19', '2026-05-14 19:50:19');

