  `region` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `nombre` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `rfc` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `telefono` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `correo` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `valor_distribucion` decimal(12,2) NOT NULL,
  `fecha_alta` date NOT NULL,
  `zona` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `file` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `user_alta` bigint(20) UNSIGNED DEFAULT NULL,
  `pais` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `unidad` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `id_unidad` bigint(20) UNSIGNED DEFAULT NULL,
  `codigo_distribuidor` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `banco` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `numero_cuenta` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `clabe` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `titular_cuenta` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `estatus` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'ACTIVO',
  `activo` tinyint(1) NOT NULL DEFAULT '1',
  `comision_acumulada_periodo` decimal(12,2) NOT NULL DEFAULT '0.00',
  `comision_pagada_periodo` decimal(12,2) NOT NULL DEFAULT '0.00',
  `comision_por_pagar_periodo` decimal(12,2) NOT NULL DEFAULT '0.00',
  `fecha_renovacion` date DEFAULT NULL,
  `fecha_proxima_renovacion` date DEFAULT NULL,
  `renovacion_estatus` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'vigente',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `public_checkout_token` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `public_checkout_activo` tinyint(1) NOT NULL DEFAULT '1',
  `public_checkout_updated_at` datetime DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

